window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["hi"]={"ICON-0001":{"nm":"पदचिह्न","de":"फर्श पर बचा मिट्टी के रंग का एक निशान। कोई देर तक इधर-उधर टहलता रहा, फिर आख़िरकार एक क़दम और आगे बढ़ गया। पदचिह्न वह समय नहीं दर्ज करता जो वहाँ ठहरने में बीता, बल्कि वह एक क्षण जब जाने का मन बना लिया गया था।"},"ICON-0002":{"nm":"दीपक","de":"जब बत्ती को आग छूती है, अंधेरा चुपचाप एक-एक बालिश्त पीछे हटता है। उँगलियों को गर्माने वाली उस छोटी सी ऊष्मा में, पुराने ज़माने के लोग अपनी मन्नतें लिखकर बहा दिया करते थे। दीपक रोशनी करने के लिए नहीं, साथ रहने के लिए जलाया जाता है।"},"ICON-0003":{"nm":"रिबन","de":"एक गाँठ में मन ख़ूबसूरती से लिपट जाता है। देने वाले हाथ के लिए खोलना आसान हो, पर पाने वाले हाथ को धीरे-धीरे खोलने का मन करे। रिबन जो बाँधता है वह डिब्बा नहीं, बल्कि सौंपे जाने से ठीक पहले की वह धड़कती हुई बेचैनी है।"},"ICON-0004":{"nm":"डाकपेटी","de":"लाल मुँह खोले गली के मोड़ पर खड़ी है। हाथ से लिखी चिट्ठियाँ दुर्लभ हो चुके इस दौर में भी, यह नन्हा डिब्बा किसी की ख़ैरियत का अंत तक इंतज़ार करता है। सबसे ज़्यादा रोशन वह तब होता है जब बिल्कुल ख़ाली हो जाए—एक स्नेहिल पात्र।"},"ICON-0005":{"nm":"निजी द्वीप मिनी-मानचित्र","de":"मोड़ो तो जेब में समा जाए, खोलो तो समुद्र और पर्वतश्रेणी पास-पास लेटे नज़र आएँ—ऐसा एक काग़ज़। पहली बार यहाँ पहुँचने वाले के लिए हर कोना अब तक न खुला हुआ एक वादा है। खुलते ही, एक छोटा-सा द्वीप भी विशाल संसार बन जाता है।"},"ICON-0006":{"nm":"माइक","de":"पहला सुर छेड़ने से ठीक पहले, साँस सम्भालने का वह आधा धड़कन। जब पता हो कि दर्शकों की निगाहें मेरे एक शब्द की राह देख रही हैं, तो उँगलियाँ काँपने लगती हैं। माइक आवाज़ को बड़ा नहीं करता, वह उस काँपन को अंत तक साथ लेकर चलता है।"},"ICON-0007":{"nm":"घड़ी","de":"सेकंड की सुई कभी नहीं रुकती, पर कोई तुम्हें जल्दी करने को नहीं कहता। डेब्यू तक कितनी रातें, मंच तक कितने मिनट—डायल पर इंतज़ार और उत्साह एक ही रफ़्तार से घूमते हैं। समय देखना दरअसल मन को सांत्वना देना है।"},"ICON-0008":{"nm":"नोटबुक","de":"सबसे ज़्यादा ख़ाली जगह वाली चीज़। नृत्य की चाल भी, भोर के संकल्प भी, आख़िर तक न भेजे गए शब्द भी—सब यहीं जमा होते हैं। इसे खोलते ही, कल का मैं आज के मुझसे धीरे से बात करने लगता है।"},"ICON-0009":{"nm":"मुहर","de":"लाल स्याही सोखकर एक बार ज़ोर से दबाने पर, वादा साफ़-साफ़ अंकित हो जाता है। लिखावट से भारी और शब्दों से स्पष्ट एक निशान। हर दस्तावेज़ के अंत में लोग नाम की बजाय अपना मन इस नन्ही मुहर को सौंप देते थे।"},"ICON-0010":{"nm":"आधार","de":"ख़ुद को जितना हो सके नीचे झुकाकर यह किसी और को सहारा देता है। ऊपर रखी चीज़ डगमगाए नहीं, इसलिए सबसे नीचे चुपचाप डटे रहने की जगह। चमकता भले न हो, पर जो टूटने नहीं देता, वह अपनापन यहीं है।"},"ICON-0011":{"nm":"डाक टिकट","de":"एक कोने पर थूक लगाकर ज़ोर से चिपकाई जाने वाली नन्ही तस्वीर। दूर भेजे गए मन पर लगाई गई सबसे ईमानदार क़ीमत। चौकोर दृश्य का एक टुकड़ा समुद्र पार तक चिट्ठी का हाथ थामे साथ चलता है।"},"ICON-0012":{"nm":"झंडा पिन","de":"नक़्शे पर ठक से गाड़ दो तो कहता है—\"मैं यहाँ तक आ पहुँचा।\" यह विजय नहीं, एक अभिलेख है, और आगे आने वाले किसी और के लिए हौसला भी। यह झंडा देखकर एक क़दम और, बिना कुछ कहे पीठ थपथपाने वाला निशान।"},"ICON-0013":{"nm":"टहनी","de":"एक बार झुक चुकी डाली टूटना भूल जाती है। हवा के आगे जहाँ-जहाँ वह झुकी, वहाँ गाँठें मज़बूती से जम जाती हैं, और असली मज़बूती सहन किए गए निशानों से आती है—यह पुराना जंगल हवा में लहराते हुए बताता है।"},"ICON-0014":{"nm":"बटन","de":"खुलती और फिर से बँधती—यह बार-बार दोहराते हुए कॉलर को कसकर रखता है। एक नन्हा घेरा भोर की ठंड को भी, अचानक उभरी शर्म को भी चुपचाप रोक देता है। टूटकर गिर जाने पर ही पता चलता है कि उसकी जगह कितनी बड़ी थी।"},"ICON-0015":{"nm":"लिफ़ाफ़ा","de":"जिस पल मुँह सील होता है, तभी यह आख़िरकार एक राज़ बनता है। भीतर क्या रखा है, यह सिर्फ़ पाने वाला ही जानता है। काग़ज़ की एक तह मन और दुनिया के बीच रखी जाती है—सबसे पतला, सबसे स्नेहिल दरवाज़ा।"},"ICON-0016":{"nm":"डिब्बा","de":"चारों कोने सीधे हों तो कुछ भी उदारता से समा लेता है। घर बदलने के मौसम में यादें, त्योहारों पर तोहफ़े, आम दिनों में बिखरा-बिखरा सामान। बंद ढक्कन के भीतर हमेशा किसी न किसी के \"बाद में\" से भरा रहता है।"},"ICON-0017":{"nm":"हैंडल","de":"दरवाज़े और इंसान के बीच सबसे पहले हाथ बढ़ाने वाली चीज़। एक बार खींचने पर ही आख़िरकार भीतर और बाहर जुड़ते हैं। आने-जाने का हर फ़ैसला इस ठंडे हाथ को एक बार थामकर गुज़रता है।"},"ICON-0018":{"nm":"चम्मच","de":"गोलाई भरे मुँह से गरमागरम शोरबा चुपचाप उठाता है। माँ ने फूँक मारकर ठंडा किए हुए पहले चम्मच की उस गर्माहट को याद रखने वाला औज़ार। खाने की मेज़ पर सबसे बार-बार होंठों को छूने वाला, सबसे स्नेहिल हाथ।"},"ICON-0019":{"nm":"चप्पल","de":"दहलीज़ पार करते ही पैर सबसे पहले राहत की साँस लेते हैं। दिनभर की खटपट उतारकर हल्के क़दमों से चलने की शाम की आवाज़। दरवाज़े पर क़रीने से रखी एक जोड़ी कहती है—\"अब घर आ गया।\""},"ICON-0020":{"nm":"चाबी","de":"बंद करना सीखने से पहले खोलना सीखा जाता है। हथेली में गर्म होती हुई, एक दिन किसी अनजान नए दरवाज़े के सामने चुपचाप ठहर जाने वाली नन्ही धातु। जाने वाले की गर्माहट सबसे लंबे समय तक अपने में समेटे रखने वाली चीज़।"},"ICON-0021":{"nm":"प्याला","de":"ख़ाली हो तो सलीक़ेदार, भरा हो तो बेइंतहा गर्म। आमने-सामने उठे दो प्यालों की टकराहट की उस साफ़ आवाज़ में एक चुपचाप वादा समा जाता है। अकेले से ज़्यादा दो के साथ चमकने के लिए जन्मा एक पात्र।"},"ICON-0022":{"nm":"थाली","de":"गोल किनारे के भीतर एक दिन भर की मेहनत भरपूर सिमटी होती है। ख़ाली होना, धोया जाना, फिर भरा जाना—जीवन भर—सबसे बार-बार चमकने वाला, सबसे बार-बार भुला दिया जाने वाला घरेलू सामान। खाने की मेज़ का मंच हमेशा इसी के ऊपर सजता है।"},"ICON-0023":{"nm":"रोशनी","de":"एक स्विच से कमरे का भाव बदल जाता है। तेज़ हो तो रोज़मर्रा, मद्धिम हो तो सांत्वना। देर से घर लौटे किसी के लिए आख़िर तक जलती रखी रोशनी की एक बूँद, दुनिया का सबसे गर्मजोशी भरा स्वागत बन जाती है।"},"ICON-0024":{"nm":"चाय की चम्मच","de":"चाय के ऊपर एक चक्कर धीरे-धीरे घुमाओ तो पत्तियाँ और पानी एक-दूसरे में घुल-मिल जाते हैं। जल्दबाज़ी न करने वाली हरकत, ख़ुशबू फैलने तक की एक छोटी प्रतीक्षा। एक चाँदी का हाथ दोपहर की रफ़्तार को स्नेह से धीमा कर देता है।"},"ICON-0025":{"nm":"बुकमार्क","de":"पढ़ते-पढ़ते रुकी जगह पर चुपचाप टिकाया गया वादा। \"यहाँ रुका हूँ, ज़रूर लौटूँगा\"—यह संकल्प पन्नों के बीच सो जाता है। कहानी बंद हो जाए तब भी, मन उस एक पंक्ति पर साफ़-साफ़ चिह्नित रहता है।"},"ICON-0026":{"nm":"कुशन","de":"सहारे की ज़रूरत वाली पीठ और घुटनों को बिना कुछ कहे थाम लेता है। गहरे धँसकर फिर धीरे-धीरे फूलते हुए, यह आज दिनभर की थकान सोख लेता है। सबसे आलसी मुद्रा को सबसे उदारता से माफ़ करने वाली चीज़।"},"ICON-0027":{"nm":"फ़्रेम","de":"एक चौकोर किनारा किसी दृश्य को हमेशा के लिए बाँध देता है। जिस पल यह क़ैद हुआ, वह पल चाहे कितना भी समय बीत जाए, फीका नहीं पड़ता। क्या रखा जाए इससे ज़्यादा, क्या बचाकर रखने का फ़ैसला लिया जाए—यह एक स्नेहिल चुनाव है।"},"ICON-0028":{"nm":"नक़्शा","de":"हर मोड़ की सिलवट में रास्ता भटकने और फिर पा लेने का निशान बसा होता है। खोलते ही, न देखी हुई जगहें भी उँगलियों से पहले-पहल चली जा सकती हैं। हर साहसिक यात्रा इस एक काग़ज़ को खोलने के नन्हे साहस से शुरू होती है।"},"ICON-0029":{"nm":"पोस्टकार्ड","de":"पीछे की आधी जगह तस्वीर, आधी ख़ाली। दूर चला गया कोई \"ठीक हूँ\" के चंद शब्दों के साथ वहाँ का दृश्य भी जोड़कर भेज देता है। बिना लिफ़ाफ़े के भी ख़ैरियत शर्मिंदा नहीं होती—सबसे ईमानदार काग़ज़ का टुकड़ा।"},"ICON-0030":{"nm":"प्रवेश बैज","de":"गले में लटकाते ही, आख़िरकार भीतरी दुनिया में क़दम पड़ता है। नन्हे कार्ड पर लिखा मेरा नाम चुपचाप स्वीकृति देता है—\"यहाँ, यह तुम्हारी जगह है।\" यह पार होने की योग्यता नहीं, कहीं का हिस्सा होने का प्रमाण है।"},"ICON-0031":{"nm":"अक्षर B","de":"शब्द के बीचोबीच सबसे ज़्यादा बुलाया जाने वाला अक्षर। होंठ एक बार भींचकर फिर हल्के से खोलने पर ही आवाज़ निकलती है। न शुरुआत, न अंत, पर लय थामे रखने वाली भरोसेमंद दूसरी जगह।"},"ICON-0032":{"nm":"विज़िटिंग कार्ड","de":"देते समय दोनों हाथों से, लेते समय नज़रें मिलाते हुए। काग़ज़ के एक टुकड़े में किसी इंसान का दिन और आत्मसम्मान चुपचाप समा जाता है। नाम और पद के बीच की तंग खाली जगह में उस दिन का पहला प्रभाव धीरे से बस जाता है।"},"ICON-0033":{"nm":"आवरण","de":"कहानी के सबसे बाहरी हिस्से में यह पहले हवा-पानी झेलता है। भीतर के शब्दों की रक्षा करते-करते इसके अपने कोने घिसने लगते हैं। खोलने से ठीक पहले की वह क्षणिक बेचैनी हमेशा इसी एक पन्ने से शुरू होती है।"},"ICON-0034":{"nm":"पाठ्यपुस्तक","de":"रेखांकन और हाइलाइटर से किसी एक इंसान का संघर्ष घनी तरह लिखा होता है। नई किताब हो तो डरावनी लगती है, पूरी पढ़ लो तो सबसे भरोसेमंद दोस्त बन जाती है। जो नहीं जानते थे उसे जान लेने के निशान हर पन्ने पर सलीक़े से मुड़े रहते हैं।"},"ICON-0035":{"nm":"डांस पास","de":"यह एक टुकड़ा अभ्यास कक्ष का दरवाज़ा चौड़ा खोल देता है। आईनों से भरा कमरा, थिरकते पैरों की आवाज़, पहली बार सीखे गए आठ गिनती के बोल। नाच अभी अनाड़ी हो तो भी ठीक है—एक नन्हा काग़ज़ काँपती हुई पीठ को चुपचाप आगे धकेलता है।"},"ICON-0036":{"nm":"फ़ाइल फ़ोल्डर","de":"बिखरे-बिखरे इधर-उधर भटकते पन्ने एक रीढ़ में क़रीने से पिरोकर आख़िरकार क्रम पा लेते हैं। क्रम बनते ही यह कहानी बन जाती है, और जितनी मोटी होती जाए, उतना ही यह स्नेहिल प्रमाण बनती है कि किसी ने उतना ही जीवन क़दम-दर-क़दम जिया।"},"ICON-0037":{"nm":"परीक्षा पत्र","de":"ख़ाली पंक्तियों के ऊपर पल भर काँपती उँगलियाँ। ग़लत जवाब से भी ज़्यादा डरावना है न जानी चीज़ का सीधा सामना करना। जाँच पूरी होने पर हर ग़लत जगह पर अगली बार बढ़ने की एक ख़ाली जगह चुपचाप बच जाती है।"},"ICON-0038":{"nm":"अक्षर A","de":"मुँह पूरा खोलने पर ही निकलने वाली पहली आवाज़। यह अक्सर पंक्ति के सबसे आगे, नाम के सबसे पहले खड़ा रहता है। जब भी कुछ शुरू करना हो तो इसी अक्षर से—इसीलिए यह हमेशा थोड़ा ज़्यादा साहसी है।"},"ICON-0039":{"nm":"अक्षर D","de":"नरमी से मुड़ी अपनी पीठ से यह किसी शब्द को धीरे से थाम लेता है। इसका गोल हिस्सा किसी के नाम के अंत में सलीक़े से टँगा रहता है। भड़कीला नहीं, पर हट जाए तो सूनापन महसूस हो—अक्षरों के बीच एक शांत साथी।"},"ICON-0040":{"nm":"अभ्यास पत्र","de":"ग़लती करने पर भी माफ़ी वाला, दुनिया का इकलौता काग़ज़। यह एक ही हरकत, एक ही वाक्य को दर्जनों बार फिर से लिखने देता है। जितने पन्ने मसलकर फेंके गए, उतना ही कोई निश्चित रूप से बेहतर होता जा रहा था।"},"ICON-0041":{"nm":"संगीत रचना पत्र","de":"रात के दो बजे, एक गुनगुनाहट नींद तोड़ देती है। पेंसिल का पंचरेखा पर ठिठकना इसलिए होता है कि धुन हाथ से भी तेज़ चलती है। मिटाए और फिर लिखे गए हर निशान में, अब तक नाम न पाया गीत धीरे-धीरे बढ़ रहा होता है।"},"ICON-0042":{"nm":"एक्सेस पास","de":"गले में लटकाते ही, एक साधारण गलियारा दूसरी दुनिया में बदल जाता है। तार अंधेरे में साँप की तरह रेंगते हैं, और मंच के पार कहीं एक अनसुनी उलटी गिनती शुरू होती है। यहाँ क़दम रखने का हक़, यह एक टुकड़ा तुम्हारी जगह बोल देता है।"},"ICON-0043":{"nm":"कॉन्टैक्ट शीट","de":"छोटे-छोटे ख़ानों में हर बार अलग भाव ठहरा हुआ है। हँसते हुए, मुड़कर देखते हुए, आँखें बंद किए हुए। एक-एक फ़्रेम को छूते जाओ तो शटर दबाने वाले उस दिन की धड़कन उँगलियों में लौट आती है। एक फ़्रेम चुनना भी पहले से ही एक अभिलेख है।"},"ICON-0044":{"nm":"कॉल शीट","de":"कल कितने बजे, कहाँ, क्या। एक काग़ज़ पहले से ही एक दिन का पूरा रास्ता खींच देता है। मिनट-मिनट भरे ख़ानों के बीच, कोई यहाँ लिखे क्रम के मुताबिक़ एक-एक क़दम सपने की ओर चलता जाता है।"},"ICON-0045":{"nm":"टैग","de":"क़ीमत के पीछे बनाने वाले का समय चुपचाप टँगा रहता है। एक झटके से उतारने की उस छोटी हरकत से ही यह आख़िरकार अपना बन जाता है। कटी हुई जगह पर बचता है नई चीज़ की महक और उत्साह की एक मुट्ठी।"},"ICON-0046":{"nm":"पोर्टफ़ोलियो","de":"आवरण पलटते ही अब तक चला रास्ता एक साथ खुल जाता है। भरोसे वाले एक पन्ने के बगल में, अनाड़ी पहला प्रयास शर्माते हुए साथ खड़ा है। किसी को पहली बार ख़ुद को सौंपते वक़्त, इससे ज़्यादा ईमानदार परिचय और कोई नहीं होता।"},"ICON-0047":{"nm":"प्लानर","de":"आज को लिखना, अगले हफ़्ते को खींचना, और कभी-कभी एक ख़ाना काला रंग देना। जैसा सोचा वैसा भले न हुआ हो, ख़ाने भरने वाला हाथ नहीं रुकता। भविष्य को एक बार पहले से जी लेने जैसी, एक छोटी सी रस्म।"},"ICON-0048":{"nm":"प्लेलिस्ट","de":"धीमे गीत और तेज़ ताल के बीच, उस दिन के मन के मौसम के मुताबिक़ गाने एक क़तार में सजाए जाते हैं। सोचो कि किसी का पूरा दिन ठीक इसी क्रम में बहता है, तो गानों के बीच की ख़ामोशी भी स्नेहिल हो जाती है।"},"ICON-0049":{"nm":"छात्र पहचान पत्र","de":"एक नाम, एक तस्वीर, और कुछ अंक। कक्षा और अभ्यास कक्ष के बीच आने-जाने के दिनों को साबित करने वाला एक कार्ड। जेब में आते-जाते कोने घिस चुके इस कार्ड में फिर कभी न लौटने वाला ताज़ा-ताज़ा हर दिन बसा है।"},"ICON-0050":{"nm":"कलाई बैंड","de":"उस दिन का रंग कलाई पर बाँधने का वह पल याद है? साथ में लगाया नारा, साथ भीगी कॉन्सर्ट की रात। पट्टी घिस जाए, रंग फीका पड़ जाए, फिर भी न खोलना—क्योंकि उस गर्मी को कलाई पर जीवित रखना चाहते हो।"},"ICON-0051":{"nm":"बाज़ूबंद","de":"बाँह पर बाँधते ही, ज़िम्मेदारी नाम का बोझ धीरे से जुड़ जाता है। कतार के सबसे आगे खड़े होने और सबसे आख़िर में जगह छोड़ने वाले का निशान। कपड़े का एक टुकड़ा किसी को थोड़ा और बड़ा बना देता है।"},"ICON-0052":{"nm":"रिंग","de":"बिना कहीं टूटे गोल घूमती एक लकीर। शुरुआत और अंत जहाँ छूते हैं, वहाँ लोग हमेशगी का आकार देखते हैं। दो हाथ चुपचाप जोड़ दो तो, शब्दों से पहले, एक वादा आकार में बच जाता है।"},"ICON-0053":{"nm":"पदक","de":"छाती पर टँगे धातु के नन्हे टुकड़े पर सहे गए दिन अंकित हैं। जो चमकता है वह धातु नहीं, उसके पीछे छुपी अभ्यास की अनगिनत रातें हैं। गर्व से पहले जो उमड़ आता है, वह किसी तरह कृतज्ञता का भाव है।"},"ICON-0054":{"nm":"एप्रन","de":"गले में डोरी बाँधते ही दोनों हाथ आज़ाद हो जाते हैं। आटा हो या रंग, किसी चीज़ में पूरी तरह डूब जाने की तैयारी का संकेत। दाग़ एक-एक करके बढ़ते जाएँ, तो उस दिन दिए गए ध्यान की गहराई भी साथ बढ़ती है।"},"ICON-0055":{"nm":"इयर हूड","de":"कानों को पूरा ढँक लो तो बाहरी आवाज़ें एक क़दम दूर हट जाती हैं। तेज़ ठंडी हवा वाले स्कूल जाने के रास्ते पर, मुलायम भीतरी हिस्से में हल्के से छिप जाने की एक नन्ही पनाहगाह। सर्दी की गर्माहट कभी-कभी ऐसे ही कान की नोक से शुरू होती है।"},"ICON-0056":{"nm":"पोशाक","de":"पर्दा उठने से पहले, हैंगर पर टँगी एक पोशाक साँस रोके खड़ी है। हर सिलाई में नृत्य की मुद्रा मुड़ी हुई है। बाँह भीतर जाते ही इंसान किरदार बन जाता है, और मंच उस पोशाक की दूसरी त्वचा बन जाता है।"},"ICON-0057":{"nm":"मुकुट","de":"सिर पर रखते ही झुकी पीठ अपने-आप सीधी हो जाती है। सुनहरी चमक शक्ति से पहले ज़िम्मेदारी की फुसफुसाहट करती है। माथे पर टिका ठंडा बोझ बता देता है—जितनी चमकदार जगह, उतना ही भारी।"},"ICON-0058":{"nm":"लबादा","de":"कंधों पर डालते ही पीठ के पीछे हवा फड़फड़ाती है। दौड़ते वक़्त कपड़े की एक धज पीछे-पीछे आने का वह एहसास। यह किसी हीरो का चिह्न कम, बस अच्छा दिखना चाहने वाले बचपन के मन के ज़्यादा क़रीब है।"},"ICON-0059":{"nm":"मुखौटा","de":"चेहरा ढँकने पर उल्टा और ज़्यादा ईमानदार हो जाता है इंसान—जैसे पुराने आँगन के खेलों में मुखौटे के पीछे मन भरकर हँसते-रोते थे। छुपे हुए भाव के परे, आम तौर पर निगली जाने वाली असली आवाज़ और ज़ोर से बाहर आ जाती है।"},"ICON-0060":{"nm":"लिपस्टिक","de":"ढक्कन घुमाकर एक लकीर खींचते ही होंठों पर एक नन्हा संकल्प जम जाता है। आईने के सामने आख़िरी जाँच, हिचकिचाहट के ऊपर पोता गया लाल रंग की एक लकीर। रंग चढ़ने के उस पल भर में, डर चुपचाप जगह छोड़ देता है।"},"ICON-0061":{"nm":"जैकेट","de":"कंधे की रेखा सही बैठे तो इंसान थोड़ा मज़बूत महसूस करता है। आस्तीन चढ़ाओ तो काम करने का मन, कॉलर खड़ा करो तो निकल पड़ने का मन। एक पोशाक चुपचाप उस दिन का रुख़ तय कर देती है।"},"ICON-0062":{"nm":"ताइक्वांडो बेल्ट","de":"रंग एक क़दम बदलते ही, उसके नीचे जमा पसीने की मात्रा भी बदल जाती है। गाँठ कसकर बाँधकर झुककर सलाम करने की डोजांग की सुबह। बेल्ट बाँधती उँगलियों से बिखरा मन फिर से इकट्ठा हो जाता है।"},"ICON-0063":{"nm":"गॉगल्स","de":"आँखों पर पहनते ही दुनिया एक सुर और साफ़ हो जाती है। हवा और धूल दोनों को रोकने वाली गोल ढाल के पार, हमेशा चला जाने वाला आम रास्ता भी न जाने क्यों शुरुआती रेखा-सा चमकता दिखता है।"},"ICON-0064":{"nm":"ग्लव्स","de":"हाथ में पहनते ही किसी भी चीज़ को मज़बूती से थामने का साहस उमड़ आता है। गिरा देने के डर से सिकुड़ी उँगलियाँ आख़िरकार पूरी खुल जाती हैं। जो बचाया जाता है वह हाथ है, पर जो असल में सुरक्षित रहती है वह आगे आने वाली चुनौती है।"},"ICON-0065":{"nm":"मास्क","de":"निचला चेहरा ढँकते ही आँखें ज़्यादा बातें कहने लगती हैं। भीड़भाड़ वाली गली में, हल्के से ढँके रहकर मिलने वाली एक छोटी-सी गुमनाम आज़ादी। इसीलिए इसे पूरा उतार देने पर बची मुस्कान और भी चमककर फैलती है।"},"ICON-0066":{"nm":"टोपी","de":"छज्जा थोड़ा नीचे झुकाओ तो धूप भी, निगाहें भी एक बालिश्त बगल से गुज़र जाती हैं। सिर पर रखी नन्ही छत के नीचे, आज कम से कम सहज भाव लेकर चला जा सकता है। सबसे हल्का रूपांतर हमेशा यहीं से शुरू होता है।"},"ICON-0067":{"nm":"शर्ट","de":"सरसराहट, अभी-अभी इस्त्री किए कॉलर से सुबह की महक आती है। ऊपर से नीचे तक क्रम में बटन बंद करते-करते, बिखरा हुआ मन भी एक-एक क़दम सलीक़ेदार होता जाता है। सफ़ेद एक टुकड़ा दिन का पहला वाक्य खोलता है।"},"ICON-0068":{"nm":"स्कार्फ़","de":"गले पर एक बार लपेटते ही हवा का रास्ता बंद हो जाता है। किनारा कंधे पर हल्के से लहराते रहने के बीच, ठंड अब भीतर तक नहीं पहुँच पाती। शान और गर्माहट के बीच कहीं टँगा एक टुकड़ा कपड़ा।"},"ICON-0069":{"nm":"दस्ताने","de":"उँगलियों की नोक तक पूरी तरह ढँक जाने पर ठंडी चीज़ों से भी डर नहीं लगता। फूँक मारते हाथ धीरे-धीरे गर्म हो जाने वाली, सर्दी की एक नन्ही ऐश्वर्य। उतारकर सौंपा गया एक दस्ताना किसी और का हाथ भी गर्म कर सकता है।"},"ICON-0070":{"nm":"सैनिक पहचान पट्टी","de":"दो पतली पट्टियाँ चुपचाप एक-दूसरे के आमने-सामने हैं। नाम के तीन अक्षर और कुछ अंक—यही किसी को आख़िर तक याद रखने देते हैं। ठंडी धातु है, फिर भी न जाने क्यों सबसे गर्म वादे जैसी लगती है।"},"ICON-0071":{"nm":"ग्रिप रिंग","de":"उँगली फँसाते ही गिरा देने की चिंता चुपचाप घुल जाती है। एक हाथ से भी आराम से थामकर हिलाने लायक़ एक छोटी सी तसल्ली। एक तस्वीर छोड़ने के लिए बाँह लंबी करते वक़्त, यह चुपचाप हथेली को सहारा देता है।"},"ICON-0072":{"nm":"फूलों का ताज","de":"सिर पर रखते ही एक गोद भर बसंत साथ चला आता है। खेतों से तोड़कर गोल गूँथे गए फूल माथे को धीरे से घेर लेते हैं। तस्वीर में चमकती मुस्कान के ऊपर, घास की हल्की महक देर तक बची रहती है।"},"ICON-0073":{"nm":"आँखों की पट्टी","de":"आँखें ढँकते ही रोशनी और शोर दोनों एक साथ दूर हट जाते हैं। दिखना बंद हो तो सुनाई सिर्फ़ अपनी साँस देती है। दुनिया को कुछ देर के लिए बंद कर भीतर के सन्नाटे में उतरते ही, पीठ पीछे एक नन्हा दरवाज़ा चुपचाप बंद हो जाता है।"},"ICON-0074":{"nm":"मफलर","de":"एक फेरा, दो फेरे—गले पर लपेटने के हर चक्कर से सर्दी थोड़ी और नरम पड़ती जाती है। ऊन के धागों के बीच कहीं किसी का बुना हुआ मन भी घुला हो सकता है। नाक की नोक तक डूब जाओ तो दुनिया और ज़्यादा गर्माहट भरी लगती है।"},"ICON-0075":{"nm":"अर्धचंद्र मुखौटा","de":"चेहरे का बस आधा हिस्सा ढँककर बहाना-रात शुरू होती है। उघड़े होंठ मुस्कुराते हैं, छुपी आँखें राज़ थामे रहती हैं। कौन है, यह पता होने और न होने के बीच की वह तंग खाई, आधी रात की हवा को बेचैन कर देती है।"},"ICON-0076":{"nm":"बेरे टोपी","de":"तिरछे रखते ही एक साधारण दिन में चुपचाप एक अंदाज़ भर जाता है। गोल, चपटे कपड़े का एक टुकड़ा कंधों पर चुपचाप किसी कलाकार का भरम ओढ़ा देता है। आईने के सामने कोण चुनने का वह पल भर भी सुहाना लगता है।"},"ICON-0077":{"nm":"चोकर","de":"गले पर सही फिट बैठाने पर निगाहें अपने-आप ऊपर जमा हो जाती हैं। एक पतली सी डोरी पूरा माहौल बदल देती है। छोटी पर स्पष्ट, आज के दिन के आत्मविश्वास को भरने वाले कुंडी जैसी कोई चीज़।"},"ICON-0078":{"nm":"पार्का","de":"ज़िप पूरी ऊपर चढ़ाते ही बर्फ़ीला तूफ़ान भी एक क़दम पीछे हट जाता है। मोटे भीतरी हिस्से में हाथ गहरे डालो तो पूरी दुनिया का शोर शांत हो जाता है। तेज़ हवा के बीच भी आख़िर तक गर्म रहने वाला, एक नन्हा घर।"},"ICON-0079":{"nm":"पैंट","de":"पैर डालकर कमर बाँधते ही, आख़िरकार निकलने की तैयारी पूरी होती है। हर क़दम पर कपड़ा अपने बनावट के साथ नरमी से हिलता है। आराम और सलीक़े के बीच कहीं दिन शुरू होता है।"},"ICON-0080":{"nm":"पियर्सिंग","de":"एक नन्हा बिंदु जोड़ने में भी थोड़ी हिम्मत लगती है। धातु की एक चमक साधारण कान पर एक साफ़ पूर्ण विराम लगा देती है। बहुत छोटी, पर निश्चित रूप से बदले हुए आज के मुझे दिखाने वाली एक रोशनी।"},"ICON-0081":{"nm":"वेवफ़ॉर्म","de":"इंजीनियर के लिए गाना सुना नहीं जाता, देखा जाता है। स्क्रीन पर ऊपर-नीचे होती पर्वतश्रेणी से वे पढ़ लेते हैं कि उस दिन साँस कहाँ काँपी थी। अब तक अदृश्य रही आवाज़ पहाड़ों की तरह लेट जाती है, और एक गीत का पूरा भूगोल खोलकर दिखा देती है।"},"ICON-0082":{"nm":"ट्यूनर","de":"प्रदर्शन से ठीक पहले, छहों तार बारी-बारी सहलाकर बिखरे हुए सुर को उनकी जगह बिठाया जाता है। आधा डिग्री भी चूक जाए तो दर्शक भूतों जैसे भाँप लेते हैं। किसी को पता न चले इतनी सटीकता से मिलाना—यही मंच के प्रति स्नेह है।"},"ICON-0083":{"nm":"स्ट्रैप","de":"कलाई पर एक बार लपेटते ही गिरा देने की चिंता चुपचाप छूट जाती है। मंच पर सबसे बड़ा डर है हाथ से कुछ छूट जाना, इसलिए यह एक नन्ही डोरी ही मन को आख़िरकार चैन देती है।"},"ICON-0084":{"nm":"झांझ","de":"बस एक बार टकराने के उस पल में, गीत के आख़िरी वाक्य पर एक साफ़ पूर्ण विराम लग जाता है। सुनहरी थाली सबसे छोटा बजना और सबसे लंबा गूँजना—दोनों जानती है। अंत को इतना रोशन होकर ही बंद होना चाहिए, ऐसे।"},"ICON-0085":{"nm":"गिटार","de":"छह तारों पर उँगलियाँ फिसलते ही एक छोटा कमरा पूरी तरह मंच बन जाता है। किसी की पहली धुन भी, नींद न आई रात की अकेली बड़बड़ाहट भी—इसी गोल लकड़ी के ढाँचे के भीतर पहली बार साँस लेती है।"},"ICON-0086":{"nm":"ध्वनि बादल","de":"आसमान के एक कोने में सुर रुई की तरह गुच्छे बनाकर तैरते रहते हैं। हवा एक बार बहकर गुज़रे तो बूँदों की बजाय धुन बरसती है, ऐसा मानकर टापू के बच्चे बिना छाते के भी उसका स्वागत करने निकल पड़ते हैं।"},"ICON-0087":{"nm":"स्टेप","de":"मंच की चाल पैरों की नोक से हल किया गया गणित है। यहाँ एक क़दम, वहाँ आधी धड़कन—ग़लत हो तो भी ठीक है, धीरे-धीरे। सैकड़ों बार चलकर शरीर में अंकित हुए ख़ाने मिलकर आख़िरकार एक गीत का नक़्शा पूरा करते हैं।"},"ICON-0088":{"nm":"एम्प","de":"फुसफुसाहट को गर्जना में बदल देने वाला डिब्बा। फिर भी वॉल्यूम एक ख़ाना ऊपर बढ़ाने से पहले हाथ हमेशा रुक जाता है। ज़्यादा तेज़ आवाज़ से कहीं ज़्यादा सटीक आवाज़ ही दर्शक दीर्घा की आख़िरी पंक्ति तक पहुँचती है, यह यह डिब्बा जानता है।"},"ICON-0089":{"nm":"सुर की रुई","de":"गोल सिर वाले सुर के निशान इकट्ठे होकर रुई का गोला बनते हैं तो तकिये जितने मुलायम हो जाते हैं। चुपचाप सिर टिकाकर लेट जाओ तो सुनाई देती-न-देती एक लोरी बहने लगती है—टापू की सबसे स्नेहिल अफ़वाह।"},"ICON-0090":{"nm":"कैसेट","de":"रिवाइंड का बटन दबाओ तो चरचराहट के साथ टेप धीरे-धीरे उस गर्मी के पहले गाने की ओर लौट जाती है। एक पूरा दौर पूरी तरह लिपटा नन्हे डिब्बे में, अब फिर कभी न छुआ जा सकने वाला समय पूरी तरह सोया हुआ है।"},"ICON-0091":{"nm":"ट्यूनिंग फ़ॉर्क","de":"दो शाखाओं वाली धातु को हल्के से बजाओ तो हवा में एक मानक सुर जन्म लेता है। इस नन्हे कँपकँपाहट पर हर वाद्य यंत्र चुपचाप सिर झुकाकर सुर मिलाता है। कुछ भी शुरू होता है इतनी नाज़ुक कँपकँपाहट से।"},"ICON-0092":{"nm":"वेवफ़ॉर्म चिप","de":"आवाज़ का एक टुकड़ा नाख़ून जितनी छोटी चिप में धीरे से क़ैद हो जाता है। जान-बूझकर रिकॉर्ड न की गई एक टिप्पणी, खो चुकी समझी गई किसी की हँसी—इसके भीतर अब भी उतनी ही गर्मजोशी से जीवित है, साँस लेती हुई।"},"ICON-0093":{"nm":"LP रिकॉर्ड","de":"सुई खाँचे के साथ पहला क़दम रखते ही, पहले एक हल्की चरचराती साँस सुनाई देती है। उस नन्हे शोर से भी प्यार करते हुए, कोई इस काले चक्र को आख़िर तक हाथ से छोड़ नहीं पाता।"},"ICON-0094":{"nm":"जेब","de":"सबसे प्यारी चीज़ हमेशा दिल के सबसे क़रीब रखी जाती है। हथेली जितनी कपड़े की एक थैली कभी हाथ गर्म करने वाला, कभी ताबीज़, तो कभी राज़ों का भंडार बन जाती है।"},"ICON-0095":{"nm":"पट्टी","de":"अभ्यास लंबा खिंच जाने वाली रात हो तो एड़ी-एड़ी पर एक-एक नन्हा पदक चिपक जाता है। \"दर्द होता है\" कहना निगल जाने के लिए चिपकाई गई एक पट्टी—कल भी नाचूँगा, यह किसी को न पता चला चुपचाप वादा है।"},"ICON-0096":{"nm":"तकिया","de":"दिनभर का पूरा मंच जहाँ आख़िर में उतरता है, वह आख़िरकार यही एक मुलायम चौकोर टुकड़ा है। सिर चुपचाप टिकाओ तो कानों में बची तालियों की आवाज़ धीरे-धीरे शांत होती जाती है, और टापू पर भी आख़िरकार रात उतरती है।"},"ICON-0097":{"nm":"घंटी","de":"टुनटुन, छोटी सी आवाज़ के साथ ही कोई दरवाज़ा धकेलकर भीतर आ जाता है। मेहमान आने का संकेत भी, दिन खुल जाने का अभिवादन भी। धातु का एक नन्हा टुकड़ा दिनभर सिर्फ़ स्वागत की ख़ुशी ही निभाता है।"},"ICON-0098":{"nm":"केस","de":"जितनी क़ीमती चीज़, उतना ही मज़बूत घर अलग से बनाया जाता है। हर बार खोलते-बंद करते हाथ सतर्क हो जाते हैं, क्योंकि भीतर रखी चीज़ महज़ सामान नहीं, बल्कि खोना न चाहा गया मन है।"},"ICON-0099":{"nm":"ब्रश","de":"एक-एक बाल तक बनावट के साथ बुहारने पर कोनों में जमी धूल चुपचाप पीछे हट जाती है। न दिखने वाली जगहों को भी न टालने वाले स्पर्श की बदौलत, कमरा हर दिन एक नई सुबह का स्वागत करता है।"},"ICON-0100":{"nm":"स्केच","de":"पूरा होने से पहले की रेखाएँ अपनी हिचकिचाहट को छुपाने की ज़हमत नहीं उठातीं। मिटाकर फिर खींचे गए हर निशान में, क्या बनना चाहा था वह बिना झूठ के बचा रहता है। जितनी अनाड़ी शुरुआत, उतनी ही सबसे ईमानदार।"},"ICON-0101":{"nm":"गुड़िया","de":"कुछ अस्तित्व सिर्फ़ बिना एक शब्द कहे बाहों में भर लेने से ही सुकून दे देते हैं। मंच के पीछे जिस रात हाथ काँप रहे थे, तकिए के पास साथ काँपते रहे उस रुई भरे दोस्त को—हर कोई दिल में कहीं न कहीं ऐसा एक साथी सँजोए रखता है।"},"ICON-0102":{"nm":"घंटी","de":"पहाड़ी मंदिर की घंटी एक बार बजकर पूरी घाटी को पार कर जाती है। दूर, और भी दूर तक पहुँचने की धातु की तड़प ही लंबी होकर गूँजती है, इसलिए वह ध्वनि सुनने वाले के सीने में धीरे-धीरे उतरती जाती है।"},"ICON-0103":{"nm":"छाता","de":"साथ लेने पर एक कंधा भीगना तय होता है। हल्का सा झुका छाता, और वह भीगा हुआ कंधा ही स्नेह का सबसे स्पष्ट प्रमाण होता है। एक छत साझा करते हुए तय हुआ छोटा-सा रास्ता दिल में लंबे समय तक बना रहता है।"},"ICON-0104":{"nm":"चटाई","de":"नंगे फ़र्श पर एक बिछा दो तो वह जगह तुरंत अभ्यास कक्ष बन जाती है। लुढ़कने और गिरने पर भी बिना कुछ कहे थाम लेने वाली यह जगह—अनगिनत गतियों ने पहली बार यहीं अपने शरीर में अपनी राह पाई।"},"ICON-0105":{"nm":"घुंघरू","de":"हल्के से हिलाओ तो हथेली में एक साफ़, खनकती ध्वनि लुढ़क आती है। पुराने समय के बच्चे जिसे रंग-बिरंगी जैकेट की किनारी पर बाँधकर आँगन में उछल-कूद करते थे, वह छोटी-सी, गोल खुशी हथेली पर फिर से जाग उठती है।"},"ICON-0106":{"nm":"नकली साँप","de":"लंबा-सा लटकता आकार शरारत से लोगों को चौंका देता है। डर जाना, भाग जाना, और अंत में खिलखिलाकर हँस पड़ना—ऐसी शरारत भी आख़िरकार एक-दूसरे के लिए स्नेह की ही एक शाखा है।"},"ICON-0107":{"nm":"खिलौना","de":"बड़े होकर भी जिसे फेंकने का मन नहीं करता, ऐसा एक डिब्बा हर किसी के पास होता है। उसके भीतर सबसे चमकीले दिनों की हँसी अब भी बिना खुली हुई कमानी की तरह कसकर लिपटी हुई है।"},"ICON-0108":{"nm":"थाली-मेज़","de":"मुड़े हुए पैर खोलते ही कोई भी जगह तुरंत परिवार का ठिकाना बन जाती है। इकट्ठे बैठकर चम्मचों के टकराने की आवाज़, वह मामूली-सा सुर-संगम ही दिनभर में सबसे गर्मजोशी से गूँजने वाला एक गीत है।"},"ICON-0109":{"nm":"साबुन","de":"हाथ में थोड़ा-थोड़ा घटते हुए, चुपचाप किसी को साफ़ कर देता है। खुद को घिसकर दूसरे को नहलाने का काम—झाग पूरी तरह बैठ जाने के बहुत बाद ही, वह शांत मन आख़िरकार दिखता है।"},"ICON-0110":{"nm":"कंघी","de":"जैसे उलझे बालों को एक-एक लट सुलझाया जाता है, वैसे ही अस्त-व्यस्त दिन भी धीरे-धीरे सँवर जाता है। आईने के सामने दिया गया एक छोटा-सा स्पर्श, बालों के परे मन की सिलवटों को भी चुपके से ठीक कर देता है।"},"ICON-0111":{"nm":"पिंजरा","de":"दरवाज़ा पूरी तरह खुला होने पर भी न उड़ने वाली, गाती रहने वाली एक चिड़िया होती है। बंद होने के कारण नहीं, बल्कि रुके रहने की इच्छा से टिकने वाला मन—इस महीन फ़र्क को यह पिंजरा सबसे पहले पहचान लेता है।"},"ICON-0112":{"nm":"हैंड वार्मर","de":"सर्दियों में मंच के बाहर लगी कतार में, जेब के भीतर की छोटी-सी गर्माहट सुन्न उँगलियों को धीरे से सेंकती है। ठंड में काँपती तुम्हें सोचकर किसी ने पहले से हिलाकर गर्म रखी हुई, हथेली भर की स्नेहमयी चीज़ है यह।"},"ICON-0113":{"nm":"रूमाल","de":"आँसू और पसीना दोनों बिना शिकायत सोख लेने वाला एक टुकड़ा कपड़ा। कोने में छोटी-सी कढ़ाई वहाँ सुंदरता से टिकी रहती है, जैसे पहले विदा हो चुके किसी ने छोड़ा आख़िरी संदेश हो—मुझे मत भूलना।"},"ICON-0114":{"nm":"स्प्रे","de":"एक बार छिड़कते ही हवा का ताना-बाना पल भर में बदल जाता है। मंच पर फैलती धुंध हो या सुबह खिड़की के पास का पौधा—इन महीन बूँदों के भीतर वे क्षण भर के लिए एक अलग ही दुनिया बनकर चमक उठते हैं।"},"ICON-0115":{"nm":"सुगंध पट्टी","de":"खुशबू चुनना, न जाने क्यों, किसी याद को चुनने जैसा ही लगता है। एक पतले काग़ज़ की नोक पर हल्की-सी टिकी सुगंध की एक लकीर, भूल चुके किसी मौसम को धीरे से नाक तक वापस ले आती है।"},"ICON-0116":{"nm":"मेज़","de":"लकड़ी की हर घिसी हुई रेखा में साथ बाँटे गए भोजनों की गिनती चुपचाप उकेरी हुई है। शोरगुल भरी शामें हों या अकेले बिताई देर रातें—इस चौकोर सतह ने बिना कुछ कहे सब कुछ अपने भीतर समेटा और चमकदार होती चली गई।"},"ICON-0117":{"nm":"धागे की गड्डी","de":"एक सिरा हल्के से खींचो तो सुलझता चला जाता है, एक टाँका लगाओ तो फिर से जुड़ जाता है। जो टूट गया हो उसे जोड़ने का काम हमेशा इसी तरह, एक पतले धागे से चुपचाप शुरू होता है।"},"ICON-0118":{"nm":"रेनकोट","de":"मूसलाधार बारिश में भी बाहर निकलने पर मजबूर कर देने वाली यही एक पोशाक है। बारिश में छपाक-छपाक चलने का सुख जानने वाले ही बारिश को बहाना बनाकर घर में नहीं बैठते।"},"ICON-0119":{"nm":"थैली","de":"मुँह को गोल समेटते ही उसके भीतर की चीज़ आख़िरकार सुरक्षित हो जाती है। एक छोटे, हाथ से घिसे थैले में सिक्के, किसी दिन की याद, और अंत तक न कह पाई बात—सब साथ हिलते-डुलते रहते हैं।"},"ICON-0120":{"nm":"किताबों की अलमारी","de":"पंक्तिबद्ध पुस्तकों की रीढ़ पर उँगली धीरे-धीरे फेरो तो बीत चुके मौसम उँगलियों तक महसूस होने लगते हैं। पढ़ी हुई किताब को फेंक न पाना इसलिए है, क्योंकि वहाँ उस वक़्त का 'मैं' अब भी जी रहा है।"},"ICON-0121":{"nm":"किताबों का ढेर","de":"पढ़ी हुई किताबें बगल में लिटा दी जाती हैं, अनपढ़ी किताबें ऊपर चढ़ती जाती हैं। कभी न कभी सबको पढ़ लेने का वादा छत के पास हिलता-डुलता रहे, फिर भी उस हिलने से भी प्यार होता है, तभी तो आज फिर एक किताब और ऊपर रख दी जाती है।"},"ICON-0122":{"nm":"चक्र","de":"पूरी ताक़त से दौड़ने पर भी जैसे वहीं के वहीं रहना लगे, पर छोटे पैर पहले पंजों की लय सीख रहे होते हैं। न रुके कल इकट्ठे होकर, एक दिन असली राह पर उजले होकर चमकते हैं।"},"ICON-0123":{"nm":"कवर","de":"धूल न जमे, धूप में रंग न उड़े—इसके लिए ढकने के काम में भी उँगलियों की मेहनत लगती है। जिस चीज़ से जितना प्यार हो, वह अनदेखी जगहों में उतनी ही स्नेह से सुरक्षित रहती है।"},"ICON-0124":{"nm":"ऊन का धागा","de":"दादी की गोद से लुढ़कता हुआ खुलता एक धागा। उलझा हुआ दिखे तो भी सिरा ढूँढ़कर हल्के से खींचो, वह बिना चूके साथ आ जाता है। सर्दी की रातें इसी तरह एक-एक बखिया करके लंबी होती चली गईं।"},"ICON-0125":{"nm":"पाउच","de":"लिप बाम, बाल-बंद, करीने से मुड़ा एक पत्र—छोटा दिखता है, पर उसके भीतर एक दिन भर का मन समाया होता है। ज़िप बंद होने की आवाज़ के साथ ही, सारी प्यारी छोटी-मोटी चीज़ें एक साथ सुरक्षित हो जाती हैं।"},"ICON-0126":{"nm":"आर्मरेस्ट","de":"किताब पढ़ते-पढ़ते सो गई दोपहर, फ़ोन पर बात करते हुए टहली गई शाम। जितनी देर बैठो, उतना ही गहरा होता जाने वाली इस जगह में, कोहनी को याद रहने वाला हर आराम एक बित्ते भर चुपचाप जमा हो गया।"},"ICON-0127":{"nm":"पैक","de":"खोलने से पहले तक यह अभी किसी का नहीं होता। सील बंद इस पैकेट में बिना खुली उम्मीदें भरी होती हैं, इसलिए कोना पकड़े उँगलियाँ हल्के से काँप उठती हैं। यही तो खोलने की रोमांचकता है।"},"ICON-0128":{"nm":"गिफ्ट रैपिंग पेपर","de":"उपहार से एक कदम पहले पहुँचने वाला मन। कोनों को मिलाकर मोड़ते और रिबन से बाँधते समय, पाने वाले का मुस्कुराता चेहरा हाथों में पहले ही चमकीला होकर खुल जाता है।"},"ICON-0129":{"nm":"गेमपैड","de":"अँगूठे को दिमाग़ से पहले याद रहने वाले बटन। हार गए तो भी बस एक राउंड और—और वही एक राउंड आख़िर में पूरी रात जगा देता है। हाथ में ठीक बैठने वाला वज़न आज रात के रोमांच को धीरे से उठा लेता है।"},"ICON-0130":{"nm":"सिग्नल","de":"लाल यानी थोड़ी देर रुको, हरा यानी अब जा सकते हो। एक साधारण से वादे से अनगिनत रास्ते बिना उलझे बहते रहते हैं। इंतज़ार का भी क्रम होता है, यह टिमटिमाती रोशनी प्यार से बता देती है।"},"ICON-0131":{"nm":"तीर चिह्न","de":"रास्ता भूल चुके व्यक्ति के लिए सबसे स्नेहिल आकृति। कहाँ जाना है, यह समझ न आने पर, किसी ने पहले खींचा हुआ एक दिशा-चिह्न रुके हुए क़दमों को फिर से मज़बूत बना देता है।"},"ICON-0132":{"nm":"निर्देशांक","de":"दो संख्याओं से दुनिया में कहीं भी ठीक जगह ढूँढ़ी जा सकती है। मिलने का तय स्थान, ख़ज़ाना गाड़ी गई रेत की पट्टी। वादा राह न भटके, इसके लिए एक छोटा बिंदु आख़िर तक थामे रहता है।"},"ICON-0133":{"nm":"टाइल","de":"अकेले में यह बस एक चौकोर टुकड़ा है। कंधे से कंधा मिलाकर साथ लेटते ही यह फ़र्श बन जाता है और दीवार भी। छोटी चीज़ें मिलकर किसी के निश्चिंत होकर पैर रखने की जगह बनाती हैं।"},"ICON-0134":{"nm":"रेत घड़ी","de":"ऊपर का हिस्सा खाली होते ही नीचे का हिस्सा धीरे-धीरे भरता जाता है। धीरे-धीरे बहती रेत देखकर हम मान लेते हैं कि समय बीत रहा है। पलट दो तो फिर से शुरुआत—यही रेत का प्यारा-सा झूठ है।"},"ICON-0135":{"nm":"गेंद","de":"फेंको तो वापस आ जाती है, मारो तो लुढ़क जाती है। गोल होने के कारण कहाँ उछलेगी, पता न होना ही इसका सबसे बड़ा आकर्षण है। खेल के मैदान के बीचोबीच, हँसी हमेशा इसी छोटी गोल आकृति से गोल-गोल शुरू हुई।"},"ICON-0136":{"nm":"स्विच","de":"क्लिक—एक दबाव में जल उठता है, एक दबाव में बुझ जाता है। अंधेरे कमरे में क़दम रखते हुए दबाई गई वह छोटी-सी आवाज़, बिखरे हुए दिन की शुरुआत और अंत को एक स्पष्ट रेखा में बाँट देती है।"},"ICON-0137":{"nm":"प्रश्न चिह्न","de":"जवाब न मालूम होना शर्म की बात नहीं है। यह तो इस बात का सुखद प्रमाण है कि जिज्ञासा अभी भी ज़िंदा है। जब यह छोटा-सा हुक मन को टक-टक थपथपाता है, तभी सीखने का पहला क़दम उठता है।"},"ICON-0138":{"nm":"माचिस की तीली","de":"खुद को रगड़कर आग सौंपने वाली एक तीली। थोड़ी देर जलकर चुपचाप बुझ जाती है, पर उस थोड़े-से पल में मोमबत्ती जल उठती है और चूल्हा गर्म हो जाता है। एक छोटा-सा त्याग गर्माहट का पहला बटन बन जाता है।"},"ICON-0139":{"nm":"स्टूल","de":"एक पैर ऊपर रखते ही न पहुँचने वाले शेल्फ़ तक भी हाथ पहुँच जाता है। किसी के क़द को पल भर के लिए बढ़ा देने का काम। नीचे झुककर हमें धीरे से ऊँचा उठाने वाली स्नेहिल जगह यहाँ है।"},"ICON-0140":{"nm":"कलाई घड़ी","de":"व्यायाम करने का फ़ैसला किए दिन कलाई पर सबसे पहले बाँधी गई चीज़। दिल की धड़कन और क़दमों को गिनने वाला छोटा-सा कोच, आज कल से थोड़ा ज़्यादा चला—यह टक-टक करके बता देता है।"},"ICON-0141":{"nm":"अलार्म","de":"हर सुबह नफ़रत झेलने वाला सबसे वफ़ादार दोस्त। रज़ाई में पाँच मिनट और की ललक से हर बार अपनी जगह लड़ने की बदौलत, न वादे देर होते हैं, न सपने। बेरहमी से बजने वाली वह आवाज़ असल में हौसला ही है।"},"ICON-0142":{"nm":"कोर","de":"बाहरी सब कुछ उतारने के बाद आख़िर तक बचा रहने वाला सबसे भीतरी हिस्सा। सेब का बीज हो या दिल की सच्चाई—किसी भी चीज़ के ठीक बीचोबीच सबसे मज़बूत चीज़ छिपी होती है। हिलने पर भी आख़िर तक टिका रहने वाला एक बिंदु है यह।"},"ICON-0143":{"nm":"पेन","de":"स्याही सूखने से पहले हाथ के किनारे पर हल्के से फैल जाने वाला निशान। लिखावट अच्छी बने या न बने, सफ़ेद काग़ज़ के सामने खींची पहली लकीर में हमेशा थोड़ी हिम्मत लगती है। यह विचार को उँगलियों तक पहुँचाने वाला पुल है।"},"ICON-0144":{"nm":"कूँची","de":"स्याही सोखकर हानजी काग़ज़ पर से गुज़रते समय, हिचकिचाहट का एक कंपन भी पूरी तरह उभर आता है। जल्दी लिखने का लालच करो तो तुरंत पकड़ में आ जाता है। कूँची उँगलियों में बसी ईमानदारी को सबसे पहले पहचान लेती है।"},"ICON-0145":{"nm":"संवाद बुलबुला","de":"शब्द मुँह से बाहर आने से पहले, सिर के ऊपर पहले गोल आकार में उभरने वाली जगह। कहने वाली बात यहीं समाई होती है। जब यह खाली हो, तो यह इस बात पर सोच-विचार कर रहा होता है कि इसमें क्या भरा जाए।"},"ICON-0146":{"nm":"चेकबॉक्स","de":"खाली चौकोर पर दो रेखाएँ खींच दो तो मन काफ़ी हल्का हो जाता है। पूरा किए काम पर खुद को दिया गया एक छोटा-सा तमगा। दिन के अंत में भरे हुए खानों को देखकर हम आश्वस्त होते हैं कि आज भी अच्छे से जिए।"},"ICON-0147":{"nm":"टैबलेट","de":"उँगली जहाँ छूती है, वहीं चित्र फैलते हैं और अक्षर बहते हैं। गोद में चुपचाप रख दो तो एक पूरी दुनिया रोशन हो उठती है। हल्का ज़रूर है, पर इसमें समाई संभावना कभी हल्की नहीं होती।"},"ICON-0148":{"nm":"रिमोट","de":"सोफ़े की दरारों में छिप जाने की जन्मजात प्रतिभा इसमें है। चैनल बदलने की ताक़त हमेशा इसे थामने वाले की होती है। परिवार के बीच सबसे छोटी और सबसे प्यारी नोकझोंक इसी एक बित्ते भर जगह पर होती है।"},"ICON-0149":{"nm":"संतुलन-भार","de":"हिलती चीज़ को थामने के लिए खुद सबसे नीचे उतर आया भार। ऊपर जितना भी हिले, नीचे भारी हो तो आख़िर में गिरता नहीं। संतुलन हमेशा अनदेखी जगह में डटा रहता है।"},"ICON-0150":{"nm":"पहेली","de":"आख़िरी बचे टुकड़े को ढूँढ़ने के लिए सोफ़े के नीचे तक टटोली गई रात। ठीक जगह बैठने के पल का वह ख़ामोश सुख। बिखरे हुए टुकड़े जब अपनी जगह पाते हैं, तभी आख़िरकार तस्वीर पूरी होती है।"},"ICON-0151":{"nm":"स्केल","de":"लंबाई नापना एक तरह से वादा निभाने का काम भी है। एक बित्ता सबके लिए एक-सा रहे, इसके लिए निशान ईमानदारी से एक कतार में लगते हैं। एक सीधी लकीर टेढ़े मन को भी सीधा कर देती है।"},"ICON-0152":{"nm":"कैनवास","de":"कुछ भी न होने वाला सफ़ेद तल सबसे ज़्यादा डरावना है, और सबसे ज़्यादा रोमांचक भी। पहला बिंदु रखने से पहले तक यह कुछ भी बन सकता है। खालीपन अंत नहीं, बल्कि शुरुआत का दूसरा नाम है।"},"ICON-0153":{"nm":"क्यूब","de":"छह तलों को मिलाने की कोशिश में पूरी रात जागने वाले लोग कम नहीं हैं। घुमाते और फिर घुमाते उँगलियों की वह ज़िद। बिखरे हुए रंग जब अपनी जगह पाते हैं, तभी एक छोटा-सा ब्रह्मांड करीने से सज जाता है।"},"ICON-0154":{"nm":"पॉकेट गेम कंसोल","de":"छुट्टियों में चचेरे भाई-बहनों के साथ सिर जोड़कर देखी जाने वाली छोटी-सी स्क्रीन। हथेली में समा जाने वाली रोमांच की दुनिया। पावर ऑन होने की धुन की बस एक कड़ी सुनते ही, वह पूरा गर्मी का मौसम एक साथ लौट आता है।"},"ICON-0155":{"nm":"पकड़","de":"कसकर पकड़ने पर हाथ में अच्छी तरह बैठ जाने वाला वह एहसास धीरे से आत्मविश्वास सौंप देता है। ताकि फिसले नहीं, ताकि छूटे नहीं। सबसे अहम पल में हाथ और औज़ार को एक मज़बूत इकाई में बाँधने वाली कड़ी है यह।"},"ICON-0156":{"nm":"फाउंटेन पेन","de":"स्याही भरकर लिखते समय लिखावट भी थोड़ी और सलीक़ेदार हो जाती है। निब की सरसराहट सुनकर मन को सँभालते हुए, हाथ से लिखे पत्र की पहली पंक्ति धीरे-धीरे शुरू करने वाली उस मेहनत को यह चुपचाप याद दिलाता है।"},"ICON-0157":{"nm":"रंग पट्टिका","de":"लाल के बगल में नीला, पीले के ऊपर हरा। रंगों के करीने से लेटे इस छोटे तख़्ते पर, तस्वीर को आख़िरकार अपना भाव मिलता है। मिलाने और परतें चढ़ाने का हर रोमांच यहीं से पहला क़दम उठाता है।"},"ICON-0158":{"nm":"सेट","de":"हर एक टुकड़ा साधारण भले हो, साथ मिलकर वे एक पूरी कहानी बन जाते हैं। कोई टुकड़ा न छूटे और सब कुछ मौजूद हो, तब मिलने वाला वह भरोसा। बिखरी हुई चीज़ों को एक जगह जुटाने के काम में पूर्णता की एक छोटी-सी खुशी छिपी होती है।"},"ICON-0159":{"nm":"शटलकॉक","de":"रैकेट से टकराकर ऊपर उठते समय पंखों से निकलने वाली मुलायम हवा की आवाज़। हल्का होने के कारण दूर न जा पाएगा ऐसा लगे, पर मन लगाकर मारो तो कोर्ट के आख़िरी छोर तक सीधा उड़ जाता है। हल्कापन भी अपने आप में एक ताक़त है।"},"ICON-0160":{"nm":"एंटीना","de":"अदृश्य संकेत पकड़ने के लिए चुपचाप आसमान की ओर खड़ा रहता है। दूर की आवाज़ों को भी आख़िर खींच लाने वाला वह धैर्य। ठीक से सुनाई न दे तो कोण ज़रा-सा बदल दो, फिर से साफ़ हो जाता है।"},"ICON-0161":{"nm":"स्टेथोस्कोप","de":"सीने पर ठंडी छूती गोल नोक, और पल भर के लिए थमी हुई साँस। एक छोटी-सी धड़कन पर कान लगाओ तो जीवित होने की सबसे पुरानी लय उँगलियों तक पहुँच जाती है। सुनना जिसमें सबसे पहले आता है, वह औज़ार है यह।"},"ICON-0162":{"nm":"प्यादा","de":"धीरे-धीरे, एक-एक घर चलने वाला छोटा-सा मोहरा। फिर भी आख़िरी पंक्ति तक पहुँचते ही यह कुछ भी बन सकता है। बोझिल क़दम से पूरी बाज़ी पलट देने वाली उस एक चाल को, पुरानी शतरंज की बिसात चुपचाप देखती रह जाती है।"},"ICON-0163":{"nm":"कंट्रोलर","de":"दो अँगूठों से ब्रह्मांड नाप ली उन रातों को याद है? हारकर फेंक दी और फिर शर्माते हुए उठाई गई हाथ से घिसी ग्रिप। स्क्रीन के पार किसी के साथ बिना शब्दों के बाँटी गई, सबसे लंबी और सबसे गर्मजोश बातचीत।"},"ICON-0164":{"nm":"गेम कंसोल","de":"पावर ऑन करते ही एक छोटी-सी बूट धुन अभिवादन की तरह गूँज उठती है। पूरी छुट्टियों भर रज़ाई के भीतर जलाया-बुझाया जाने वाला चौकोर बक्सा—बचपन का पहला रोमांच हमेशा इसी स्क्रीन की रोशनी से शुरू हुआ।"},"ICON-0165":{"nm":"टाइमलाइन","de":"बायाँ छोर शुरुआत है, दायाँ छोर अभी न आया दिन। बीच में कहीं भी एक बिंदु खींचकर रख दो, भूल चुका समझा कोई पल फिर से खुल जाता है। समय को एक ही रेखा में लिटा देने वाली जगह है यह।"},"ICON-0166":{"nm":"प्रिज्म","de":"बस साफ़ लगने वाली रोशनी असल में सात रंग समेटे हुए थी, यह सोचकर हैरानी होती है। काँच के एक टुकड़े से गुज़रते ही इंद्रधनुष बनकर खुल जाने वाला भेद। जो चीज़ जितनी सुघड़ दिखे, उसके भीतर उतने ही ज़्यादा रंग छिपे होते हैं।"},"ICON-0167":{"nm":"गोल्फ़ टी","de":"गेंद को चुपचाप टिकाए रखने वाला एक छोटा-सा आधार। जितना दूर भेजना हो, उतना ही पहले मज़बूती से थामने वाली किसी चीज़ की ज़रूरत होती है। घास पर यह छोटी-सी कील पहला क़दम थाम लेती है।"},"ICON-0168":{"nm":"बुनाई की सलाई","de":"एक फंदा, फिर एक और फंदा। एक भी छूट जाए तो सब खोलकर शुरुआत पर लौटना पड़ता है। एक सर्दी के मौसम में गोद पर धीरे-धीरे लंबा होता मफ़लर—वह जगह जहाँ उँगलियों का धैर्य गर्माहट में बुना गया।"},"ICON-0169":{"nm":"धुन की पंक्ति","de":"बोल चढ़ने से पहले, होंठों से गुनगुनाते हुए फिसल पड़ी एक कड़ी। अभी शब्दों से न जुड़ी उस धुँधली धुन में, गीत का सबसे ईमानदार पहला चेहरा छिपा होता है।"},"ICON-0170":{"nm":"रडार","de":"न दिखने वाले अंधेरे की ओर संकेत भेजकर, लौटते हुए एक बिंदु का चुपचाप इंतज़ार करता है। कुछ भी न दिखे तो भी वहाँ कुछ है, यह मानने वाला, गोल हरी रोशनी का धैर्य।"},"ICON-0171":{"nm":"रिदम पैड","de":"टक-टक, हल्के से थपथपाओ तो रोशनी और आवाज़ एक साथ उछल पड़ते हैं। ताल को दिमाग़ से पहले हाथों को याद कराने वाली जगह। हथेली पर बिछा हुआ, सबसे छोटा और सबसे प्यारा मंच है यह।"},"ICON-0172":{"nm":"रंग","de":"पुराने चित्रकार पत्थर और मिट्टी घिसकर रंग निकालते थे। नील घास से, लाल मिट्टी से। अभी उँगलियों पर निचोड़ी गई इस एक बूँद में भी, प्रकृति को सहेजकर उतारने की वह पुरानी मेहनत बहती है।"},"ICON-0173":{"nm":"रेखा","de":"बिंदु से बिंदु जोड़ने का मन बनाते ही, तभी जन्म लेने वाली चीज़। छोटी हो या लंबी, टेढ़ी हो या सीधी, कहीं जा पहुँचने की इच्छा का सबसे सरल छूट गया निशान है यह। हर तस्वीर की शुरुआत।"},"ICON-0174":{"nm":"शटर","de":"क्लिक, वह छोटा-सा एक पल का अंधेरा एक दृश्य को हमेशा के लिए थाम लेता है। पलक झपकते ही बह जाने वाला कोई भाव भी, रोशनी को ज़रा-सा काटकर याद में जमा देने वाला छोटा-सा ब्लेड है यह।"},"ICON-0175":{"nm":"सुरक्षा रस्सी","de":"ऊँचाई पर चढ़ने वाले व्यक्ति से एक क़दम पहले मज़बूती से बाँधी जाने वाली रस्सी। गिरने के डर से घबराए मन को इसके बदले थामकर, अनदेखे ही साथ खड़े रहने वाला वादे का धागा। यह हमेशा पीठ पीछे रहता है।"},"ICON-0176":{"nm":"ताला","de":"भंडार पर लगाया जाने वाला भारी लोहे का ताला। किसी को क़ैद करने के लिए नहीं, बल्कि प्रिय चीज़ को निश्चिंत होकर रखने की इच्छा से। बंद करने वाले हाथ में भी मेहनत बसती थी, पुराने घर की वह मज़बूती।"},"ICON-0177":{"nm":"तराज़ू","de":"एक पलड़ा भारी हो तो दूसरा अपने आप हल्का हो जाता है। क्या और कितना रखा जाए, इस हिचकिचाहट के पल में इंसान निष्पक्षता सीखता है। डगमगाकर संतुलन सिखाने वाली दो भुजाएँ।"},"ICON-0178":{"nm":"विभाजक","de":"कसकर जुड़ी चीज़ भी रेशे के सहारे चलो तो आख़िरकार अलग हो ही जाती है। किसी भी चीज़ को दो भागों में बाँटकर भीतर झाँकने वाला एक छोटा औज़ार। जुड़ी हुई चीज़ को फिर से खोलकर देखने की चाहत रखने वाली, जिज्ञासु उँगलियाँ।"},"ICON-0179":{"nm":"गिनती-यंत्र","de":"एक, दो, तीन। उँगलियों की जगह चुपचाप संख्याएँ गिनने वाला छोटा-सा दोस्त। कोई गिनती छूट न जाए, इस घबराहट को टक-टक करके निश्चिंतता में बदल देने वाला गिनती का प्यारा साथी।"},"ICON-0180":{"nm":"कर्सर","de":"स्क्रीन पर कहीं टिमटिमाते हुए अगले आदेश का इंतज़ार करता एक छोटा तीर। हिचकिचाहट के दौरान भी वह अपनी जगह नहीं छोड़ता, चलो अब शुरू करें, चुपचाप इशारा करती रोशनी की नोक।"},"ICON-0181":{"nm":"होल्ड","de":"उँगलियों की ताक़त पूरी तरह खत्म होने से ठीक पहले, आख़िरी बार थामा जाने वाला वह एक बिंदु। न छोड़ूँगा, इसी एक इरादे पर टिके रहने के पल होते हैं, दीवार पर लगा यह छोटा उभार चुपचाप बता देता है।"},"ICON-0182":{"nm":"गोलपत्थर","de":"नदी में लंबे समय लुढ़कते हुए अपने सारे कोने छोड़ देने वाला पत्थर। गोल हो जाना, घिस गए समय का दूसरा नाम है। हथेली में चुपचाप थामो तो बहती नदी का धैर्य महसूस होता है।"},"ICON-0183":{"nm":"कुल-चिह्न","de":"पुराने कुल एक ध्वज पर पशु और तारे उकेरकर खुद को पहचान दिलाते थे। शब्दों से पहले मन पहुँचाने वाली एक तस्वीर। एक व्यक्ति के गौरव को एक छोटे खाने में संजोकर समेटा गया, पुराना निशान।"},"ICON-0184":{"nm":"ढाल","de":"आड़े आना हमेशा पीठ पीछे खड़े व्यक्ति के लिए होता था। उड़ते तीरों को खुद पर लेकर किसी के मामूली दिन की रक्षा करने वाली, भारी पर स्नेहिल दीवार।"},"ICON-0185":{"nm":"पुनर्जीवन","de":"बुझकर फिर से जल उठने वाला एक मन होता है। एक बार गिरकर ही आख़िरकार सीखने को मिलता है, फिर से उठने का तरीक़ा। जिसे अंत समझा गया, उसी जगह चुपचाप भर आने वाली दूसरी साँस।"},"ICON-0186":{"nm":"धनुष","de":"दूर तक भेजने की चाह रखने वाला हाथ पहले डोरी को पूरी तरह खींचता है। छोड़ने के लिए उतना ही पास भींचना पड़ता है, यह बात कसकर मुड़ी धनुष की लकड़ी चुपचाप बिना कहे बता देती है।"},"ICON-0187":{"nm":"दिल का चिह्न","de":"पसंद है, यह बात बार-बार सिकुड़कर एक छोटे आकार में बदल जाती है। लाइटस्टिक की नोक पर भी, आपस में जुड़ी उँगलियों के बीच भी हल्के से उभर आने वाला यह आकार। मन का सबसे आम और सबसे ईमानदार संक्षिप्त रूप।"},"ICON-0188":{"nm":"बादल","de":"हवा की दिशा में धीरे-धीरे बहते हुए हर बार अलग चेहरा बन जाता है। कभी खरगोश, कभी रुई—किसी को भी देर तक न थामे, सब कुछ बहा देने वाला आसमान का सबसे हल्का मन।"},"ICON-0189":{"nm":"भूलभुलैया","de":"बंद दीवार के सामने मुड़कर लौटना सीखने की जगह। भटकते हुए भी क़दम धीरे-धीरे निकास की ओर बढ़ते जाते हैं। एक बार रास्ता भटकना ज़रूरी है, तभी दिशा की समझ खुलती है।"},"ICON-0190":{"nm":"दाँत","de":"टूटा हुआ दाँत छत पर फेंकने की एक रीत हुआ करती थी। नया दाँत सीधा निकले, यह एक छोटी सी प्रार्थना। बड़े होते हुए एक बार कुछ खोना पड़ता है, तभी उससे मज़बूत कुछ मिलता है—बचपन का यह स्नेहिल वादा।"},"ICON-0191":{"nm":"ग्रह","de":"कभी अपनी राह से हटे बिना तारे की परिक्रमा करने वाला गोल पिंड। अकेला दिखे तो भी हमेशा पास किसी को साथ घुमाने वाला गुरुत्वाकर्षण। चुपचाप अपनी जगह टिके रहना ही आख़िर एक दुनिया बन जाता है।"},"ICON-0192":{"nm":"तारा","de":"रास्ता भटक चुकी रातों में लोग सबसे चमकीले बिंदु की ओर देखते थे। न पहुँच पाने लायक़ दूर होकर भी दिशा साफ़-साफ़ बता देने वाली रोशनी। दूर होने के कारण ही और मज़बूत होता जाने वाला वादा।"},"ICON-0193":{"nm":"छायाकृति","de":"रोशनी की ओर पीठ करके खड़े होते ही इंसान का बस रूपरेखा बचता है। नाम और भाव दोनों मिटी हुई एक काली आकृति। खाली होने के कारण ही और भी ज़्यादा कल्पना करने पर मजबूर करने वाली, न भरी हुई जगह।"},"ICON-0194":{"nm":"कान","de":"अच्छा गाने के लिए पहले अच्छा सुनना ज़रूरी है। ताल हो या मन, आख़िर सब सुनने से ही शुरू होता है। दुनिया की हर आवाज़ जहाँ सबसे पहले पहुँचकर ठहरती है, वह गोल खुला छोटा दरवाज़ा।"},"ICON-0195":{"nm":"गिरा हुआ पत्ता","de":"गिरने के उसी पल में सबसे सुंदर चमकने वाले पत्ते होते हैं। एक मौसम की हरियाली को लाल रंग में पूरी तरह जलाकर, धीरे से नीचे रख देने वाला हल्कापन। अंत भी इतना सुंदर हो सकता है, यह पतझड़ दिखा देता है।"},"ICON-0196":{"nm":"चाँद","de":"पूर्णिमा की गोल रोशनी तले दोनों हाथ जोड़कर मन्नत माँगी गई रातें हुआ करती थीं। घटता-बढ़ता हुआ, कभी एक जैसा न रहने वाला चेहरा। बदलते हुए भी हमेशा उसी जगह को रोशन करने वाला दीया।"},"ICON-0197":{"nm":"दिल","de":"मंच पर भी सबसे ईमानदार चीज़ आख़िर यही धड़कन है। काँपते हुए भी न रुकना, और भर आने पर और ज़ोर से धड़कना। शब्दों से पूरी न हो सकी हौसलाअफ़ज़ाई को अपनी धड़कन से जताने वाला, छोटा लाल ढोल।"},"ICON-0198":{"nm":"परछाईं","de":"रोशनी जब तक है, कभी न बिछड़ने वाला साथी। जितना उजाला हो उतनी गहरी और जितना धुंधलका हो उतनी हल्की होने वाली, मुझे सबसे लंबे समय तक साथ देने वाली एक और मैं। अकेले दिनों में भी साथ खड़ा एक व्यक्ति।"},"ICON-0199":{"nm":"पूँछ","de":"खुशी में अपने आप हिल उठती है, डर में चुपके से सिमट जाती है। मुँह कसकर बंद रखो तो भी आख़िर मन न छिपा पाने वाला ईमानदार सिरा। शरीर जिससे मन सबसे पहले उजागर करता है।"},"ICON-0200":{"nm":"पूँछ की डोरी","de":"फीते की तरह सिरे पर बाँधकर समेटने वाली एक छोटी डोरी। खुल न जाए, इसलिए एक बार और मज़बूती से गाँठ बाँधा हुआ मन। बिखरने में आसान चीज़ों को एक साथ जोड़कर सँभाल कर रखने वाला, स्नेहिल बंधन।"},"ICON-0201":{"nm":"पुतली","de":"शब्द तो चुने जा सकते हैं, पर आँखों की चमक छिपाई नहीं जा सकती। पकड़ में आए दिल का सबसे पहला रिसाव जहाँ से होता है, उस काले घेरे के भीतर। पसंद है कहना निगल भी लो, तो भी पुतलियाँ पहले ही तुम्हारी ओर काँपने लगती हैं।"},"ICON-0202":{"nm":"घोड़े की नाल","de":"लंबे रास्तों पर दौड़ते-दौड़ते जितना पैर की नोक घिसती गई, उतना ही मज़बूत होता गया लोहे का यह टुकड़ा। दरवाज़े पर उल्टा टाँग दो तो आते-जाते सौभाग्य उसी में जमा हो जाते हैं, कहते हैं। किसी के सही-सलामत घर लौटने को यह चुपचाप सहारा देता है।"},"ICON-0203":{"nm":"कुल-चिह्न पत्थर","de":"हवा-बारिश अक्षरों को धुंधला कर भी दें, तो भी उंगलियों से टटोलने पर उकेरी हुई रेखाएँ फिर से स्पष्ट जी उठती हैं। भुलाया न जाना चाहने वाले किसी मन का भार। पत्थर इस तरह एक नाम को लंबे समय तक सँजोए रखता है।"},"ICON-0204":{"nm":"जालीदार पैर","de":"पैर की उँगलियों के बीच जुड़ी एक पतली झिल्ली से पानी को धकेलना सीखा जाता है। तैरने में अनाड़ी किसी को प्रकृति ने चुपके से थमाया एक नन्हा चप्पू। धीमा ही सही, आख़िर नदी के उस पार पहुँचा देने वाला यह एक स्नेहिल रचना है।"},"ICON-0205":{"nm":"चमकी","de":"हाथ पर लग जाए तो कई दिनों तक पीछा नहीं छोड़ती, सब यही शिकायत करते हैं, फिर भी उत्सव के दिन सबसे पहले इन्हीं चमकीले कणों को ढूँढ़ते हैं। तारों की धूल की एक मुट्ठी बिखेर दो तो साधारण काग़ज़ भी चमक उठता है, और आज ख़ास बन जाता है।"},"ICON-0206":{"nm":"पंजा","de":"जंगल का जानवर अपने पंजे से मिट्टी को खुरचकर अपना रास्ता छोड़ जाता है। यह धमकी नहीं, एक निशान है—यहाँ से गुज़रा था, इसका मौन हस्ताक्षर। एक तीखी नोक किसी के लिए स्नेहिल मार्गदर्शक चिह्न भी बन जाती है।"},"ICON-0207":{"nm":"बिजली","de":"आसमान जिस क्षण भर के लिए अपनी हथेली की रेखाएँ खोल दिखाता है, प्रकाश गरज से पहले पहुँच जाता है। मानो कह रहा हो कि बड़ी आवाज़ पहुँचने से पहले एक साँस भर लो। भय और विस्मय हमेशा उसी एक चमक से साथ-साथ जन्म लेते हैं।"},"ICON-0208":{"nm":"ताबीज़","de":"लाल काग़ज़ पर स्याही से गहराई से दबाकर लिखी गई एक कामना की पंक्ति। तकिए के नीचे रखने पर बुरे सपने टल जाते हैं, ऐसा माना जाता था। किसी की सलामती की दुआ माँगता मन इस पतले से काग़ज़ के एक टुकड़े में भी इतना गर्मजोश होता है।"},"ICON-0209":{"nm":"कूची-पंख","de":"कूची की नोक के पंख बन जाने के क्षण होते हैं। एक रेखा खींचते समय काग़ज़ पर फिसलती वह हल्की-सी अनुभूति। लिखना दरअसल उड़ना ही है, यह बात स्याही घोंटता वह पुराना हाथ धुंधले-से जानता रहा होगा।"},"ICON-0210":{"nm":"हड्डी","de":"माँस पूरी तरह गल जाने के बाद ही जो शेष रह जाता है। सबसे कठोर होने के कारण अंत तक टिकी रहने वाली वह श्वेत संरचना। समय सब कुछ अपने साथ ले जाए, फिर भी अंततः बस आकार को याद रखने वाला एक मौन प्रमाण।"},"ICON-0211":{"nm":"नाक","de":"गंध स्मृति तक पहुँचने का सबसे तेज़ छोटा रास्ता है। त्योहार की रसोई की तेल की महक, पहली बर्फ़ गिरने के बाद की सुबह की ठंडी हवा—नाक की नोक पहले पहचान लेती है और मन एक क्षण देर से पीछे-पीछे आता है।"},"ICON-0212":{"nm":"टोस्ट","de":"व्यस्त सुबह में सबसे जल्दी हाथ में आने वाला एक निवाला। सुनहरी सिकी सतह पर दाँत गड़ाओ तो दिन भर का साहस कुरकुरा होकर बिखर जाता है। भव्य न सही, पर पेट भरने वाली चीज़ें ही इंसान को फिर से खड़ा करती हैं।"},"ICON-0213":{"nm":"कुकी","de":"ओवन के आगे सबसे लंबा इंतज़ार करने वाले को ही पहला निवाला मिलता है। ताज़ा सिंकी किनार की गर्माहट, क्षण भर की मिठास। किसी को याद करते हुए पकाई गई कुकी अजीब तरह से और भी मीठी होती है।"},"ICON-0214":{"nm":"नाश्ता","de":"अभ्यास लंबा खिंचने वाली दोपहर में, बैग की गहराई से निकाला गया एक छोटा-सा पैकेट। आधा-आधा बाँटने पर तृप्ति अजीब तरह से दोगुनी हो जाती है। भूख से पहले मन को भरने वाली स्नेह की एक मुट्ठी।"},"ICON-0215":{"nm":"कैप्सूल","de":"घुमाकर खोलने से पहले कोई नहीं जान सकता। गोल खोल के भीतर जो है वह हमेशा वही एक-सी धड़कन है। एक छोटे संयोग को ख़रीदने-बेचने वाली, दुनिया की सबसे ईमानदार सिहरन।"},"ICON-0216":{"nm":"दरवाज़े का हत्था","de":"दरवाज़ा खोलने-बंद करने वाले अनगिनत हाथ जिस जगह को सबसे पहले छूते हैं। ठंडी शुरुआत से हथेली में गर्म होती हुई, यह घर की पहली अभिवादन है। हाथों के स्पर्श जितने जमा होते जाते हैं, वह कमरा उतना ही धीरे-धीरे किसी का घर बनता जाता है।"},"ICON-0217":{"nm":"सैर","de":"बिना किसी मंज़िल के चलने का भी एक कारण होता है। उलझे विचारों को क़दम-दर-क़दम सुलझाने का समय। एक चक्कर लगाकर लौटो तो जवाब वही रहता है, पर मन अकेला ही काफ़ी हल्का हो जाता है।"},"ICON-0218":{"nm":"स्कूटर","de":"तंग गलियों को चीरती हुई दौड़ती दो पहिए। तेज़ न सही, पर हवा को पूरे बदन से महसूस करती है। दूर न भी जाना पड़े, आज बस ठंडी हवा में खुलकर दौड़ लगाने का मन करता है, ऐसे दिन भी होते हैं।"},"ICON-0219":{"nm":"सेफ़्टी बार","de":"सवार होने से पहले, सीने के आगे मज़बूती से नीचे उतरने वाली एक आड़ी छड़। डरावने रास्ते को अंत तक साथ झेलने वाला एक भरोसेमंद वादा। कसकर पकड़ लो तो कोई हर्ज़ नहीं, यह ठंडे स्वर में बिना कुछ कहे बता देती है।"},"ICON-0220":{"nm":"सीढ़ियाँ","de":"एक-एक क़दम चढ़ते-चढ़ते कब नज़ारा बदल जाता है, पता ही नहीं चलता। एक साथ किसी ऊँचाई तक नहीं पहुँचा जा सकता, यह पैरों के तलवे पहले सीखते हैं। चढ़ना-उतरना ही, किसी के लिए एक दिन भर के क़दम रहे।"},"ICON-0221":{"nm":"टेरारियम","de":"यह काँच के भीतर जंगल क़ैद करना नहीं, बल्कि एक पूरी दुनिया को मन लगाकर पालना है। जहाँ काई फैलती है और पानी की बूँदें जमती हैं, ऐसा हथेली भर का ब्रह्मांड। जितना भीतर झाँको, मन उतना ही धीरे-धीरे हरे रंग में रंगता जाता है।"},"ICON-0222":{"nm":"मंच","de":"बित्ता भर ऊँची जगह पर चढ़ते ही दिखने वाला नज़ारा बदल जाता है। जहाँ भय और गर्व एक ही ऊँचाई पर आमने-सामने आते हैं। कौन खड़ा होता है, उसी के अनुसार वह एक पायदान हर बार एक अलग मंच बन जाता है।"},"ICON-0223":{"nm":"हवाई जहाज़","de":"बादल पैरों तले बिछने के क्षण, छोड़ी हुई जगह आख़िरकार याद आने लगती है। यह दूर होना नहीं, दुनिया का और विस्तृत होना है। एक छोटे टापू पर पला सपना भी इसी तरह आसमान पार करता है।"},"ICON-0224":{"nm":"स्केटबोर्ड","de":"गिरना सीखने के बाद ही जिस पर सवार हुआ जा सकता है, ऐसी एक चीज़। हर बार घुटना छिलने पर संतुलन थोड़ा-थोड़ा शरीर में उकेरा जाता है। जितना अच्छे से गिरो, उतनी ही दूर लुढ़कते जाने वाले, ईमानदार चार पहिए।"},"ICON-0225":{"nm":"पासपोर्ट","de":"कवर पलटते ही खाली पन्नों की भरमार दिखती है। भरने वाली हर एक मुहर आगे चलकर जिए हुए जीवन का प्रमाण बनती है। कितनी दूर जा चुके हो उससे ज़्यादा, कहीं भी जा सकने की संभावना समेटे हुए एक छोटी-सी किताब।"},"ICON-0226":{"nm":"हाथ से बना नक़्शा","de":"न सही दूरी है, न सही अनुपात, पर हाथ से बनाया रास्ता होने के कारण खोने का कोई डर नहीं। गली और दुकानों के नाम जिस पर आत्मीयता से उलझे हैं, ऐसा काग़ज़। दिल से दिया गया मार्गदर्शन रास्ते से भी पहले हमेशा गर्मजोशी भरा होता है।"},"ICON-0227":{"nm":"मंच संचालन चार्ट","de":"मंच पर हर एक क़दम को रेखा से खींचा गया काग़ज़। कहाँ रुकना है, कहाँ मुड़ना है, तीर पहले से यह वादा तय कर देते हैं। आज़ाद दिखने वाला नृत्य भी असल में इसी एक पन्ने से शुरू होता है।"},"ICON-0228":{"nm":"सीट गाइड","de":"अनजान जगह में सबसे पहले टटोलकर ढूँढ़ी जाने वाली चीज़ अपनी सीट होती है। पंक्ति और नंबर का पीछा करते हुए आख़िर पहुँचा वह एक ख़ाना। काग़ज़ का एक टुकड़ा हज़ारों सिहरनों को क़रीने से, हर एक को अपनी जगह बिठा देता है।"},"ICON-0229":{"nm":"गली मार्गदर्शक कार्ड","de":"भूलभुलैया-सी गलियों में रास्ता भटकने वाले के लिए किसी ने अपने हाथ से लिखा मार्गदर्शन। किस मोड़ पर मुड़ना है, यह बताती स्नेहिल लिखावट। मोहल्ले की इंसानियत एक छोटे कार्ड पर साफ़-साफ़ अंकित हुई है।"},"ICON-0230":{"nm":"सुरक्षा पास","de":"यह कार्ड गले में डालते ही भीतरी दुनिया का दरवाज़ा आख़िरकार खुलता है। प्रवेश की अनुमति देने वाला एक छोटा अधिकार, और यहाँ का हिस्सा होने का मौन प्रमाण। इसे पाने में लगा समय जो जानता है, वही इसका भार समझता है।"},"ICON-0231":{"nm":"डे रिस्टबैंड","de":"कलाई पर एक बार बाँध लो तो निकालने तक उस दिन के सदस्य बने रहते हो। काग़ज़ की एक पट्टी भीतर-बाहर को बाँट देती है और साथ बिताए उसी एक दिन का चिह्न बन जाती है। तोड़ देने के बाद भी उसका निशान काफ़ी देर तक रह जाता है।"},"ICON-0232":{"nm":"गेस्ट लेबल","de":"सीने पर चिपकाया गया एक छोटा नाम-पट्टा अनजान जगह को अपनी जगह बना देता है। “स्वागत है” शब्द जब काग़ज़ के एक टुकड़े पर सवार होकर सौंपा जाता है, तब पहली बार आया व्यक्ति भी आख़िरकार मेहमान बन जाता है।"},"ICON-0233":{"nm":"पोस्टर ट्यूब","de":"लपेटे हुए पोस्टर को बिना एक भी सिलवट के सुरक्षित रखने वाला मज़बूत बेलनाकार डिब्बा। जितनी क़ीमती तस्वीर हो, उतनी ही सीधी करके भेजनी पड़ती है न। भीतर दिखता नहीं, फिर भी किसी की मेहनत को समेटे यह रास्ते पर निकल पड़ता है।"},"ICON-0234":{"nm":"फ़ोल्डर कवर","de":"दस्तावेज़ों के मोटे बंडल को लपेटने वाला पहला पन्ना। सामग्री से पहले हाथ को छूने वाला चेहरा। कवर सलीक़ेदार हो तो भीतर की मनःस्थिति भी सलीक़ेदार लगती है, एक छोटी औपचारिकता की स्नेहिल शुरुआत।"},"ICON-0235":{"nm":"यादगार पोस्टकार्ड","de":"दूर के किसी दृश्य के एक टुकड़े पर हाल-चाल लिखकर भेजा जाता है। पहुँचने तक भेजा हुआ मन भी थोड़ा पुराना होकर और प्यारा लगने लगता है। स्क्रीन पर आया संदेश जिस तक कभी न पहुँच पाए, हाथ से लिखे पत्र की वह धीमी गर्माहट।"},"ICON-0236":{"nm":"गिफ़्ट टैग","de":"उपहार पर बाँधा गया काग़ज़ का एक छोटा टुकड़ा। “तुम्हारे लिए” इन तीन शब्दों से ही पैकिंग पहले ही पूरी हो जाती है। क्या दिया, उससे ज़्यादा किसे याद करते हुए दिया, यह लिखने वाला दुनिया का सबसे छोटा पत्र।"},"ICON-0237":{"nm":"पैकिंग स्टिकर रोल","de":"हर बार एक टुकड़ा फाड़कर लगाते ही अंतिम रूप कहीं ज़्यादा साफ़-सुथरा हो जाता है। खुलने को बेताब सिरे को सलीक़े से थाम लेने वाली एक छोटी गाँठ। मन लगाकर लपेटी गई पैकिंग की आख़िरी चाल हमेशा इसी लिपटी हुई पट्टी से निकलती है।"},"ICON-0238":{"nm":"पारदर्शी पत्र आवरण","de":"हाथ से लिखा पत्र समय के साथ फीका न पड़े, इसके लिए लपेटी गई एक पारदर्शी परत। अक्षर वैसे ही दिखते रहें, पर हाथों का मैल न पहुँचे। किसी के संजोए मन को एक अदृश्य झिल्ली चुपचाप बचाए रखती है।"},"ICON-0239":{"nm":"रंगीन सील","de":"लिफ़ाफ़ा बंद करने वाला आख़िरी बिंदु, रंग जितना गहरा हो उतना ही मन बाहर नहीं रिसता। फाड़े जाने तक किसी का हाथ न पहुँचा हो, ऐसा एक वादा। राज़ को भी ऐसी सुंदर गाँठ की ज़रूरत होती है।"},"ICON-0240":{"nm":"मैसेज टैग बुक","de":"छोटी-छोटी पर्चियों को एक साथ बाँधे एक नन्ही किताब। हर एक पन्ना किसी को सौंपे जाने वाला एक शब्द है। न कह सके शब्दों को धीरे-धीरे इकट्ठा करते रहो, तो कभी-न-कभी उन्हें पहुँचाने का साहस पनप ही जाता है।"},"ICON-0241":{"nm":"फ़ोल्डिंग साइनबोर्ड","de":"खोलो तो कहता है “इधर से”, मोड़ो तो कहता है “आज बस इतना ही”। गली के मुहाने पर टाँगें फैलाए खड़ा, रास्ता भटकने वाले किसी के लिए यह पूरा दिन डटा रहता है। मुड़ने वाली शाम मेरे लिए सबसे स्नेहिल विश्राम है।"},"ICON-0242":{"nm":"मेल बैंड","de":"पोस्टकार्ड्स के ढेर को कमर में बाँध लो तो बिखरने वाले हाल-चाल आख़िरकार मन के एक गुच्छे में बदल जाते हैं। एक हल्की-सी पट्टी दूर तक जाने वाले शब्दों को सलीक़े से बाँधकर, यात्रा पर निकलती पीठ को चुपचाप विदा देती है।"},"ICON-0243":{"nm":"धन्यवाद पर्ची बंडल","de":"“शुक्रिया” शब्द ज़ुबान से बार-बार फिसल जाता है, इसलिए हथेली भर के काग़ज़ पर लिखकर चुपचाप बाँध दिया जाता है। बंडल जितना मोटा होता जाता है, किसी के प्रति ऋणी मन की मोटाई भी उतनी ही साथ-साथ बढ़ती जाती है।"},"ICON-0244":{"nm":"चियर चैंट सैंपल शीट","de":"“इस तरह पुकारिए” लिखा एक नमूना पत्रक। जिस पर अभी आवाज़ नहीं चढ़ी, ऐसा प्रोत्साहन पहली ताल का इंतज़ार करते खाली स्वर-लेख की तरह चुपचाप बस सिहरन ही समेटे रहता है।"},"ICON-0245":{"nm":"प्री-रिकॉर्डिंग आवेदन पर्ची","de":"पूर्व-रिकॉर्डिंग बुक करवाने को लिखी गई पर्ची हमेशा सुबह पाँच बजे वाले ख़ाने में ठहरी रहती है। नींद कम करके जगह पाने की चाहत को, यह छोटा काग़ज़ मानो सब समझते हुए चुपचाप लिख लेता है।"},"ICON-0246":{"nm":"फ़ैनसाइन क्रम टिकट","de":"किस नंबर पर अभिवादन करना है, यह तय करने वाला एक पत्रक। क़तार में लगना अपनी बारी का इंतज़ार करना नहीं, बल्कि इतना पसंद करने वाले मन को नंबर न दे पाने के कारण थोड़ी देर के लिए एक क्रम उधार लेना है।"},"ICON-0247":{"nm":"कतार नंबर कलाईबंद","de":"एक अकेला नंबर आज क़तार में लगने का क्रम तय कर देता है। आगे हो या पीछे, इस छोटी-सी हल्की पट्टी को कलाई पर बाँधे लोग आख़िर उसी एक मंच को देखने जुटे एक-मन साथी ही हैं।"},"ICON-0248":{"nm":"फ़ोटोकार्ड सॉर्टिंग चार्ट","de":"एक ही चेहरा होते हुए भी सब अलग है कहकर हर ख़ाने में बाँटकर लिखा जाता है। चार्ट जितना भरता जाता है, मन उतना ही सुव्यवस्थित होता जाता है, और ख़ाली रह गया एक ख़ाना आज उसे भरने की चाहत से दिल को धड़काता है।"},"ICON-0249":{"nm":"एल्बम चेकलिस्ट","de":"वर्ज़न, फ़ोटोकार्ड, सील बंद है या नहीं तक—नंबरों में लिखा गया स्नेह की एक सूची। पूरा भर जाने वाले दिन के गर्व की पहले से कल्पना करते हुए, आज भी एक पंक्ति पर एक सलीक़ेदार गोल घेरा खींच दिया जाता है।"},"ICON-0250":{"nm":"चियर गाइड पर्ची","de":"हाथ का इशारा, पुकारने की ताल, साँस लेने की जगह तक। पहली बार आया व्यक्ति भी जल्दी एक स्वर में घुल-मिल जाए, इसलिए यह छोटी पर्ची एक दयालु मार्गदर्शक बनकर हाथ से हाथ में गुज़रती रहती है।"},"ICON-0251":{"nm":"प्राइवेट मेमो पैड","de":"किसी को भी न दिखाने वाले वाक्य चुनकर यहीं लिखे जाते हैं। कभी न खोला गया पन्ना ही सबसे ईमानदार होता है, यह बात यह पैड अपना कवर बंद रखे हुए मौन होकर सँजोए रखता है।"},"ICON-0252":{"nm":"एनिवर्सरी स्टैंप शीट","de":"दबाओ, और एक और दिन ख़ास बन जाता है। साधारण तारीख़ पर टक से लगी एक छोटी मुहर से, “आज” याद रखने लायक़ दिनों की सूची में चुपके से अपना नाम दर्ज करा लेता है।"},"ICON-0253":{"nm":"क्लिपबोर्ड कवर","de":"हवा चले, बारिश टकराए, फिर भी क्लिप किया काग़ज़ अंत तक सुरक्षित रहता है। बोर्ड का कवच बनने की ज़िम्मेदारी ख़ुद उठाने वाला मैं, लिखे हुए अक्षरों का भरोसेमंद अंगरक्षक हूँ।"},"ICON-0254":{"nm":"फ़ाइल इंडेक्स","de":"मोटे दस्तावेज़ों के बीच रास्ता न भटके, इसलिए एक छोटी ज़बान बाहर निकालकर “यहाँ है” बताता है। रंग-बिरंगे एक टैब से सौ पन्नों पर एक नज़र में क़ाबू पाया जाता है।"},"ICON-0255":{"nm":"कैटेगरी टैब लेबल","de":"यह इस ख़ाने में, वह उस ख़ाने में। दुनिया की अव्यवस्था को एक-एक पंक्ति करके सलीक़े से सँवारना ही मेरा काम है। लेबल लगते ही, गड्डमड्ड चीज़ें आख़िरकार अपनी जगह पा लेती हैं।"},"ICON-0256":{"nm":"मिनी अप्रूवल बोर्ड","de":"मुहर को टक से दबाते ही, अजीब तरह से सच में बड़ा हो जाने का एहसास होता है। आकार छोटा हो पर तेज़-तर्रार अधिकार से भरा, एक स्वीकृति की मुहर लगते ही ढेर सारा काम फुर्ती से निपट जाता है।"},"ICON-0257":{"nm":"पारदर्शी दस्तावेज़ पाउच","de":"भीतर सब साफ़ दिखता है, छिपाने को कुछ नहीं। ज़रूरी काग़ज़ को समेटे, बारिश में भीगने या मुड़ जाने से बचाते हुए, अपने पारदर्शी बदन से लपेटकर तय जगह तक पहुँचा देता है।"},"ICON-0258":{"nm":"अटेंडेंस बैंड","de":"आया, और एक और ख़ाना भर गया। हर दिन के क़दम पट्टी के साथ-साथ पंक्ति में जमते जाएँ, तो न दिखने वाली निष्ठा आख़िरकार एक नज़र में दिखने वाला एक नमूना बन जाती है।"},"ICON-0259":{"nm":"ग़लती नोटबुक","de":"ग़लत हुई चीज़ों को लिख लेना शर्म इकट्ठा करना नहीं है। एक ही जगह दो बार न लड़खड़ाने के लिए, बीती कल की भूल को आज के मार्गदर्शक के रूप में फिर से लिख लिया जाता है।"},"ICON-0260":{"nm":"शेड्यूल स्टैंप बोर्ड","de":"ख़ाली कार्यक्रम-सूची पर एक मुहर लगाते ही “वादा” जन्म ले लेता है। कलाई के एक झटके से दिन तय हो जाने का जादू—वह जादू असल में पहले से तैयारी करने की मेहनत का दूसरा नाम है।"},"ICON-0261":{"nm":"बुक स्पाइन लेबल","de":"शेल्फ़ की ओर पीठ करके खड़ी किताबों का नाम-पट्टा। संकरी रीढ़ पर लिखे छोटे अक्षर, सैकड़ों किताबों के बीच ढूँढ़ी जा रही उसी एक किताब को इशारे से एक झटके में बुला लेते हैं।"},"ICON-0262":{"nm":"फ़ोटो प्रोटेक्टर","de":"नंगे हाथ मना हैं। एक भी उँगली का निशान न छोड़ने की हिदायत देते हुए, यह किसी क़ीमती तस्वीर पर धीरे से अपना बदन बिछा देता है। पसंद करने वाला मन इसी सतर्क स्पर्श से लंबे समय तक बना रहता है।"},"ICON-0263":{"nm":"फ़िल्म इंडेक्स शीट","de":"फ़िल्म की एक-एक पट्टी पर नंबर लगा दो तो बिखरे हुए क्षण फिर से कहानी का अपना क्रम पा लेते हैं। रोशनी से लिखी स्मृतियाँ गड्डमड्ड न हों, इसकी देखभाल करने वाला एक छोटा मार्गदर्शक।"},"ICON-0264":{"nm":"फ़ोटो स्लीव बैग","de":"चौकोर ख़ुशियों को एक-एक करके सँजोकर रखा गया एक पारदर्शी घर। कोना दबने की चिंता के बिना, सबसे प्रिय चेहरा इसके भीतर चारों मौसम भर सलीक़े से चमकता रहता है।"},"ICON-0265":{"nm":"मिनी फ़ोटो लिफ़ाफ़ा","de":"अभी छपी तस्वीर की गर्माहट ठंडी होने से पहले ही, एक छोटा लिफ़ाफ़ा अपनी दोनों बाहें फैलाकर उसे थाम लेता है। हथेली भर के मुँह से भीतर गई वह एक तस्वीर, न जाने कब किसी के बैग का ख़ज़ाना बन जाती है।"},"ICON-0266":{"nm":"लेंटिकुलर कवर","de":"झुकाने पर भाव बदल जाने वाली नाज़ुक तस्वीर को बिना एक भी खरोंच के बचाना ही मेरा दायित्व है। हर कोण पर बदलते हर चेहरे की रक्षा करते-करते, मुझे भी कम मेहनती नहीं होना पड़ता।"},"ICON-0267":{"nm":"कट सॉर्टिंग लेबल","de":"चार तस्वीरों में से कौन-सी सबसे अच्छी है, यह लेबल ख़ुद ही बता देता है। अच्छी आई हुई और मज़ेदार वाली को साथ-साथ अलग करके रखने का यह छोटा-सा काम ही किसी याद को दो बार जीने का राज़ है।"},"ICON-0268":{"nm":"फ़ोटो स्ट्रिप बैंड","de":"संकरी, लंबी चार-तस्वीर वाली याद को सलीक़े से लपेटकर बाँधता है। उस दिन की बिखरने को बेताब हँसी को एक बंडल में मज़बूती से थामकर, बैग की गहराई तक सुरक्षित पहुँचा देता है।"},"ICON-0269":{"nm":"फ़ोटो कॉर्नर स्टिकर","de":"एल्बम में तस्वीर चिपकाते समय, चारों कोनों को धीरे से थाम लेने वाला एक छोटा हाथ। गोंद पोतने की ज़रूरत नहीं फिर भी गिरने न पाए—बारीक़ी इसी तरह कोनों से शुरू होती है।"},"ICON-0270":{"nm":"प्रिंट करेक्शन चार्ट","de":"थोड़ा और गर्म, थोड़ा कम चमकीला। पसंद का रंग आने तक अंकों से खेलता एक चार्ट, एक साधारण तस्वीर को चुपचाप एक कलाकृति में बदल देता है।"},"ICON-0271":{"nm":"रसीद क्लिप","de":"मुड़ी-तुड़ी रसीदों को सलीक़े से दबोचे रखता है, छोड़ता नहीं। अपने छोटे मुँह से दिन भर के ख़र्च को चुस्त-दुरुस्त रखने से, महीने के अंत का हिसाब कहीं ज़्यादा हल्का हो जाता है।"},"ICON-0272":{"nm":"बुकिंग कन्फ़र्मेशन स्लिप","de":"“आरक्षण हो गया है” इस एक पंक्ति से मन धीरे से शांत हो जाता है। काग़ज़ का एक टुकड़ा वादे का प्रमाण बनकर, इंतज़ार वाले उस दिन तक सिहरन को धीरे-धीरे सँजोए रखता है।"},"ICON-0273":{"nm":"रिटर्न रसीद","de":"उधार ली चीज़ को वापस उसकी जगह रख दिया, इसका छोटा पर सर-उठाकर खड़ा हो सकने वाला प्रमाण। यह काग़ज़ हाथ में आते ही, मन के किसी कोने में टिका एक क़र्ज़ आसानी से मिट जाता है।"},"ICON-0274":{"nm":"क्लेम टिकट होल्डर","de":"छोड़ी हुई चीज़ वापस लेने वाला टिकट खो न जाए, इसलिए मैं इसे तुम्हारी जगह कसकर थामे रखूँगा। एक छोटी पर्ची का ठिकाना कभी-कभी किसी के दिन के अंत को भी तय कर देता है।"},"ICON-0275":{"nm":"रेंटल टैग टेल","de":"उधार ली हर चीज़ पर लहराता एक छोटा टैग। इस पूँछ का पीछा करो तो कौन क्या ले गया, तुरंत सामने आ जाता है, तो खोई हुई चीज़ की गुत्थी भी जल्दी ही सुलझ जाती है।"},"ICON-0276":{"nm":"इंस्पेक्शन चेकलिस्ट","de":"एक-एक करके आँखों से टटोलकर देखा जाता है कि कुछ छूटा तो नहीं। जब चेक-निशान पंक्तिबद्ध होकर भरते जाते हैं, तब न दिखने वाली सावधानी आख़िरकार भरोसे का नाम पा लेती है।"},"ICON-0277":{"nm":"सेटलमेंट मेमो लिफ़ाफ़ा","de":"आया और गया पैसा लिफ़ाफ़े पर लिख दो तो बिखरे हुए अंक शांति से पंक्तिबद्ध हो जाते हैं। हिसाब का अंत हमेशा यही छोटी सी पर्ची स्थिर मन से पूर्णविराम लगाकर देती है।"},"ICON-0278":{"nm":"शिपिंग लेबल","de":"कहाँ जाना है, किस तक पहुँचना है, अपने बदन पर लिखे हुए यह रास्ते पर निकल पड़ता है। यह लेबल चिपकते ही, डिब्बा एक मंज़िल वाला यात्री बनकर सिहरन के साथ रवाना हो जाता है।"},"ICON-0279":{"nm":"रिसीट कन्फ़र्मेशन बैंड","de":"“अच्छे से मिल गया” यह एक बात एक पट्टी में बाँधकर वापस भेजी जाती है। पाने वाले की राहत और भेजने वाले की तसल्ली, इसी छोटी डोरी पर चुपचाप एक-दूसरे का हाथ थाम लेते हैं।"},"ICON-0280":{"nm":"वर्ड कार्ड रिंग","de":"अलग-अलग बिखर जाएँ तो खो जाने वाले शब्दों को, एक छोटी रिंग एक साथ पिरोकर थामे रखती है। पलटते-पलटते, अनजाने शब्द भी न जाने कब ज़ुबान पर बसे दोस्त बन जाते हैं।"},"ICON-0281":{"nm":"प्रोनन्सिएशन मेमो बैंड","de":"जिस जगह जीभ बार-बार फिसलती है, वहाँ एक छोटा निशान टाँग दिया जाता है। मुँह में रास्ता भटकती अनजान ध्वनि भी, इस मेमो का पीछा करते ही न जाने कब अपना सही उच्चारण पा लेती है। एक अनाड़ी आवाज़ को धीरे-धीरे सधाने का पहला पन्ना।"},"ICON-0282":{"nm":"ट्रांसलेशन नोट बॉक्स","de":"शब्द और शब्द के बीच पार करने वाले छोटे पुल एक-एक ख़ाने में सलीक़े से मुड़े रखे हैं। मुश्किल से चुना गया एक वाक्य लिखकर चुपके से थमा दो, तो न पहुँचने वाला मन भी बीच में एक पर्ची रखकर क़रीब आ जाता है।"},"ICON-0283":{"nm":"कोट स्क्रैप शीट","de":"मन को सीधे छू लेने वाला वाक्य हाथ से नक़ल करने पर ही लंबे समय तक टिकता है। किताब के कोने से काटी गई एक पंक्ति को मेज़ के आगे चिपका दो, तो वे अक्षर धँसते जा रहे उस दिन को चुपचाप थाम लेते हैं।"},"ICON-0284":{"nm":"नोट इंडेक्स","de":"मोटी किताब के भीतर रास्ता न भटके, इसके लिए लगाए गए रंग-बिरंगे छोटे झंडे। लौटने की जगह पता हो तभी और दूर भटका जा सकता है, यह बात टक से बाहर निकले टैब पन्नों के बीच से चुपचाप बता देते हैं।"},"ICON-0285":{"nm":"मेमोराइज़ेशन चेक चिप","de":"याद किए हुए के पास टक से लगाया गया एक निशान। दिमाग़ में क्षण भर ठहरकर ग़ायब होने वाली चीज़ों को थाम लेने वाला एक छोटा लंगर है यह, इसलिए काला भरा हर ख़ाना पिछली रात बहाई मेहनत को चुपचाप अपने भीतर लिए रहता है।"},"ICON-0286":{"nm":"क्विज़ एनवलप पैक","de":"लिफ़ाफ़ा फाड़ने से पहले कोई नहीं जानता क्या निकलेगा। उँगलियों से बंद जगह को टटोलते वे कुछ क्षण—एक सवाल सलीक़े से मुड़ा हुआ, उस धड़कन को भी साथ में सील किया हुआ सिहरन का एक पुलिंदा।"},"ICON-0287":{"nm":"ग्रामर टैब नोटबुक","de":"नियम दिमाग़ से रटे नहीं जाते, हाथ से सधते हैं। सबसे ज़्यादा खुले पन्ने के रंगीन टैब से लेकर धीरे-धीरे घिसती-मुलायम होती नोटबुक तक, वह घिसा हुआ कोना ही तुम्हारे टिके रहने के समय की वलय बन जाता है।"},"ICON-0288":{"nm":"स्पीकिंग प्रैक्टिस चार्ट","de":"मुँह खोलना दुनिया में सबसे मुश्किल काम लगने वाले किसी के लिए एक चार्ट। उँगली से ख़ाना-दर-ख़ाना उतरते जाओ तो गले में काँपता पहला शब्द भी न जाने कब अपनी आवाज़ पा लेता है। साहस की भी तो एक बारी होती है।"},"ICON-0289":{"nm":"कलर रफ़ शीट","de":"पूरे बनने से पहले के रंग बेतरतीब लेटे साँस सँभाल रहे हैं। सही जवाब नहीं, बल्कि अभी बस एक संभावना—इस अनगढ़ पन्ने पर किसी भी चीज़ से ज़्यादा कल का हिस्सा लहराता समाया है।"},"ICON-0290":{"nm":"मूड बोर्ड टुकड़ा","de":"छितर-बितर बिखरे हुए प्रभावों को एक जगह इकट्ठा करके चिपका दो, तो मुश्किल से हाथ आती वह मनोदशा धुंधले-से अपना रूप-रेखा दिखा देती है। अभी बिना नाम के किसी अहसास की ओर, टुकड़े एक-दूसरे के सहारे टिककर चुपचाप इशारा करते हैं।"},"ICON-0291":{"nm":"पैटर्न सैंपल बुक","de":"बोझक़ी की जाली और झरोखे की बुनावट एक किताब में क़रीने से सजी हुई है। जहाँ एक ही नमूना अंत तक दोहराया जाता है, वहाँ आलस नहीं, एक वादा बसता है—एक ही लय को थामे रखने वाला दृढ़ मन।"},"ICON-0292":{"nm":"कॉस्ट्यूम स्वॉच शीट","de":"एक ही रोशनी होते हुए भी हर कपड़े के टुकड़े पर बनावट और छाया अलग-अलग जमती है। मंच का परिधान चुनने से पहले, उँगलियों से दर्जनों बार सहलाते हुए हिचकिचाई वह रात एक छोटे नमूने में पूरी की पूरी सँजोई है।"},"ICON-0293":{"nm":"लोगो निषेध गाइड शीट","de":"क्या नहीं करना है, यह पहले साफ़-साफ़ लिख दिया गया काग़ज़। लाल क्रॉस से काटी गई रूपरेखा के भीतर ही आज़ादी और स्पष्ट होती है, तो जो जगह गतिरोध लगती थी वहीं उलटा एक नया रास्ता खुल जाता है।"},"ICON-0294":{"nm":"कलर रेफ़रेंस चिप","de":"रंग शब्दों में कभी ठीक से समझाया नहीं जा सकता, इसलिए अलग से बनाया गया एक नमूना टुकड़ा। सूर्यास्त सबसे लाल हुआ था वह एक पल एक छोटी हथेली पर क़ैद करके, अगले व्यक्ति को “यही तो है वह रंग” ठीक-ठीक सौंपा जा सके, ऐसा किया गया।"},"ICON-0295":{"nm":"लेआउट रफ़ कार्ड","de":"क्या कहाँ रखना है, इसकी हल्के से खींची गई पहली तस्वीर। जगह तय करना असल में मन तय करना ही है, इसलिए अनाड़ी ढंग से बिखरी रेखाओं के बीच से पूरे का संतुलन धीरे-धीरे आँखें खोलता है।"},"ICON-0296":{"nm":"मैटीरियल मेमो बोर्ड","de":"लकड़ी, मिट्टी, पत्थर—छू सकने वाली चीज़ों के नाम घनी तरह लिखे हैं। जो पहले हाथ से बनावट पढ़ना शुरू करते हैं, वही जानते हैं यह राज़—किससे बनाया जाए, यह पहले से ही आधा तय कर देता है कि वह क्या बनेगा।"},"ICON-0297":{"nm":"पैटर्न ट्रेसिंग पेपर","de":"रूपरेखा के ऊपर पतला काग़ज़ बिछाकर धीरे से रेखाओं का पीछा करते हुए खींचा जाता है। किसी और के रास्ते को थोड़ी देर उधार लेते समय हाथ वह रास्ता सीख लेता है, और नक़ल की गई रेखाओं के बीच से न जाने कब अपनी ही एक रेखा चुपके से पनप आती है।"},"ICON-0298":{"nm":"एंट्री पाथ बैंड","de":"फ़र्श पर लंबी चिपकी पट्टी का पीछा करते हुए लोग पंक्ति बनाकर भीतर आते हैं। उत्साहित क़दम उलझें नहीं, इसलिए धीरे से मार्गदर्शन करती एक रेखा—सिहरन बिखरने न पाए, इसे थामे रखने वाला एक अदृश्य स्नेहिल हाथ।"},"ICON-0299":{"nm":"इवेंट गाइड पिकेट","de":"“इधर से” यह एक बात कहने की जगह खड़ा एक तख़्ता। कोई भटके नहीं, इसलिए हर मोड़ पर खड़ी की गई एक छोटी दयालुता, पहली बार आए व्यक्ति के अनजान दिन का हाथ थामे मानो चुपचाप साथ चलती है।"},"ICON-0300":{"nm":"बूथ नंबर लेबल","de":"हर बूथ को दिया गया एक नंबर उस एक जगह के मालिक को स्पष्ट रूप से तय कर देता है। छोटा-सा नंबर, पर “यह जगह तुम्हारी है” का वादा होने से, अनजान आयोजन-स्थल में भी लौटने की एक जगह बन जाती है।"},"ICON-0301":{"nm":"स्टाफ़ सहमति पत्र","de":"साथ काम करने का मन बनाने की जगह पर छोड़ा गया एक हस्ताक्षर। यह महज़ एक पतला कागज़ है, पर इसमें एक-दूसरे पर भरोसा करने का पूरा भार समाया है, और आयोजन का हर मददगार हाथ यहीं से शुरू होता है।"},"ICON-0302":{"nm":"ट्रायल टिकट बंडल","de":"हाथ में आराम से समाने के लिए मोटा बाँधा गया अनुभव-टिकटों का गट्ठर। बाँटने पर यह घटता नहीं, बल्कि किसी के \"पहली बार\" को बार-बार बढ़ाता है — जितना छुओ, उतना ही गर्म होता जाने वाला भलाई का बंडल।"},"ICON-0303":{"nm":"कतार चिह्न पत्रक","de":"\"यहाँ से इंतज़ार कीजिए,\" फर्श धीरे से कह उठता है। बारी का सम्मान करने वाले दिल जब जुटते हैं, तो लंबी कतार भी एक दृश्य बन जाती है, और एक छोटा-सा निशान बेचैनी को शांति में बदल देता है।"},"ICON-0304":{"nm":"मौके पर पिकअप टैग","de":"पहले से मँगाई चीज़ को खुद लेने की जगह पर हल्के से टँगा एक छोटा टैग। हाथ में आते ही कंधों से सरककर उतर जाने वाली वह हल्की राहत — देर तक इंतज़ार करते दिल को आख़िरकार आकार मिलने की गाँठ।"},"ICON-0305":{"nm":"रहस्य बॉक्स टिकट","de":"अंदर क्या है, यह जाने बिना एक चुनने का आनंद। हिलाओ तो भीतर खड़खड़ाती आवाज़ पर पहले दिल धड़कता है, और खोलने से ठीक पहले का वह पल दिन का सबसे उम्मीद-भरा, फूला हुआ क्षण बन जाता है।"},"ICON-0306":{"nm":"अदला-बदली पूर्ण स्टिकर","de":"अदला-बदली बिना किसी रुकावट के पूरी होने की सूचना देने वाली छोटी गोल मुहर। देने-लेने वाले हाथों के बीच बचा वह चिकना पूर्णविराम है, और एक बार चिपकते ही वह सौदा आख़िरकार गर्माहट से गोल हो जाता है।"},"ICON-0307":{"nm":"अभिलेख मुहरबंद पट्टी","de":"एक अनमोल पिटारे को पट्टी से एक बार लपेटकर चुपचाप सील कर दिया जाता है। बिना वजह न खोलने की गुज़ारिश और भीतर रखी चीज़ को उतना ही क़ीमती मानने का सबसे शांत शिष्टाचार, यह सब एक ही पट्टी में समाया है।"},"ICON-0308":{"nm":"गुप्त संदेश कैप्सूल","de":"कहने की चाहत रखे एक बात को छोटे से डिब्बे में सहेजकर बंद रखा जाता है। न भेज सके एहसास को दफनाने की तरह कसकर बंद कर दो, तो फिर से खोलने वाले उस दिन तक हथेली पर रखी यह छोटी तिजोरी समय की रखवाली करती है।"},"ICON-0309":{"nm":"नन्हा स्क्रैप कार्ड","de":"काटकर चिपकाए एक टुकड़े में उस दिन का मूड हल्के से बसा रहता है। डायरी से हल्का और तस्वीर से ज़्यादा हाथ का एहसास लिए यह हथेली-भर कागज़, उँगलियों के बीच से फिसल जाने वाले दिन को कसकर थाम लेता है।"},"ICON-0310":{"nm":"पहली मुलाक़ात अभिलेख पत्र","de":"इस टापू पर पहली बार पैर रखने के दिन की धड़कन एक छोटी-सी पंक्ति में बच जाती है। अजनबीपन के अपनेपन में बदलने से ठीक पहले का, सबसे निर्मल पहला एहसास कागज़ अपने भीतर सँजोकर लंबे समय तक रख देता है।"},"ICON-0311":{"nm":"यादों की छँटाई तालिका","de":"यादों को उनकी परत और शाखा के हिसाब से एक-एक कर बाँटकर लिखी गई तालिका। हर याद को एक ही दराज़ में उलट-पुलट भर दिया जाए तो सबसे प्यारा दिन भी दब जाता है, इसलिए जो जितना क़ीमती हो, उतनी ही नज़ाकत से उसकी अपनी जगह तय होती है।"},"ICON-0312":{"nm":"संवाद-बुलबुला मेमो चिप","de":"कहने की चाहत रखी बात गुब्बारे-सी गोल फूलकर कागज़ पर तैरती है। मुँह से न कह पाई कोई बात भी उस गोल घेरे के भीतर धीरे से हिम्मत जुटा लेती है — दिल के बाहर निकलने का एक छोटा, गर्म रास्ता।"},"ICON-0313":{"nm":"तारीख़ धारक","de":"आज कौन-सी तारीख़ है, यह सीधा खड़ा कर आमने-सामने दिखाने वाला एक छोटा स्टैंड। लगातार बहते जा रहे दिनों में से बस एक दिन चुनकर सामने बिठा दो, तो एक साधारण-सी तारीख़ में भी मनाने लायक गर्माहट उतर आती है।"},"ICON-0314":{"nm":"संग्रह क्रमांक टैग","de":"चाही हुई हर चीज़ को दिया गया एक अनोखा नंबर। संग्रह करना यानी यह वादा करना कि दुनिया में यही एक चीज़ अद्वितीय कहलाएगी, इसलिए छोटे टैग पर लिखा अंक दिल के भार को साफ़-साफ़ उकेर देता है।"},"ICON-0315":{"nm":"अभिलेखागार स्लिप","de":"लंबे समय तक सँभालकर रखी जाने वाली चीज़ों को एक-एक कर पिरोने वाला पतला भीतरी कागज़। रोशनी और समय से बस एक परत भर दूर रखने का काम — किसी चीज़ से प्यार करना आख़िरकार उसे अच्छे से सँभाल पाना ही है।"},"ICON-0316":{"nm":"फ़ोटोकार्ड टॉपलोडर स्ट्रैप","de":"टॉपलोडर को गले में लटकाने के लिए जोड़ने वाली एक पतली डोरी। सबसे चहेते चेहरे को सीने के पास रखकर दिन गुज़ारने का यह फैनडम का तरीक़ा है, और इस एक पतली डोरी में पूरे दिन का प्यारा साथ बँधा रहता है।"},"ICON-0317":{"nm":"फ़ोटोकार्ड स्टैंड पिन","de":"एक छोटी पिन से फ़ोटोकार्ड मेज़ पर सीधा खड़ा हो जाता है। लेटा रहे तो बस कागज़ का एक टुकड़ा, पर खड़ा हो जाए तो आमने-सामने मिलने वाला चेहरा बन जाता है, और नज़र को देर तक ठहरने की एक जगह चुपचाप बना देता है।"},"ICON-0318":{"nm":"होलो फ़ोटोकार्ड फ़िल्म","de":"हर कोण पर इंद्रधनुष बहा देने वाली एक पतली फ़िल्म की परत। रोशनी को हल्का-सा क़ैद करने वाली यह परत सीधे-सादे कार्ड को तारों की चमक पहना देती है, कलाई हिलाते ही हर बार एक नया भाव चमककर जाग उठने वाला छोटा-सा जादू।"},"ICON-0319":{"nm":"फ़ोटोकार्ड सुरक्षा कैप","de":"किनारे पर एक बार दबाव पड़ते ही मानो चाहा हुआ दिल भी साथ मुड़ जाता है। एक अनमोल टुकड़े को कसकर थामने वाला यह पारदर्शी कवच है, और सच में किसी चीज़ को चाहने के काम में हमेशा ऐसी ही सावधानी साथ चलती है।"},"ICON-0320":{"nm":"फ़ोटोकार्ड छँटाई ट्रे","de":"दर्जनों फ़ोटोकार्ड को कतार में सुला देने वाली एक उथली ट्रे। बिखरे रहें तो बस एक ढेर, पर लाइन से सुला दो तो एक संग्रह बन जाता है, और सजाने वाले हर हाथ में प्यार का क्रम परत-दर-परत उकेरा जाता है।"},"ICON-0321":{"nm":"फ़ोटोकार्ड अदला-बदली लिफ़ाफ़ा","de":"एक फ़ोटोकार्ड को लिफ़ाफ़े में डालकर सौंपते वक़्त उँगलियाँ पल-भर हिचकिचाती हैं। यह उसे विदा करना नहीं, बल्कि किसी का सबसे चहेता बनने की गुज़ारिश है। लिफ़ाफ़े की परत मोड़ते ही एक छोटा-सा रिश्ता चुपचाप हाथ बदल लेता है।"},"ICON-0322":{"nm":"फ़ोटोकार्ड सजावटी पेन","de":"ख़ाली जगह को भरने वाली चीज़ लिखावट नहीं, भावना है। जहाँ-जहाँ निब गुज़रे, वहाँ नन्हे दिल और तारे उग आते हैं, और सादा-सा कागज़ दुनिया की इकलौती हौसला-अफज़ाई बनकर जाग उठता है। सजाना, स्वीकारोक्ति का ही दूसरा नाम है।"},"ICON-0323":{"nm":"फ़ोटोकार्ड क्लिप रिंग","de":"टक की आवाज़ के साथ क्लिप बंद हो जाती है। उस एक छोटे-से ताले से बिखरने वाले कार्ड एक कतार में जुड़ जाते हैं। दिन-भर बैग में हिलते रहने पर भी किसी किनारे को खरोंच नहीं आती। मज़बूती कभी-कभी इतनी ही ख़ामोश होती है।"},"ICON-0324":{"nm":"फ़ोटोकार्ड कैरी पाउच","de":"ज़िप को खोलते-बंद करते हाथ में कब आदत बस गई, पता ही नहीं चला। अचानक बारिश आए या भीड़ धकेले, भीतर की जगह हमेशा सूखी रहती है। सबसे चहेती चीज़ को सबसे गहरे कोने में रखना — यही तो ढोने का प्यारा परिश्रम है।"},"ICON-0325":{"nm":"फ़ैन मीटिंग रिस्टबैंड स्ट्रैप","de":"कलाई पर डोरी बाँधने वाले स्टाफ़ का हाथ कितना गर्म था, यह एक फ़ैन ने लंबे समय तक याद रखा। एक गाँठ आज इस जगह से जुड़े होने का निशान है। खुल न जाए इसलिए दो बार लपेटी गई वह डोरी दिन-भर की धड़कन थामे रखती है।"},"ICON-0326":{"nm":"प्रवेश रिस्टबैंड","de":"प्रवेश-द्वार पार करते ही उस पल भीतर और बाहर आख़िरकार साफ़-साफ़ बँट जाते हैं। दिन-भर पहने रहने से जल्द ही यह त्वचा से जान-पहचान बना लेती है, और उतारते वक़्त तक एक हल्की-सी लकीर छूट जाती है — मानो वहाँ ठहरने का सबूत हो।"},"ICON-0327":{"nm":"टॉक कॉर्नर चिप","de":"टॉक कॉर्नर शुरू होते ही एक चिप लुढ़कती चली जाती है। कौन पहले बोलेगा, कौन-सा सवाल निकलेगा — यह छोटा-सा संयोग पूरा माहौल बदल देता है। लिखी-बँधी स्क्रिप्ट से कहीं ज़्यादा प्यारी है एक चिप की मनमौज़ी।"},"ICON-0328":{"nm":"हस्ताक्षर कार्यक्रम कतार टिकट","de":"नंबर लिखी पर्ची हाथ में थामे कतार में खड़े होते हैं। नंबर 142। आगे खड़े 141 लोगों को गिनते-गिनते दिल पहले ही अपनी बारी गिन लेता है। इंतज़ार लंबा है, पर इस एक पर्ची की बदौलत वह समय भी उत्साह का हिस्सा बन जाता है।"},"ICON-0329":{"nm":"हाई-टच दस्ताना","de":"हथेलियाँ छूने के उस पल में दस्ताना वह छोटी-सी गर्माहट अपनी जगह ले लेता है। आधे सेकंड के स्पर्श के लिए दिन-भर गर्म रखा गया हाथ। कपड़े के बावजूद वह सिहरन रुकती नहीं, यह हर किसी को तभी पता चलता है।"},"ICON-0330":{"nm":"स्मृति फ़ोटो पिन","de":"क्लिक, एक आवाज़ में आज का दिन जस-का-तस क़ैद हो जाता है। पिन से थमे फ़्रेम के भीतर, संकोच से मुस्कुराया चेहरा भी बाद में सबसे याद आने वाला दृश्य बन जाता है। दर्ज करना, पल को थामने का सबसे प्यारा लालच है।"},"ICON-0331":{"nm":"सीट रिबन टैग","de":"सीट की पीठ पर टँगा एक नन्हा रिबन बिना हवा के भी हौले-हौले झूलता है। किसी ने बाँधा हुआ निशान, यहाँ कोई था इसका सबूत। शो ख़त्म होने के बाद ख़ाली सीट पर भी बस यही रिबन मानो अब भी ताल याद रखे हुए है।"},"ICON-0332":{"nm":"उपहार जाँच लेबल","de":"हर एक उपहार पर एक लेबल चिपकता है। भेजा गया या नहीं, जाँचा गया या नहीं, कुछ छूटा तो नहीं। किसी का दिल पाने के काम में भी घर-गृहस्थी चाहिए, इसलिए यह छोटा-सा स्टिकर देखभाल और देखभाल के बीच बिना किसी कमी के कड़ी जोड़ता है।"},"ICON-0333":{"nm":"स्मृति स्लिप","de":"लंबे समय तक सँभालने के लिए लिखा गया एक कागज़। उस दिन का मौसम, सीट नंबर, आख़िरी गाने का नाम तक। याद धुँधली पड़ जाए, पर यह स्लिप कभी धुँधली नहीं पड़ती। यादों को सँभालने के लिए भी एक छोटा-सा फॉर्म चाहिए होता है।"},"ICON-0334":{"nm":"चीयर टॉवल लूप","de":"तौलिये के सिरे में एक कड़ी लगा दो तो कंधे से फिसलकर गिरता नहीं। पसीना पोंछने, सिर के ऊपर घुमाने, और फिर गले में डालने की हर हरकत के बीच, एक छोटी-सी कड़ी हौसला-अफज़ाई की हरकत को बिना टूटे जोड़े रखती है।"},"ICON-0335":{"nm":"स्लोगन क्लिप","de":"स्लोगन के दोनों सिरों को क्लिप कसकर थामे रहती है, ताकि दोनों बाँहें ऊँची उठाने पर भी अक्षर न मुड़ें, न लहराएँ। नज़र से ओझल रहकर संदेश को सीधा रखने वाला, सबसे ख़ामोश सहायक कलाकार यहीं है।"},"ICON-0336":{"nm":"ध्वनि-रोधी पाउच","de":"ज़िप धीरे से, बिना आवाज़ के सरकती है। जहाँ शांति का वादा किया गया है, वहाँ एक भी शोर न रिसने के लिए बुनी गई एक ख़ामोशी। ख़याल रखना कभी-कभी ख़ुद को अनसुना कर देना भी होता है, यह पाउच चुपचाप कह रहा है।"},"ICON-0337":{"nm":"तालि लय चिप","de":"हथेलियाँ जब भी टकराती हैं, चिप ताल गिनती है। ताली, ताली, ताली — बिखरी तालियाँ किसी पल एक ही लय में जुट जाती हैं। हज़ारों तालियों के एक साँस बन जाने का वह जादू, एक छोटी चिप चुपचाप थाम लेती है।"},"ICON-0338":{"nm":"चीयर गाइड फ़ोल्डर","de":"खोलो तो हौसला-अफज़ाई का तरीक़ा चरण-दर-चरण लिखा मिलता है — किस पंक्ति पर कौन-सा रंग उठाना है, कब जयकारा लगाना है। पहली बार आए इंसान को भी यह एक फ़ोल्डर जल्दी अपने परिवार का हिस्सा बना देता है — वादा बाँटने की एक छोटी पुस्तिका।"},"ICON-0339":{"nm":"सीट पंखा स्ट्रैप","de":"पंखे की मुठिया में डोरी बाँध दो तो हाथ से छूट भी जाए तो गिरता नहीं। गर्म दिन में पंखा झलते-झलते जब जयकारे में दोनों हाथ आज़ाद हो जाते हैं, तब वह कलाई पर लटक जाता है। एक डोरी गर्मी और उत्साह, दोनों को एक साथ ठंडा कर देती है।"},"ICON-0340":{"nm":"चमक फ़िल्म टुकड़ा","de":"रोशनी पड़ते ही हर टुकड़ा अलग कोण पर बिखर जाता है। हथेली पर रखो तो एक नन्हा इंद्रधनुष झिलमिलाता है, और हिलाते ही रंग जीवंत होकर नाच उठते हैं। शायद चमकना यानी रोशनी को बारीक टुकड़ों में बाँटकर रखना ही है।"},"ICON-0341":{"nm":"मिनी बैनर पोल","de":"छोटा डंडा खोलते ही कपड़ा हवा पाकर तन जाता है। दोनों हाथों से ऊँचा उठाओ तो अक्षर सीटों के पार तक पहुँचते हैं, मोड़ दो तो बैग के एक कोने में समा जाता है। दिल का आकार डंडे की लंबाई से नहीं नापा जाता।"},"ICON-0342":{"nm":"चीयर स्टिकर पैक","de":"हर एक स्टिकर पर एक हौसला-अफज़ाई का जुमला छपा है। डायरी पर, फ़ोन पर, लैपटॉप के कोने पर — जहाँ भी चिपके, रोज़मर्रा की ज़िंदगी हौसले के रंग में रँग जाती है। पसंद करने वाला दिल यूँ ही हर जगह अपने निशान छोड़ जाता है।"},"ICON-0343":{"nm":"एल्बम सुरक्षा कवर","de":"एल्बम को कवर में लपेटने वाला हाथ सतर्क रहता है, ताकि किनारे घिसें नहीं, धूप में फीके न पड़ें। संगीत कानों से सुना जाता है, पर यह एक टुकड़ा हाथों को याद रहता है — जिस चीज़ को चाहा जाए, उसे लंबे समय तक पास रखने की चाहत का कवच।"},"ICON-0344":{"nm":"डिस्क स्लीव रिंग","de":"डिस्क को स्लीव में डालकर रिंग से बाँध दो तो एक एल्बम-पुस्तक बन जाती है। पन्ना पलटते वक़्त की सरसराहट भली लगती है। बिखरे संगीत को हाथ में क़रीने से इकट्ठा कर लेना, यही तो संग्रहकर्ता की ख़ामोश ख़ुशी है।"},"ICON-0345":{"nm":"गुड्स स्टोरेज डिवाइडर","de":"एक डिवाइडर से बिखरने वाला सामान अपनी जगह पा जाता है — यहाँ फ़ोटोकार्ड, वहाँ की-रिंग, उसके बगल में लाइट स्टिक। सजाना यानी चीज़ों के लिए घर बनाना। खाने बँटते ही अस्त-व्यस्तता व्यवस्था में बदल जाती है।"},"ICON-0346":{"nm":"रैंडम पैक सील कॉर्ड","de":"रैंडम पैक का मुँह डोरी से बाँध दो तो किसी की भी तक़दीर अभी तय नहीं होती। खोलने से पहले तक सब अपनी-अपनी उम्मीद के नायक होते हैं। सील खोलती उँगलियों की सिहरन ही असल में वह ख़ुशी है, जिसे यह डोरी सँभाले रखती है।"},"ICON-0347":{"nm":"उपहार छँटाई बॉक्स","de":"बोनस चीज़ें बॉक्स के भीतर क़िस्म के हिसाब से क़तार में लगती हैं — पोस्टकार्ड पोस्टकार्ड के साथ, बुकमार्क बुकमार्क के साथ। बढ़ते-बढ़ते भरते खाने देखो तो अब तक जुटाया समय एक नज़र में दिख जाता है। सजाना ही यादों की सूची बनाना है।"},"ICON-0348":{"nm":"संस्करण भेद लेबल","de":"दिखने में एक जैसी लगें, पर एक जैसी न हों ऐसी चीज़ें होती हैं। एक लेबल संस्करण A को संस्करण B से, पहले प्रिंट को पुनर्मुद्रण से अलग करता है। एक छोटे-से निशान की बदौलत उलझन मिट जाती है, और संग्रह की दुनिया में एक साफ़ पहचान-पर्ची जुड़ जाती है।"},"ICON-0349":{"nm":"पहले हफ़्ते बिक्री जाँच मेमो","de":"रिलीज़ का पहला हफ़्ता, और एक अंक पर दिल हिल उठता है। नोटपैड पर साफ़-साफ़ लिखे गए चेक निशान। कुछ दिनों के रिकॉर्ड जुट जाएँ तो हौसला-अफज़ाई की एक छोटी रिपोर्ट-कार्ड बन जाती है — पसंद के दिल को अंकों में तर्जुमा करने की सलीक़ेदार आदत।"},"ICON-0350":{"nm":"पोस्टर फ़िक्सिंग कैप","de":"लपेटे हुए पोस्टर के सिरे में कैप लगा दो तो वह खुला-खुला ही शांत रहता है, ताकि दीवार पर टाँगें या फ्रेम में जड़ें, इस सोच के बीच वह मुड़े नहीं। सबसे चहेते दृश्य को सीधा और सुरक्षित रखने वाला एक छोटा ढक्कन है।"},"ICON-0351":{"nm":"स्टैंडिंग फ़ोटो स्टैंड","de":"स्टैंड पर तस्वीर टेढ़ी होकर खड़ी होती है — मेज़ के एक कोने में, आँखों की सीध के ठीक सही कोण पर। गुज़रते वक़्त हर बार नज़रें मिलाने वाला यह अविष्कार, चहेते चेहरे को रोज़मर्रा के नज़ारे में लाने का सबसे सीधा तरीक़ा है।"},"ICON-0352":{"nm":"रिहर्सल टेप रोल","de":"फ़र्श पर टेप चिपकाकर खड़े होने की जगह चिह्नित की जाती है — एक क़दम, दो क़दम, ठीक यहीं। एक ही निशान पर दर्जनों बार पैर रखने से चाल-ढाल शरीर में उतर जाती है। चमकदार मंच के नीचे यही ईमानदार टेप के निशान बिछे होते हैं।"},"ICON-0353":{"nm":"मंच चाल पिन","de":"मंच के फ़र्श में गड़ी एक पिन अगला क़दम बता देती है। अँधेरे में भी पैर की उँगलियाँ पहले उस जगह को टटोल लेती हैं। न दिखने वाला मगर ठीक रास्ता, यह अनगिनत रिहर्सल्स ने खींचा अदृश्य नक़्शा है।"},"ICON-0354":{"nm":"स्टाफ़ ईयर कैप","de":"ईयर कैप लगाते ही दर्शकों की जयकारे की गूँज एक परत मद्धम हो जाती है, और सिर्फ़ क्यू सुनाने वाली आवाज़ ही साफ़ रह जाती है। मंच के पीछे स्टाफ़ के कान हमेशा दो दुनिया एक साथ सुनते हैं — शोर के बीच संकेत चुनने का एक छोटा साधन।"},"ICON-0355":{"nm":"ग्रीनरूम हैंगर टैग","de":"हर हैंगर पर एक नाम-पर्ची लटकी है — पहली पोशाक, दूसरी पोशाक, आंकोर पोशाक। बदलने का क्रम पंक्तिबद्ध लिखा वह तालिका देखो, तो दिन का पूरा मंच पहले ही कपड़ों के क्रम में उकेरा दिखता है — हलचल को सँभालती एक शांत व्यवस्था।"},"ICON-0356":{"nm":"प्रॉप जाँच टैग","de":"मंच पर चढ़ने से पहले, हर एक सामान पर एक टैग बाँधा जाता है — कुछ छूट तो नहीं गया, सब ठीक तो है। दर्शकों को पता नहीं चलता, पर यह छोटी-सी जाँच हादसे को रोक लेती है। बेदाग़ दिखने वाले मंच के पीछे हमेशा एक बारीक़ हाथ होता है।"},"ICON-0357":{"nm":"क्यू साइन चिप","de":"क्यू चिप हाथ से हाथ गुज़रती है — अभी, अंदर जाओ। एक भी शब्द बोले बिना टाइमिंग पहुँच जाने का पल। मंच के बग़ल के अँधेरे में यह छोटा-सा संकेत सबकी ताल को छूटने से बचाए रखता है।"},"ICON-0358":{"nm":"बैकस्टेज पैच","de":"एक दरवाज़ा है, जिससे सिर्फ़ यह पैच पहने लोग गुज़र सकते हैं — मंच के पीछे, जहाँ दीवार के उस पार से जयकारे सुनाई देते हैं। कपड़े का एक नन्हा टुकड़ा चमकदार आगे और व्यस्त पीछे को बाँट देता है — मंच को थामे रखने वालों की पहचान।"},"ICON-0359":{"nm":"प्रॉम्प्टर शेड बोर्ड","de":"शेड बोर्ड प्रॉम्प्टर की रोशनी को दर्शकों तक रिसने से रोके रखता है — सिर्फ़ मंच पर खड़ा शख़्स देखे, देखने वालों को पता भी न चले। न पकड़ी जानी चाहिए ऐसी मदद को चुपचाप छुपाता, मंच का यह शालीन गुप्त रखवाला है।"},"ICON-0360":{"nm":"ग्रीनरूम मिरर कवर","de":"शो के बाद ग्रीनरूम में शीशे को कपड़े से ढका जाता है। दिन-भर अनगिनत भाव झलकाता वह शीशा कुछ देर के लिए अपनी आँखें मूँद लेता है। मेकअप उतरा साफ़ चेहरा आख़िर में जिससे आमने-सामने होता है, वह शीशा नहीं, ख़ामोश अँधेरा है।"},"ICON-0361":{"nm":"प्री-रिकॉर्डिंग एंट्री रिस्टबैंड","de":"एक बार बाँधने पर काटे बिना न खुलने वाली एक छोटी पट्टी। प्री-रिकॉर्डिंग की सीटों तक पहुँचने की इकलौती योग्यता के लिए, किसी ने घुप अँधेरी भोर में पहली ट्रेन पकड़ी। कलाई का यह वज़न ही उस दिन-भर की धड़कन बन जाता है।"},"ICON-0362":{"nm":"रिकॉर्डिंग प्रतीक्षा लेबल","de":"लाल बत्ती जलने से ठीक पहले, सबकी साँसों को एक पंक्ति में बाँधे रखना मेरा काम है। क्यू का इंतज़ार करती ख़ामोशी में मैं अंत तक चुपचाप डटा रहता हूँ। मेरे उतरते ही आख़िरकार लाइव प्रसारण का पर्दा उठता है।"},"ICON-0363":{"nm":"कैमरा पोज़िशन चिप","de":"फ़र्श पर छपा एक छोटा निशान छह कैमरों की चाल बड़ी सफ़ाई से तय कर देता है। कहाँ से लिया जाए तो सबसे चमकदार दिखे, यह निर्देशक को रिहर्सल से पहले ही पता होता है — फ़्रेम के बाहर से फ़्रेम के भीतर को पहले ही उकेर लेने वाला हाथ।"},"ICON-0364":{"nm":"साउंड चेक टैग","de":"ख़ाली सीटों की ओर माइक को टक-टक थपथपाकर देखा जाता है। गूँज लंबी हो तो छत पर ध्वनि-सोखक की एक और परत। दर्शकों की नज़र बचाकर आवाज़ की बनावट सँवारने की यह मेहनत, इसी छोटे टैग से चुपचाप शुरू होती है।"},"ICON-0365":{"nm":"ऑन-साइट स्टैंप बुक","de":"जब भी किसी जगह से गुज़रो, एक खाने में एक मुहर जुड़ जाती है। स्याही के हर फैले निशान में उस दिन का मौसम और धड़कन साथ छप जाते हैं। पूरा भरा पन्ना किसी और की न हो सकने वाली, सिर्फ़ मेरी क़दमों की नक़्शा-किताब बन जाता है।"},"ICON-0366":{"nm":"ब्रॉडकास्ट स्टेशन विज़िटर स्ट्रैप","de":"यह डोरी न हो तो लॉबी का गेट खुलता ही नहीं। गले में डाले, गलियारे में क़दम-दर-क़दम चलते हुए, कल तक सिर्फ़ स्क्रीन पर दिखने वाली दुनिया धीरे-धीरे इतनी क़रीब आ जाती है कि हाथ से छुई जा सके।"},"ICON-0367":{"nm":"स्टूडियो फ़ुट कवर पैक","de":"स्टूडियो का फ़र्श हमेशा ठंडा और फिसलन-भरा होता है। जूते उतारकर पतले फ़ुट कवर पहन लो तो क़दमों की आवाज़ ग़ायब हो जाती है। कैमरा तो नृत्य क़ैद करता है, क़दमों की आवाज़ नहीं, इसलिए आवाज़ मिटाना भी मंच के प्रति एक शिष्टाचार है।"},"ICON-0368":{"nm":"ग्रीनरूम स्नैक टैग","de":"रिहर्सल और लाइव शो के बीच, भूख सबसे ईमानदारी से आती है। ग्रीनरूम के एक कोने में हर नाश्ते पर लिखा एक छोटा नाम-टैग, किसका है यह बताता। सँभालकर रखने की यह नज़ाकत ही लंबे, लंबे दिन को आख़िर तक थाम रखती है।"},"ICON-0369":{"nm":"मॉनिटरिंग मेमो बैंड","de":"स्क्रीन बार-बार देखते हुए लिखा जाता है — यहाँ नज़र, वहाँ आधी ताल। ठसाठस भरी लिखावट कल के अपने-आप को भेजा एक गुप्त पत्र है। सिरे पर चिपकी यह पट्टी कल से एक बित्ता बेहतर होने का ख़ामोश वादा है।"},"ICON-0370":{"nm":"शोकेस निमंत्रण स्लिप","de":"एक कागज़ किसी के लिए पूरे एक साल का इंतज़ार भी बन जाता है। शोकेस में बुलाने वाली एक छोटी-सी पंक्ति, लिफ़ाफ़ा खोलती उँगलियों की सिहरन तक समेटकर, दुनिया के सबसे छोटे निमंत्रण-पत्र के रूप में जन्मी है।"},"ICON-0371":{"nm":"प्रेस लैन्यार्ड स्ट्रैप","de":"पत्रकार के गले में लटककर शटर की खटर-पटर के बीचोबीच घूमती है। सबसे अच्छा कोण खोजने भागते क़दम, और वही रफ़्तार मंच की गर्माहट को बाहरी दुनिया तक पहुँचाने का रास्ता बन जाती है।"},"ICON-0372":{"nm":"मंच अभिवादन क्रम तालिका","de":"तालियों की बौछार के बीच भी कोई न चूके, इसलिए कौन पहले और कौन बाद में, यह एक पंक्ति में लिख दिया जाता है। अंतिम अभिवादन की सजावट भी पहली एंट्री जितनी ही सलीक़े से तय की जाती है।"},"ICON-0373":{"nm":"फ़ोटो वॉल फ़्लोर मार्कर","de":"फ़ोटो वॉल के आगे फ़र्श पर पैर रखने की जगह पहले से उकेरी होती है। एक क़दम भी हटो तो पीछे का लोगो कट जाता है। सबसे चमकदार क़ैद होने वाली उस जगह का राज़ पैरों तले चुपचाप निशान बना है।"},"ICON-0374":{"nm":"प्रीमियर रिस्टबैंड","de":"थिएटर की बत्तियाँ बुझने से ठीक पहले कलाई पर बँधने वाली एक छोटी पट्टी। पर्दा उठते ही सब एक ही अँधेरे में वही दृश्य पहली बार देखते हैं। उस पहले पल में साथ होने का यह एक छोटा-सा हाज़िरी-निशान है।"},"ICON-0375":{"nm":"स्मृति पर्दा टुकड़ा","de":"आख़िरी शो के दिन, अंतिम अभिवादन के बाद पर्दा धीरे-धीरे उतरा। उसी हिस्से से काटकर फ्रेम में जड़ा एक टुकड़ा। कपड़े में रोशनी की गर्मी और तालियों की गूँज अब भी हल्की गुनगुनी बसी है, अभी ठंडी नहीं हुई।"},"ICON-0376":{"nm":"पहली प्रस्तुति मुहर","de":"दुनिया के सामने पहली बार आने वाले दिन, उस एक पल के लिए उकेरी गई मुहर। दूसरी बार पहला प्रकटीकरण नहीं होता, इसलिए स्याही सूखने का छोटा-सा पल भी फिर कभी न लौटने वाला समय है।"},"ICON-0377":{"nm":"मंच पल कार्ड","de":"किसी मंच पर सबसे चमकीले एक फ़्रेम को काटकर कार्ड में समाया गया है। संगीत और रोशनी थम चुके हैं, पर हाथ में आते ही उस दिन के जयकारे कानों में फिर से गूँज उठते हैं — थमा हुआ दृश्य जी उठने का एक छोटा जादू।"},"ICON-0378":{"nm":"एंडिंग पोज़ मेमो","de":"आख़िरी सुर थमने के उस पल, ठहर जाने वाली उँगलियों और नज़र के कोण को उकेरता एक मेमो। एंडिंग का एक फ़्रेम कई दिन तय कर सकता है, यह जानने वाला ही इस छोटे-से चित्र को नाज़ुक तरीक़े से मोड़कर रखता है।"},"ICON-0379":{"nm":"टूर सिटी पिन","de":"नक़्शे पर घूमे गए हर शहर में एक पिन गड़ जाती है। बुसान की समुद्री हवा और ग्वांगजू की दोपहर, दोनों इन छोटी कील-नोकों में क़ैद हैं। बिंदुओं को चुपचाप जोड़ो तो एक पूरे मौसम को पार करती लंबी यात्रा की रेखा दिखती है।"},"ICON-0380":{"nm":"सीटिंग सेक्शन क्लिप","de":"हज़ारों सीटों को खंडों में बाँटकर रास्ता दिखाती है, ताकि कोई भटके नहीं, किसी से टकराए नहीं। मुझे फ़ॉलो करो, हर कोई अपनी जगह पहुँच जाएगा। व्यवस्था आख़िर में सबके लिए एक छोटी-सी दयालुता ही तो है।"},"ICON-0381":{"nm":"एंट्री गेट टैग","de":"गेट के आगे एक-एक कर बारी से जाँच होती है। टिकट थामा हाथ और धड़कता दिल भीतर लाने वाला आख़िरी द्वार। मुझसे गुज़रते ही लंबा इंतज़ार ख़त्म होता है और आज का मंच शुरू होता है।"},"ICON-0382":{"nm":"रिस्टबैंड यादगार कैप्सूल","de":"रंग फीका पड़ जाए तो भी उस दिन की गूँज ज्यों-की-त्यों सील रहती है। कलाई की पट्टी को फेंकने का दिल नहीं होता, इसलिए उसे नाज़ुकी से लपेटकर एक छोटे कैप्सूल में रख देते हैं। अनमोल याद को भी लेटने की एक जगह देना चाहते हैं, इसीलिए।"},"ICON-0383":{"nm":"ऑन-साइट एक्सचेंज पोल","de":"फ़ैन और मंच के बीच, हाथ से हाथ कुछ पहुँचता है — शायद चिट्ठी, शायद कोई छोटा तोहफ़ा। मैं उस दिल के सुरक्षित पहुँचने के लिए रास्ता बनाता हूँ, यहाँ का सबसे व्यस्त पुल।"},"ICON-0384":{"nm":"प्रदर्शन तारीख़ मुहर","de":"उस दिन की तारीख़ एक गोल मुहर के भीतर छपकर हमेशा के लिए ठहर जाती है। कैलेंडर के पन्ने पलटते जाएँ, पर यह छोटा गोला उसी एक दिन में ठहरा रहता है। जो दिन भुलाना न चाहें, लोग हमेशा कुछ-न-कुछ मुहरबंद कर देते हैं।"},"ICON-0385":{"nm":"टूर बैग पैच","de":"साथ टूर पर घूमे बैग में हर शहर के लिए एक-एक पैच जुड़ता जाता है। कपड़े पर सिले शहरों के नाम कब एक बायोडाटा बन जाते हैं, पता ही नहीं चलता। घिसे-फटे किनारे भी हर जगह साथ जाने का सबूत बनकर रह जाते हैं।"},"ICON-0386":{"nm":"टिकट बोर्ड कॉर्ड","de":"प्रवेश-कतार के आख़िर में हिलता एक बोर्ड, उसके सिरे को कसकर बाँधती एक डोरी। टिकट ऊँचे थामे हाथों की लंबी क़तार के बीच, मैं उत्साह की क़तार के सबसे आगे की जगह चुपचाप चिह्नित करती हूँ।"},"ICON-0387":{"nm":"आंकोर रिबन टुकड़ा","de":"आंकोर की पुकार सबसे ऊँची रही उस रात, मंच सजाने वाले रिबन का एक टुकड़ा गिर गया। ख़त्म होने का अफ़सोस जताते और लंबा गाए गीत की तरह, इस टुकड़े में भी जाने का मन न होने की एक गाँठ बँधी है।"},"ICON-0388":{"nm":"संदेश कैप्सूल बोतल","de":"शीशे की बोतल के भीतर नाज़ुकी से मोड़कर रखी एक बात। कभी पहुँचने की आस लिए बहाई गई छोटी नाव की तरह, मैं दिल को थामे समय पर धीरे-धीरे बहती हूँ। खुलने वाले उस दिन तक, वादा भीतर चुपचाप सोया रहता है।"},"ICON-0389":{"nm":"नन्हा इक़रार टैग","de":"मुँह से न कह पाई बात एक छोटे टैग पर लिखकर चुपके से टिका दी जाती है। लिखावट काँपती है, पर सच्चाई साफ़ रहती है। सबसे छोटा कागज़ कभी-कभी सबसे बड़ी हिम्मत थामे रहता है।"},"ICON-0390":{"nm":"गुमनाम हौसला-पेटी","de":"नाम न लिखो तो भी दिल की बात पहुँच जाती है। पेटी में आई हर पर्ची में किसी की हौसला-अफज़ाई एक-एक कर गुमनाम जमा होती जाती है। किसने लिखा, पता न हो पर गर्माहट साफ़ हो, ऐसा बेचेहरा अपनेपन का संग्रह।"},"ICON-0391":{"nm":"कामना-मोड़ कागज़","de":"एक चौकोर कागज़ उँगलियों के साथ-साथ सारस बनता है, तारा बनता है। हर बार मोड़ने पर चाही हुई मुराद भी एक परत और सिमट जाती है। मन लगाकर मोड़े आकार में, शब्दों से ज़्यादा देर टिकने वाली सच्चाई बसती है।"},"ICON-0392":{"nm":"मुहरबंद रिबन मोम","de":"मोम टपकाकर मुहर ज़ोर से दबा दो तो चिट्ठी आख़िरकार सील हो जाती है — दिल को मज़बूती से बाँधने का यही पुराना तरीक़ा है। ठंडी होती लाल मोम पर एक राज़ चुपचाप बंद हो जाता है।"},"ICON-0393":{"nm":"उपहार सुरक्षा कागज़","de":"उपहार को चोट न लगे, इस डर से उसके चारों ओर नरमी से लपेटा जाता है। हर सिलवट में टूट न जाने की गुज़ारिश बसी है। पाने वाले को पता भी नहीं चलेगा, ऐसी अनदेखी जगह में बसी एक सावधान परत।"},"ICON-0394":{"nm":"रंगीन चिट्ठी डोरी","de":"चिट्ठी बाँधने वाली डोरी का भी अपना रंग होता है — पीला हौसले का, नीला याद का। शब्दों में पूरी न कही जा सकी भावना रंग चुनकर गाँठ में बाँध दी जाती है। खोलने से पहले ही दिल का तापमान उँगलियों तक पहले पहुँच जाता है।"},"ICON-0395":{"nm":"हस्तलिपि ढकने वाली पट्टी","de":"सौंपने के आख़िरी पल तक लिखावट छुपाए रखने वाली एक पट्टी। पकड़े जाने के डर से काँपते इक़रार को अंतिम क्षण तक थामे रखती है। हल्का-सा उठाते ही खुलने वाली सच्चाई, उस सिहरन का भार मैं सबसे क़रीब से जानती हूँ।"},"ICON-0396":{"nm":"चीयर वाक्य चिप","de":"लाइट स्टिक की लहरें उठें उस रात, एक स्वर में पुकारा जाने वाला एक वाक्य चिप के भीतर उकेरा है। बिखरे दिलों को एक पंक्ति में जोड़ने वाला वादे का शब्द। जब सब मिलकर गाएँ, तभी वह वाक्य सबसे तेज़ चमकता है।"},"ICON-0397":{"nm":"पुरानी प्रैक्टिस रूम की-रिंग","de":"प्रैक्टिस रूम का दरवाज़ा सैकड़ों बार खोलने-बंद करने वाली की-रिंग। रंग उतर गया, कड़ी ढीली हो गई, पर उसमें सबसे अनाड़ी दिनों का पसीना हाथ की छुअन बनकर रह गया है। पुराना होना यानी उतनी ही देर तक ठहरे रहना है।"},"ICON-0398":{"nm":"मंच मेकअप क्रेयॉन टुकड़ा","de":"मंच का मेकअप रोशनी के नीचे ही आख़िरकार पूरा होता है — उसी गहरे रंग का एक टुकड़ा। पसीने में भी न फैले इतनी कसावट से लगाने के निशान में, दूर की सीटों तक भाव पहुँचाने की पूरी मेहनत बसी हुई है।"},"ICON-0399":{"nm":"इयरटिप केस","de":"मंच पर अपनी ही आवाज़ सुनने देने वाला वह नन्हा इयरटिप। शो ख़त्म होते ही उसे केस के भीतर नाज़ुकी से लिटा दिया जाता है। जो चीज़ संगीत को सबसे क़रीब से पहुँचाती है, उसे उतनी ही देखभाल से सँभालने का मन करता है।"},"ICON-0400":{"nm":"निजी लॉकर लेबल","de":"छात्रावास के गलियारे के छोर पर, हर लॉकर पर एक नाम-पर्ची चिपकी है। किसकी जगह है, यह बताने वाली छोटी लिखावट एक अजनबी जगह को घर में बदल देती है। अपना खाना मिलना, यहाँ ठहरने की एक मीठी इजाज़त है।"},"ICON-0401":{"nm":"पोर्टेबल गला-देखभाल बोतल","de":"रिहर्सल के बीच वह धीरे-धीरे गुनगुने पानी का एक घूँट उतारती है। गला तो गायक के लिए उधार लिया हुआ साज़ है, इसलिए ठंडा होने से पहले भरी यह छोटी बोतल कल की पहली सुर की रखवाली पहले से करती है। स्नेह भरा मन हमेशा इतना ही मौन होता है।"},"ICON-0402":{"nm":"शेड्यूल रिमाइंडर पिन","de":"मिनट-दर-मिनट भरे दिन के ऊपर, एक पिन अगले खाने की ओर इशारा करती है। उन घनी पंक्तियों के बीच सबसे सुखद चीज़ है एक खाली खाना। खिड़की से बाहर झाँकने का वह छोटा-सा समय वहीं, दुबका हुआ छिपा है।"},"ICON-0403":{"nm":"ग्रीनरूम कंबल क्लिप","de":"श्रृंगार पूरा करके कुर्सी से टिककर झपकी लेती एक दोपहर, किसी ने चुपचाप कंधों पर कंबल ओढ़ा दिया। फिसलने से रोकने के लिए दबाई गई यह क्लिप, मंच पर जाने तक उस स्पर्श की गर्माहट को चुपचाप थामे रखती है।"},"ICON-0404":{"nm":"छोटी परफ्यूम शीशी","de":"कलाई के अंदरूनी हिस्से पर हल्के से थपथपाओ तो खुशबू बस एक बित्ते भर में ही खिलती है। दूर तक न फैले तो कोई बात नहीं। जो पास आए वही इस निशान को पहचाने, यही तो इसे और गोपनीय, और अपना-सा बनाता है।"},"ICON-0405":{"nm":"अभ्यास-पोशाक धुलाई टैग","de":"कितनी भी बार धोओ, कपड़े में गहरे बस गई पसीने की महक कभी पूरी तरह नहीं जाती। धूप में सुखाकर मुलायम हुई अभ्यास-पोशाक को फिर से तह करते हुए वह सोचती है—जो निशान मिटता नहीं, वही असल में सबसे ईमानदार निशान है।"},"ICON-0406":{"nm":"लाइटिंग जेल फिल्म","de":"एक पतली रंगीन फिल्म लगाते ही सफ़ेद रोशनी शाम की लालिमा में घुल जाती है, और एक और परत चढ़ाते ही भोर उतर आती है। मंच को किस मौसम का रंग देना है, यह तय करती एक हाथ पर्दे के पीछे साँस रोके खड़ी है।"},"ICON-0407":{"nm":"स्पॉटलाइट लेंस कैप","de":"कैमरा बंद रहने के दौरान भी कोई इस छोटी टोपी को खोलकर लेंस साफ़ करता है। अभी न खींचे गए अगले दृश्य के लिए। पर्दे पर न दिखने वाले उस समय में, सबसे व्यस्त हाथ पहले से फोकस मिलाकर रखता है।"},"ICON-0408":{"nm":"मंच परावर्तक बोर्ड","de":"खुद न चमकते हुए भी, मिली रोशनी को छाया भरे चेहरे तक लौटा देने वाला एक बोर्ड होता है। मंच का बीचोंबीच इतना उजला इसलिए है क्योंकि किनारे पर कोई चुपचाप कोण साधकर उसे परावर्तित करती एक बाँह वहाँ मौजूद है।"},"ICON-0409":{"nm":"कलर फ़िल्टर स्लीव","de":"पारदर्शी स्लीव में नीली रोशनी डालो तो दर्शक-दीर्घा पूरी तरह समंदर बन जाती है, और लाल में बदलो तो वहीं शाम ढल जाती है। एक ही मंच का महज़ एक रंग से अलग मौसम बन जाने का जादू, इसी पतली एक परत से शुरू होता है।"},"ICON-0410":{"nm":"लाइट नंबर पिन","de":"अनगिनत रोशनियों में से हर एक पर एक छोटा नंबर लगा है। कौन-सी जलेगी, कौन-सी सोएगी, आज रात के शो का प्रवाह इन्हीं अंकों के क्रम में पहले से बुना जा चुका है। चमकते पर्दे के पीछे हमेशा एक बारीक सूची खुली पड़ी रहती है।"},"ICON-0411":{"nm":"लाइटिंग टेप मार्कर","de":"अँधेरे में डूबे मंच के फ़र्श पर, चमकीला टेप उस जगह को चुपचाप उजागर करता है जहाँ पैर को थमना है। दर्शक-दीर्घा से न दिखने वाली, पर कलाकार के पंजे इसी धुँधली रोशनी को टटोलकर अपनी जगह ढूँढते हैं। अँधेरे में भी एक स्नेहिल राह-दिखाने वाला होता है।"},"ICON-0412":{"nm":"शैडो ब्लॉकिंग बोर्ड","de":"रिसती रोशनी को रोककर छाया को तीखा गिराने वाला एक बोर्ड। अँधेरे को साधना आखिर रोशनी को ही साधना है, इसलिए क्या दिखाना है यह पहले तय होता है इस बात से कि क्या चुपचाप छिपाकर रखना है।"},"ICON-0413":{"nm":"प्रकाश-मात्रा जाँच चिप","de":"जगह की चमक नापने वाली एक छोटी चिप हथेली पर अंक पढ़ती है। बहुत उजाला भी, बहुत अँधेरा भी आँखों को खलता है। इंसान जहाँ सबसे सुकून से ठहरता है, वह अदृश्य उचित सीमा, यही चिप चुपचाप निभाती है।"},"ICON-0414":{"nm":"पिन-स्पॉट शेड","de":"पिन-स्पॉट कहीं और न फैले, इसके लिए लगाया गया एक ढकना। रोशनी को सिर्फ़ एक व्यक्ति पर समेटना एक स्नेहिल एकाग्रता है। उस गोल घेरे की रोशनी में पैर रखते ही, दुनिया कुछ पल के लिए बस एक ही व्यक्ति को देखती है।"},"ICON-0415":{"nm":"ईयरटिप सेट","de":"कान में ठीक से बैठी ईयरटिप की एक जोड़ी। नाप में ज़रा भी चूक हो तो आवाज़ रिसती है, और रिसते ही ताल छूट जाती है। मंच पर बिना कँपे बहता गाना, कभी-कभी असल में इसी छोटी रबर की एक जोड़ी से शुरू होता है।"},"ICON-0416":{"nm":"केबल वेल्क्रो","de":"उलझे तारों को एक लड़ी में करीने से बाँधती वेल्क्रो पट्टी। जिसे कोई न देखे, मंच के पीछे उतना ही व्यवस्था चमकती है। केबलों के एक बंडल की सफ़ाई, मंच के आगे बिना कँपे बहती आवाज़ को चुपचाप थामे रखती है।"},"ICON-0417":{"nm":"लाइन चेक लेबल","de":"दर्जनों तारों में से हर एक पर कौन-सा साज़ है यह हाथ से लिखकर चिपकाए गए नाम-पर्चे। उस टेढ़े-मेढ़े लेखन के हर हिस्से को अपनी जगह टिके रहना ज़रूरी है, तभी अलग-अलग बज रही आवाज़ें आख़िर एक धुन में मिलकर बहती हैं।"},"ICON-0418":{"nm":"साइलेंस पैड","de":"पैरों की आहट और कंपन, दोनों को चुपचाप निगल जाने वाला एक साइलेंस पैड। जहाँ सचमुच सन्नाटे की ज़रूरत है, वहीं यह बिछाया जाता है। सबसे साफ़ आवाज़ कभी-कभी इसी शांत फ़र्श पर जन्म लेती है, जहाँ से कोई शोर बाहर नहीं रिसता।"},"ICON-0419":{"nm":"साउंड चेक टोकन","de":"शो से पहले आवाज़ मिलाते वक़्त हाथ में गर्म होता एक टोकन। हर बार जब एक माइक, एक स्पीकर की जाँच पूरी होती है, यह जगह बदलकर थमा दिया जाता है। असली मंच की पूर्णता इसी शांत रिहर्सल में कदम-दर-कदम गढ़ी जाती है।"},"ICON-0420":{"nm":"माइक कवर कैप","de":"यहाँ अनगिनत आवाज़ें छू चुकी हैं, इसलिए माइक की नोक को ढँकने वाली इस कैप को और मन से पोंछा जाता है। यह गीत को थामने वाला पात्र है, सो गायिका के लिए मानो एक और हाथ। पोंछते-पोंछते वह कल की पहली पंक्ति पहले से गुनगुना लेती है।"},"ICON-0421":{"nm":"पॉप फ़िल्टर क्लिप","de":"होंठों और माइक के बीच झूलती एक पतली जाली की परत। उस पर्दे को थामे रखने वाली छोटी क्लिप की बदौलत, खुरदुरी रिसती साँसें ना जाने कब गोल और मुलायम आवाज़ में ढलकर बहने लगती हैं।"},"ICON-0422":{"nm":"साउंड रैक टैग","de":"घुप्प अँधेरे बैकस्टेज में, तह-दर-तह सजे उपकरण की रैक के बीच राह न भटकने के लिए टाँगा गया एक छोटा टैग। दर्शक-दीर्घा को भर देने वाली शानदार आवाज़ का स्रोत हमेशा ऐसी ही धुँधली जगह पर करीने से सजाकर रखा जाता है।"},"ICON-0423":{"nm":"स्पीकर ग्रिल पिन","de":"स्पीकर की जाली को मज़बूती से थामे रखने वाली पिन। जहाँ से आवाज़ बाहर निकलती है वह खिड़की सबसे पहले धूल की मार खाती है, इसलिए एक पतली जाली सुर की रखवाली करती है। कान तक पहुँचने वाली हर चीज़ पर अदृश्य सुरक्षा की एक-एक परत चढ़ी होती है।"},"ICON-0424":{"nm":"स्टेप मार्कर स्टिकर","de":"फ़र्श पर बिंदु-बिंदु चिपकाए गए चाल के निशान। सामूहिक नृत्य का तलवार-सा एकसाथ मेल खा जाना, असल में पैरों तले छिपा एक राज़ है। दर्जनों लोग एक ही बिंदु पर पैर रखकर बिखरते और फिर जुटते हैं, इन्हीं अनगिनत वादा किए गए निशानों पर।"},"ICON-0425":{"nm":"टर्न प्रैक्टिस डिस्क","de":"अपनी जगह पर गोल-गोल घूमने वाली अभ्यास चकती। चक्कर से जीतने के लिए पहले एक बिंदु पर नज़र गड़ाना सीखना पड़ता है। चाहे कितनी भी तेज़ी से घूमो, उस एक बिंदु को कभी न छोड़ने का संतुलन, यह शरीर में धीरे-धीरे उतरता जाता है।"},"ICON-0426":{"nm":"नी टेप रोल","de":"घुटने को मज़बूती से लपेटने वाला एक टेप का रोल। हज़ारों बार कूदकर उतरने वाले जोड़ आख़िर तक चुप रहते हैं, पर यह एक परत उस मौन को चुपचाप थामे रहती है। अंत तक टिके रहने वाले शरीर के पीछे हमेशा किसी की देखभाल होती है।"},"ICON-0427":{"nm":"टो एलाइनमेंट बोर्ड","de":"पंजों के कोण को करीने से साधने वाला एक बोर्ड। कहते हैं नृत्य उँगलियों से ज़्यादा पंजों में पूरा होता है। एक ही दिशा में फैले दर्जनों पंजे मिलकर, अनेक के एक इंसान जैसे दिखने का जादू रचते हैं।"},"ICON-0428":{"nm":"प्रैक्टिस रूम नॉन-स्लिप पैड","de":"अभ्यास कक्ष के फ़र्श पर बिछाया गया फिसलन-रोधी पैड। मन खोलकर कूदने के लिए पहले सुरक्षित होना ज़रूरी है। गिरने के डर के बिना बेफ़िक्र लुढ़का जा सके ऐसे फ़र्श पर ही, सबसे साहसी और निडर हरकतें आख़िरकार खिलती हैं।"},"ICON-0429":{"nm":"मूव ब्रेकडाउन कार्ड","de":"कोरियोग्राफ़ी को एक-एक ताल में बारीकी से बाँटकर बनाया गया कार्ड। कितनी भी मुश्किल हरकत हो, हिस्सा-हिस्सा बाँटो तो कब वह साथ चलने लगती है, पता ही नहीं चलता। मंच पर पानी-सा बहता सहज प्रवाह, इन्हीं तोड़-तोड़कर याद किए गए चित्रों से मिलकर बनता है।"},"ICON-0430":{"nm":"मिरर कवर कर्टन पिन","de":"अभ्यास कक्ष के आईने को कुछ देर ढँकने वाले पर्दे को थामे रखने वाली पिन। बिना किसी प्रतिबिंब के, केवल शरीर के एहसास से नाचने का समय भी ज़रूरी है। आईना ढँकते ही संगीत आख़िरकार त्वचा तक उतर आता है, यह वह जानती है।"},"ICON-0431":{"nm":"बीट काउंट बीड","de":"टक्, हर ताल पर एक-एक दाना उँगली से सरकाते हुए गिनती गिनी जाती है। पुराने गिनने के तरीक़े की तरह, हाथ में पकड़ में आने वाली चीज़ से। संगीत की रीढ़, यानी ताल, ऐसी छूकर महसूस होने वाली चीज़ से सीखी जाए तभी वह शरीर में मज़बूती से बैठती है।"},"ICON-0432":{"nm":"वार्मअप चेक स्ट्रैप","de":"शरीर पूरी तरह खुल गया या नहीं, यह दर्शाने वाली एक जाँच रस्सी। असली अभ्यास से पहले हमेशा एक शांत तैयारी आती है। चोट लगने के बाद पछताने से बेहतर है एक डोरी बाँधकर धीरे-धीरे शरीर को जगाना, यही आख़िर में लंबे समय तक नाचने देता है।"},"ICON-0433":{"nm":"कॉस्ट्यूम नंबर क्लिप","de":"कई पोशाकें आपस में गड्डमड्ड न हों, इसलिए नंबर टाँकने वाली क्लिप। साँस रोककर कपड़े बदलने के बीच एक पोशाक भी उलझी तो बड़ी मुसीबत, इसलिए हर कपड़े पर उसकी बारी साफ़ लिखी होती है। हड़बड़ी भी व्यवस्था का सहारा मिले तो सुंदर लगती है।"},"ICON-0434":{"nm":"मेंडिंग रूम पिन कुशन","de":"सिलाई कक्ष के एक कोने में रखा पिन कुशन। फटी सिलाई और टूटे बटन को चुपचाप जोड़ता आया एक हाथ यहाँ ठहरता है। मंच पर बेदाग़ पोशाक के पीछे, मंच कभी न देखने वाली सुई की एक-एक टाँके की मेहनत छिपी है।"},"ICON-0435":{"nm":"फ़ैब्रिक स्क्रैप रिंग","de":"बचे हुए कपड़े के टुकड़ों को एक साथ पिरोई गई एक रिंग। असली पोशाक खराब होने की स्थिति के लिए वैसा ही कपड़ा पहले से बचाकर रखा जाता है। कुछ न हो यह उम्मीद करते हुए रखी गई यह छोटी तैयारी, ठीक बड़ी मुसीबत आने पर मंच की पोशाक बचा लेती है।"},"ICON-0436":{"nm":"क्विक बटन पैक","de":"जल्दी में सीधे टाँके जा सकने वाले बटनों का एक पैक। शो से ठीक पहले एक बटन टूट जाए तो पूरा ड्रेसिंग रूम पल भर में हलचल से भर जाता है। उस छोटी पर घबरा देने वाली आपातस्थिति को एक ही झटके में शांत करने वाला, छोटा पर बेहद भरोसेमंद प्राथमिक-उपचार बक्सा।"},"ICON-0437":{"nm":"स्टेज बेल्ट होल्डर","de":"मंच की पोशाक की बेल्ट को कसकर थामने वाला होल्डर। चाहे कितनी भी ज़ोर से कूदो या घूमो, कपड़े न बिगड़ें। मंच पर बेफ़िक्र भोगी गई वह आज़ादी, दरअसल कहीं न दिखने वाली जगह को कसकर बाँध देने से ही आती है।"},"ICON-0438":{"nm":"फ़ेदर डस्टर","de":"रोशनी के नीचे एक छोटा-सा रोआँ भी उभरकर दिखता है, इसलिए पंखों वाले झाड़न से पोशाक पर धीरे-धीरे झाड़ते हैं। मंच पर पैर रखने से ठीक पहले, कपड़े को आख़िरी बार सँवारने वाला वह स्नेहिल स्पर्श हमेशा इसी मुलायम पंख का हिस्सा होता है।"},"ICON-0439":{"nm":"ग्रीनरूम स्लिपर टैग","de":"ग्रीनरूम की हर चप्पल पर लगा एक नाम-पर्चा। किसकी है यह लिखा एक छोटा-सा टैग, हम एक ही टीम हैं इस चुपचाप राहत को अपने में समेटे रहता है। जूते उतारकर पैर फैलाने वाला वह कमरा, बैकस्टेज का सबसे आरामदायक घर बन जाता है।"},"ICON-0440":{"nm":"स्टाइलिंग क्लिप बोर्ड","de":"बाल सँवारते वक़्त लटों को थामे रखने वाला क्लिप बोर्ड। एक-एक लट सँवारते हुए, उँगलियाँ बिखरने को उतावले बालों को कुछ देर के लिए इस क्लिप को सौंप देती हैं। करीनापन आख़िर ऐसे ही छोटे-छोटे ठहरावों के जुटने से बनता है।"},"ICON-0441":{"nm":"सेफ़्टी पिन ऑर्गनाइज़र कैप्सूल","de":"सिलाई फट जाने वाली किसी भोर, कैप्सूल का ढक्कन खोलो तो छोटी ठंडी चाँदी करीने से लेटी दिखती है। कहीं न दिखने वाली भीतर की जगह से पोशाक को सबसे मज़बूती से थामने वाला हाथ—सेफ़्टी पिन हमेशा मंच के पीछे चुपचाप काम करती है।"},"ICON-0442":{"nm":"लेंस क्लीनिंग क्लॉथ","de":"फूँक मारकर गोल-गोल घुमाते हुए पोंछो तो धुँधली दुनिया साफ़ हो जाती है। वह छोटा-सा पल इतना अच्छा लगता है कि बार-बार लेंस पोंछने का मन करता है। किसी की नज़र को उसकी जगह साफ़ कर देने वाली एक छोटी वसंत की धूप।"},"ICON-0443":{"nm":"ट्राइपॉड रबर फ़ीट","de":"तीनों पैरों की नोक पर रबर लगाते ही फ़र्श अब चीखना बंद कर देता है। जैसे-जैसे यह छोटा-सा बिंदु कँपन को निगल जाता है, स्क्रीन का दृश्य झूठ-सा शांत हो जाता है। स्थिरता हमेशा पैरों तले से ही चुपचाप शुरू होती है।"},"ICON-0444":{"nm":"कैमरा रेन कवर","de":"बूँदें भले टपकती रहें, लेंस सूखा रहकर दुनिया को कैद करता है। बाहर शूटिंग की एक धुँधली दोपहर में, कैमरे पर एक पारदर्शी रेनकोट सहज ही चढ़ा दिया जाता है। जो प्यारा है उसे भीगने से पहले ही ढँक लेना चाहिए, यही तो है।"},"ICON-0445":{"nm":"फ़िल्मिंग मार्कर टेप","de":"यहाँ खड़े हो जाओ, वहाँ मुड़ो—रंग-बिरंगे छोटे निशान बिना एक शब्द कहे राह साफ़ बता देते हैं। शो खत्म होने पर बेझिझक उतार भी दो, फिर भी अभ्यस्त पंजे उस जगह को बहुत देर तक याद रखते हैं।"},"ICON-0446":{"nm":"कट डिवाइडर क्लिप","de":"बिखरने को तैयार काग़ज़ों को एक ही ग्रास में दबोच लेने वाली एक छोटी क्लिप। टक्, एक ताज़गी भरी आवाज़ में कल और आज करीने से बँध जाते हैं। सँवारना असल में खो जाने से बचाई गई किसी चीज़ को चुपचाप थामे रखने की एक स्नेहिल आदत है।"},"ICON-0447":{"nm":"व्हाइट बैलेंस बोर्ड","de":"सफ़ेद बोर्ड को स्क्रीन के सामने रखो तो रंग धीरे-धीरे अपनी जगह ढूँढ लेते हैं। पीली शाम भी, नीली भोर भी, बिना किसी झूठ के। सच्ची सफ़ेदी को जानने वाला एक बोर्ड, बाक़ी सारे रंगों को ईमानदारी से बोलने देता है।"},"ICON-0448":{"nm":"मेमोरी स्टोरेज कैन","de":"एक छोटे टिन के डिब्बे में यादों की चिप्स गहरी नींद में सोई हैं। ढक्कन खोलो तो खटाक, बीते मौसम के दृश्य हथेली में बरस पड़ते हैं। स्मृति ऐसे ही किसी मज़बूत डिब्बे में सहेजकर रखी रहती है।"},"ICON-0449":{"nm":"मॉनिटर हुड कैप","de":"मॉनिटर के चारों ओर एक काला शेड लपेटते ही चमक का प्रतिबिंब एकदम रुक जाता है। धूप से भरी खिड़की के पास भी स्क्रीन अपना रंग नहीं खोती। अच्छी तरह देखने के लिए पहले फ़ालतू चमक को रोकना होगा, यह हुड चुपचाप बता देता है।"},"ICON-0450":{"nm":"सेट साउंडप्रूफ़ पिन","de":"दरवाज़े की दरार में लगी एक छोटी पिन बाहरी शोर को धीरे से काट देती है। गलियारे की आहट भी, बगल के कमरे की हँसी भी यहाँ तक नहीं पहुँच पाती। साफ़ आवाज़ पकड़नी है तो पहले सन्नाटा रचना होगा, आख़िर।"},"ICON-0451":{"nm":"मेकअप स्पंज पैक","de":"मुलायम स्पंज करीने से एक साथ रखे एक बंडल में। उँगलियों से हल्के थपथपाकर पाउडर लगाओ तो चेहरा एक टोन उजला हो जाता है। मंच पर चमकती मुस्कान के पीछे हमेशा ये कोमल स्पर्श छिपे होते हैं।"},"ICON-0452":{"nm":"हेयरपिन केस","de":"आसानी से खो जाने वाली छोटी पिनों का करीना घर। ढक्कन खोलो तो चाँदी की कतारें कतार बाँधकर स्वागत करती हैं। बिखर जाएँ तो दिखतीं ही नहीं, पर जुट जाएँ तो भरोसा देती हैं—छोटी चीज़ों को भी अपना घर चाहिए।"},"ICON-0453":{"nm":"ब्रश स्टेरिलाइज़िंग बॉक्स","de":"दिनभर रंग सँभाले हुए ब्रश डिब्बे के भीतर पराबैंगनी स्नान करते हैं। जब अदृश्य रोशनी पुराना मैल धो देती है, कल की नोक फिर से पहले जैसी मुलायम हो जाती है। स्वच्छता भी मेहनत की एक तह है।"},"ICON-0454":{"nm":"पाउडर पफ़ मेश","de":"गोल-गोल पफ़ जाली के भीतर चुपचाप साँस लेते हैं। जाली से हवा आती-जाती रहे तो मुलायमियत लंबी टिकती है। अच्छी तरह सूखा एक पफ़, कल सुबह की चमक पहले से अपने भीतर समेटे रहता है।"},"ICON-0455":{"nm":"होल्ड-स्प्रे कैप","de":"छिड़्... एक बार छिड़कते ही हवा में भी बाल नहीं बिखरते। मेहनत से बनाए बालों के आकार को रातभर थामे रखने वाला एक छोटा ढक्कन। कसकर सजे इस केशराशि पर चमकदार रोशनी बिखरती हुई गिरती है।"},"ICON-0456":{"nm":"लिप ब्रश कवर","de":"पतली नोक वाली बालियों को धीरे से लपेटने वाला एक छोटा ढक्कन। बैग में इधर-उधर हिलने पर भी ब्रश सीधा और साफ़ बना रहता है। एक छोटे ब्रश को सँभालने वाला मन ही होंठों पर रंग की एक रेखा पूरी करता है।"},"ICON-0457":{"nm":"क्यू-नंबर मिरर","de":"अपनी बारी बताने वाले अंक के बग़ल में एक छोटा आईना चुपचाप लगा है। मंच पर जाने से ठीक पहले, बिखरी अगली लट को आख़िरी बार सँवारने की जगह। घबराहट भी एक बार आईने में देख ले तो थोड़ी हल्की हो जाती है।"},"ICON-0458":{"nm":"रिस्टबैंड टॉवेल","de":"माथे का पसीना कलाई की एक हरकत से पोंछ देने वाला एक मुलायम पट्टा। कोरियोग्राफ़ी जितनी तीखी होती जाए, हाथ उतना ही बार-बार वहाँ जाता है। साँस उखड़ते हर पल साथ रहने वाला, कलाई पर टिकी एक छोटी तसल्ली की लकीर।"},"ICON-0459":{"nm":"प्रॉप बैग लेबल","de":"ड्रेसिंग रूम में दस एक जैसे बैग कतार में खड़े हों तो भी कोई गड़बड़ नहीं होती। हर बैग पर लगा नाम-पर्चा उसके मालिक को साफ़ बता देता है। 'यह मेरा है' लिखना एक छोटा पर स्नेहिल निशान है।"},"ICON-0460":{"nm":"प्रैक्टिस रूम बुकिंग पिन","de":"आज यह अभ्यास कक्ष किसका होगा। दरवाज़े के सामने बोर्ड पर टिकी एक छोटी पिन बिना बोले समय बाँट देती है। अगली बारी का इंतज़ार करते दिल इसी एक पिन के पीछे चुपचाप कतार बाँधते हैं।"},"ICON-0461":{"nm":"वॉल क्लॉक कवर रिंग","de":"दीवार घड़ी पर एक पारदर्शी ढक्कन धीरे से बैठकर धूल को रोक देता है। टिक-टिक करती सुइयाँ धुँधली नहीं होतीं और समय साफ़ बहता रहता है। जो प्यारा हो उस पर हमेशा एक अदृश्य सुरक्षा की परत चाहिए होती है।"},"ICON-0462":{"nm":"फ़्लोर प्रोटेक्टर पैड","de":"कुर्सी के पैर के नीचे लगा एक पतला पैड लकड़ी के फ़र्श की खरोंच पहले से रोक देता है। घसीटो तो भी खरोंच नहीं आती, हटाओ तो भी कोई निशान नहीं छूटता। फ़र्श की अनदेखी परवाह, यही लंबे समय तक टिकाए रखने का राज़ है।"},"ICON-0463":{"nm":"नो-ड्रिंक्स मार्कर चिप","de":"यहाँ पीने की चीज़ थोड़ी देर के लिए एक तरफ़ रख दो, एक छोटी चिप स्नेह से यही विनती करती है। सुर-ताल की किताबें और उपकरण भीग जाएँ तो मुश्किल होगी। 'मना है' जैसा शब्द भी इस तरह कहा जाए तो कब गर्मजोशी भरा ख़याल बन जाता है, पता ही नहीं चलता।"},"ICON-0464":{"nm":"वेंटिलेशन बटन लेबल","de":"घुटन भरी हवा को बदलना हो तो यहाँ दबाना, बटन के बग़ल में एक छोटा लेबल राह दिखाता है। साँस खुलने का काम, हैरानी की बात है, इसी एक मामूली-से निशान से चुपचाप शुरू होता है।"},"ICON-0465":{"nm":"स्पीकर रबर फ़ुट","de":"स्पीकर के नीचे बिछा रबर स्टैंड भारी कँपन को धीरे से निगल लेता है। बेस अब फ़र्श पर फैलकर नहीं भटकता, इसलिए आवाज़ और साफ़ बजती है। अच्छी गूँज हमेशा एक मज़बूत आधार पर ही आख़िरकार निखरती है।"},"ICON-0466":{"nm":"लॉकर नंबर मैग्नेट","de":"लॉकर के दरवाज़े पर सटकर चिपकने वाला एक छोटा अंक-चुंबक। आज मेरा सामान किस नंबर के खाने में सोएगा। रोज़ जगह बदले तो भी, एक चुंबक भर से पल भर में मेरा खाना बन जाता है। अपनापन ऐसे ही हल्के निशान से आता है।"},"ICON-0467":{"nm":"मिरर वाइपर","de":"आईने पर एक बार सरका दो तो भाप की धुंध साफ़ हट जाती है। धुँधला चेहरा एकदम साफ़ उभर आने का वह पल। खुद को ठीक से देखने के लिए पहले जो धुँधला है उसे चुपचाप पोंछना ज़रूरी है।"},"ICON-0468":{"nm":"डोर कुशन पैड","de":"ज़ोर से बंद होते दरवाज़े की दरार में लगाया गया एक मुलायम गद्दा। धड़ाम की आवाज़ को भी, हाथ फँसने को भी मुलायमी से सह लेता है। कड़वी टक्कर के बीच स्नेह की एक परत हौले से घुसा देने वाली एक छोटी सुरक्षा।"},"ICON-0469":{"nm":"केबल कवर ब्लॉक","de":"फ़र्श पर से गुज़रते केबल पर एक मज़बूत ढक्कन दृढ़ता से पुल बना देता है। न पैर उलझेगा, न तार दबेगी। राह रोके बिना राह की रखवाली करने वाले एक ब्लॉक की चुप्पी।"},"ICON-0470":{"nm":"कॉशन वेट-फ़्लोर कोन","de":"भीगे फ़र्श पर पीला शंकु अकेला खड़ा चुपचाप चेतावनी देता है। सँभलकर, धीरे से पैर रखना। चमकते मंच के पीछे ऐसे ही चुपचाप हर कदम की रखवाली करने वाला एक छोटा पहरेदार खड़ा रहता है।"},"ICON-0471":{"nm":"इमरजेंसी लाइट स्टिक","de":"बिजली गुल हुए गलियारे में झट जल उठती एक किरण। अँधेरे में भी राह न भटके, इसलिए यह आपातकालीन उजाला हाथ में थमाया जाता है। सबसे अँधेरे पल में सबसे उजली हो जाने वाली चीज़ें दुनिया में सच में होती हैं।"},"ICON-0472":{"nm":"रेलिंग गार्ड कैप","de":"सीढ़ी की रेलिंग के छोर पर लगी गोल टोपी नुकीले कोने को मुलायमी से लपेट लेती है। बेध्यानी में हाथ भी छू जाए तो चोट नहीं लगती। तीखेपन को चुपचाप ढँक देना, यह भी किसी के लिए एक ख़याल ही है।"},"ICON-0473":{"nm":"स्टेज एज कुशन","de":"मंच के किनारे कोने पर एक मुलायम गद्दा लपेटा जाता है। तीखी कोरियोग्राफ़ी में पंजा छू भी जाए तो चोट न लगे। चमकती हर एक हरकत के पीछे अदृश्य सुरक्षा साथ-साथ नाचती रहती है।"},"ICON-0474":{"nm":"फ़्लोर मार्कर डिस्क","de":"फ़र्श पर रखी गोल तश्तरी चुपचाप कहती है 'यहाँ खड़े हो जाओ'। कतार में लगने वाला भी, जगह ढूँढने वाला भी इस एक बिंदु को देखकर वहीं थम जाता है। व्यवस्था एक छोटे निशान से ही उगती है।"},"ICON-0475":{"nm":"फ़्लैशलाइट स्ट्रैप","de":"टॉर्च के सिरे पर लटकती डोरी को कलाई के गिर्द एक बार लपेट लो तो अँधेरे में भी रोशनी हाथ से नहीं छूटती। गिरने की चिंता के बिना दोनों हाथ आज़ाद हो जाते हैं—छोटा पर भरोसेमंद एक फेरा।"},"ICON-0476":{"nm":"क्राउड-कंट्रोल रोप","de":"यहाँ से आगे मत आना, एक रस्सी धीरे से एक रेखा खींच देती है। ख़तरनाक और सुरक्षित जगह को चुपचाप अलग करती एक स्नेहिल सीमा। रोक देना भी किसी को बचाने का एक तरीक़ा है।"},"ICON-0477":{"nm":"सेफ़्टी चेक पिन","de":"जाँच पूरी हुई हर जगह पर एक छोटी पिन 'जाँचा गया' छोड़ जाती है। कुछ भी न छूटे यह देखते हुए मन की एक मुहर-सी बिंदु। सुरक्षा कोई बड़ी बात नहीं, यह एक-एक कर छानबीन के निशानों का जोड़ है।"},"ICON-0478":{"nm":"मिनी क्लैपबोर्ड","de":"टक्—पहली ताल को काटती चटपटी आवाज़ पर, वहाँ खड़े सबकी साँस एक ही पल में मिल जाती है। छोटी दिखे तो भी हर दृश्य की शुरुआती रेखा हमेशा यही एक ताल है। शूटिंग की उत्साह भरी शुरुआत यहीं से खुलती है।"},"ICON-0479":{"nm":"डेस्क माइक कवर","de":"मेज़ पर रखे माइक पर एक मुलायम ढक्कन धीरे से चढ़ा दिया जाता है। साँस तेज़ी से फूटे तो भी बिना शोर के मुलायमी से पहुँचती है। आवाज़ को सबसे गर्मजोशी से लपेटने वाली यही एक छोटी मुलायम परत है।"},"ICON-0480":{"nm":"अकॉस्टिक पैनल पीस","de":"दीवार में जड़ा साउंड-अब्ज़ॉर्बिंग पैनल का एक टुकड़ा गूँज को चुपचाप समेट लेता है। आवाज़ टकराकर बिखरे नहीं, इसलिए गीत और साफ़ ठहरता है। अच्छी गूँज हमेशा सन्नाटे को मन से सँवारने से शुरू होती है।"},"ICON-0481":{"nm":"हेडफ़ोन हुक कैप","de":"हेडफ़ोन को यहाँ टाँगना एक छोटा वादा है। डोरी सुलझाकर करीने से रखना, ताकि अगला व्यक्ति सीधे उठाकर पहन सके। एक हुक व्यस्त बूथ में चुपचाप व्यवस्था ले आता है।"},"ICON-0482":{"nm":"रिकॉर्डिंग लाइट","de":"लाल बत्ती जलते ही, बूथ के भीतर हर साँस थम जाती है। दरवाज़े के बाहर की आहट भी रुक जाने वाला यह इशारा। आवाज़ को थामने का काम इसी गहरे सन्नाटे को सँभालने से शुरू होता है।"},"ICON-0483":{"nm":"पिक ऑर्गनाइज़र बॉक्स","de":"रंग के हिसाब से खाने बाँटकर रखे गए पिक्स। मोटाई और वज़न उँगलियों की आदत बनाते हैं। मंच पर जाने से ठीक पहले, बिना देखे एक ही झटके में सही पिक उठा लेने की वह सटीकता, यहीं से उगती है।"},"ICON-0484":{"nm":"केबल लेबलर","de":"दर्जनों उलझे तारों वाले फ़र्श पर भी राह न भटकनी हो तो दोनों सिरों पर नाम लिखना होगा। कहाँ से आया, कहाँ जाना है, यह लिखने वाला ही अँधेरे में भी हाथ भटकाए बिना काम कर पाता है।"},"ICON-0485":{"nm":"मिनी मिक्सर नॉब","de":"एक उँगली-जितना घुमाओ तो आवाज़ की बुनावट बदल जाती है। ऊपर करो तो खुरदुरी, नीचे करो तो दब जाती है, इसी बीच के एक बिंदु को टटोलने का काम। सबसे बारीक स्पर्श सबसे बड़ा बदलाव गढ़ता है।"},"ICON-0486":{"nm":"स्टैंड लॉक वॉशर","de":"मंच को थामे रखने वाली चमकती रोशनी नहीं, यह छोटी कड़ी है। कँपन को मज़बूती से थामे हुए, किसी की नज़र में आए बिना अपनी जगह पर चुपचाप डटी रहती है।"},"ICON-0487":{"nm":"सेट स्ट्राइक लेबल","de":"खड़ी की गई हर चीज़ को फिर से सावधानी से लिटाने का भी एक साफ़ क्रम होता है। कहाँ खोलना है, कहाँ ले जाना है, यह लिखा एक पर्चा। बनाने वाले हाथ जितने ही कुशल, समेटने वाले हाथ भी होते हैं।"},"ICON-0488":{"nm":"लॉस्ट एंड फ़ाउंड एनवेलप चिप","de":"कोई छोड़ गया सामान, उसके साथ एक कहानी भी जुड़ी होती है। एक छोटे लिफ़ाफ़े में रखकर मालिक के नाम का इंतज़ार करना, खो चुके व्यक्ति के दिल को भी थोड़ी देर के लिए थाम लेने जैसा स्नेह है।"},"ICON-0489":{"nm":"क्लीनिंग रूट मार्कर","de":"फ़र्श पर खींचे तीरों का पीछा करो तो कहीं भी सफ़ाई से चूक नहीं होती। झाड़ू को भी राह चाहिए, वरना वह यूँ ही घूमता रह जाता है। सबसे चमकती जगह हमेशा सबसे अच्छे से खींचे गए क़दमों के आख़िर में होती है।"},"ICON-0490":{"nm":"एग्ज़िट गाइड वैंड","de":"आख़िरी तालियाँ थमते ही यह छड़ी राह खोलती है। अब भी उत्साह से भरे दिलों को बिना चोट पहुँचाए धीरे-धीरे बाहर ले जाने वाला एक हाथ। अंत की ओर राह दिखाने में भी गर्मजोशी भरा ख़याल छिपा होता है।"},"ICON-0491":{"nm":"लेफ़्टओवर टेप बॉल","de":"इस्तेमाल के बाद बचा टुकड़ा गोल लपेट दो तो उसका फिर से कोई काम निकल आता है। फेंके जाने वाला किनारा इकट्ठा होकर एक मज़बूत गेंद बन जाए जैसे, संजोने वाला मन छोटी उँगलियों से ही उगता है।"},"ICON-0492":{"nm":"सीट नंबर कैप","de":"दर्शक-दीर्घा की हर कुर्सी पर अंक अंकित होना ज़रूरी है, तभी कोई भटकता नहीं। जगह तय करने वाली एक छोटी टोपी, पहली बार आए व्यक्ति की धड़कन को सहज राहत में बदल देती है।"},"ICON-0493":{"nm":"रीसाइक्लिंग सॉर्टर पिन","de":"काग़ज़ और प्लास्टिक को अलग-अलग खानों में टाँकती एक छोटी पिन। मिल जाएँ तो बस कचरा, बँट जाएँ तो फिर काम आने वाला संसाधन। बाँटना असल में चीज़ों को दूसरी ज़िंदगी लौटाने का एक स्नेहिल काम है।"},"ICON-0494":{"nm":"इक्विपमेंट रिटर्न टैग","de":"उधार ली गई चीज़ को हमेशा अपनी जगह लौटना ही चाहिए। पर्चा टाँगकर लौटाते हर हाथ के साथ भरोसा एक-एक परत जमता जाता है। जो अच्छे से लौटाए, वही अगली बार भी बेफ़िक्र होकर उधार लेता है।"},"ICON-0495":{"nm":"ग्रीन रूम चेकआउट की","de":"आज का श्रृंगार और पोशाक सब उतारकर, आख़िर में यह चाबी लौटा दी जाती है। भीतर आते वक़्त मिली चीज़ को बाहर जाते वक़्त वापस रख देना। दिन की शुरुआत और अंत एक ही हाथ में समाए रहते हैं।"},"ICON-0496":{"nm":"कुशन पफ़ केस","de":"मुलायम पफ़ दबने पर अपनी बुनावट खो देता है। एक गोल घर में उसे सहेजकर लिटाने की वजह यही है। मुलायमियत को लंबे समय तक थामे रखना है तो पहले मुलायमी से ही सँभालना होगा।"},"ICON-0497":{"nm":"आई-शैडो चिप","de":"पलकों पर टिका रंग का एक बिंदु पूरी अभिव्यक्ति बदल देता है। एक छोटी चिप में सोया रंग रोशनी के नीचे ही आख़िरकार जागता है, और मंच की ओर उठी नज़र में गहराई भर देता है।"},"ICON-0498":{"nm":"ब्लशर ब्रश कैप","de":"बालियों की नोक बिगड़ जाए तो रंग निखरना भी साथ ही बिखर जाता है। एक छोटी टोपी चढ़ाकर उस बुनावट को बचाना, अच्छे औज़ार को लंबे समय तक अपने पास रखने वाले व्यक्ति की एक चुप आदत है।"},"ICON-0499":{"nm":"स्लिम लिप पैलेट","de":"मोटा पैलेट बैग में पूरी जगह घेर लेता है। एक पतली-सी पंक्ति ही काफ़ी है, यह जानने वाला हाथ। कम करना ही सँभालकर रखने का असली काम बन जाने का पल यही है।"},"ICON-0500":{"nm":"मस्कारा गार्ड","de":"एक-एक करके उठाई गई पलकें फैलें नहीं, इसलिए एक छोटा गार्ड उस मोड़ को धीरे से थामे रखता है। जिसे मन से सँवारा गया है, उसे मन से ही सँभालना चाहिए, आईने के सामने बिताया समय यही सिखाता है।"},"ICON-0501":{"nm":"कॉटन बड केस","de":"सफ़ेद कॉटन बड्स को इधर-उधर बिखरने से बचाने वाला एक छोटा-सा घर। आख़िरी बार सुधार के लिए हमेशा पास रखा जाने वाला स्पर्श। छोटी-छोटी तैयारियाँ ही बड़े मंच की हर कमी को भर देती हैं।"},"ICON-0502":{"nm":"आईलैश कर्लर रबर पैक","de":"जब रबर सख़्त हो जाए, तो पलकें दबाते वक़्त हल्की-सी चुभन होती है। बदलने के लिए अतिरिक्त रबर पहले से रख लेना, उस कोमलता से आता है जो छोटी-छोटी तकलीफ़ों का भी ख़याल रखती है।"},"ICON-0503":{"nm":"कंसीलर ब्रश","de":"महीन बालों वाली नोक धीरे से परछाइयों को मिटा देती है। जहाँ रोशनी कभी नहीं पहुँची, वहाँ उजाला ले आने का काम। खामियों को ढँकने के बजाय रोशनी जोड़ने वाला हाथ कहीं ज़्यादा सुंदर निखार देता है।"},"ICON-0504":{"nm":"पाउडर सिफ़्टर","de":"महीन पाउडर को एक बार छान लेने से वह बिना गुठलियों के मुलायम तरीके से बैठता है। एक बार और छलनी से गुज़ारने की वह मेहनत। लगन आख़िरकार उसी उँगली से झलकती है जो एक कदम और आगे बढ़ती है।"},"ICON-0505":{"nm":"बैंग्स रोल क्लिप","de":"सामने के बालों को गोल लपेटकर कुछ देर थामे रखने वाली क्लिप। इंतज़ार के दौरान आकार शांति से बैठ जाता है। बिना जल्दबाज़ी के इंतज़ार करना जानने की जगह पर ही सलीका खिलता है।"},"ICON-0506":{"nm":"हेयर वैक्स स्पून","de":"वैक्स हाथों में लगने से पहले इस छोटे-से चम्मच से निकाला जाता है। ठीक जितनी ज़रूरत हो उतना ही लेने का संयम। बिना अति किए इस्तेमाल करना जानने वाला हाथ ही सबसे स्वाभाविक बनावट रचता है।"},"ICON-0507":{"nm":"कर्लिंग आयरन रेस्ट मैट","de":"तपते हुए कर्लिंग आयरन को यूँ ही कहीं नहीं रखा जा सकता। एक सहारा देने वाली मैट मेज़ और हाथ, दोनों को बचाती है। जहाँ गर्मी को संभालना हो, वहाँ हमेशा एक सुरक्षित ठिकाने की ज़रूरत होती है।"},"ICON-0508":{"nm":"हेयर ऑयल सैंपल","de":"एक बूँद ही काफ़ी चमक के लिए, इसलिए इसे एक छोटी-सी सैंपल शीशी में करीने से भरकर बैग के एक कोने में चुपके से रख दिया जाता है। बड़ी शीशी से कहीं ज़्यादा यह छोटी शीशी हाथ में आती है।"},"ICON-0509":{"nm":"ब्रश क्लीनिंग रेक","de":"ब्रिसल्स में उलझे बालों को यह रेक धीरे-धीरे सुलझाता है। औज़ारों की देखभाल करना काम खत्म होने के बाद का एक शांत अनुष्ठान है। अच्छी तरह संवारा गया ब्रश ही कल की बनावट को सुंदर रूप से गढ़ता है।"},"ICON-0510":{"nm":"हेयर टाई बॉबिन","de":"बस एक फिरकी पर लपेट देने भर से सब एक नज़र में दिख जाते हैं। यह गोल करीने से समेटा गया छोटा-सा बंडल, उन व्यस्त सुबहों को दी गई एक कोमल राहत है जब रबर बैंड चारों ओर लुढ़कते फिरते थे।"},"ICON-0511":{"nm":"डाई ग्लव पैक","de":"रंग चढ़ाने वाले हाथों को दाग़ से बचाने के लिए पहने जाने वाले पतले दस्ताने। काम खत्म होने के बाद भी साफ़ हाथों से अगली चीज़ का स्वागत करने की चाहत। सुरक्षा, आख़िरकार, उसी तैयारी का दूसरा नाम है।"},"ICON-0512":{"nm":"हेयरनेट पाउच","de":"बालों का आकार थामे रखने वाली जाली को करीने से मोड़कर रखने वाली एक छोटी-सी थैली। जितनी कम मोटाई की चीज़ हो, उतनी ही आसानी से खो जाती है, इसलिए उसे अपना ठिकाना देने वाला वह सोच-समझकर किया गया स्पर्श आभार का पात्र है।"},"ICON-0513":{"nm":"फ्लाईअवे फिक्सर पेन","de":"उड़ते हुए छोटे बालों को हल्के से दबाकर सलीके में बिठाने वाला पेन। बड़ी स्टाइलिंग खत्म होने के बाद की आख़िरी छुअन। पूरा करना हमेशा सबसे छोटी जगह को सहलाने का काम होता है।"},"ICON-0514":{"nm":"परफ्यूम टेस्टर कैप","de":"ख़ुशबू चुनते वक़्त उसे सीधे नाक के पास नहीं रखते। एक छोटी टोपी पर लगाकर हवा में बिखरने देने से ही उसकी असली बनावट सामने आती है। ख़ुशबू भी, एक कदम दूर से सूँघने पर ही सच्ची लगती है।"},"ICON-0515":{"nm":"रोल-ऑन सेंट बॉटल","de":"एक गोल मनका लुढ़कते हुए कलाई पर ख़ुशबू खींचता है। पुराने टपकाने वाले परफ्यूम की शीशियों के उलट, फिसलती-सी बिछती एक लकीर। ख़ुशबू छूने के हर तरीके के साथ एक अलग कहानी छोड़ जाती है।"},"ICON-0516":{"nm":"बॉडी मिस्ट कैप","de":"कोहरे-सी फैलती ख़ुशबू को बंद रखने वाला एक छोटा-सा ढक्कन। खुलने पर ही उड़ जाने वाली चीज़ को बंद करके संभालना। थोड़ा बचाकर रखने की चाहत उस ख़ुशबू को साथ ज़्यादा देर तक टिकाए रखती है।"},"ICON-0517":{"nm":"हैंड क्रीम कीरिंग","de":"हाथों पर लगाई जाने वाली छोटी-सी क्रीम में एक कड़ी जोड़ दें, तो वह हर जगह साथ चलती है। बैग के बाहर लटककर हिलती-डुलती यह संगिनी, सूखी उँगलियों के लिए भेजी गई एक कोमल कुशल-क्षेम बन जाती है।"},"ICON-0518":{"nm":"शावर पफ हुक","de":"झाग बनाने के बाद उसे अच्छी तरह सुखाना ज़रूरी है। बाथरूम के एक कोने में हुक पर टँगी जालीदार गेंद, पानी की बूँदें झटककर अगली ताज़ी सुबह का इंतज़ार करती है।"},"ICON-0519":{"nm":"मसाज बॉल पाउच","de":"अकड़े हुए कंधों को ढीला करने वाली सख़्त गेंद को एक छोटी थैली में रखा जाता है। मंच के पीछे की छोटी-सी फ़ुर्सत, थके हुए बदन को चुपचाप सहलाने का पल। देखभाल हमेशा ख़ुद से ही शुरू होती है।"},"ICON-0520":{"nm":"कूलिंग पैच टिन","de":"लगाते ही ठंडक से भर देने वाले पैच जमा किए हुए एक डिब्बा। तपते मंच के ख़त्म होने वाली रात, गरम हुए तन और मन को धीरे-धीरे शांत करती एक छोटी-सी राहत इसमें सोई रहती है।"},"ICON-0521":{"nm":"नेल ऑयल पेन","de":"दबाओ, मलो, और चमक। सूखी उँगलियों के लिए बस एक बूँद ही काफ़ी है। किसी भव्य नुस्ख़े की ज़रूरत नहीं, इस छोटे-से पेन की नोक से फैलती हल्की चमक नाखूनों पर सलीके से घूमती है। देखभाल यूँ ही एक छोटी-सी बूँद से शुरू होती है।"},"ICON-0522":{"nm":"सैशे क्लिप","de":"काग़ज़ पर ख़ुशबू को बाँध रखने वाली एक छोटी गाँठ। जब भी दराज़ खोलो, हाथ से पहले एक हल्की-सी महक तुम्हारा स्वागत करती है। न दिखते हुए भी पास बने रहने वाला यह अपनापन—एक क्लिप चुपचाप एक दिन भर की राहत समेटे रहती है।"},"ICON-0523":{"nm":"नेल टिप ट्रे","de":"दसों उँगलियों के रंगों को पहले से सजाकर रखने वाला एक छोटा-सा मंच। आज कौन-सा रंग जँचेगा—ट्रे पर एक शांत ऑडिशन शुरू होता है। चुनने का वह छोटा पल कुछ इस तरह रोमांचित करता है कि उँगलियों का दिन यहीं से शुरू होता है।"},"ICON-0524":{"nm":"क्यूटिकल पुशर कैप","de":"पीछे धकेलने के काम में भी एक कोमलता होती है। एक छोटी-सी खुरदरी त्वचा को गोल नोक से धीरे-धीरे, बिना जल्दबाज़ी के। जल्दबाज़ी करता हाथ हमेशा कुछ न कुछ छोड़ देता है, इसलिए सँवारना धीरे से देखने वाले मन के कहीं ज़्यादा क़रीब है।"},"ICON-0525":{"nm":"मिनी फ़ाइल बफ़र","de":"खुरदरा पहलू और महीन पहलू, दो चेहरे एक ही हाथ में थामे। नुकीली जगहों को धीरे-धीरे घिसकर चिकना बनाना छोटी बात लगती है, पर पूर्णता हमेशा ऐसे ही छोटे स्पर्शों से आती है। आख़िरी शब्द हमेशा कोमलता का ही होता है।"},"ICON-0526":{"nm":"नेल स्टिकर शीट","de":"तारा, फूल, दिल—आज के मूड से मेल खाती बस एक शीट चुनकर लगा लो, बात ख़त्म। नाखून-भर आकार की छोटी-छोटी तस्वीरों की क़तार वाली शीट पर, एक स्टिकर उँगली पर छूटे कोमल हस्ताक्षर की तरह चमकता है।"},"ICON-0527":{"nm":"जेल लैंप शेड प्लेट","de":"रोशनी को कुछ देर के लिए बंद रखने वाली एक पतली परत। सूखने के दौरान आँखें आराम करती हैं, बस उँगलियाँ चुपचाप सख़्त होती जाती हैं। इंतज़ार को भी छाया की एक पट्टी चाहिए होती है—बिना जल्दबाज़ी के उस पल में आज की उँगलियाँ पूरी होती हैं।"},"ICON-0528":{"nm":"नेल आर्ट पार्ट्स टिन","de":"चमकते हुए टुकड़े ख़ाने-ख़ाने में सोए रहते हैं। क्यूबिक, मोती, तारों की धूल—बिना नाम की एक ज़ेवर-पेटी खोलने के रोमांच से ढक्कन उठता है। नाखूनों पर कौन-सी चमक सजाएँ—चुनने का वही पल सबसे ज़्यादा चमकता है।"},"ICON-0529":{"nm":"हैंड केयर ग्लव पैक","de":"सोते समय हाथों को मिलने वाली एक छोटी-सी छुट्टी। दस्तानों के भीतर रूखी त्वचा रातभर धीरे-धीरे कोमल होती जाती है। देखभाल आख़िर वही चीज़ है जो न दिखने वाली जगह पर होती है—सुबह होते ही उँगलियाँ सबसे पहले उस कोमलता को जान लेती हैं।"},"ICON-0530":{"nm":"रिमूवर पंप बॉटल","de":"एक बार दबाओ, ठीक जितनी ज़रूरत हो उतना ही निकलता है। रुई में समाकर फैलती ठंडी ख़ुशबू नाखूनों पर बीता कल साफ़ मिटा देती है। ख़ाली करने में भी एक लय होती है, और एक बार का पंप नई पॉलिश के लिए जगह चुपचाप बना देता है।"},"ICON-0531":{"nm":"राइनस्टोन ट्वीज़र्स","de":"उँगली से भी बारीक रत्न पकड़ने के लिए और भी बारीक हाथ चाहिए। बिना काँपे एक बिंदु को सरकाने वाली ट्वीज़र की नोक—बारीकी उतनी ही औज़ार की भी हिस्सेदारी है जितनी मन की। एक छोटी-सी चमक अपनी जगह पा लेती है।"},"ICON-0532":{"nm":"ईयरिंग स्टोरेज प्लेट","de":"अकेली छूटी बाली फिर कभी दराज़ में खोकर न भटके, इसलिए। जोड़ी-जोड़ी अपनी जगह पर टिका देने से, व्यस्त सुबह में चुनने का समय कहीं हल्का हो जाता है। सलीका दरअसल आने वाले कल के अपने-आप को दी गई एक छोटी-सी दयालुता है।"},"ICON-0533":{"nm":"रिंग साइज़र लूप","de":"उँगली की गोलाई को अंक में बदल देने वाला छोटी-छोटी घेरियों का एक बंडल। एक-एक फिट होती घेरी पहनकर देखना, ठीक वैसा ही है जैसे धीरे-धीरे यह जानना कि मुझे क्या बिल्कुल सही बैठता है। ठीक फिट होने पर मिलने वाली उसी राहत जैसा।"},"ICON-0534":{"nm":"वॉच बैंड पिन","de":"जब घड़ी का पट्टा ढीला पड़ने लगे, तो यह एक छोटी-सी पिन समय को फिर से कलाई पर बाँध देती है। सबसे गहरे छिपे पुर्ज़े ही सबसे लंबे समय तक टिकते हैं—यह बात एक बरसों पहनी घड़ी चुपचाप जानती है।"},"ICON-0535":{"nm":"नेकलेस एंटी-टैंगल प्लेट","de":"पतली ज़ंजीरें आपस में न उलझें, इसलिए बँटे हुए ख़ाने। उलझन-रहित सुबह की शुरुआत पिछली रात पहले से बाँट दिए गए छोटे विभाजनों से होती है। सहूलियत आख़िरकार वही मन है जो हाथ पहुँचने से पहले ही सब सँवार देता है।"},"ICON-0536":{"nm":"ब्रोच बैक क्लैस्प","de":"सामने जितना चमकीला हो, पीछे उतना ही ख़ामोश। कपड़े में टँकी ब्रोच को मज़बूती से थामे रखने वाला एक छोटा क्लैस्प—हर दिखती चमक के पीछे एक बेनाम हाथ ख़ामोशी से थामे रहता है। न दिखने के कारण ही यह जगह ज़्यादा भरोसेमंद है।"},"ICON-0537":{"nm":"सनग्लासेस पाउच","de":"गर्मी की तेज़ रोशनी रोकने वाले लेंस को एक मुलायम कपड़ा चुपचाप लपेट लेता है। बैग के भीतर की टकराहट से एक जोड़ी नज़र को बचाने वाली छोटी-सी थैली। किसी चीज़ को संजोने का मन हमेशा ऐसी ही एक मुलायम परत बनकर आता है।"},"ICON-0538":{"nm":"बेल्ट होल पंच","de":"चाहे कमर एक निशान कम हो जाए, या मौसम एक निशान बढ़ जाए। बस एक और छेद कर दो, बेल्ट फिर से जिस्म पर फ़िट बैठ जाती है। बदलती हमेशा मैं ही हूँ, और चुपचाप मुझसे मेल बिठा देना इस छोटे-से औज़ार का काम है।"},"ICON-0539":{"nm":"स्कार्फ़ रिंग क्लिप","de":"फिसलते हुए स्कार्फ़ को एक बिंदु पर समेटकर थामने वाली क्लिप। हवा में खुलती जा रही अदा आख़िर अपनी जगह पा लेती है। शालीनता भी कभी-कभी इस छोटी-सी क्लिप पर टिककर, बिखरने को तैयार दिन को सलीके से समेट देती है।"},"ICON-0540":{"nm":"चार्म लूप सेट","de":"बैग के एक किनारे टाँगने के लिए छोटी-छोटी कड़ियाँ एक सेट में आईं। पसंदीदा चीज़ को अपने पास लटकाए रखने का मन—एक चार्म पर उस दिन का मूड टाँग देना, बस अपनी ही जानी एक छोटी-सी रस्म-सी लगती है, कुछ अजीब-सी खुशी देती है।"},"ICON-0541":{"nm":"लिंट रिमूवर कैनिस्टर","de":"जब स्वेटर एक रात में ही बूढ़ा-सा दिखने लगे रोएँ उठकर, तो इस डिब्बे को धीरे से घुमाओ और वह फिर से नए जैसा दिखने लगेगा। घिसाव को हटाती हल्की-सी गुनगुनाहट कुछ इस तरह भरोसा दिलाती है। प्यारा कपड़ा यूँ एक बार फिर जी उठता है।"},"ICON-0542":{"nm":"फ़ैब्रिक सेंट कार्ड","de":"अलमारी में गहरे रख दो, तो कई दिनों तक ख़ामोशी से ख़ुशबू से भर देती है। शब्दों की जगह ख़ुशबू में लिखी एक चिट्ठी—बिना खोले पढ़ी जाने वाली एक इबारत। कपड़ा निकालते हर सुबह, कल लिखी गई वह कोमलता सबसे पहले फैलती है।"},"ICON-0543":{"nm":"एंटी-स्टैटिक पिन","de":"सर्दी की उस सुबह जब स्कर्ट टाँगों से चिपक जाए, एक पिन उस चिपकन को धीरे से छुड़ा देती है। न दिखने वाले घर्षण को भी सहलाती एक छोटी-सी शांति—एक मामूली-सी झुँझलाहट मिट जाए तो दिन कहीं ज़्यादा सहज गुज़रता है।"},"ICON-0544":{"nm":"पोर्टेबल क्लोथ्स ब्रश","de":"दरवाज़े से निकलने के ठीक पहले, कंधे पर हल्के से बैठी धूल की एक लकीर। तह किया हुआ ब्रश खोलकर एक बार फेरने से पहला प्रभाव फिर से सलीकेदार हो जाता है। पूर्णता हमेशा दरवाज़े पर ही होती है, और सलीका उसी एक स्पर्श से पूरा होता है।"},"ICON-0545":{"nm":"लॉन्ड्री बैग लेबल","de":"जो चीज़ें आपस में नहीं मिलनी चाहिए, उन्हें एक जाली में बंद करो, और एक लेबल चुपचाप उनका नाम लिख देता है। कपड़ों की भी अपनी जगह होती है, और जगह के साथ एक छोटा-सा चिह्न आता है। आसानी से उलझने वाले दिन का सुभीता इसी छोटे नाम-पट्टे से उगता है।"},"ICON-0546":{"nm":"स्टेन रिमूवर पेन","de":"कमीज़ पर कॉफ़ी की एक बूँद का निशान भी, हल्के-हल्के थपथपाने से चुपचाप हट जाता है। ग़लती को ढँकने की नहीं, बल्कि उसे शांति से मिटा देने वाली एक कलम। हर किसी को दिन फिर से साफ़-सुथरा शुरू करने का एक मौक़ा चाहिए होता है।"},"ICON-0547":{"nm":"शू शाइन क्लॉथ","de":"कपड़े से एक बार पोंछ देने भर से चमड़ा अपनी चमक वापस पा लेता है। जितने पुराने जूते, उतनी ही गहरी चमक चढ़ती है। चमक साथ चली आई दूरी का इनाम है—जूते वह समय चुपचाप पाँव की पीठ पर उकेरते रहते हैं।"},"ICON-0548":{"nm":"शूलेस टिप कैप","de":"खुले फीते के सिरे पर लगाई गई एक छोटी-सी टोपी। फ़िनिश लाइन तक नज़र न भटके, इसलिए सिरे को कसकर बंद कर दिया जाता है। एक अच्छी तरह बँधा फीता ही एक क़दम और आगे भेजता है—एक मामूली-सी सावधानी ही आख़िर तक दौड़ने का साहस बन जाती है।"},"ICON-0549":{"nm":"हैंगर नेम चिप","de":"एक जैसे दिखने वाले हैंगरों के बीच, यह छोटी-सी चिप चुपचाप बता देती है 'मेरी जगह'। व्यस्त सुबह की उलझन को कम करने वाला एक ख़ामोश मार्गदर्शक—ढूँढने की मेहनत कम हो जाए तो दिन की शुरुआत भी हल्की लगती है।"},"ICON-0550":{"nm":"लेंस ट्वीज़र्स टिन","de":"कभी-कभी उँगली से भी सटीक नोक की ज़रूरत होती है। छोटे लेंस को बिना काँपे उठाने वाली ट्वीज़र डिब्बे के भीतर अपनी बारी का इंतज़ार करती है। सटीकता हमेशा शांति से तैयार, पुकारे जाने तक सोई रहती है, फिर तुरंत जाग उठती है।"},"ICON-0551":{"nm":"मिनी कॉटन पैड पैक","de":"बस एक बार इस्तेमाल के लिए ठीक जितना चाहिए उतना ही रखा गया छोटा बंडल। बैग की मोटाई कम करता है, पर मुलायमियत जस-की-तस रहती है। कम सामान रखना भी एक तरह की कोमलता है—जो जगह ख़ाली की गई, वहाँ एक हल्का दिन आ बसता है।"},"ICON-0552":{"nm":"ब्लॉटिंग पेपर केस","de":"दोपहर की नाक पर फैली चमक को एक पतले पन्ने से धीरे से दबाकर पोंछ लेते हैं। डिब्बे के भीतर करीने से सोए पन्ने—एक पन्ना निकालने के उसी पल भर, हर कोई थोड़ी देर रुककर आईने के सामने अपने-आप को कोमलता से निहारता है।"},"ICON-0553":{"nm":"फ़ोल्डिंग कॉम्ब मिरर","de":"तह करो तो हथेली-भर, खोलो तो आईना और कंघी। बैग के एक कोने से आनन-फानन की सज-धज संभालने वाला एक छोटा-सा हरफ़नमौला। सलीका कोई भव्य चीज़ नहीं, बल्कि कहीं भी खोलकर एक बार सँवर लेने वाले मन के क़रीब है।"},"ICON-0554":{"nm":"ट्रैवल रेज़र कैप","de":"यात्रा के बैग में तेज़ ब्लेड को सुरक्षित सुला देती है। यह भोथरी-सी दिखने वाली मज़बूत टोपी की बदौलत, व्यस्त सुबह टटोलती उँगलियाँ भी कट नहीं पातीं। ख़याल रखना हमेशा ख़तरे को एक क़दम पहले ही ढँक देना है।"},"ICON-0555":{"nm":"लिप बाम लूप","de":"बैग की पट्टी पर लटकती एक छोटी-सी ढाल। जेब में लुढ़ककर टूटने की चिंता के बिना, सूखे होंठ हमेशा हाथ की पहुँच में रहते हैं। किसी चीज़ को पास रखना आख़िर वही मन है जो ज़रूरी चीज़ को सबसे नज़दीक रखता है।"},"ICON-0556":{"nm":"हैंड सैनिटाइज़र होल्डर","de":"एक हाथ से दबाओ तो एक चुटकी सफ़ाई टपक पड़ती है। दरवाज़े पर, मेज़ पर, कहीं भी टाँग दो, हाथ धोने का मन भी उतना ही क़रीब आ जाता है। अच्छी आदत भव्य नहीं होती, वह हाथ की पहुँच से ही शुरू होती है।"},"ICON-0557":{"nm":"स्लिम टिशू पाउच","de":"पतली-सी काया में एक मुट्ठी टिशू समाई है। जेब को फुलाए बिना भी, अचानक बहती नाक या आँसुओं के लिए हमेशा चुपचाप तैयार रहती है। किसी को चुपके से थमाने के लिए एक पन्ना—तैयारी जितनी दुबली, उतनी ही ख़ूबसूरत।"},"ICON-0558":{"nm":"मिनी माउथवॉश बॉटल","de":"तीखी नूडल्स खाकर किसी से मिलने जाना हो, उस दिन यह छोटी शीशी चुपके से मुँह की ताज़गी संभाल लेती है। एक घूँट की ताज़गी कभी-कभी बड़ा आत्मविश्वास बन जाती है, और झिझकता हुआ अभिवादन कहीं ज़्यादा सहज हो जाता है।"},"ICON-0559":{"nm":"शिमर पाउडर चिप","de":"उँगली पर हल्का-सा लगाकर गाल पर लगाओ, तो रोशनी के नीचे तारों की धूल-सी बिखरती फैलती है। एक मामूली गाल पल-भर में चमक उठे, यह इस छोटी-सी चिप का ही जादू है। रोशनी हमेशा ऐसे ही आती है, उँगली पर लगी एक चुटकी चमक बनकर।"},"ICON-0560":{"nm":"ग्लिटर टोनिंग स्टिकर","de":"जहाँ बहुत ज़्यादा चमक असहज लगे, वहाँ यह स्टिकर हल्के से रोशनी दबा देता है। तड़क-भड़क का एक तह हटाना भी सज-धज का ही हिस्सा है—हटाई गई जगह पर बची हल्की-सी नज़ाकत कभी-कभी एक और ही एहसास बन जाती है।"},"ICON-0561":{"nm":"स्टोन पिकअप पेन","de":"राह चलते पाँव में अटका एक छोटा-सा पत्थर। झुककर उठाने की ज़हमत उठाने वाला एक पेन। जिसे यूँ ही अनदेखा किया जा सकता था, उसे उँगली से चुपचाप उठाने वाला मन—कोमलता हमेशा रुक जाने से शुरू होती है।"},"ICON-0562":{"nm":"फॉल्स लैश स्टोरेज प्लेट","de":"एक-एक बरौनी को करीने से लिटा रखने वाली एक छोटी-सी प्लेट। उतार लेने के बाद भी उनकी सुंदर वक्रता बिखरती नहीं। कुछ देर के लिए उतार दी गई चीज़ें भी अपनी जगह याद रखती हैं—यही है सुव्यवस्थित रखरखाव की शांत, सलीकेदार राहत।"},"ICON-0563":{"nm":"डबल-आईलिड टेप कटर कैप","de":"दो धारें आपस में मिलकर एक ही झटके में गाँठ काट देती हैं। कटान जितना साफ़, अगली गाँठ उतनी ही सलीकेदार बनती है। अच्छे से बाँधना और अच्छे से काटना जानने वाली उँगली से, नई शुरुआत भी कहीं ज़्यादा हल्के से खुलती है।"},"ICON-0564":{"nm":"फ़ेस-लाइन टेप","de":"जबड़े की रेखा पर एक पट्टी, साँस रोककर सावधानी से चिपकाई जाती है। कंटूरिंग कोई नई रेखा खींचना नहीं, बल्कि पहले से मौजूद सुंदर जगह की ओर इशारा करना है। यह वही स्पर्श है जो हमेशा से वहाँ रही बनावट को कोमलता से उकेरता है।"},"ICON-0565":{"nm":"लाइट-रिफ़्लेक्टिंग पाउडर","de":"रोशनी को पूरी तरह पीकर उसे सुंदरता से लौटा देने वाला एक पाउडर। ख़ुद न चमकते हुए भी, पाई हुई रोशनी को महीन कणों में बिखेरकर उजाला फैलाता है। जैसे मिली कोमलता किसी और को आगे सौंपी जाए, चमक बाँटने से ही बड़ी होती है।"},"ICON-0566":{"nm":"मेकअप सेटिंग फ़ैन","de":"मेहनत से सजाए गए रूप को दिन के आख़िर तक थामे रखने वाली पंखे की हवा। न बिखरे, न बहे, इसलिए धीरे से ठंडा करके जमा देती है। लगन से सँवारा गया चेहरा मंच का पर्दा गिरने तक साफ़ बना रहे, इसलिए।"},"ICON-0567":{"nm":"कलर करेक्टर पैलेट चिप","de":"बिगड़े हुए रंग को एक-एक ख़ाने से सहलाकर ठीक करने वाले छोटे-छोटे टुकड़े। जो रंग अकेला बेमेल-सा लगता था, वह भी साथ में मेल खाता रंग पाकर आख़िर निखर उठता है। रंग जब रंग से हाथ मिलाता है, तभी एक साफ़ तस्वीर बनती है।"},"ICON-0568":{"nm":"नेक स्कार्फ़ पैक","de":"गले में लपेट लो, तो भोर की अभ्यास-कक्ष की ठंडी हवा काफ़ी नरम पड़ जाती है। दादी अपने पोते के गले में लपेटती उस स्पर्श जैसी गर्माहट। सर्दी हमेशा सबसे पतली जगह से आती है, इसलिए वह सबसे पहले गर्दन को ही अपने आग़ोश में लेती है।"},"ICON-0569":{"nm":"हीटेड आई मास्क एन्वेलप","de":"गरम की गई आई मास्क रखने वाला एक छोटा लिफ़ाफ़ा। खोलते ही पलकों पर सुस्ती भरी गर्माहट धीरे से फैल जाती है। थके हुए दिन को कुछ देर के लिए सील करके फिर छोड़ देने वाला, सोने से पहले का एक कोमल अनुष्ठान।"},"ICON-0570":{"nm":"पोर्टेबल ह्यूमिडिफ़ायर फ़िल्टर","de":"बिल्कुल सूखे कमरे में नमी लौटाने वाली एक छोटी छन्नी। न दिखने वाले भीतरी हिस्से से धुंधलापन चुपचाप छानती रहती है। कमरे भर की नमी दरअसल किसी की अनदेखी मेहनत से बचाई गई एक स्वच्छता है।"},"ICON-0571":{"nm":"विटामिन ऑर्गनाइज़र बॉक्स","de":"दिन-भर की गोलियाँ ख़ाने-ख़ाने में बाँटकर रखने वाला डिब्बा। नियम से खा लेना कल भी मंच पर खड़े होने का एक संकल्प है। हर छोटे ख़ाने में, ख़ुद को संजोने वाला मन बड़े करीने से सजा हुआ है।"},"ICON-0572":{"nm":"स्लीप ईयरप्लग केस","de":"दुनिया की आवाज़ों को कुछ देर के लिए बंद कर देने वाले ईयरप्लग का घर। सन्नाटे को भी देखभाल चाहिए, इसलिए वे केस के भीतर करीने से लेटते हैं। गहरी नींद वाली रात ही अगले दिन आवाज़ को साफ़ जगा देती है—यह आराम भली-भाँति जानता है।"},"ICON-0573":{"nm":"कूल टॉवेल क्लिप","de":"ठंडा किया हुआ तौलिया फिसले नहीं, इसलिए कंधे पर मज़बूती से जकड़ने वाली क्लिप। भीषण गर्मी के दिन गर्दन को छूती ठंडक की एक लकीर लंबी दोपहर को सहने लायक बनाती है। थोड़ी-सी ठंडक भी थाम लो तो लंबे समय तक रहती है।"},"ICON-0574":{"nm":"स्ट्रेच बॉल बैग","de":"बदन ढीला करने वाली गेंद को वापस समेटने वाली थैली। ख़ूब फैलाकर फिर छोटा समेटना, साँस के अंदर-बाहर जाने जैसा है। खुलने और समेटने के बीच, तन और मन दोनों धीरे-धीरे मज़बूत होते जाते हैं।"},"ICON-0575":{"nm":"कंप्रेशन बैंडेज रोल","de":"मुड़ी हुई टख़ने को चक्कर-चक्कर घेरकर थामने वाली पट्टी। यह दबाना नहीं, बल्कि चुपचाप सहारा देना है। जितनी ज़्यादा तकलीफ़ वाली जगह हो, उतना ही ज़रूरी है पास ख़ामोशी से टिके रहने वाला एक हाथ—यह बात लपेटती हुई पट्टी फुसफुसाती है।"},"ICON-0576":{"nm":"कंडीशन चेक टैग","de":"आज की तबीयत एक पंक्ति में लिखकर टाँगने का एक टैग। अच्छे और बुरे को खुलकर टाँगना एक छोटी हिम्मत है। ठीक होने का दिखावा करने के बजाय आज के अपने-आप को लिख देने से, कोई न कोई उस एक पंक्ति को पढ़कर चुपचाप ख़याल रख लेता है।"},"ICON-0577":{"nm":"शू फ़्रेशनर कैप्सूल","de":"जूते के भीतर टक से डाल दिया जाने वाला ख़ुशबू का कैप्सूल। पूरे दिन मंच नापते पाँवों को दी गई एक छोटी, हल्की-सी राहत। सबसे ज़्यादा मेहनत करने वाली जगह को सबसे अच्छी ख़ुशबू—कोमलता पाँव की उँगलियों तक भी बिना चूके पहुँचती है।"},"ICON-0578":{"nm":"इनसोल साइज़ चार्ट","de":"एक इनसोल पर भी पाँव के नाप को साफ़-साफ़ अंकित करने वाला चार्ट। बिल्कुल फ़िट बैठती एक जोड़ी मंच पर पड़ते क़दमों को हल्का बना देती है। हर किसी के अलग-अलग डग को समझना—फ़िटिंग आख़िर सामने वाले को गहराई से समझने वाला मन है।"},"ICON-0579":{"nm":"शूहॉर्न कीरिंग","de":"जूता-चम्मच को हथेली-भर छोटा करके टाँगी गई चाबी की कड़ी। जूता पहनने के उस पल भर को सहज बनाने वाला एक छोटा-सा ख़याल। राह पर निकलते पाँवों के साथ हमेशा किसी की एक कोमल मददगार बाँह चुपचाप लटकी रहती है।"},"ICON-0580":{"nm":"बैग डस्ट कवर","de":"प्यारे बैग को धूल से धीरे से ढँक देने वाला कपड़ा। इस्तेमाल न होने के दौरान भी उसे करीने से सुलाकर उसकी बनावट बचाए रखता है। जिन चीज़ों पर हाथ कम जाता है पर मन टिका रहता है, उनमें ऐसी ही ख़ामोश देखभाल बसती है।"},"ICON-0581":{"nm":"स्ट्रैप एडजस्टर पिन","de":"ढीली पड़ी पट्टी को जिस्म पर बिल्कुल फ़िट कर देने वाली पिन। ढीली हो तो कंधे से फिसलती है, कसी हो तो साँस भारी हो जाती है। ठीक-ठाक बैठने की उसी छोटी-सी समायोजन में, मंच का परिधान और मन, दोनों आख़िर सहज हो जाते हैं।"},"ICON-0582":{"nm":"ज़िपर लुब्रिकेंट पेन","de":"अटकी हुई ज़िप पर एक बार फिराओ, तो वह फिर से नरमी से फिसलने लगती है। अटकी हुई चीज़ का यूँ सरककर खुल जाना कितना सुकूनभरा लगता है। रुकी हुई जगह को फिर बहाना, बस एक हल्की-सी नरमी की लकीर से होता है।"},"ICON-0583":{"nm":"स्नीकर क्लीनर टिप","de":"मिट्टी-धूल से सने स्नीकर को एक-एक बिंदु करके साफ़ करने वाली ब्रश की नोक। मंच से दूर, न दिखने वाले अभ्यास के निशानों को लगन से मिटाती है। फिर से सफ़ेद हुए जूते की नोक देखकर लगता है कल फिर एक नए मन से दौड़ा जा सकेगा।"},"ICON-0584":{"nm":"वॉटरप्रूफ़ स्प्रे कैप","de":"बारिश की बूँदों को गोल मोतियों में बदलकर गिरा देने वाली वॉटरप्रूफ़िंग की टोपी। भीगने से पहले एक तह पहले से चढ़ा देना, दूर तक देखने वाली एक कोमलता है। बारिश का दिन आने वाला जानकर, साफ़ आज पर ही एक परत की चादर लपेट दी जाती है।"},"ICON-0585":{"nm":"लेदर प्रोटेक्टर क्लॉथ","de":"चमड़े पर धीरे से ढँककर सिलवटों से बचाने वाला कपड़ा। जैसे पुराने ज़माने में हाथ हानजी काग़ज़ से पर्दा लपेटते थे, वैसे ही यह बनावट को बचाए रखता है। जिसे जितना लंबे समय साथ रखना हो, उतना ही धीरे-धीरे—सधना दरअसल देखभाल में बिताए समय का ही दूसरा नाम है।"},"ICON-0586":{"nm":"कैरियर नेम बेल्ट","de":"अनगिनत बैगों के बीच अपने बैग को एक नज़र में पहचान दिलाने वाला नाम-पट्टा। कन्वेयर पर चक्कर काटते सामानों के बीच, वह एक अक्षर से हाथ उठाता है। चाहे कितनी ही दूर निकल जाओ, एक नाम ही दोबारा मिलने का भरोसा दिलाता है।"},"ICON-0587":{"nm":"कंप्रेशन बैग क्लिप","de":"फूला हुआ सामान चपटा दबाकर बंद कर देने वाली क्लिप। यह ख़ाली करना नहीं, बल्कि करीने से तह करके समेटना है। घर-गृहस्थी को सलीके से समेटने वाली उँगली से लालच भी उतना ही छोटा होता जाता है—यह बात कसकर दबा हुआ सामान चुपचाप बता देता है।"},"ICON-0588":{"nm":"ट्रैवल डिटर्जेंट शीट","de":"वॉशबेसिन में सिर्फ़ एक पन्ने से कपड़े धुलवा देने वाली डिटर्जेंट शीट। घर से दूर, हाथ से कपड़े धो लेने वाली मुसाफ़िर की उस पुरानी सूझ-बूझ जैसी। हल्के सामान से निकलकर भी सलीका साथ ले जाना, राह के मुसाफ़िर का बरसों पुराना नज़रिया है।"},"ICON-0589":{"nm":"नेक पिलो कवर","de":"गर्दन को सहारा देने वाले तकिए पर नया चढ़ाया गया एक साफ़-सुथरा ग़िलाफ़। जिस जगह पर सिर टिकाना हो, वह हमेशा साफ़ हो तो मन को चैन मिलता है। किसी को सुकून से टिकने देने के लिए जगह को नरम और साफ़ ख़ाली रखना—मेहमाननवाज़ी वहीं से शुरू होती है।"},"ICON-0590":{"nm":"लगेज स्केल स्ट्रैप","de":"बैग को झट उठाकर उसका वज़न भाँपने वाली पट्टी। निकलने से पहले, सामान का वज़न हाथ से पहले ही थाम कर देख लेना। ले जाने और छोड़ जाने के बीच, मन के बोझ को भी साथ में चुपचाप तौल लेने का पल।"},"ICON-0591":{"nm":"शू पाउच पेयर","de":"बायाँ-दायाँ, दो जूतों को साथ-साथ रखने वाला थैलियों का एक जोड़ा। अलग रखने पर आसानी से खोने वाली चीज़ भी जोड़ी में रखी जाए तो भरोसेमंद लगती है। जो हमेशा साथ चलती हैं, उनमें एक-दूसरे को चुपचाप संभाले रखने की ताक़त होती है।"},"ICON-0592":{"nm":"एक्स्ट्रा बैग लूप","de":"जिस दिन एक हाथ कम पड़ जाए, उस दिन बैग को चुपके से टाँगने वाली एक छोटी कड़ी। सारा सामान संभाल पाना मुमकिन ही न हो, ऐसे दिनों के लिए एक अतिरिक्त सहूलियत। कुछ देर टाँग देने की एक जगह होने भर से कंधे कहीं हल्के हो जाते हैं।"},"ICON-0593":{"nm":"ट्रैवल इटिनरेरी चिप","de":"दिन-भर के रास्ते को एक चिप पर साफ़-साफ़ अंकित कर दिया जाता है। कहाँ मिलना है, कहाँ से बहना है—राह में भटकते क़दमों के लिए पहले से खींची गई एक मार्गरेखा। साथ चली जाने वाली राह अगर ख़ाने-ख़ाने बाँटकर लिख ली जाए, तो शायद ही भटकती है।"},"ICON-0594":{"nm":"मल्टी-एडेप्टर कैप","de":"अनजान देश के सॉकेट में भी बिल्कुल फ़िट बैठ जाने वाली टोपी। बनावट अलग होते हुए भी आख़िर एक-दूसरे से जुड़ जाते हैं। अलग-अलग जगहों से आई चीज़ों को जोड़ने का काम—तालमेल आख़िर एक छोटे-से रूपांतरण से ही चुपचाप शुरू होता है।"},"ICON-0595":{"nm":"ट्रांज़िट कार्ड स्लीव","de":"हर बार गेट पर छूने पर कार्ड को बचाने वाली एक पारदर्शी परत। रोज़ की आवाजाही, उसके घिसते निशानों तक को सुंदरता से लपेटती है। साधारण-सी राह भी संजो लो तो याद बन जाती है—यह पतली-सी परत यही साबित करती है।"},"ICON-0596":{"nm":"टिकट क्लिप","de":"पल-भर में मुड़-तुड़ जाने वाले टिकट को सलीके से थामने वाली क्लिप। राह में टिकट खो जाए तो मन भी डगमगा जाता है। जितना छोटा काग़ज़, उतना मज़बूती से थामना—सफ़र का सुकून आख़िर उसी एक ख़ाने से आता है।"},"ICON-0597":{"nm":"ट्रांसफ़र मेमो चिप","de":"कहाँ बदलना है, यह एक पंक्ति में लिखा गया एक छोटा चिप। हर उलझे हुए मोड़ पर, पहले से लिखा एक शब्द राह को रौशन कर देता है। नोट दरअसल राह भूलते भावी अपने-आप को चुपके से दी गई एक कोमल इशारा है।"},"ICON-0598":{"nm":"गेट पास टैग","de":"दरवाज़ा पार करते वक़्त चुपचाप पहचाना जाने वाला गुज़रने का टैग। रुकी हुई-सी लगने वाली राह भी अपनी पात्रता रखने पर सरककर खुल जाती है। खुलकर सामने आना, यही है बिना झिझक के अगले ख़ाने में सहज क़दम बढ़ाना।"},"ICON-0599":{"nm":"टैक्सी रसीद होल्डर","de":"हर छोटी पर्ची पर उस दिन तय की गई राह का साफ़ निशान छपा है। चारों ओर बिखरती पर्चियों को एक साथ करीने से जोड़ लो, तो मामूली-सा दिन भी पर्ची-दर-पर्ची जमा होकर एक ठीक-ठाक सफ़र बन जाता है।"},"ICON-0600":{"nm":"बाइसिकल रिफ़्लेक्टिव बैंड","de":"धुंधली राह पर गुज़रती रोशनी को थामकर चुपचाप चमकने वाली पट्टी। ख़ुद रोशन न होते हुए भी, किसी और की रोशनी से जगमगा उठती है। ख़ुद को दिखने लायक बनाना, रात की राह की एक कोमल गुज़ारिश है—कि कृपया सही-सलामत लौट आना।"},"ICON-0601":{"nm":"सूटकेस पहिया कवर","de":"हवाई अड्डे की कन्वेयर बेल्ट पर हज़ारों बार लुढ़कने के बाद भी सूटकेस के कोने बिल्कुल सही सलामत रहते हैं, बस इसी छोटे से कवर की बदौलत जो पहियों को लपेटे रहता है। सबसे ऊबड़-खाबड़ राह से सबसे पहले टकराने वाली यह जगह — किसी को चुपचाप बचाना हमेशा ऐसी ही किसी अनदेखी जगह से शुरू होता है।"},"ICON-0602":{"nm":"सीट हेडरेस्ट कवर","de":"लंबी बस यात्रा में, हेडरेस्ट पर एक कवर चढ़ाकर खिड़की से सिर टिका लेते हैं। पिछले यात्री की खुशबू और कल की थकान यहाँ तक नहीं पहुँच पाती। टिकने की जगह का साफ़ होना, अनजान रास्ते पर मिलने वाला एक अप्रत्याशित बड़ा सुकून है।"},"ICON-0603":{"nm":"पार्किंग स्थान पिन","de":"\"कौन-सी मंज़िल, कौन-सा खाना था?\" जो कभी खाली पार्किंग गैराज में भटका हो, वही जानता है यह पिन कितना भरोसेमंद है। धुंधली पड़ती याद की जगह एक टिका हुआ निशान, लौटने की राह पहले से तय कर देता है।"},"ICON-0604":{"nm":"रूम-की लैन्यार्ड","de":"कमरे की चाबी आख़िर इतनी आसानी से कैसे गुम हो जाती है। इसे डोरी में पिरोकर कलाई में लपेट लो, तो आज रात लौटने वाला कमरा भूलने का सवाल ही नहीं उठता। किसी अनजान शहर में भी अपनी एक जगह तय होने का छोटा-सा सुकून कलाई पर टंगा रहता है।"},"ICON-0605":{"nm":"दरवाज़ा साइन चिप","de":"रिहर्सल शुरू होते ही दरवाज़े पर एक चिप टांग दी जाती है। \"परेशान न करें\" — यानी अभी पूरी तरह एकाग्रता का समय है। मंच के पीछे की वह गहरी ख़ामोशी, ऐसे ही छोटे इशारों से बिना कुछ कहे सँभाली जाती है।"},"ICON-0606":{"nm":"टॉयलेटरी पाउच","de":"टूथब्रश, फ़ेस वॉश, हथेली जितना छोटा तौलिया। जहाँ भी जाओ, बस यही पाउच साथ ले लो तो दिन की शुरुआत और अंत हमेशा उन्हीं जाने-पहचाने हाथों से सँवर जाते हैं। अनजान बिस्तर को पल भर में अपना-सा बना देने वाली गृहस्थी की एक छोटी मुट्ठी।"},"ICON-0607":{"nm":"अतिरिक्त तौलिया क्लिप","de":"सिंक के पास, वह फ़ालतू तौलिया रखने की जगह न मिलने से हमेशा नम पड़ा रहता था। क्लिप से पकड़कर टाँग दो तो वह आख़िरकार अपनी जगह पा लेता है। किसी चीज़ को सूखने की जगह देना — अपनापन अक्सर इतने ही आकार का होता है।"},"ICON-0608":{"nm":"पावर स्ट्रिप पाउच","de":"हर बार बैग खोलने पर चार्जर एक गुत्थी बनकर उलझे मिलते थे। पूरी पावर स्ट्रिप को लपेटकर अंदर रख दो तो सब कुछ करीने से सुलझ जाता है। तार का खुलना यही कहता है कि यात्रा से पहले दिल का एक कोना भी धीरे से सुलझ जाता है।"},"ICON-0609":{"nm":"बंक नंबर लेबल","de":"छात्रावास के हर दो-मंज़िला बिस्तर पर लगा एक नंबर टैग। कौन-सी जगह मेरी है यह बताने वाले इस एक लेबल से, पहली बार आया अनजान कमरा भी रात होते-होते अपना घर बन जाता है। हर शुरुआत हमेशा इतनी ही छोटी होती है।"},"ICON-0610":{"nm":"मिनी कपड़े सुखाने की डोरी","de":"खिड़की की चौखट के बीच दोनों सिरे बाँध दो तो वह कपड़े सुखाने की डोरी बन जाती है। धूप भरे दिन, हाथ से धुले कुछ मोज़े हवा में फूले-फूले झूलते हैं। घर से दूर भी रोज़मर्रा की ज़िंदगी ऐसे ही किसी डोरी पर सूखती है।"},"ICON-0611":{"nm":"स्लिपर पहचान टैग","de":"दरवाज़े पर ढेर सारी चप्पलें जमा हों तो किसकी कौन-सी है, कुछ पता ही नहीं चलता। एक छोटा टैग लगा दो तो जूते भी अपने मालिक को पहचान लेते हैं। साथ रहकर गुज़ारा करने वाली ज़िंदगी में ऐसे अपनेपन भरे निशानों की सख़्त ज़रूरत होती है।"},"ICON-0612":{"nm":"नाश्ता कूपन होल्डर","de":"सुबह के भोजन का कूपन खोंसकर रखने वाला होल्डर। भूखी सुबह में, यही एक पर्ची भाप उठते एक कटोरे सूप की गारंटी बन जाती है। सफ़र का हर दिन हमेशा एक गर्म भोजन से धीरे-धीरे खुलता है।"},"ICON-0613":{"nm":"टखना परावर्तक पट्टी","de":"टखने पर बाँधो तो अँधेरे में रोशनी वापस चमका देती है। रात की सैर में, दूर से आती गाड़ी को बिना कुछ कहे हाथ हिलाकर बताने वाली एक छोटी पट्टी — \"यहाँ कोई है।\" सुरक्षा इतनी ही सादगी से चमकती है।"},"ICON-0614":{"nm":"वेट वाइप कैप","de":"वेट वाइप पैकेट के मुँह पर बिल्कुल फ़िट बैठने वाली कैप। एक-एक शीट धीरे से निकलती है और बाकी सूखने नहीं पातीं। मामूली दिखने वाली, पर रोज़ हाथ लगने वाली चीज़ों की एक न एक वजह ज़रूर छिपी होती है।"},"ICON-0615":{"nm":"पिकनिक चटाई पट्टा","de":"चटाई को गोल लपेटकर पट्टे से बाँध दो। हान नदी का किनारा हो या चेरी फूलों की छाँव, बिछाते ही वह जगह अपनी बन जाती है। घास पर हथेली जितनी ज़मीन को साथ लेकर घूमने वाला एक पट्टा।"},"ICON-0616":{"nm":"मच्छर पैच केस","de":"गर्मी की रातों की ज़रूरी चीज़, मच्छर पैच रखने वाला केस। खुजली होने से पहले ही तैयार रख लेने की सोच इसी एक छोटे ख़ाने में समाई है। खुले मंच की पिछली सीटें ऐसी ही छोटी-छोटी सावधानियों से हमेशा भरोसेमंद बनती हैं।"},"ICON-0617":{"nm":"सैर बोतल हुक","de":"सैर पर निकलते वक़्त पानी की बोतल बैग पर टाँगने का हुक। प्यास लगते ही हाथ की पहुँच में पानी होना, उतनी ही दूर तक चलने की गारंटी है। चलने वाले को रुकने न देने वाला एक छोटा-सा जुड़ाव।"},"ICON-0618":{"nm":"फोल्डेबल शॉपिंग बास्केट","de":"खोलो तो टोकरी, मोड़ो तो हथेली जितनी छोटी। बाज़ार की गलियों में घूमते हुए मन भा गई सब्ज़ियों का एक गुच्छा रखने के लिए बिल्कुल सही। गृहस्थी की समझदारी हमेशा कम जगह घेरने और हल्का उठाने की दिशा में ही बढ़ती आई है।"},"ICON-0619":{"nm":"पवनरोधी क्लिप","de":"हवा वाले दिन, फड़फड़ाते तंबू के किनारे को पकड़कर मज़बूती से थाम लेती है। एक क्लिप, बार-बार हिलती चीज़ को उसकी जगह पर दबाकर रोक देती है। बाहर सबसे भरोसेमंद चीज़, हैरानी से, इतनी ही उंगली जितनी होती है।"},"ICON-0620":{"nm":"धूप रोक पिन","de":"खिड़की में लगाकर धूप को तिरछा रोकने वाली पिन। दोपहर की तेज़ रोशनी को थोड़ी छाँव से धीरे से ढँक देती है। चकाचौंध कम करना भी किसी के लिए सबसे कोमल स्पर्श बन जाता है।"},"ICON-0621":{"nm":"आपातकालीन सीटी कैप","de":"आपातकालीन सीटी के मुँह को ढँकने वाली कैप। धूल न जाए, ताकि ज़रूरत की घड़ी में एक ही साँस में बज उठे। कभी इस्तेमाल न हो यही उम्मीद रखते हुए भी, बस पास होने से ही मन को सुकून देने वाली चीज़ें होती हैं।"},"ICON-0622":{"nm":"छाता नोक कैप","de":"छाते की नोक पर पहनाई जाने वाली छोटी कैप। नुकीला सिरा भोथरा हो जाए तो न बगल वाला, न अपना बैग चोट खाता है। बारिश के दिन का शिष्टाचार ऐसे ही किसी तीखे सिरे को गोल और नरम लपेटने से चुपचाप शुरू होता है।"},"ICON-0623":{"nm":"रेनकोट पाउच","de":"तह किए रेनकोट को लपेटकर रखने वाला पाउच। अगली बारिश आने तक बैग के एक कोने में ख़ामोशी से इंतज़ार करता है। तैयारी आख़िर में, शायद कभी काम न आए ऐसी चीज़ को पहले से सँभाल रखने वाला दिल का एक हिस्सा ही तो है।"},"ICON-0624":{"nm":"वाटरप्रूफ़ जूता कवर","de":"जूतों के ऊपर चढ़ा दो तो बारिश का पानी अब अंदर नहीं रिस पाता। बरसात में स्कूल जाते वक़्त भी मोज़े सूखे रहते हैं। पैर की उंगलियों तक न भीगने वाला दिन, सोचे से कहीं ज़्यादा मूड बदल देता है।"},"ICON-0625":{"nm":"बर्फ़ फिसलनरोधी पैड","de":"जूतों के तले चिपकाने पर बर्फ़ीली सड़क भी उतनी डरावनी नहीं लगती। बर्फ़ से भरी गलियों को छोटे-छोटे क़दमों से पार करते उस सर्दी में, न फिसलने देते हुए चुपचाप थामे रखने वाला पैड। सावधान क़दमों के नीचे छिपा भरोसा।"},"ICON-0626":{"nm":"कूलिंग नेक रिंग","de":"गले में लपेटो तो ठंडी हवा शांति से घूमती रहती है। भरी गर्मी में भी गर्दन पर ठंडक की एक लकीर लपेटे घूमने वाली गर्मियों की समझदारी। गर्मी झेलने का तरीका भी हर साल थोड़ा और सलीके से निखरता जाता है।"},"ICON-0627":{"nm":"हैंडहेल्ड फ़ैन स्टैंड","de":"हाथ वाले पंखे को टिकाकर खड़ा रखने का स्टैंड। दोनों हाथ खाली हों तो किताब के पन्ने भी पलटे जा सकते हैं और पंखा झलने के बजाय लिखा भी जा सकता है। हवा की एक छोटी लकीर मेज़ के सामने की लंबी गर्मी को किसी तरह सह्य बना देती है।"},"ICON-0628":{"nm":"हैंड वार्मर पाउच","de":"हैंड वार्मर ले जाने वाला पाउच। ठंडी पड़ी उंगलियों को गरमाने के लिए जेब में हाथ डालते ही, वहाँ पहले से एक छोटी गर्माहट इंतज़ार में मिलती है। सर्दी की हर बाहरी यात्रा गर्माहट की इसी एक मुट्ठी के सहारे निकाली जाती है।"},"ICON-0629":{"nm":"ईयरमफ़ केस","de":"कान ढँकने वाले ईयरमफ़ रखने का केस। अगली सर्दी आने तक इन्हें करीने से सँभालकर रखने की जगह। मौसम बदलने पर भी न फेंकी जा सकने वाली चीज़ों में, फिर मिलने वाली सर्दी पर एक ख़ामोश भरोसा छिपा होता है।"},"ICON-0630":{"nm":"यूवी सेंसर चिप","de":"रोशनी को हल्का सा छुओ तो यह चिप रंग से बता देती है आज की धूप कितनी तेज़ है। धूप की अनदेखी तीव्रता को आख़िरकार आँखों के सामने ले आती है। आसमान पढ़ने वाली एक छोटी आँख को कलाई पर बाँध लेने जैसा है यह।"},"ICON-0631":{"nm":"गली स्टैंप बोर्ड","de":"गली के मुहाने की हर दुकान से मुहर लेकर भरा जाने वाला बोर्ड। हर ख़ाना भरने के साथ मोहल्ले का नक्शा मन में साफ़ उभरने लगता है। पैरों से चलकर बटोरी गई यादें ऐसे ही मुहर के निशानों में बाकी रह जाती हैं।"},"ICON-0632":{"nm":"यात्रा पिन बोर्ड","de":"घूमी हर जगह पर एक पिन गाड़ देने वाला छोटा बोर्ड। बिंदु जैसे-जैसे बढ़ते हैं, मेरी दुनिया की परिधि भी साथ ही फैलती जाती है। हर पिन एक निशान है जो चुपचाप कहता है, \"मैं यहाँ था।\""},"ICON-0633":{"nm":"छोटी दिशासूचक डोरी","de":"चाहे कितना भी भटको, उत्तर अकेला हमेशा अपनी जगह अटल रहता है। सीने के पास लटका यह छोटा दिशासूचक, जब पता ही न चले किस ओर जाना है, तब पहले धीरे से डगमगाते मन को ही थाम लेता है।"},"ICON-0634":{"nm":"रास्ता खोज मेमो रिंग","de":"रास्ता ढूँढते हुए लिखी गई पर्चियाँ एक छल्ले में पिरो दी जाती हैं। \"लाल डाकघर के डिब्बे से बाएँ मुड़ो।\" किसी की टेढ़ी-मेढ़ी लिखावट अनजान गली को धीरे से राह दिखाती है। काग़ज़ पर बचा रास्ता आसानी से धुंधला नहीं पड़ता।"},"ICON-0635":{"nm":"लैंडमार्क स्टिकर बुक","de":"हर मंज़िल पर ख़रीदे एक-एक स्टिकर से भरी जाने वाली किताब। मीनारें, पुल, पुराने क़िले की दीवारें, पन्ने-दर-पन्ने जमा होती जाती हैं। घूमी हुई जगहों को इकट्ठा करना, गुज़रे वक़्त को उंगलियों से फिर से छूने जैसा है।"},"ICON-0636":{"nm":"मेट्रो ट्रांसफ़र चिप","de":"लाइनें अलग होने वाले इंटरचेंज स्टेशन पर हाथ में कसकर पकड़ी जाने वाली चिप। कहाँ बदलनी है यह तय करने का वह छोटा-सा पल, कभी-कभी पूरे दिन की दिशा ही पलट देता है। एक छोटे फ़ैसले से शहर एक अलग चेहरा दिखाता है।"},"ICON-0637":{"nm":"मोहल्ला खोज कार्ड","de":"\"आज बस इस मोहल्ले की बेकरी तक।\" एक कार्ड निकालो तो आज की मंज़िल तय हो जाती है। हमेशा गुज़री जानी-पहचानी गली भी कोई मिशन मिलते ही नया रास्ता बन जाती है। यह याद दिलाने वाला एक कार्ड कि रोमांच कहीं दूर नहीं है।"},"ICON-0638":{"nm":"दुकान विज़िटिंग कार्ड होल्डर","de":"पसंदीदा दुकानों से मिले विज़िटिंग कार्ड खोंसकर रखने वाला होल्डर। स्वादिष्ट खाने वाली जगह, अपनेपन से मिलने वाला मालिक — एक-एक करके ख़ाने भरते जाते हैं। किसी शहर से लगाव, ऐसे ही छोटे काग़ज़ के टुकड़ों से शुरू होता है।"},"ICON-0639":{"nm":"कोर्स पूर्णता बैज बोर्ड","de":"सैर का पूरा रास्ता आख़िर तक तय करने पर एक बैज भर जाने वाला बोर्ड। पूरा रास्ता तय करने का संतोष एक गोल धातु बनकर हाथ में रह जाता है। आख़िर तक चलने वाला ही जानता है वह गर्व, जो यहाँ साफ़ अंकित हो जाता है।"},"ICON-0640":{"nm":"बैग लॉक की-रिंग","de":"बैग की ज़िप पर लगाया जाने वाला छोटा ताला-सह-की-रिंग। क़ीमती चीज़ों को कसकर सँभालते हुए भी बैग के किनारे से खनकता रहता है। सुरक्षा और सजावट का एक साथ होना, यात्री का एक चतुर साथी है।"},"ICON-0641":{"nm":"गुम-रोधी टैग","de":"बैग के सबसे गहरे अँधेरे में दुबका रहता है, और जिस पल सब हार मान लेते हैं, ठीक तभी हल्के से टिमटिमाता है — \"यहाँ हूँ मैं।\" गुम हो चुका समझा गया मन उंगलियों तक लौटने की आवाज़। छोटा होकर भी आख़िर तक मालिक का साथ नहीं छोड़ता।"},"ICON-0642":{"nm":"ज़िप लॉक रिंग","de":"क्लिक — एक बार बंद हो जाए तो किसी आम हाथ से खुलती नहीं। हड़बड़ी में बढ़ते नाख़ून और चुपके से आती उंगली, दोनों को समान रूप से रोकने वाली ज़िद। सुरक्षा कभी-कभी थोड़ी सख़्त हो तो चलता है, यह अपने भारी वज़न से बता देती है।"},"ICON-0643":{"nm":"चोरी-रोधी घंटी पट्टा","de":"भुगतान पूरा होने तक शेल्फ़ पर रखी चीज़ों को बेवजह बाहर न जाने देने वाला एक अदृश्य द्वारपाल। ईमानदार हाथ छूकर गुज़रे तो आख़िर तक ख़ामोश रहता है। जो घंटी नहीं बजती, वही सबसे शांत घंटी है।"},"ICON-0644":{"nm":"संपर्क छिपाने वाला लेबल","de":"पार्सल के डिब्बे पर लिखे नाम और नंबर के ऊपर धीरे से एक परत बिछ जाती है। कौन रहता है, कहाँ जाना है — यह बस पाने वाले को ही पता होना चाहिए। अच्छी तरह ढकना भी अपनेपन का एक रूप है, यह चुपचाप अपनी जगह सँभाले रखती है।"},"ICON-0645":{"nm":"पासपोर्ट कवर बैंड","de":"अनजान हवाई अड्डा, तड़के कन्वेयर पर घूमते एक जैसे दिखने वाले दर्जनों कवर। उनके बीच सिर्फ़ अपने रंग से \"इधर है\" इशारा करती है। दूर सफ़र पर निकले दस्तावेज़ को पहनाया गया एक छोटा कोट। जिल्द घिस जाए तब भी सफ़र चमकीला ही रहता है।"},"ICON-0646":{"nm":"नकदी छाँटने का पाउच","de":"नोट बाईं ओर, सिक्के दाईं ओर, आपातकालीन पैसा किसी को न पता वाले ख़ाने में। बाज़ार से लौटा हाथ सबसे पहले यहीं टटोलता है। उलझा-सा दिन भी इसके अंदर करीने से, खनकते हुए अपनी जगह पा लेता है।"},"ICON-0647":{"nm":"सुरक्षा सील स्टिकर","de":"एक बार उखाड़ो तो निशान रह जाता है। \"किसी ने खोला था\" यह बात आख़िर तक न छिपा पाने वाली एक छोटी, ईमानदार अंतरात्मा। सील बंद सही-सलामत पहुँचे हर डिब्बे के नीचे, इसी दोस्त की अटल ख़ामोशी बिछी होती है।"},"ICON-0648":{"nm":"आपातकालीन संपर्क चिप","de":"रास्ता भूले बच्चे की जेब, लैपटॉप बैग के अंदर, कुत्ते की पट्टे का सिरा। जब बोल पाना मुमकिन न हो, तब भी यह साफ़-साफ़ नंबर पुकार देती है। एक छोटी चिप में पूरी तरह \"मुझे घर पहुँचा दो\" समाया रहता है।"},"ICON-0649":{"nm":"सेल्फ़ी स्टिक रिमोट कैप","de":"हाथ कम पड़ने से जिस समूह-फ़ोटो में हमेशा कोई न कोई कट जाता था। अब आख़िर में बटन दबाते ही पूरा परिवार एक ही फ्रेम में समा जाता है। सब साथ हँसते उस पल में, मैं धीरे से शटर दबाकर उसी में कूद जाता हूँ।"},"ICON-0650":{"nm":"लेंस पाउच डोरी","de":"फ़ालतू लेंस बैग के अंदर टकराएँ नहीं, इसलिए डोरी से कसकर थाम लिया जाता है। एक शीशे का टुकड़ा ही एक नज़ारा होता है, इसलिए उसका वज़न बेवजह हिलाया नहीं जाता। फ़ोटोग्राफ़र की सावधानी हर गाँठ में बँधी होती है।"},"ICON-0651":{"nm":"फ़िल्टर केस रिंग","de":"एक पतली-सी परत एक ही आसमान को अलग रोशनी में बदल देती है। उन छोटे जादुओं को गोल घोंसले में करीने से सँभालकर रखने की जगह। केस खोलने के हर पल, आज कैसी शाम क़ैद करूँ, उंगलियाँ पल भर के लिए सिहर उठती हैं।"},"ICON-0652":{"nm":"ट्राइपॉड पाउच","de":"मोड़ो तो हथेली जितना, खोलो तो न हिलने वाले तीन पैर। काँपते हाथों की जगह नज़ारा थामे रखने वाले दोस्त को करीने से लपेटकर रखते हैं। सामान जितना भारी हो, उतना ही नरम कपड़ा उसे सुलाने का हक़ रखता है।"},"ICON-0653":{"nm":"कैमरा स्ट्रैप पैच","de":"दिन भर चलते-चलते वह वक़्त आ जाता है जब कैमरा कंधे पर भारी पड़ने लगता है। तभी एक पैच चुपचाप उस बोझ का कुछ हिस्सा बाँट लेता है। एक अच्छी तस्वीर के लिए दूर तक चलने वाले कंधे पर रखा गया एक छोटा, मुलायम सुकून।"},"ICON-0654":{"nm":"मेमोरी छँटाई कार्ड","de":"सैकड़ों यादें किस कार्ड में सोई हैं, यह याद न आने वाली रात में, रंग-बिरंगे निशान राह दिखा देते हैं। बसंत का सफ़र नीले रंग में, पहला मंच पीले में। यादों को भी अलग-अलग ख़ाने देने वाली एक छोटी, अपनेपन भरी पुस्तकालयाध्यक्ष।"},"ICON-0655":{"nm":"चार्जिंग केबल रोल","de":"बैग के अंदर तार गाँठों का तमाशा खड़ा करे उससे पहले, उसे गोल लपेटकर करीने से सुला दिया जाता है। एक तार सुलझाओ तो न जाने क्यों दिल की एक लकीर भी साथ ही सुलझ जाती है। गोल लिपटा हुआ दृश्य देखते ही मन को शांति मिलती है।"},"ICON-0656":{"nm":"फ़ोटो बैकअप लेबल","de":"\"ये तस्वीरें, बैकअप हुई थीं न?\" देर रात अचानक उभरती इस बेचैनी का जवाब पहले से लिखकर रखने वाली एक छोटी पर्ची। पल जितना क़ीमती हो, उतना ही दो से ज़्यादा जगह ज़िंदा रहना चाहिए, यह लेबल साफ़-साफ़ लिख देता है।"},"ICON-0657":{"nm":"कंपोज़िशन फ्रेम बोर्ड","de":"चौकोर खिड़की से दुनिया देखो तो क्या रखना है और क्या छोड़ना है, एक झटके में दिख जाता है। अच्छी तस्वीर ज़्यादा भरने से नहीं, अच्छे से घटाने से बनती है — यह पहले खाली फ्रेम ही सिखा देती है।"},"ICON-0658":{"nm":"सिक्का पर्स चार्म","de":"बैग के किनारे झूलते हुए मुट्ठी भर खुले पैसे थामे रहता है। वेंडिंग मशीन के सामने, भाप उठते फिश-बन ठेले के सामने सबसे पहले खुलने वाला छोटा ख़ज़ाना। वह खनक छोटी-छोटी ख़ुशियों का साउंड इफ़ेक्ट है।"},"ICON-0659":{"nm":"रसीद स्पिंडल","de":"फेंकते-फेंकते रह गए काग़ज़ के टुकड़े एक-एक करके पिरो दिए जाते हैं। आज क्या खाया, क्या ख़रीदा — रसीद किसी भी बहीखाते से ज़्यादा ईमानदार डायरी है। महीने भर की जमा करो तो ज़िंदगी का काफ़ी मोटा रिकॉर्ड बन जाता है।"},"ICON-0660":{"nm":"बाज़ार टोकरी टैग","de":"बाज़ार जाती कलाई पर टँगकर बाज़ार की गलियों में साथ घूमता है। एक टुकड़ा टोफू, एक गुच्छा हरा प्याज़, और मुफ़्त में मिली अपनापी। यह सारा बोझ बिना शिकायत के अपने ऊपर ले लेता है। ख़ाली होने से ज़्यादा भरने में ख़ुश होने वाला एक दोस्त।"},"ICON-0661":{"nm":"स्मृति चुंबक बोर्ड","de":"हर मंज़िल पर एक चुनकर फ्रिज के दरवाज़े पर चिपका दो, रसोई एक छोटा विश्व-मानचित्र बन जाती है। घूमे हुए शहर साथ-साथ लटककर फुसफुसाते हैं, \"फिर चलें।\" एक साधारण लोहे के टुकड़े में भी यादों को थामे रखने की ताक़त होती है।"},"ICON-0662":{"nm":"क्षेत्रीय स्टैंप बुक","de":"हर पन्ने पर एक मुहर, चली गई गलियाँ स्याही में फिर से जी उठती हैं। पूरे देश घूमकर बटोरे लाल निशान ही तो हैं क़दमों के नक्शे। ख़ाली ख़ाने जितने कम होते जाते हैं, अगला सफ़र उतना ही चुपचाप इशारा करने लगता है।"},"ICON-0663":{"nm":"पैकिंग डोरी रील","de":"एक तोहफ़े का डिब्बा बाँधने के लिए बिना रुके खुलता, लंबा-सा धैर्य। सही वक़्त पर काटना जानने वाले हाथ को ही यह साफ़-सुथरी गाँठ बख़्शती है। लिपटी हुई, यह चुपचाप अपनी अगली बारी का इंतज़ार करती है।"},"ICON-0664":{"nm":"तोहफ़ा कुशन पैक","de":"टूटने वाले दिल को नरमी से गले लगाकर थामती है। हिलती-डुलती डिलीवरी गाड़ी में भी, \"फ़िक्र मत करो, मैं थाम लूँगी\" कहते हुए मुलायम बनी रहती है। यह डिब्बा खोलने वाले की खिली मुस्कान तक पहले से बचाकर रखती है।"},"ICON-0665":{"nm":"क़ीमत छिपाने वाला स्टिकर","de":"तोहफ़े में दी जाने वाली चीज़ की क़ीमत को चुपचाप ढँक देने वाला, एक अपनेपन भरा झूठ। \"क़ीमत जानने की ज़रूरत नहीं, बस दिल क़ुबूल करो\" कहते हुए क़ीमत के टैग पर धीरे से बैठ जाता है। यह छिपाना नहीं, बल्कि उस दिल को और चमका देना है।"},"ICON-0666":{"nm":"छोटी शॉपिंग कार्ट चिप","de":"असली कार्ट भले न धकेल पाओ, पर उंगली की नोक पर झूलता यह छोटा दोस्त बाज़ार जाने की पूरी सिहरन समेटे रहता है। छोटा होकर भी \"आज क्या ख़रीदूँ?\" वाली वह धड़कन असली से कम भारी नहीं होती।"},"ICON-0667":{"nm":"चमकीला जूता क्लिप","de":"रात की सैर पर निकले जूते की नोक पर चमककर, गुज़रती गाड़ी को इशारा देती है — \"यहाँ कोई है।\" अँधेरी गली में सबसे पहले स्वागत करने आने वाली छोटी रोशनी। सुरक्षा हमेशा पैर की उंगलियों से ही चुपचाप शुरू होती है।"},"ICON-0668":{"nm":"छोटी टॉर्च कैप","de":"टॉर्च के सिर पर पहनाओ तो रोशनी और दूर, और मुलायम फैलती है। अँधेरे तंबू की छत पर तारों का झुंड बना देने वाली एक छोटी जादूगरनी। जिस रात अँधेरा थोड़ा डरावना लगे, उस रात इससे बेहतर दोस्त कोई नहीं।"},"ICON-0669":{"nm":"सुरक्षित-घर-वापसी बटन","de":"दबाओ तो \"सही-सलामत पहुँच गया\" यह एक लाइन दूर बैठे परिवार तक उड़कर पहुँच जाती है। देर रात दरवाज़े की आवाज़ की जगह, एक छोटा बटन ही ख़बर पहुँचा देता है। कोई इसी इशारे का इंतज़ार करते हुए सो जाता है।"},"ICON-0670":{"nm":"परावर्तक स्टिकर रोल","de":"एक टुकड़ा काटकर बैग पर, साइकिल पर, छाते पर चिपका दो तो रात का रास्ता काफ़ी कम ख़तरनाक हो जाता है। हेडलाइट से टकराते ही चमककर जाग उठने वाला एक नींद भरा साथी। लिपटे हुए, यह अगले अँधेरे के आने का इंतज़ार करता है।"},"ICON-0671":{"nm":"आपातकालीन टैक्सी कार्ड","de":"बटुए के एक ख़ाने में रख लो तो देर रात एक ख़ाली स्टॉप भी उतना डरावना नहीं लगता। एक नंबर, पते की एक लाइन एक वादे की तरह लिखी होती है — \"मैं घर पहुँचा दूँगा।\" किसे पता था \"आपातकाल\" शब्द इतना भरोसेमंद भी हो सकता है।"},"ICON-0672":{"nm":"रात्रि मार्ग नक्शा पट्टी","de":"बत्तियाँ कम हों वहाँ इसे कलाई पर बाँधकर चलते हैं। कौन-सी गली रोशन है, कहाँ अँधेरा है, रात ही जानने वाला शॉर्टकट धीरे से बता देती है। अँधेरे में भी दिशा न खोने देने के लिए साथ बँधी रहने वाली एक पट्टी।"},"ICON-0673":{"nm":"सुरक्षा अलार्म पाउच","de":"मुश्किल घड़ी में खींचो तो पूरी गली चौंक उठे इतनी ज़ोर से चीख़ती है। बाक़ी वक़्त पाउच के अंदर चुपचाप छिपी रहकर, सिर्फ़ उसी एक पल के लिए अपनी आवाज़ बचाकर रखती है। सबसे छोटे बैग में छिपी सबसे बड़ी पुकार।"},"ICON-0674":{"nm":"दरवाज़ा रोशनी की-रिंग","de":"अँधेरे गलियारे के आख़िर में टटोल-टटोलकर चाबी का छेद ढूँढती रातों को अब अलविदा। दरवाज़े पर लटककर लौटते हाथ का एक गोल रोशनी से स्वागत करती है। \"बहुत मेहनत की, घर आ गए\" — यह की-रिंग पहले ही कह देती है।"},"ICON-0675":{"nm":"कमरे में लौटने की पर्ची","de":"\"छाता ले जाना, निकलते वक़्त बत्ती बुझा देना।\" फ्रिज पर चिपकी छोटी-सी हिदायत ख़ाली कमरे की रखवाली करती है। लौटने वाले के लिए लिखी एक छोटी पर्ची। एक काग़ज़ में समाया अपनापन दरवाज़े तक चुपचाप साथ चलता है।"},"ICON-0676":{"nm":"केबल कंघी","de":"उलझे हुए तारों को बालों की तरह धीरे-धीरे सुलझाकर करीने से बिठा देती है। मेज़ के पीछे जंगल-सी उलझी केबलों की भीड़ चंद बार कंघी करते ही सुलझ जाती है। उलझती तो सिर्फ़ बाल ही नहीं, कंघी यह धीरे से याद दिलाती है।"},"ICON-0677":{"nm":"पेन होल्डर डिवाइडर","de":"पेंसिल इधर, हाइलाइटर उधर, कैंची आख़िरी ख़ाने में। एक ही डिब्बे के अंदर एक छोटा गाँव बाँटकर पेनों को उनकी जगह देती है। ख़ाने बन जाएँ तो हाथ भी फिर नहीं भटकता। मेज़ पर एक छोटी व्यवस्था की शुरुआत।"},"ICON-0678":{"nm":"मॉनिटर मेमो क्लिप","de":"मॉनिटर की बगल में टँगकर \"आज के काम\" को ठीक नज़र के सामने ले आती है। भूलने का मौक़ा दिए बिना सीधे सामने दिखने वाला एक छोटा नोटिस बोर्ड। एक क्लिप, बार-बार टालने की आदत को धीरे से थाम लेती है।"},"ICON-0679":{"nm":"दराज़ छँटाई ट्रे","de":"क्लिप और रबर बैंड, पिन और रबड़। दराज़ के छोटे-छोटे क़बीलों को अपना-अपना कमरा देती है। ख़ानों में बँटी जगह तक हाथ पहुँचे तो ढूँढने में लगने वाला वक़्त कम हो जाता है और मन का एक कोना हल्का हो जाता है।"},"ICON-0680":{"nm":"धूल ब्रश ट्यूब","de":"लेंस पर बैठा धूल का एक कण भी तस्वीर में एक बड़ा दाग़ बन जाता है। इसलिए ब्रश डिब्बे के अंदर हमेशा साफ़-सुथरा तैयार रहकर इंतज़ार करता है। किसी की नज़र में न आने वाली सफ़ाई सँभालने वाली, एक मेहनती उंगली।"},"ICON-0681":{"nm":"डेस्क मैट कॉर्नर","de":"मेज़ के एक कोने में बिछी हथेली जितनी नरमी। पेन लुढ़ककर गिरता नहीं, और ठंडे शीशे की जगह गर्म बनावट कलाई को थाम लेती है। लंबी रात की लिखावट न काँपे, इसके लिए सबसे पहले अपनी जगह देने वाली एक अपनापी भरी सतह।"},"ICON-0682":{"nm":"माउस कॉर्ड होल्डर","de":"तार उलझ जाए तो कहीं न कहीं मन भी उलझ जाता है। बिखरने वाली एक लकीर को पहले ही पकड़कर करीने से लिटा देने वाला हाथ। नज़र में मुश्किल से आते हुए भी मेज़ की बनावट को चुपचाप सँवारने वाला, एक छोटा मेहनती सलीक़ा।"},"ICON-0683":{"nm":"चार्जिंग डॉक स्टैंड","de":"लेटे हुए डिवाइस को तिरछा खड़ा करो तो स्क्रीन आख़िरकार आँखों से नज़रें मिलाती है। चार्ज होते हुए का इंतज़ार भी करीने से सजा हुआ लगने लगता है। सहारा देना, आराम कर रही किसी चीज़ की भी मुद्रा सँभालना है।"},"ICON-0684":{"nm":"छोटा कूड़ेदान लेबल","de":"सबसे छोटे डिब्बे को भी अपना नाम मिलता है। \"यहाँ फेंकें\" यह एक लाइन बिखरी मेज़ पर एक शांत व्यवस्था बुला लाती है। लेबल आख़िर में, किसी चीज़ से यह कहने वाला एक छोटा अभिवादन है कि तुम्हारा काम यहाँ है।"},"ICON-0685":{"nm":"पार्टीशन बोर्ड पिन","de":"बोर्ड पर काग़ज़ का एक टुकड़ा दबाकर टिका देती है। न भूलना चाहने वाले मन को कुछ देर दीवार के हवाले करना। पिन की नोक पर लटका आज का इरादा हवा में हल्का हिलता है, हर बार गुज़रते वक़्त तुम्हें थाम लेता है।"},"ICON-0686":{"nm":"लेबल फ्रेम चिप","de":"एक चौकोर किनारा साधारण लिखावट को एक साफ़, सुस्पष्ट वाक्य में बदल देता है। आसानी से बिखर जाने वाले नोट को करीने भरी गरिमा से लपेटने वाली एक चिप। बंद करना नहीं, बल्कि ज़रूरी बात को खोने से बचाकर गले लगाना है।"},"ICON-0687":{"nm":"पारदर्शी दराज़ हैंडल","de":"पारदर्शी दराज़ पर हैंडल लगा दो तो अंदर क्या है यह देखते हुए भी बेवजह खोलने से बच जाते हो। दिखे, पर पास न आए, हथेली जितनी एक दूरी। पारदर्शिता में भी शिष्टाचार चाहिए, दराज़ यही फुसफुसाकर कहती है।"},"ICON-0688":{"nm":"ढक्कन लॉक क्लिप","de":"खुला छोड़ दो तो ख़ुशबू और रंग दोनों चुपचाप उड़ जाते हैं। ढक्कन को कसकर काटे रखने वाली एक छोटी सी क्लिप से कल का रंग कल तक पूरा-पूरा बचा रहता है। बंद करना दरअसल, जो प्यारा है उसे बचाए रखने का काम है।"},"ICON-0689":{"nm":"डिसिकेंट होल्डर","de":"सीलन से नफ़रत करते हुए चुपचाप अपनी जगह सँभाले एक छोटा पहरेदार। सूखी हवा को पास रखना ही लंबे समय तक सँभालकर रखने की पहली शर्त है, यह सलीक़ेदार होल्डर चुपचाप याद दिलाता है। सूखापन इसी तरह बचा रहता है।"},"ICON-0690":{"nm":"स्टोरेज बास्केट टैग","de":"हर टोकरी पर एक छोटा नाम टैग। किस ख़ाने में क्या रहता है यह तय कर लो तो ढूँढने में लगने वाला वक़्त सीधे आराम के वक़्त में बदल जाता है। सँवारना, भविष्य के अपने-आप को पहले से थमाई गई एक अपनेपन भरी पर्ची है।"},"ICON-0691":{"nm":"मिनी पार्टीशन बोर्ड","de":"मेज़ पर पल भर में एक आरामदेह छोटा कमरा खड़ा कर देने वाला एक छोटा विभाजक। इस एक बोर्ड से दुनिया से थोड़ा मुँह मोड़ा हुआ एक शांत कोना बन जाता है। एकाग्रता के बसने लायक़, पूरी तरह अपनी एक आरामदेह जगह।"},"ICON-0692":{"nm":"बैग स्टैंड","de":"बार-बार गिर पड़ने वाले लिफ़ाफ़ों की पीठ को धीरे से थामकर खड़ा रखने वाला स्टैंड। बस करीने से खड़े होने भर से चुनना कहीं आसान हो जाता है। सीधा खड़ा रखना, अगले हाथ के लिए पहले से सोची गई एक फ़िक्र है।"},"ICON-0693":{"nm":"ख़ाली स्थान चिह्न चिप","de":"जान-बूझकर ख़ालीपन को चिह्नित करने वाली चिप। भरी जाने वाली जगह को छोड़ रखना भी एक पक्की योजना है। ख़ाली ख़ाना आलस नहीं, बल्कि जल्द आने वाली किसी चीज़ के लिए विनम्रता से छोड़ी गई हथेली जितनी जगह है।"},"ICON-0694":{"nm":"टूथब्रश कवर कैप","de":"मुँह को छूने वाले ब्रश के लिए और भी नाज़ुक ख़याल रखा जाता है। धूल का एक कण भी रोक देने वाली एक छोटी टोपी। न दिखने वाली सफ़ाई का ख़याल रखना ही, हर सुबह को ताज़ा खोलने वाली एक मामूली-सी मेहनत है।"},"ICON-0695":{"nm":"साबुन डिश जाली","de":"पानी में डूबकर साबुन नरम न पड़े, इसके लिए उसे धीरे से ऊपर उठाए रखने वाली जाली। पानी बह जाने देना ही उसे ज़्यादा देर तक साथ बनाए रखने की कुंजी है — यह बात बाथरूम की सबसे नीची, सबसे छोटी जगह से रोज़ चुपचाप साबित होती है।"},"ICON-0696":{"nm":"शैम्पू पंप क्लिप","de":"पंप के सिर को धीरे से थामे रखती है, ताकि एक दबाव में बस उतना ही निकले जितना ठीक हो। सँभालकर इस्तेमाल करने की आदत ही दूर तक चलने वाली गृहस्थी की नींव है। एक छोटी क्लिप फ़िज़ूलख़र्ची को अपनेपन से क़ाबू में रखती है।"},"ICON-0697":{"nm":"रेज़र हुक कैप","de":"तीखी चीज़ों के लिए अलग से एक छोटा घर बनाया जाता है। रेज़र को कैप में खोंसकर टाँग दो तो नमी और ख़तरा दोनों बहकर उतर जाते हैं। तीखेपन को सावधानी से सँभालना, आख़िर ख़ुद को सँजोने का ही एक तरीक़ा है।"},"ICON-0698":{"nm":"शावर तौलिया रिंग","de":"लंबा फैला तौलिया एक छल्ला बनाकर हाथ न पहुँचने वाली पीठ तक ले जाता है। झाग फिसलती जिस एक लकीर के सहारे, अकेले भी अपनी पीठ रगड़ने वाली अपनेपन भरी गर्माहट पूरे बाथरूम में गर्मजोशी से फैल जाती है।"},"ICON-0699":{"nm":"नाली छन्नी पैक","de":"पानी बहने देती और कचरा थाम लेती एक छोटी जाली। किसी की नज़र न पड़ने वाली जगह में चुपचाप रुकावट रोकती रहती है। सबसे नीची जगह पर काम करने वाली चीज़ें ही घर का बहाव सँभालती हैं, नाली बिना कुछ कहे यही बता देती है।"},"ICON-0700":{"nm":"सक्शन हुक बोर्ड","de":"एक कील ठोके बिना भी दीवार पर एक नई जगह बना देता है। दबाकर चिपकाओ और उखाड़ लो तो निशान तक नहीं रहता। बिना दाग़ छोड़े कुछ देर ठहरकर चले जाने की कला — सक्शन कप इस हल्के शिष्टाचार को अच्छी तरह जानता है।"},"ICON-0701":{"nm":"बाथरूम स्लिपर टैग","de":"दहलीज़ के आगे करीने से रखी एक जोड़ी। जूते उतारकर घर में प्रवेश करने की जो देखभाल है, वह सहेजते हुए बाथरूम के दरवाज़े तक पहुँचती है। ठंडी उँगलियों को गर्माहट देने वाले इस छोटे से स्वागत को, नामपट्टी चुपचाप उसकी जगह बताती रहती है।"},"ICON-0702":{"nm":"मिनी कुल्ला कप","de":"दाँत साफ़ करने के लिए एक घूँट पानी थामने वाला छोटा गोल प्याला। कुल्ला करने के उस संक्षिप्त पल में, यह दिन की शुरुआत और अंत को चुपचाप अपने भीतर समेट लेता है। दिखावटी नहीं, पर हर रोज़ साथ रहने वाला—सादगी ही सबसे लंबे समय तक चलने वाली गृहस्थी है।"},"ICON-0703":{"nm":"डस्टर स्लीव","de":"धूल को सहलाते हुए धीरे से समेट लेने वाले ब्रश के पंखों पर पहनाया गया एक आवरण। जैसे कोई पक्षी उड़ान में न होने पर अपने पंख धीरे से समेट लेता है, वैसे ही आराम की जगह जानने वाला औज़ार लंबे समय तक साथ बना रहता है।"},"ICON-0704":{"nm":"लिंट रोलर रिफिल","de":"एक परत उतारते ही उसके नीचे से एक नई, साफ़ सतह उग आती है। रोएँ और बालों को समेटने वाली चिपचिपी भीतरी परतें। इस्तेमाल होने के बाद फिर से भर जाने वाली गोल रिफिल में, मेहनती दोहराव का गुण लिपटा हुआ है।"},"ICON-0705":{"nm":"कपड़ा क्लैंप","de":"हाथ की जगह पोंछे को मज़बूती से दबोचने वाला यह क्लैंप। ठंडे फर्श और उँगलियों के बीच एक बालिश्त की दूरी बनाए रखता है। गंदा काम अपने ज़िम्मे लेने वाला यह एक हैंडल, मुश्किल सफाई को कहीं ज़्यादा हल्का बना देता है।"},"ICON-0706":{"nm":"कोना ब्रश कैप","de":"संकरी दरारों में घुसने के लिए बनी पतली ब्रिस्टल की नोक को सँभालने वाली छोटी टोपी। एक ऐसा मन जो हाथ न पहुँचें वहाँ के कोनों तक का भी ख़याल रखता है। अनदेखे कोनों को साफ़ करने वाला ही घर के आँचल को एक बालिश्त और बड़ा करता है।"},"ICON-0707":{"nm":"स्प्रे बॉटल लेबल रिंग","de":"स्प्रे बोतल के कंधे पर धीरे से चिपकी एक छोटी नामपट्टी। इसके भीतर साफ़ पानी है या डिटर्जेंट, यह एक ही पंक्ति में स्पष्ट बता देती है। पहले से ही उलझन मिटा देने वाला लेबल, फुर्तीली गृहिणी की पुरानी आदत है।"},"ICON-0708":{"nm":"टिशू रिफिल बैंड","de":"ख़त्म हुई जगह पर नया रोल फिट कर उसे कसकर बाँध देने वाली पट्टी। टूटे हुए को फिर से जोड़ने का सबसे सरल स्पर्श। ख़त्म होने से पहले ही भर देने वाले किसी के मन को, यह छोटा सा फंदा गोल-गोल लपेटे रहता है।"},"ICON-0709":{"nm":"सफाई दस्ताना हुक","de":"गीले काम के तुरंत बाद भीगे दस्तानों को टाँगकर सुखाने वाला हुक। मेहनत कर चुके हाथों को थोड़ी देर आराम की जगह देता है। नमी धीरे-धीरे सूखने के बीच, यह अगले काम के लिए धीरे-धीरे साँस समेटने का छोटा विश्राम है।"},"ICON-0710":{"nm":"झाड़ू हैंगर पिन","de":"झाड़ू को उल्टा टाँगकर रखने पर उसके बाल मुड़ते नहीं, सीधे बने रहते हैं। सीधा लटका हुआ अगले आँगन की प्रतीक्षा करने की मुद्रा। काम पूरा हो जाने के बाद भी अपना आकार बनाए रखने में मदद करने वाली, छोटी पर मज़बूत एक जगह।"},"ICON-0711":{"nm":"कूड़े की थैली क्लिप","de":"थैली का मुँह मज़बूती से दबोचकर, एक बूँद भी बाहर न रिसने देते हुए इसे कसकर बंद कर देता है। सिरे को ठीक से बाँधने का एक स्पर्श, सफाई को कहीं ज़्यादा नफ़ीस बना देता है। आख़िरकार, समापन हमेशा अच्छी तरह बंद करने से ही शुरू होता है।"},"ICON-0712":{"nm":"कपड़ा-पिन डिब्बा","de":"बिखर जाने पर आसानी से खो जाने वाली कपड़े की क्लिपों का साथ रहने वाला डिब्बा। छोटी चीज़ों को एक साझा घर देता है। उँगलियों के इन नन्हे सिपाहियों को एक जगह समेट देने पर, ज़रूरत पड़ने पर एक नज़र में ढूँढा जा सकता है।"},"ICON-0713":{"nm":"मोज़ा जोड़ी रिंग","de":"बिछड़ा हुआ मोज़ा हमेशा चुपके से कहीं गायब हो जाता है। धोने से पहले हर जोड़े को एक रिंग से बाँध दो, तो मुलायम सूखने के बाद भी दोनों जुदा नहीं होते। छाँटना, गुम होने के विरुद्ध पहले से किया गया एक छोटा वादा है।"},"ICON-0714":{"nm":"लॉन्ड्री बॉल पाउच","de":"वॉशिंग मशीन के भीतर लुढ़कते-लुढ़कते कपड़ों में बसी मैल को धीरे-धीरे थपथपाकर जगाता है। अपने गोल शरीर से कपड़ों को सहलाने वाली एक लय। तेज़ पानी की धार के बीच, थपथपाहट की—धुलाई की पुरानी सहज-प्रवृत्ति को एक थैली में लपेटे घुमाता है।"},"ICON-0715":{"nm":"वूल वॉश मेज़रिंग कैप","de":"नाज़ुक कपड़ों के लिए उतनी ही नाज़ुक मात्रा। वूल डिटर्जेंट को ठीक एक ढक्कन भर बारीकी से नापने वाली मेज़रिंग कैप। एक छोटे से निशान में ऊन को संभालने का सतर्क स्पर्श छिपा है। अतिरिक्त को कम करना भी एक तरह की देखभाल है।"},"ICON-0716":{"nm":"फैब्रिक मेंडिंग पैच","de":"घिसी हुई जगह पर धीरे से जोड़ा गया एक छोटा पैच। घिसे हुए हिस्से को यूँ ही फेंक देने की बजाय, उसे संभाल कर रखने वाले उँगलियों के मन। सिले हुए हर निशान में, उस कपड़े के साथ बीते बरसों का बुनावट सुंदरता से बचा रह जाता है।"},"ICON-0717":{"nm":"सुखाने की रैक पिन","de":"हवा में कपड़े उड़ न जाएँ, इसके लिए सुखाने की रैक को चुपचाप थामे रखने वाली पिन। धूप में कपड़े लहराने वाले दिनों में भी, हिलते-डुलते बीच अपनी जगह बनाए रखने में मदद करती है। छोटा पर भरोसेमंद एक वज़नी लंगर होने की ज़िम्मेदारी।"},"ICON-0718":{"nm":"अंडरवियर वॉश बैग टैग","de":"नाज़ुक अंतर्वस्त्र को जाल में अलग रखकर धोया जाता है। तेज़ पानी की धार से मुलायम चीज़ों को पूरी तरह से लपेटकर बचाने वाला जाल। नामपट्टी लगी एक छोटी थैली बताती है कि कमज़ोर चीज़ों की सावधानी से रक्षा करना भी गृहस्थी का ही हिस्सा है।"},"ICON-0719":{"nm":"डिटर्जेंट स्कूप हुक","de":"पाउडर डिटर्जेंट भरने वाले चम्मच को दीवार पर करीने से टाँग दो। डिब्बे में गिराकर हाथ भिगोने की झंझट अब नहीं। एक ही जगह एक ही औज़ार रखने की सुघड़ आदत, इस छोटे हुक में मज़बूती से समाई है।"},"ICON-0720":{"nm":"वॉशिंग लाइन स्टॉपर","de":"कपड़े की रस्सी के सिरे को कसकर दबोचकर, भारी कपड़े लदे होने पर भी उसे फिसलने नहीं देता। तनी हुई एक डोर को झुकने से बचाते हुए आख़िर तक टिके रहने वाली आख़िरी गाँठ। एक मज़बूत समापन इसी पर टिका है।"},"ICON-0721":{"nm":"तकिया कवर लेबल","de":"हर रात गाल सबसे पहले जिस जगह छूता है, उसके भीतर सिली हुई नाख़ून जितनी छोटी नामपट्टी। धुलाई का तापमान लिखा वह बारीक अक्षर भला कौन पूरा पढ़ता है? फिर भी, सोए हुए चेहरे के पास पहरा देने वाला यह सबसे नज़दीकी मार्गदर्शन है।"},"ICON-0722":{"nm":"कंबल क्लिप","de":"खिड़की खुली रात में, हवा अंदर आए तब भी रज़ाई भागकर नहीं जाती। क्योंकि मुँह कसकर बंद किए क्लिप ने कोना पकड़ रखा है। सोए हुए इंसान की जगह किनारा थामे रहने वाला, यह एक ख़ामोश हाथ है।"},"ICON-0723":{"nm":"नाइट लाइट शेड बोर्ड","de":"\"रोशनी आँखों तक पहुँचे तो नींद दूर भाग जाती है।\" किसी ने चुपके से खड़ा किया एक शेड बोर्ड, जिससे रोशनी पीछे हट जाती है और बिस्तर के पैताने को ही धुँधला भिगोती है। अंधेरे का एक बालिश्त उधार देने वाली छोटी आड़।"},"ICON-0724":{"nm":"बेडसाइड गैप पॉकेट","de":"गद्दे और दीवार के बीच, हाथ न पहुँच पाने वाली उस दरार को याद करो। लुढ़ककर गिरा रिमोट भी, चश्मा भी, अब यहीं आकर जमा होते हैं। खोने ही वाली चीज़ों को थामने के लिए बिस्तर ने चुपके से खोली यह जेब।"},"ICON-0725":{"nm":"चश्मा रखने की ट्रे","de":"लेंस उतारते ही दुनिया धीरे से धुँधली हो जाती है, और उस पल भर की लाचारी को एक छिछली तश्तरी थाम लेती है। सुबह होते ही, उँगलियों के टटोले बिना भी, चश्मा हमेशा उसी जगह पर इंतज़ार करता मिलता है।"},"ICON-0726":{"nm":"अलार्म क्लॉक स्टैंड","de":"सुबह छह बजे, सबसे नापसंद आवाज़ जिस मज़बूत आधार पर गूँजती है। बिना हिले-डुले घड़ी को थामे रखकर, आख़िरकार किसी का दिन खोल देता है। जागने के इस नीरस वादे को यह चुपचाप अपने कंधों पर उठाए रखता है।"},"ICON-0727":{"nm":"बेडसाइड केबल होल्डर","de":"सिरहाने से नीचे लटकती चार्जिंग केबल अब फर्श पर नहीं गिरती। क्योंकि छोटा होल्डर तार के सिरे को धीरे से थामे रखता है। हाथ बढ़ाते ही मिल जाने वाली दूरी—रात की चाल को व्यवस्थित करने वाला एक स्पर्श।"},"ICON-0728":{"nm":"पजामा स्टोरेज बैंड","de":"करीने से तह किए नाइटसूट को एक चक्कर लपेटकर बाँध देने वाली पट्टी। आसानी से बिगड़ जाने वाली नरमाहट को भी करीना चाहिए। कल रात की अपनी ख़ातिर, आज का अपना उन्हें सलीके से लपेट रखने की एक छोटी तैयारी।"},"ICON-0729":{"nm":"सुगंध कार्ड होल्डर","de":"सुगंध बसे एक कार्ड को तिरछा टिका दो, तो जैसे पन्ना पलटते हुए नाक से मौसम पलटता है। लैवेंडर से सिट्रस तक—यह ख़ुशबू में लिखी उस दिन की एक डायरी बन जाती है।"},"ICON-0730":{"nm":"चाबी की तश्तरी पैड","de":"दरवाज़े के एक कोने में, जहाँ चाबियाँ खनखनाकर गिरा करती थीं। मुलायम पैड बिछी तश्तरी अब उस तीखी आवाज़ को निगल लेती है। घर लौटे इंसान की पहली हरकत को, यह छोटा आधार चुपचाप थाम लेता है।"},"ICON-0731":{"nm":"छाता ड्रिप कैप","de":"साथ लाए छाते की नोक से बारिश का पानी टपकता रहता है। एक कैप उस टपकन को करीने से समेट लेती है, मानो किसी ने पहले से ही सोचकर फर्श पर धीरे-धीरे फैलने वाले उस छोटे गड्ढे को रोक दिया हो।"},"ICON-0732":{"nm":"मास्क हुक चिप","de":"दरवाज़े के पास दीवार पर लगी नाख़ून जितनी छोटी चिप। बाहर निकलने की आख़िरी रस्म की तरह, मास्क यहीं टँगता है। साथ ले जाना न भूलें, इसके लिए दरवाज़े पर आँखों की ऊँचाई थामे रखने वाला एक छोटा याद-यंत्र।"},"ICON-0733":{"nm":"पार्सल कटर शीथ कवर","de":"पार्सल के डिब्बे चीरने वाले ब्लेड पर पहनाया गया सुरक्षा कवर। खोलने की उत्तेजना के पीछे छिपे कट लगने के जोखिम को चुपचाप ढँक देता है। इंतज़ार के अंत को सुरक्षित ढंग से खोलने वाली, नज़र न आने वाली एक सोच।"},"ICON-0734":{"nm":"जूता ब्रश स्टैंड","de":"पॉलिश के बाद गीला ही रखा हुआ जूता ब्रश जहाँ टिकता है। नमी सोखने पर भी फर्श सूखा-साफ़ बना रहता है। सफ़ाई करने वाले औज़ार को भी आराम की जगह चाहिए, यह छोटा आधार धीरे से बताता है।"},"ICON-0735":{"nm":"विज़िटर मेमो बोर्ड","de":"\"बस थोड़ी देर के लिए आया था।\" दरवाज़े के मेमो बोर्ड पर छूटी एक छोटी सी पंक्ति। एक-दूसरे से चूक गए लोगों के लिए समय के आर-पार बातें बाँटने का एक छोटा चौक। काग़ज़ के एक कोने पर हाल-चाल, गुज़ारिश और एक दिल एक के ऊपर एक जमा होते जाते हैं।"},"ICON-0736":{"nm":"दरवाज़ा ड्राफ्ट स्टॉपर रोल","de":"दरवाज़े के नीचे उँगली जितनी दरार से रिसती ठंडी हवा। लपेटा हुआ स्टॉपर उस रास्ते को चुपचाप रोक देता है। बिना दिखे बाहर बहती जा रही गर्माहट को, यह कमरे में एक परत और थाम लेता है।"},"ICON-0737":{"nm":"डोर स्टॉपर चार्म","de":"पूरी तरह खुला दरवाज़ा फिर से बंद न हो जाए, इसके लिए उसका पैताना थामे रखने वाला एक छोटा चार्म। आते-जाते हवा और पदचाप के लिए भारीपन से अपनी जगह टिकाए रखता है। दरवाज़े को खुला बनाए रखने वाली, एक स्नेहिल ज़िद।"},"ICON-0738":{"nm":"दरवाज़े की लाइट स्विच कवर","de":"देर रात टटोलते हुए ढूँढा जाने वाला दरवाज़े का स्विच। अंधेरे में एक चमकने वाला कवर धीरे से अपनी जगह की सूचना देता है। हाथ भटके नहीं, इसके लिए रोशनी जलने से पहले ही चमकने वाला एक छोटा मार्गदर्शक।"},"ICON-0739":{"nm":"कप होल्डर पैड","de":"मेज़ पर रखे कप के फिसलने लगते ही, एक पैड उसका पैर धीरे से थाम लेती है। पानी की बूँदें जमने पर भी एक निशान तक न छोड़ने वाला, शांति से अपनी जगह बनाए रखने वाला आधार।"},"ICON-0740":{"nm":"कार सुगंध क्लिप","de":"गाड़ी के भीतर लटकी एक छोटी सुगंध क्लिप। वेंट की हवा पर सवार होकर, हल्की महक धीरे-धीरे उस तंग जगह को भर देती है। लाल बत्ती पर इंतज़ार की बोरियत को भी ख़ुशबू से गर्माने वाला, ड्राइवर की सीट का एक स्नेहिल सुकून।"},"ICON-0741":{"nm":"सीटबेल्ट कवर","de":"कंधे को पार करती बेल्ट पर पहनाया गया मुलायम कवर। गर्दन को छूती वह खुरदुरी अनुभूति धीरे से मिट जाती है। सुरक्षा के लिए बनी एक पट्टी में भी स्नेह जोड़ा जा सकता है, यह एक बालिश्त कपड़ा बता देता है।"},"ICON-0742":{"nm":"पार्किंग नंबर कवर बोर्ड","de":"भूतल पार्किंग में अपनी जगह बताने वाले नंबर को, फोटो लेने से पहले चुपके से ढँक देने वाला बोर्ड। हर किसी के पास ऐसी जानकारी होती है जो वह पीछे नहीं छोड़ना चाहता। रोज़मर्रा के एक दृश्य से सावधानी से मिटाई गई एक परत।"},"ICON-0743":{"nm":"साइकिल घंटी कैप","de":"टन-टन। गली के मोड़ पर साइकिल का भेजा हुआ स्वच्छ अभिवादन। घंटी पर पहनाया गया कैप बारिश में भी उस आवाज़ को बचाए रखता है। एक छोटी घंटी की टुनटुन पर लोग मुस्कुराकर एक कदम राह छोड़ देते हैं।"},"ICON-0744":{"nm":"हैंडलबार ग्रिप रिंग","de":"हथेली को छूने वाले हैंडल की बनावट को मुलायमी से लपेटने वाली रिंग। देर तक थामे दौड़ने पर भी हाथ सुन्न नहीं पड़ते। जितना दूर का रास्ता हो, उतना ही थामने की जगह का आराम उस दूरी को छोटा कर देता है।"},"ICON-0745":{"nm":"हेलमेट लेबल स्टिकर","de":"हेलमेट के भीतरी हिस्से पर चिपकाया गया नाम का स्टिकर। एक जैसे दिखने वाले सुरक्षा हेलमेटों के बीच धीमे से पुकारता है, \"यह मेरा है।\" सिर की रक्षा करने वाली मज़बूती पर उकेरा गया, सबसे निजी एक निशान।"},"ICON-0746":{"nm":"व्हील रिफ्लेक्टर कैप","de":"सूरज ढलते ही जिसका असली काम शुरू होता है, वह है यह कैप। गुज़रती रोशनी को पकड़कर पहिये को साफ़ चमका देता है। अंधेरे में \"यहाँ कोई है\" कहकर रोशनी से भेजा गया एक छोटा संकेत।"},"ICON-0747":{"nm":"कार की चाबी का पाउच","de":"जेब में दूसरी चाबियों से टकराकर खरोंचें खाती रही कार की चाबी। मुलायम पाउच उस सतह को पूरी तरह लपेट लेता है। रोज़ थामी जाने वाली चीज़ बिना खरोंच लंबे समय टिकी रहे, यही चाहत इसमें समाई है।"},"ICON-0748":{"nm":"सक्शन शेल्फ पिन","de":"एक भी कील ठोके बिना दीवार से चिपक जाने वाली सक्शन शेल्फ पिन। निशान न छोड़ना चाहने वाली दीवार पर भी सामान रखने का एक ख़ाना बन जाता है। कुछ समय के लिए ठहरे कमरे में गृहस्थी टाँगने का, बिना निशान वाला हुनर।"},"ICON-0749":{"nm":"नो-ड्रिल हुक बोर्ड","de":"दीवार में छेद किए बिना भी कुछ टाँगा जा सकता है, यह सोचकर ही अच्छा लगता है। बिना छेद वाला हुक बोर्ड हल्का सामान चुपचाप अपने ज़िम्मे ले लेता है। उधार ली गई जगह को नुक़सान न पहुँचाने की चाहत, एक छोटी सी हुक में सुंदरता से समाई है।"},"ICON-0750":{"nm":"मैग्नेटिक ऑर्गनाइज़र बार","de":"धातु के अपनी जगह पर टक से चिपकने की आवाज़। चारों ओर बिखरे छोटे औज़ारों को चुंबक से खींचकर समेट लो, तो अस्त-व्यस्त कार्य-मेज़ एक पंक्ति में करीने से सज जाने का छोटा सा सुख साथ चला आता है।"},"ICON-0751":{"nm":"गैप-फिलर रॉड","de":"फ्रिज और दीवार के बीच, छोड़ी हुई उस संकरी दरार को याद करो। एक पतली छड़ उस बीच की जगह को उपयोगिता से भर देती है। बेकार समझी गई जगह से भंडारण खींच निकालने वाली, एक मितव्ययी सोच।"},"ICON-0752":{"nm":"एडहेसिव पैड शीट","de":"एक बार चिपका दो तो भारी चीज़ को भी आराम से थाम लेने वाली एक चिपकने वाली पैड शीट। उतारो तो हैरानी से एक भी निशान नहीं बचता। नज़र से ओझल जगह पर वज़न सहने वाली, एक शांत और हठी ताक़त।"},"ICON-0753":{"nm":"ओवर-डोर हुक कैप","de":"दरवाज़े के ऊपर बस हल्के से टिकाना काफ़ी है, ऐसा हुक कैप। बैग हो या तौलिया, हाथ की पहुँच में ही टँगे रहते हैं। एक भी कील ठोके बिना जन्मा यह हैंगर, तंग कमरे में एक ख़ाना और साँस लेने की जगह जोड़ देता है।"},"ICON-0754":{"nm":"केबल वॉल क्लिप","de":"दीवार पर लटकती तारों को एक पंक्ति में थामे रखने वाली क्लिप। मेज़ के पीछे उलझा धागों का जाल एक साफ़ लकीर में सुलझ जाता है। दिखाई न देने वाली यह करीनेबंदी, कमरे की हवा तक को हल्का बना देती है।"},"ICON-0755":{"nm":"लैंप बेस पैड","de":"स्टैंड लैंप के पाँव के नीचे धीरे से बिछाई गई एक पैड। मेज़ पर खरोंच का निशान नहीं छोड़ती, और हल्की सी कँपकँपी तक को शांत कर देती है। रोशनी खड़ी करने के काम में भी, न हिलने वाला फर्श पहले ज़रूरी है।"},"ICON-0756":{"nm":"एंटी-स्लिप एडहेसिव प्लेट","de":"पैरों तले चुपके से सरकती रहने वाली चटाई आख़िरकार अपनी जगह थम जाती है, क्योंकि चिपकने वाली प्लेट फर्श को कसकर पकड़ लेती है। गिरते-गिरते बचने वाले पल को पहले ही हटा देने वाला, नज़र न आने वाला एक सुरक्षा-जाल।"},"ICON-0757":{"nm":"प्रिसिज़न ड्राइवर कैप","de":"\"यह इतना छोटा सा पेंच खुल ही नहीं रहा।\" सटीक स्क्रूड्राइवर की नोक पर पहनाया कैप उसकी धार बचाए रखता है। हथेली जितनी मशीन के भीतर की दुनिया खोलने वाला, उँगलियों का सबसे नाज़ुक औज़ार।"},"ICON-0758":{"nm":"हेक्स रेंच रिंग","de":"कई हेक्स रेंचों को एक ही छल्ले में पिरोकर बाँध देने वाली रिंग। आकार के अनुसार पंक्तिबद्ध धातु पंखे की तरह खुलकर फैल जाती है। ज़रूरत की उस एक छड़ को एक ही झटके में चुन लेने वाली, हाथ की सुव्यवस्थित लय।"},"ICON-0759":{"nm":"मिनी टेप मेज़र चार्म","de":"हथेली में समा जाने वाले मिनी टेप मेज़र से जुड़ा एक छल्ला। चाबी के छल्ले में लटककर हर जगह साथ चला आता है। अचानक जागी जिज्ञासा की लंबाई को, ठीक वहीं नापकर जवाब देने वाला एक छोटा दोस्त।"},"ICON-0760":{"nm":"स्क्रू सॉर्टिंग बॉक्स","de":"तरह-तरह के पेंच अपने-अपने ख़ाने में जगह पा लेते हैं, ऐसा एक छँटाई डिब्बा। घुल-मिलकर लुढ़कते रहने वाले छोटे पुर्ज़ों में भी एक व्यवस्था बन जाती है। कुछ ठीक करने से पहले, पहले करीना सीखने वाला एक हाथ।"},"ICON-0761":{"nm":"ग्लू नोज़ल कैप","de":"बंद रखो तो जमूँगा नहीं, खुला छोड़ो तो सूख जाऊँगा—मैं इसी बीच के फ़ासले में जीता हूँ। हर गिरती बूँद के साथ, कहीं न कहीं कोई टूटी चीज़ फिर से जुड़ रही होती है। एक छोटा ढक्कन ठहराव और बहाव की सीमा-रेखा को चुपचाप थामे रखता है।"},"ICON-0762":{"nm":"लेवल कीरिंग","de":"चाबियों के गुच्छे के सिरे पर लटकती हथेली जितनी ईमानदारी। झुकी हुई अलमारी को सबसे पहले भाँप लेने वाला हमेशा यही छोटा बुलबुला होता है। दुनिया थोड़ी टेढ़ी हो गई है, यह चुपचाप बताने वाले दोस्त को मैं जेब में लिए घूमता हूँ।"},"ICON-0763":{"nm":"चिमटी टिप कैप","de":"जो चीज़ जितनी नुकीली होती है, उसे उतने ही ज़्यादा एक कपड़े की ज़रूरत होती है। नोक को धीरे से ढँक दो, तो न हाथ चोटिल होते हैं, न पुर्ज़े। तीखेपन को संभालने का पहला शिष्टाचार उसकी नोक को धीरे से ढँकना है—यह छोटी कैप वही स्नेह निभाती है।"},"ICON-0764":{"nm":"छोटी कटिंग मैट","de":"हज़ारों बार ब्लेड गुज़रने पर भी जिसके घाव खुद-ब-खुद भर जाते हैं, ऐसा एक तख़्ता। कटे हुए स्थान पर अगला काम फिर से रखा जाता है, और वह फिर भर जाता है। दूसरी चीज़ों को सुंदरता से कट जाने देने के लिए अपना शरीर देने वाले फर्श का, एक ख़ामोश दिन।"},"ICON-0765":{"nm":"रिपेयर पार्ट्स पाउच","de":"एक पेंच, एक स्प्रिंग हमेशा के लिए ग़ायब न हो, इसके लिए मुँह भींचकर रखने वाली थैली। मरम्मत के बाद बचे नन्हे-नन्हे टुकड़े यहीं चुपचाप अपनी अगली बारी का इंतज़ार करते हैं। किसी चीज़ को खोने से रोकना हमेशा ऐसे ही मामूली ख़ानों का काम होता है।"},"ICON-0766":{"nm":"नाश्ते की थैली क्लिप","de":"खुली थैली की कुरकुरेपन को बचाना, आख़िरकार एक निर्णायक चुटकी पर ही निर्भर करता है। सीलन आने का कोई मौका न देने का एक छोटा वादा। सिरे को कसकर दबोच देने की यह आदत कल के नाश्ते को बचा लेती है।"},"ICON-0767":{"nm":"जेली पोर्शन कप","de":"एक थैली को कई लोगों में बाँटना हो, तो पहले उसे बराबर से बाँटना पड़ता है। हर छोटे कप में समान हिस्सा भर देने वाला मन। बाँटना, मेरी मान्यता है, हमेशा एक जैसी मात्रा से शुरू होता है, ताकि किसी को बुरा न लगे।"},"ICON-0768":{"nm":"चॉकलेट फॉइल टुकड़ा","de":"मिठास लपेटे रखने वाली चाँदी सी परत उँगलियों के बीच आसानी से सिकुड़ जाती है। सीधा करो तो पल भर चमकती है, मोड़ो तो एक याद बन जाती है। पूरा खा लेने के बाद ही सबसे सुंदर बनने वाला यह रोशनी का एक टुकड़ा—फेंकने से पहले एक बार और देख लो।"},"ICON-0769":{"nm":"स्नैक लेबल स्ट्रिप","de":"भीतर क्या है, कब तक अच्छा रहेगा—ख़ामोश थैली की जगह मैं बोलकर बताती हूँ। एक पट्टी चिपकते ही नाश्ते को भी नाम और वादा मिल जाता है। छाँटना, सच कहूँ तो, याद रखने का सबसे स्नेहिल तरीक़ा है।"},"ICON-0770":{"nm":"कैंडी सॉर्टिंग बॉक्स","de":"खट्टी और मीठी चीज़ों को एक ही ख़ाने में मत रखो। हाथ हिचकिचाए नहीं, इसके लिए पहले से ही बाँट देने का काम। छोटे-छोटे डिब्बे पंक्ति में सज जाएँ तो, चुनने का सुख चुपके से दोगुना हो जाता है।"},"ICON-0771":{"nm":"कुकी कुशन पेपर","de":"कुकी को राह में चोट न लगे, इसके लिए बीच-बीच में रखा गया पतला काग़ज़। जितनी नाज़ुक चीज़ हो, उतना ही मुलायम साथ चाहिए। कभी-कभी मज़बूती से ज़्यादा नरमाहट ही बेहतर सुरक्षा देती है।"},"ICON-0772":{"nm":"डोनट बॉक्स स्ट्रिंग","de":"क्रॉस बाँधी एक गाँठ डिब्बे के भीतर केक की सलामती की ज़िम्मेदारी उठाती है। हैंडल बनती है, मुहर बनती है, और बेसब्र इंतज़ार की एक निशानी भी। इस धागे के खुलने का पल ही किसी के जन्मदिन का पल होता है।"},"ICON-0773":{"nm":"ब्रेड बैग टाई","de":"एक बार मरोड़कर मोड़ो और मुझे लगा दो, तो ब्रेड की नरमाहट कल सुबह तक सुरक्षित रहती है। हवा को रोकने वाली एक छोटी, हठी ज़िद। किसी नरम चीज़ को लंबे समय बचाना हमेशा किसी मज़बूत चीज़ का ही काम होता है।"},"ICON-0774":{"nm":"स्नैक स्वैप टैग","de":"तुम्हारा हिस्सा मुझे, मेरा हिस्सा तुम्हें। छोटे टैग पर नाम लिखकर नाश्ता बदलने वाले उस दिन की खुशी, याद है? बाँटकर खाने के मन पर चिपकने वाले काग़ज़ पर हमेशा किसी दोस्त का नाम साफ़-साफ़ लिखा होता है।"},"ICON-0775":{"nm":"स्ट्रॉ स्टॉपर कैप","de":"एक घूँट के बाद थोड़ी देर रुकना हो तो मुझे बंद कर दो। न कुछ गिरे, न ठंडा हो, वहीं चुपचाप इंतज़ार करता रहे। होंठ फिर से छूने वाले उस पल के लिए मुँह को पहरा देने वाली, एक छोटी टोपी का काम।"},"ICON-0776":{"nm":"टंबलर नेम रिंग","de":"कतार में खड़े कई टंबलरों के बीच 'यह मेरा है' बताने वाली एक छोटी रिंग। एक रंग भर से मिलावट धीरे से सुलझ जाती है। अपनी चीज़ का निशान बताने के लिए बस यह एक रिंग ही काफ़ी और स्पष्ट है।"},"ICON-0777":{"nm":"कप होल्डर स्लीव","de":"गरम कप और हथेली के बीच चुपके से आ बैठने वाली नालीदार काग़ज़ की एक परत। जलने न दे, फिसलने न दे, इसी ख़याल से जोड़ी गई एक तवज्जो। बीच की जगह की रक्षा करना ही एक सलामत घूँट को पूरा करता है।"},"ICON-0778":{"nm":"आइस ट्रे लेबल","de":"कोई है जो हर बर्फ़ बनाने की तारीख़ लिखकर रखता है, इस विश्वास के साथ कि ठंडक में भी एक क्रम होना चाहिए। एक छोटी लेबल फ्रीज़र के समय को ईमानदारी से, एक के बाद एक क्रम में बहने देती है।"},"ICON-0779":{"nm":"टी बैग टॉन्ग्स","de":"घुलने का समय देखते रहकर, ठीक सही पल पर उसे बाहर निकाल लेती है। बहुत गाढ़ा होने से पहले रुक जाना जानने वाला हाथ का हुनर। चाय की गहराई भिगोने के समय से ज़्यादा, निकालने का सही पल तय करता है।"},"ICON-0780":{"nm":"ड्रिप फिल्टर स्टैंड","de":"गरम पानी धीरे-धीरे नीचे उतर सके, इसके लिए फिल्टर को थामे ख़ामोश खड़ा रहता है। जल्दबाज़ी करने पर ख़ुशबू हल्की पड़ जाती है, यह अच्छी तरह जानता है। इंतज़ार को सहारा देने के काम में भी, न डगमगाने वाला रुख़ ज़रूरी है।"},"ICON-0781":{"nm":"बॉटल स्ट्रैप","de":"पानी की बोतल को कलाई या कंधे पर लटकाकर साथ चलने वाली पट्टी। जान-बूझकर उठाए बिना भी हमेशा पास रखने का एक साथी-भाव। न भूलने के लिए हल्के से बाँध लेना ही, कभी-कभी सबसे स्नेहिल तरीक़ा होता है।"},"ICON-0782":{"nm":"कैन लिड कवर","de":"आधी पी हुई कैन का मुँह ढँककर धूल और गैस उड़ने से रोकता है। अगले घूँट तक ताज़गी बनाए रखने की ज़िम्मेदारी उठाने वाली एक छोटी टोपी। थोड़ी देर के लिए खुली चीज़ को चुपचाप ढँक देने में भी देखभाल छिपी है।"},"ICON-0783":{"nm":"ड्रिंक कूपन होल्डर","de":"दसवाँ मुफ़्त कप—वह वादा न खोए, इसके लिए स्टैम्प कार्ड को अपने भीतर सँभाले रखता है। एक-एक ख़ाना भरते गए दिन कुचले न जाएँ, इसी ख़याल से। इस होल्डर के भीतर किसी नियमित ग्राहक के मेहनती क़दमों का हिसाब जमा होता है।"},"ICON-0784":{"nm":"लंचबॉक्स बैंड","de":"ढक्कन खुल न जाए, इसके लिए लंचबॉक्स को एक चक्कर कसकर गले लगाने वाली पट्टी। बैग के भीतर शोरबा न रिसे, ऐसी एक छोटी सी तसल्ली। दोपहर तक की सलामती, इसी कसी हुई एक फेरी की ज़िम्मेदारी है।"},"ICON-0785":{"nm":"साइड-डिश कप सेट","de":"हर व्यंजन को अपनी जगह मिले तो स्वाद आपस में नहीं मिलते। किमची किमची जैसी, साग साग जैसा, हर एक अलग-अलग साफ़। छोटे कपों से बना यह बँटवारा ही लंचबॉक्स की व्यवस्था है, और हाथ के स्वाद पर एक स्नेह की परत भी।"},"ICON-0786":{"nm":"चॉपस्टिक केस","de":"दिन के तीनों वक़्त साथ रहीं चॉपस्टिक्स को साफ़-सुथरा समेटकर ले जाने वाला एक छोटा घर। स्कूल बैग के भीतर भी अपना करीना बनाए रखने वाला एक ख़ामोश साथी। साथ ले जाने की यह देखभाल ही, आख़िर में एक सुघड़ भोजन बना देती है।"},"ICON-0787":{"nm":"सॉस बॉटल लेबल","de":"सोया सॉस है या सिरका, उलझन देने वाली बोतल को यह स्पष्टता का लबादा पहनाता है। एक पंक्ति चिपकते ही उँगलियों की झिझक ग़ायब हो जाती है। व्यस्त रसोई की रफ़्तार ऐसे ही छोटे निशानों से चुपचाप बनती है।"},"ICON-0788":{"nm":"गिमबैप रोलिंग शीट","de":"चावल और भरावन को एक शरीर बनाकर लपेट देने वाली पतली सी सीवीड की चादर। काटते समय बिखरे न, इसके लिए इसे मज़बूती से लपेटना ज़रूरी है। पिकनिक की सुबह की खुशी इसी एक परत से गोल-गोल लिपटकर बाहर आती है।"},"ICON-0789":{"nm":"पिक होल्डर कप","de":"सींक और टूथपिक को एक जगह खड़ा रख दो, तो ज़रूरत के वक़्त हाथ भटकते नहीं। नुकीली चीज़ों को भी अपना एक तय घर देने का काम। तरतीब देना, आख़िरकार, अगले हाथ के लिए किया गया एक छोटा सा उपकार है।"},"ICON-0790":{"nm":"आइस पैक कवर","de":"ठंडक को थोड़ी देर और थामे रखने के लिए आइस पैक को एक परत और लपेट देता है। ओस जमने से बैग गीला न हो, इसका भी ख़याल साथ में। ठंडक को आख़िर तक बचाए रखना हमेशा इसी मोटी परत का काम होता है।"},"ICON-0791":{"nm":"लंचबॉक्स डिवाइडर","de":"चावल और साइड डिश एक-दूसरे की जगह न लाँघें, इसके लिए खड़ी की गई एक छोटी दीवार। शोरबा इधर-उधर न बहे, ऐसे एक ख़ाने की शांति। ख़ानों में बँटा लंचबॉक्स, बनाने वाले के बारीक मन को पूरी तरह अपने भीतर सँजोए रखता है।"},"ICON-0792":{"nm":"मील ऑर्डर कार्ड","de":"शोरबा पहले या चावल पहले, आज के क्रम को धीरे से बताने वाला कार्ड। क्रम से खाने पर स्वाद और बढ़ जाता है, यह एक स्नेहिल सलाह है। हर भोजन में भी किसी कहानी जैसा एक बहाव होता है, यह चुपचाप बता देता है।"},"ICON-0793":{"nm":"मेज़रिंग कप स्टिकर","de":"निशान के पास चिपका एक छोटा स्टिकर 'यहाँ तक' कहकर ठीक जगह दिखा देता है। हर बार उलझन में डालने वाली मात्रा को एक ही झटके में सही कर देने वाला निशान। सटीकता, यूँ ही एक छोटी सी दिशा-रेखा से शुरू होती है।"},"ICON-0794":{"nm":"सिलिकॉन लिड हैंडल","de":"गरम ढक्कन को उँगलियाँ जलाए बिना उठाने देने वाला एक छोटा हैंडल। भाप उठते बर्तन को खोलने का हौसला चुपचाप उधार देता है। सुरक्षा हमेशा, पहले से थामने की जगह तैयार रखने से ही आती है।"},"ICON-0795":{"nm":"मिनी क्लिप हैंगर","de":"पोंछा हो या थैली, टाँगने की जगह न रखने वाली चीज़ों को जगह देने वाली एक छोटी क्लिप। बिखरी दीवार के एक कोने को करीने से सजे दृश्य में बदल देती है। टाँगकर रखने की एक आदत रसोई को कहीं ज़्यादा हल्का बना देती है।"},"ICON-0796":{"nm":"ऑइल ब्रश कैप","de":"तेल लगाने वाले ब्रश की नोक को ढँक दो, तो धूल भी और जमना भी टल जाता है। अगली रसोई तक उस मुलायमी को बचाए रखने वाली एक टोपी। औज़ार की छोटी सी देखभाल, आख़िरकार स्वाद को लंबे समय तक बचाए रखती है।"},"ICON-0797":{"nm":"सॉल्ट स्पून पॉट","de":"नमक के डिब्बे में टिककर बसा एक छोटा चम्मच। एक चुटकी की सटीकता को हर बार सलीके से उठाकर देता है। स्वाद ठीक करने का हाथ का हुनर, यह छोटा चम्मच जितना याद रखता है, उतना ही मन है।"},"ICON-0798":{"nm":"टाइमर मैग्नेट बोर्ड","de":"फ्रिज के दरवाज़े पर चिपककर नूडल के 3 मिनट गिनता है, कसरत के 30 सेकंड नापता है। एक चुंबक से बहता समय आँखों के सामने ठहर जाता है। बीतते जा रहे पल को थोड़ी देर के लिए दीवार पर टाँके रखने वाला, एक मेहनती छल्ला।"},"ICON-0799":{"nm":"पॉट हैंडल कवर","de":"गर्म हो चुके हैंडल को नंगे हाथ न पकड़ना पड़े, इसके लिए लपेटी गई एक परत। गर्मी और हथेली के बीच खड़ी एक छोटी ढाल। बर्तन को सलामती से उठाना हमेशा, इसी मुलायम लपेट से शुरू होता है।"},"ICON-0800":{"nm":"कटिंग बोर्ड ग्रिप रबर","de":"मुझे नीचे बिछा दो तो चॉपिंग बोर्ड फिर फिसलता नहीं। चाकू चलाते वक़्त डगमगाहट होने पर नीचे से थामे रखने वाला रबर का एक टुकड़ा। स्थिरता, नज़र न आने वाली जगह पर मज़बूती से दबोचने का ही काम है।"},"ICON-0801":{"nm":"रसोई दस्ताना क्लिप","de":"आग के सामने बिना रुके चलते रहने वाले हाथ के थोड़ी देर ठहरने की जगह। फड़फड़ाते दस्ताने को दीवार पर टिका दो, तो अगले भोजन तक की छोटी सी साँस मिल जाती है। सफ़ाई आख़िर में स्नेह का ही दूसरा नाम है।"},"ICON-0802":{"nm":"कॉफ़ी स्टिक होल्डर","de":"काउंटर के पास, पतली छड़ियाँ कंधे से कंधा मिलाकर करीने से खड़ी रहती हैं। किसी की सुबह वाली प्याली में गोला बनाने को तैयार, कतार में खड़ी ये मानो गाना शुरू करने से ठीक पहले का कोई गायक-मंडल हों।"},"ICON-0803":{"nm":"कोस्टर सेट बैंड","de":"प्याली के मेज़ से टकराने की उस छोटी सी खनक को धीरे से थाम लेने वाली पट्टी। गोल कोस्टरों को एक साथ बाँध दो, तो मेहमान का स्वागत तैयार हो जाता है। आतिथ्य हमेशा ऐसी ही छोटी जगहों से पहले शुरू होता है।"},"ICON-0804":{"nm":"सिरप लेबल चिप","de":"बोतल पर चिपका एक नाम। मीठा, गाढ़ा—यह छोटा सा शब्द ही व्यस्त सुबह को थोड़ा और सुव्यवस्थित कर देता है। लेबल दरअसल एक छोटा सा वादा पहले से लिख रखने का कागज़ है।"},"ICON-0805":{"nm":"डेज़र्ट पिक पॉट","de":"फल के एक टुकड़े को चुभोकर उठाने वाली नुकीली छड़ियाँ जिस डिब्बे में साथ रहती हैं। डेज़र्ट की थाली पर झंडे की तरह गड़ने से पहले, यहाँ चुपचाप अपनी बारी का इंतज़ार करती हैं। मिठास में भी एक तरतीब होती है।"},"ICON-0806":{"nm":"मडलर स्लीव","de":"हिलाने वाली छड़ियों की मुट्ठी को गले से लगाकर लिपटा कागज़ी अंगरखा। ठंडे पेय से रिसती नमी को खुद सोख लेता है, और गिलास थामी उंगलियों को सूखा रखता है। अनदेखी परवाह हमेशा किनारों से आती है।"},"ICON-0807":{"nm":"टेकआउट कैरियर टैग","de":"जब दो हाथ भी कम पड़ जाएँ, तब कपों को थाम लेने वाला छोटा सा हैंडल। पैक की गई गर्माहट की एक बूँद भी न गिरने देकर, वह गर्माहट किसी की गली के मोड़ तक साथ छोड़ आता है।"},"ICON-0808":{"nm":"कैफ़े बज़र कवर","de":"बज़र बजने तक के इंतज़ार को चुपचाप लपेटे रखने वाला आवरण। कैफ़े के एक कोने में चमकती अपनी बारी की पर्ची की रखवाली करते हुए, यह जल्द ही अपना नंबर पुकारे जाने की उस सिहरन को भी साथ समेटे रखता है।"},"ICON-0809":{"nm":"स्टैंप कूपन रिंग","de":"दस खाने भर जाएँ तो एक प्याली मुफ़्त मिलने वाला कागज़। हर बार एक मुहर बढ़ने के साथ 'नियमित ग्राहक' का नाम भी थोड़ा-थोड़ा बढ़ता है। एक छोटी सी कड़ी में पिरोई, बेहद सादी सी खुशी।"},"ICON-0810":{"nm":"कॉफ़ी बीन सैंपल बैग","de":"एक मुट्ठी बीन्स को थामे, पहले ख़ुशबू ही थमा देने वाला थैला। नाक की नोक को छूती खटास और मिठास, वह पहला अहसास ही एक प्याली की तक़दीर तय कर देता है। ख़ुशबू किसी भी बयान से पहले पहुँच जाती है।"},"ICON-0811":{"nm":"फ्रिज लेबल मैग्नेट","de":"फ्रिज के दरवाज़े पर टक से चिपकने वाला छोटा चुंबकीय नामपट्ट। क्या कब आया, यह लिख दो तो भुला-सा दिया गया व्यंजन भी अपनी बारी वापस पा लेता है। घर-गृहस्थी दरअसल बहती याद को थाम कर बाँधने का काम है।"},"ICON-0812":{"nm":"स्टोरेज डेट चिप","de":"भरने का दिन साफ़ अंकित कर देने वाला एक टुकड़ा। कई दिन बीत जाने पर भी चुपचाप बता देने वाला छोटा गवाह कि यह अभी ठीक है। ताज़गी उस उंगली से बची रहती है जो तारीख़ याद रखती है।"},"ICON-0813":{"nm":"पोर्शन कंटेनर बैंड","de":"बाँट कर रखे डिब्बे की कमर को घेरे लिपटा बैंड। हिलते ढक्कन को मज़बूती से थाम कर फ्रिज के भीतर की छोटी सी तरतीब बचाए रखता है। किसी चीज़ को बाँधना दिल को सँवारने के काम जैसा ही लगता है।"},"ICON-0814":{"nm":"सील क्लिप रंग पट्टी","de":"थैले के मुँह को कसकर दबोचने वाली रंग-बिरंगी क्लिपें। लाल यानी तीखा, पीला यानी मीठा—रंग देखते ही हाथ पहले से जान जाता है। रसोई की ट्रैफ़िक लाइटें यूँ ही बिना कुछ कहे रास्ता दिखाती हैं।"},"ICON-0815":{"nm":"फ्रीज़र पैक नामपट्ट","de":"जमी हुई चीज़ के ऊपर धीरे से रखा नामपट्ट। पाले से ढके थैले को भी याद दिलाता रहता है कि वह क्या था। शीतनिद्रा में सोई सामग्री को दी गई एक छोटी सी सलामी।"},"ICON-0816":{"nm":"सब्ज़ी भंडारण जाली","de":"मिट्टी लगी सब्ज़ियों को उदारता से अपनी गोद में लेने वाली विरल जाली। साँस लेने की जगह मिले तो ही चीज़ें देर तक टिकती हैं, यह बात दादी की रसोई पहले से जानती थी। हवादारी सब्ज़ियों को दी गई एक कोमल छूट है।"},"ICON-0817":{"nm":"बॉटल कैप सॉर्टिंग कैप","de":"आकार के हिसाब से ढक्कनों की जोड़ी मिलाने वाली छँटाई की टोपी। खोया हुआ जोड़ा फिर से ढूँढ लेना सोचे से कहीं ज़्यादा कोमल काम है। सही जोड़ी मिल जाए तो रसोई भी थोड़ी और करीने से सज जाती है।"},"ICON-0818":{"nm":"एग ट्रे लेबल","de":"दस छोटे घोंसलों में से हर एक पर साफ़-साफ़ अंकित निशान। पहले पुराने अंडे इस्तेमाल करने की सलाह देती घर-गृहस्थी की समझ। सुबह के एक तले अंडे में भी तरतीब का ख़याल रखने वाला दिल छिपा होता है।"},"ICON-0819":{"nm":"लेफ़्टओवर स्टिकर","de":"'यह मेरा है!' लिख कर चिपका दो, तो फ्रिज को भी पल भर की शांति मिल जाती है। रात के नाश्ते का मालिक पहले से तय कर देने वाला एक प्यारा सा युद्ध-घोषणापत्र। परिवार आज भी ऐसी ही छोटी-छोटी संधियों पर चलता रहता है।"},"ICON-0820":{"nm":"कटलरी रेस्ट पीस","de":"चम्मच और चॉपस्टिक मेज़ को सीधे न छुएँ, इसलिए धीरे से टिका देने वाला एक टुकड़ा। यह छोटी सी सफ़ाई चुपके से एक भोजन की शान बढ़ा देती है। खाने की मेज़ के तौर-तरीके ऐसी ही जगहों में चुपचाप पनपते हैं।"},"ICON-0821":{"nm":"नैपकिन होल्डर रिंग","de":"हवा में उड़ जाने वाले नैपकिन को धीरे से थाम कर पकड़े रखने वाली कड़ी। खुलने की बारी का इंतज़ार करते सफ़ेद कागज़ को करीने से समेटकर, मेज़ पर एक छोटी सी तरतीब साफ़ उकेर देती है।"},"ICON-0822":{"nm":"टेबल मैट कॉर्नर","de":"मैट के उठे हुए कोने को धीरे से दबाकर सहला देने वाला टुकड़ा। एक सिरा थमे तो ही पूरा फैलाव सीधा रहता है, यह बात मेज़ हर रोज़ सिखाती है। एक कोने का भी अपना हिस्सा-भर ज़िम्मा होता है।"},"ICON-0823":{"nm":"छोटी मसाला ट्रे","de":"एक कटोरी सोया सॉस, एक चुटकी नमक साथ-साथ थाम कर रखने वाली छोटी थाली। एक छोटे-से साथ को भी अपनी जगह देने वाला मेज़ का बड़ा दिल। कोरियाई भोजन इन्हीं छोटी-छोटी चीज़ों का ख़याल रखने वाले दिल से गहरा होता है।"},"ICON-0824":{"nm":"टेबल नंबर चिप","de":"व्यस्त रेस्तराँ में 'फ़लाँ नंबर!' कहकर पुकारा जाने वाला वह अंक। इंतज़ार को एक तरतीब देकर सबके लिए बराबरी बचाए रखता है। एक चिप में समाया है एक छोटा वादा, और जल्द आने वाला एक गर्म कटोरा।"},"ICON-0825":{"nm":"वाटर कप मार्कर बैंड","de":"पानी के गिलास पर लिपटकर चुपके से बता देने वाली पट्टी कि यह किसका है। एक जैसे दिखने वाले गिलासों के बीच अपनी जगह बताने वाला एक छोटा झंडा। साथ बैठी मेज़ पर ऐसी छोटी परवाह बेवजह की ग़लतफ़हमी टाल देती है।"},"ICON-0826":{"nm":"साइड प्लेट सॉर्टिंग पिन","de":"बाँट कर खाई जाने वाली प्लेटों को रंग से अलग करने वाली पिन। मेरे और तुम्हारे बीच एक नरम रेखा खींचकर, बाँटकर खाने की खुशी को और साफ़-सुथरा बना देती है। स्नेह बाँटो, पर सफ़ाई का ख़याल पूरी तरह रखो।"},"ICON-0827":{"nm":"मेन्यू स्क्रीन बोर्ड","de":"खोले गए मेन्यू के पीछे चुपके से छिप जाने वाला सोचने का वक़्त। क्या खाना है, यह चुनने की वह छोटी झिझक भी असल में भोजन का ही एक हिस्सा है। आज क्या खाऊँ—उस सिहरन को यह चुपचाप ढँक देता है।"},"ICON-0828":{"nm":"प्लेस कार्ड होल्डर","de":"नामपट्ट को सीधा खड़ा रखने वाला छोटा स्टैंड। किसी समारोह में हो या दावत में, यह साफ़ बता देता है कि यहाँ आपकी जगह है। आतिथ्य पूरा होता है सिर्फ़ उस पल जब कोई नाम पुकारा जाता है।"},"ICON-0829":{"nm":"मफ़िन कप स्लीव","de":"ताज़े पके मफ़िन की मोटी कमर को कसकर लपेटा कागज़ी अंगरखा। गर्म तन को हाथ से फिसलने न देकर थामे रखता है, और एक कौर मुँह में जाने के उस पल तक गर्माहट सहेजे रखता है। मिठाई को भी अंगरखे की ज़रूरत होती है।"},"ICON-0830":{"nm":"पाइपिंग बैग कैप","de":"क्रीम निचोड़ने वाले थैले की नोक को कसकर बंद रखने वाली टोपी। आराम के दौरान एक बूँद भी बाहर न रिसने देकर मुँह को दृढ़ता से बंद रखती है। केक पर खिलने वाला एक छोटा फूल इसी संयम से जन्म लेता है।"},"ICON-0831":{"nm":"कुकी कटर रिंग","de":"तारे और भालू के आकार में आटे को काट देने वाला गोल साँचों का सेट। वही आटा उंगलियों से गुज़रकर दर्जनों भावों में जाग उठता है। जो भी बेक करो, आटे को सबसे पहले जो छूता है वह हमेशा लगन ही होती है।"},"ICON-0832":{"nm":"डो स्क्रैपर चार्म","de":"आटे को मितव्ययिता से समेटकर साफ़-साफ़ बाँटने वाला चपटा हाथ। कटोरे से चिपकी एक मुट्ठी तक का ख़याल रखने वाली वह लगन ही एक रोटी के आकार को तय करती है। बेकिंग एक कंजूस हाथ का ही काम है।"},"ICON-0833":{"nm":"मेज़रिंग स्पून बोर्ड","de":"एक छोटा चम्मच, आधा बड़ा चम्मच—बिना डगमगाए मापने वाले चम्मचों को करीने से लिटा देने वाला पट्टा। एक सही चम्मच स्वाद के संतुलन को सीधा खड़ा करता है। 'हाथ का स्वाद' कहावत के पीछे असल में बारीक नाप ही छिपा होता है।"},"ICON-0834":{"nm":"ओवन मिट हुक","de":"गर्म ओवन के सामने पहरा देने वाले दस्ताने को टाँगने वाली कड़ी। जलने से बचाने वाला मोटा हाथ आराम के दौरान भी हाथ की पहुँच में चुपचाप ठहरा रहता है। सुरक्षा हमेशा अपनी जगह पर बने रहने से शुरू होती है।"},"ICON-0835":{"nm":"कूलिंग रैक क्लिप","de":"ताज़े पके बिस्किटों के ठंडे होने वाली जाली को करीने से दबोचती हुई क्लिप। भाप उड़ने के दौरान उन्हें खिसकने न देकर, कुरकुरेपन के पूरा होने का इंतज़ार साथ करती है। ठंडा होने में भी थोड़े धैर्य की ज़रूरत होती है।"},"ICON-0836":{"nm":"केक टॉपर पिक","de":"'जन्मदिन मुबारक' के अक्षरों को केक के ऊपर हल्के से गाड़ देने वाली सींक। मोमबत्ती बुझने से ठीक पहले, यह छोटा सा झंडा किसी के दिन को सबसे ज़्यादा रोशन करता है। ख़ुशी ऊँची खड़ी हो तो ही अच्छी दिखती है।"},"ICON-0837":{"nm":"शुगर पाउडर शेकर","de":"आख़िरी हल्की सी बुरकन को थामे एक डिब्बा। ताज़े पके डेज़र्ट पर सफ़ेद बर्फ़ की तरह हौले से बैठ जाता है, और एक साधारण टुकड़े को एक छोटा तोहफ़ा बना देता है। आख़िरी छुअन सबसे हल्के हाथ से आती है।"},"ICON-0838":{"nm":"त्रिकोण गिमबाप लेबल","de":"लपेटा हुआ कवर 1, 2, 3 क्रम में उतारो तो लावर उस त्रिकोण पर कुरकुरा वापस लौट आता है। सुबह-सुबह सुविधा स्टोर के भरोसेमंद साथी को एक नज़र में पहचनवा देने वाली एक लकीर। देर रात पढ़ाई के बाद की भूखी रातें यहीं चिपकी रहती हैं।"},"ICON-0839":{"nm":"कप नूडल लिड होल्डर","de":"3 मिनट के इंतज़ार के दौरान ढक्कन को उठने न देकर चुपचाप दबाए रखने वाला टेका। भाप न निकल जाए इसलिए ऊपर रखी जाती रही चॉपस्टिक की जगह अब यही लेता है। नूडल्स के पकने का वह छोटा सा वक़्त, रात के नाश्ते का सबसे रोमांचक पल होता है।"},"ICON-0840":{"nm":"हॉट बार स्क्युअर कैप","de":"सींक की नोक को कसकर थाम लेने वाली छोटी टोपी। एक कौर लेना आसान बनाकर, हाथ पर मसाले की एक बूँद तक न लगने देकर रखवाली करती है। बंसिक दुकान के बाहर की चटपटी खुशी हमेशा ऐसी छोटी चीज़ों से ही पूरी होती है।"},"ICON-0841":{"nm":"प्लास्टिक बैग हैंडल","de":"उंगलियों में फँसाओ तो प्लास्टिक हल्के से चरमराकर रोता है। ख़रीदारी का वज़न एक तरफ़ झुक जाता है, और घर तक का रास्ता हथेली पर लाल निशान छोड़ जाता है। उस हल्की सी आवाज़ में आज दिन-भर की गृहस्थी भारी होकर झूलती रहती है।"},"ICON-0842":{"nm":"रसीद फ़ोल्ड क्लिप","de":"लंबी खुली रसीद को आधा मोड़कर टक से दबा दो, तो आज ख़र्च हुए पैसे एक करीने का बंडल बन जाते हैं। स्याही की महक वाले कागज़ जैसे-जैसे ढेर होते जाते हैं, गृहस्थी की मामूली यादें भी करीने से सज जाती हैं।"},"ICON-0843":{"nm":"माइक्रोवेव टैग","de":"टिन― की आवाज़ गूँजने से पहले, यह टैग चुपचाप गरम होने का समय गिन रहा होता है। कितने मिनट कितने सेकंड, और गरम होने वाली चीज़ का नाम लिखा एक छोटा सूचना-पट्ट। गरम होने की बारी का इंतज़ार करते दिल पर भी ऐसे ही निशान होते हैं।"},"ICON-0844":{"nm":"डिस्काउंट स्टिकर रोल","de":"एक-एक खाना उखाड़ते ही चिपचिपी सी चरमराहट उंगलियों को गुदगुदाती है। लाल अंक कतार में खुलते जाएँ, तो किसी की टोकरी थोड़ी हल्की हो जाती है। गोल लिपटी इंतज़ार करती एक छोटी मेहरबानी का रोल।"},"ICON-0845":{"nm":"सॉस पाउच रिंग","de":"कुछ खट्टा सा होंठों के कोने पर फूट पड़ता है, और साधारण-सा दिन थोड़ा और मीठा हो जाता है। गोल कड़ी में लटकी पाउच हर कदम पर झूले, तो एक छोटी मिठास जेब में दिन-भर मेरे साथ चलती है।"},"ICON-0846":{"nm":"कनवीनियंस स्टोर बास्केट चिप","de":"हाथ में थामो तो प्लास्टिक हल्के से लचक जाती है। रात की रोशनी से जगमगाती दुकान, दो-एक त्रिकोण गिमबाप और एक पेय समा जाने-भर की गहराई। अकेले होकर भी अकेलापन न लगे, ऐसा ठीक एक भोजन-भर का अपनापन भरा कटोरा।"},"ICON-0847":{"nm":"मैकरॉन बॉक्स बैंड","de":"रंग-बिरंगे मैकरॉन बिखर न जाएँ, इसलिए एक पट्टी डिब्बे को धीरे से गले लगाए रहती है। रिबन खोलने से ठीक पहले की वह सिहरन असल में सबसे मीठी होती है, यह बात तोहफ़ा पाने वाला उंगलियों से जान लेता है।"},"ICON-0848":{"nm":"फ्रूट नेट क्लिप","de":"जाली का मुँह समेटकर दबाओ, तो सेब की महक जाली की झिरियों से हौले से रिस आती है। लुढ़क न जाएँ, इसलिए थामे रखने वाला एक छोटा हाथ। मुरझाने से पहले जल्दी खा लेना, यह ख़ामोश मगर स्नेहिल सलाह है।"},"ICON-0849":{"nm":"जैम जार लिड क्लॉथ","de":"गोल कपड़े को ढक्कन पर चढ़ाकर रबर बैंड से बाँधती नानी की गर्मियों की रसोई याद आ जाती है। चौकोर छापे वाले एक कपड़े में जैम पकने का मीठा वक़्त और लगन साथ-साथ बंद हो जाते हैं। हाथ का स्वाद ऐसे ही ढँककर सहेजा जाता है।"},"ICON-0850":{"nm":"कुकी टाई रिबन","de":"ताज़ी पकी कुकीज़ को सेलोफेन में रखकर टाई मरोड़ते ही, मक्खन की महक रिबन के छोर तक पहुँच जाती है। हाथ से बनाई चीज़ किसी को थमाने वाला हाथ हमेशा थोड़ा काँपता है। एक गाँठ जो दिल को भी साथ बाँध देती है।"},"ICON-0851":{"nm":"चॉकलेट डिवाइडर बोर्ड","de":"खाना दर खाना, चॉकलेट को एक-दूसरे से छूने न देकर जगह तय कर देता है। न पिघले, न टूटे। एक छोटा डिवाइडर आख़िर तक जो बचाता है वह है किसी को थमाने लायक एक पूरा साबुत दिल।"},"ICON-0852":{"nm":"टी गिफ़्ट लेबल","de":"चाय की थैली पर लिपटे लेबल पर, हाथ से साफ़-साफ़ लिखा एक नाम। भिगोने पर भाप के साथ घास की महक उठेगी, यह छोटा कागज़ पहले से इशारा कर देता है। पीने से पहले ही हाथ को गरमा देने वाली एक प्याली।"},"ICON-0853":{"nm":"कैंडी बॉटल नेकलेस","de":"रंग-बिरंगी टॉफ़ी भरी बोतल की गर्दन पर डोरी बाँधकर बना हार। हर कदम पर भीतर छोटी गोलियों-सी आवाज़ लुढ़कती है। मिठास को गले में पहन घूमने वाला बचपन का एक फ़ख़्रवाला ख़ज़ाना।"},"ICON-0854":{"nm":"गिफ़्ट स्पून चार्म","de":"हैंडल के सिरे पर लटका एक छोटा चार्म, और साधारण-सा चम्मच पता नहीं कब तोहफ़ा बन जाता है। हर बार निकाले जाने पर हल्की, साफ़ खनक। किसी को दिए जा रहे दिल में एक नन्हा निखार जोड़ने वाला छोटा सा गहना।"},"ICON-0855":{"nm":"स्नैक थैंक-यू टैग","de":"जितना मिला उसका थोड़ा-सा भी लौटाने की इच्छा। नाश्ते के थैले पर हल्के से लटकाया एक धन्यवाद टैग। पूरा न कह पाए 'शुक्रिया' की जगह, एक छोटा अभिवादन चुपचाप हाथ से हाथ में जाता है।"},"ICON-0856":{"nm":"मास्किंग टेप सैंपल रिंग","de":"एक-एक बित्ता काटकर चिपकाए गए डिज़ाइन एक छोटी पट्टी में कतार बनाकर लगे हैं। कौन सा रंग अच्छा लगेगा, यह उंगलियों से धीरे-धीरे चुनते हुए, सजाने की सोच भर से दिन रंग-बिरंगा हो जाता है। एक ऐसी नमूना-पंक्ति जहाँ सोचना भी सुख देता है।"},"ICON-0857":{"nm":"स्टिकर ट्वीज़र कैप","de":"नुकीली चिमटी की नोक पर टोपी चढ़ाओ, तो नाखून-भर का स्टिकर भी बिना नुकसान के रहता है। उंगली जहाँ न पहुँच सके, ऐसे कोने को हौले से उठाने वाला एक सटीक हाथ। जो पसंद है उसे संभालने में हमेशा थोड़ी सावधानी लगती है।"},"ICON-0858":{"nm":"डायरी कॉर्नर सील","de":"डायरी के चारों कोनों पर सील चिपकाओ, तो फड़फड़ाते पन्ने जादू की तरह शांत हो जाते हैं। कागज़ के हल्के से दबने का अहसास, आज के दिन को करीने से बंद कर देने वाली एक छोटी रस्म। रिकॉर्ड कोनों से ही मज़बूत होना शुरू होता है।"},"ICON-0859":{"nm":"पंचिंग गाइड बोर्ड","de":"कहाँ छेद करना है, यह पहले से बता देने वाला पट्टा। बिंदीदार रेखा के सहारे धीरे से मिलाओ तो चूक की गुंजाइश नहीं रहती। बिना जल्दबाज़ी एक बार और नाप लेने वाला दिल—सटीकता हमेशा उसी एक पल की छोटी फ़ुर्सत से चुपचाप आती है।"},"ICON-0860":{"nm":"पेपर स्क्रैप ट्रे","de":"कैंची चलाने के बाद बचे कागज़ के टुकड़े सरसराते हुए ट्रे में जमा हो जाते हैं। मेज़ अस्त-व्यस्त न हो, इसलिए छोटे टुकड़ों के थोड़ी देर ठहरने का बसेरा। शिल्प का पिछला हिस्सा ऐसे ही बिना आवाज़ के सँवर जाता है।"},"ICON-0861":{"nm":"कलर इंक पैड","de":"पैड पर हल्के से दबाकर उठाओ, तो उंगलियों पर रंग नम-नम फैल जाता है। लाल पीला नीला, एक मुहर में उतर आने वाला एक छोटा इंद्रधनुष। सफ़ेद कागज़ पर टप-टप, रंग रोपने वाली एक मुलायम सी जगह।"},"ICON-0862":{"nm":"डेकोरेटिव टेप रोल","de":"गोल-गोल खुलता डिज़ाइन बिना रुके चला जाता है। एक टुकड़ा उखाड़कर चिपकाओ, तो सादी सी जगह पर फूल खिल जाते हैं। हाथ जैसे-जैसे चलता है वैसे-वैसे और सुंदर होता, गोल लिपटा इंतज़ार करता एक छोटा जादुई रोल।"},"ICON-0863":{"nm":"थीम स्टैंप कैप","de":"स्याही सूखे नहीं, इसलिए मुहर के सिर को कसकर लपेटने वाली एक छोटी टोपी। अगली बार छपने वाला डिज़ाइन साफ़ बना रहे, इसलिए चुपचाप निगरानी करती है। अच्छे से सहेजा गया रंग अगले कागज़ पर भी वैसा ही चटख खिलता है।"},"ICON-0864":{"nm":"डेको पंच स्क्रैप","de":"पंच के टक से गिराए छोटे टुकड़े। तारों, दिलों और पंखुड़ियों में कटे रंगीन कागज़ के टुकड़े हथेली पर हौले से ढेर हो जाते हैं। फेंकने के लिए बहुत सुंदर, इसलिए फिर कहीं न कहीं चिपका दिए जाने वाले छोटे रत्न।"},"ICON-0865":{"nm":"बॉबिन लेबल रिंग","de":"हर रील पर रंगीन धागे का नाम लिखा एक छोटा लेबल। उलझने से पहले अपनी जगह बता देने वाला एक स्नेहिल निशान। उलझा धागा हो या उलझा दिल, एक नामपट्ट से सुलझाना कहीं आसान हो जाता है।"},"ICON-0866":{"nm":"नीडल बुक कवर","de":"सुइयाँ सटी-सटी टँकी फ़ेल्ट की किताब को ढँकने वाला मुलायम आवरण। खोलते ही सिलाई के औज़ार करीने से लेटे मेरा स्वागत करते हैं। उंगलियाँ न चुभें, इसलिए नुकीली चीज़ों को स्नेह से सुला देने वाली एक छोटी सी किताब।"},"ICON-0867":{"nm":"फ़ैब्रिक सैंपल रिंग","de":"खुरदुरा हो या मुलायम, उंगलियों से कपड़े की बुनावट को एक-एक कर टटोलकर चुनने का धीमा वक़्त। रंग के हिसाब से करीने से जुटे कपड़ों के टुकड़ों के बीच, कपड़ा एक पोशाक बनने से पहले चुपचाप पहले छुए जाने का इंतज़ार करता है।"},"ICON-0868":{"nm":"एम्ब्रॉयडरी हूप लूप","de":"गोल हूप में कपड़ा फँसाकर कसो, तो वह ढोल की खाल-सा तना खिंच जाता है। एक-एक टाँका काढ़ने की तैयारी पूरी होने का छोटा संकेत। हूप जिसे मज़बूती से थामता है वह कपड़ा नहीं, ध्यान लगाया दिल है।"},"ICON-0869":{"nm":"बटन सॉर्टिंग कैप्सूल","de":"लुढ़कते फिरते बटन कैप्सूल के हर खाने में रंग के हिसाब से चुपचाप बैठ जाते हैं। कुछ खो न जाए, इसलिए छोटे-छोटे बाँट कर रखने की घर-गृहस्थी की समझ। बिखरी चीज़ों को समेटने में भी इतनी लगन लगती है।"},"ICON-0870":{"nm":"टेलर चॉक होल्डर","de":"कपड़े पर रेखा खींचने वाली चॉक को हाथ में पकड़ने लायक थामने वाला होल्डर। आसानी से टूट जाने वाली चीज़ को मज़बूती से सहारा देता है। पहली लकीर सीधी हो तभी कपड़ा भी सीधा बनता है, कैंची उठाने से पहले का यह शांत पहला संकल्प।"},"ICON-0871":{"nm":"पिन जार","de":"पारदर्शी बोतल के भीतर सिलाई की पिनें एक-दूसरे से टकराकर खनकती हैं। धूप में देखो तो हर सुई की नोक पर एक छोटी चमक बैठ जाती है। बिखरने पर ख़तरनाक हो सकने वाली चीज़ों को एक जगह जुटाकर करीने से सुला देने वाला एक कसा हुआ पात्र।"},"ICON-0872":{"nm":"मेंडिंग टेप रोल","de":"फटी जगह पर रखकर इस्त्री करते ही चुपके से चिपक जाने वाली जादुई पट्टी। एक भी टाँका लगाए बिना घिसा कपड़ा चुपचाप जुड़ जाता है। फेंकने की जगह रफ़ू कर पहनते रहने वाला दिल गोल रोल के भीतर परत-दर-परत लिपटा रहता है।"},"ICON-0873":{"nm":"पैच टेम्प्लेट पेपर","de":"पैच का आकार पहले से बना दिया गया एक डिज़ाइन कागज़। बिंदीदार रेखा कैंची के चलने का रास्ता स्नेह से दिखाती है। जो बनाना चाहते हैं उसका खाका पहले खींच लेना—सिहरन हमेशा इस हल्की सी रूपरेखा से ही शुरू होती है।"},"ICON-0874":{"nm":"वॉटरकलर जार कैप","de":"बोतल के मुँह पर चढ़ा दो, तो रंगीन पानी चाहे जितना हिले, एक बूँद भी नहीं रिसती। कूची धोए धुँधले पानी के मेज़ पर फैलने की चिंता तक ढँक देती है। चित्र बनाने की जगह को चुपचाप संभाले रखने वाला एक शांत ढक्कन।"},"ICON-0875":{"nm":"पेस्टल प्रोटेक्टर बैंड","de":"सफ़ेद-सा चूरा छोड़ने वाले पेस्टल पर पट्टी बाँध दो, तो उंगलियाँ कम गंदी होती हैं। नरम रंग टूटे नहीं, इसलिए हौले से लपेटता कागज़। जितना नाज़ुक हो, उतने ही कोमल हाथ से पकड़ो, तभी कागज़ पर भी वह कोमलता से रंग भरता है।"},"ICON-0876":{"nm":"कलर पेंसिल एक्सटेंडर कैप","de":"घिसी छोटी रंगीन पेंसिल के सिरे पर टोपी लगाओ, तो एक बित्ता फिर से लंबी हो जाती है। छोटी हो गई कहकर आसानी से न फेंकने वाला दिल। आख़िर तक इस्तेमाल करने वाली उंगलियों से ही, चित्र का रंग आख़िरी खाने तक और गहरा होकर पूरा होता है।"},"ICON-0877":{"nm":"ब्रश वॉश कप हुक","de":"सफ़ाई वाले कप को कड़ी पर टाँग दो, तो कूची से गिरी बूँदें टपटप बहती जाती हैं। अगला रंग रंगने से पहले, कूची धोने का छोटा साफ़ मौन। साफ़ होने की उस आवाज़ में भी एक शांत लय बहती रहती है।"},"ICON-0878":{"nm":"पैलेट नाइफ़ कैप","de":"रंग फैलाने और खुरचने वाली नाइफ़ की धार पर कसकर चढ़ी एक छोटी टोपी। तीखी नोक भोथरी न हो, इसलिए चुपचाप निगरानी करती है। गाढ़े लगे रंग की बनावट, इसी एक अच्छे से संभाली गई धार से जन्म लेती है।"},"ICON-0879":{"nm":"कैनवस क्लिप","de":"कैनवस के कपड़े को फ़्रेम पर ज़ोर से खींचकर टिकाए रखने वाली मज़बूत क्लिप। कसकर पकड़े तो चित्र बनाने वाली सतह ढोल-सी तन जाती है। न डगमगाने वाला आधार हो तभी उसके ऊपर दौड़ती कूची भी मन-भर आज़ाद रहती है।"},"ICON-0880":{"nm":"ड्रॉइंग बोर्ड स्ट्रैप","de":"पट्टे को कंधे पर डाल दो, तो बोर्ड पीठ के पीछे साथ चलता है। कहीं भी बैठ जाओ, वही जगह अपना निजी स्टूडियो बन जाती है। बनाने लायक कोई नज़ारा ढूँढने हल्के से निकल पड़ने वाला, पीठ पर लदा एक छोटा सा चित्रशाला।"},"ICON-0881":{"nm":"एक्रिलिक पेंट ट्यूब","de":"एक बूँद पानी डालो तो सुबह बन जाती है, कम डालो तो आधी रात। एक जैसा नीला भी उंगलियों में हर बार अलग आसमान खोल देता है। एक ट्यूब दबाते ही, आज के दिल का रंग कागज़ पर फैल जाता है।"},"ICON-0882":{"nm":"ग्रेडिएंट सैंपल शीट","de":"नज़ारा एक बार में लाल नहीं होता, यह बात यह कागज़ पहले से जानता था। हल्के से गहरे तक जाती छोटी-छोटी सीढ़ियाँ। आँख उनके बीच धीरे-धीरे चलती हुई, रंग के पकने के उस वक़्त को चुपचाप पीछे-पीछे चलती है।"},"ICON-0883":{"nm":"क्रोशिया हुक कैप","de":"धागा उंगली में चुभने से पहले पहना लिया जाने वाला, अँगूठे की मोटाई-सा छोटा कवच। लंबे समय से बुनाई करने वाला हाथ ही यह जानता है। बिना चोट खाए ही आख़िरी टाँके तक स्नेह से पहुँचाया जा सकता है।"},"ICON-0884":{"nm":"निटिंग रिंग मार्कर","de":"कहाँ तक पहुँचे हो, यह एक निशान भर से फिर साफ़ हो जाता है। एक ही टाँका दो बार न गिनना पड़े, यह राहत। दिल भी वैसे ही, बीती हुई जगह को धीरे से टोहते ही रास्ता नहीं भूलता।"},"ICON-0885":{"nm":"रो काउंटर चार्म","de":"एक लड़ी पूरी बुनने का शांत सबूत खाना दर खाना जमा होता जाता है। अंतहीन दिखने वाला काम भी एक-एक कर गिनने पर पता चलता है कि आधा तो कब का बीत गया। एक छोटी गिनती आज के दिल को आख़िर तक थामे रखती है।"},"ICON-0886":{"nm":"थ्रेड टेल टाइडी पिन","de":"खुला धागे का सिरा वैसे ही छोड़ दो, तो पता नहीं अगली गाँठ कहाँ उलझ जाए। न दिखने वाली जगह को पहले से सँवारने वाला हाथ। स्नेह अक्सर ऐसे ही, आँख से ओझल जगहों में पहले चलता है।"},"ICON-0887":{"nm":"नॉट प्रैक्टिस कॉर्ड","de":"सादी गाँठ, तितली गाँठ, अँगूठी गाँठ। हाथ आकार याद न कर ले तब तक वही डोरी बाँधकर फिर खोली जाती है। बेढब उंगलियाँ जिस रात अचानक सधने लगती हैं, वह एक डोरी सबसे पहले जान लेती है।"},"ICON-0888":{"nm":"यार्न लेबल बैंड","de":"कौन-सी मोटाई, कौन-सा रंग—हर लच्छी पर लिखी एक छोटी पट्टी। ख़त्म होने के बाद ही वैसा धागा न मिलने पर भटकी कई रातों से बनी एक आदत। रिकॉर्ड आने वाले अपने लिए लिखा गया एक स्नेहिल चिट्ठा है।"},"ICON-0889":{"nm":"गेज रूलर पीस","de":"10 सेंटीमीटर में कितने टाँके आते हैं—वह छोटा अंक ही एक पूरे कपड़े का आकार तय करता है। हथेली-भर टुकड़ा पूरे नाप को थामे रखता है, यह उठाकर देखो तो काफ़ी वज़नदार बात लगती है।"},"ICON-0890":{"nm":"बटनहोल मार्कर","de":"बटन लगाने से पहले, कहाँ छेद करना है वहाँ पहले एक बिंदी बना ली जाती है। जल्द मिट जाने वाले उस निशान की बदौलत ही कुर्ते का किनारा टेढ़ा नहीं होता। लगन अक्सर आख़िर तक न दिखने वाली जगह में चुपचाप ठहरी रह जाती है।"},"ICON-0891":{"nm":"स्मॉल टैसल लूप","de":"नोरिगे के सिरे पर लटकते गुच्छे की तरह, एक छोटी कड़ी हिलोर पैदा करती है। लटककर चुपचाप लहराती चीज़ पर हमेशा नज़र टिकी रहती है। हवा गुज़रते ही चुपचाप जीवंत हो उठने वाली एक बुनावट।"},"ICON-0892":{"nm":"मिनी पेंट बॉटल","de":"बचाना नहीं, बल्कि सटीक इस्तेमाल करना ही रंग को सही ढंग से बरतने का तरीक़ा है। एक बूँद ही काफ़ी रंग, छोटी बोतल के पास रखकर नापने वाला हाथ। संयम लालच को एक बार छोड़ देने से ही आता है।"},"ICON-0893":{"nm":"स्मॉल सैंडिंग स्टिक","de":"खुरदुरी सतह से शुरू होकर धीरे-धीरे महीन सतह की ओर बढ़ते हैं। एक ही बार में चिकनी हो जाने वाली सतह कहीं नहीं होती। बुनावट को एक-एक पायदान नीचे उतारती उंगलियों से, खुरदुरी जगह धीरे-धीरे नरम होती जाती है।"},"ICON-0894":{"nm":"मॉडल क्लिप स्टैंड","de":"गोंद लगा पुर्ज़ा हाथ में थामे रखो तो उंगलियों के निशान रह जाते हैं। चिमटी में हौले से जकड़ दो, तो हाथ आज़ाद हो जाते हैं, और सूखना अपने-आप चुपचाप पूरा हो जाता है। इंतज़ार भी हल्का हो जाता है जब कोई उसे थाम कर सहारा देता है।"},"ICON-0895":{"nm":"ग्लू वर्क प्लेट","de":"गोंद की एक बूँद मेज़ पर गिरे तो निशान लंबे समय तक रह जाता है। पहले एक पट्टिका बिछा देने की आदत। शायद आधा काम उसी इच्छा से शुरू होता है कि जगह गंदी न हो।"},"ICON-0896":{"nm":"पार्ट्स सॉर्टिंग कंपार्टमेंट","de":"एक जैसे दिखने वाले दर्जनों पुर्ज़े मिल जाएँ तो जोड़ना जल्द ही भूल-भुलैया बन जाता है। हर खाने में बाँट कर रखने वाला हाथ भटकने के आने वाले वक़्त को पहले से घटा देता है। सँवारना आने वाले अपने लिए दी गई एक मेहरबानी है।"},"ICON-0897":{"nm":"असेंबली ऑर्डर चिप","de":"किस नंबर के पुर्ज़े से शुरू करना है, यह लिखा एक छोटा चिप। तरतीब का ख़याल रखो तो आसानी से नहीं बिखरता। मॉडल हो, या धीरे-धीरे क़दम दर क़दम बना कोई भी दिन, वह इसी शांत वादे पर मज़बूत होता है।"},"ICON-0898":{"nm":"मिनी ब्रश हुक","de":"इस्तेमाल की गई कूची को लिटा दो तो बाल दबकर मुड़ जाते हैं। उलटा टाँगकर नमी निकाल देने वाली जगह। औज़ार को देर तक साथ रखने वाला इंसान काम खत्म होने के बाद ही और ज़्यादा व्यस्त और स्नेहिल रहता है।"},"ICON-0899":{"nm":"प्लास्टिक स्क्रैप पॉट","de":"साँचे से अलग किए गए बचे हुए टुकड़े चुपचाप जमा होते हैं एक डिब्बे में। फेंके गए-से लगें भी, किसी दिन एक छोटी बारीकी बनकर लौट आते हैं। बचे हुए का भी अपना समय आता है, यह डिब्बा चुपचाप इंतज़ार करते हुए जानता है।"},"ICON-0900":{"nm":"फ़िनिशिंग स्प्रे कैप","de":"आख़िरी परत बहुत पास से छिड़को तो सीधे बहकर उतर जाती है। एक बित्ता दूरी से, हल्के से, हल्के से। चमक चढ़ाने का काम शायद दिल के लालच को एक बार छोड़ देने की ही एक तालीम है।"},"ICON-0901":{"nm":"लेड रिफिल केस","de":"थैले में पतली सीसा आसानी से टूट जाती है। एक छोटे डिब्बे में करीने से लिटाकर रखने पर एक भी कतरा बेकार नहीं जाता। सहेजना आख़िर में, आने वाले कल के अपने आप को पहले से संभालकर रखने का एक ख़ामोश तरीक़ा है।"},"ICON-0902":{"nm":"इरेज़र स्लीव","de":"रबर पर पहनाया हुआ काग़ज़ का एक नन्हा कोट। इस्तेमाल से जितना काला पड़ता जाता है, उतने ही सुधार के निशान इस पर जमा होते जाते हैं। मिटाना भी, शुरुआत से फिर से चलने की एक मीठी इजाज़त है।"},"ICON-0903":{"nm":"निब स्टोरेज ट्यूब","de":"पेन की निब सूखने पर फटती है और चोट लगने पर मुड़ जाती है। अलग से लिटाकर रखने वाला एक छोटा डिब्बा, लिखावट की बनावट को लंबे समय तक बचाए रखता है। जिस औज़ार को नरमी से संभाला जाता है, वह अंत में उतनी ही नरमी से फिसलकर बदला चुकाता है।"},"ICON-0904":{"nm":"फाउंटेन पेन इंक सैंपल","de":"एक-एक बूँद टपकाकर आज़माई जाने वाली स्याहियाँ। जो रंग फ़िरोज़ी लगता था, काग़ज़ पर आकर गहरा समंदर बन जाता है। रंग को हमेशा आमने-सामने मिलकर ही जाना जा सकता है—मन में सोचा हुआ रंग अक्सर चूक जाता है।"},"ICON-0905":{"nm":"बुक डार्ट टिन","de":"पढ़ते-पढ़ते जहाँ छोड़ा, वहाँ हल्के से खोंस दिया गया एक नन्हा झंडा। अगली बार किताब खोलने पर, कल का अपना आप हाथ हिलाकर इंतज़ार करता मिलता है। जहाँ रुके थे, वह जगह भी एक वादा बन जाती है—इस छोटे-से निशान का यही मीठा काम है।"},"ICON-0906":{"nm":"फ़्लैग टैब पैक","de":"एक पर्ची निकालकर चिपकाओ, और ठीक वहीं से कहानी फिर शुरू हो जाती है। जब किताब के किनारे पर नन्हे झंडे कतार में लग जाते हैं, तो बिखरे हुए विचार एक ही नक़्शे में करीने से जमा हो जाते हैं।"},"ICON-0907":{"nm":"क्लिप-संग्रह चुंबक","de":"बिखरी हुई क्लिपों को एक ही झटके में समेट लेने वाला एक छोटा चुंबक। जो चीज़ जितनी छोटी होती है, उतनी ही जल्दी खो जाती है, इसलिए इकट्ठा करने की यह एक शक्ति ही अस्त-व्यस्त मेज़ को चुपचाप बचा लेती है। खींचकर पास लाने में भी एक कोमलता होती है।"},"ICON-0908":{"nm":"पेंसिल कैप सेट","de":"पेंसिल की नोक को ढँककर बैग के अंदर की चीज़ों की रक्षा करने वाली नन्हीं टोपियाँ। जो नुकीला होता है, वह कभी न कभी किसी को चुभ ही जाता है, इसलिए उसे धीरे से ढँकने वाले एक हाथ की ज़रूरत होती है। ताकि नोक कुंद भी न हो, और किसी को चोट भी न लगे।"},"ICON-0909":{"nm":"डेस्क नेमप्लेट स्टिकर","de":"नाम लिखकर मेज़ के आगे चिपकाते ही, वह जगह आख़िरकार किसी की अपनी बन जाती है। एक बालिश्त-भर जगह को भी जब कोई मालिक मिल जाता है, तो वहाँ मन बिठाने का ढंग भी अचानक बदल जाता है।"},"ICON-0910":{"nm":"स्किपिंग रोप हैंडल कैप","de":"मूठ का सिरा घिसकर फटने से पहले पहनाई जाने वाली टोपी। हज़ार बार से ज़्यादा घुमाई गई रस्सी की लय को, दिमाग़ से पहले हथेली याद रखती है। शरीर में उकेरी गई ताल आसानी से नहीं भूलती।"},"ICON-0911":{"nm":"योगा रिंग स्ट्रैप","de":"रिंग थामकर धीरे-धीरे शरीर को खोलो। जितना पट्टा कसता जाता है, उतने ही अकड़े हुए कंधे परत-दर-परत ढीले होते जाते हैं। खींचना ज़बरदस्ती करने का काम नहीं, बल्कि शरीर के खुलने तक चुपचाप इंतज़ार करने का काम है।"},"ICON-0912":{"nm":"टेबल टेनिस बॉल केस","de":"इतनी हल्की कि दूर तक लुढ़क जाए, और पैर पड़ते ही चपटी पिचक जाए, ऐसी एक सफ़ेद गेंद। एक छोटा-सा केस इस सबसे नाज़ुक गेंद को अगले मैच तक सँभाल कर रखता है। मज़बूती अक्सर नरमी से लपेटे जाने से ही आती है।"},"ICON-0913":{"nm":"बैडमिंटन ग्रिप टेप","de":"पसीने से फिसलती मूठ पर एक करीने भरी परत लपेट दी जाती है। अच्छी तरह लिपटी हुई ग्रिप पर रैकेट हाथ का ही एक हिस्सा बन जाता है। ज़ोर से नहीं, अहसास से खेलने का राज़ इस पतली-सी एक परत में छिपा है।"},"ICON-0914":{"nm":"छोटी स्कोर चिप","de":"एक अंक, फिर एक और अंक। छोटी-छोटी चिप्स सरकाते हुए स्कोर धीरे-धीरे जमा होता जाता है। जब गिनती आँखों के सामने हो, तो मुक़ाबला और साफ़ हो जाता है, और एक अंक की कमी को पाट लेने का हौसला भी चुपके से उभर आता है।"},"ICON-0915":{"nm":"स्नीकर डायरेक्शन क्लिप","de":"करीने से रखे गए जूतों की नोक हमेशा एक ही दिशा में देखती है। उतारते वक़्त हाथ का एक हल्का घुमाव। यह छोटी-सी करीनेबंदी कल की सुबह के क़दमों को भी उतना ही हल्का बना देती है।"},"ICON-0916":{"nm":"व्हिसल लैनयार्ड","de":"सीटी को गले में लटकाते ही रुको कहने का अधिकार मिल जाता है। एक छोटी-सी आवाज़ पर पूरा मैदान एक साथ थम जाने का नज़ारा। उस नन्ही आवाज़ पर भरोसा करने वाले दिल ही मिलकर एक वादा बनते हैं।"},"ICON-0917":{"nm":"बॉल पंप नीडल ट्यूब","de":"हवा निकली हुई गेंद भी एक पतली सुई से फिर से तन जाती है। एक छोटे डिब्बे में सहेजकर रखी वह सुई, खो जाने की घड़ी पूरे पंप को ही बेकार बना देती है। जब सबसे छोटी चीज़ सबसे ज़रूरी बन जाए।"},"ICON-0918":{"nm":"मिनी कोन मार्कर","de":"यहाँ से वहाँ तक, एक नन्हा शंकु अदृश्य सीमा-रेखा खींच देता है। कोई रेखा न होने पर भी लोग उस निशान का अनुसरण करते हुए अपने आप क़तार बना लेते हैं। अनुशासन इसी तरह के छोटे संकेतों से चुपचाप उगता है।"},"ICON-0919":{"nm":"टोकन पाउच","de":"खनकते टोकन को एक जगह जमा करने वाली थैली। मुँह कस देने पर कुछ भी बिखरने का डर नहीं रहता। छोटी और मामूली चीज़ों को भी जब तक कोई ठिकाना न मिले, वे अपना काम पूरा नहीं कर पातीं—यह बात थैली बिना कुछ कहे दिखा देती है।"},"ICON-0920":{"nm":"कार्ड शफ़ल मैट","de":"फिसलनदार मेज़ पर पत्ते ठीक से हाथ में नहीं आते। एक बिछावन भर से फेंटना और उठाना दोनों कहीं ज़्यादा सहज हो जाता है। अच्छे से खेलने में भी, पहले सतह चुनने की एक मीठी तैयारी शामिल होती है।"},"ICON-0921":{"nm":"बोर्ड कॉर्नर गार्ड","de":"बोर्ड-गेम की रात ख़त्म होने पर कोई चुपचाप सबसे पहले बोर्ड के चारों कोनों को सँभालता है। क्योंकि वह जानता है कि गहरी हो चुकी सिलवट अगली बाज़ी को टेढ़ा कर देगी। किनारों को सीधा करती उंगलियों में, कल फिर साथ खेलने की इच्छा छिपी होती है।"},"ICON-0922":{"nm":"डाइस कप लिड","de":"हिलाना, लुढ़काना, और सब मिलकर साँस रोक लेने का वह छोटा-सा पल। यह पासों को उछलकर बाहर न भागने देने वाली एक नन्ही छत है। ढक्कन के भीतर आज की क़िस्मत पल भर को साँस लेती है, फिर खड़खड़ाती हुई बाहर लुढ़क आती है।"},"ICON-0923":{"nm":"टाइल एलाइनिंग बोर्ड","de":"खेल में जो जितना उत्साहित होता है, उसकी पंक्ति उतनी ही टेढ़ी हो जाती है। टाइलें तिरछी होने पर उन्हें हौले से धकेलकर सीधा कर देने का काम। सीधा करना दरअसल किसी की उत्साहित हड़बड़ाहट को प्यार से थाम लेने वाला एक हाथ है।"},"ICON-0924":{"nm":"स्कोर चिप टिन","de":"जितना डिब्बा चिप्स से भरता जाता है, उतना ही खेल भी गरमाता जाता है। गोल-गोल अंक हथेली में खड़खड़ाकर टकराते हैं, तब जीत-हार से पहले ही वह आवाज़ ख़ुशी दे जाती है।"},"ICON-0925":{"nm":"टर्न मार्कर रिंग","de":"अब तुम्हारी बारी है, यह बताने वाली एक नन्ही अंगूठी। एक खाने आगे सरकाने के उसी पल भर के लिए, सबकी निगाहें चुपचाप मुझ पर आ टिकती हैं। यह इंतज़ार और बेताबी के बीच धीरे-धीरे घूमती एक कड़ी है।"},"ICON-0926":{"nm":"गेम पीस स्टैंड","de":"जो मोहरा जितनी आसानी से गिरता है, उसके पाँव उतने ही मज़बूत होने चाहिए। थोड़ी लड़खड़ाती बिसात पर भी एक स्टैंड उसकी जगह थामे रखता है। छोटी चीज़ों के टिके रहने पर ही ऊपर की बड़ी चीज़ ऊँची खड़ी रह पाती है।"},"ICON-0927":{"nm":"रूलबुक क्लिप","de":"नियमपुस्तिका खुली छोड़ी जाए तो उसके पन्ने चुपके से पलट ही जाते हैं। हवा के पन्ने उड़ा ले जाने से पहले, एक पन्ने को हल्के से दबाए रखने वाली यह क्लिप है। नियमों को थामे रखना ज़रूरी है, तभी खेल आख़िर तक चलता रहता है।"},"ICON-0928":{"nm":"पिक केस स्ट्रैप","de":"गिटार पिक हमेशा सबसे रोमांचक पल में ही उंगलियों से फिसल जाता है। केस से लटकती एक डोरी उस नन्हे भाग जाने को रोक लेती है। जिसने संगीत रुक जाने की वह रात झेली है, वही इस डोरी का शुक्रगुज़ार होता है।"},"ICON-0929":{"nm":"रीड स्टोरेज ट्यूब","de":"रीड सूखते ही अपनी आवाज़ खो देती है। नम डिब्बे के भीतर सरकंडे की एक पतली कतरन अगली प्रस्तुति का इंतज़ार करती है। साँस भरने से पहले, पहले साँस को सुला देने वाली एक जगह है यह।"},"ICON-0930":{"nm":"स्ट्रिंग वाइंडर","de":"तार ढीला पड़ते ही सुर भी चुपचाप बैठ जाता है। हैंडल को धीरे-धीरे घुमाकर कसाव लौटा लाने का काम—लगन हमेशा कलाई के सिरे से ही आती है। सुरीली आवाज़ ऐसी ही छोटी-छोटी करीनेबंदियों से शुरू होती है।"},"ICON-0931":{"nm":"इंस्ट्रूमेंट क्लॉथ","de":"प्रस्तुति ख़त्म होते ही वाद्य पर भी हल्का-सा पसीना रह जाता है। मुलायम कपड़े से एक बार पोंछते ही, चमक के साथ आज के सुर भी शांति से बैठ जाते हैं। संजोने का मन हमेशा समापन में ही उजागर होता है।"},"ICON-0932":{"nm":"ट्यूनिंग पिन कवर","de":"ट्यूनिंग पिन को खुला छोड़ दें तो पता ही नहीं चलता कब वह जंग खा जाती है। एक छोटा कवर धातु के मौसम को एक ताल पीछे धकेल देता है। जो सबसे पहले अनदेखे कोनों की सुध लेता है, वही सबसे लंबे समय तक बजाता है।"},"ICON-0933":{"nm":"म्यूज़िक स्टैंड क्लिप लाइट","de":"अंधेरे मंच के पीछे, कभी-कभी बस स्वरलिपि ही रोशन होनी चाहिए। स्टैंड से जकड़ी एक नन्ही बत्ती, हल्के से रोशनी नीचे उतार देती है। स्वर अपना रास्ता न खोएँ, इसलिए पैरों तले उजाला बिछाती मुट्ठी-भर रोशनी।"},"ICON-0934":{"nm":"प्रैक्टिस म्यूट कैप","de":"भोर की रियाज़ हमेशा पड़ोसियों की नींद से चुपचाप जूझती है। एक कैप लगाते ही गरजती आवाज़ सिमटकर फुसफुसाहट बन जाती है। किसी की गहरी नींद की रखवाली करते हुए भी पनपने वाला संगीत ऐसा ही होता है।"},"ICON-0935":{"nm":"ड्रम पैड स्टिकर","de":"ड्रम पैड पर चिपके नन्हे निशान। कहाँ थपकी दें तो कैसी आवाज़ निकलेगी, यह हाथ याद करे उससे पहले आँखें रास्ता पहचान लेती हैं। ताल इसी तरह धीरे-धीरे शरीर में उकेरी जाती है।"},"ICON-0936":{"nm":"मेलोडी मेमो चिप","de":"गुनगुनाई हुई धुन को न थामा जाए तो वह पल भर में उड़ जाती है। चिप पर जल्दबाज़ी में लिखे कुछ बोल आगे चलकर पूरा गीत भी बन जाते हैं। प्रेरणा हमेशा उस हाथ के पास लौटकर आती है, जो लगन से लिखता रहता है।"},"ICON-0937":{"nm":"बुक कवर बैंड","de":"पढ़ी-अधूरी किताब बैग में मन-मुताबिक़ खुल जाए तो मुश्किल होती है। एक बैंड से पन्नों को हल्के से बाँध दें, तो पन्ने आज्ञाकारी बने रहते हैं। अगले पन्ने के लिए करीने से समेटकर रखने का यह एक वादा है।"},"ICON-0938":{"nm":"पेज होल्डर रिंग","de":"एक हाथ से किताब खोले रखकर गरम कॉफ़ी पीने का मन करे, ऐसा एक दिन। उंगली में पहनी अंगूठी बदले में पन्नों को थाम लेती है। थोड़ी-सी सुकून की गुंजाइश ऐसे ही मामूली आविष्कारों से शुरू होती है।"},"ICON-0939":{"nm":"रीडिंग टाइमर चिप","de":"बस एक अध्याय और, कहकर बैठें तो रात कब गहरी हो जाती है, पता ही नहीं चलता। चिप दबाकर समय तय कर लें तो पढ़ाई में भी एक विराम आ जाता है। जो चीज़ जितनी प्यारी हो, उतनी ही रुकना जानने की मीठी हिम्मत भी चाहिए।"},"ICON-0940":{"nm":"बुक कॉर्नर गार्ड कैप","de":"जिस किताब से जितना ज़्यादा लगाव होता है, उसके कोने चुपचाप उतने ही पहले घिसते हैं। एक कैप पहनाते ही कवर के कोने गोल और सुरक्षित रहते हैं। जिसे लंबे-लंबे समय तक पास रखना हो, उस चाहत को हल्के से पहनाया गया एक नन्हा कवच है यह।"},"ICON-0941":{"nm":"रीडिंग नोट बैंड","de":"एक पंक्ति पढ़कर सीने में कुछ धप्प से बैठ जाने का एक पल होता है। पट्टी पर लिखा हुआ वह भाव, बुकमार्क की तरह उसी पन्ने पर ठहर जाता है। रेखांकित उस पंक्ति की गरमाहट, बस पढ़ने वाले को ही पता होती है।"},"ICON-0942":{"nm":"लाइब्रेरी रिटर्न टैग","de":"लौटाने की तारीख़ हमेशा एक दिन पहले ही आ जाती है। टैग पर लिखी तारीख़ जब चुपचाप पीठ पर हाथ रखकर धकेलती है, तो उधार ली किताब को भी विदाई की एक शिष्टता मिल जाती है। अगले किसी के हाथों के लिए, पुस्तकालय इसी तरह इंतज़ार करता है।"},"ICON-0943":{"nm":"बुक लाइट क्लिप","de":"सोए हुए परिवार के पास अकेले जागकर पढ़ने वाली रात। किताब के किनारे क्लिप से जकड़ी एक नन्ही रोशनी ही काफ़ी होती है। पूरे अंधेरे को हटाने की ज़रूरत नहीं, बस एक पन्ने भर के लिए एक शांत लम्हा ही काफ़ी होता है।"},"ICON-0944":{"nm":"बुक सेंट कार्ड","de":"पुरानी किताबों से धूप और काग़ज़ के घुले-मिले एक ख़ुशबू आती है। उस ख़ुशबू को एक पन्ने में समेट लिया गया यह कार्ड, खोलते ही पुरानी किताबों की गली को पल भर के लिए नाक की नोक पर ज़िंदा कर देता है। यादें ख़ुशबू से भी पन्ने पर निशान लगाती हैं।"},"ICON-0945":{"nm":"रीड-टु मार्कर पिन","de":"कहाँ तक पढ़ा था भला, उस बेबस सवाल को मिटा देने वाली एक नन्ही पिन। आख़िरी वाक्य पर टाँक दें, तो कल का अपना आप और भटकता नहीं। रुकी हुई जगह को याद रखने वाला यह एक प्यारा निशान है।"},"ICON-0946":{"nm":"फ़ोन स्ट्रैप चार्म","de":"फ़ोन की डोरी पर लटकी एक कड़ी भर से इंसान थोड़ा अलग दिखने लगता है। पसंदीदा रंग, पसंदीदा आकार। हाथ में थमी यह छोटी-सी पसंद दिन के मूड को हल्के से हिला देती है।"},"ICON-0947":{"nm":"कैमरा लेंस गार्ड कैप","de":"सफ़र की तस्वीरों की क़िस्मत एक लेंस पर टिकी होती है। सुरक्षा कैप हटाने का वह पल, दरअसल शटर दबाने के लिए मन की तैयारी होता है। नज़ारा क़ैद करने से पहले, सबसे पहले आँख खोलने की एक छोटी-सी रस्म।"},"ICON-0948":{"nm":"चार्जिंग पोर्ट प्लग","de":"बैग के भीतर की धूल हमेशा चार्जिंग छेद पर ही पहली नज़र गड़ाती है। एक प्लग से उस नन्हे मुँह को बंद कर दें तो पिन लंबे समय तक साफ़ रहती है। अनदेखे झिरियों तक की सुध लेने वाली एक लगन यहाँ छिपी है।"},"ICON-0949":{"nm":"फ़ोन ग्रिप पॉप रिंग","de":"आराम से एक वीडियो देखने के लिए फ़ोन को तिरछा टिकाने का काम। पीछे लगी पॉप रिंग खोलने पर हाथ और स्क्रीन दोनों को थोड़ी राहत मिल जाती है। थोड़ा-सा उभरा एक स्टैंड शाम के एक पल को सुकून से खींच देता है।"},"ICON-0950":{"nm":"स्क्रीन वाइप पैच","de":"उंगलियों के निशान से भरी स्क्रीन कहीं न कहीं मन को भी धुँधला कर देती है। पैच से एक बार पोंछते ही दुनिया फिर से साफ़ नज़र आने लगती है। साफ़-सफ़ाई कभी-कभी बस एक उंगली भर का छोटा-सा काम होती है।"},"ICON-0951":{"nm":"सिम पिन केस","de":"सिम पिन एक ऐसी परी है जो ठीक ज़रूरत के वक़्त ही ग़ायब हो जाती है। केस के एक ख़ाने में रखते ही, अब बाल-पिन ढूँढ़ने पूरा घर छानना नहीं पड़ता। एक छोटी-सी करीनेबंदी अकसर आपाधापी के पल को चुपचाप बचा लेती है।"},"ICON-0952":{"nm":"वायरलेस चार्जिंग पैड स्टिकर","de":"पैड पर बस टिका दो, और फ़ोन ख़ुद-ब-ख़ुद भर जाए ऐसी एक रात। चिपकाया गया स्टिकर फ़ोन के लेटने की जगह हल्के से बता देता है। अनदेखी बिजली बिना आवाज़ किए दिन-भर की ऊर्जा भर देती है।"},"ICON-0953":{"nm":"नोटिफ़िकेशन कवर स्टिकर","de":"जो सूचना देखनी न हो, उसे ढँक देना ही मन को सुकून देता है। एक स्टिकर भर से भोर की नन्ही रोशनी सुला दी जाती है। कभी-कभी न देखना भी अपने आप को सँभालने का एक मीठा तरीक़ा होता है।"},"ICON-0954":{"nm":"लेंस गार्ड रिंग","de":"कैमरे का लेंस ज़मीन को छूने वाला वह पल भर, दिल धक्क से बैठ जाता है। चारों तरफ़ लिपटी एक अंगूठी उस छोटी-सी गिरावट को चुपके से रोक लेती है। यादें क़ैद करने वाली आँख को सबसे पहले ढँकने वाला एक घेरा है यह।"},"ICON-0955":{"nm":"केबल नेम टैग","de":"उलझे हुए ढेर सारे तारों में से आख़िरकार अपनी वाली को पहचान लेना। एक टैग भर से चार्जिंग तार को भी अपना नाम मिल जाता है। बिखरे तारों के बीच रास्ता बताने वाला एक नन्हा झंडा है यह।"},"ICON-0956":{"nm":"चार्जर पाउच","de":"यात्रा के बैग में चार्जर हमेशा आपस में उलझकर झगड़ते रहते हैं। एक पाउच के भीतर करीने से जमा करते ही आख़िरकार सुलह हो जाती है। सामान समेटने की कला बिखरी चीज़ों को प्यार से एक जगह बुला लेने में है।"},"ICON-0957":{"nm":"पावर स्ट्रिप लेबल","de":"मल्टी-प्लग के सारे छेद एक जैसे दिखते हैं और हर बार गड्डमड्ड हो जाते हैं। लेबल लगाकर किसकी जगह कौन-सी है, यह तय कर दें तो व्यस्त सुबह कहीं ज़्यादा सहज हो जाती है। एक छोटा-सा नाम-पर्चा रोज़मर्रा की मामूली झिकझिक कम कर देता है।"},"ICON-0958":{"nm":"कॉर्ड वाइंडर रील","de":"खोलकर इस्तेमाल करना, फिर वापस लपेटकर रखना—तार का एक करीना भरा दिन। एक रील पर परत-दर-परत लपेटते ही उलझन साफ़-साफ़ ग़ायब हो जाती है। इस्तेमाल के बाद वापस अपनी जगह लौटाने वाला हाथ ही कल को हल्का बनाता है।"},"ICON-0959":{"nm":"मैग्नेटिक कनेक्टर कैप","de":"चुंबकीय पिन कब बारीक़ लोहे की धूल खींच लेती है, पता ही नहीं चलता। कैप से ढँक दें तो चिपचिपी धूल टिक नहीं पाती। जिस डिवाइस को एक बार और सहेजने वाला हाथ छूता है, वह लंबे समय तक साथ रहता है।"},"ICON-0960":{"nm":"पावर बैंक बैंड","de":"पावर बैंक और उसकी तार अलग रख दें तो एक न एक ज़रूर ग़ायब हो जाती है। एक बैंड से बाँध दें तो दोनों आख़िरकार एक जोड़ी बन जाते हैं। बाहर निकलने से ठीक पहले, साथ-साथ चलने को कहते हुए हल्के से बाँधी गई एक नन्ही गाँठ है यह।"},"ICON-0961":{"nm":"प्लग डस्ट कैप","de":"ख़ाली सॉकेट का छेद कुछ ही दिनों में चुपचाप धूल का घर बन जाता है। यह नन्ही कैप जब उस जगह की रखवाली सँभाल लेती है, तो अगली बार लगने वाला चार्जर एक साफ़-सुथरी पहली साँस ले पाता है। ख़ाली वक़्त को करीने से सँभालने वाला एक द्वारपाल।"},"ICON-0962":{"nm":"केबल कलर रिंग","de":"उलझे तारों में अपनी वाली टटोलती रात, किसी ने कहा था चलो रंग चढ़ा दें। नीला तुम्हारा, पीला मेरा। एक छोटी-सी कड़ी से हम फिर एक-दूसरे को गड्डमड्ड नहीं करते। रियाज़-कक्ष के एक कोने में बचा हुआ, एक मीठे वादे का निशान।"},"ICON-0963":{"nm":"एडेप्टर सॉर्टिंग चिप","de":"गोल पिन और चपटी पिन, 110 और 220। हर देश के अलग-अलग सॉकेट के चेहरों को चुपचाप याद रख लेने वाली एक चिप। समुद्र पार पहले मंच की ओर निकलते बैग के एक कोने में, यह छोटी-सी वर्गीकरण-पर्ची हमेशा दबी रहती थी।"},"ICON-0964":{"nm":"ईयर टिप सॉर्टिंग ट्रे","de":"कहते हैं हर इंसान के कान की गहराई और चौड़ाई अलग होती है। बड़े, मध्यम और छोटे—तीनों जोड़ों को एक क़तार में लिटाकर अपने कान में ठीक फ़िट बैठने वाला एक जोड़ा चुनने का काम। ध्वनि सुनने से पहले, पहले शरीर को साथ बिठाने की एक मीठी रस्म।"},"ICON-0965":{"nm":"केस सिलिकॉन रिंग","de":"मंच के परिधान की एक-एक सिलाई पर ध्यान जाता है, पर केस के कोने अक्सर नंगे ही चोट खाते हैं। यह पतली सिलिकॉन पट्टी जब किनारे को हल्के से लपेट लेती है, तो हाथ से फिसल जाने वाली भोर में भी स्क्रीन सही-सलामत सुबह का स्वागत करती है।"},"ICON-0966":{"nm":"नॉइज़-कैंसल स्टिकर","de":"दुनिया की आवाज़ों को थोड़ी देर के लिए बंद कर देने का मन करे, ऐसे भी दिन होते हैं। हेडफ़ोन के कान पर चिपका यह नन्हा स्टिकर सन्नाटा जगाने का एक निशान है। दर्शकों की तालियाँ हों या मेट्रो का शोर, एक गीत ख़त्म होने तक उन्हें दूर ले जाकर रखने वाला एक ताबीज़।"},"ICON-0967":{"nm":"ईयर हुक सेट","de":"नाचते वक़्त इयरफ़ोन का एक कान हमेशा पहले भाग जाता है। कान की बाहरी बनावट को हल्के से थामने वाली इस कड़ी को पहन लें, तो तेज़ कोरियोग्राफ़ी के बीच भी बस संगीत ही आख़िर तक कान में टिका रहता है। रियाज़-कक्ष के लोगों के बीच बँटी हुई एक छोटी-सी खोज।"},"ICON-0968":{"nm":"क्लीनिंग ब्रश कैप","de":"ब्रश की नोक पर लगी धूल फिर से न बिखरे, इसके लिए पहनाई जाने वाली एक नन्ही टोपी। सफ़ाई के औज़ार को भी सफ़ाई की ज़रूरत होती है—यह बात झाड़ू के बाद उसे उलटा खड़ा कर देने वाला हाथ बहुत पहले से जानता आया है।"},"ICON-0969":{"nm":"चार्जिंग डॉक बेस पैड","de":"चार्जिंग डॉक मेज़ पर बार-बार फिसलता था, क्योंकि उसके पाँव नहीं थे। नीचे बिछाया यह पतला पैड जब पाँव की जगह ले लेता है, तो डिवाइस अपनी जगह चुपचाप टिका रहकर रातभर शांति से ऊर्जा भरता है।"},"ICON-0970":{"nm":"लेफ़्ट-राइट मार्कर","de":"बायाँ L, दायाँ R। अंधेरे में टटोलकर भी पहचाना जा सके, इसलिए एक और बिंदु लगा दिया जाता है। मंच पर बाएँ और दाएँ पैर को एक बार भी न गड्डमड्ड करने की चाहत, इस नन्हे निशान पर पूरी की पूरी उकेरी हुई है।"},"ICON-0971":{"nm":"ऑडियो स्प्लिटर जैक कैप","de":"एक ही धुन को कई लोगों में बाँट देने वाला वह जैक, आराम के वक़्त उसके सिरे को बंद रखना ज़रूरी है। ताकि धूल परिपथ में न घुस जाए। साथ सुना हुआ गीत अगली बार भी उतना ही साफ़ बहता रहे, इसकी चाहत लिए एक छोटा-सा सतर्क हाथ है यह।"},"ICON-0972":{"nm":"ईयरफ़ोन केबल वाइंडर","de":"सूत की उलझन लपेटती पुरानी हाथ की हरकत की तरह, इयरफ़ोन की तार भी यहाँ गोल-गोल लपेटने पर सलीके से सज जाती है। बैग में उलझी-लुढ़की धुन के करीने से जम जाने का पल। कल की खोलने की मशक़्क़त कहीं ज़्यादा हल्की हो जाती है।"},"ICON-0973":{"nm":"लेंस कैप होल्डर स्ट्रैप","de":"लेंस खोलते ही हर बार कैप का ठिकाना खो जाता था। डोरी से बाँधकर कैमरे के पास ही टाँग दें, तो अब जेब बेकार में टटोलनी नहीं पड़ती। किसी चीज़ को न खोना हो तो उसे पास ही बाँध दो—यह हाथ ने सबसे पहले सीख लिया।"},"ICON-0974":{"nm":"हॉट शू कवर चार्म","de":"कैमरे के ऊपर ख़ाली पड़ी हॉट-शू जगह में एक छोटा-सा गहना धीरे से खोंस दिया जाता है। किसी काम का न होने वाला वह एक चार्म, भारी-भरकम और रूखे उपकरण को अचानक अपनी ही चीज़ जैसा प्यारा दिखा देता है। औज़ार से लगाव जोड़ने का यही काम है।"},"ICON-0975":{"nm":"स्ट्रैप एडजस्टर बकल","de":"बैग की डोरी जब भी कंधे में धँसती है, इस बकल को थोड़ा ढीला या कस दिया जाता है। अपने शरीर के मुताबिक़ लंबाई चुनती उंगलियों की एक हरकत। सामान उठाना भी आख़िर में अपने आप की देखभाल करना ही है—यह बकल चुपचाप बता देता है।"},"ICON-0976":{"nm":"फ़िल्टर स्टैक केस","de":"रोशनी को बाँटने वाली शीशे की परतों को करीने से लिटाकर रखने वाला एक नन्हा घर। धुँधलापन और साफ़ी, सांझ और रात। जैसे मौसम पहले से चुनकर रखा गया कोई दराज़ हो, फ़ोटोग्राफ़र निकलने से पहले हमेशा सबसे पहले यही केस खोलकर देखता है।"},"ICON-0977":{"nm":"ब्लोअर डस्ट कैप","de":"हवा उड़ाकर धूल भगाने वाली रबर की गेंद, उसका मुँह भी धूल के आगे उतना ही कमज़ोर होता है। आराम के वक़्त इस कैप को पहना दिया जाता है। दूसरों को साफ़ करने वाला औज़ार अपने ही मुँह को चुपचाप ढँक लेता है—यह बात कुछ अजीब-सी मीठी लगती है।"},"ICON-0978":{"nm":"शटर बटन कवर","de":"बैग के भीतर मन-मुताबिक़ शटर दब जाने से ख़ाली आसमान की सौ तस्वीरें उतर जाना, हर किसी के साथ कभी न कभी होता है। बटन पर चढ़ाया यह नन्हा कवर उस बेकार मेहनत को रोक देता है। जिन पलों को सच में सहेजना हो, बस उन्हें ही सहेजने की एक मामूली-सी सिटकिनी।"},"ICON-0979":{"nm":"बैटरी सॉर्टिंग स्टिकर","de":"ख़त्म हो चुकी और पूरी भरी बैटरी एक ही थैले में गड्डमड्ड हो जाएँ, तो हमेशा गड़बड़ हो जाती है। हर बैटरी पर लगा रंगीन स्टिकर उस उलझन को चुपचाप सुलझा देता है। लाल यानी ख़ाली, हरा यानी भरोसेमंद। शूटिंग-स्थल पर जलता एक ख़ामोश ट्रैफ़िक-लाइट।"},"ICON-0980":{"nm":"कैमरा बैग डिवाइडर","de":"लेंस, बॉडी और अतिरिक्त बैटरी आपस में न टकराएँ, इसलिए बैग के भीतर ख़ाने बना दिए जाते हैं। एक ही सामान के भीतर कई छोटे कमरे बसाने का काम। हर जगह का अपना मालिक तय होता है, इसलिए हिलने-डुलने पर भी कोई अपनी जगह नहीं खोता।"},"ICON-0981":{"nm":"शूटिंग ग्लव पैड","de":"सर्दियों की बाहरी शूटिंग में, बस शटर दबाने वाली उंगली की नोक ठंडी नहीं पड़नी चाहिए। हथेली पर मोटा-सा पैड, और उंगलियों की नोक पर अहसास छोड़ने वाले दस्ताने। गरमाहट और सटीकता को एक साथ एक हाथ में थामने की, शूटिंग-स्थल की एक मीठी बीच की राह।"},"ICON-0982":{"nm":"टैबलेट निब ट्यूब","de":"पेन की निब भी पेंसिल की सीसा की तरह घिसती है, यह बात लंबे समय से टैबलेट थामे रखने वाले ही जानते हैं। अतिरिक्त निबों को गोल-गोल जमा किए यह नन्हा डिब्बा, न टूटनी चाहिए ऐसी रेखा को पहले से भर देने वाली उंगली की एक बचत-राशि जैसा है।"},"ICON-0983":{"nm":"कीकैप ट्रे","de":"जिस दिन एक-एक कीकैप निकालकर धोया और फिर से लगाया, उस दिन यह ट्रे एक नन्हा दलदली किनारा बन गई। स्वर और व्यंजन ख़ाने-दर-ख़ाने लेटकर नमी सुखाते हुए का नज़ारा। एक बार अलग करने पर ही दिखने वाली एक लगन भी होती है।"},"ICON-0984":{"nm":"माउस फ़ीट पैक","de":"माउस के मेज़ पर फिसलते हुए दौड़ने का राज़, तले पर चिपके इन नन्हे पैरों में छिपा है। घिस जाने पर बदल देने वाला एक बंडल। एक अनदेखी जगह से चुपचाप चिकनाई थामे रखने वाली चीज़ों की मेहनत।"},"ICON-0985":{"nm":"लैपटॉप स्टैंड पैड","de":"दिखने में नोटबुक जैसा, पर असल में लैपटॉप को उठाकर टिकाने वाला रबर का एक स्टैंड। स्क्रीन को आँखों की सीध तक हल्के से उठाकर झुकी गर्दन को सीधा करने का काम। जो लंबे समय तक लिखता और झाँकता रहता है, उसकी मुद्रा सीधी रखने वाली एक फ़िक्र।"},"ICON-0986":{"nm":"वेबकैम कवर स्लाइडर","de":"उंगली से सरकाकर लेंस को ढँक दो, फिर सरकाकर खोल दो। बस तब दिखना चाहती हूँ जब मैं दिखना चाहूँ, यह मन। इस एक नन्ही स्लाइडर में निजता नाम की एक बड़ी राहत बसती है। बंद होने की आवाज़ अजीब-सी भरोसेमंद लगती है।"},"ICON-0987":{"nm":"यूएसबी सॉर्टिंग लेबल","de":"एक जैसी दिखती पाँच काली छड़ें, किसमें क्या भरा है, बिल्कुल पता नहीं चलता। एक छोटा लेबल चिपकाकर नाम दे दें, तभी वह अपने परिवार का हिस्सा बनती है। बुलाने के लिए एक नाम हो, तभी ढूँढ़ना भी आसान होता है।"},"ICON-0988":{"nm":"डेस्क पैड कॉर्नर","de":"डेस्क पैड के कोने बार-बार मुड़ते रहें, तो हस्तलिपि भी टेढ़ी हो जाती है। चारों कोनों को हल्के से दबाए रखने वाले ये नन्हे पुर्ज़े मेज़ पर एक सपाट शांति की रखवाली करते हैं। सतह के शांत रहने पर ही उंगलियों की नोक भी शांत रह पाती है।"},"ICON-0989":{"nm":"हब स्टैंड क्लिप","de":"कई तारें जहाँ एक साथ मिलती हैं, ऐसे एक हब को मेज़ के किनारे तिरछा खड़ा रखने वाली क्लिप। अस्त-व्यस्त तारों के एक बिंदु पर आकर करीने से जम जाने का नज़ारा। उलझे हुए को एक धागे में पिरो देने की कारीगरी यहाँ भी ज़िंदा है।"},"ICON-0990":{"nm":"स्क्रीन क्लीनर स्प्रे कैप","de":"स्क्रीन पर लगे उंगलियों के निशान मिटाने वाले स्प्रे का मुँह बंद रखने वाली एक नन्ही टोपी। तरल न रिसे, न सूखे, इसलिए इसे हमेशा कसकर बंद रखा जाता है। साफ़ देखना हो तो पहले सफ़ाई के साधन को ही सहेजना पड़ता है—घर-गृहस्थी का यह एक सीधा-सादा क्रम है।"},"ICON-0991":{"nm":"मेमोरी कार्ड वॉलेट","de":"कई दिनों के मंच के दृश्य एक नाख़ून-जितने कार्ड में ख़ामोशी से सोए रहते हैं। खो जाए तो पूरा दिन का दिन ही ग़ायब हो जाता है, इसलिए उसे एक नन्हे बटुए में सहेजकर संजोया जाता है। सबसे छोटी और सबसे बड़ी याद, दोनों को थामने वाला एक घर।"},"ICON-0992":{"nm":"एक्सटर्नल ड्राइव लेबल रिंग","de":"काले पाँच बाहरी हार्ड-ड्राइव एक जैसे चेहरे लिए दराज़ में सोए रहते हैं। लेबल चिपकाकर 'उस साल की गर्मी', 'अनप्रकाशित क्लिप' नाम दे देने का काम। धुँधली हो चुकी याद पर एक साफ़ अनुक्रमणिका जोड़ने की मेहनत है यह।"},"ICON-0993":{"nm":"बैकअप चेक चिप","de":"बैकअप हुआ या नहीं, इस बाल-बराबर फ़र्क़ पर मन सिकुड़ जाता है। पूरा होने की जगह पर हल्के से खोंसी यह नन्ही चिप बता देती है कि 'यहाँ तक सब सुरक्षित है'। सुकून हमेशा एक निशान छोड़ने से ही मिलता है।"},"ICON-0994":{"nm":"क्लाउड मेमो टोकन","de":"आसमान में कहीं तैरते एक भंडार-घर तक एक पंक्ति का संदेश तैरा भेजने वाला टोकन। जहाँ भी खोलो, वह लिखावट सामने आकर मिलती है—एक नन्हा जादू। पतंग उड़ाकर मन्नत लिखी जाने वाली रात का आसमान, अब मानो हथेली पर हल्के से उतर आया हो।"},"ICON-0995":{"nm":"यूएसबी गार्ड कैप सेट","de":"पिन खुली छोड़कर बैग में लुढ़कते रहने पर संपर्क-बिंदु ख़राब होते ही हैं। हर सिरे पर एक नन्ही टोपी पहनाकर एक सेट में सँभाल लेते हैं। इस्तेमाल न होने के वक़्त को करीने से सुला देने का काम। अगले जुड़ाव की सबसे ख़ामोश तैयारी।"},"ICON-0996":{"nm":"डेटा केस बैंड","de":"क़ीमती डेटा रखने वाली डिवाइस को चारों ओर से कसकर लपेटने वाली एक पट्टी। एक फेरा लगाकर मज़बूती से बाँध दें, ताकि हिलते बैग में कहीं टकराव न हो। पोटली को लगन से गाँठ लगाती रही पुरानी उंगलियाँ, डिजिटल दुनिया में भी उसी तरह ज़िंदा हैं।"},"ICON-0997":{"nm":"फ़ाइल सॉर्टिंग टैग","de":"सैकड़ों फ़ाइलें बिना नाम के जमा होती जाएँ, तो ढूँढ़ना ही भटकना बन जाता है। रंग-बिरंगे टैग लगाकर शाखाएँ खोल देने के उसी पल, अस्त-व्यस्त ढेर के बीच एक राह निकल आती है। सहेजना, आख़िर में एक राह बनाने का ही काम है।"},"ICON-0998":{"nm":"पासवर्ड हिंट कार्ड","de":"पूरा पासवर्ड लिख दो तो ख़तरा है, बिल्कुल न लिखो तो भूल जाओगे। इसलिए बस वही सुराग़ छोड़ा जाता है जिसे सिर्फ़ मैं समझूँ। जैसे 'पहले मंच वाला वह शहर'। जवाब नहीं, बस राह लिख रखने का यह एक चतुर और मीठा तरीक़ा है।"},"ICON-0999":{"nm":"स्टोरेज डेट स्टिकर","de":"रखने की तारीख़ न लिखो तो संजोना जल्द ही भुलाना बन जाता है। हर डिब्बे पर लगा तारीख़ का स्टिकर 'कब से' को साफ़-साफ़ उकेर देता है। अचार डालने का दिन लिख रखने वाले पुराने भंडार-घर का मन, इस छोटे-से काग़ज़ पर आगे चलता है।"},"ICON-1000":{"nm":"मिनी रिंग लाइट कैप","de":"गोल-गोल रोशनी बिखेरने वाली एक नन्ही बत्ती, उसके रोशनी वाले छेद को ढँकने वाली एक कैप। बैग में लेंस पर खरोंच न आए, इसलिए रोशनी को थोड़ी देर सुला दिया जाता है। जलाने से पहले के अंधेरे को करीने से सँजोए रखना भी, उजाले को संजोने का एक तरीक़ा है।"},"ICON-1001":{"nm":"माउंट कसने का पेंच","de":"बस एक और घुमाव। ढीला हुआ फ़ासला मिट जाता है, और हथेली के नीचे एक भारी सुकून उतर आता है। न डगमगाने वाले मंच के पीछे हमेशा किसी की एक फुर्तीली कलाई छिपी होती है। एक छोटा-सा पेंच जो थामे रखता है, वह है एक अनदेखी मज़बूती।"},"ICON-1002":{"nm":"ऑन-एयर संकेत चिप","de":"जैसे ही लाल बत्ती जलती है, गलियारे के क़दम धीरे से पंजों के बल चलने लगते हैं। \"प्रसारण जारी है\"—इस एक वाक्य के आगे सब साँस रोक लेते हैं। दरवाज़े के उस पार का सन्नाटा भी किसी के लिए एक मुड़ा हुआ दिल है, यह छोटी-सी चिप चुपचाप यही बताती है।"},"ICON-1003":{"nm":"चैट मेमो पैड","de":"स्क्रीन पर से फिसल जाने वाले उत्साह-भरे शब्दों को उँगलियों की नोक से थाम लेती है। बह जाने वाला हर एक शब्द काग़ज़ पर साफ़-साफ़ ठहर जाने का पल। दर्ज करना, देर से ही सही, पहुँचने की चाहत रखने वाली कोमलता के ठहरने की जगह है।"},"ICON-1004":{"nm":"साइलेंट कीबोर्ड कवर","de":"रात के दो बजे, चाबियाँ दबाने की आवाज़ झूठ की तरह ग़ायब हो जाती है। गहरी नींद में सोए रूममेट की साँसों को न जगाने के लिए बिछी एक पतली-सी परत। सबसे शांत ख़याल हमेशा किसी बेआवाज़ जगह से ही शुरू होता है।"},"ICON-1005":{"nm":"माइक आर्म क्लिप","de":"होंठों और माइक के बीच, बस उतनी ही दूरी जिस पर गीत नहीं डगमगाता। यह छोटी-सी क्लिप उस वादे को थामे रखती है। मंच के पीछे हमेशा ऐसा ही एक हाथ पहले से आकर चीज़ों को स्थिर थामे रहता है।"},"ICON-1006":{"nm":"बैकड्रॉप क्लैंप","de":"हवा चले तब भी पर्दा हिलता नहीं। क्योंकि एक छोटा-सा जबड़ा कोने को कसकर काट रखता है, पूरे दृश्य को थामे हुए। न डगमगाने वाले नज़ारे के पीछे, कहीं किसी अनदेखी जगह में दाँत भींचे कोई खड़ा है।"},"ICON-1007":{"nm":"स्ट्रीम डेक लेबल","de":"दर्जनों बटनों पर लगे छोटे-छोटे नाम-पर्चे हाथ को भटकने नहीं देते। लेबल की एक पंक्ति लाइव प्रसारण की एक ग़लती को पहले ही मिटा देती है। धैर्य दरअसल काँपने से पहले लिख लिए गए अक्षरों से आता है।"},"ICON-1008":{"nm":"टाइमस्टैंप बटन","de":"दबाते ही, बहते समय पर एक छोटा-सा झंडा गड़ जाता है। कभी न लौटने वाले अभी पर मुहर लगाने का काम। बहुत बाद में मुड़कर देखने पर वही निशान यादों में उतरने का द्वार बन जाता है।"},"ICON-1009":{"nm":"टैग रीडर की-रिंग","de":"पास ले जाते ही टिक् की आवाज़ के साथ जानकारी जाग उठती है। चाबी के छल्ले से लटका, जेब में खनकता एक छोटा-सा साथी। साधारण दिन इन्हीं छोटी-छोटी संकेत-ध्वनियों के सहारे बेख़तर आगे बढ़ता है।"},"ICON-1010":{"nm":"स्मार्ट प्लग लेबल","de":"हर सॉकेट पर नाम लिख दो, तो फिर कौन-सी तार किसकी है, इसमें भटकना नहीं पड़ता। अनदेखी बिजली को भी नाम देने वाला मन। सफ़ाई-सुथराई कोमलता का ही एक और उधार लिया हुआ चेहरा है।"},"ICON-1011":{"nm":"तापमान-नमी सेंसर स्टैंड","de":"कमरे के तापमान और नमी को बिना बोले निहारता एक हथेली-भर पहरेदार। आराम कभी मुँह नहीं खोलता, पर यह स्टैंड हर पल चुपचाप तुम्हारी हालत की ख़बर रखता है। सुख-चैन इसी तरह चुपचाप संभाला जाता है।"},"ICON-1012":{"nm":"डोर सेंसर कैप","de":"दरवाज़े के धीरे से खुलने का वह पल न चूकने वाली एक छोटी-सी आँख। किसी के लौट आने का संकेत बिना बोले पहुँचा देती है। सूने घर की रखवाली हमेशा ऐसी ही चुप चीज़ें करती हैं।"},"ICON-1013":{"nm":"रिमोट होल्डर","de":"इधर-उधर लुढ़कते रहे रिमोट आख़िरकार अपनी-अपनी जगह पा जाते हैं। खोने ही वाली किसी चीज़ को धीरे से थाम लेने वाली छोटी-सी जगह, फिर मिलने का वादा पहले से उकेरने वाला एक हाथ।"},"ICON-1014":{"nm":"स्लीप ऐप टोकन","de":"अच्छी नींद वाली हर रात एक गोल-सा पुरस्कार लुढ़कता हुआ जमा होता जाता है। नींद भी अभ्यास की तरह धीरे-धीरे इकट्ठा होती है, यह ऐप प्यार से बता देता है। अच्छी तरह आराम कर चुके तुम्हें दिया गया, दुनिया का सबसे छोटा इनाम।"},"ICON-1015":{"nm":"टाइमर क्यूब बेस","de":"तीन मिनट क़दम-दर-क़दम बीतते रहें, तब भी क्यूब बिना डगमगाए अपना समय गिनता है। उसके नीचे धीरे से थामे रहने वाली एक हथेली-भर जगह। इंतज़ार को भी, चैन से पैर टिकाने के लिए एक ज़मीन चाहिए होती है।"},"ICON-1016":{"nm":"नोटिफिकेशन लाइट कवर","de":"बहुत तेज़ न हो, इसलिए रोशनी को एक परत में मुलायमी से लपेट लेता है। सूचना भले जल्दबाज़ी में हो, आँखें बस चैन में रहें। ख़याल रखना वह मन है जो रोशनी की तीव्रता तक धीरे से नाप लेता है।"},"ICON-1017":{"nm":"बैटरी बदलने का कार्ड","de":"यह कार्ड दिखे, तो समझो डिवाइस के भीतर धड़कते छोटे दिल को बदलने का वक़्त आ गया है। रुकने से पहले ही ख़याल रख लेने का प्यारा इशारा। लंबे साथ का राज़ हमेशा एक धड़कन पहले चौकन्ने रहने में छिपा है।"},"ICON-1018":{"nm":"जॉयस्टिक कैप सेट","de":"अंगूठा फिसले नहीं, इसलिए हल्के से पहनाई गई छोटी-छोटी टोपियाँ। उँगलियों की नोक का एहसास और साफ़ हो जाता है। यह छोटी-सी कैप कभी-कभी पसीने से भीगे हाथों वाले एक मुक़ाबले की हार-जीत तय कर देती है।"},"ICON-1019":{"nm":"स्विच डॉक कवर","de":"कंसोल के आराम करने की जगह को धूल से धीरे से ढँक देता है। थोड़ी देर सोई डिवाइस को भी एक कंबल तो चाहिए ही। स्नेह उसी वक़्त और साफ़ दिखता है, जब चीज़ इस्तेमाल में नहीं होती।"},"ICON-1020":{"nm":"हैंडहेल्ड कंसोल पाउच","de":"सफ़र में हमेशा इसी के भीतर। हैंडहेल्ड कंसोल को नरमी से गले लगाने वाली थैली। बैग के भीतर इधर-उधर टकराने पर भी बेअसर रहे, इसलिए क़ीमती चीज़ों को एक बार और लपेट देना ही अच्छा है।"},"ICON-1021":{"nm":"बटन स्टिकर रिंग","de":"फीके पड़े बटन पर बस एक छोटी-सी तस्वीर रखो, और उसी पल वह पूरी तरह अपना बन जाता है। एक जैसे दिखने वाले डिवाइस पर अपनी अलग पहचान छोड़ने का काम। ख़ासियत हमेशा ऐसी ही मामूली जगहों से चुपचाप खिलती है।"},"ICON-1022":{"nm":"गेम कार्ट्रिज केस","de":"रात-भर डूबे रहने वाला वह एक खेल इस छोटे-से केस के भीतर गहरी नींद में सोता है। ढक्कन फिर से खोलो, तो वह रात जस-की-तस जाग उठती है। यादें हैरानी से हथेली-भर डिब्बे में ही समा जाती हैं।"},"ICON-1023":{"nm":"कूलिंग फ़ैन स्टैंड","de":"हवा गर्मी को ठंडा करती रहे, तब तक डिवाइस को हल्के से टेढ़ा करके थामे रखने वाली जगह। तपे हुए बदन को साँस लेने की एक फुर्सत देता है। दूर तक दौड़ना है तो थोड़ी देर रुककर ठंडा होना भी आना चाहिए।"},"ICON-1024":{"nm":"रिस्ट स्ट्रैप पिन","de":"कलाई पर लपेटकर पिन लगाओ, तो चाहे कितनी भी तेज़ हरकत हो, कंट्रोलर साथ नहीं छोड़ता। यह अड़चन-सा दिखने वाला फीता असल में वह भरोसा है जो बेधड़क उछल-कूद करने देता है।"},"ICON-1025":{"nm":"एनालॉग ग्रिप कैप","de":"लंबे इस्तेमाल से चिकनी हुई ग्रिप पर नया लिबास पहनाया जाता है। हाथ को जानी-पहचानी अनुभूति वैसी ही रहे, बस ऊपरी सतह नई-सी लगे। जान-पहचान और हल्की-सी सिहरन एक ही हाथ में साथ-साथ ठहरने का पल।"},"ICON-1026":{"nm":"सेव स्लॉट लेबल","de":"हर सेव-स्लॉट पर किसका सफ़र है, यह साफ़-साफ़ लिख दिया जाता है। लेबल की एक पंक्ति बीते कुछ दिनों की यात्रा को चुपचाप संभाले रखती है। क़ीमती यादों पर नाम उकेर देना ही अच्छा है, ताकि वे मिट न जाएँ।"},"ICON-1027":{"nm":"रिकॉर्डर पाउच","de":"आवाज़ को समेटने वाली मशीन, भीतर छुपी चीज़ के कारण और भी क़ीमती हो जाती है। झटकों से बचाने वाली नरम थैली में उसे संभालकर साथ रखा जाता है। शायद किसी की आवाज़ भीतर सोई हो, इसलिए और भी सावधानी से।"},"ICON-1028":{"nm":"विंडस्क्रीन कैप","de":"हवा की सरसराहट हटाकर बस आवाज़ को बचा लेता है। बाहर रिकॉर्डिंग करते वक़्त माइक पर हल्के से पहनाई गई मुलायम टोपी। बेतरतीब शोर के बीच से सिर्फ़ सच्चाई चुनकर समेटने वाली एक छोटी-सी छलनी।"},"ICON-1029":{"nm":"वॉइस मेमो लेबल","de":"यह वाला बोल याद आया वाला है, यह वाला गुनगुनाई हुई धुन। हर वॉइस मेमो पर रंग-बिरंगा नाम-पर्चा चिपकाया जाता है। यहाँ-वहाँ बिखरे प्रेरणा के टुकड़े आख़िरकार अपनी-अपनी जगह पाकर क़तार में लग जाते हैं।"},"ICON-1030":{"nm":"सैंपलिंग बटन चिप","de":"दबाते ही, पहले से समेटी गई आवाज़ का एक टुकड़ा उछलकर बाहर आ जाता है। बारिश की बूँद, तालियाँ, किसी की हँसी—दुनिया के ये टुकड़े उँगली की नोक पर जाग उठते हैं। संगीत ऐसी ही छोटी-छोटी चिप्स का प्यारा सामूहिक गान है।"},"ICON-1031":{"nm":"ध्वनि-संग्रह लिफ़ाफ़ा","de":"रास्ते चलते-चलते अचानक बटोरी आवाज़ों को इस लिफ़ाफ़े में धीरे से समेट लिया जाता है। हवा की बुनावट, यहाँ तक कि भोर की गली का सन्नाटा भी। कभी गीत बनने वाली सामग्री हमेशा ऐसे ही सादगी से इकट्ठी होती है।"},"ICON-1032":{"nm":"मिनी ट्राइपॉड पैर","de":"तीन टाँगें मेज़ पर एक छोटा-सा मंच खोल देती हैं। काँपते हाथ की जगह दृढ़ता से खड़े होकर दृश्य को थामे रखती हैं। एक साफ़-सुथरी तस्वीर आख़िरकार चुपचाप ठहरे इन तीन पैरों से ही जन्म लेती है।"},"ICON-1033":{"nm":"रिकॉर्डिंग फ़ाइल टैग","de":"सैकड़ों रिकॉर्डिंग फ़ाइलों पर एक-एक करके छोटा-सा टैग लगाया जाता है। ताकि एक नज़र में पता चले किस दिन पहली बार निकली पहली पंक्ति कौन-सी है। बिखरी हुई आवाज़ों को फिर से ढूँढ निकालने वाला एक छोटा-सा मील का पत्थर।"},"ICON-1034":{"nm":"वेवफ़ॉर्म स्टिकर पट्टी","de":"आवाज़ की शक्ल को हूबहू ढालकर बनी लहरदार पट्टी। नोटबुक या केस पर लपेटो, तो मानो संगीत आँखों के सामने दिखने लगे। जो सुना जाता है उसे दिखाई दे जाने वाला बना देने का, एक प्यारा-सा भ्रम।"},"ICON-1035":{"nm":"हेडसेट हुक पिन","de":"अभ्यास ख़त्म होते ही, थके हेडसेट के लिए आराम की जगह धीरे से तैयार कर देता है। मेज़ के कोने में गड़ी एक छोटी-सी अंकड़ी। सलीके से रखी मेज़, कल के जोश को पहले से टाँगकर रखने की जगह है।"},"ICON-1036":{"nm":"मिनी गिफ़्ट बॉक्स पट्टी","de":"तोहफ़े के डिब्बे की कमर पर लिपटा आख़िरी एक चक्कर। इसी एक पट्टी से मन आख़िरकार पूरा हो जाता है। मेहनत अक्सर भीतर रखी चीज़ से पहले, ऊपर सहलाते हाथ से ही पहुँच जाती है।"},"ICON-1037":{"nm":"रिबन टेल कैप","de":"रिबन का सिरा खुल न जाए, इसलिए उसे धीरे से लपेटकर पूरा कर दिया जाता है। नज़र में मुश्किल से आने वाला एक बारीक विवरण, तोहफ़े का पहला प्रभाव चुपचाप बदल देता है। अंत सुंदर हो, तो मन भी सुंदरता से पहुँचता है।"},"ICON-1038":{"nm":"सीलिंग वैक्स","de":"गरम बूँद टपकाकर लिफ़ाफ़ा बंद कर दिया जाता है। पुरानी चिट्ठियों की तरह, बिना इजाज़त न खोलने का एक भारी वादा। तौर-तरीक़ा कभी-कभी ऐसे ही किसी गर्मजोश वज़न को समेटे रखता है।"},"ICON-1039":{"nm":"थैंक-यू कार्ड होल्डर","de":"शुक्रिया वाले शब्द रखने वाला कार्ड मुड़े नहीं, इसलिए उसे सीधा थामे रखता है। मन सीधा खड़ा होकर पहुँचे, इसीलिए। कृतज्ञता उसकी शक्ल भी सलीकेदार हो, तो मन में और लंबे समय तक रह जाती है।"},"ICON-1040":{"nm":"तारे के आकार का पैडिंग पेपर","de":"तारों के आकार में काटे गए काग़ज़ डिब्बे के ख़ाली कोनों को फूला-फूला भर देते हैं। हिले तब भी कुछ न चोटिल हो, यही चाहत की रुई है। पैकिंग के भीतर के अंधेरे में भी, गोया एक छोटा-सा तारा चमक रहा हो।"},"ICON-1041":{"nm":"गिफ़्ट लिस्ट टैग","de":"पानेवाले का ख़ाना ख़ाली, और क़लम देर तक ठहरी रहती है। नाम के तीन अक्षर लिखते हुए याद आता चेहरा, साथ बिताए मौसम। बाँधे जाने के उस पल यह छोटा-सा काग़ज़, खुलने से पहले किसी को न पढ़ पाने वाला एक राज़ बन जाता है।"},"ICON-1042":{"nm":"बधाई स्टैंप रिंग","de":"दबाते ही एक गोल बधाई साफ़ छपकर उभर आती है। स्याही सूखने के उस छोटे-से पल का इंतज़ार करते हुए, किसे यह देना है यह सोचने वाला मन ही सबसे गर्मजोश होता है। एक बार और छापने का मन कर आए, तो यही इसकी एक ख़ामी है।"},"ICON-1043":{"nm":"गिफ़्ट कॉर्ड बॉबिन","de":"मेहनत से लिपटी रहकर, फिर किसी के धड़कते उँगली-सिरों पर ख़ुशी-ख़ुशी खुल जाती है। लिपटने और खुलने के उसी छोटे-से पल में, धागे से बँधा एक मन आख़िरकार तोहफ़ा बन जाता है।"},"ICON-1044":{"nm":"गाँठ का लटकन (फूल नहीं)","de":"फूल की नक़ल नहीं, बल्कि एक ही धागा बार-बार ख़ुद को लपेटते-लपेटते ख़ुद-ब-ख़ुद खिल उठने की शक्ल। रातभर गाँठें चुनती रही उँगलियों का धैर्य, ऐसी ही एक छोटी-सी कली बनकर रह गया है।"},"ICON-1045":{"nm":"लकी कॉइन पाउच","de":"दूर सफ़र पर निकलने वाले की जेब में चुपके से कुछ सिक्के डाल देने वाला मन। यह वज़न भरने का नहीं, कोमलता भरने का काम है। हर क़दम पर खनकती आवाज़, अच्छे से लौट आना जैसी दुआ की जगह ले लेती है।"},"ICON-1046":{"nm":"विश कैप्सूल चार्म","de":"गोल ख़ोल के भीतर मुड़ी एक मन्नत गहरी नींद सो रही है। खोलने से पूरी हो जाती है, यह झूठ है, पर बिना खोले संभाले रखने से वह चाहत हमेशा के लिए ज़िंदा रहती है, यह सच है।"},"ICON-1047":{"nm":"सुरक्षा गाँठ डोरी","de":"पाँच रंगों के धागों से मज़बूती से बुनी, बुरी ऊर्जा को पीछे मोड़ देने वाली डोरी। बचपन में कलाई पर गाँठ बाँधती दादी के हाथ की तरह, हर बँधी जगह पर किसी की दुआ महीन ढंग से जड़ी है।"},"ICON-1048":{"nm":"छोटा पेपर क्रेन केस","de":"हज़ार बार मोड़ने पर मन्नत बनती है कहा जाने वाला काग़ज़ का सारस, बस उस एक को चोट से बचाकर रखने वाला छोटा-सा घर। एक पंख भी सिकुड़ जाए, तो उस रात लगाई मेहनत भी धीरे-धीरे खुल जाती है।"},"ICON-1049":{"nm":"स्पार्कल स्टोन पाउच","de":"मंच के लिबास से गिरे रोशनी के छोटे-छोटे कण, फेंकने का मन न होने पर बटोर लेने की जगह। एक बार चिपक जाए तो हफ़्तों साथ चलने वाली चमक भी यहाँ हथेली पर जैसे चुपचाप सो जाती है।"},"ICON-1050":{"nm":"शुभ-संकेत स्टैंप चिप","de":"अच्छा दिन चुनते वक़्त धीरे से जोड़ी जाने वाली एक छोटी-सी पर्ची। किसी ज्योतिषी की देहरी पर नहीं, अपनी ही मेज़ पर, आज बस अच्छी बातें हों इस चाहत से हल्के से छापी गई प्यारी अंधविश्वास की एक बूँद।"},"ICON-1051":{"nm":"विश ब्रेसलेट कार्ड","de":"कंगन के आकार में छपे एक काग़ज़ में किसी की ख़ामोश दुआ समाई है। कलाई पर न भी बँधे, तो बटुए में गहरे रख दो, वह मन हमेशा साथ बँधकर साथ चलता रहेगा।"},"ICON-1052":{"nm":"दहलीज़ नमक जार","de":"मोटा नमक एक छोटी-सी शीशी में भरकर दरवाज़े के आगे धीरे से रख दिया जाता है। बुरी ऊर्जा लौट जाए और प्यारे मेहमान ही अंदर आएँ, यह पुराना हिसाब-किताब है। नमक का हर एक कण घर की रखवाली करने वाला एक छोटा-सा पहरेदार है।"},"ICON-1053":{"nm":"लकी नंबर कवर टैग","de":"खुरचने से ठीक पहले, हर कोई एक पल के लिए विजेता होता है। भाग्यशाली अंक को नरमी से ढँकने वाला यह टैग, आस के सबसे ज़्यादा फूलने वाले उस आख़िरी एक पल की रखवाली करता है। खुरचती उँगलियाँ काँपें तब भी, अनजान बनकर आँखें मूँद लेता है।"},"ICON-1054":{"nm":"बर्थडे कैंडल कीपर कैप","de":"एक बार जलाई गई मोमबत्ती को भी अगले जन्मदिन तक सँभालकर रखने वाला जतन-भरा मन। पिछले साल माँगी मन्नत अगर अब तक पूरी न हुई हो, तो इस साल वहीं से आगे बढ़कर फिर माँग लेने की एक कोमल तरकीब है।"},"ICON-1055":{"nm":"एनिवर्सरी काउंटडाउन रिंग","de":"डी-डे को उँगली में पहना देने वाली एक शरारती चीज़। बचे दिनों की गिनती जब भी एक घर पीछे खिसकती है, दिल भी उतना ही आगे खिंचता चला आता है। शून्य पर पहुँचते ही अपने-आप चमक उठेगी, यह अकेले ही ज़िद पकड़े है।"},"ICON-1056":{"nm":"पार्टी हैट स्ट्रैप","de":"टोपी को सिर पर धीरे से थामे रखने वाला एक महीन फीता। जिसका जन्मदिन है वही थोड़ी देर में घुटन बताकर उतार फेंकता है, पर तस्वीर में वह एक पल हमेशा के लिए सिर पर टिका रह जाता है। बस इतना ही इसका काम काफ़ी है।"},"ICON-1057":{"nm":"छोटा केक पिक","de":"दो उँगलियों जितने छोटे केक पर गड़ा एक नन्हा निशान। एक ही कौर में मिट जाने वाली मिठास के ऊपर भी, बधाई अपना क़द तान कर खड़ी रहती है। छोटा हो तब भी जन्मदिन जन्मदिन ही है, और आज का सितारा तुम ही हो।"},"ICON-1058":{"nm":"पार्टी पॉपर लेबल","de":"धमाके की आवाज़ न सही, पर देखने में सबसे भड़कीला काग़ज़ी पटाखा। लिफ़ाफ़े पर चिपकते ही, एक सादा-सा डाक जश्न के घर से आई चिट्ठी में बदल जाता है। उतारने का मन न होने के कारण कई लोग उसे यूँ ही चिपका छोड़ देते हैं।"},"ICON-1059":{"nm":"फ़ोटो हैंगर क्लिप","de":"डोरी पर टँगी यादें कहीं गिर न जाएँ, इसलिए मैं हमेशा अपना मुँह कसकर भींचे रखता हूँ। जब तक एक तस्वीर मेरी पकड़ में है, तब तक खिड़की से आती हवा भी वे दिन गिरा नहीं पाती।"},"ICON-1060":{"nm":"डेट बैलून पैच","de":"अंक लिखा गुब्बारे के आकार का पैच। कपड़े पर चिपकाओ तो पूरा मोहल्ला जान जाता है आज कौन-सा ख़ास दिन है। उतारने पर निशान रह जाता है, और वह धुँधला निशान भी एक और यादगार बन जाता है।"},"ICON-1061":{"nm":"गिफ़्ट एक्सचेंज मार्कर","de":"लेने वाले हाथ और देने वाले हाथ को हल्के-से गड्डमड्ड कर देने वाला एक शरारती निशान। किसने दिया इससे ज़्यादा क्या आया-गया इसे याद रखने को कहने वाला, तोहफ़े बाँटने की मेज़ का एक छोटा और प्यारा नियम।"},"ICON-1062":{"nm":"एनिवर्सरी टेबल नंबर","de":"हर जश्न की मेज़ पर छोटा-सा खड़ा किया गया एक अंक। कौन कहाँ बैठेगा यह पहले से तय कर लेने से किसी को अजीब नहीं लगता, यह बात कई बार जश्न मना चुके लोगों की गर्मजोश समझ इसमें समाई है।"},"ICON-1063":{"nm":"डोरनॉब गिफ़्ट बैग","de":"कॉलबेल बजाए बिना दिल पहुँचाने का एक तरीक़ा। दरवाज़े की कुंडी पर चुपके से टाँगकर भाग-सा जाओ, तो उसे पाने वाले के चेहरे पर आया चौंका देने वाला भाव ही देने वाले को लौटने वाला सबसे बड़ा तोहफ़ा बन जाता है।"},"ICON-1064":{"nm":"सीक्रेट डिलीवरी लेबल","de":"ऊपर कुछ भी लिखा नहीं है। भेजने वाले को आख़िर तक छिपाए रखना ही इस लेबल का छोटा-सा गुमान है। पाने वाला जितनी देर सिर खुजाकर मुस्कुराता रहे, यह ख़ुफ़िया मिशन उतना ही परिपूर्ण होता जाता है।"},"ICON-1065":{"nm":"डोरबेल मेमो चिप","de":"दरवाज़ा खटखटाने की हिम्मत न हो, तो उसकी जगह चिपका दी जाने वाली एक छोटी-सी पर्ची। \"थोड़ी देर के लिए आया था\" जैसी एक छोटी पंक्ति कॉलबेल की आवाज़ से भी ज़्यादा देर तक रह जाती है। टेढ़े-मेढ़े हस्तलेख का भी अपना एक भाव होता है।"},"ICON-1066":{"nm":"बॉक्स कटर सेफ़्टी कैप","de":"कूरियर का चाक़ू बेख़याली में उँगली की ओर बढ़े, तो चुपके से आगे आ खड़ा होने वाला एक छोटा हीरो। नई चीज़ के उत्साह में जल्दबाज़ हुई उँगलियों को आख़िरी कट तक सही-सलामत बचाए रखता है।"},"ICON-1067":{"nm":"बबल रैप का टुकड़ा","de":"मैं दबाए जाने के लिए ही पैदा हुआ। टक् की आवाज़ के साथ फूटते ही दिन-भर का तनाव न जाने कैसे धीरे से ढीला पड़ जाता है। भीतर लिपटी असली चीज़ से भी कहीं ज़्यादा देर तक मुझसे प्यार होने वाले दिन भी कभी-कभी आते हैं।"},"ICON-1068":{"nm":"अराइवल टाइम पिन","de":"कितने बजे पहुँचेगा, यह बिल्कुल साफ़-साफ़ टाँकने वाली एक पिन। धुँधले-से इंतज़ार को भी एक निशान मिल जाए, तो वह कहीं ज़्यादा सहनीय हो जाता है। उस वक़्त तक दरवाज़े की ओर कितनी बार झाँकोगे, यह पूरी तरह तुम्हारे हाथ में है।"},"ICON-1069":{"nm":"पार्सल लॉकर की-रिंग","de":"पार्सल-लॉकर का कोड बार-बार भूल जाने वाले के लिए एक छोटा-सा साथी। चाबी के छल्ले पर लटका-लटका डोलता रहता है, और ठीक ऐन मौक़े पर \"अरे हाँ\" कहलवा देना ही इस दोस्त की चुपचाप वाली ख़ासियत है।"},"ICON-1070":{"nm":"एंट्रीवे बास्केट टैग","de":"दहलीज़ के कोने में रखी टोकरी पर चिपका एक नाम-पर्चा। \"यहीं रख जाना\" जैसा एक बिना बोला वादा उस पर लिखा है। ख़ाली हो तब भी, किसी के मन का इंतज़ार करने वाली जगह कभी अकेली नहीं होती।"},"ICON-1071":{"nm":"एड्रेस कवर स्टिकर","de":"फेंकने वाले डिब्बे पर नाम छोड़कर बस पता मिटा दिया जाता है। सबको पता चले तो चले, नाम तक ठीक है, पर कहाँ रहते हो यह अपना ही राज़ रहे। यह एक परत उघेड़कर चिपकाते ही एक छोटी-सी राहत जन्म लेती है।"},"ICON-1072":{"nm":"स्नैक टिन लेबल","de":"डिब्बे में क्या है, यह एक नज़र में बता देने वाला लेबल। पर मज़े की बात यह कि \"स्नैक्स\" लिख दो, तो ढक्कन खोले बिना भी न जाने क्यों मन भरा-भरा लगने लगता है। भूख की ज़िम्मेदारी लेबल नहीं ले सकता, यह अलग बात है।"},"ICON-1073":{"nm":"छोटा नेकलेस पेंडेंट","de":"कपड़ों के भीतर चुपचाप शरीर की गर्मी बाँटता एक छोटा-सा दाना। किसी की नज़र न पहुँचे ऐसी जगह से हमेशा सटा रहने के कारण ही और भी प्यारा लगता है। सीने के पास साथ चलने वाला सबसे नज़दीकी दोस्त।"},"ICON-1074":{"nm":"पॉप्रिंट स्टैंप मैट","de":"पंजे पर हल्के-से दबाओ तो छोटे-छोटे पैरों के निशान क़तार में उभर आते हैं। कौन कहाँ से चला, यह काग़ज़ पर साफ़-साफ़ दर्ज एक दिन की सैर की डायरी। स्याही से रंगा पहला क़दम हमेशा सबसे साफ़ रहता है।"},"ICON-1075":{"nm":"फ़र ब्रश कैप","de":"कंघी में उलझे बालों को साफ़-सुथरे ढंग से संभालने वाली एक छोटी-सी टोपी। बाल झड़ने के मौसम में एक ही झटके में मुट्ठी-भर बाल जमा हो जाते हैं, यह कैप न हो तो पूरा घर रुई-सी बर्फ़ का मैदान बन जाए। बिना दिखे मेहनती एक सफ़ाईकर्मी।"},"ICON-1076":{"nm":"वॉक बैग केस","de":"सैर पर ले जाने वाले थैलों को सलीके से थामे रखने वाला छोटा-सा घर। जिसने पहले से साथ रख लिया हो वही चैन से टहल पाता है, यह यह केस रोज़ चुपचाप साबित करता है। भूल जाओ तो मुश्किल में डाल देने वाला वही एक थैला।"},"ICON-1077":{"nm":"नेम कवर टैग","de":"असली नाम को धीरे से ढँककर बस उपनाम छोड़ देने वाला टैग। दुनिया में एक ऐसी कोमलता भी होती है जिसे हर किसी के सामने दिखाने का मन नहीं करता। बस जानने वालों को ही मालूम वह पुकार, यहाँ महीन ढंग से छिपी है।"},"ICON-1078":{"nm":"वाटर बाउल मैट पैड","de":"पानी के कटोरे के नीचे बिछा मैं हमेशा गीला रहता हूँ। चारों ओर छलककर उछलने वाली बूँदों को अपनी ओर खींचकर, फ़र्श को सूखा रखता हूँ। कोई मेरी तारीफ़ नहीं करता, पर मुझे भी कोई शिकायत नहीं।"},"ICON-1079":{"nm":"टॉय मेंडिंग थ्रेड","de":"सिलाई उधड़ी गुड़िया को फेंका नहीं, दोबारा सिया जाता है। एक-एक टाँके से भरी हर जगह में, उस बच्चे के साथ बिताया वक़्त फिर से मज़बूत हो उठता है। मरम्मत आख़िर में, विदाई को चुपचाप टाल देने का काम है।"},"ICON-1080":{"nm":"मेमेंटो फ़ोटो नेकलेस","de":"सबसे खिलखिलाकर हँसती हुई एक तस्वीर को गले में पहनकर घूमने वाला मन। तस्वीर वाला वह दिन स्थिर होकर जड़ हो जाने के बजाय, हर क़दम के साथ हिलते-डुलते आज तक साथ चलता रहता है। वह अच्छा पल कभी थमता नहीं।"},"ICON-1081":{"nm":"मूड कलर चिप","de":"अगर मन का भी कोई रंग होता, तो आज तुम्हारा रंग क्या होता? चिप चुनकर मेज़ पर रखते ही, शब्दों में न बयां हो सकी भावना धीरे-धीरे फैलने लगती है। शाम की लाली हो या भोर की रोशनी, दोनों अच्छे—यह उस दिन के तुम्हें धीरे से दिखाने वाला एक छोटा-सा आईना है।"},"ICON-1082":{"nm":"टुडेज़ रिकॉर्ड मार्बल","de":"दिन ढलते ही, गोली के भीतर आज का दिन गोल होकर बँध जाता है। अच्छे किए काम और अटपटे रहे पल सब लुढ़कते हुए समेट लिए जाते हैं। हथेली पर रखो तो बीते कल का तुम थोड़ा गर्म लगता है, पीठ थपथपाकर कहता है आज भी अच्छे से जिया।"},"ICON-1083":{"nm":"प्रेज़ नोट जार","de":"अच्छे शब्द बहुत आसानी से बिखर जाते हैं, इसलिए एक-एक करके मोड़कर इस शीशी में भर दिया जाता है। तारीफ़ खुशबू की तरह जमा हो जाए, तो मन ख़ाली-सी रात में ढक्कन खोला जाता है। किसी की दी हुई एक कोमलता फिर से निकालकर पढ़ने पर, उस दिन की गर्माहट फिर से जी उठती है।"},"ICON-1084":{"nm":"रिकंसिलिएशन रिबन कॉर्ड","de":"उलझा हुआ मन गाँठ जैसा होता है; खोलने में भी उतनी ही मेहनत लगती है। दो लोग डोरी के दोनों सिरे थामकर धीरे-धीरे खींचें, तो पता ही नहीं चलता कब एक सुंदर रिबन बन जाता है। सुलह काटने का नहीं, फिर से बाँधने का काम है, यह डोरी चुपचाप बताती है।"},"ICON-1085":{"nm":"ग्रैटिट्यूड टोकन","de":"शुक्रिया कहने का शब्द होंठों से आसानी से न निकले, उस दिन इसकी जगह एक टोकन धीरे से थमा दिया जाता है। पाने वाला हाथ उसी छोटे-से वज़न से पूरा मन पढ़ लेता है। शब्दों से पहले पहुँचने वाली सच्चाई—एक गोल दाने में प्रेम भरकर पार जाता है।"},"ICON-1086":{"nm":"ब्रेक टाइम मार्कर","de":"दिन-भर दौड़ते रहे अभ्यास कक्ष को भी साँस लेने का एक पल चाहिए होता है। यह निशान दरवाज़े पर टाँग दो, तो वक़्त थोड़ी देर के लिए धीमा पड़ जाता है। विराम-चिह्न हो तभी गीत साँस ले पाता है, यह बात हाँफते हुए दिन जी चुका हर कोई जानता है।"},"ICON-1087":{"nm":"सीक्रेट फ़ीलिंग्स ड्रॉअर","de":"कुछ दिन ऐसे होते हैं जब दिल की हर बात खोलकर नहीं दिखाई जा सकती। ऐसे में मन के भीतर एक छोटी-सी दराज़ में दुख और सिहरन दोनों को चुपचाप रखकर बंद कर दिया जाता है। अभी छोड़ दो तो चलेगा—कभी धीरे-धीरे खोलकर सब सुलझाने का दिन आएगा ही।"},"ICON-1088":{"nm":"स्माइल स्टिकर रोल","de":"एक-एक चौकोर उतारो, तो एक हँसता चिह्न उँगली की नोक पर उतर आता है। नोटबुक के कोने में, दोस्त के लॉकर पर धीरे से चिपका देने वाली एक छोटी-सी ख़ुशी। काग़ज़ पर एक नन्हा सूरज उगे, तो उसे पाने वाले किसी का दिन थोड़ा उजला हो जाता है।"},"ICON-1089":{"nm":"वेल-विशेज़ बेल चार्म","de":"दूर बैठी तुम तक पहुँचने की चाहत एक घंटी में समा गई है। हिलाओ तो एक साफ़ आवाज़ ख़ैरियत पूछने की बात कह देती है। \"ठीक तो हो न\" पूछने की हिम्मत न जुटा पाए जिस दिन, यह छोटी-सी झंकार हवा पर सवार होकर पहले पहुँच जाती है।"},"ICON-1090":{"nm":"स्प्रिंग रेन कवर पिन","de":"बसंत की बारिश वाले दिन, जिन चीज़ों से हमें प्यार होता है वही सबसे जल्दी भीग जाती हैं। इस पिन से कवर को कसो, तो बूँदें बग़ल से बहकर निकल जाती हैं। किसी क़ीमती किताब को गले लगाने वाला मन—एक छोटी पिन ही उस कोमलता की जगह ले लेती है।"},"ICON-1091":{"nm":"समर कूलिंग स्टिकर","de":"कड़ी गर्मी से थके हाथ की पीठ पर बस एक चिपका दो। पुदीने जैसी ठंडक फैलते ही पसीना कुछ हद तक थम जाता है। बरामदे में लेटकर पंखा झलने वाली वह ठंडक, हथेली-भर काग़ज़ मन लगाकर नक़ल कर लेता है।"},"ICON-1092":{"nm":"ऑटम प्लेड क्लॉथ स्क्रैप","de":"शरद ऋतु के खेतों जैसा दिखने वाला चौखानेदार कपड़े का एक टुकड़ा। घिसी जगह पर किसी ने मेहनत से लगाई थिगली का निशान है यह। फेंके बिना सी-सिलाकर काम में लाने वाला मन—छोटे-छोटे कपड़े जुड़कर घिसे को फिर गर्मजोशी से जिला देते हैं।"},"ICON-1093":{"nm":"विंटर ग्लव क्लिप","de":"सर्दियों के दस्ताने न जाने क्यों बार-बार एक-एक करके भाग जाते हैं। इस क्लिप से दोनों को जोड़ दो, तो ठिठुरते हाथ रास्ता नहीं भटकते। खोना न पड़े यह चाहत एक छोटी-सी धातु में समाकर, दोनों को साथ-साथ थामे रखती है।"},"ICON-1094":{"nm":"रेनी सीज़न वॉटरप्रूफ़ टैग","de":"बरसात के मौसम में नाम-पर्चा भी बारिश में फैल जाता है। वॉटरप्रूफ़ परत चढ़ी यह टैग मूसलाधार बारिश में भी लिखावट बचाए रखती है। बारिश थमने के बाद भी साफ़ रह जाने वाली एक पंक्ति—किसकी है यह अंत तक न भूल जाए, इसीलिए।"},"ICON-1095":{"nm":"फ़र्स्ट स्नो कीपिंग जार","de":"पहली बर्फ़ हाथ छूते ही ग़ायब हो जाती है, इसलिए कम-से-कम वह सिहरन ही एक शीशी में बचाकर रख ली गई है। शीशे में क़ैद असल में बर्फ़ नहीं, उस दिन धड़कता रहा दिल है। हिलाओ तो एक पूरी सर्दी फिर से बिखर उठती है, उसी सुबह में वापस ले जाती हुई।"},"ICON-1096":{"nm":"होलिडे एनवेलप बैंड","de":"त्योहार के लिफ़ाफ़े पर लपेटी एक लाल पट्टी। भीतर रखी चीज़ से कहीं ज़्यादा बड़ा है देने वाले हाथ का प्रेम, यह सब जानते हैं। अच्छे से रहने की दुआ और सौभाग्य दोनों साथ बाँधने वाला मन, इसी महीन पट्टी में सलीके से बँधा है।"},"ICON-1097":{"nm":"पिकनिक डिश बैंड","de":"चटाई बिछाकर टिफ़िन खोलो तो हवा बार-बार ढक्कन उठाती रहती है। इस बैंड से बर्तन कसकर बाँध दो, तो पिकनिक बिखरने नहीं पाती। साथ लाया एक वक़्त का खाना आख़िर तक बचाए रखने का मन, एक छोटी पट्टी में समाया है।"},"ICON-1098":{"nm":"सीज़नल सेंट सैंपल कार्ड","de":"खोले बिना ही मौसम पता चल जाए, इसलिए एक कार्ड में उस ऋतु की महक भर दी गई है। बसंत में फूल, शरद में सूखी पत्तियों की गंध। नाक की नोक पर छूते ही पूरा मौसम याद आ जाता है—\"यही तो है अप्रैल की हवा।\""},"ICON-1099":{"nm":"प्राइस टैग क्लिपबोर्ड","de":"बार-बार उड़ जाने वाली क़ीमत-पर्ची की सिरदर्दी को इस एक क्लिपबोर्ड ने हमेशा के लिए शांत कर दिया। अंकों को मज़बूती से थामकर ग्राहक के सामने सीधा पेश करता है। व्यापार की पहली नमस्ते हमेशा एक बेढब न होने वाली, ईमानदार पंक्ति से शुरू होती है।"},"ICON-1100":{"nm":"ओपन साइन फ़्लिप बोर्ड","de":"दरवाज़े पर इस पट्टिका को पलटकर टाँग दो, तो दुकान आख़िरकार जाग उठती है। \"तैयारी में\" से \"आइए स्वागत है\" तक। दिन की शुरुआत का ऐलान करने वाला एक छोटा-सा संकेत—मालिक का हाथ हर सुबह सबसे पहले यहीं छूता है।"},"ICON-1101":{"nm":"कूपन मुहर पैड","de":"सारे दस खाने भर जाएं तो न जाने क्यों कुछ अच्छा होने लगता है। हर मुहर किसी नियमित ग्राहक का एक कदम है, समय के साथ जमा हुआ स्नेह है। पैड पर स्याही सूखने तक दबे हर निशान में, फिर आने का एक छोटा वादा जीवंत साँस लेता है।"},"ICON-1102":{"nm":"पेपर बैग हैंडल कैप","de":"कागज़ के थैले का हैंडल वज़न के आगे हमेशा कमज़ोर पड़ता है। यह कैप लगाते ही टूटने को आई डोरी मज़बूत हो जाती है। अंदर रखी चीज़ को सुरक्षित घर तक पहुँचाने की चाह—एक छोटा-सा पुर्ज़ा उस सफ़र को आख़िर तक थामे रखता है।"},"ICON-1103":{"nm":"काउंटर सिक्का ट्रे","de":"हाथ से हाथ में खुल्ले पैसे देने की झिझक को यह ट्रे चुपचाप हल्का कर देती है। सिक्कों की खनक अपनी जगह ढूँढ लेने की आवाज़। लेन-देन इतना गर्मजोशी भरा हो जाता है, बस इस गोल-से ख़याल की बदौलत।"},"ICON-1104":{"nm":"पॉइंट स्टैम्प चिप","de":"आज उठाए गए कदम एक चिप में करीने से जमा होते जाते हैं। यह कैसा अजब हिसाब है कि जितना जमा होता है, दिल उतना हल्का लगता है। थोड़ा-थोड़ा भरते जाने का सुख, ख़ाली मटके को धीरे-धीरे भरते देखने की ख़ुशी जैसा है।"},"ICON-1105":{"nm":"शेल्फ़ नंबर पिन","de":"हर शेल्फ़ पर एक छोटा-सा नंबर स्नेह से टंका होता है। कहाँ क्या रखा है, यह चुपचाप बताने वाला मार्गदर्शक। भटकने न देने के लिए पहले से जगह बता देने का यह मन—व्यवस्था में भी ऐसी गर्माहट बसती है।"},"ICON-1106":{"nm":"चखने वाली सींक कप","de":"चखने का एक टुकड़ा सींक में लगाकर आगे बढ़ाता छोटा-सा कप। झिझकता ग्राहक भी इस एक कौर पर धीरे से दिल खोल देता है। \"एक बार लीजिए ना\" कहने वाली उदारता सींक की नोक पर लटकी, पहली बार आए किसी का कदम रोक लेती है।"},"ICON-1107":{"nm":"रिज़र्वेशन लिस्ट होल्डर","de":"आज आने वाले मेहमानों के नाम इस होल्डर में करीने से खड़े हैं। यह स्नेहिल वादा कि इंतज़ार का भी अपना क्रम होता है। एक कागज़ को सीधा खड़ा रखना, किसी के दिन का स्वागत करने की पहली सजग तैयारी बन जाती है।"},"ICON-1108":{"nm":"दीवार फ़ोटो डोरी क्लिप","de":"दीवार पर डोरी बाँधकर तस्वीरें एक-एक करके क्लिप से टाँगी जाती हैं। मुस्कुराते पल कपड़ों की तरह पास-पास लटककर सूखते हैं। धूप आती जगह पर यादें फैला दो, तो हर बार गुज़रते वक़्त उस दिन की हँसी फिर से लहरा उठती है।"},"ICON-1109":{"nm":"मिनी रग कोना","de":"कमरे के किनारे बिछी एक छोटी-सी दरी। ठंडे फ़र्श पर सबसे पहले गर्माहट फैलाने वाली जगह। नंगे पाँव सबसे पहले जिस बित्ते को छूते हैं—घर लौटे किसी के पैर की उँगलियाँ यहीं आकर आख़िरकार निश्चिंत और सुस्त होती हैं।"},"ICON-1110":{"nm":"नेमप्लेट पर्दा कपड़ा","de":"नामपट्टी को धीरे से ढक देने वाला कपड़े का एक टुकड़ा। नाम को कुछ देर छुपाए रखना भी घर-गृहस्थी की अपनी एक शान है। भीतर और बाहर की सीमा पर सुंदर ढंग से पड़ा एक आँचल—आज चुपचाप आराम करने की चाह मुलायमियत से लटक जाती है।"},"ICON-1111":{"nm":"लाइट कॉर्ड क्लिप","de":"लटकती लाइट की डोरी को यह क्लिप सलीक़े से थाम लेता है। रोशनी बिखरने न पाए, ऐसे राह को सीधा करने वाला हाथ। शाम उतरते वक़्त बिखरी एक डोरी को सँवार दो, तो कमरे की रोशनी और दिल दोनों उतने ही शांत हो जाते हैं।"},"ICON-1112":{"nm":"पोस्टर मैग्नेट कैप","de":"पोस्टर को दीवार पर लगाने वाला छोटा-सा चुंबकीय कैप। एक भी पिन का छेद किए बिना कागज़ अपनी जगह थामे रहता है। जो चीज़ें प्यारी हों उन्हें छूने वाला हाथ हमेशा नरम होता है—बिना नुक़सान पहुँचाए रखने का यह मन यहाँ बसा है।"},"ICON-1113":{"nm":"पर्दा तासल डोरी","de":"पर्दे के छोर को एक तरफ़ बाँध रखने वाली झालरदार डोरी। सुबह की धूप आने का रास्ता सुंदर ढंग से खोल देती है। झालर वाली डोरी को एक बार खींचो, तो कमरे में एक रोशन दिन फ़ौरन भरता चला आता है और ठहर जाता है।"},"ICON-1114":{"nm":"कैंडल होल्डर लेबल","de":"कैंडल होल्डर पर चिपका एक छोटा-सा लेबल। कौन-सी ख़ुशबू जल रही है, कब पहली बार जलाई गई थी, साफ़-साफ़ लिखा जाता है। पसंदीदा ख़ुशबू को नाम देने का यह काम—यह सलीक़ा कमरे की हवा को और भी स्नेहिल बना देता है।"},"ICON-1115":{"nm":"डिस्प्ले शेल्फ़ रबर पैर","de":"शेल्फ़ को डगमगाने से रोकते चार रबर के पैर। दिखाई न देने वाली जगह से चुपचाप वज़न सहते हैं। छोटे और नीचे होने से नज़र नहीं आते, पर सबसे नीचे टिके रहने वाला ही आख़िर सबसे लंबे समय तक साथ निभाता है।"},"ICON-1116":{"nm":"दिशा संकेत तीर चार्म","de":"किस तरफ़ जाना है, यह सोचकर झिझकने वाले के लिए एक तीर चुपचाप दिशा बता देता है। रास्ता न भटकने का स्नेहिल इशारा। हर चौराहे पर किसी ने पहले से जो मन रखा है, उसी की बदौलत आज भी बिना भटके आगे बढ़ा जाता है।"},"ICON-1117":{"nm":"द्वीप निमंत्रण चाबी डोरी","de":"द्वीप पर बुलाने वाले के हाथ में थमाई जाने वाली चाबी की डोरी। इसे ले लो, तो अब तुम भी यहाँ के परिवार का हिस्सा हो। किसी अनजान मेहमान को गर्मजोशी से भीतर बुलाने का यह स्वागत, डोरी के छोर पर लटके एक छोटे वादे में मज़बूती से समाया है।"},"ICON-1118":{"nm":"नज़दीकी तापमान चिप","de":"दो लोगों के बीच का तापमान एक चिप चुपके से बता देती है। अभी भी अजनबी-सी नीली रोशनी है, या कभी की गर्म लाल हो चुकी है। स्नेह गहरा होने की रफ़्तार नापना मुश्किल है, पर हथेली उस गर्माहट को सबसे पहले पहचान लेती है।"},"ICON-1119":{"nm":"पसंद नमूना बक्सा","de":"किसी को क्या पसंद है, यह अभी पता न हो तो छोटे-छोटे नमूने एक बक्से में भरकर सामने रख दिए जाते हैं। चुनने के आनंद में पसंद धीरे-धीरे बढ़ती है। कौन-सी चीज़ आख़िर तुम्हारी बनेगी—बक्से में रोमांचक संभावनाएँ भरी पड़ी हैं।"},"ICON-1120":{"nm":"देखभाल आरक्षण पिन","de":"किसी की देखभाल करने का वादा इस एक पिन में साफ़-साफ़ टंका है। नाम और समय लिख दो, तो दिल भटकता नहीं। एक-दूसरे के बच्चों को बारी-बारी से देखने वाली वह स्नेहिल आपसदारी, यहीं जीवंत साँस लेती है।"},"ICON-1121":{"nm":"विकास स्मृति कैप्सूल","de":"जैसे चौखट पर नापे गए क़द के निशान एक-एक कर जमा होते जाते हैं, यह कैप्सूल कल के तुम्हें चुपचाप बंद करके रख देता है। बहुत आगे किसी दिन ढक्कन खोलोगे तो पता चलेगा, वह छोटा-सा कदम कितनी दूर तक चल आया है।"},"ICON-1122":{"nm":"पहली मुलाक़ात स्मृति पट्टी","de":"पहली बार हाथ थामने की वह सिहरन एक पट्टी में धीरे से बाँध दी जाती है। गाँठ खोलने के लिए नहीं बँधी, बल्कि उस दिन की गर्माहट को कलाई पर हमेशा ज़िंदा रखने के लिए वहीं ठहरी रहती है।"},"ICON-1123":{"nm":"माय रूम सजावट लेबल","de":"\"यह मेरी जगह है।\" जैसे ही एक छोटा-सा लेबल मेज़ के कोने पर चिपकता है, अजनबी लगता कमरा आख़िरकार साँस लेकर माय रूम बन जाता है। नाम की पर्ची वह पहली जगह है जहाँ दिल टिककर बैठता है।"},"ICON-1124":{"nm":"घनिष्ठता कंचा जार","de":"हिलाओ तो टुनटुन, दोनों के बीच एक कदम क़रीब आने की आवाज़ लुढ़कती है। जब जार लबालब भरने को होगा, तब तो बस नाम पुकारते ही हँसी सबसे पहले स्वागत में आ खड़ी होगी।"},"ICON-1125":{"nm":"डेब्यू तैयारी सील","de":"लिफ़ाफ़ा बंद करने वाला आख़िरी पन्ना। यहाँ तक तैयारी थी, अगला पन्ना पलटते ही मंच है। उँगली की नोक से ज़ोर से दबाते हुए ट्रेनी अपनी साँस सँभालता है। आख़िरकार, शुरुआत हो रही है।"},"ICON-1126":{"nm":"पानी","de":"सबसे आम है, इसीलिए सबसे क़ीमती है। बत्तियाँ बुझी सुबह के अभ्यास कक्ष में, एक घूँट भर बैठे हुए किसी को फिर से खड़ा कर देता है। बिना अपने आकार के, किसी भी बर्तन में समा जाने वाली स्नेहिलता।"},"ICON-1127":{"nm":"निर्मल जल","de":"तली के कंकड़ तक चमकाकर दिखा देने वाली पारदर्शिता। पहाड़ी झरना अपनी निर्मलता पर कभी घमंड नहीं करता। जिस दिल में कुछ छुपाना नहीं होता, वह हमेशा ऐसे ही तली तक झलकता है।"},"ICON-1128":{"nm":"समुद्री जल","de":"जीभ पर छूते ही दूर से लहरें उमड़ आती हैं। एक खारे घूँट में क्षितिज, समुद्री पक्षी और छूटा हुआ बंदरगाह पूरा-का-पूरा घुला होता है। समुद्र हमेशा एक नमकीन स्मृति बनकर रह जाता है।"},"ICON-1129":{"nm":"बर्फ़","de":"हथेली पर धीरे-धीरे छोटी होती जाती है, जितना पकड़ो उतनी ही ग़ायब होती जाती है। दिखने में कठोर, पर जानती है कि आख़िर में पानी में लौट जाना है। बर्फ़ वह नदी है जिसने पल भर के लिए साँस रोक रखी है।"},"ICON-1130":{"nm":"बर्फ़ का गोला","de":"कसकर बनाया गया एक गोला गली को चीरता हुआ सफ़ेद उड़ान भरता है। खिलखिलाती हँसी और ठंड से लाल हुए गाल। सर्दी बच्चों के हाथ में धीरे से जो सबसे सफ़ेद खिलौना थमा देती है, यही है।"},"ICON-1131":{"nm":"मिट्टी","de":"बीज को गोद में लेती है, बारिश का पानी पीती है, और गुज़रते क़दमों को चुपचाप सह लेती है। सब कुछ अपने आग़ोश में लेने वाली काली त्वचा। जो कुछ भी उगता है, उसकी पहली जगह में यही एक मुट्ठी बसती है।"},"ICON-1132":{"nm":"उपजाऊ मिट्टी","de":"उँगलियाँ गहरे धँसाओ तो एक काली चिकनाई मुलायमियत से लिपट जाती है। दादी की सब्ज़ी की क्यारी हर साल हरी-भरी रहने का राज़ यहीं छुपा था। अच्छी तरह पकी मिट्टी खाद की महक से भरपूर फ़सल की फुसफुसाहट करती है।"},"ICON-1133":{"nm":"चिकनी मिट्टी","de":"नमी सोखते ही यह किसी भी आकार को सहज भाव से स्वीकार लेती है। हाथ के इशारे पर कभी चिड़िया बनती है, कभी कटोरा, यह स्नेहिल देह। चाक घूमते रहने के दौरान, मिट्टी की एक मुट्ठी आख़िरकार सपना देखना शुरू करती है।"},"ICON-1134":{"nm":"रेत","de":"उँगलियों के बीच से धीरे-धीरे फिसल जाने वाले महीन कण। जितना पकड़ो उतनी तेज़ी से बह जाती है, हर बार समय जैसी लगने लगती है। समुद्र-तट की एक मुट्ठी में असंख्य बीते कल सोए पड़े हैं।"},"ICON-1135":{"nm":"कंकड़","de":"नाले के किनारे गोल-गोल घिसे हुए पत्थर। नुकीले कोने मिटने तक पानी ने बरसों-बरस सहलाया है, इसी का निशान हैं ये। जितने दूर तक लुढ़के हों, उतने ही सुंदर ढंग से हाथ में आकर बैठते हैं।"},"ICON-1136":{"nm":"पत्थर","de":"राह किनारे बेपरवाही से पड़ा एक टुकड़ा। कोई इसे ठोकर मारकर आगे बढ़ जाता है, तो कोई चुपचाप उठाकर मीनार बना देता है। एक ही पत्थर दिल के हिसाब से कभी बोझ बनता है, तो कभी मन्नत।"},"ICON-1137":{"nm":"चौरस पत्थर","de":"पुराने महल के आँगन को पार करता एक चौड़ा-सा पत्थर। सैकड़ों वर्षों के जूते इस पर चलते रहे हैं, जिससे बीचोबीच एक गड्ढा-सा बन गया है। एक-एक कदम रखने वाला हर इंसान, वहाँ समय की एक और परत जोड़ जाता है।"},"ICON-1138":{"nm":"चूना पत्थर","de":"कभी समुद्र रहे इस दौर की सीपियाँ परत-दर-परत जमकर सफ़ेद पत्थर बन गईं। भट्टी में डालो तो चूने में घुलकर दीवारों को चमकीला सफ़ेद रंग देती हैं। शांत दिखने पर भी यह एक पूरे युग को समेटे पत्थर है।"},"ICON-1139":{"nm":"कोयला","de":"काले होकर सो गया पुराना जंगल। करोड़ों साल पहले के फ़र्न धरती में गहरे दबकर कठोर हो गए हैं। आग लगाओ तो बहुत दिनों से दबी सूरज की रोशनी फिर से धधककर जाग उठती है।"},"ICON-1140":{"nm":"चारकोल","de":"आग को अपने भीतर थामता है, पर धुएँ को चुपचाप निगल जाता है। भट्टी में काली होकर दबी लकड़ी, अंगीठी पर बिना कुछ कहे लाल होकर खिल उठती है। जो जितना चुप रहता है, वह उतनी ही देर तक गर्म रहता है।"},"ICON-1141":{"nm":"टहनी","de":"टूटने से बचने के लिए चुपचाप मुड़ती आई टहनी झुकने का हुनर जानती है। कठोर हवा को सहते हर जगह पर एक गाँठ बन जाती है, और सच्ची मज़बूती आख़िर अच्छी तरह मुड़ पाने का ही निशान है।"},"ICON-1142":{"nm":"लट्ठा","de":"कटे हुए वलयों में सौ बसंत और जाड़े गोल-गोल परतों में तह हो गए हैं। एक पेड़ ने जो पूरा जीवन जिया, वह पूरा-का-पूरा लेटा हुआ है, अब चुपचाप घर का खंभा बनने की अपनी बारी का इंतज़ार करता हुआ।"},"ICON-1143":{"nm":"इमारती लकड़ी","de":"रंदा हर बार गुज़रता है तो एक-एक परत सुगंधित रेशा उघड़ता जाता है। खुरदरी लकड़ी चिकनी होते-होते, बुरादा फ़र्श पर पीली बर्फ़ जैसा जमा होता जाता है। सँवारता हाथ इसकी उपयोगिता को जगा देता है।"},"ICON-1144":{"nm":"तख़्ता","de":"फ़र्श बिछाता है, चौकी बनाता है, बाड़ लगाता है। सीधे काटे गए एक-एक तख़्ते जब इकट्ठे होते हैं, तब जाकर इंसानों के रहने की जगह खड़ी होती है। मामूली चीज़ें ढेर होकर आशियाना बन जाती हैं।"},"ICON-1145":{"nm":"बाँस","de":"भीतर से खोखला होकर भी हवा के आगे सीधा खड़ा रहता है। हर गाँठ पर टूटकर फिर से नए सिरे से उगने का वह जज़्बा, पुराने विद्वान अपनाना चाहते थे। ख़ाली होकर भी और भी अकड़कर खड़े रहने वाली चीज़ यहाँ है।"},"ICON-1146":{"nm":"कॉर्क","de":"ज़ोर से दबाकर छोड़ दो तो फिर अपनी असली मोटाई में फूल जाता है। हल्का पर हठीला यह रेशा देखकर पता चलता है कि नरमी कभी कमज़ोरी नहीं होती। बोतल के ढक्कन से लेकर नोटिस बोर्ड तक, यह चुपचाप सहारा देता रहता है।"},"ICON-1147":{"nm":"घास","de":"कुचली जाए तो भी अगली बारिश में फिर खड़ी हो जाती है। बिना किसी एक नाम के पूरे मैदान को ढँक लेने वाला हरा हठ। छोटा समझकर हल्के में मत लेना, बसंत की पहली ख़बर हमेशा इसी नीची जगह से आती है।"},"ICON-1148":{"nm":"पुआल","de":"शरद ऋतु की फ़सल कटने के बाद खेत में सुनहरा बचा रह जाने वाला। बुनो तो छत बन जाए, बिछाओ तो गर्म बिस्तर। हर दाना दे चुकने के बाद भी आख़िर तक इंसान को ढँकने वाला मन है यह।"},"ICON-1149":{"nm":"सरकंडा","de":"हवा छूकर गुज़रे तो सरसराहट के साथ पूरा नदी-किनारा गा उठता है। भीतर से खोखला होने के कारण और दूर तक रोने वाला तना। लहराता हुआ यह रूप ही इसका गीत है, इसमें सरकंडे को रत्ती भर शर्म नहीं आती।"},"ICON-1150":{"nm":"कपास","de":"पकी हुई फली टप से फूटे तो एक छोटा-सा बादल खिल उठता है। यह हल्की, मुलायम रुई धागा बनकर, कपड़ा बनकर, ठंडी सर्दी की रात में किसी के कंधों को चुपचाप गर्माहट देती है।"},"ICON-1151":{"nm":"भेड़ ऊन","de":"हाथ पर मलो तो एक चिकनाई घूमने लगती है और गर्माहट धीरे से बनी रहती है। ठंडे पहाड़ को सहने के लिए भेड़ ने अपने बदन पर लपेटा हुआ यह कोट। वह छँटी हुई गर्माहट अब आकर इंसान की सर्दी में समा जाती है।"},"ICON-1152":{"nm":"धागा","de":"दिखे न दिखे जैसा महीन होकर भी, टूटे हुए दो सिरों को फिर जोड़ने वाला हमेशा यही होता है। एक लड़ी अकेली कमज़ोर होती है, पर बुनी जाए तो एक पूरा कपड़ा बन जाती है। जोड़ने के काम में मोटाई कभी मायने नहीं रखती।"},"ICON-1153":{"nm":"कपड़ा","de":"बाना और ताना अनगिनत बार आपस में गुँथकर एक पूरा टुकड़ा बनाते हैं। अकेले खुल जाने वाले धागे एक-दूसरे को कसकर थाम लेते हैं, यही इसका नतीजा है। जितनी घनी बुनाई उतनी ज़्यादा गर्माहट, यह बात इंसानों के बीच भी उतनी ही सच है।"},"ICON-1154":{"nm":"चमड़ा","de":"जितना इस्तेमाल होता है, हाथों का स्पर्श उतना ही रचता जाता है और धीरे-धीरे अपने मालिक जैसा दिखने लगता है। शुरू की अकड़न ढलती जाती है, इस बीच रंग गहरा होता है और बुनावट मुलायम पड़ती है। समय ने जो चमक खोदी है, उसकी नक़ल कोई नहीं कर सकता।"},"ICON-1155":{"nm":"पंख","de":"हथेली पर रखो तो भी वज़न महसूस न हो, इतना हल्का। आसमान में उड़ने की स्मृति जिसमें वैसी ही बसी रह गई है, एक लड़ी। सबसे हल्की चीज़ ही सबसे ऊँचा उड़ती है, यह बात कभी मत भूलना।"},"ICON-1156":{"nm":"सीप का ख़ोल","de":"\"कान से लगाकर देखो\" कहती दादी की बात अचानक याद आ जाती है। भीतर की इंद्रधनुषी चमक में छूटा हुआ समुद्र पूरा-का-पूरा उकेरा है, इसलिए ख़ाली ख़ोल से भी एक बीते ज़माने की लहरें सुनाई देती हैं।"},"ICON-1157":{"nm":"मूँगा","de":"पत्थर जैसा कठोर हो गया, पर कभी यह ज़रूर साँस लेता एक समूह था। धीमे समुद्र में सैकड़ों साल लगाकर अपनी शाख़ें फैलाता है। सबसे मज़बूत शाख़ सबसे लंबे इंतज़ार के बाद ही उगती है।"},"ICON-1158":{"nm":"मोती","de":"रेत के एक कण की खटक सही न पाकर, सीप ने उसे चुपचाप रोशनी में लपेट दिया। दर्द को गोल आकार में समेटो तो यह ऐसी ही चमकीली बन जाती है, यह समुद्र की दी हुई एक छोटी-सी सांत्वना है।"},"ICON-1159":{"nm":"समुद्री घास","de":"भाटे के समय चट्टानों पर फिसलती हुई फैली हरी पट्टी। हाथ में लो तो तेज़ समुद्री गंध छा जाती है। बिना जड़ के, धारा के सहारे अपने बदन को सौंपे हुए, समुद्र अपना बाग़ चुपचाप सँवारता रहता है।"},"ICON-1160":{"nm":"सूखा समुद्री शैवाल","de":"एक काली चादर को आँच पर हल्का सेंको तो वह हरी होकर एक सोंधी महक फैला देती है। ताज़े पके चावल में उसे लपेटने वाली वह सुबह। पतली-सी होकर भी एक वक़्त के भोजन की ख़ुशी को भरपूर समेट लेती है।"},"ICON-1161":{"nm":"नमक","de":"मैं समुद्र की धूप में छोड़ी हुई सफ़ेद क्रिस्टल हूँ। एक चुटकी से फीका शोरबा गहरा हो जाता है, पर हाथ फिसल जाए तो हर स्वाद दब जाता है। सही नाप जानने वाली उँगलियाँ ही मुझे ठीक से बरत पाती हैं।"},"ICON-1162":{"nm":"शीशे का टुकड़ा","de":"टूटने की उसी जगह पर आख़िरकार रोशनी मोड़कर इंद्रधनुष खिलाता है। साबुत रहते हुए जिस हुनर का पता ही नहीं था। टूटी चीज़ में भी धूप बाँटने का हिस्सा बचा रहता है, यह खिड़की के पास पड़ा टुकड़ा चुपचाप बता जाता है।"},"ICON-1163":{"nm":"काँच","de":"पारदर्शी होने का मतलब सिर्फ़ यह नहीं कि कुछ छुपाना नहीं है। रोशनी को ज्यों-का-त्यों आर-पार जाने देने के लिए इसने अपना रूप ही मिटा दिया है। बिना दिखे वहाँ टिके रहने के काम में भी, हाथ छूते ही एक ठंडी सफ़ाई महसूस होती है।"},"ICON-1164":{"nm":"काँच की बोतल","de":"भीतर ख़ाली होना ज़रूरी है, तभी कुछ समा सकता है। जैम हो, जंगली फूलों की मुट्ठी हो, या मोड़कर रखी चिट्ठी—जो भी भीतर आए, उसी से नाम बदल जाता है। ख़ालीपन से न डरने वाला बर्तन ही सबसे उदार होता है।"},"ICON-1165":{"nm":"ख़ाली बोतल","de":"आख़िरी घूँट पीने के बाद जो सन्नाटा आता है, वह मुझे पसंद है। कोई मुझे फेंक देता है, कोई धोकर खिड़की की चौखट पर रखकर मुझमें धूप भर देता है। ख़त्म हो चुकी जगह पर फिर से काम आना, यही ख़ाली हो चुकी चीज़ों का दूसरा जीवन है।"},"ICON-1166":{"nm":"काग़ज़","de":"कुछ भी लिख लेने की तैयारी में मैं सफ़ेद फैला रहता हूँ। पहली पंक्ति में झिझकते किसी के दिल में सबसे देर तक झाँकने वाला हमेशा मैं ही होता हूँ। ख़ाली पन्ने का धीरज स्याही से एक बित्ता ज़्यादा गहरा होता है।"},"ICON-1167":{"nm":"पुराना काग़ज़","de":"पीला पड़ जाना बुढ़ापा नहीं, सहनशीलता है। हर तह में खोलकर पढ़ने वाले हाथों की गर्माहट रच-बस गई है। पुराना काग़ज़ भुला न दिया जाए, इसलिए अपने ही रंग में बीत गया समय लिखकर रखता है।"},"ICON-1168":{"nm":"स्याही","de":"एक बूँद से शुरू होकर वाक्य बनती है, सूखने पर एक वादे की तरह रह जाती है। फैल जाए तो जितना फैली उतना ही उस दिन का निशान बन जाती है। चीज़ों को वापस न लौटने लायक़ बनाना मेरा काम है, इसलिए लोग मुझे एक बार फिर सोच-समझकर टिकाते हैं।"},"ICON-1169":{"nm":"लौह अयस्क","de":"ज़मीन के भीतर लाल नींद सोता रहा पत्थर हूँ मैं। एक बार आग से गुज़रकर ही आख़िरकार अपने भीतर का लोहा सौंपता हूँ। कठोरता शुरू से कठोर नहीं होती, वह तपिश से गुज़रने के बाद मिला हुआ नाम है।"},"ICON-1170":{"nm":"लोहे की सिल्ली","de":"अयस्क आग सहने के बाद ही एक ढेले में ठंडा हुआ। यह ठंडा, भारी आकार पुल भी बनता है, तलवार भी, कुदाल भी। मेरा उपयोग अभी तय नहीं हुआ, इसलिए मैं कुछ भी बन सकता हूँ।"},"ICON-1171":{"nm":"ताँबे का अयस्क","de":"कच्चे सेब जैसी हरी ज़ंग ओढ़े मिट्टी से बाहर निकला हूँ। पिघलाओ तो घंटी बजती है, मूर्ति खड़ी होती है, तार में बिजली बहती है। अँधेरी ज़मीन में सोते हुए भी मैं हमेशा किसी न किसी नाम से पुकारे जाने की अपनी बारी का इंतज़ार करता रहा।"},"ICON-1172":{"nm":"ताँबे की सिल्ली","de":"लंबे समय पास रखो तो यह अपने हाथों से नीला परिधान सिल लेती है। कोई उस रंगत को दोष कहता है, तो कोई उसे बरसों की छाप मानकर सहलाता है। अपने बदलते रंग से न शर्माने वाली धातु ही सबसे लंबे समय प्यार पाती है।"},"ICON-1173":{"nm":"सोने का अयस्क","de":"नदी की रेत को बार-बार छानकर मिला एक कण हूँ। दुर्लभ होने से क़ीमती नहीं, बल्कि कभी न बदलने से क़ीमती हूँ। न ज़ंग खाने वाले दिल जैसा बनने की सीख देते हुए पुराने लोग इसे हाथ में थमाकर निशानी के तौर पर देते थे।"},"ICON-1174":{"nm":"सोने की सिल्ली","de":"न धुँधलाते, न ज़ंग खाते, एक ढेले की तरह पड़ी रहती हूँ। लोगों के लालच की सबसे ज़्यादा बातें सुनी हैं, फिर भी मुझे ख़ुद कुछ नहीं चाहिए। बस चमकने के काम के प्रति ईमानदार एक भारी-भरकम ख़ामोशी हूँ।"},"ICON-1175":{"nm":"कबाड़ धातु","de":"उपयोगिता ख़त्म नहीं हुई, बल्कि अगली उपयोगिता का इंतज़ार हो रहा है। टूटी कीलें और पिचके डिब्बे एक जगह जमा होकर फिर तेज़ आग से मिलते हैं। मेरे लिए \"फेंक दिया गया\" शब्द का मतलब है, कुछ देर आराम करना।"},"ICON-1176":{"nm":"पेच","de":"अकेले मैं कुछ नहीं कर सकता। घुमाकर धँसते हुए दो तख़्तों को कसकर जोड़ने पर ही आख़िर अपना हिस्सा निभाता हूँ। छोटे बदन से बड़ी चीज़ को थामने का हुनर, इस कसने वाली ताक़त में भी मेहनत बसी है।"},"ICON-1177":{"nm":"कील","de":"एक बार धँस जाऊँ तो आसानी से पीछे नहीं हटता। हथौड़े की हर चोट से जो गहरा होता है, वह घाव नहीं, वादा है। कुछ भी मज़बूती से जोड़ने का काम हो, तो मैं ख़ुशी-ख़ुशी अपना सिर आगे कर देता हूँ।"},"ICON-1178":{"nm":"दाँतेदार पहिया","de":"बग़ल वाले के दाँत धकेलते हुए साथ में घूमता हूँ। अकेले तेज़ भागने की जगह पास वाले की रफ़्तार से क़दम मिलाना जानता हूँ। जैसे घड़ी में दाँत मिलने पर ही समय बहता है, वैसे ही मैं मानता हूँ कि तालमेल ही असली गति है।"},"ICON-1179":{"nm":"स्प्रिंग","de":"जितना दबाया जाए, उतनी ही ज़ोर से भीतर वापस लौटने की ताक़त जमा होती जाती है। झुकना हार मानना नहीं, फिर से खुलने की तैयारी है। जितना धक्का सहा, उतना ही उछल जाने वाला यह छोटा-सा कुंडल, जहाँ लचीलापन ही असली मज़बूती है।"},"ICON-1180":{"nm":"तार","de":"बाहर से एक सीधा-सादा आवरण, भीतर से बिना रुके बहता रास्ता। दिखाई न देने वाली जगहों से रोशनी और आवाज़ ढोता हूँ। जैसे मंच के पीछे चुपचाप जोड़ता कोई हाथ, न दिखने के कारण ही मैं ज़्यादा भरोसेमंद रास्ता हूँ।"},"ICON-1181":{"nm":"बैटरी","de":"आधे दिन की रोशन धूप को छोटे-से बदन में करीने से समेट लेती है। ख़त्म होने पर बस फिर भर लो, यह कहते हुए ख़ालीपन को कभी अंत नहीं मानती। किसी की लंबी रात रोशन करने वाली एक छोटी-सी शाम अपने भीतर सँजोए रखती है।"},"ICON-1182":{"nm":"बल्ब","de":"एक महीन तार लाल तपकर अँधेरे को पीछे धकेलता है। यह अपना बदन जलाकर कमरा गर्म नहीं करता, रोशन करता है। जलने के पल में सबसे ज़्यादा तपता है, इसीलिए सबसे रोशन, एक पल भर का छोटा-सा सूरज।"},"ICON-1183":{"nm":"लेंस","de":"बिखरती रोशनी को समेटकर एक बिंदु पर साफ़-साफ़ खड़ा कर देता है। दूर के तारे भी, हथेली पर छोटे अक्षर भी, चुपचाप बुला लेता है। देखने के काम में मदद करते हुए ख़ुद अपना रूप छुपा लेने वाला, एक साफ़, गोल दलाल।"},"ICON-1184":{"nm":"रबर","de":"दबाओ या खींचो, आख़िर में अपनी जगह लौट आता है। नरम कहकर हँसने वाले भी बारिश के दिन मुझे ही पहनना चुनते हैं। कठोर झटके को नरमी से सह लेने का काम—इस नरमाहट में भी हठ बसता है।"},"ICON-1185":{"nm":"प्लास्टिक का टुकड़ा","de":"मुख्य ढाँचे से टूटकर अलग हुआ एक छोटा-सा टुकड़ा हूँ। फेंके जाने के क़रीब था, पर कई जमा हों तो फिर नई चीज़ बन जाते हैं। छोटा होने से हल्का नहीं, हल्का होने से दूर तक जा सकने वाला, किसी का एक हिस्सा हूँ।"},"ICON-1186":{"nm":"रस्सी","de":"कई लड़ें बटकर ही आख़िर एक डोरी बनती है। अकेली आसानी से खुल जाती है, पर बुनी जाए तो जहाज़ भी खींचती है, बोझ भी बाँधती है। जितना साथ मिलकर बटी जाए, उतनी मज़बूत होती यह हथेली पर खुरदरी लगती, आपसदारी की पुरानी गाँठ है।"},"ICON-1187":{"nm":"पाल का कपड़ा","de":"हवा से नफ़रत नहीं करता, बल्कि उसे पूरे सीने से गले लगाता है। कसकर फूलूँ तभी जहाज़ को दूर भेज सकता हूँ, इसलिए विरुद्ध हवा भी मेरे लिए ताक़त बन जाती है। तेज़ चीज़ का विरोध किए बिना उसे गले लगाकर आगे बढ़ने का तरीक़ा, मैंने समुद्र से सीखा है।"},"ICON-1188":{"nm":"लंगर का टुकड़ा","de":"लंगर का बस एक कोना हूँ, पर उसका वज़न पूरी तरह याद रखता हूँ। गहरे तल को थामकर जहाज़ को रोक देने वाले वे दिन। अब टूटकर अलग होने पर भी, ठहरने के वज़न को जानने वाला भारी टुकड़ा हूँ।"},"ICON-1189":{"nm":"जहाज़ की कील","de":"लहरों में हिलते डेक को एक-एक जगह से जकड़े रखने वाली कील हूँ। नमक से लाल ज़ंग खा जाने पर भी आख़िर तक अपनी जगह नहीं छोड़ी। बहती हुई चीज़ को मज़बूती से थामे रखने में भी हिम्मत लगती है।"},"ICON-1190":{"nm":"वाटरप्रूफ़ कपड़ा","de":"बारिश रोकने के काम में कोई शिकायत नहीं करता। ऊपर से बरसती चीज़ को चुपचाप सह लेता है, और नीचे रखी चीज़ को सूखा बचाए रखता है। भड़कीला न होकर भी किसी के सामान को भीगने से बचाने वाली, एक भरोसेमंद परत है यह।"},"ICON-1191":{"nm":"रंगाई","de":"सादे कपड़े में चुपचाप रचकर ही आख़िर रंग बनता है। नीला हो या मंजिष्ठा लाल, पुरानी माँएँ अपनी उँगलियाँ रंगते हुए कपड़े को रंग पहनाती थीं। भीतर बैठकर रचने के काम में भी, ऐसी गहराई है जो आसानी से नहीं छूटती।"},"ICON-1192":{"nm":"सुगंधित तेल","de":"बस एक बूँद से कमरे भर में एक विस्तृत मैदान फ़ौरन फैल जाता है। आँखों से न दिखे तब भी सबसे पहले पहुँचने वाला मेहमान। सोई हुई स्मृतियों के आँचल को धीरे से खींचने वाला, नाक तक सबसे पहले पहुँचने वाला दृश्य है यह।"},"ICON-1193":{"nm":"मोम","de":"गर्मी पाए तो बहता है, ठंडा हो तो जमकर अपना आकार थामे रखता है। नरमी और कठोरता के बीच आते-जाते, किसी भी चीज़ का चुपचाप साँचा बना देता है। बंद करने, सील करने, चमकाने वाला, तापमान के साथ अपना रूप बदलने वाला यह स्नेहिल पदार्थ है।"},"ICON-1194":{"nm":"मोमबत्ती","de":"अपना बदन धीरे-धीरे पिघलाकर अँधेरे का एक कोना रोशन करती है। पूरी जलकर ख़त्म हो जाने पर बस छोटा-सा क़द ही बचता है, पर जिस वक़्त उसने किसी की रात गर्म की, वह वक़्त कभी ग़ायब नहीं होता। छोटी होते हुए चमकने का तरीक़ा जानने वाली एक सीधी बत्ती है।"},"ICON-1195":{"nm":"खाद","de":"सड़ती हुई चीज़ें एक जगह जमा होकर सबसे उपजाऊ मिट्टी बन जाती हैं। फेंके हुए छिलके और सूखे गिरे पत्ते बसंत के नए अंकुर का भोजन बन जाते हैं। जिस जगह को ख़त्म मान लिया गया था, वहीं अगला जीवन चुपचाप अपनी पहली साँस सँभालता है।"},"ICON-1196":{"nm":"चावल","de":"एक दाना हाथ में आने तक अठासी बार हाथ लगता है। रोपाई से लेकर दँवरी तक, किसान का पूरा साल इसी छोटे-से दाने में पूरी तरह समाया रहता है। भाप उठता चावल का एक कटोरा असल में किसी का पूरा चार मौसम है।"},"ICON-1197":{"nm":"भूरा चावल","de":"बस ऊपरी छिलका हल्का-सा उतारकर अपना असली रंग वैसा ही बनाए रखा है। चबाने पर जितना सोंधा लगता जाए, वह जल्दबाज़ी न करने वाली ईमानदारी का स्वाद है। चिकना छिलवाने से इनकार कर, खुरदरी बनावट बचाए रखने वाला, दाने का यह मज़बूत हठ है।"},"ICON-1198":{"nm":"गेहूँ","de":"हवा में एक साथ सिर झुकाते सुनहरे खेत याद हैं। रोटी बनकर, नूडल बनकर, आटे की गोली बनकर दुनिया भर की मेज़ों को गर्म करता है। आम होने के कारण ही और गहराई से इंसानी ज़िंदगी में रच-बस गया एक अनाज है।"},"ICON-1199":{"nm":"आटा","de":"बारीक, मुलायम सफ़ेद चूर्ण बनने के बाद ही आख़िर कुछ भी बनने की तैयारी करता है। पानी मिले तो फूलता है, आग मिले तो पकता है। कोई तय आकार न होने के कारण, हाथ जैसे गूँधें वैसा ही रूप ले लेने वाला यह सीधा-सादा आधार है।"},"ICON-1200":{"nm":"गुँधा हुआ आटा","de":"चूर्ण और पानी हथेली के नीचे एक ढेले में घुल-मिल जाते हैं। जितना गूँधो उतना ही लचीला होता जाए, जितना इंतज़ार करो उतना ही फूलकर उभर आए। जल्दबाज़ी करो तो सख़्त हो जाए, इसलिए ख़मीर उठने का समय किसी हाल में जल्दी नहीं कराया जा सकता, यही पुरानी बेकरी कहती है।"},"ICON-1201":{"nm":"ब्रेड क्रम्ब्स","de":"उंगलियों पर लगी सफ़ेद धूल झाड़ते-झाड़ते न जाने कब आस्तीन तक भी सफ़ेद हो जाती है। तलने के लेप में बदल जाए तो कुरकुरी, ढेर लगे तो मानो साल की पहली बर्फ़। यह एक पाव की सबसे हल्की निशानी है जो सिंकने के बाद बचती है, फिर भी छोटी-सी चीज़ में भी काम आने की गुंजाइश बढ़ती जाती है।"},"ICON-1202":{"nm":"पास्ता नूडल्स","de":"उबलते पानी में एक मुट्ठी को पंखे की तरह फैलाते ही रसोई में मानो दूर की धूप उतर आती है। लंबी लड़ियाँ कलाई का काम माँगती हैं, और अल दांते तो थोड़ा कच्चा रहकर इंतज़ार करना जानने वाला मन है। काँटे पर बल खाकर लिपटती उस चमक को तो देखो।"},"ICON-1203":{"nm":"इंस्टेंट नूडल्स","de":"मंच का सारा मेकअप उतारने के बाद भोर में चुपके से चढ़ाया गया एक पैकेट। नूडल्स के नरम होने के वे तीन मिनट दिन का सबसे निजी समय होते हैं। फूँक मारते ही साँस के साथ तनाव भी ठंडा पड़ जाता है, और धुंधले चश्मे के पार आज का दिन चुपचाप ख़त्म हो जाता है।"},"ICON-1204":{"nm":"चावल केक (त्तोक)","de":"चावल जब ओखली की मार सह लेता है, तभी जाकर वह त्तोक बनता है। मे के रूप में, इन्जोलमी के रूप में, सोंगप्योन के रूप में—वही अनाज हाथों के हुनर के हिसाब से सौ नाम पाता है। दावत की थाली में सजे तो मुँह से पहले प्यार बुलाता है, ऐसी चीज़ जो बाँटकर खाने में ही सच में अच्छी लगती है।"},"ICON-1205":{"nm":"त्तोक-गुक चावल केक","de":"गारे-त्तोक को तिरछा काटो तो टुकड़े छोटे सिक्कों जैसे गोल निकलते हैं। सफ़ेद शोरबे में तैरता यह त्तोक है या कोई गोल-सी मन्नत? नए साल की पहली सुबह एक कटोरा खाली करते ही उम्र में एक साल जुड़ जाता है—यही इस देश का प्यारा-सा हिसाब है।"},"ICON-1206":{"nm":"आलू","de":"मिट्टी झटकते ही एक गोल चेहरा उजागर हो जाता है। गांगवोन की ढलानों की हवाओं में भी चुपचाप मोटी हुई यह जड़, भाप में पकने पर भुरभुरी और तलने पर सोंधी लगती है। जेब हल्की होने वाले दिनों में भी इसने परिवार का पेट ईमानदारी से भरा।"},"ICON-1207":{"nm":"शकरकंद","de":"गली के मोड़ पर जब भुने शकरकंद की भट्टी खड़ी होती, वही तो जाड़े की शुरुआत होती थी। फ़ॉइल हटाते ही पीली भाप सबसे पहले उंगलियों को गर्म करती, और वह मिठास सर्दी सहने वाली इस जड़ का बदला था। फूँक मारते हुए बीच से तोड़कर बाँटकर खाने लायक गर्माहट।"},"ICON-1208":{"nm":"गाजर","de":"मिट्टी में सीधी उतरी नारंगी छड़ी जैसी एक जड़। लगता था सिर्फ़ ख़रगोश को ही पसंद है, पर भूनो तो छिपी मिठास जाग उठती है, और सूप में डालो तो रंगत भी बढ़ा देती है। \"आँखों के लिए अच्छी है\" कहने वाले बुज़ुर्गों की बात लगभग सच निकली।"},"ICON-1209":{"nm":"मूली","de":"यह एक सफ़ेद, भारी जड़ हो तो जाड़े की थाली भरपूर लगती है। दोंगचिमी में ठंडी-सी, मूली के सूप में ताज़ी, ककदुगी में कुरकुरी। कुछ भी बेकार नहीं जाता—हरे पत्ते भी छज्जे पर सुखाकर सिरेगी बना लिए जाते हैं, यह एक मितव्ययी सब्ज़ी है।"},"ICON-1210":{"nm":"प्याज़","de":"छिलका उतारते ही आँख से एक आँसू लुढ़क आता है। तीखा और चुभने वाला गूदा भी गरम तेल से मिलते ही झूठ की तरह मीठा हो जाता है। लगभग हर कोरियाई पकवान की पहली पंक्ति में लिखा जाने वाला नाम, स्वाद की नींव चुपचाप बिछाने वाला शांत नायक।"},"ICON-1211":{"nm":"हरा प्याज़","de":"बारीक कटा सफ़ेद डंठल और हरी पत्तियाँ शोरबे पर बिखेरते ही, तब जाकर एक कटोरा पूरा-सा लगता है। खाने के बाद बची जड़ को पानी के गिलास में खड़ा कर दो तो फिर से लहलहा उठती है—गृहणियों का एक छोटा-सा खिड़की-बाग़।"},"ICON-1212":{"nm":"लहसुन","de":"छह कलियाँ गोल घेरे में मिलकर एक गाँठ बनाती हैं। यह वही तीखी जड़ है जिसने भालू को इंसान बना दिया, ऐसा कहते हैं। चाकू की पीठ से ठक-ठक कूटो तो ख़ुशबू भड़क उठती है—इसकी एक मुट्ठी के बिना न किमची की बात बनती है, न स्ट्यू की।"},"ICON-1213":{"nm":"अदरक","de":"गाँठों-सी उलझी हुई एक छोटी-सी ऊबड़-खाबड़ जड़। एक टुकड़ा भर डालने से मछली की गंध शांत हो जाती है और ठंडा शरीर भीतर से गर्म हो उठता है। ज़ुकाम से कराहती रातों में शहद के साथ उबालकर पी जाने वाला वह गर्म प्याला इसी तीख़ेपन से शुरू होता था।"},"ICON-1214":{"nm":"नापा गोभी","de":"भरे-पूरे पत्तों को नमक में सान दो, तब जाकर किमची का पहला अध्याय खुलता है। देर पतझड़ में हर आँगन में पहाड़ों-सी ढेर लगती वह गोभी। पूरे परिवार का बैठकर एक साथ एक बड़ा ढेर तैयार करना, लंबी सर्दी साथ काटने का एक वादा हुआ करता था।"},"ICON-1215":{"nm":"पत्तागोभी","de":"परत-दर-परत लिपटे गोल पत्तों को एक-एक कर छीलते जाओ तो कोई अंत ही नहीं मिलता, और न जाने कब मन धीमा और सुकून भरा हो जाता है। उबालो तो नरम-नरम, भूनो तो मीठी-मीठी। सादी-सी दिखने वाली इस सब्ज़ी में एक अनजानी-सी नरमाई छुपी रहती है।"},"ICON-1216":{"nm":"आइसबर्ग लेट्यूस","de":"गोल पत्ते में मांस का एक टुकड़ा रखकर ऊपर से सम्जांग भी लगाकर मुँह भर के कौर बना लेते हैं। गोल घेरे में बैठकर लपेट-लपेट कर खाने की उस बैठक में हर कोई चुपचाप औपचारिकता उतार देता है—यह और कुछ नहीं, हरे रंग का आतिथ्य है।"},"ICON-1217":{"nm":"सलाद पत्ता","de":"बगीचे के एक कोने में सबसे पहले उगने वाला पत्ता। तोड़ते जाओ तो फिर उग आता है, पूरी गर्मी भर थाली भरता रहता है। ठंडे पानी से धोकर हाथ से लपेट-लपेट कर खाई जाने वाली वह ताज़ी हरी महक, किसी-किसी के लिए तो पूरी की पूरी घर की याद है।"},"ICON-1218":{"nm":"पालक","de":"डिब्बा खाली करते ही ताक़त उमड़ आने वाला कार्टून का वह हरा रंग। उबालो तो एक मुट्ठी भर सिमट जाए, पर महक और दम ज्यों का त्यों रहता है। हाथ से मसल कर बनाओ या मिसो सूप में एक मुट्ठी घोल दो—आम है इसलिए हल्के में लेने वाली सब्ज़ी क़तई नहीं है।"},"ICON-1219":{"nm":"फर्न (कोसारी)","de":"बसंत के पहाड़ ने दी हुई कोमल कोंपलों को तोड़कर उबालो और फिर सुखाओ। इतनी लंबी मेहनत के बाद ही यह पूजा की थाली तक और बिबिम्बाप तक पहुँचती है। जितना हाथ लगे उतनी ही परत-दर-परत मेहनत रचती जाती है, यह पहाड़ का एक मौसम भर पाला हुआ बहुमूल्य साग है।"},"ICON-1220":{"nm":"पहाड़ी साग","de":"नाम-रहित लगें भी, हर एक अपनी अलग महक लिए बसंत का उपहार हैं। दादी के हाथ पहाड़ी रास्ते में एक झलक में पहचान लेते हैं कि कौन-सा पत्ता खाने लायक है। साग की एक टोकरी में उस मौसम का पूरा एक हिस्सा महक समेत चला आता है।"},"ICON-1221":{"nm":"मगवर्ट (सुक)","de":"जमी हुई ज़मीन को सबसे पहले चीरकर उगने वाली, कड़वी-सी पर सुगंधित घास। त्तोक में गूँथ दो तो बसंत की रोशनी सीधे मुँह में उतर आती है। नए साल के पहले महीने में इसे उबालकर सूप बनाने से साल भर की मनहूसियत टलती थी, ऐसा मानते थे—बसंत हमेशा इसी महक से आया करता था।"},"ICON-1222":{"nm":"पेरिला पत्ता","de":"एक ही पत्ता पूरे मुँह को गहरे रंग में रंग देने के लिए काफ़ी है। सुनहरे पोर्क बेली के साथ या सोया सॉस में तह-दर-तह अचार बनाकर रखो तो एक कटोरा चावल पल भर में ख़त्म हो जाता है। यह अनोखी महक सिर्फ़ इस धरती की थाली पर ही मीठी-मीठी लगती है।"},"ICON-1223":{"nm":"शिमला मिर्च","de":"भीतर से खोखला, कुरकुराहट से टूटने वाला हरा फल। हल्का-सा तीखापन सुस्त हो चुके स्वाद को जगाता है, और तेल में भूनो तो रंगत और भी निखर जाती है। बारीक काटकर बस बिखेर दो तो कोई भी पकवान पल भर में ताज़ा हो उठता है।"},"ICON-1224":{"nm":"शिमला मिर्च (रंगीन)","de":"लाल, पीला, नारंगी—ट्रैफ़िक लाइट जैसे रंग एक पूरी टोकरी भर। कच्ची में काटो तो मीठा रस टपकने लगता है, और सिर्फ़ रंगत से ही थाली रोशन हो उठती है। \"सुंदर दिखने वाली सब्ज़ी स्वाद भी बढ़ाती है\" यह कहावत इस पर एकदम सटीक बैठती है।"},"ICON-1225":{"nm":"टमाटर","de":"फल है या सब्ज़ी, हमेशा से बहस का विषय रहा वह गोल लाल फल। देर तक उबालो तो स्वाद गहरा हो जाता है, कच्चा खाओ तो बेहद ताज़ा लगता है। यह मध्य-गर्मी की धूप को सबसे ईमानदारी से समेटने वाला फल है, इसलिए एक कौर लेते ही मानो पूरा दिन ही फूट पड़ता है।"},"ICON-1226":{"nm":"खीरा","de":"गर्मी की तपिश को सबसे ताज़गी से ठंडा करने वाला हरा रंग। ठंडे सूप में तैराओ तो मुँह ठंडा और तरोताज़ा हो जाता है, सोबागी बनाकर अचार डालो तो कुरकुरापन जी उठता है। तपते दिन में पतला-पतला काटकर आँखों पर भी रखा जा सकता है—अंदर-बाहर दोनों से ठंडक देने वाली सब्ज़ी।"},"ICON-1227":{"nm":"कद्दू","de":"बेल के छोर पर गोल-गोल लटककर देर पतझड़ तक धीरे-धीरे मिठास भरता जाता है। खूब पकाओ तो पीली दलिया बनकर पेट को सुकून देता है, तलो तो सुनहरी जियोन बनता है। छज्जे के नीचे लटका दो तो पूरे जाड़े भर भरोसेमंद भंडार बना रहता है।"},"ICON-1228":{"nm":"कच्चा कद्दू (एहोबाक)","de":"गर्मी के बगीचे में रोज़ थोड़ा-थोड़ा मोटा होता हुआ हल्का हरा रंग। मिसो स्ट्यू में मोटे टुकड़ों में, जियोन में सुनहरा-सुनहरा भुना—इतना नरम कि छोटे बच्चे के मुँह में भी सह जाता है। आम होने के बावजूद उतना ही प्यारा, मध्य-गर्मी की थाली का नियमित मेहमान।"},"ICON-1229":{"nm":"बैंगन","de":"बैंगनी चमक से दमकता हुआ एक लंबा-सा फल। तेल सोख ले तो बेहद नरम हो जाता है, अच्छी तरह भाप में पकाओ तो रेशा रेशम-सा महीन हो जाता है। सादा दिखने पर भी हर किसी के साथ अच्छी तरह घुल-मिल जाने वाला, थाली का प्यारा सहायक किरदार।"},"ICON-1230":{"nm":"मक्का","de":"एक-एक दाना क़तार में साफ़-सुथरा सजा हुआ पीला अनाज। बर्तन में भाप देकर फूँक मारते हुए काटा जाने वाला गर्मियों का नाश्ता, और यह संकेत भी कि खेत पूरी तरह पक गए हैं। मुलायम बालों के एक गुच्छे के भीतर मिठास भरपूर छिपी होती है।"},"ICON-1231":{"nm":"सोयाबीन","de":"छोटे, सख़्त दाने रात भर पानी पीकर फूल उठते हैं। बारीक पीसो तो सोया दूध बनता है, अच्छी तरह किण्वित करो तो जांग बनता है—इस धरती की थाली की अधिकतर प्रोटीन यहीं से शुरू हुई। मिट्टी में एक दाना गाड़ो तो वह फिर एक पूरे पौधे के रूप में लौट आता है।"},"ICON-1232":{"nm":"टोफू","de":"सोयाबीन जब पानी पीकर पिस जाए और जम जाए, तो सीधे कोनों वाला एक सफ़ेद टुकड़ा बनता है। नरम और सीधा-सादा, किसी भी सूप में जाकर अपने रंग की ज़िद नहीं करता। चम्मच से उठाओ तो भी हौले से बिखर जाता है—सादगी ही जिसका गुण है, ऐसा एक भोजन।"},"ICON-1233":{"nm":"राजमा (लाल फली)","de":"छोटे लाल दानों को खूब उबालो तो गहरी लाल मिठास घुलकर उतर आती है। सबसे लंबी रात, गर्म राजमा दलिया की एक कटोरी से सर्दी और बुरी आत्माएँ दोनों को भगाने वाला वह मन इसी में बसा है। सिरुतोक की परत-दर-परत में वह लाल रंग सीधे भक्ति ही था।"},"ICON-1234":{"nm":"लाल फली का पेस्ट (पत-अंगेउम)","de":"उबली हुई राजमा को बारीक मसलकर, खूब पका-पकाकर बनाई गई एक नरम भराई। ब्रेड के बीच में, त्तोक के अंदर, बर्फ़ के गोले पर एक चम्मच—मिठास की वह एक लकीर पुरानी यादों तक को गर्म कर देती है। छानने और पकाने का वह लंबा समय ही सीधे मिठास बन जाता है।"},"ICON-1235":{"nm":"मशरूम","de":"बारिश थमने के बाद जंगल की धुंधली छाया में बिना आवाज़ किए सिर उठाता है। सूरज की एक झलक भी न पाकर भी अपनी महक बढ़ाने वाली मिट्टी की कारीगरी। सूप में एक मुट्ठी भर डालो तो बिना मांस के भी गहरा उम्दा स्वाद घुल आता है—जंगल का छुपाया एक राज़।"},"ICON-1236":{"nm":"शिइताके मशरूम","de":"पूरी तरह खुली टोपी वाला भूरा छाता। धूप में अच्छी तरह सुखाओ तो महक कई गुना गहरी हो जाती है, एक सूखा टुकड़ा भर एक पूरी हांडी शोरबे की ज़िम्मेदारी बख़ूबी उठा लेता है। शाकाहारी थाली का मज़बूत स्तंभ, और गहरे स्वाद को समझने वालों का पुराना ग्राहक।"},"ICON-1237":{"nm":"पाइन मशरूम (सोंगी)","de":"पतझड़ के गहरे चीड़ जंगल में, सिर्फ़ चीड़ के पेड़ों के पास ही चुपके से सिर उठाता है। इसे कोई उगा नहीं सकता, सिर्फ़ पैरों से खोजना पड़ता है, इसीलिए इसकी महक और भी क़ीमती लगती है। हल्का भूनकर बस नमक की एक चुटकी लगाओ तो जंगल का एक टुकड़ा मुँह में उतर आता है।"},"ICON-1238":{"nm":"किंग ऑयस्टर मशरूम","de":"मोटे तने को रेशों के साथ खींच-खींच कर फाड़ो तो चिपचिपापन हाथ में आ जाता है। हर मौसम में मज़बूती से उगता रहता है, इसलिए थाली से कभी दूर नहीं होता। भूनकर या भाप में—भरपूर गूदे के भीतर बिना बोझ वाला मज़बूत स्वाद ठसाठस भरा रहता है।"},"ICON-1239":{"nm":"स्ट्रॉबेरी","de":"जाड़ा सहने वाले पॉलीहाउस के दूर छोर पर सबसे पहले लाल पककर तैयार होती है। एक कौर लेते ही खट्टी-मीठी, बिल्कुल बसंत की पहली नमस्ते जैसी लगती है। केक के ऊपर एक गोल दाना रख दो तो एक साधारण-सा आज भी जल्द ही सालगिरह-सा बन जाता है।"},"ICON-1240":{"nm":"ब्लूबेरी","de":"टप से फूटते ही मुँह भर खट्टापन उजाले-सा फैल जाता है। बैंगनी छोटे-छोटे मोतियों को एक-एक कर उठाते जाओ तो न जाने कब पूरा डिब्बा ख़ाली हो जाता है, सफ़ेद दूध पर बिखेर दो तो मानो एक छोटा-सा रात का आकाश ही फैल जाता है।"},"ICON-1241":{"nm":"सेब","de":"एक कौर लेते ही सट-से आवाज़ के साथ पतझड़ बिखर जाता है। बाग़ की दादी अपने आँचल से पोंछकर जो लाल रंग थमाती थीं, वह रंग तभी आता है जब धूप को लंबे समय तक अपने भीतर सँजोया जाए। जितना सख़्त उतना ही अंत तक मीठा रहना जानता है यह।"},"ICON-1242":{"nm":"नाशपाती","de":"छिलका उतारते ही उंगलियाँ पहले ठंडी हो जाती हैं। चुसोक की पूजा की थाली की सबसे अगली पंक्ति—इसका ठंडा, मीठा रस मुँह भर जाने के उस पल, पतझड़ की रात की हवा का एक टुकड़ा चुपचाप आकर पास बैठ जाता है।"},"ICON-1243":{"nm":"आड़ू","de":"आड़ू के फूल जहाँ-जहाँ झरे, वहाँ-वहाँ रोएँदार-सी एक गर्मी उभरती है। हल्का-सा दबाओ तो महक पहले फैलती है, और एक कौर लेते ही पूरा मौसम मुँह के भीतर चला आता है।"},"ICON-1244":{"nm":"अंगूर","de":"बैंगनी दाने एक ही गुच्छे में लटककर एक-दूसरे के कंधों पर टिके रहते हैं। टप से फूटते ही खट्टापन पहले आता है और मिठास आधी धड़कन देर से—मानो गर्मी के आख़िरी दिनों का बुलाया हुआ एक सुघड़-सा गान।"},"ICON-1245":{"nm":"हरे अंगूर","de":"हल्का हरा रंग धूप को सीधे आर-पार जाने देता है, जिससे हर दाने में मानो एक दीया जल उठता है। बिना बीज का साफ़-सुथरा ताज़गी भरा स्वाद, जैसे अभी-अभी निकाली गई एक पहली पंक्ति—बिना किसी अतिरिक्त बात के मिठास।"},"ICON-1246":{"nm":"नींबू","de":"पीले छिलके को नाख़ून से खरोंचो तो महक टप से नाक की नोक को जगा देती है। एक बूँद से होंठ अपने-आप सिकुड़ जाएँ, फिर भी उस खटास के अंत में कहीं अजीब-सा एक कोना है जहाँ पूरा दिन रोशन हो उठता है।"},"ICON-1247":{"nm":"नीबू (लाइम)","de":"नींबू से छोटा और गहरा हरा यह फल पहले अपनी तीखी, ताज़ी महक से नमस्ते करता है। एक टुकड़ा भर गुनगुने पानी को भी पल भर में जगा देता है—छोटी मगर मज़बूत ताज़गी की एक मुट्ठी।"},"ICON-1248":{"nm":"संतरा","de":"छिलका उतारते ही उंगलियों पर धूप की-सी ख़ुशबू लग जाती है। एक-एक कली मुँह में डालो तो टप-टप, मीठे रस के छोटे-छोटे गुब्बारे फूटते हैं—गोल चीज़ मन को भी गोल-गोल घुमा देती है।"},"ICON-1249":{"nm":"संतरा (कयुल)","de":"याद है वह स्वाद—जाड़े में गर्म फ़र्श वाले कमरे में रज़ाई के भीतर पैर दबाए इसे छीलकर खाने का? नाखूनों के बीच से फैलती महक पूरे कमरे को पीला रंग देती थी। एक थैली ही पूरे परिवार के इकट्ठे बैठने का बहाना बन जाती।"},"ICON-1250":{"nm":"केला","de":"भूखी भोर में अभ्यास कक्ष के कोने में, बैग से लुढ़ककर निकले एक पीले फल से भूख मिटाने के दिन भी हुआ करते थे। नरम, मीठा और पेट भरने वाला—सबसे प्यारा अस्थायी सहारा।"},"ICON-1251":{"nm":"अनानास","de":"काँटेदार छिलके की एक परत पार करने के बाद ही पीला गूदा दिखता है। एक टुकड़ा मुँह में रखो तो खट्टा-मीठापन जीभ को टप से चुभता है, और होंठों के आस-पास न जाने कब दक्षिणी समुद्र की महक मंडराने लगती है।"},"ICON-1252":{"nm":"आम","de":"अच्छी तरह पका गूदा हाथ से चीरो तो चिपचिपी मिठास वाली महक उंगलियों को भिगो देती है। गहरा पीला रंग मुँह में घुलकर ग़ायब होते ही, गर्मियों की एक छोटी दोपहर की झपकी जैसा मीठा सपना गुज़र जाता है।"},"ICON-1253":{"nm":"नारियल","de":"सख़्त छिलके को हिलाओ तो अंदर से छलछल पानी की आवाज़ आती है। तोड़ो तो सफ़ेद गूदा और ठंडा रस—दूर के समुद्र को पूरी तरह समेटकर हिलोरें लेता एक छोटा-सा घड़ा।"},"ICON-1254":{"nm":"ड्रैगन फ्रूट","de":"गुलाबी शल्कों जैसा दिखने वाला बाहरी रूप पहले तो ठिठका देता है, पर चीरकर देखो तो सफ़ेद गूदे में काले तिल-जैसे बीज बिखरे मिलते हैं। स्वाद में सादा, दिखावे में भड़कीला—बाहर और भीतर पूरी तरह उलट एक चालाक-सा छलिया।"},"ICON-1255":{"nm":"कीवी","de":"रोएँदार भूरे छिलके को आधा काटो तो एक हरा रत्न उजागर होता है। तारों-सी जड़ी काली बीजों वाले उस टुकड़े का एक चम्मच मुँह में डालो तो खट्टेपन का एक कौर नींद को झकझोर कर जगा देता है।"},"ICON-1256":{"nm":"चिकन","de":"तेल लगे पैन में रखते ही सबसे पहले सुनहरी छनछनाहट पकती है। सादा और नरम, बिना किसी झिझक के किसी भी थाली में जगह बना लेने वाला—एक आसान भोजन का नियमित मेहमान।"},"ICON-1257":{"nm":"पोर्क","de":"तवे पर छनछनाते हुए, तेल के छींटे उड़ाते हुए सुनहरा पकता जाता है। सलाद के एक पत्ते में सम्जांग लगाकर मुँह भर कौर बनाते उन दफ़्तर-भोज की रातों में, उसकी सोंधी ख़ुशबू पूरी बैठक को गर्म कर देती।"},"ICON-1258":{"nm":"बीफ़","de":"हर लाल रेशे में तेल बारीक़ी से जड़ा हुआ चमकता है। गर्म पत्थर की थाली पर रखते ही सबसे पहले महक कमरा भर देती है, और एक टुकड़ा मुँह में जाते ही दिन भर की थकान चुपचाप ढीली पड़ जाती है।"},"ICON-1259":{"nm":"बेकन","de":"सुबह के तवे पर कुरकुरा होकर तेल नाचने लगता है। बस उस नमकीन महक से देर तक सोने वाला परिवार भी आँखें मलते हुए रसोई में इकट्ठा हो जाता है—महक जो पहले बुलाती है वह भोजन।"},"ICON-1260":{"nm":"सॉसेज","de":"काटे गए निशान चौड़े खुलते ही रस टप से फूट पड़ता है। टिफ़िन के एक ख़ाने की ज़िम्मेदारी उठाती वह लाल ऑक्टोपस-सी शक्ल, बचपन के लंच टाइम की एक छोटी-सी शानो-शौकत हुआ करती थी।"},"ICON-1261":{"nm":"पेप्परोनी","de":"गोल, तीखा एक टुकड़ा गर्म चीज़ पर किनारों से मुड़ने लगता है। तेल हल्का-सा जमा हो जाए तो वही पूरे पिज़्ज़ा की चरम सीमा होती है—छोटा होकर भी इसकी मौजूदगी उतनी ही गोल और गहरी है।"},"ICON-1262":{"nm":"पैटी","de":"मोटा-सा गूँथकर तवे पर रखते ही किनारों से भूरा पकने लगता है। दबाकर भुने एक टुकड़े के बीच सब्ज़ियाँ भर दो तो एक हाथ में ठीक से समा जाने वाला भरपूरपन तैयार हो जाता है।"},"ICON-1263":{"nm":"अंडा","de":"टप से फोड़ो तो ज़र्दी एक गोल सूरज-सी फिसल आती है। ताज़े पके चावल में मिला लो तो भी ठीक, गिम्बाप की पीली लकीर बन जाए तो भी ठीक—सबसे आम इसलिए सबसे प्यारा प्रोटीन।"},"ICON-1264":{"nm":"दूध","de":"भोर में दरवाज़े के सामने रखी एक ठंडी बोतल, हथेली पर छूती उस ठंडक से अक्सर दिन खुला करता था। गर्म करो तो भाप उठती है, ठंडा करो तो सोंधापन—हर हाल में पास बना रहने वाला एक सफ़ेद रंग।"},"ICON-1265":{"nm":"चीज़","de":"एक पीला टुकड़ा गर्म ब्रेड पर धीरे-धीरे बिखरने लगता है। उस लंबे तार बनने के एक पल का इंतज़ार करता मन—जितना पिघलता जाए उतनी ही सोंधाहट गहरी और गाढ़ी होती जाती है।"},"ICON-1266":{"nm":"चेडर चीज़","de":"गहरा नारंगी रंग एक झलक में ही नमकीन स्वाद का संकेत दे देता है। बारीक़ काटकर टोस्ट में भर दो तो उम्दा स्वाद मुँह भर फैल जाता है—जितना साफ़ रंग, उतना ही साफ़ स्वाद।"},"ICON-1267":{"nm":"मक्खन","de":"गर्म तवे पर एक टुकड़ा डालते ही हौले से पिघलकर सोंधी भाप उठने लगती है। ब्रेड पर लगाओ, चावल में मिलाओ—जो भी छूए उसे और भी नरम बना देने वाला एक पीला जादू।"},"ICON-1268":{"nm":"व्हिपिंग क्रीम","de":"फेंटते-फेंटते पतला सफ़ेद रंग धीरे-धीरे सख़्त बादलों में फूलता जाता है। केक के ऊपर एक चम्मच रखते ही, एक साधारण दोपहर छोटे-से जन्मदिन जैसी रोशन हो उठती है।"},"ICON-1269":{"nm":"दही (योगर्ट)","de":"चम्मच डालते ही चिकनाई से उठ आने वाला खट्टा सफ़ेद रंग। एक टुकड़ा फल मिला दो तो सुबह हल्की हो जाती है, एक कप ही पेट को शांति से सँवार देता है—एक नरम शुरुआत का स्वाद।"},"ICON-1270":{"nm":"मैकरल मछली","de":"जाली पर रखते ही तेल के छींटे उड़ते हुए मछली जैसी पर सोंधी धुआँ रसोई भर भर देती है। कांटे निकालकर चावल पर रख देने वाले वे हाथ—एक आम थाली में बसी सबसे गहरी भक्ति।"},"ICON-1271":{"nm":"सैल्मन मछली","de":"गुलाबी रेशे परत-दर-परत बिछे हुए हैं। ठंडा खाओ तो मुँह में नरमी से घुल जाता है, भूनो तो तेल रिसकर सोंधा हो जाता है—दूर समुद्र के विरुद्ध तैरकर आया एक मज़बूत स्वाद।"},"ICON-1272":{"nm":"टूना मछली","de":"डिब्बे का ढक्कन खोलते ही नमकीन महक झट से उठ आती है। चावल में मिलाकर या समुद्री शैवाल में लपेटकर किराए के छोटे कमरे में खाई गई वे रातें—एक डिब्बा ही एक भरपूर भोजन बना करता था, ऐसे भी दिन थे।"},"ICON-1273":{"nm":"कॉड मछली","de":"साफ़ गूदा इतना सादा है कि उबालते ही शोरबा शुरू से ही ताज़गी भर देता है। जाड़े की बंदरगाह की चाकू-सी हवा सहने वाली सफ़ेद मछली, एक गर्म कटोरे भर स्ट्यू से ठंडे हाथ भी धीरे-धीरे पिघल जाते हैं।"},"ICON-1274":{"nm":"झींगा","de":"पीठ गोल मोड़कर पकते ही स्लेटी रंग गुलाबी हो जाता है। टप से फूटती लचक और सोंधी महक—एक-एक कर छीलकर खाते जाओ तो न जाने कब थाली ख़ाली हो जाती है।"},"ICON-1275":{"nm":"केकड़ा","de":"सख़्त ख़ोल के भीतर से सफ़ेद गूदा निकालना धैर्य का एक छोटा-सा समय है। उस मेहनत के अंत में मुँह में जाने वाला एक टुकड़ा मीठा होता है—मानो पतझड़ का पूरा समुद्र मुँह में उतर आया हो।"},"ICON-1276":{"nm":"स्क्विड (कैलामारी)","de":"तवे पर गोल-गोल सिमटते हुए सोंधी महक उठाता है। चबाने में लचीला एक टुकड़ा, चो-जांग में डुबोकर मुँह में डालो तो नमकीन समुद्र साथ चला आता है।"},"ICON-1277":{"nm":"शंख (क्लैम्स)","de":"साफ़ शोरबे में मुँह खोलकर चुपचाप अपनी महक दे देते हैं। खदबदाकर उबलने की आवाज़ में समुद्र की गंध फैल जाती है, और एक सुड़ुक लेते ही ठंडा पड़ा पेट गर्माहट से खुल जाता है।"},"ICON-1278":{"nm":"फ़िश केक","de":"सींक समेत गर्म शोरबे में डुबोते ही भाप उठने लगती है। ठंडे दिन ठेले के सामने, काग़ज़ के कप में शोरबा लेकर फूँक मारते वे हाथ—गली की दी हुई एक छोटी-सी तसल्ली।"},"ICON-1279":{"nm":"किमची","de":"घड़े में धीरे-धीरे पककर खट्टी, गहरी महक बढ़ाती जाती है। हाथ से फाड़कर ताज़े पके चावल पर रख दो तो बस काफ़ी है, घर-घर अलग स्वाद ही उस घर की अपनी विरासत है।"},"ICON-1280":{"nm":"पीली अचारी मूली","de":"एक पीला टुकड़ा कुरकुरा होकर मुँह में सहजता से टूटता है। गिम्बाप के एक रोल या स्नैक की थाली के साथ हमेशा रहने वाला साथी—इसका खट्टा-मीठापन तेल से भरे मुँह को ताज़ा कर देता है।"},"ICON-1281":{"nm":"अचार (पिकल)","de":"खीरा नमक में पल भर साँस रोकता है, फिर सिरके में जाकर आँखें खोलता है। कुरकुरापन लौटने के उस पल को चूकने के डर से शीशे का जार धूप वाली खिड़की से कभी नहीं हटता। धीरे-धीरे अचार बनने का वह समय ही स्वाद लेकर आता है।"},"ICON-1282":{"nm":"गोचुजांग","de":"घड़े के भीतर एक साल सह चुकी लालिमा। तीखेपन के पीछे सोयाबीन की मिठास चुपचाप छिपी रहती है, इसलिए एक चम्मच घोलते ही स्ट्यू आख़िरकार अपने घर का चेहरा बन जाती है। आँगन के घड़ों ने धूप से पाला हुआ यह गहराई है।"},"ICON-1283":{"nm":"दोएनजांग","de":"मेजू फफूंद को गले लगाकर एक पूरी सर्दी बिता चुका है। सोंधापन पकने और अधिक-पकने के बीच की एक जोखिम भरी रस्सी पर चलना है—दादी उस सीमा को उंगलियों की महक की एक झलक से ही पहचान लेती थीं। जितना इंतज़ार करो, उतना ही गहरा होता स्वाद।"},"ICON-1284":{"nm":"सोया सॉस","de":"सोयाबीन जितना काला होता जाए, उतना ही भीतर से गहरा होता जाता है। एक बूँद से साग जी उठता है और ब्रेज़ को चमक मिलती है, इसलिए रसोई का हर रंग आख़िर में इसी गर्म भूरे रंग से शुरू होता है। नमक से परे एक उम्दा स्वाद।"},"ICON-1285":{"nm":"चुनजांग","de":"एक ही जैसा काला रंग होते हुए भी बनावट अलग है। कैरामेल में एक बार और भूनी गई मीठे-नमकीन का वह अंतिम स्वाद, नूडल्स में मिला दो तो वह काली चमक स्वाद को झकझोर कर जगा देती है। चाइनीज़ वोक स्वाद का पहला बटन।"},"ICON-1286":{"nm":"करी पाउडर","de":"कई मसाले एक चम्मच में मिलजुल कर एक पीले पाउडर में समा जाते हैं। पानी में घोलो तो खदबदाते हुए उबलते हुए पूरा घर गर्म कर देता है—बारिश की एक शाम को सबसे भरपूर एक कटोरे की झलक बन जाता है।"},"ICON-1287":{"nm":"काली मिर्च","de":"साबुत पीसो तो महक ज़िंदा रहती है, पहले से पीसकर रखो तो महक चुपके से उड़ जाती है। आख़िरी घुमाव हमेशा आँच बंद करने से ठीक पहले होता है—यह पकाने वाले हाथ की सँभालकर रखी एक छोटी-सी विराम-रेखा है।"},"ICON-1288":{"nm":"लाल मिर्च पाउडर","de":"पतझड़ की धूप में सुखाई गई ताईयांगचो मिर्च तभी जाकर अपनी लालिमा पूरी करती है। बारीक पीसो या मोटा, इससे किमची का स्वभाव बदल जाता है, इसलिए हाथ का हुनर आख़िर इसी पाउडर के दाने चुनने की कला से आता है।"},"ICON-1289":{"nm":"नमक","de":"स्वाद ठीक करना यानी कमी वाली तरफ़ एक चुटकी करके धीरे-धीरे बढ़ना। एक बार डला नमक फिर वापस नहीं होता, इसीलिए अनुभवी हाथ हमेशा आख़िर में थोड़ा कम डालकर चख लेता है। जितना बचाकर रखा, उतनी ही गुंजाइश है।"},"ICON-1290":{"nm":"चीनी","de":"यह कड़वाहट को शांत करती है और खटास के कोनों को गोल कर देती है। पर मिठास को अपनी मौजूदगी पकड़ में नहीं आने देनी चाहिए, इसलिए जितना अच्छा मसाला उतनी ही चुपके से चीनी आख़िर में ग़ायब हो जाती है। छिपना जानने वाली मिठास।"},"ICON-1291":{"nm":"शहद","de":"मधुमक्खी फूलों के बाग़ में हज़ारों बार आना-जाना कर इकट्ठा किया गया एक जार। जम जाए तो गुनगुने पानी के हौज़ में फिर से पिघला लो, चाय में घोलो तो गले को नरमी से लपेट लेता है। एक पूरा मौसम भर पका हुआ, सुनहरे रंग का एक चम्मच।"},"ICON-1292":{"nm":"खाना पकाने का तेल","de":"गर्म तवे पर एक बार घुमाओ तो सामग्री चिपकना भूल जाती है। जल्दी डालो तो जल जाए, देर से डालो तो चिपक जाए, इसलिए धुआँ अभी उठना शुरू हो उस एक पल का इंतज़ार ही तलने का असली नियम है। ध्वनि से समय नापा जाता है।"},"ICON-1293":{"nm":"ऑलिव ऑयल","de":"पहली दबाई के हरे रंग में घास की महक और हल्का तीखापन साथ-साथ जीता है। आँच पर चढ़ाने की बजाय आख़िर में घुमाना ही इसकी महक को अंत तक ज़िंदा रखता है, इसलिए बिना पकाए इस्तेमाल करना ही इसका सबसे ईमानदार उपयोग है।"},"ICON-1294":{"nm":"तिल का तेल","de":"आख़िर में एक बूँद टपकाते ही मौसमी साग आख़िरकार पूरा होने की घोषणा करता है। सोंधापन आँच पर आसानी से उड़ जाने वाला स्वभाव है, इसलिए यह हमेशा सारी पकाई खत्म होने के बाद चुपके से जोड़ी जाने वाली अंतिम विराम-रेखा बनती है।"},"ICON-1295":{"nm":"वनीला बीन","de":"एक फली चीरकर काले बीज खुरचते ही मिठाई महक का एक नया परिधान पहन लेती है। इस्तेमाल हो चुके छिलके को भी फेंकने के बजाय चीनी में दबाकर रख देना—यह पेस्ट्री शेफ़ को विरासत में मिली एक पुरानी मितव्ययता है।"},"ICON-1296":{"nm":"कोको (काकाओ)","de":"फल के भीतर सफ़ेद गूदा और कड़वे बीज। किण्वन और धूप में सुखाने के बाद ही यह हमारी जानी-पहचानी मिठास में तब्दील होता है। चॉकलेट बनने से पहले, इसका सबसे जंगली, पहला चेहरा यही है।"},"ICON-1297":{"nm":"चॉकलेट","de":"हथेली की गर्मी भर से ही पिघल जाने वाला एक नाज़ुक स्वभाव। अठ्ठाईस डिग्री के आस-पास जमाओ तभी टूटने वाली वह चमक जीती है, इसलिए मिठास के पीछे अनजाने में एक बड़ा नख़रैला तापमान का नियम छिपा रहता है।"},"ICON-1298":{"nm":"कॉफ़ी बीन्स","de":"पिसने से पहले एक दाना कठोर ख़ामोशी के क़रीब होता है। पर गर्म पानी से मिलते ही फूलकर अपनी महक उड़ेल देता है—सुबह को जगाने वाला पहला संकेत हमेशा इसी छोटे दाने से शुरू होता है।"},"ICON-1299":{"nm":"चाय की पत्तियाँ","de":"गर्म पानी में ज़्यादा देर रहे तो कसैली हो जाती है, कम देर रहे तो फीकी। पत्तियों के धीरे-धीरे खुलने के समय को चुपचाप नापना—चाय बनाना असल में इंतज़ार को उंगलियों से मापना है।"},"ICON-1300":{"nm":"पुदीना","de":"मसलो तो कड़वाहट रिसने लगती है, इसलिए इसे हमेशा नरमी से ही सँभालना पड़ता है, एक कोमल पत्ता। हल्के से थपथपाकर सोई हुई महक जगाओ और तपते दिन गिलास में तैरा दो, तो मानो पूरी गर्मी एक सुर ठंडी होकर बैठ जाती है।"},"ICON-1301":{"nm":"जड़ी-बूटियाँ","de":"तने समेत डालने पर सुगंध गहरी होती है, सिर्फ़ पत्तियाँ इस्तेमाल करने पर वह हल्की-सी उजली रहती है। सुखाने पर वह और गाढ़ी हो जाती है, ताज़ी रहने पर एकदम ताज़गी भरी—एक गुच्छे में समाई सुगंध जितनी विस्तृत होती है, रसोई का रंग-ढंग भी उतना ही फैल जाता है।"},"ICON-1302":{"nm":"शाहबलूत","de":"काँटेदार छिलके के भीतर चमकदार गूदा छिपा रहता है। चीरा लगाकर भूनने पर वह चटख़ आवाज़ के साथ खुलता है और मीठी महक बिखेरता है—ठंडी हवा में गली के भुने-शाहबलूत की थैली की गर्माहट मानो हाथों में महसूस होने लगती है।"},"ICON-1303":{"nm":"मूँगफली","de":"उसकी सोंधी महक भूनने की आँच में पूरी होती है। एक-एक दाना छीलते-छीलते समय का पता ही नहीं चलता—बरामदे में साथ बैठकर बाँटने पर, कहानियाँ भी उसी के साथ धीरे-धीरे छिलती जाती हैं।"},"ICON-1304":{"nm":"बादाम","de":"हल्का उबालकर छिलका उतारने पर भीतरी हिस्सा और सफ़ेद, और मुलायम हो जाता है। पीसकर घोलने पर दूध जैसा, साबुत भूनने पर कुरकुरा—एक दाने में समाया यह बदलाव हलवाई की कल्पना को भरपूर विस्तार देता है।"},"ICON-1305":{"nm":"तिल","de":"धीमी आँच पर हौले-हौले हिलाते रहने पर एक क्षण वे टप-टप उछलने लगते हैं। वह आवाज़ थमने से ठीक पहले का पल सबसे सोंधा होता है—तिल भूनना आख़िर में कान से किया जाने वाला काम बन जाता है।"},"ICON-1306":{"nm":"गन्ना","de":"एक गाँठ चबाने पर घास जैसी महक के साथ मीठा रस रिस आता है। जिस डंठल को बार-बार औटाना पड़े तभी वह जानी-पहचानी मिठास बनता है—चीनी की शुरुआत यूँ अचरज भरे ढंग से इतनी हरी और इतनी लंबी होती है।"},"ICON-1307":{"nm":"कच्ची चीनी","de":"कम परिष्करण से गुज़री, अपना असली रंग सहेजे हुए खुरदुरी मिठास। मिट्टी जैसी एक हल्की गहराई भीतर बनी रहती है, इसलिए जिन हाथों को चीज़ के परिष्कृत होने से पहले वाली सच्चाई भाती है, वे जान-बूझकर इसे ढूँढ़ निकालते हैं।"},"ICON-1308":{"nm":"कोको बीन्स","de":"फली से अभी-अभी निकाला बीज कड़वा और कसैला होता है। ख़मीर उठने के कई दिन चुपचाप सहने के बाद ही सुगंध खिलती है, इसलिए मिठास इस बीज को लंबे धीरज के अंत में मिला एक छोटा-सा पुरस्कार है।"},"ICON-1309":{"nm":"कोको निब्स","de":"भुने बीज को बारीक तोड़े गए टुकड़ों में चीनी का एक भी कण नहीं होता। मुँह में डालते ही पहले कड़वापन आता है, सोंधापन देर से आता है—इसलिए मिठास से पहले वाले कोको से सबसे ईमानदार मुलाक़ात यहीं होती है।"},"ICON-1310":{"nm":"कच्ची कॉफ़ी बीन्स","de":"अभी भी कच्ची महक लिए हरे दाने। ऐसे में उनकी सुगंध गहरी नींद में सोई रहती है, इसलिए आँच के अभिषेक से पहले तक वे चुपचाप एक ऐसी संभावना बने रहते हैं जिसे ख़ुद नहीं पता कि वह क्या बनेगी।"},"ICON-1311":{"nm":"भुनी कॉफ़ी बीन्स","de":"जिस भूरी सतह से हल्का-सा तेल रिस आया है, उस पर सुगंध पूरी तरह जमा हो चुकी है। ठंडे होने से पहले पीसने पर ही वह महक अक्षुण्ण रहती है, इसलिए एक प्याले की तक़दीर भूनने के बाद चंद दिनों में ही चुपचाप तय हो जाती है।"},"ICON-1312":{"nm":"वनीला बीन","de":"सुगंध की एक लकीर दूध की पूरी हांडी को रंग देती है। इस्तेमाल हो चुकी फली को भी चीनी के मर्तबान में डाल दें तो कुछ दिनों बाद सारी चीनी सुगंधित हो जाती है—यह ऐसी विलासिता है जिसमें फेंकने लायक़ कुछ भी नहीं बचता।"},"ICON-1313":{"nm":"काली मिर्च","de":"एक साबुत काली मिर्च की महक पिसते ही क्षीण होने लगती है। इसलिए उसे मेज़ पर साबुत रखकर ज़रूरत पड़ने पर ही कूटा जाता है—ताज़गी दरअसल टालमटोल न करने वाले मन से खिलती है।"},"ICON-1314":{"nm":"सफ़ेद मिर्च","de":"छिलका उतरने से और चिकना हुआ दाना तीखेपन से ज़्यादा हल्का-सा असर छोड़ता है। सफ़ेद सॉस में एक भी काला धब्बा न छोड़ने की परवाह से जन्मी, यह किसी अनदेखी जगह की महीन नज़ाकत है।"},"ICON-1315":{"nm":"दालचीनी","de":"एक टुकड़ा भिगोने पर चाय में गुनगुना तीखापन धीरे-धीरे फैलता है। पाउडर के बजाय साबुत डालने पर सुगंध देर तक टिकती है, इसलिए सर्दियों के पेय की गहराई इस सूखे छिलके के धैर्य से आती है।"},"ICON-1316":{"nm":"लौंग","de":"छोटी कील जैसी दिखने वाली एक फूल-कली में सुगंध घनी-सी जमी है। ज़्यादा डाल दें तो वह पूरे भोजन को निगल जाती है, इसलिए एक ही कली का संयम स्वाद का संतुलन चुपचाप बनाए रखता है।"},"ICON-1317":{"nm":"जायफल","de":"बीज को साबुत रखकर ज़रूरत पड़ने पर हल्का-सा कद्दूकस किया जाता है। पहले से पीसने पर सुगंध जल्दी बिखर जाने की उसकी फ़ितरत है, इसलिए एक झटके में की गई आख़िरी खुरचन दूध की महक को और गहरा बना देती है।"},"ICON-1318":{"nm":"इलायची","de":"हरी फली को टप से तोड़ते ही भीतर से एक ठंडी-तीखी सुगंध छलक पड़ती है। चाय में बस एक-दो दाने कूटकर डालने भर से एक सामान्य-सा प्याला अचानक किसी दूर देश की ख़ुशबू पा लेता है।"},"ICON-1319":{"nm":"केसर","de":"एक फूल से मुश्किल से तीन धागे बटोरे गए लाल रेशे। गुनगुने पानी में घोलने पर पीला रंग धीरे-धीरे फैलता है—बेशक़ीमती होना हाथों से एक-एक करके चुनने में लगे समय का भार भी है।"},"ICON-1320":{"nm":"हल्दी","de":"मिट्टी की जड़ को पीसने पर उँगलियों के पोर तक पीला रंग चढ़ जाता है। तेल में हल्का भूनने पर ही सुगंध जागती है, इसलिए करी का सुनहरा रंग वह रंग है जिसे इस छोटी-सी जड़ ने आँच पर उगाया है।"},"ICON-1321":{"nm":"तेजपत्ता","de":"वह पत्ता जिसे विजेता के माथे पर सजाया जाता था, ऐसा कहते हैं। उबलते पानी में एक पत्ती डालते ही भाप के बीच से पुराने मैदान की जय-जयकार पल भर को उठ आती है। जीत न पाए दिन भी, इसकी महक साँस में भरने पर, आज के तुम्हें चुपचाप गले लगा लेने वाली एक हरी-भरी दिलासा बन जाती है।"},"ICON-1322":{"nm":"नारियल का दूध","de":"कड़े ख़ोल को तोड़ने पर ही बहकर निकलता है वह सफ़ेद रस। किसी गर्म देश के बाज़ार के एक कोने में, स्ट्रॉ लगाकर एक घूँट पीते ही दोपहर की प्यास पूरी तरह ठंडी हो जाती है। मुँह भर फैलती ठंडी मिठास उष्णकटिबंधीय छाया साथ ले आती है।"},"ICON-1323":{"nm":"नारियल तेल","de":"जमने पर पहली बर्फ़ जैसा सफ़ेद, हथेली पर गर्म करने पर सुगंध धीरे से फैल जाती है। सिर से पाँव तक बस एक डिब्बा काफ़ी है कहकर सौंपी गई द्वीप की दादी की स्नेहिल गृहस्थ सूझ, इस गोल डिब्बे में पूरी की पूरी संजोई है।"},"ICON-1324":{"nm":"सूखा केला","de":"धूप में कई दिन लिटाने पर पीला गूदा चबाने योग्य नरम-चिपचिपा हो जाता है। एक-एक टुकड़ा बचा-बचाकर काटते रहने पर, बरसात के फ़सल-मौसम की चिपचिपी मीठी महक मुँह में धीरे से फिर जी उठती है। धीरे-धीरे पका मीठापन इस तरह एक ऋतु को सहेजता है।"},"ICON-1325":{"nm":"सूखा आम","de":"नरम गूदा धूप में गाढ़ा होकर अंबर-सी जेली में बदल गया। खट्टा, मीठा और चबाने लायक़—तीनों स्वाद एक ही टुकड़े में समाए हैं, इसलिए मुँह में धीरे-धीरे घुमाते रहो तो एक थैले में पूरी दोपहर लंबी हो जाती है।"},"ICON-1326":{"nm":"सूखा अनन्नास","de":"काँटेदार बाहरी रूप के उलट, भीतरी गूदा बेहद पीला और उजला होता है। धूप में सुखाने पर खट्टापन गाढ़ा हो जाता है, इसलिए एक टुकड़ा काटते ही होंठों के कोने अपने-आप ऊपर उठ जाते हैं। एक टुकड़े के अंत में बचा ताज़ा-सा असर देर तक ठहरता है।"},"ICON-1327":{"nm":"उष्णकटिबंधीय फल टोकरी","de":"ताज़े तोड़े गए रंग एक ही टोकरी में घुल-मिल जाते हैं। आम का नारंगी, केले का पीला, अनन्नास का सुनहरा—हाथ बढ़ाकर चुनने से पहले ही नाक की नोक से गर्मी का मौसम बहकर आ जाता है। बस देखने भर से मन उजला कर देने वाली एक गोद-भर।"},"ICON-1328":{"nm":"समुद्री शैवाल का बंडल","de":"भाटे से खुली चट्टानों से बटोरे गए समुद्र के बाल। नमकीन खारी महक में लहरों की आवाज़ उलझी है, इसलिए ठंडे पानी में चुपचाप भिगोने पर हल्की मछली जैसी समुद्री महक धीरे-धीरे रसोई तक बहकर आ जाती है। एक मुट्ठी मेज़ पर एक छोटा-सा तटीय दलदल बिछा देती है।"},"ICON-1329":{"nm":"सूखी समुद्री खाद्य वस्तुएँ","de":"दृढ़ता से सूखे समुद्र की एक मुट्ठी। हाथ से रेशे के सहारे फाड़ने पर नमक के साथ-साथ पुराने बंदरगाह की खारी हवा भी खुल जाती है। मक्कोली का एक कटोरा अपने-आप याद आने वाला, स्नेहिल थाली के पास बैठा पुराना दोस्त।"},"ICON-1330":{"nm":"सूखी स्क्विड","de":"दस पैरों को क़रीने से फैलाकर धूप में सुखाया गया है। आँच पर हल्का भूनते ही सोंधी महक उठे तो रेशे के सहारे लंबा फाड़ लो। उस चबाने वाले स्वाद से, देर रात के नाश्ते की थाली की शान एक पायदान ऊपर चढ़ जाती है।"},"ICON-1331":{"nm":"नमकीन मछली","de":"मोटे नमक में दबाकर रखने पर मछली समय सहना सीख जाती है। उसके गहरे नमकीन गूदे का एक निवाला भर मिले तो चावल की पूरी कटोरी पल भर में ख़ाली हो जाती है—यह समुद्र किनारे की दादी की उँगलियों से चली आई एक स्नेहिल तरकीब है।"},"ICON-1332":{"nm":"नमकीन झींगा","de":"छोटे झींगे नमक में धीरे-धीरे पककर स्वाद की गहराई में बदल जाते हैं। किमची के मौसम में पत्तागोभी के भीतर एक चम्मच डालते ही, पूरे आँगन में फैल जाने वाली वह खारी महक। वही एक चम्मच पूरे साल की किमची का स्वाद तय करता है।"},"ICON-1333":{"nm":"अंचोवी","de":"उँगली जितना छोटा शरीर पूरी हांडी के शोरबे की गहराई सँभालता है। सिर और अंदरूनी हिस्सा निकालते हुए बातें करते बचपन की रसोई—छोटी होकर भी गृहस्थी के बीचोंबीच मज़बूती से खड़ी रहने वाली एक आभारी मछली।"},"ICON-1334":{"nm":"कोम्बू","de":"समुद्र की तह में लंबी उगी काली पट्टी। ठंडे पानी में डालकर उबाल आने से ठीक पहले धीरे से बाहर निकाल लेना, शोरबा बनाने वाले हाथों का पीढ़ी-दर-पीढ़ी निभाया वादा है। गहरा स्वाद कभी जल्दबाज़ी नहीं करता।"},"ICON-1335":{"nm":"हिजिकी","de":"उभरी-उभरी बनावट मुँह में टप-टप फूटती है। बसंत में तटीय चट्टानों को हरा रंग देने वाला यह शैवाल, हाथ से मसलकर सजाया जाए तो थाली के एक कोने में एक छोटा-सा ताज़ा समुद्र फैल जाता है। यह बसंत को चबाने जैसा स्वाद है।"},"ICON-1336":{"nm":"सीप","de":"दो मज़बूत खोल के बीच लंबे समय तक सँजोकर गढ़ा गया एक गोल प्रकाश। रेत के एक कण की तकलीफ़ को रत्न में बदलने तक, समुद्र ने कभी जल्दबाज़ी नहीं की। हथेली पर रखते ही उस लंबे धैर्य का भार भी साथ आ बैठता है।"},"ICON-1337":{"nm":"मूँगे की सजावट","de":"लहरों ने सैकड़ों बरसों में तराशी समुद्र की एक डाली। धूप पड़ते ही गुलाबी और नारंगी रंग में फैल जाती है, इसलिए शेल्फ़ पर चुपचाप रखी भर से एक पूरा कमरा गर्म द्वीप में रंग जाता है। उँगलियों को छूने वाला खुरदुरा दाना भी कैसा अपना-सा लगता है।"},"ICON-1338":{"nm":"सीप का बटन","de":"सीप की देह जिस जगह से चली गई, वहीं की चमकदार भीतरी परत को गोल आकार में काटा गया है। कॉलर पर टाँकने पर, बंद करते ही हर बार उँगलियों की नोक पर एक छोटा-सा इंद्रधनुष चमक उठता है। सब कुछ दे देकर विदा लेते समुद्र का छोड़ा आख़िरी स्नेहिल उपहार।"},"ICON-1339":{"nm":"काँच की गोली","de":"हथेली पर घुमाओ तो भीतर क़ैद रोशनी भी लुढ़कती हुई साथ चलती है। गली में बैठकर सूरज ढलने का होश खोए बिना खेली जाने वाली उन कंचों की उम्र में, एक गोली और जीत लेने वाले बच्चे की जेब असाधारण रूप से भारी और गर्वीली लगती थी।"},"ICON-1340":{"nm":"चंदन की नक्काशी","de":"तराशे गए हर रेशे से एक हल्की सुगंध रिसती रहती है। पुराने लोग इस लकड़ी को जलाकर बिखरे मन को सहेजा करते थे। एक टुकड़ा चुपचाप हाथ में थामे रहो तो उँगलियों से एक शांति धीरे-धीरे ऊपर चढ़ने लगती है।"},"ICON-1341":{"nm":"अगरबत्ती","de":"एक पतली-सी लकड़ी धीरे-धीरे जलते हुए ऊपर की ओर राह बनाती है। धुएँ की खींची रेखा को आँखों से पीछा करते-करते, दिन-भर जल्दबाज़ी करता मन भी कब चाल धीमी करके वहीं चुपचाप ठहर जाता है, पता ही नहीं चलता।"},"ICON-1342":{"nm":"रंगदायी फूल","de":"पंखुड़ियों में छिपा रंग उबलती हांडी में घोल दें तो साफ़ कपड़ा धीरे-धीरे उसी रंग में रंग जाता है। प्रकृति के पहले से रंगे रंग को कुछ देर के लिए उधार लेना—रंगाई मूलतः फूल को भेजा गया एक स्नेहिल हाल-चाल था।"},"ICON-1343":{"nm":"नील रंग","de":"नील को बार-बार सड़ाकर पाया गया गहरा, गमगीन नीलापन। हर बार डुबोकर निकालने पर कपड़ा आसमानी रंग से धीरे-धीरे समुद्री रंग की ओर सरकता है। यह प्रतीक्षा का रंग है, जो जल्दबाज़ी उतार फेंकने पर ही खिलता है।"},"ICON-1344":{"nm":"लाल रंग","de":"मजीठ की जड़ उबालने पर मिट्टी में सोई एक साँझ हांडी के भीतर जाग उठती है। यह गाँव का सबसे शुभ, सबसे उजला रंग था—जो उत्सव के दिन नई दुल्हन के लहँगे के आँचल को सुंदरता से रंग देता था।"},"ICON-1345":{"nm":"ज़री का धागा","de":"बाल से भी बारीक सोना खींचकर एक-एक तार को मन लगाकर बुना जाता है। जिस-जिस जगह कढ़ाई हुई, वहाँ प्रकाश ठहर जाता है, इसलिए दीया बुझे अँधेरे कमरे में भी वह नक़्शा अकेला ही हल्के से चमकता रहता है।"},"ICON-1346":{"nm":"रेशम","de":"रेशम-कीड़े के थूके धागे को बुनते-बुनते, बार-बार बुनकर ही मुश्किल से एक थान तैयार होता है। हाथ की पीठ पर छूने पर बसंत के पानी-सा फिसलता स्पर्श—यह वह बारीक-बनावट कपड़ा है जिसे पुराने लोगों ने पूरा एक मौसम गोद में लेकर धीरे-धीरे पाला।"},"ICON-1347":{"nm":"मोती का बटन","de":"मोती की भीतरी चमक को ही चुनकर गोल आकार में तराशा गया है। जोगोरी के कॉलर पर एक-एक करके लगाते हुए, उँगलियाँ पल भर को नज़ाकत से भर जाती हैं। छोटा होकर भी पहनावे की शान को चुपचाप ऊपर उठाने वाला एक सलीक़ेदार दाना।"},"ICON-1348":{"nm":"नक़्शे का टुकड़ा","de":"फटे किनारे के पार एक अनजाना समुद्र-तट अचानक टूटकर रह जाता है। कहते हैं बाक़ी टुकड़े जोड़ने वाला ही ख़ज़ाने तक पहुँचता है—पर शायद हवा के सहारे उसे ढूँढ़ते भटकने की वह पूरी यात्रा ही ख़ज़ाना थी।"},"ICON-1349":{"nm":"पुराना समुद्री नक़्शा","de":"खारे पानी से धुँधलाया मार्ग और फीका पड़ चुका कम्पास का चित्र। किसी नाविक ने घोर अँधेरी रात में सिर्फ़ तारों को देखकर खींची लकीर को उँगली से थामकर चलो, तो एक भुला-बिसरा द्वीप पुराने काग़ज़ पर फिर धीरे से उभर आता है।"},"ICON-1350":{"nm":"बोतल में बंद पत्र","de":"लहरों में बहकर आई काँच की बोतल के भीतर, लिपटा हुआ काग़ज़ का एक टुकड़ा। किसने कब भेजा, यह पता नहीं ऐसा एक हाल-चाल आख़िर किसी के हाथ लग ही गया। दिल में जगह हो तो समुद्र भी इस तरह इतना धीमा डाकिया बन जाता है।"},"ICON-1351":{"nm":"बहकर आया संदूक","de":"खारे पानी से फूलकर कड़ा हो चुका ढक्कन खोलने के पल तक ही रोमांच बना रहता है। भीतर ख़ज़ाना हो या ख़ाली रेत, दूर से बहकर आया संदूक हमेशा किसी अनजान चेहरे की कहानी भी साथ लिए तट पर आ लगता है।"},"ICON-1352":{"nm":"छोटी चाबी","de":"हथेली में सिमटकर आ जाने वाला धातु का एक पुराना टुकड़ा। किस दरवाज़े को खोलती है, यह बेशक़ भुला दिया गया हो, पर उँगलियों में एक स्नेहिल भार भारी-सा टिका रहता है, जो बंद करने से पहले खोलने का ही ख़याल दिलाए।"},"ICON-1353":{"nm":"चाँदी का सिक्का","de":"हाथों के छूने से नक़्श धुँधला पड़ चुका एक गोल चाँदी। किसी का किराया या थकी-हारी एक रात का बिस्तर रहा एक सिक्का, उसकी ठंडी सतह को सहलाओ तो कहीं पुराने लेन-देन की गर्माहट धुँधली-सी उँगलियों में फिर जी उठती है।"},"ICON-1354":{"nm":"सोने का सिक्का","de":"हथेली पर रखते ही उसका भारीपन सबसे पहले मन को हिला देता है। धूप में पीला चमकता एक सिक्का, रखने से मानो अमीर बन जाओगे लगता है—पर सच तो यह है कि सबसे उजली चमक उसे हाथ में आने से ठीक पहले वाली धड़कन में होती है।"},"ICON-1355":{"nm":"कप्तान की मुहर","de":"लाल मोम पर कसकर दबाकर छापा गया कप्तान का वादा। एक ही निशान से आदेश खड़ा होता और दुर्गम मार्ग तय होता था। सत्ता आख़िर में इतनी ही थी—एक जहाज़ पर सवार सब लोगों का मिलकर मान लिया एक छोटा-सा, मज़बूत ठप्पा।"},"ICON-1356":{"nm":"हैंडहेल्ड माइक","de":"हाथ में थामते ही अजीब-सा भरोसेमंद भार हथेली भर देता है। काँपता पहला अभिवादन देते वक़्त भी, आख़िर में ऊँचा सुर छेड़ते पल भी—यह एक छोटी-सी छड़ी तुम्हारी आवाज़ को हौले से पंख लगा देती है।"},"ICON-1357":{"nm":"वायरलेस माइक","de":"तार ग़ायब होते ही मंच पूरा और चौड़ा हो गया। दर्शक-दीर्घा के अंत तक दौड़ जाओ तब भी आवाज़ एक बार भी टूटती नहीं, मानो कोई पीठ पर हौले से धकेलकर कह रहा हो, जी भर के दौड़ो और गाओ।"},"ICON-1358":{"nm":"स्टैंड माइक","de":"पैरों के पास मज़बूती से खड़ा होकर चुपचाप गायक का इंतज़ार करता है। दोनों हाथ आज़ाद हों तो गीत उँगलियों की जगह पूरे शरीर में फैल जाता है। एक ही जगह आख़िर तक टिके रहने में भी एक साफ़ आन होती है, यह छड़ी चुपचाप कहती है।"},"ICON-1359":{"nm":"पॉप फ़िल्टर","de":"माइक के आगे गोल-सा आड़े खड़े कपड़े की एक परत। तेज़ साँसों को नरमी से छान लेती है और सिर्फ़ साफ़ आवाज़ को पार जाने देती है। किसी को साफ़ सुनवाना दरअसल आख़िर तक अनदेखी जगह पर टिककर चुपचाप रोकना है।"},"ICON-1360":{"nm":"इन-इयर मॉनिटर","de":"कान में फिट बैठते ही हज़ारों की जय-जयकार के पार अपना गीत साफ़-साफ़ फिर जी उठता है। रोशनी और आवाज़ दोनों उमड़ते मंच पर लय न छूटने देने वाला, सबसे छोटा और सबसे गुप्त साथी।"},"ICON-1361":{"nm":"हेडफ़ोन","de":"कानों को ढँकते ही दुनिया एक बित्ता छोटी हो जाती है और सिर्फ़ गीत बड़ा रह जाता है। एक गोल कमरा जिसमें कोई घुस नहीं सकता। अकेले लगाए हेडफ़ोन के भीतर, अजीब बात है कि तुम अकेले नहीं होते।"},"ICON-1362":{"nm":"संगीत-पत्र","de":"काली बिंदियाँ जब लकीरों पर चुपचाप बैठ जाती हैं, तो चुप बैठा काग़ज़ आवाज़ को अपने भीतर सहेज लेता है। यह पढ़ी नहीं, सुनी जाने वाली लिखावट है। खोलते ही, थमा हुआ गीत फिर से साँस लेने लगता है।"},"ICON-1363":{"nm":"गायन-पत्र","de":"जहाँ-जहाँ साँस लेनी हो, वहाँ छोटा-सा गोला बना दिया गया है। यहाँ भीतर खींचो, वहाँ धीरे से छोड़ दो। आवाज़ को चोट न लगने देने के लिए राह साफ़ करता, एक स्नेहिल नक़्शा।"},"ICON-1364":{"nm":"पियानो-पत्र","de":"दस उँगलियाँ एक साथ राह पूछती हैं, ऐसा एक पन्ना। बायाँ हाथ जड़ पकड़ता है, दायाँ हाथ गीत उकेरता है। अलग-अलग कहानी कहते रहे दोनों हाथ, आख़िरी माप में आख़िरकार एक होकर मुड़ जाते हैं।"},"ICON-1365":{"nm":"गिटार कॉर्ड चार्ट","de":"उँगलियों की पहली विदेशी भाषा का पहला शब्द यहीं लिखा है। छह बिंदियाँ जब गोल घेरों में जमा होती हैं, तभी एक सुर गूँजता है। दबाते-दबाते बीती हर रात, उँगलियों की नोक पर कड़क खाल जम जाती है।"},"ICON-1366":{"nm":"मेट्रोनोम","de":"टक, टक—एक अडिग क़दम बग़ल में बजता रहता है। जब मन आगे दौड़ने लगे तो पीछे से धीरे-धीरे, धीरे-धीरे थाम लेता है। लय आख़िर में साथ चलने का ही एक वादा है।"},"ICON-1367":{"nm":"ट्यूनर","de":"सुई जब बीचोंबीच सरककर आ जाती है, तभी सुर अपनी जगह पाता है। न ऊँचा, न नीचा, वह एक ही बिंदु। मेल खाना दरअसल यही है—अब और न काँपते हुए चुपचाप थम जाना।"},"ICON-1368":{"nm":"पियानो-कुंजी कार्ड","de":"एक-एक पन्ना पलटते ही चाबियाँ हथेली में चलकर आ जाती हैं। सा से नी तक, सात ख़ानों का एक छोटा-सा ब्रह्मांड। असली पियानो न होने वाली रातों में भी, गीत यहीं चुपचाप बढ़ता रहता है।"},"ICON-1369":{"nm":"गिटार पिक","de":"अँगूठे और तर्जनी के बीच फँसाया जाने वाला, छोटा-सा मज़बूत टुकड़ा। गिर जाए तो कुर्सी के नीचे हमेशा के लिए ग़ायब हो जाता है, पर हाथ में आते ही छहों तार एक साथ गूँज उठते हैं।"},"ICON-1370":{"nm":"ड्रमस्टिक","de":"दोनों छड़ें हवा में टकराती हैं तो वहीं एक इशारा गिरता है। एक, दो, तीन, चार। बिखरे हुए सबके दिल उन चार मात्राओं की ताल पर एक ही रफ़्तार से धड़कने लगते हैं।"},"ICON-1371":{"nm":"टैम्बोरीन","de":"एक बार बजाने पर धूप के बारीक टुकड़ों की तरह साफ़ आवाज़ चारों ओर बिखर जाती है। हल्की दिखने वाली, पर जब उत्साह ठंडा पड़ने लगे तो सबसे पहले हाथ इसी ताल की ओर जाता है। छोटी होकर भी इसे कोई अनदेखा नहीं कर सकता।"},"ICON-1372":{"nm":"डांस स्नीकर्स","de":"फ़र्श पर फिसलते हुए घूमने वाले पैरों के लिए, घर्षण ही हथियार बन जाता है। घिसे हुए तलवे में बार-बार का घुमाव उकेरा जाता है। सबसे शानदार क़दम हमेशा एक मज़बूत जोड़ी से ही शुरू होता है।"},"ICON-1373":{"nm":"नी पैड","de":"अनगिनत बार घुटनों के बल गिरकर फिर उठे लोग ही जानते हैं, इस पतले कपड़े की एक परत का शुक्रिया। फ़र्श को और डरावना न होने देने वाली यह चीज़—हिम्मत कभी-कभी इसी तरह घुटनों पर लपेटी जाती है।"},"ICON-1374":{"nm":"कलाई गार्ड","de":"मुड़ने वाली जगह को पहले से लपेट दें, तो ज़ोरदार हरकत भी कुछ नरम पड़ जाती है। कलाई ख़ामोश रहती है, दर्द होने तक अकेली सहती रहती है। उसी लंबी ख़ामोशी को, एक परत उसकी जगह रोक लेती है।"},"ICON-1375":{"nm":"टखना गार्ड","de":"ऊँची छलाँग के अंत में उतरना है, और उस उतरने के अंत में टखना है। सबसे निचली जगह, जो पूरे शरीर का भार सँभालती है। यह छोटी-सी पट्टी कल की मश्क़ को चुपचाप बचाए रखती है।"},"ICON-1376":{"nm":"स्ट्रेच बैंड","de":"खींचो तो जितना खींचा उतना ही वापस अपनी जगह लौटने की ज़िद करता है। उस प्रतिरोध को सहते-सहते, शरीर अनजाने ही थोड़ा-थोड़ा लंबा होता जाता है। खिंचाव आख़िर में सहे गए समय का छोड़ा निशान है।"},"ICON-1377":{"nm":"योगा मैट","de":"बिछाते ही फ़र्श पर अपने हिस्से की एक ज़मीन बन जाती है। लेटने, झुकने और साँस साधने की एक छोटी-सी सल्तनत। दिन की शुरुआत और अंत, इसी एक चादर पर चुपचाप समेटे जाते हैं।"},"ICON-1378":{"nm":"फ़ोम रोलर","de":"अकड़ी जगह पर धीरे से दबाओ तो पहले दर्द होता है, फिर जल्द ही राहत मिलती है। जो कड़ा हो गया है उसे ढीला करने में हमेशा थोड़ा-सा दर्द होता है ही। शरीर हो या मन, खुलने से पहले उसे एक बार दबना ही पड़ता है।"},"ICON-1379":{"nm":"डम्बल","de":"वही वज़न उठाओ, फिर उठाओ। कल से बस एक बार ज़्यादा, बस इतना ही। किसी चमक-दमक के बिना दोहराव में, बाँह ख़ामोशी से मोटी होती जाती है। बस ईमानदार लोहे का एक टुकड़ा।"},"ICON-1380":{"nm":"केटलबेल","de":"एक ही मूठ से पूरा शरीर घूम जाता है। जब गोल वज़न चक्र खींचते हुए घूमता है, तो थामे रखने वाले का संतुलन जाँच पर चढ़ता है। हिलने से बचना है तो पहले अपना केंद्र जानना होगा।"},"ICON-1381":{"nm":"रस्सी कूद","de":"पैरों तले सरसराते गुज़रते रस्सी को लाँघो, फिर फिर लाँघो। आँगन में दोस्तों के साथ गिनती करते खेले उस खेल जैसा, गिनती जितनी चढ़ती है साँस उतनी ही चढ़ती है और हँसी उतनी ही बढ़ती जाती है।"},"ICON-1382":{"nm":"रनिंग शूज़","de":"सड़क पर उतरने के बाद ही असली क़ीमत पता चलती है, ऐसी एक जोड़ी। भोर की हवा चीरते हुए वही राह फिर दौड़ो तो कल जो मोड़ दूर लगता था, आज पास आ खड़ा होता है। दूरी को पैर याद रखते हैं।"},"ICON-1383":{"nm":"वर्कआउट तौलिया","de":"माथे का पसीना पोंछते ही, वहाँ आज की मेहनत की एक लकीर बस जाती है। धोने पर निशान मिट जाए भले, पर जो बहाया वह कहीं न कहीं क़रीने से जमा होता जाता है। सबसे सच्चा हौसला हमेशा साथ में सूखता है।"},"ICON-1384":{"nm":"पानी की बोतल","de":"ख़ाली हो तो भरो, सूख जाए तो एक घूँट पी लो। यही सीधा-सादा आना-जाना दिन को ख़ामोशी से थामे रखता है। कुएँ पर जैसे बाल्टी ऊपर-नीचे होती थी, वैसे ही भरने के काम से दिन फिर से शुरू होता है।"},"ICON-1385":{"nm":"प्रोटीन शेक","de":"अच्छे से हिलाकर एक घूँट गटको, तो आज तोड़ी मांसपेशी कल फिर से भर उठती है। स्वाद भले चमकदार न हो, पर शरीर जानता है कि यही तो रिकवरी की भाषा है। विकास हमेशा चुपचाप पिया जाता है।"},"ICON-1386":{"nm":"एनर्जी बार","de":"जेब में चपटा दबा एक टुकड़ा। एक भोजन और दूसरे भोजन के बीच, ख़ाली समय भरने वाला आपातकालीन रसद। भव्य कुछ नहीं, पर यह छोटा-सा एक निवाला दोपहर की एक और हरकत सह लेने की ताक़त देता है।"},"ICON-1387":{"nm":"गले की टिकिया","de":"मुँह में घुमाओ तो तीखी पुदीने की महक खुरदुरे हुए गले को हौले से सहला देती है। बहुत बोले दिन, बहुत गाई रात—एक छोटी-सी टिकिया खुरदुरी राह को थपथपा देती है। मिठास का भी बेशक़ कोई काम है।"},"ICON-1388":{"nm":"वोकल चाय","de":"गर्म भाप गले को गर्माहट देती है, और एक घूँट में कंधों का तनाव धीरे से ढीला पड़ जाता है। दादी के बनाए अदरक की चाय जैसा एक पुराना नुस्ख़ा। गाने से पहले, आवाज़ को दिया गया एक स्नेहिल नमस्ते।"},"ICON-1389":{"nm":"शहद-पानी","de":"गुनगुने पानी में एक चम्मच शहद धीरे-धीरे घोलो। गला खुरदुरा होने पर बड़े-बुज़ुर्ग हमेशा बनाकर देते थे, वही प्याला। न दवा, न पेय, बस भीतर से शरीर को चुपचाप सहलाने वाली एक मिठास।"},"ICON-1390":{"nm":"ह्यूमिडिफ़ायर टंकी","de":"कमरे में एक छोटी-सी धुंध छोड़ने वाला बर्तन। सूखी हवा गले को खरोंचने वाली सर्दियों की रात में, बिना दिखे नमी बाँटती है। किसी का ख़याल रखना अक्सर इसी तरह बिना आवाज़ के बहता है।"},"ICON-1391":{"nm":"विश्राम कूपन","de":"\"आराम कर सकते हो\" लिखा एक काग़ज़ का टुकड़ा। हाथ में लेते ही, मन का बोझ एक पायदान हल्का हो जाता है। रुकना भी अभ्यास ही है—यह छोटी-सी पर्ची तुम्हारी जगह यह इजाज़त देती है।"},"ICON-1392":{"nm":"अभ्यास समय-सारणी","de":"ख़ाने-ख़ाने में लिखे समय पर, दिन क़रीने से बैठता जाता है। सुबह स्वर-साधना, दोपहर नृत्य-रचना, शाम विश्राम। धुँधला-सा लगता कल भी लकीरों में बाँट दिया जाए तो, कब चलने लायक़ बन जाता है, पता ही नहीं चलता।"},"ICON-1393":{"nm":"उपस्थिति मुहर","de":"\"आज भी आया\" का एक निशान कसकर दबाकर छापा जाता है। स्याही से हल्का फैला गोल घेरा जैसे-जैसे ख़ाने-दर-ख़ाने बढ़ता है, कुछ न लगने वाली मेहनत कब एक राह बन जाती है, पता ही नहीं चलता। हर दिन का एक छोटा-सा सबूत।"},"ICON-1394":{"nm":"प्रशंसा स्टिकर","de":"\"अच्छा किया\" कहने के बदले, चुपचाप एक तारा चिपका दिया जाता है। नाख़ून जितनी छोटी चमक, पर कॉपी के कोने में बैठते ही पूरा दिन उजला हो जाता है। तारीफ़ छोटी होकर भी, अजीब तरह से देर तक चमकती रहती है।"},"ICON-1395":{"nm":"मानसिक नोट्स","de":"मंच के पीछे काँपते मन को, शब्दों में खोलकर लिख दिया गया पन्ना। अच्छा न बीता दिन भी ईमानदारी से लिख दें तो कहीं-न-कहीं थोड़ा हल्का लगता है। मन जितना भीतर झाँका जाए, उतना ही मज़बूत होता जाता है।"},"ICON-1396":{"nm":"इमेज ट्रेनिंग कार्ड","de":"आँखें बंद करके हाथ में थामते ही, मन में चुपचाप मंच फैल जाता है। अभी न खड़े हुए स्थान पर पहले से एक चक्कर चलकर देख लेने का काम। कल्पना में खींचा गया रास्ता, असली पैरों की नोक से एक क़दम पहले पहुँच जाता है।"},"ICON-1397":{"nm":"भाव-अभ्यास शीशा","de":"शीशे के सामने कभी मुस्कुराते, कभी चेहरा कड़ा करते, वही चेहरा सौ बार से भी ज़्यादा बनाया जाता है। ख़ुशी हो या दुख, दोनों को अभ्यास चाहिए—यह यहीं सीखा जाता है। भाव आख़िर में मन को बाहर उतार लिखने का ही काम है।"},"ICON-1398":{"nm":"नृत्य-रचना नोट्स","de":"पैर और बाँहों के गुज़रने वाले रास्ते को, चित्रों में उतार लिखा गया पन्ना। हर आठ मात्रा पर शरीर को कहाँ जाना है, तीर चुपचाप बता देते हैं। जो हरकत किसी तरह याद नहीं होती थी, वह भी इस पर धीरे-धीरे सध जाती है।"},"ICON-1399":{"nm":"कोरियो वीडियो चिप","de":"एक छोटी-सी चिप में सैकड़ों बार की हरकतें पूरी की पूरी समाई हैं। सोने से पहले एक बार और चलाकर देखो, तो उँगलियाँ अपने-आप उसी राह पर चलने लगती हैं। दोहराव, शरीर से उतार लिखा गया एक और अभिलेख है।"},"ICON-1400":{"nm":"मंच-गतिविधि चार्ट","de":"मंच को ऊपर से देखा गया एक नक़्शा। कौन कहाँ मिलता और कहाँ बिखरता है, यह सब लकीरों और बिंदुओं से पहले ही तय है। कई लोग मिलकर एक चित्र बनाना चाहें तो पहले रास्ते ही बाँटने होते हैं।"},"ICON-1401":{"nm":"रिहर्सल पास","de":"दर्शक-दीर्घा खाली है और रोशनियाँ अभी सोई हुई हैं। यह एक पास तुम्हें उसी सन्नाटे में प्रवेश दिलाता है। जब कोई नहीं देख रहा होता, वही मंच है—और वहीं से शुरू होता है तुम्हारे सबसे ईमानदार रूप से मिलने का समय।"},"ICON-1402":{"nm":"स्टाइल बुक","de":"आज किस मन से पहनूँ? एक कमीज़ को भी कोई मिज़ाज शोभा देता है, यह किताब चुपचाप यही बताती है। जितने पन्ने पलटोगे, दर्पण के सामने हिचकिचाती उँगलियों में उतनी ही छोटी-छोटी समझ जमा होती जाएगी।"},"ICON-1403":{"nm":"हेयर स्प्रे","de":"फुर्र, एक बार छिड़कते ही हवा भी बेपरवाह होकर इसे बिखेर नहीं सकती। मंच पर बस उन चंद मिनटों को बेदाग़ थामे रखने की एक छोटी-सी ज़िद। हर परफेक्ट पल आख़िर ऐसी ही मामूली ज़िद पर पूरा होता है।"},"ICON-1404":{"nm":"मेकअप पैलेट","de":"बारह ख़ानों के रंग, बारह अलग मनोदशाएँ हैं। आज किस भाव से गाना है, उँगलियाँ पहले चुनती हैं और दिल बाद में उनका साथ देता है। ख़ाली होते हर ख़ाने में मंच पर छोड़े गए दिन चुपचाप बसे रहते हैं।"},"ICON-1405":{"nm":"कॉस्ट्यूम पिन","de":"सबसे चमकदार पल में, ठीक उसी जगह जो नज़र नहीं आती, कपड़े को थामे रखती एक छोटी सी पिन होती है। ताकि फिसले नहीं, बिखरे नहीं। मंच की चमक हमेशा किसी की मज़बूती के सहारे खड़ी होती है।"},"ICON-1406":{"nm":"नेम बोर्ड","de":"ख़ाली बोर्ड पर जब नाम भर जाता है, तब कोई धुंधला वादा साफ़ हो उठता है। इस जगह कौन खड़ा होगा—यह एक पंक्ति का लेख तय करता है। नाम दरअसल सबसे छोटा और सबसे मज़बूत संकल्प है।"},"ICON-1407":{"nm":"फैन सर्विस कार्ड","de":"पाने वाला सिर्फ़ एक ही होता है, पर उस एक के लिए यह पूरी दुनिया है। एक छोटी-सी अभिवादन-पंक्ति में कई रातों की कृतज्ञता दबा-दबाकर भरने का काम। दिल हथेली जितने काग़ज़ पर भी यूँ ही छलक उठता है।"},"ICON-1408":{"nm":"हस्ताक्षर अभ्यास पत्र","de":"शुरुआत में अपना ही नाम अनजाना-सा उकेरा जाता है। सौ बार खींचने और हज़ार बार सँवारने की भोर, जब तक हाथ मन से पहले उस लय को याद न कर ले। तभी जाकर एक नाम आख़िरकार हस्ताक्षर बनता है।"},"ICON-1409":{"nm":"इंटरव्यू प्रश्न पत्र","de":"\"इस सवाल का क्या जवाब दूँ।\" काग़ज़ थामे उँगलियाँ हल्के से काँप उठती हैं। जवाब रटने का नहीं, बल्कि सच्चे मन को क्रम से सजाने का समय है—क्योंकि इंटरव्यू हो या इक़रार, आख़िर में दोनों दिल के क्रम का ही सवाल हैं।"},"ICON-1410":{"nm":"विदेशी भाषा शब्दकोश","de":"सबसे घिसा हुआ कोना बताता है कि सबसे ज़्यादा किस शब्द को निहारा गया। जितना वक़्त एक अनजाने उच्चारण को ज़ुबान पर बैठने में लगता है, उतना ही एक बालिश्त कभी न देखी दुनिया की दूरी भी कम होती जाती है।"},"ICON-1411":{"nm":"उच्चारण सुधार कार्ड","de":"लुढ़कता हुआ 'र', फिसलता हुआ 'स'। कार्ड एक-एक करके पलटते हुए ज़ुबान को सधाने की भोरें होती हैं। जितनी बोली साफ़ होती जाती है, उतना ही साफ़ होता जाता है उस चेहरे का ख़याल, जिस तक इन शब्दों से पहुँचना है।"},"ICON-1412":{"nm":"लाइव चेकलिस्ट","de":"माइक ऑन, इन-ईयर जाँचा, चाल-ढाल परखी। हर बॉक्स भरते ही सीने की बेचैनी उतनी ही ख़ाली होती जाती है। मंच पर चढ़ने से पहले, बारीकी ही सबसे शांत क़िस्म का साहस है।"},"ICON-1413":{"nm":"कंडीशन पैच","de":"चिपकाते ही एक जगह गर्माहट से भर उठती है। थका हुआ कंधा, अकड़ी पिंडली—शरीर के छोटे इशारों का चुपचाप जवाब देने वाली हथेली जितनी तसल्ली। अच्छी तरह आराम करना भी अभ्यास का एक हिस्सा है।"},"ICON-1414":{"nm":"आइस पैक","de":"सूजी हुई टख़ने पर चुपचाप रखा जाता है। ठंडक जैसे-जैसे धीरे-धीरे उतरती है, तभी पता चलता है आज कितना दौड़ा गया। मंच के पीछे की रिकवरी हमेशा इसी तरह बिना आवाज़ के आती है।"},"ICON-1415":{"nm":"फर्स्ट-एड पाउच","de":"पट्टी, दर्दनिवारक, छोटा आईना। मामूली-सी चीज़ों से भरी यह छोटी थैली एक पल सबसे बड़ा सहारा बन जाती है। पहले से जोड़ी गई फ़िक्रमंदी अनचाहे संकट के आगे सबसे उजली चमकती है।"},"ICON-1416":{"nm":"क्यू कार्ड","de":"कैमरे के परे से कोई इसे चुपके से ऊपर उठाता है। भूलने ही वाली वह एक पंक्ति वहाँ साफ़-साफ़ लिखी होती है। बिना अटके बहते किसी शो के पीछे हमेशा ऐसा ही एक हाथ होता है, जो कभी स्क्रीन पर नहीं दिखता।"},"ICON-1417":{"nm":"मिशन लिफ़ाफ़ा","de":"लिफ़ाफ़ा खोलने से ठीक पहले का पल सबसे धड़कता है। अंदर जो भी हो, अभी न जानने की वह छोटी-सी रोमांचित घड़ी। वैरायटी शो की असली मज़ा उसी सीलबंद एक पल में पूरा जीवंत है।"},"ICON-1418":{"nm":"नेम टैग","de":"सीने पर टँका एक छोटा-सा नाम पहली नमस्ते की जगह ले लेता है। जो अब तक एक-दूसरे को नहीं जानते, उनके बीच एक नेम टैग अजनबीपन की बर्फ़ को टक से तोड़ देता है। नाम पुकारे जाने के उसी पल से रिश्ता शुरू होता है।"},"ICON-1419":{"nm":"पेनल्टी स्टीकर","de":"हारने वाले के माथे पर टक से चिपकता एक पन्ना ठहाकों की बाढ़ ला देता है। सज़ा कहने के लिए यह बहुत अपना-सा है, कि हारना भी लंबे समय की याद बन जाता है। साथ हँसने के लिए बना एक छोटा, प्यारा-सा निशान।"},"ICON-1420":{"nm":"रैंडम पेनल्टी कार्ड","de":"निकालने से पहले कोई नहीं जानता। हाथी की सूँड़ बनाकर दस चक्कर लगाने हैं या एक बार नखरा दिखाना है। एक पर्ची पर पूरी क़िस्मत सौंपने के उसी पल, हँसी का ग़ुब्बारा सबसे पहले फूट पड़ता है।"},"ICON-1421":{"nm":"संकेत कार्ड","de":"फँसी हुई जगह पर चुपके से बढ़ाया गया हाथ जैसी कोई चीज़। यह पूरा जवाब नहीं देती, बस राह भर बताती है। अच्छा संकेत सही उत्तर नहीं, बल्कि एक बार फिर सोचने का साहस चुपचाप सौंप देने का काम है।"},"ICON-1422":{"nm":"चांस कार्ड","de":"झुके हुए पासे को एक झटके में पलट देने वाला वह इकलौता मौक़ा। यह कार्ड कब निकाला जाए, यही जीत-हार तय करती है। सहेजी और सँजोई गई क़िस्मत आख़िरी और सबसे निर्णायक पल में ही अपनी कीमत साबित करती है।"},"ICON-1423":{"nm":"टाइम-आउट कार्ड","de":"थोड़ी देर रुक जाना ठीक है, यह कार्ड तुम्हारी ओर से यही कहता है। साँस लेने की फ़ुर्सत चाहिए तो निडर होकर हाथ उठाना—रुकना भी एक जायज़ रणनीति है, और अच्छी तरह आराम करना भी हुनर की एक सीट है।"},"ICON-1424":{"nm":"लाफ बटन","de":"टक, दबाते ही खिलखिलाती हँसी की आवाज़ भरपूर बरस पड़ती है। सचमुच मज़ेदार दृश्य में ऐसा साउंड इफ़ेक्ट भी चुपके से हाथ बँटाता है। महफ़िल की गर्माहट यूँ ही एक छोटी शरारत से गर्म होती है।"},"ICON-1425":{"nm":"साउंड इफ़ेक्ट रिमोट","de":"एक बटन पर तालियाँ, दूसरे पर हूटिंग। सिर्फ़ उँगलियों से माहौल गढ़ने वाला जादूगर कंट्रोल रूम में चुपचाप बैठा है। स्क्रीन पर कभी न दिखने वाली यह दिशा-कला ही उस दृश्य को साँस लेता रखती है।"},"ICON-1426":{"nm":"क्लैपरबोर्ड","de":"टक, एक चटख़ आवाज़ के साथ एक कट शुरू होता है। दर्जनों NG और सिर्फ़ एक OK के बीच, यह काला बोर्ड हर पल को साफ़-साफ़ गिनता है। यह रिकॉर्ड का पहला क़दम है।"},"ICON-1427":{"nm":"मार्किंग टेप","de":"पैर की उँगलियाँ जब चुपचाप उस रेखा को छूती हैं, रोशनी मानो इंतज़ार करती हुई हल्के से नीचे उतर आती है। घिस जाने तक याद किया गया वह एक निशान—मंच आख़िर फ़र्श पर खींची एक छोटी रंगीन पट्टी से ही पूरा होता है।"},"ICON-1428":{"nm":"लाइटिंग फ़िल्टर","de":"वही चेहरा रोशनी का रंग बदलते ही पूरी तरह बदल जाता है। नीले फ़िल्टर में भोर बसती है, लाल में साँझ। माहौल कभी दूर नहीं होता—यह तो एक पतले से रंगीन काग़ज़ के भीतर चुपचाप मुड़ा रहता है।"},"ICON-1429":{"nm":"कैमरा बैटरी","de":"लाल बत्ती टिमटिमाने लगते ही दिल पहले बेचैन हो उठता है। क्योंकि सबसे बढ़िया दृश्य हमेशा बैटरी के एक फ़ीसद बचने पर ही आता है। जेब में रखा एक अतिरिक्त टुकड़ा ही जल्द ही साँस लेने की राहत बनता है।"},"ICON-1430":{"nm":"मेमोरी कार्ड","de":"एक दिन भर की हँसी और पसीना नाखून जितनी चिप में ठसाठस भर जाते हैं। इतना छोटा कि खोना आसान, और उतना ही अनमोल भी। सँजोई गई यादों का वज़न कभी आकार से नहीं नापा जा सकता।"},"ICON-1431":{"nm":"पोलरॉइड फ़िल्म","de":"क्लिक, और फिर एक शांत इंतज़ार। सफ़ेद सतह पर धीरे-धीरे चेहरा उभरने के वे चंद पल अजीब-सी सिहरन देते हैं। हाथ में थमी इंस्टेंट फ़ोटो में भी सब्र का एक चम्मच ज़रूर मिलाना पड़ता है।"},"ICON-1432":{"nm":"फ़ोटोकार्ड फ़िल्म","de":"इस एक पन्ने पर कौन-सा भाव छपेगा, यह छपने से ठीक पहले तक राज़ रहता है। किसी का चहेता बनने वाला चेहरा यहीं जन्म लेता है। एक छोटा-सा काग़ज़ इतना बड़ा दिल थामे रहता है।"},"ICON-1433":{"nm":"फ़ोटोकार्ड स्लीव","de":"पोका को नंगे हाथों से नहीं छुआ जाता। एक कोना दब जाए तो उस दिन की मुस्कान तक कसकने लगती है। अपने चहेते को एक पारदर्शी पन्ने में सहेज कर लपेटना—प्यार सँजोने में भी इतनी ही मेहनत लगती है।"},"ICON-1434":{"nm":"टॉपलोडर","de":"दो सख़्त पन्नों के बीच दबाते ही वक़्त भी इसे मनमाने ढंग से मोड़ नहीं सकता। न मुड़ना, न झुकना। किसी क़ीमती चीज़ को सँभालने के काम में हमेशा एक परत मज़बूती की उधार ली जाती है।"},"ICON-1435":{"nm":"स्टीकर पैक","de":"एक-एक करके छीलकर डायरी के कोने पर, लैपटॉप के पीछे टक से चिपकाया जाता है। एक छोटी-सी तस्वीर से बेरंग दिन रंग-बिरंगा हो उठता है। अपने इर्द-गिर्द को सजाने की इच्छा की कोई उम्र नहीं होती।"},"ICON-1436":{"nm":"साइन पेन","de":"स्याही के काग़ज़ पर सरसराने की आवाज़ में क़तार लंबी होती जाती है। धड़कते हाथ से आगे बढ़ाए गए एल्बम पर, बस कुछ सेकंड की मुलाक़ात लंबे समय तक ठहरी रहती है। पेन की नोक से होकर दिल पार जाता है।"},"ICON-1437":{"nm":"सिग्नेचर एल्बम","de":"कवर खोलते ही एक जानी-पहचानी घुमावदार लिखावट पहले नमस्ते कहती है। संगीत से बना रिश्ता काग़ज़ पर एक बालिश्त और क़रीब आ जाता है। सहेज कर रखना यानी उस पल को चुपचाप ठहरा देना।"},"ICON-1438":{"nm":"लाइट स्टिक बैटरी","de":"\"जल जा, प्लीज़।\" प्रवेश से ठीक पहले बैटरी बदलते हाथ व्यस्त हैं। हज़ारों रोशनियों के बीच मेरी वाली बुझ न जाए—एक छोटी बैटरी उस विशाल रात को रौशन कर देती है।"},"ICON-1439":{"nm":"लाइट स्टिक पाउच","de":"बिना एक ख़रोंच के, अगली रात के नारों तक बड़े जतन से सँभाला हुआ। जलती हुई जगह पूरी तरह ठंडी हो जाने पर भी इसे सहेज कर घर लाया जाता है। भजन-वाद्य की भी अपनी जगह होती है, और उस जगह को सँभालने वाला मन भी।"},"ICON-1440":{"nm":"स्लोगन बैनर","de":"लंबे कपड़े पर लिखा वाक्य दर्शक-दीर्घा के आर-पार फैल जाता है। ज़ुबान से न कह पाया गया समर्थन जब खुलकर सामने आता है, एक इंसान का सच्चा दिल पूरे हुजूम की पुकार बन जाता है। वह कपड़ा हूबहू एक आवाज़ बन जाता है।"},"ICON-1441":{"nm":"मिनी बैनर","de":"हथेली में समा जाने वाला एक छोटा-सा समर्थन। दूर टँगा बड़ा बैनर सबका है, पर यह सिर्फ़ तुम्हारी मेज़ के कोने पर ही लहराता है। आकार छोटा हो तो दिल छोटा नहीं होता—यह चुपचाप हिलकर यही साबित करता है।"},"ICON-1442":{"nm":"फैन लेटर","de":"पानेवाले का नाम तीन बार दोबारा लिखा, और पहली पंक्ति सात बार मिटाई। लिफ़ाफ़ा बंद करने से ठीक पहले उँगलियाँ काँपती हैं, क्योंकि दिल बहुत ज़्यादा ईमानदार है। एक टिकट से भी भारी सच्चाई उसके भीतर मुड़ी हुई है।"},"ICON-1443":{"nm":"गिफ्ट रैप","de":"खोलने से ठीक पहले का वह एक सेकंड सबसे रोमांचक होता है, यह किसी से बेहतर रैपिंग पेपर जानता है। जल्द ही फट जाने की क़िस्मत जानते हुए भी, यह देने वाले के दिल जैसी सबसे मुलायम बनावट में ख़ुद को लपेट लेता है।"},"ICON-1444":{"nm":"रिबन","de":"बहुत कसकर बाँधो तो घुटन होती है, ढीला छोड़ो तो खुल जाता है, तो बीच की उस सही जगह को ढूँढना ही असली मेहनत है। उँगलियों से चुनी एक गाँठ में दिल की शक्ल बस जाती है। तोहफ़े की आख़िरी पंक्ति हमेशा रिबन ही लिख देता है।"},"ICON-1445":{"nm":"थैंक-यू कार्ड","de":"ज़ुबान से कहा शुक्रिया हवा में बिखर जाता है, पर हाथ से लिखा जाए तो लंबे समय टिका रहता है। मिली हुई मेहरबानी पर थोड़ा और जोड़कर वापस भेजने का काम। हर हर्फ़ दबाकर लिखते वक़्त दिल दुगना गहरा होता जाता है।"},"ICON-1446":{"nm":"लंचबॉक्स कूपन","de":"इस एक पर्ची से दोपहर के खाने की फ़िक्र धीरे से घुल जाती है। ताज़े पके चावल से भाप उठती हुई, हर ख़ाने में भरा एक भरपूर भोजन जो पहले से वादा किया गया है। भूखी दोपहर को मज़बूती से थामे रखने वाला एक छोटा-सा ताबीज़।"},"ICON-1447":{"nm":"स्नैक कूपन","de":"दोपहर तीन बजे, जब हल्की भूख का इशारा मिले, तब निकालने के लिए बना है यह। एक छोटी मिठाई से मूड आधा बालिश्त ऊपर उठने की बात जानने वाला कूपन। कोई बड़ा इनाम नहीं, पर ठीक ज़रूरत के पल चुपके से पहुँच जाता है।"},"ICON-1448":{"nm":"कैफ़े कूपन","de":"एक गरमागरम प्याला और खिड़की किनारे एक सीट—यह कूपन बस इतना ही वादा करता है। मामूली-सी लगे तो भी किसी के लिए यह दिन गुज़ार लेने का एक छोटा इनाम बन जाता है। एक ऐसा मीठा न्योता जिसकी ख़ुशबू एक क़दम पहले पहुँच जाती है।"},"ICON-1449":{"nm":"डॉर्म क्लीनिंग पास","de":"खिड़कियाँ पूरी खोलकर, रज़ाई झाड़कर, धूल का एक कण तक भागने वाला दिन। ख़ुद न करना पड़े, यह इतना बड़ा ऐशोआराम निकला। कमरा चमकता है तो दिल भी चुपके से सँवर जाता है।"},"ICON-1450":{"nm":"रिपेयर किट","de":"पेचकस, टेप, कुछ अनजान-से पुर्ज़े। सब इकट्ठे हों तो लगता है कुछ भी ठीक न हो, ऐसा कुछ नहीं है, पर खोलकर देखो तो हमेशा एक चीज़ कम निकलती है। फिर भी हाथ में थामते ही अजीब-सा भरोसा जगाने वाला यह विश्वास का डिब्बा है।"},"ICON-1451":{"nm":"लकी टिकट","de":"न सीट, न नंबर—एक बिल्कुल ख़ाली टिकट। आज कौन-सी अच्छी बात होगी, यह उस पर लिखा न होना ही असली बात है। उस ख़ाली जगह को भरना उसी का काम है जो इसे जेब में लिए घूमता है।"},"ICON-1452":{"nm":"पासा","de":"निष्पक्षता शब्द को सबसे अच्छे से जानने वाला दोस्त। किसी का पक्ष नहीं लेता, छहों पहलुओं को बराबर चाहता है। हथेली छोड़कर लुढ़कते हुए दूर जाने के उसी एक पल भर, हुनर और पहचान भी थोड़ी देर के लिए क़िस्मत को अपनी जगह सौंप देते हैं।"},"ICON-1453":{"nm":"ट्रैवल पास","de":"यहाँ से वहाँ तक, बस एक क़दम ही काफ़ी है—यह एक वादा है। लंबी राह को छोटा तह करके जेब में रख देने वाला जादुई काग़ज़। निकलने में हिचकिचाहट के दिन, इससे बेहतर बहाना-रोधक कोई नहीं।"},"ICON-1454":{"nm":"री-ट्राई पास","de":"गिरे हुए को हाथ बढ़ाने की बजाय, दोबारा कोशिश करने को चुपचाप पीठ थपथपाने वाला टिकट। यह सबसे शांत तरीक़े से बताता है कि हार अंत नहीं, बस एक छोटा-सा विराम है। एक बार और की हिम्मत यहीं से उमड़ती है।"},"ICON-1455":{"nm":"क्विक फ़िनिश पास","de":"इंतज़ार को थोड़ा-सा फलाँग जाने वाली एक प्यारी-सी चीट-की। जो दिल तीन मिनट भी सह नहीं सकता, उसे कौन दोष दे सकता है। रेत-घड़ी की रेत को उँगली से टक धकेल देने जैसी, हल्की-सी बेईमान ख़ुशी यहाँ छिपी है।"},"ICON-1456":{"nm":"प्रोडक्शन बूस्टर","de":"वही हाथ, वही वक़्त, फिर भी नतीजा दुगना। राज़ मत पूछो, ऐसे मानो कहते हुए कार्यमेज़ पर व्हिर्र से ख़ुशी-ख़ुशी घूमता है। मेहनती दो हाथों को चुपके से पंख देने वाला एक छोटा-सा यंत्र।"},"ICON-1457":{"nm":"अफ़िनिटी कैंडी","de":"जो अटपटापन शब्दों से नहीं सुलझता, वह मिठास के आगे यूँ ही घुल जाता है। साथ खाई एक टॉफ़ी से रिश्ता कल से एक बालिश्त क़रीब आ जाता है। मिठास ही क़रीब आने की रफ़्तार है, यह एक प्यारी-सी खोज।"},"ICON-1458":{"nm":"मूड रिकवरी जेली","de":"उदास दिन में ठंडी और नरम कोई चीज़ रामबाण होती है। एक कौर खाते ही धुँधला-सा चेहरा चुपके से खिल उठता है। दिल सुधारने का काम वैसे भी अनमोल होता है, इसलिए R रेटिंग यूँ ही नहीं लगी।"},"ICON-1459":{"nm":"स्पार्कल पाउडर","de":"मामूली चीज़ पर हल्के से छिड़को तो अचानक ख़ास बन जाती है। असल में यह बस चमकता हुआ चूर्ण है, फिर भी छिड़कते ही दुनिया थोड़ी और उत्साहित दिखने लगे, यह अजीब बात है। रोज़मर्रा में टक से डाला गया ख़ुशी का मसाला जैसा वजूद।"},"ICON-1460":{"nm":"स्टेज टेप","de":"मंच पर खड़े होते ही अनगिनत रोशनियाँ एक साथ तुम्हें ढूँढ लेती हैं। उस जगह को फ़र्श पर एक छोटा-सा X चुपचाप निशान बना कर रखता है। नज़र से ओझल जगह पर सबसे सटीक चीज़ ही आख़िर सबसे बड़े मंच को थामे रखती है।"},"ICON-1461":{"nm":"केबल टाई","de":"उलझे तारों को एक झटके में क़रीने से सुलझाने वाला एक छोटा हीरो। एक बार कस दो तो वापस नहीं होता, यही इसकी कमी भी है और जादू भी। सफ़ाई को दिल से लेने वालों का चुपचाप सँभाला हुआ ज़रूरी सामान।"},"ICON-1462":{"nm":"स्पेयर केबल","de":"होने पर जिसकी कोई क़दर नहीं, न होने पर ही जिसकी बेइंतहा ज़रूरत महसूस होती है। मंच के पीछे बैग की गहराई में सोया रहता है और निर्णायक पल में पल भर में जाग उठता है। यह अपने पूरे वजूद से \"तैयारी\" शब्द को साबित कर देता है।"},"ICON-1463":{"nm":"रिहर्सल चेक शीट","de":"चाल-ढाल, क्यू, यहाँ तक कि पोशाक बदलने तक—हर ख़ाना ठसाठस भरा काग़ज़। यहाँ एक भी निशान छूट जाए तो किसी का दिल धक से बैठ जाता है। एक बेदाग़ मंच का पर्दा तभी उठता है जब यह पूरा भर चुका हो।"},"ICON-1464":{"nm":"सेट साइनबोर्ड","de":"यहाँ कैफ़े है, वहाँ गली है, तीरों के पीछे-पीछे चलो तो एक बिल्कुल अलग दुनिया। तख़्ते पर रँगा एक झूठ, पर कैमरे के सामने सच बन जाता है। दिशा दिखाने के काम को पूरी ज़िंदगी अर्पित करने वाला एक ईमानदार पथ-प्रदर्शक।"},"ICON-1465":{"nm":"मिनी ट्रॉफ़ी","de":"हाथ में थामते ही अजीब-सा लगे कि क़द एक बालिश्त बढ़ गया, ऐसा सोने का एक टुकड़ा। पहला नंबर न आना बिल्कुल ठीक है, आज की सारी मेहनत मुझे पता है, ऐसा कहती हुई यह मेज़ पर चमकती है। एक छोटा इनाम देने वाली एक बड़ी तसल्ली।"},"ICON-1466":{"nm":"बैकपैक","de":"कंधे पर टाँगते ही लगता है जैसे कहीं भी निकल पड़ा जा सकता है। भीतर भले कुछ ख़ास न हो, संभावनाएँ भरपूर हैं। हर सफ़र इन्हीं कंधे-पट्टियों को कसकर बाँधने से शुरू होता है।"},"ICON-1467":{"nm":"कंपास","de":"राह भटकने पर भी घबराहट न होने की वजह यह है कि सुई की नोक हमेशा उत्तर की ओर इशारा करती है। देर तक डोलते-डोलते आख़िर अपनी जगह ढूँढ लेने का यह रूप बिलकुल इंसानी दिल जैसा है। भटकना ठीक है, यह अपनी काँपती नोक से यही कहता है।"},"ICON-1468":{"nm":"नोटबुक","de":"पहला पन्ना हमेशा ख़ाली रहता है। क्या लिखना है, यह सिर्फ़ क़लम थामने वाला जानता है। मैं तो बस इंतज़ार करती हूँ, कि आज के विचार लिखावट बनकर मुझ पर चुपचाप उतर आएँ। R रेटिंग दरअसल जल्द भरे जाने वाली संभावना का वज़न है।"},"ICON-1469":{"nm":"पेंसिल","de":"ग़लत होना भी ठीक है, यही इस औज़ार का सबसे कोमल पहलू है। रबड़ दोस्त साथ हो तो जितनी बार चाहो, दोबारा शुरुआत की जा सकती है। छिलते-छिलते छोटी होती जाती है, पर यह छोटा होना ही इस बात का सबूत है कि इसे लंबे समय प्यार किया गया।"},"ICON-1470":{"nm":"फ़िल्म","de":"रोशनी गुज़रते ही उस दिन का रंग जस का तस दर्ज हो जाता है। एक फ्रेम गुज़र जाए तो कभी वापस नहीं आता, यही तनाव भी है और आकर्षण भी। तेज़ रफ़्तार दौर में जानबूझकर एक धड़कन धीमा याद रखने वालों की पसंद।"},"ICON-1471":{"nm":"इंस्टेंट कैमरा","de":"क्लिक, और फिर एक छोटा-सा इंतज़ार। हाथ में थामे हल्के से हिलाओ तो धुँधला पल धीरे-धीरे साफ़ होता जाता है। इस पल को इसी जगह एक काग़ज़ के पन्ने पर जस का तस थाम लेने वाली, थोड़ी-सी जादुई मशीन।"},"ICON-1472":{"nm":"पुरानी तस्वीर","de":"रंग जितना उड़ा है, उतना ही वक़्त बीता है। जहाँ-जहाँ कोना घिसा है, वहाँ किसी का स्पर्श ठहरा रहा है। सबसे पुरानी तस्वीर सबसे साफ़ याद क्यों थामे रहती है—शायद उन्हीं स्पर्शों की वजह से।"},"ICON-1473":{"nm":"स्क्रैपबुक","de":"फेंकने में जिनका मन न माने, ऐसे टुकड़े इकट्ठे होते-होते एक पूरी किताब बन जाती है। बासी हुआ फ़िल्म टिकट, सूखी पंखुड़ी, एक छोटा-सा नोट। दूसरों की नज़र में यह कबाड़ हो, पर खोलने वाले के लिए एक पूरा दौर ही ज़िंदा हो उठता है।"},"ICON-1474":{"nm":"यात्रा डायरी","de":"आज की हवा और लहरें, और दिल की एक पंक्ति। बिना किसी घटना वाले दिन भी नियम से लिखना ही समुद्री यात्रा का क़ायदा है। सुरक्षित पहुँचने का सबूत हमेशा इस मोटे रिकॉर्ड में कहीं न कहीं दर्ज होता है।"},"ICON-1475":{"nm":"नक़्शे का टुकड़ा","de":"यह पूरे नक़्शे का बस एक कोना है, पर इसके बिना आख़िर राह नहीं मिलती। फटा हुआ किनारा जब किसी दूसरे टुकड़े से ठीक जुड़ जाए, वह अनुभूति ही कुछ और है। R रेटिंग की मौजूदगी पहेली के आख़िरी टुकड़े जैसी है।"},"ICON-1476":{"nm":"बोतल में चिट्ठी","de":"कौन पढ़ेगा, यह न जानते हुए भी यह चुपचाप ख़ुद को लहरों के हवाले कर देती है। इसे किसी जवाब की उम्मीद नहीं, बस चाहती है कि यह दिल कहीं तो पहुँच जाए। यह सबसे धीमा, पर सबसे रूमानी तरीक़ा है चिट्ठी भेजने का।"},"ICON-1477":{"nm":"पासा","de":"\"फिर तू?\" मानो कहते हुए गोल-मटोल मुस्कुराते छहों पहलू। एक जैसी शक्ल, फिर भी हर बार लुढ़कने पर अलग जवाब देना—यह इस दोस्त की न बदलने वाली मनमानी है। हाथ छोड़ते ही उस पल भर के लिए फ़ैसला क़िस्मत को सौंप दिया जाता है।"},"ICON-1478":{"nm":"पिनव्हील","de":"हवा चले तभी यह जीवंत होती है। यूँ ही छोड़ दो तो बस काग़ज़ के पंख हैं, पर कोई फूँक मार दे तो ख़ुशी-ख़ुशी घूमने लगती है। मदद लेने में शर्म न आना, यही इस छोटे-से फूल की सूझबूझ है।"},"ICON-1479":{"nm":"पिकनिक बास्केट","de":"ढक्कन खुलते ही किम्बाप की ख़ुशबू पहले नमस्ते कहती है। हरी घास, बिछी हुई चटाई, और खाना बाँटते कई हाथ। जिस दिन यह टोकरी भर जाती, अजीब बात है, आसमान हमेशा साफ़ ही रहता था।"},"ICON-1480":{"nm":"फूलदान","de":"एक ही डंठल रखते ही कमरे की हवा बदल जाती है। ख़ाली होने पर चुपचाप इंतज़ार करना ही इसका फ़र्ज़ है। फूल को और चमकाने के लिए अपनी मौजूदगी को धीमे से नीचा दिखाने वाला, कमरे का सबसे विनम्र मंच-साज़।"},"ICON-1481":{"nm":"फूल की पंखुड़ी","de":"हवा जब एक पंखुड़ी को उड़ा ले जाती है, बहार उतनी ही हल्की हो जाती है। आँगन का पुराना पेड़ हर साल वही अभिवादन दोहराता है—गिरना भी खिलने के काम का एक हिस्सा है। बिखरना अंत नहीं, बल्कि अगली बहार को पहले से भेजी गई एक चिट्ठी है।"},"ICON-1482":{"nm":"गुलाब","de":"पहले काँटे खड़े करना यह वादा है कि इसे यूँ ही न छुओ। उसके भीतर सबसे लाल दिल छिपा है। किसी ने एक डंठल चुपचाप पाँव के पास रख दिया और नाम की जगह सिर्फ़ रंग में दिल लिखकर चला गया।"},"ICON-1483":{"nm":"लिली","de":"निर्मल सफ़ेद चीनी मिट्टी के बर्तन के पास हमेशा यह सफ़ेद फूल रखा जाता रहा। ख़ुशबू भले दूर तक जाए, पर अदा कभी न बिखरे। तड़क-भड़क की जगह पवित्रता चुनने वाली उस जगह पर, लिली चुपचाप एक कोने की गरिमा थामे रखती है।"},"ICON-1484":{"nm":"ट्यूलिप","de":"सिर थोड़ा झुकाए क़तार में खड़े होने की मुद्रा अजीब-सी सलीक़ेदार लगती है। बहार की क्यारी की पहली पंक्ति सँभालने वाला फूल। एक साथ खिलने और एक साथ झड़ने की वह ईमानदारी छोटे मौसम को सबसे गहरे रंग में रँग देती है।"},"ICON-1485":{"nm":"हाइएसिंथ","de":"एक ही डंठल पर छोटी घंटियाँ ठसाठस टाँगी हैं। हिलाने पर आवाज़ नहीं आती, पर उसकी जगह ख़ुशबू पूरे कमरे में गूँजती है। बहार की दहलीज़ पर, एक फूलदान से कमरे की पूरी हवा बदल देने वाली एक कोमल ऐयाशी।"},"ICON-1486":{"nm":"मेंढक नमूना","de":"शीशे के डिब्बे में वक़्त थमा हुआ एक छोटा-सा शरीर। लेबल पर लिखा है—'खेत और जलाशय, बारिश के अगले दिन सबसे ज़्यादा फुर्तीला।' थमने के बाद ही, किसी जीव के रहने वाले पानी के किनारे का तापमान तक रिकॉर्ड में रह जाता है।"},"ICON-1487":{"nm":"छिपकली नमूना","de":"पूँछ काटकर भाग जाने वाली उस चतुराई को नमूना बन जाने पर भी मिटाया नहीं जा सकता। धूप-सेकी पत्थर की दीवार को पसंद करने वाला एक छोटा मेहमान। पास रखे नोट में उसकी पसंदीदा धूप की दिशा साफ़-साफ़ लिखी है।"},"ICON-1488":{"nm":"छछूँदर रिकॉर्ड","de":"ज़मीन के भीतर घूमने वाले की डायरी मिट्टी की बुनावट में लिखी जाती है। कहाँ खोदा, कहाँ रुका—अदृश्य राहों का एक नक़्शा। रोशनी को पीठ दिखाकर बिताया गया वक़्त भी किसी के लिए बेहद ईमानदार रिकॉर्ड बन जाता है।"},"ICON-1489":{"nm":"सीप नमूना","de":"लहरों ने हज़ारों बार सँवारकर भेजा एक मज़बूत बुनावट। तटीय गाँव के लोग सिर्फ़ ख़ोल की बुनावट देखकर ही बता देते थे कि यह किस समुद्र की है। कभी साँस लेता समुद्र का यह रूप हथेली जितने नमूने में जस का तस समाया है।"},"ICON-1490":{"nm":"प्रवाल नमूना","de":"गहरे समुद्र में सैकड़ों साल में मुश्किल से एक बालिश्त बढ़ता है। शाख़ जैसा दिखता है, पर असल में यह अनगिनत छोटी जानों का साथ बनाया घर है। जो जितना धीमा है, वह उतना ही लंबा टिकता है, यह मूँगा चुपचाप साबित कर देता है।"},"ICON-1491":{"nm":"आइडोंग सुराग़","de":"टापू पर कहीं बिखरी एक कहानी का एक टुकड़ा। एक छोटी-सी काग़ज़ की पर्ची चुपचाप अगले क़दम की तरफ़ इशारा करती है। हर मुहिम आख़िर ऐसे ही मामूली निशान उठाने से शुरू होती है, ऐसा पुराना राहनुमा कहता है।"},"ICON-1492":{"nm":"सिग्नेचर टुकड़ा","de":"बिखरा हुआ नक़्श जब अपनी जगह पा लेता है, तभी एक निशान पूरा बनता है। किसी की अपनी अनूठी बुनावट खुदी हुई यह टुकड़ा। जुड़ने से पहले तक अपना मतलब छुपाए रखता है, जुड़ते ही आख़िरकार एक नाम बन जाता है।"},"ICON-1493":{"nm":"स्टेज मेमोरी शार्ड","de":"एक गीत ख़त्म होने के बाद भी दर्शक-दीर्घा में शेष गर्माहट बनी रहती है। उस गर्माहट को उतारकर जमाओ तो ऐसा ही एक छोटा टुकड़ा बनता है। बिखरी तालियों और हुर्रे की किरचें, चुपचाप इकट्ठी करो तो वह पूरी रात फिर से जी उठती है।"},"ICON-1494":{"nm":"डेब्यू स्टैंप","de":"पहली बार अपना नाम पुकारे जाने वाले दिन, हाथ की पुश्त पर लगा वह स्याही का निशान। फैले नहीं इसलिए बड़ी सावधानी से सुखाया गया मन ही असली शुरुआती रेखा था। एक छोटी मुहर एक ख़ास दिन को हमेशा के लिए अमिट बना देती है।"},"ICON-1495":{"nm":"टॉप आइडल मेडल","de":"सबसे ऊँचे मुक़ाम पर पहुँचने वाले को ही मिलने वाला वह भारीपन। पर यह मेडल भारी धातु की वजह से नहीं है। मंच को साथ भरने वाले अनगिनत हाथों का वज़न ही एक बिंदु पर जस का तस इकट्ठा हो जाता है।"},"ICON-1496":{"nm":"छोटी चाबी","de":"डॉर्मिटरी की पहली चाबी हमेशा सबसे भीतरी कमरे की होती थी। जहाँ बंद करना सीखने से पहले खोलना सीखा जाता था। जाने के दिन, ठंडी धातु पर हथेली की छोड़ी गर्माहट देर तक टिकी रहती है।"},"ICON-1497":{"nm":"ख़ज़ाना बक्सा","de":"खुलने से पहले तक कोई नहीं जानता कि भीतर क्या है। यही न-जानना ख़ज़ाना बक्से का असली ख़ज़ाना है। ढक्कन उठाने के उस छोटे पल में, हर कोई पल भर के लिए बचपन की उसी धड़कन में लौट जाता है।"},"ICON-1498":{"nm":"नक़्शा (ब्लूप्रिंट)","de":"एक-एक करके खींची लकीरों पर अभी न बनी हुई इमारत बसती है। नक़्शा खोलना कल को पहले से एक बार चलकर देखने जैसा है। एक अच्छी तरह खींची लकीर ही न ढहने वाले कल को थामे रखती है।"},"ICON-1499":{"nm":"रेसिपी कार्ड","de":"हाथों से घिसे एक कार्ड पर दादी माँ का स्वाद मात्रा बनकर लिखा है। 'नमक एक चुटकी' जैसी धुँधली बात ही सबसे सटीक राज़ है। जितनी लिखावट धुँधली होती जाती है, उतनी ही साफ़ याद आती है वह रसोई जहाँ यह पकवान कभी उबलता था।"},"ICON-1500":{"nm":"सुविधा अनुमति-पत्र","de":"एक काग़ज़ ख़ाली ज़मीन को 'इस्तेमाल के क़ाबिल जगह' में बदल देता है। नई इमारत को हमेशा पहले गाँव की मुहर चाहिए होती थी। अनुमति, आख़िर में, यही कहने वाली एक गर्मजोश मुहर है कि यहाँ कुछ शुरू करना ठीक है।"},"ICON-1501":{"nm":"बंदरगाह अनुमति-पत्र","de":"जहाज़ के लंगर डालने से पहले उसे यही एक काग़ज़ चाहिए होता था। बंदरगाह की धुंधली मुहर दूर से आए यात्री का पहला स्वागत होती है। जाने और पहुँचने के बीच, बंदरगाह हमेशा एक काग़ज़ के टुकड़े से ही दिल खोलता है।"},"ICON-1502":{"nm":"द्वीप-सदस्यता प्रमाण-पत्र","de":"यह छोटा प्रमाण-पत्र बताता है कि तुम अब इस द्वीप के अपने बन गए हो। पुराने गाँव में जब कोई नया पड़ोसी आता, तो उसका नाम सूची में जोड़कर गरम चावल के केक बाँटे जाते थे। यह मात्र एक काग़ज़ है, पर उस पर लिखा है वह उजला स्वागत—\"अब तुम भी हम में से एक हो।\""},"ICON-1503":{"nm":"निवास-नामपट्ट","de":"दरवाज़े के पास टँगा एक नाम ही खाली कमरे को आख़िरकार किसी का घर बना देता है। पुराने अतिथि-गृहों में भी सबसे पहले स्वामी का नाम खुदा हुआ पट्ट टाँगा जाता था। नामपट्ट छोटा भले हो, पर उसमें यह गर्माहट भरी है—\"यहाँ कोई रहता है।\""},"ICON-1504":{"nm":"फैनडम डाक-टिकट","de":"थूक लगाकर दबाकर चिपकाने की वह लगन ही एक सम्पूर्ण चिट्ठी बनाती थी। छोटे से काग़ज़ पर अपने पसंदीदा एहसास को टिकाकर दूर भेज देने का काम। डिजिटल युग में भी कोई न कोई अब भी अपना दिल हाथ से ही डाक में भेजता है।"},"ICON-1505":{"nm":"चमकीला द्वीप-बैज","de":"कॉलर पर लगाते ही एक छोटी रोशनी हर राह में साथ चलने लगती है। रास्ते में वही बैज पहने किसी से मिलो, तो बिना कुछ कहे ही बात समझ आ जाती है। यह चमक दिखावा नहीं, बल्कि एक शांत संकेत है—\"हम एक ही द्वीप से प्यार करते हैं।\""},"ICON-1506":{"nm":"कार्य-मेज़","de":"निशानों से भरी सतह उन हाथों की गवाही देती है जिन्होंने सबसे ज़्यादा चीज़ें गढ़ीं। यह वह जगह है जहाँ चीज़ें ठीक की गईं, जोड़ी गईं, सँवारी गईं। साफ़-सुथरी मेज़ से कहीं ज़्यादा, बिखरी हुई कार्य-मेज़ में असल में और भी कहानियाँ छिपी होती हैं।"},"ICON-1507":{"nm":"संग्रह-पेटी","de":"जो चीज़ जितनी क़ीमती होती है, उतनी ही पहले उसकी जगह तय कर दी जाती है। पुराने ज़माने के लोग भी क़ीमती दस्तावेज़ों को पौलाउनिया लकड़ी के संदूक में अलग रखते थे। कुछ अच्छी तरह सँभालना, आख़िरकार, आने वाले किसी के लिए आज को करीने से तह करके रख देना है।"},"ICON-1508":{"nm":"संसाधन-पेटी","de":"जब बहुतायत हो तो जमा कर लो, जब कमी हो तो निकालकर काम में लाओ। यहाँ उस दौर की समझ छिपी है जब भरा हुआ भंडार-घर ही मन को भरोसा देता था। भंडारण, असल में, अपने आने वाले कल को पहले से थमाया गया एक स्नेह भरा भोजन है।"},"ICON-1509":{"nm":"ठंडा-पेटी","de":"बर्फ़ से भरा यह संदूक कड़ी गर्मी में भी ठंडक थामे रखता था। मानो बर्फ़-घर की पुरानी सूझ-बूझ हथेली भर आकार में उतर आई हो। ठंडक बचाए रखना असल में सबसे ताज़ा पल को थोड़ी देर और टिकाए रखना है।"},"ICON-1510":{"nm":"हैंड-पंप","de":"हत्थे को ऊपर-नीचे हिलाते ही ज़मीन के भीतर से गहरा पानी उमड़ आता है। एक ईमानदार मशीन, जो पहले एक कटोरा पानी डाले बिना नहीं बहती थी। पहले देना पड़ता है, तभी मिलता है—यह सच कुएँ के किनारे ने बहुत पहले जान लिया था।"},"ICON-1511":{"nm":"जल-शोधक","de":"धुंधला पानी परत दर परत साफ़ होकर निकलता है, यह एक छोटा चमत्कार है। पुराने लोग मटकों में रेत और कोयला परत दर परत बिछाकर पानी छानते थे। स्वच्छता मुफ़्त नहीं मिलती, यह तो धीरे-धीरे छानने की लगन है।"},"ICON-1512":{"nm":"पानी की झारी का स्टैंड","de":"जिस पल झारी को अपनी विश्राम-जगह मिलती है, उस पल फूलों की क्यारी का दिन सँवर जाता है। औज़ार को टाँगने की जगह तय करना उस इंसान की आदत है जो अपने काम से प्यार करता है। एक जगह तय होते ही पूरा आँगन कहीं ज़्यादा सुथरा लगने लगता है।"},"ICON-1513":{"nm":"मछली पकड़ने की छड़ का स्टैंड","de":"मछली के काटने तक इंसान भले चला जाए, पर छड़ अपनी जगह थामे रहती है। नदी किनारे बरसों को यूँ ही खींचते रहने की वह धैर्य भरी मुद्रा यहीं जड़ी रह जाती है। स्टैंड, आख़िरकार, बेचैनी को थोड़ी देर के लिए टिकाने वाला एक सहारा है।"},"ICON-1514":{"nm":"चुनाई की टोकरी","de":"पहाड़ी साग की एक मुट्ठी, जंगली फूल की एक कली लेकर लौटती माँ के हाथ का बोझ। बुने हुए बाँस की दरारों से मिट्टी की गंध धीरे-धीरे रिस आती है। उसमें क्या भरा है, इस पर निर्भर करता है कि खाली टोकरी बसंत बने या पतझड़।"},"ICON-1515":{"nm":"ओखली-मूसल","de":"धम्म, धम्म, एक-सी लय में अनाज कूटते ही गाँव का दिन जाग उठता था। त्योहारों पर जिसकी कूटने की आवाज़ गलियों में गूँज उठती थी, ऐसा औज़ार। कठोर को कोमल बनाने के लिए हाथ की स्थिर लय चाहिए होती है।"},"ICON-1516":{"nm":"चॉपिंग बोर्ड","de":"चाकू के गुज़रे हर निशान में एक वक़्त के भोजन का इतिहास उकेरा जाता है। खरोंचों से भरा लकड़ी का तख़्ता रसोई का उस हाथ के लिए तमगा है जो सबसे ज़्यादा मेहनती रहा। किसी चीज़ को काटना उसे प्रेम से परोसने की इच्छा से ही शुरू होता है।"},"ICON-1517":{"nm":"पतीला","de":"उबलते पानी की गुड़गुड़ आवाज़ किसी भी संगीत से ज़्यादा अपनी लगती है। भूख से बेचैन तड़के, नूडल्स के पकने का इंतज़ार करते वे तीन मिनट सबसे निजी सुकून होते हैं। गोल तले भर, किसी को खिलाने की चाहत की गर्माहट पकती रहती है।"},"ICON-1518":{"nm":"तवा","de":"आग पर पल भर में पका देने की कुशलता इसी एक तवे पर टिकी होती है। जितनी अच्छी तरह मसा हुआ तल हो, उतना ही कम चिपकता और उतना ही ज़्यादा चमकता है। बरसों से इस्तेमाल हुआ लोहे का तवा ख़ुद ही रसोई के बीते सालों का सबूत है।"},"ICON-1519":{"nm":"ओवन","de":"दरवाज़ा बंद करके इंतज़ार करते समय, भीतर चुपचाप जादू घटता रहता है। जब आटा फूलता है और रंग पकने लगता है, वह समय। दिखे न दिखे, भरोसा रखकर इंतज़ार करो तो एक गर्म नतीजा दरवाज़ा खोलकर बाहर आ ही जाता है।"},"ICON-1520":{"nm":"मिक्सर","de":"कठोर से कठोर चीज़ भी इसमें डालते ही पल भर में एक मुलायम गिलास बन जाती है। अलग-अलग सामग्रियाँ मिलकर एक नया स्वाद जन्म लेता है, ऐसा एक छोटा भँवर। सामंजस्य, आख़िरकार, हर किसी के अपने कोनों को थोड़ा-थोड़ा छोड़ देने का नाम है।"},"ICON-1521":{"nm":"फेंटनी","de":"कलाई की एक ही हरकत में हवा क़ैद हो जाती है, और फेंटने की रफ़्तार जितनी तेज़, पतला मिश्रण उतना ही सख़्त खड़ा होने लगता है। जब झाग चोटियों-सी उठने लगती हैं, तो सिर्फ़ घोल ही नहीं फूलता। आज किसी को खिलाने की चाहत भी उसी के साथ फूलती है।"},"ICON-1522":{"nm":"कॉफ़ी ग्राइंडर","de":"मुट्ठी भर बीजों पर हत्था घुमाते ही दाँतों के बीच सुगंध सबसे पहले टूटती है। जब बाँह अकड़ने लगे, तब कहीं जाकर पिसाई बारीक होती है, और उतनी ही मेहनत से पहला घूँट गहरा होता है। लगन हमेशा कलाई से ही शुरू होती है।"},"ICON-1523":{"nm":"आटा-चक्की","de":"दाना पत्थरों के बीच जाकर सफ़ेद आटा बनकर निकलता है। पहली बार बारीक न हो तो कोई बात नहीं, दो बार और पीस लो। खुरदरे को महीन बनाने में भी एक क्रम होता है, यह चक्की चुपचाप सिखाती है।"},"ICON-1524":{"nm":"चीरा-मेज़","de":"लट्ठा चढ़ते ही आरी पहले उसकी रेशों को पढ़ती है। गाँठों से बचकर सीधी राह पर ही चीरो, तभी तख़्ता मुड़ता नहीं। लकड़ी काटना, आख़िरकार, एक पेड़ के जिए हुए समय को करीने से बिछाना है।"},"ICON-1525":{"nm":"सिलाई मशीन","de":"घर्र-घर्र—सुई का कपड़ा पकड़कर दौड़ने की आवाज़ देर रात को भर देती है। एक ही सीवन दो टुकड़ों को एक देह में जोड़ता है, और मंच के परिधान के भीतर छिपी हर टाँके में किसी की नींद-रहित घड़ियाँ मज़बूती से सिली जाती हैं।"},"ICON-1526":{"nm":"रँगाई-मेज़","de":"सफ़ेद कपड़े को डुबोकर निकालो तो पहले हल्का हरा दिखे, फिर हवा से मिलते ही आख़िरकार नीला हो जाए। वह रंग जो तभी आता है जब नील को तीन बार भिगोया जाए। इंतज़ार ही रंग बन जाता है, यह मैंने पहली बार इसी रँगाई-मेज़ के सामने सीखा।"},"ICON-1527":{"nm":"कैमरा तिपाई","de":"तीन टाँगें फैलाकर ज़मीन थामते ही, काँपती दुनिया थम जाती है। हाथ में पकड़ने पर जो तस्वीर काँप जाती, वही इन तीन बिंदुओं के वादे पर स्पष्ट हो उठती है। किसी चीज़ को देर तक निहारना है तो पहले टिककर खड़ा होना आना चाहिए।"},"ICON-1528":{"nm":"लाइट स्टैंड","de":"एक खंभे पर रोशनी टिकाते ही कमरे का कोई भी कोना छोटा मंच बन जाता है। कोण को हल्का सा मोड़ते ही परछाइयाँ लंबी होती हैं और भाव जीवंत हो उठते हैं। यह अँधेरा मिटाता नहीं, बल्कि अँधेरे को भी प्रेम से उसकी जगह पर रख देता है।"},"ICON-1529":{"nm":"माइक स्टैंड","de":"ऊँचाई सेट होते ही मुँह और गीत के बीच की दूरी तय हो जाती है। हाथ हटा लो तो भी आवाज़ वहीं ठहरी रहती है। जब दोनों हाथ आज़ाद हों, तभी उस मंच पर पूरे बदन से गाया जाने वाला गीत सचमुच शुरू होता है।"},"ICON-1530":{"nm":"सुर-लेख स्टैंड","de":"खुला हुआ पन्ना तिरछा टिकते ही, स्वर वादक की नज़र की ऊँचाई पर पंक्तिबद्ध हो जाते हैं। एक इशारे में अगला बंद आ भी जाए, तो सहारा डगमगाता नहीं। किसी के वादन के पीछे हमेशा एक ख़ामोश जगह होती है।"},"ICON-1531":{"nm":"घर की क्यारी","de":"मिट्टी जोतकर नालियाँ बनाओ तो ज़मीन पर वादे की छोटी लकीरें उभर आती हैं। बीज दबे कुछ दिन कुछ न होने जैसा लगे, पर किसी सुबह कोमल अंकुर मिट्टी को धकेलकर ऊपर आ जाते हैं। यह दृश्य केवल उसे दिखता है जिसने इंतज़ार किया।"},"ICON-1532":{"nm":"उर्वर क्यारी","de":"बीज वही है, पर इस मिट्टी में पत्तियाँ दोगुनी बड़ी होती हैं। उँगली धँसाओ तो काली, मुलायम मिट्टी नाख़ूनों तक साथ आती है। अच्छी तरह उगना, आख़िरकार, अनदेखी ज़मीन का पैरों तले चुपचाप किया गया काम था।"},"ICON-1533":{"nm":"ग्रीनहाउस","de":"शीशे की छत के नीचे मौसम एक ताल धीमे बहता है। बाहर पाला पड़े तो भी भीतर मध्य-ग्रीष्म की नमी बरकरार रहती है। ठंड से कमज़ोर चीज़ों के लिए किसी ने धूप को छत में चुपचाप क़ैद कर रखा है।"},"ICON-1534":{"nm":"जड़ी-बूटी क्यारी","de":"उँगलियों की नोक से पत्तियों को छुओ तो सुगंध पहले नमस्ते कहती है। तुलसी, रोज़मेरी, पुदीना—हर नाम पुकारते ही एक अलग गंध उँगलियों से चिपक जाती है। एक छोटी सी क्यारी पूरी रसोई को स्नेह से बदल देती है।"},"ICON-1535":{"nm":"फलों का बाग़","de":"बसंत में फूलों की छाँव से, पतझड़ में फलों के भार से डालियाँ झुक जाती हैं। सीढ़ी चढ़कर एक फल तोड़कर काटो तो पूरे साल की धूप से बटोरी मिठास मुँह में फूट पड़ती है। यह मानो पेड़ का इंसान को दिया गया एक जवाब हो।"},"ICON-1536":{"nm":"मशरूम लट्ठा","de":"कटे हुए लट्ठे में छेद करके बीज बोओ तो मरा हुआ पेड़ फिर कुछ उगा देता है। कुछ दिन बाद जिस सुबह टोपियाँ गुच्छों में फूटती हैं, अंत मानी गई जगह पर एक नई गृहस्थी चुपचाप शुरू होती है।"},"ICON-1537":{"nm":"मधुमक्खी का छत्ता","de":"कान पास ले जाओ तो भीतर से एक धीमी, फुर्तीली गुनगुनाहट सुनाई देती है। हज़ारों बार फड़फड़ाए पंख मिलकर मुश्किल से एक चम्मच भर मिठास बनाते हैं। फूलों के बीच आते-जाते एक दिन की मेहनत यहाँ चिपचिपी और सुनहरी बनकर टिकी है।"},"ICON-1538":{"nm":"मुर्ग़ीघर","de":"भोर होने से पहले, टहनी पर बैठे पंछी सबसे पहले खड़बड़ाने लगते हैं। गरम पुआल में हाथ डालो तो अब भी गर्माहट लिए एक अंडा हाथ लगता है। जो जगह सबसे पहले सुबह की ख़बर देती है, वही सबसे पहले सुबह की थाली सजाती है।"},"ICON-1539":{"nm":"चरागाह","de":"घास की गंध और धूप की गंध घुली-मिली एक विशाल मैदान। बाड़े के भीतर धीरे-धीरे जुगाली करती पीठों के ऊपर से बादलों की परछाइयाँ गुज़रती हैं। यहाँ जल्दबाज़ी की कोई ज़रूरत नहीं, यहाँ समय भी घास चरने जैसा धीमे बहता है।"},"ICON-1540":{"nm":"चीज़ बनाने की कार्यशाला","de":"ताज़ा निकाला दूध जमने और पकने से होकर धीरे-धीरे सख़्त होता है। गुफ़ा-सी ठंडी अलमारी पर कुछ महीने इंतज़ार करो तो सफ़ेद टुकड़े में गहरा स्वाद बस जाता है। चीज़ वह नाम है जो केवल जल्दबाज़ी न करने वाले दूध को मिलता है।"},"ICON-1541":{"nm":"टोफ़ू बनाने की कार्यशाला","de":"सोयाबीन भिगोकर पीसकर उबालो तो कच्चा फीका दूध सुगंधित हो उठता है। नमकीन घोल की एक बूँद बिखरे हुए को इकट्ठा कर नरम टोफ़ू बना देती है, और धीरे दबाने से कोनें उभर आते हैं। बिखरे मन को सहलाकर आकार देने वाला हाथ यहीं है।"},"ICON-1542":{"nm":"मर्तबान चबूतरा","de":"धूप भरे आँगन के एक कोने में नाटे मटके इकट्ठे होकर धूप सेंकते हैं। ढक्कन खोलो तो बरसों पुराने समय की गंध एकदम से नाक तक आ जाती है। दादी का बनाया चटनी-सा स्वाद असल में सालों को चम्मच-चम्मच खाने का काम है।"},"ICON-1543":{"nm":"चक्की-घर","de":"खड़खड़ाते हुए पत्थर घूमें तो अनाज आटे में खुल जाता है। सफ़ेद धूल धूप में तैरती रहती है, और चावल के केक की एक टोकरी गूँधने की चाह रखने वाले लोग बारी का इंतज़ार करते हैं। गाँव का उत्सव-दिन हमेशा इसी दहलीज़ से शुरू होता था।"},"ICON-1544":{"nm":"बेकरी","de":"ओवन के दरवाज़े की दरार से मक्खन और चीनी की गंध रिसती है। जब फूला हुआ आटा सुनहरा होने लगता है, दुकान के आगे से गुज़रते क़दम अनजाने ही धीमे पड़ जाते हैं। एक ताज़ी पकी रोटी में वह कोमलता है जिसे कोई नहीं टाल पाता।"},"ICON-1545":{"nm":"फुटपाथी नाश्ता ठेला","de":"विनाइल का तंबू हवा में फड़फड़ाता है और तोकबोक्की का शोरबा उबल-उबलकर गाढ़ा होता जाता है। एक फ़िश-केक की सींक और काग़ज़ के गिलास में शोरबा गटकती एक शाम, ठंड और भूख दोनों को एक साथ पिघला देने वाली जगह। गली के छोर पर रखा एक छोटा सुकून।"},"ICON-1546":{"nm":"पश्चिमी रसोई","de":"तवा गरम होता है और ज़ैतून का तेल चटख़ता है। आँच के एक फेर से सॉस गाढ़ा भी हो सकता है, जल भी सकता है। यहाँ जहाँ थाली में रंगों के संतुलन तक का हिसाब रखा जाता है, एक भोजन सँवारकर रचा गया एक प्रदर्शन बन जाता है।"},"ICON-1547":{"nm":"चीनी रसोई","de":"तेज़ आँच पर वॉक नाचते हुए-सा घूमता है। लपटों के उठने के उस छोटे पल में सामग्रियों की सुगंध पूरी तरह क़ैद हो जाती है। तेज़ और गरम, ज़रा भी हिचके तो छूट जाने वाली उसी एक साँस में चीनी पकवान का राज़ छिपा है।"},"ICON-1548":{"nm":"कैफ़े","de":"दरवाज़ा धकेलते ही कॉफ़ी बीजों की सुगंध और मद्धम संगीत पहले स्वागत करते हैं। खिड़की के पास की सीट, ठंडा होता लाते का एक कप और खुली हुई नोटबुक। व्यस्त दिन में पल भर साँस लेने के लिए शहर ने जगह-जगह ऐसे छोटे कमरे छिपा रखे हैं।"},"ICON-1549":{"nm":"मिठाई की दुकान","de":"शीशे की अलमारी के भीतर रंग-बिरंगे केक क़तार में ग्राहकों का इंतज़ार करते हैं। जिस पल काँटा क्रीम को चीरता है, होठों के कोने पहले ही ऊपर उठ जाते हैं। उदास दिन में भी एक टुकड़ा सह लेने लायक़ बना देने वाला, यह छोटा मीठा नुस्ख़ा।"},"ICON-1550":{"nm":"क़साई की दुकान","de":"लाल रोशनी के नीचे मांस रेशों के सहारे करीने से टिका है। \"आज यह अच्छा है\" इतना कहते ही चाकू ठीक सही मोटाई पर फिसलता है। शाम की थाली की भरपूरता चुपचाप इसी हाथ से शुरू होती है, जो हर रोज़ अपनी जगह थामे रहता है।"},"ICON-1551":{"nm":"समुद्री-खाद्य कार्य-मेज़","de":"भोर की मछली की गंध और बर्फ़ की ठंडक घुली-मिली एक कार्य-मेज़। शल्क उड़ें और हाथ सुन्न हो जाएँ, फिर भी सबसे ताज़ा चुनने वाली आँख कभी नहीं रुकती। समुद्र से अभी-अभी निकली चीज़ों को यहीं से थाली तक की राह मिलती है।"},"ICON-1552":{"nm":"नमक का खेत","de":"समुद्र का पानी रोक लो तो धूप और हवा बाक़ी काम कर देते हैं। कुछ दिन इंतज़ार करो और पानी सूख जाए तो ज़मीन पर सफ़ेद क्रिस्टल तारों-से उग आते हैं। एक मुट्ठी नमकीन स्वाद असल में समुद्र और आकाश का धीरे-धीरे मिलकर बनाया गया उपहार है।"},"ICON-1553":{"nm":"समुद्री शैवाल सुखाने का रैक","de":"लंबी रस्सी पर मियोक और दाशिमा एक साथ टँगे हवा में झूलते हैं। समुद्र का पानी लिए चीज़ें सूखते-सूखते गहरे हरे रंग में गहराती हैं। धूप और खारी हवा ने मिलकर रचा समुद्र का सबसे सादा स्वाद यहाँ टँगा है।"},"ICON-1554":{"nm":"छोटा घाट","de":"पानी में आधे डूबे लकड़ी के तख़्ते पैरों तले हल्के से लहराते हैं। एक छोटी नाव बाँधने के लिए ठीक-ठाक जगह। दूर जाना और सही-सलामत लौट आना, दोनों इसी एक कोने से शुरू और ख़त्म होते हैं।"},"ICON-1555":{"nm":"बंदरगाह गोदाम","de":"समुद्री हवा से रंगा लकड़ी का दरवाज़ा खोलो तो जाल, पीपे और रस्सियाँ छत तक ढेर मिलती हैं। दूर की यात्रा पर जाने वाला सामान और अभी-अभी पहुँचा सामान थोड़ी देर एक ही छत के नीचे ठहरते हैं। जाने और लौटने का पल भर छूकर गुज़र जाने वाला ट्रांज़िट-स्टेशन जैसी जगह।"},"ICON-1556":{"nm":"प्रकाश-स्तंभ","de":"रात का समुद्र सबसे गहरा अंधेरा होने पर ही यह अपना काम शुरू करता है। घूमती रोशनी कोहरे को चीरकर कहती है, \"यहाँ एक राह है।\" किसी के सही-सलामत लौट आने के लिए, कभी न सोने वाला एक ऊँचा पहरेदार।"},"ICON-1557":{"nm":"जहाज़-निर्माण स्थल","de":"कील खड़ी कर पसलियाँ जोड़ो तो एक जहाज़ का ढाँचा आकार लेने लगता है। जिस आँगन में हथौड़ों की आवाज़ दिन भर गूँजती है, वहाँ पानी का स्वाद न जानने वाला जहाज़ अपनी पहली यात्रा का सपना देखता है। जाने के लिए पहले मज़बूत होने वाली जगह।"},"ICON-1558":{"nm":"रिकॉर्डिंग बूथ","de":"दरवाज़ा बंद होते ही बाहर की हर आवाज़ पल भर में ग़ायब हो जाती है। हेडफ़ोन के पार सुनाई देता है सिर्फ़ अपनी साँस और ताल। इस छोटे कमरे की ख़ामोशी में आख़िरकार एक ऐसी आवाज़ जन्म लेती है जो बेखटके काँप सकती है।"},"ICON-1559":{"nm":"संगीत कक्ष","de":"दरवाज़े की दरार से रिसते सुर गलियारे को भर देते हैं। कोई सुर टटोलता है, कोई ताल गिनता है। जहाँ अनाड़ी आवाज़ें और पकी हुई आवाज़ें घुल-मिल सकें, ऐसी एक अपनी-सी कक्षा, जहाँ हर गीत पहला क़दम रखता है।"},"ICON-1560":{"nm":"पियानो कक्ष","de":"चाबियों का ढक्कन खोलो तो सफ़ेद चाबियों पर हल्की धूल जमी मिलती है। उँगलियाँ छूते ही पूरा कमरा स्वच्छ गूँज से भर जाता है। अकेले होकर भी अकेलापन न लगे, ऐसी शामें अगर होती हैं तो शायद इसी एक पियानो की वजह से।"},"ICON-1561":{"nm":"नृत्य कक्ष","de":"पंजों से दबाओ तो फ़र्श वापस ऊपर धकेलता है। चारों दीवारों के आईने एक ही हरकत को चार बार दोहराते रहें, तब तक शरीर ताल से आधी धड़कन पहले ही कोरियोग्राफ़ी याद कर लेता है। पसीना और साँस सबसे देर तक टिकने वाला कमरा—यहाँ पली हरकतें मंच तक चलकर जाती हैं।"},"ICON-1562":{"nm":"जिम कक्ष","de":"वज़न झूठ नहीं बोलता। जितना उठाओ उतना ही सही-सही कंधों में जमा होने वाली उस ईमानदारी से प्यार करके लोग हर भोर मुझे ढूँढ आते हैं। आईने में धीरे-धीरे उभरता है मांसपेशियाँ नहीं, बल्कि हार न मानकर सहे गए वे घंटे।"},"ICON-1563":{"nm":"योग कक्ष","de":"गहरी साँस लो तो लगता है लकड़ी का फ़र्श भी साथ में फूल रहा है। तेज़ दौड़ते हुए आए दिन को धीरे-धीरे तह करके रख देने वाला कमरा, जहाँ एक चटाई पर हर कोई अपनी साँस की रफ़्तार पर लौट आता है। जल्दबाज़ी करता मन भी यहाँ पल भर के लिए ख़ुद को नीचे रख देता है।"},"ICON-1564":{"nm":"मेकअप कक्ष","de":"मंच पर क़दम रखने से ठीक पहले, लोग यहाँ पल भर के लिए कोई और बन जाते हैं। आईने के इर्द-गिर्द के बल्ब जब चेहरे को समान रूप से सेंकते हैं, तो काँपन पाउडर-पफ़ की नोक पर चिपककर कॉलर के पीछे चुपके से छिप जाती है। जहाँ रूप बदलना शुरू भी होता है और ख़त्म भी।"},"ICON-1565":{"nm":"पोशाक कक्ष","de":"मंच पर एक पहनावा पूरा होने तक, यहाँ टँगे कपड़े दर्जनों बार पहनाए और उतारे जाते हैं। पिन लगी घूमती पुतली, चॉक से खींची सिलाई-रेखा। चमक के पीछे हमेशा किसी की सुई-धागे की निशानी बची रहती है।"},"ICON-1566":{"nm":"प्रसारण सेट","de":"कैमरे में दिखने वाली सिर्फ़ एक ओर को असली-सा सजाना काफ़ी है, यह मैंने जल्दी सीख लिया। प्लाईवुड के पीछे जाओ तो सिर्फ़ खाली ढाँचा मिलता है। सामने की शान को चुपचाप थामने का काम हमेशा अनदेखी लकड़ी की कड़ियों का ही होता है।"},"ICON-1567":{"nm":"फ़ोटो स्टूडियो","de":"तीन दिशाओं से रोशनी डालकर परछाइयाँ मिटाना पहला राज़ है। मुख्य रोशनी चेहरे को उभारती है, सहायक रोशनी छाँव को, और पीछे की रोशनी बालों की नोक को जिलाती है। शटर गिरने के उस पल में, एक सफ़ेद पर्दा आज की सबसे अच्छी मुस्कान क़ैद कर लेता है।"},"ICON-1568":{"nm":"कॉन्सर्ट हॉल","de":"ऊँची छत के अंधेरे में मैं हमेशा एक ही वादा थामे रखता हूँ—जिस पल पर्दा उठेगा, ख़ाली कुर्सियाँ भी एक इंसान की तरह साँस रोक लेंगी। जिस एक पल पहली धड़कन गिरती है, उसी के लिए मैं साल भर चुपचाप ख़ाली खड़ा रहता हूँ।"},"ICON-1569":{"nm":"फ़ैन-मीटिंग बूथ","de":"हाथ और हाथ के बीच की दूरी ठीक एक मेज़ जितनी होती है। छोटा-सा अभिवादन, काँपता हुआ ऑटोग्राफ़, आख़िर तक न कह सका एक शब्द, सब क़तार में गुज़रते हैं। इस छोटे से खाने में बरसों से पाला हुआ पसंदीदा एहसास पहली बार आमने-सामने आता है।"},"ICON-1570":{"nm":"बिस्तर","de":"दिन का अंत सबसे पहले थामने वाला हमेशा मैं ही रहा। अभ्यास से भारी हुए पैर, मंच के पीछे बची काँपन—सब कुछ शांत हो जाने के बाद, सुबह फिर हल्के पंजों से शुरू होती है। शुभ रात्रि कहकर, बिना कुछ बोले गले लगा लेता हूँ।"},"ICON-1571":{"nm":"दो-तल्ला बिस्तर","de":"ऊपर और नीचे की मंज़िल के बीच, सीढ़ी के पाँच डंडे दो लोगों को जोड़ते हैं। बत्ती बुझाकर बाँटी छोटी आवाज़ें, छत पर चिपकाए चमकते हुए तारे। तंग कमरा सबसे विशाल तब बनता है जब हर रात सीढ़ी चढ़ती-उतरती कहानियाँ चलती हैं।"},"ICON-1572":{"nm":"शेल्फ़","de":"उस पर क्या रखा है, इससे उस इंसान का पता चलता है। मिली चिट्ठी, पहली ट्रॉफ़ी, धुँधली पड़ चुकी प्रवेश-टिकट एक क़तार में सजे मिलते हैं। मैं शेखी बघारने वाला फ़र्नीचर नहीं, बल्कि उन यादों को चुपचाप सजाने वाली जगह हूँ जिन्हें फेंकते नहीं बना।"},"ICON-1573":{"nm":"मेज़","de":"गीत-नोटबुक खुली रहती है, मिटाए निशानों के ऊपर फिर नई पंक्तियाँ खिंचती हैं। रातभर जमा हुए काग़ज़ के गिलास और बड़ी मुश्किल से मिली एक धुन की पंक्ति। मन को शब्दों में उतारने का धीमा काम हमेशा इसी सपाट सतह पर चुपचाप होता रहता है।"},"ICON-1574":{"nm":"कुर्सी","de":"\"थोड़ी देर बैठ जाओ\" कहना अचरज भरी बात है, कितना अपनापन लिए होता है। बैठक लंबी खिंचे या अभ्यास बढ़ता जाए, पीठ का सहारा चुपचाप इंसान का वज़न थामे रखता है। जो जितनी देर खड़ा रहा हो, वही मुझे उतना ही ज़्यादा अपनाता है, यह मुझे पता है।"},"ICON-1575":{"nm":"सोफ़ा","de":"देर रात के निवास को बैठक-कक्ष बनाने के लिए मैं अकेला ही काफ़ी हूँ। सब मिलकर सिमटकर मनोरंजन कार्यक्रम देखते-देखते, कोई एक कब बाँह के सहारे सो जाता है, पता ही नहीं चलता। धँसा हुआ बीच का हिस्सा उस घर की गर्माहट का सबूत है।"},"ICON-1576":{"nm":"मेज़","de":"गोल घेरे में बैठो तो कोई भी मुखिया की जगह पर नहीं रहता। ताज़ा उबला शोरबा, टकराते चम्मचों की आवाज़, आज हुई बातें बीच में इकट्ठा होती हैं। एक गोल सतह खुलते ही बिखरा दिन भी फिर एक साथ बैठ जाता है।"},"ICON-1577":{"nm":"अलमारी","de":"जब भी मौसम बदलता है, भीतर से पुरानी कहानियाँ छलक पड़ती हैं। मंच के परिधान और रोज़मर्रा के कपड़े कंधे से कंधा मिलाए, बंद दरवाज़े के पीछे अगली बारी का इंतज़ार करते हैं। दरवाज़ा खुलते ही आख़िरकार तय होता है कि आज क्या पहना जाएगा।"},"ICON-1578":{"nm":"आईना","de":"तारीफ़ हो या ख़ामी, मैं दोनों को एक जैसी ईमानदारी से लौटाता हूँ। मंच पर जाने से पहले आख़िरी जाँच की जगह, लोग मेरे सामने भाव सँवारते और मुद्रा सीधी करते हैं। सबसे सच्चा दोस्त कभी एक शब्द नहीं बोलता।"},"ICON-1579":{"nm":"श्रृंगार-मेज़","de":"हर छोटी दराज़ में एक अलग चेहरा सोया रहता है। मंच के लिए एक डिब्बा, रोज़ के लिए एक डिब्बा, सँभालकर रखा हुआ एक सीमित-संस्करण। आईने के आगे बैठते ही, आज कैसा इंसान बनकर दरवाज़े से निकलना है, यह धीरे-धीरे तय होने लगता है।"},"ICON-1580":{"nm":"दरी","de":"नंगे पैर का पहला स्पर्श ही उस कमरे का तापमान तय करता है। बैठकर नाश्ता करने और लोटपोट होने के निशान रोएँ बनकर रह जाते हैं। ठंडे फ़र्श को एक बित्ता और गरम रखने वाला, सबसे नीची जगह से काम करने वाला फ़र्नीचर।"},"ICON-1581":{"nm":"पर्दा","de":"सुबह को कितना भीतर आने देना है, यह मैं तय करता हूँ। हल्का सा हटाओ तो धूप लंबी होकर भीतर आती है, कस के बंद करो तो देर तक सोना भी माफ़ी लायक़ बन जाता है। खिड़की और कमरे के बीच खड़े होकर रोशनी की मात्रा चुपचाप नियंत्रित करना हमेशा मुझे ही सौंपा गया हिस्सा है।"},"ICON-1582":{"nm":"लैंप","de":"एक ही कमरा रोशनी के रंग के हिसाब से बिल्कुल अलग समय बन जाता है। पीली रोशनी शाम को लंबा खींचती है, सफ़ेद रोशनी भोर को साफ़ जगाती है। एक स्विच से दिन का मिज़ाज चुपके से बदल देने वाला, हथेली भर का जादूगर।"},"ICON-1583":{"nm":"दीवार घड़ी","de":"सेकंड की सुई की आवाज़ केवल शांत कमरे में सुनाई देती है। अभ्यास जितना गहराता है, उतना ही मुझे भूल जाते हो, फिर अचानक ऊपर देखो तो खिड़की के बाहर कब भोर हो गई, पता ही नहीं चलता। बीते समय को दोष दिए बिना, बस चुपचाप अगले पल की ओर इशारा करना।"},"ICON-1584":{"nm":"फूलदान","de":"फूल मुरझा भी जाएँ तो भी मैं अपनी जगह ख़ाली नहीं छोड़ता। मिला हुआ एहसास पल भर के लिए थामने वाला बर्तन, जब तक पानी बदलने वाला हाथ रहता है तब तक मेज़ रौशन रहती है। ख़ाली रहने पर भी मैं किसी के इंतज़ार की मुद्रा में ही खड़ा रहता हूँ।"},"ICON-1585":{"nm":"पोस्टर फ़्रेम","de":"पसंदीदा चेहरे को दीवार पर टाँगने में भी लगन लगती है। धूप सीधे न पड़े ऐसी जगह, एक दम सीध में गड़ी हुई कील। शीशे के भीतर सहेजकर लिटाया गया काग़ज़ का एक टुकड़ा, हर सुबह कमरे में क़दम रखते ही सबसे पहले मुझे नमस्ते कहता है।"},"ICON-1586":{"nm":"फ़ोटोकार्ड बोर्ड","de":"वर्णानुक्रम में लगाऊँ या रिलीज़ क्रम में, यह ख़ुशनुमा उलझन ही फैंडम की शुरुआत है। एक ख़ाली ख़ाना उस अभी न मिले पसंदीदा की जगह है। एक-एक कार्ड से भरते-भरते, बोर्ड मेरा अपना छोटा इतिहास बन जाता है।"},"ICON-1587":{"nm":"लाइटस्टिक स्टैंड","de":"बैटरी निकाल दो, हत्था ऊपर रखो। तिरछा झुकाकर खड़ा करने के कोण में भी अपनी एक कला है। अगली आने वाली जयकार का इंतज़ार करते हुए, स्टिक यहीं अपनी रोशनी बुझाकर करीने से लेट जाती है। अच्छे से आराम करे तो और चमककर जलती है।"},"ICON-1588":{"nm":"ट्रॉफ़ी शेल्फ़","de":"सबसे आगे की क़तार में सबसे पुरानी रखी जाती है। किसी छोटी प्रतियोगिता की मूर्ति से लेकर बड़े मंच के प्याले तक, ऊँचाई के क्रम में नहीं, मन के क्रम में सजते हैं। जब भी पोंछता हूँ, उस दिन के मंच पर की काँपन फिर उँगलियों में उतर आती है।"},"ICON-1589":{"nm":"पिकनिक टोकरी","de":"ढक्कन खोलते ही बसंत की धूप की गंध पहले रिस आती है। किम्बाप, थर्मस और एक चटाई करीने से तह होकर मैदान की ओर जाने को तैयार खड़े मिलते हैं। मुझे उठाए इंसान के क़दम किसी वजह से हमेशा एक बित्ता ज़्यादा हल्के हो जाते हैं।"},"ICON-1590":{"nm":"छोटा गमला","de":"खिड़की की चौखट का एक बित्ता ही मेरे लिए काफ़ी है। पानी देना अक्सर भूल भी जाओ तो उदारता से सह लेने वाला एक छोटा हरापन। किसी व्यस्त इंसान की मेज़ के एक कोने में, मैं रोज़ एक और पत्ता खोलकर चुपचाप आज का हाल-चाल पहुँचाता हूँ।"},"ICON-1591":{"nm":"बड़ा गमला","de":"मेरा क़द बढ़ने के साथ इंसान भी साथ बढ़ता है। बैठक-कक्ष का एक कोना घेरे चौड़े पत्ते जब धूप सोखकर छाँव डालते हैं, तो कमरे में भी चुपके से मौसम उतर आता है। यह इनाम केवल उसे पता है जो पानी देना नहीं भूलता।"},"ICON-1592":{"nm":"सुगंधित मोमबत्ती सेट","de":"बत्ती में आग लगाते ही कमरे की हवा एक पायदान नीचे बैठ जाती है। सुगंध धीरे-धीरे फैलते हुए कल की बची थकान को सेंककर बाहर भेज देती है। एक छोटी लौ से व्यस्त दिन के अंत को एक शांत रस्म की तरह पूरा करने का काम।"},"ICON-1593":{"nm":"मिनी फ़्रिज","de":"देर रात दरवाज़ा खोलो तो ठंडा पेय का एक डिब्बा मेरा स्वागत करता है। हल्की सी गुनगुनाती आवाज़ ख़ाली निवास को कम अकेला बना देती है। बड़ी गृहस्थी न सही, पर भूख से बेचैन तड़के को सँभालने में मुझ जैसा कोई नहीं।"},"ICON-1594":{"nm":"टिड्डी-जाल टोपी","de":"सिर पर रखते ही गर्मी का मैदान कंधों पर चढ़ आता है। गोल जाल धूप को कोमलता से छानता है, और हर क़दम पर घास की गंध हल्के से लहराती है। एक भी टिड्डी न पकड़ पाओ तो भी अच्छा, ऐसी टोपी जो पूरा मौसम ओढ़ा देती है।"},"ICON-1595":{"nm":"चुनाई-जाल थैली","de":"कमर पर लटकी यह चुनाई का साथी बन जाती है। मुँह को हल्का सा कस दो तो पकड़ा हुआ फिर भाग नहीं पाता, यह मैदान में सीखा पहला गुर है। हल्की कपड़े की थैली एक दिन की उपज को करीने से गोद में भर लेती है।"},"ICON-1596":{"nm":"कीट अवलोकन शीशी","de":"पल भर ठहरने वाले मेहमान के लिए हवा के छेद सबसे ज़रूरी होते हैं, यह मुझे पता है। ढक्कन में छेदा गया एक छोटा साँस-मार्ग, तली पर बिछी घास की एक पत्ती। देखना ख़त्म होते ही उसे वापस झाड़ियों में लौटा देना भी इसी जोड़ी का हिस्सा है।"},"ICON-1597":{"nm":"नमूना-पिन डिब्बा","de":"पिन को तिरछा गाड़ने के एक ही कोण में भी हुनर बसा होता है। बहुत गहरा जाए तो टूट जाता है, बहुत उथला हो तो हिल जाता है, इसलिए उँगलियों की ताक़त बड़ी सावधानी से बाँटनी पड़ती है। किसी छोटे जीवन को देर तक निहारने की चाह रखने वाले की लगन इस डिब्बे में चुपचाप समाई है।"},"ICON-1598":{"nm":"पालन-बक्से का ढक्कन","de":"भीतर और बाहर की सीमा सँभालना मेरा काम है। बहुत कसकर बंद करो तो साँस घुटती है, बहुत ढीला छोड़ दो तो राह भटक जाती है, इसलिए मैं हमेशा एक बाल-सी दरार छोड़े रखता हूँ। सुरक्षा देना, क़ैद करने से साफ़ अलग बात है।"},"ICON-1599":{"nm":"तितली आहार तश्तरी","de":"शक्कर के पानी में भिगोई रुई बीचोबीच रखो तो पंख इकट्ठे हो जाते हैं। उथला और चौड़ा, ऐसी गहराई कि छोटे पैर धँसें नहीं, यही राज़ है। एक तश्तरी धूप भरे बग़ीचे में पल भर ठहरकर जाने वाले मेहमानों को चुपचाप बुला लेती है।"},"ICON-1600":{"nm":"कीट-आकर्षण लैंप","de":"अंधेरे में हल्की सी जलाकर रखो तो छोटे पंख रोशनी के पीछे इकट्ठे होने लगते हैं। चमक हल्की रखो, जगह लोगों से दूर। भिनभिनाती गर्मी की रात को कहीं ज़्यादा शांत कर देने वाला, अत्यंत प्रेमिल एक बुलावा।"},"ICON-1601":{"nm":"कीट स्टिकर लेबल","de":"छह टाँगें और एंटीना की एक जोड़ी—नाखून जितने छोटे काग़ज़ के टुकड़े में एक छोटी सी ज़िंदगी सोई हुई है। इसे नोटबुक के कोने पर हल्के से चिपका दो, तो पन्नों के बीच एक बित्ता भर घास का मैदान चुपचाप खुल जाता है।"},"ICON-1602":{"nm":"संग्रहण अनुमति टैग","de":"जाल उठाने से पहले, बड़े लोग पहले पूछते हैं—कितने, और कहाँ तक। यह एक छोटा सा टैग उत्साहित जिज्ञासा और निभाए जाने वाले वादे के बीच एक कोमल रेखा खींच देता है।"},"ICON-1603":{"nm":"चारा डिब्बी","de":"ढक्कन खोलते ही एक हल्की मछली जैसी, ठंडी भोर की गंध उठती है। मछली को शायद चारा नहीं बुलाता, बल्कि वह मन बुलाता है जो फ्लोट के हिलने तक धैर्य से रुका रहना जानता है।"},"ICON-1604":{"nm":"फ्लोट रखने का डिब्बा","de":"रंग-बिरंगे फ्लोट खाने-दर-खाने सोए पड़े एक छोटी सी अलमारी। कोई शांत झील की सुबह है, तो कोई तेज़ धार की दोपहर। पानी के हर मिज़ाज के लिए, उपयुक्त साथी को करीने से तह करके रखा गया है।"},"ICON-1605":{"nm":"मछली पकड़ने की डोरी की रील","de":"खुली हुई डोरी को उँगलियों पर मत लपेटो। इस गोल औज़ार पर करीने से फिर से लपेट दो, तो उलझनें भी चुपके से सुलझ जाती हैं। यह उस स्पर्श जैसा है जो ढीले पड़ गए दिन को फिर से सँवार देता है।"},"ICON-1606":{"nm":"काँटा निकालने वाला","de":"फँसे हुए काँटे को नंगे हाथ से निकालते हुए चुभन झेल चुका इंसान ही इस औज़ार को पहचानता है। यह उस छोटे जीव के लिए, और मेरी उँगलियों के लिए भी, कम दर्द वाला रास्ता है। लिहाज़ हमेशा इन्हीं छोटी-छोटी सीमाओं से शुरू होता है।"},"ICON-1607":{"nm":"सीप फावड़े का कवर","de":"कीचड़ से अभी-अभी निकाले फावड़े की धार को लपेटती एक परत। ताकि कीचड़ और खारा पानी धार को न चाट सकें, यह समुद्र और औज़ार के बीच एक पतला, नरम विश्राम धीरे से बिछा देता है।"},"ICON-1608":{"nm":"ज्वार-भाटा तालिका कार्ड","de":"पानी कब चढ़ता है और कब उतरता है, यह हथेली जितना कार्ड चुपचाप बता देता है। यह चाँद और समुद्र के बीच हुए पुराने वादे को इंसान द्वारा लिख लिया गया एक छोटा सा कैलेंडर है।"},"ICON-1609":{"nm":"फिश टैंक सफाई ब्रश","de":"शीशे की दीवार पर जमी हरी काई को धीरे से साफ़ करो, तो पानी के भीतर की छोटी दुनिया में फिर से रोशनी उतर आती है। किसी के दिन को उजला करने का काम अक्सर ऐसे ही चुपचाप बहता है।"},"ICON-1610":{"nm":"टैंक तापमान चिप","de":"एक अंक टिमटिमाकर सही डिग्री पर थमता है, तो मछलियाँ आख़िरकार निश्चिंत हो जाती हैं। न बहुत ठंडी न बहुत गर्म, बस एक ख़ाने भर की गर्माहट। देखभाल वहाँ तक भी पहुँचती है जहाँ नज़र नहीं जाती।"},"ICON-1611":{"nm":"समुद्री जीव अवलोकन ट्यूब","de":"पारदर्शी ट्यूब के भीतर कुछ देर के लिए ठहरा एक छोटा मेहमान। पीठ के पंख को चुपचाप गिनकर, उसे फिर समुद्र में लौटा दिया जाता है। निरीक्षण करना पाना नहीं, बस थोड़ी देर के लिए उधार लेना है।"},"ICON-1612":{"nm":"जीवाश्म ब्रश","de":"करोड़ों वर्षों से सोए पत्थर की बनावट को जगाने वाला हथौड़ा नहीं, ब्रश की मुलायम नोक है। जल्दबाज़ी करते ही बिखर जाने वाले समय के सामने, सावधानी ही सबसे गहरा शिष्टाचार बन जाती है।"},"ICON-1613":{"nm":"खुदाई ब्रश कैप","de":"ब्रश की नोक बहुत सूख जाए तो मिट्टी भी साफ़ नहीं झड़ती। एक छोटी टोपी ब्रश की साँस को नम बनाए रखती है। औज़ारों को संजोने वाला हाथ ही खुदाई का पहला क़दम उठाता है।"},"ICON-1614":{"nm":"भू-स्तर नमूना पट्टी","de":"एक बित्ता मिट्टी के भीतर सैकड़ों साल तह-दर-तह बिछे पड़े हैं। इसे इस पट्टी पर धीरे से उठा लो, तो अब तक अनदेखे समय के निशान रेखाएँ खींचते हुए धीरे-धीरे उभर आते हैं।"},"ICON-1615":{"nm":"हड्डी के टुकड़ों की ट्रे","de":"बिखरे टुकड़ों को खाने-दर-खाने लिटाओ, तो हवा में बिखर गई एक ज़िंदगी धीरे-धीरे अपनी जगह टटोलते हुए ढूँढ लेती है। पुनर्स्थापन दरअसल खोए हुए क्रम को स्नेह से फिर से पूछना है।"},"ICON-1616":{"nm":"पुनर्स्थापन टेप","de":"टूटी जगह को जोड़ती एक पतली सी पट्टी। यह घाव को छिपाने की ज़हमत नहीं उठाती, बल्कि उसे स्नेह से गले लगाकर थाम लेती है। यह चुपचाप साबित करती है कि जो टूट चुका है, वह फिर से सम्पूर्ण हो सकता है।"},"ICON-1617":{"nm":"प्रदर्शन नामपट्टिका कवर","de":"शीशे के उस पार नामपट्टिका फीकी न पड़े, इसलिए धीरे से ढकने वाली एक चादर। इसमें यह इच्छा समाई है कि कौन, कहाँ रहा—यह छोटा सा वाक्य दूर भविष्य तक भी साफ़ पढ़ा जा सके।"},"ICON-1618":{"nm":"संग्रह-कक्ष टैग","de":"रोशनी में कभी न आए खज़ाने जिस गहरे कमरे में सोए पड़े हैं। उसके भीतर हर चीज़ पर एक छोटा नाम-टैग लटका है—ताकि उजली जगह पर खड़े हुए बिना भी वे कभी भुलाए न जाएँ।"},"ICON-1619":{"nm":"संग्रहालय दान लिफ़ाफ़ा","de":"कोई अपने जीवन भर की जमा-पूँजी बिना कुछ कहे सौंप देता है। इस लिफ़ाफ़े में जो है वह वस्तु नहीं, बल्कि लंबे समय से संजोया गया एक मन है। बाँटना ही सबसे लंबे समय तक टिकने वाली प्रदर्शनी बनकर किसी को रोशन करता है।"},"ICON-1620":{"nm":"नमूना क्रमांक चिप","de":"जिस जगह से इसे इकट्ठा किया गया, वहीं एक छोटी संख्या धीरे से टाँक दी जाती है। कब, कहाँ पहली बार मुलाकात हुई। जो खोज दर्ज नहीं की जाती, वह जल्द ही सुबह की धुंध की तरह बिखर जाती है।"},"ICON-1621":{"nm":"उल्का-टुकड़ा बोतल","de":"रात के आसमान को चीरते हुए गिरा एक टुकड़ा शीशे की बोतल में क़ैद हो गया। मन्नत माँगने की फ़ुर्सत मिलने से पहले ही बुझ गई रोशनी की वह किरण, अब हाथों में धीरे-धीरे फिर से चमकती है।"},"ICON-1622":{"nm":"सीप विंड चाइम डोरी","de":"समुद्र किनारे एक-एक करके चुनी सीपियों को धागे में पिरोकर छज्जे पर टाँग दो। जब भी हवा गुज़रती है, खनकती-खनकती, उस गर्मी का समुद्र चुपचाप घर के भीतर तक चला आता है।"},"ICON-1623":{"nm":"इंद्रधनुषी ओस-बूँद","de":"बारिश थमने के बाद पत्ती की नोक पर लुढ़कती एक बूँद। उस गोल आकार के भीतर पूरा आसमान और सातों रंग गोलाई में समाए हैं। कभी-कभी सबसे छोटी चीज़ ही सबसे विशाल दृश्य को अपने भीतर समेट लेती है।"},"ICON-1624":{"nm":"कोहरा संग्रह बोतल","de":"भोर के पहाड़ी दामन का कोहरा एक बोतल भर घर ले आया। हाथ में लेते ही यह ठंडा और धुँधला दूधिया हो उठता है। जिसे थामा नहीं जा सकता, उसे थोड़ी देर पास रखने की एक छोटी और स्नेहिल लालसा।"},"ICON-1625":{"nm":"ओस-कटोरी","de":"रातभर घास की पत्तियों ने बूँद-बूँद जो ओस जमा की, उसे थामने वाला एक छोटा प्याला। एक घूँट भी पूरा नहीं, फिर भी सुबह का सबसे साफ़ और स्वच्छ हिस्सा वहाँ शांति से ठहरा रहता है।"},"ICON-1626":{"nm":"हवा की लहर रिबन पिन","de":"हवा के गुज़रने से बनी लहर को हूबहू उतारकर बाँधा गया एक रिबन। इसे बालों में लगाओ तो हर क़दम पर एक हल्की बयार लहराते हुए पीछे-पीछे चलती है। बसंत की हलकी सी हल्कापन एक पिन में चुपचाप बाँध दी गई है।"},"ICON-1627":{"nm":"लहरों की आवाज़ कैप्सूल","de":"इसे कान के पास धीरे से लगाओ, तो दूर समुद्र की लहरें उमड़ आती हैं। बचपन में सीप के खोल में समाई वह आवाज़, मानो किसी ने एक छोटे से कैप्सूल में सहेजकर मुहर लगा दी हो।"},"ICON-1628":{"nm":"रेत-तारा टुकड़ा","de":"रात के समुद्र तट पर मुट्ठी भर रेत उठाओ, तो उसमें तारों के चूरे मिले चमकते हैं। वे आसमान से गिरे हैं या लहरों ने बारीक पीसे हैं, यह कोई ज़हमत उठाकर नहीं पूछता।"},"ICON-1629":{"nm":"द्वीप मौसम लॉग चिप","de":"द्वीप का आसमान दिन में कई बार अपना मन बदल लेता है। साफ़, कोहरा, बौछार—इन्हें एक छोटी चिप में करीने से दर्ज कर लो, तो कल के आसमान को आज फिर से खोलकर देखा जा सकता है।"},"ICON-1630":{"nm":"चट्टान सीढ़ी किट","de":"खड़ी ढलान पर चढ़ने-उतरने के लिए एक सीढ़ी, फिर एक और। बिखरे हिस्सों को जोड़ दो तो चट्टान भी एक इत्मीनान भरी सैर बन जाती है। रास्ता बनाना दरअसल किसी के अगले क़दम को पहले से बिछाकर रखना है।"},"ICON-1631":{"nm":"कच्चे रास्ते का पैटर्न रोल","de":"मुलायम कच्चे रास्ते की बनावट को हूबहू उतारा गया एक बेलनाकार टुकड़ा। इसे सरसराते हुए बिछाओ, तो नंगे पाँव चलने का मन कर उठे ऐसी एक गाँव की पगडंडी क़दमों तले चुपचाप बिछ जाती है।"},"ICON-1632":{"nm":"पत्थर के रास्ते का पैटर्न चिप","de":"पुरानी गलियों को सजाने वाले पत्थरों की बनावट एक छोटी चिप में जस की तस समाई है। हर क़दम पर खटर-खटर, पुराने गाँव की पदचाप पैरों की उँगलियों में फिर से जी उठती है।"},"ICON-1633":{"nm":"समुद्र तट की बाड़ का टुकड़ा","de":"लहरें रेत पर न चढ़ आएँ, इसलिए खड़ी की गई नीची बाड़ का एक हिस्सा। समुद्र और रेत के बीच एक कोमल रेखा खींचकर खड़ा, एक छोटा और चुपचाप निभाने वाला सीमा-रक्षक।"},"ICON-1634":{"nm":"घास पुनर्स्थापन पैच","de":"रौंदे जाने से नंगी हुई जगह पर धीरे से बिछाया गया हरियाली का एक टुकड़ा। कुछ ही दिनों में घास-फूस आपस में हाथ मिलाकर वह खाली जगह भर देते हैं। प्रकृति हमेशा ख़ुद को सँभालना जानती है।"},"ICON-1635":{"nm":"जल-मार्ग सूचक खूँटी","de":"पानी को बहने का रास्ता पहले से बता देने वाली खूँटी। बरसात का पानी भटके नहीं, इसलिए ज़मीन में गड़ा एक छोटा मील का पत्थर बारिश के दिनों में भी चुपचाप डटा रहता है।"},"ICON-1636":{"nm":"छोटे पुल का पुर्ज़ा","de":"नाले के दोनों किनारों को जोड़ने वाले एक नन्हे पुल का टुकड़ा। इस किनारे और उस किनारे के बीच, कभी भी पार जा सकने का वादा इसी एक छोटे पुर्ज़े से चुपचाप शुरू होता है।"},"ICON-1637":{"nm":"दृश्य-स्थल रेलिंग कैप","de":"द्वीप की सबसे ऊँची जगह पर, उस रेलिंग के सिरे को ढकने वाला एक अंतिम टुकड़ा। दूर तक देखने के लिए जुटे लोगों के हाथ जिस जगह को सबसे ज़्यादा छूते हैं, वह इसे चुपचाप सहारा देकर बचाए रखता है।"},"ICON-1638":{"nm":"कैम्पफ़ायर आधार","de":"लकड़ियाँ रखने से पहले, चिंगारियाँ बिखर न जाएँ इसलिए सहारा देने वाली एक जगह। इसके ऊपर तारों को निहारते हुए बतियाई गई रातें लंबे समय तक गर्म जलती रहती हैं।"},"ICON-1639":{"nm":"वॉलपेपर नमूना रोल","de":"कमरे का मिज़ाज एक दीवार से शुरू होता है। एक छोटा रोल खोलकर रंग चुनना दरअसल यह पहले से चुपचाप सोचना है कि आगे कैसे दिन जीने की इच्छा है।"},"ICON-1640":{"nm":"फ़्लोरिंग नमूना चिप","de":"नंगे पाँव जिस फ़र्श को छुएँगे, उसका एहसास पहले उँगलियों से टटोल लो। गर्म हो या ठंडा—इस एक छोटी सी चिप पर आगे बिताए जाने वाले दिनों की आरामदेह अनुभूति चुपचाप टिकी है।"},"ICON-1641":{"nm":"छत हुक सेट","de":"शहतीर पर एक हुक टाँगते ही, ख़ाली छत किसी की राह तकती हुई एक जगह बन जाती है। विंड चाइम टाँगें या गमला? भार तो यह छोटा लोहे का हुक झेल लेता है, पर टाँगना क्या है, यह रहने वाले का मन तय करता है।"},"ICON-1642":{"nm":"खिड़की टिंट फ़िल्म","de":"दोपहर की रोशनी बहुत साफ़-सच्ची होती है, इसलिए खिड़की पर एक पतली परत चढ़ा दी जाती है। धूप अंदर तो आती है पर किनारे नरम पड़ जाते हैं, और कमरे की हर चीज़ खुबानी रंग में सौम्य हो उठती है। यह रोकना नहीं, रोशनी को स्नेह से फैलाना है।"},"ICON-1643":{"nm":"डोरबेल कवर","de":"मेहमान जो घंटी बजाते हैं, उसे भी कपड़े चाहिए, यह कहकर किसी ने एक गोल ढक्कन पहना दिया। यह बारिश रोकता है, धूल रोकता है, और सबसे बढ़कर \"यहाँ कोई रहता है\" यह पहला अभिवादन देने वाला एक छोटा गोल मुँह है।"},"ICON-1644":{"nm":"अतिथि-पुस्तिका स्टैंड","de":"आने वाला हर कोई नाम लिखकर जाए, इसलिए खड़ा किया गया एक आधार। स्याही सूखने से पहले, क़लम की नोक से हाल-चाल की एक पंक्ति बह निकलती है। आए-गए क़दम जब पंक्ति-दर-पंक्ति जमा होते हैं, तो ख़ाली नोटबुक कब इस घर का सबसे मोटा एल्बम बन जाती है, पता ही नहीं चलता।"},"ICON-1645":{"nm":"फ़र्नीचर स्थान पिन","de":"हटाऊँ या न हटाऊँ, इस उलझन में पड़ी मेज़ की जगह को एक पिन फ़र्श में गाड़कर तय कर देती है। फ़र्नीचर के पैरों को धीरे से थामने वाली एक छोटी कील। जगह एक बार तय हो जाए तो उससे लगाव हो जाता है, यह लकड़ी का फ़र्श चुपचाप सिर हिलाकर मान लेता है।"},"ICON-1646":{"nm":"भंडारण लेबल फ़्रेम","de":"क्या कहाँ रखा है, दराज़ यह कभी बोल नहीं पाती। इसलिए एक चौकोर फ़्रेम में नाम-पट्टी लगाकर उसकी जगह बोलने का काम सौंपा गया। एक लेबल के अपनी जगह बैठते ही, अस्त-व्यस्त ख़ाने अपना नाम वापस पाकर शांत हो जाते हैं।"},"ICON-1647":{"nm":"रूम डिफ़्यूज़र स्टिक","de":"छड़ी के सिरे को भिगोई ख़ुशबू धीरे-धीरे ऊपर फैलती है। कभी लैवेंडर, तो कभी बारिश के बाद की घास का मैदान। जब यह अदृश्य धागे जैसी महक कमरे की हवा बदल देती है, घर लौटे इंसान के कंधों से दिन भर की थकान धीरे से उतर जाती है।"},"ICON-1648":{"nm":"बीज पैकेट क्लिप","de":"बसंत में ख़रीदे पर पूरे न बोए जा सके बीजों को, लिफ़ाफ़े समेत क्लिप से मज़बूती से जकड़ दिया जाता है। एक भी दाना फिसल जाए तो अगला मौसम एक पंक्ति छोटा हो जाता है। इस छोटी सी जकड़न में अगले साल का पूरा बगीचा सोया पड़ा है।"},"ICON-1649":{"nm":"पौध ट्रे","de":"हर ख़ाने में मिट्टी भरकर नन्हे अंकुर का पहला कमरा बनाया जाता है। एक छेद में एक जीवन, क़तार में सीधे-सीधे बढ़ते नए विद्यार्थी। झाँककर देखो तो हरियाली गुच्छों में हाज़िरी लगाती हुई एक सुबह, ट्रे पर हर रोज़ नए सिरे से शुरू होती है।"},"ICON-1650":{"nm":"सिंचाई सूचक पिन","de":"\"मुझे प्यास लगी है।\" गमला बोल नहीं सकता, इसलिए मिट्टी में गड़ी एक छोटी तख्ती उसकी जगह इशारा भेजती है। रंग बदलते ही पानी देने का समय। पौधे और इंसान के बीच का सबसे छोटा दुभाषिया इसी एक बित्ता भर छड़ी में पूरा समाया है।"},"ICON-1651":{"nm":"फ़सल सहारा डोरी","de":"बढ़ता तना अपने ही भार से डगमगा न जाए, इसलिए इसे सहारे से एक मुलायम डोरी से धीरे से बाँध दिया जाता है। ज़्यादा कस दो तो साँस रुके, ज़्यादा ढीला छोड़ दो तो गिर जाए, इसलिए बाँधने वाले हाथ को बस उतना ही स्नेह चाहिए। बढ़ने में भी किसी के साथ की ज़रूरत होती है।"},"ICON-1652":{"nm":"कीट-रोधी जाली","de":"कोमल पत्तियों पर नज़र गड़ाए छोटे-छोटे मुँहों को, बारीकी से बुनी जाली चुपचाप रोक देती है। हवा और धूप को गुज़रने देकर सिर्फ़ नुक़सान पहुँचाने वाले को टाल देने वाला एक अदृश्य द्वारपाल। बगीचा शांत रहता है तो इसी घनी जाली की परवाह की वजह से।"},"ICON-1653":{"nm":"धूप मापन कार्ड","de":"यहाँ कितनी धूप आती है, यह जानने के लिए क्यारी में एक कार्ड खड़ा करके चुपचाप पूछा जाता है। रंग जितना गहरा हो, आज उतनी ही रोशनी मिली। धूप पसंद करने वाले पौधे और छाँव में सुकून पाने वाले पौधे की जगह, यह छोटा सा काग़ज़ बाँट देता है।"},"ICON-1654":{"nm":"मिट्टी pH परीक्षण पट्टी","de":"मिट्टी पर परीक्षण पट्टी लगाओ तो गुलाबी से नीले तक, ज़मीन अपना मन रंग में उड़ेल देती है। न बहुत खट्टी न बहुत कड़वी जगह पर जड़ें सबसे सहज साँस लेती हैं। मिट्टी का अनदेखा मन एक-एक ख़ाना करके पढ़ा जाता है।"},"ICON-1655":{"nm":"फ़सल टोकरी लेबल","de":"आज तोड़ा गया सलाद-पत्ता है या चेरी टमाटर, हर टोकरी पर एक नाम-पट्टी लगाई जाती है। मिट्टी की गंध और हरी महक से भरी फ़सल की सुबह में, लेबल लगते ही वह टोकरी मेज़ तक जाने वाले रास्ते का पहला मील का पत्थर बन जाती है।"},"ICON-1656":{"nm":"बीज संग्रह जार","de":"इस साल की कटाई के बीजों को शीशे के जार में भरकर अगले बसंत को भेज दिया जाता है। ढक्कन बंद होते ही समय कुछ देर के लिए थम जाता है, और नन्हे दाने अंधेरे में अपनी बारी का इंतज़ार करते हैं। यह एक पूरे मौसम को पार करके पहुँचाई गई चिट्ठी जैसा जार है।"},"ICON-1657":{"nm":"कलम बंधन टेप","de":"कटी हुई डाल और नई डाल को आमने-सामने रखकर टेप से लपेट दो, तो दोनों धीरे-धीरे एक शरीर बन जाते हैं। टूटी जगह से फिर बहता रस, धीरे-धीरे भरता घाव। जोड़ना दरअसल एक-दूसरे की बनावट को अपनाना है।"},"ICON-1658":{"nm":"कटाई कैंची कैप","de":"तेज़ धार वाली कैंची की नोक पर एक छोटी टोपी पहनाई जाती है। डालियाँ छाँटने वाला हाथ आराम कर रहा हो, तब धार कुंद न हो और हाथ ज़ख़्मी न हो, इसलिए। काम पूरा कर चुके औज़ार को भी रात के कपड़े चाहिए, यह कहकर बगीचा अपने औज़ारों को प्यार से सुला देता है।"},"ICON-1659":{"nm":"फूल-बीज छाँटन डिब्बा","de":"गुल-मेहँदी, दुपहरिया, चार-बजे का फूल—नाम और रंग में अलग बीजों को हर ख़ाने में अपना कमरा मिल जाता है। मिल जाएँ तो बसंत में कौन किसका पता नहीं चलता। डिब्बे के भीतर की छोटी दीवारें अभी न खिले बगीचे का नक़्शा पहले से खींच रखती हैं।"},"ICON-1660":{"nm":"गमला ट्रॉली","de":"चार पहिए लगाओ तो भारी गमला भी धूप के पीछे टहलने निकल पड़ता है। सुबह पूरब की खिड़की, दोपहर में छाँव। भार से जकड़ी हरियाली अब लुढ़कते हुए, दिन भर रोशनी का पीछा करते हुए सबसे अच्छी जगह ढूँढती है।"},"ICON-1661":{"nm":"बेल दिशा-डोरी","de":"कहाँ जाऊँ न जानकर हवा टटोलती बेल की टेंड्रिल को, यह डोरी धीरे से सही राह पर ले जाती है। ऊपर, और ऊपर। पकड़ने की जगह दे दो तो पौधा अचरज भरे ढंग से वह हाथ थाम लेता है। बढ़ने में भी एक राह दिखाने वाले की ज़रूरत होती है।"},"ICON-1662":{"nm":"पुष्प-भाषा कार्ड होल्डर","de":"फूल के पास टँगे कार्ड में वह फूल जो कहना चाहता है, लिखा होता है। हाइड्रेंजिया कहता है सच्चाई, डेज़ी कहती है मासूमियत। क्यारी में टहलना ही चिट्ठियाँ पढ़ने की सैर बन जाए, इसलिए एक छोटा होल्डर चुपचाप मूक फूल को आवाज़ उधार देता है।"},"ICON-1663":{"nm":"बग़ीचा तख्ती कैप","de":"बारिश-हवा से लिखावट न फैल जाए, इसलिए बग़ीचे की तख्ती पर एक साफ़ टोपी पहनाई जाती है। \"यहाँ टमाटर\", \"यहाँ तुलसी\"। धुँधले पड़ने वाले नाम साफ़ बने रहते हैं, तो साल बीत जाने पर भी बगीचा अपने किसी भी सदस्य को नहीं भूलता।"},"ICON-1664":{"nm":"खाद चम्मच","de":"मिट्टी में पोषण मिलाते वक़्त, लालच करने पर जड़ें ही झुलस जाती हैं। इसलिए एक चम्मच, बस उतना ही। एक नन्हा चम्मच सही मात्रा उठाकर याद दिलाता है—अच्छी परवरिश का मन हमेशा नाप-तौल जानने वाली उँगलियों से आता है।"},"ICON-1665":{"nm":"फुहार नॉज़ल","de":"नॉज़ल घुमाओ तो पानी की धार कोहरे जैसी बिखरकर गिरती है। तेज़ धार में झुलसती कोमल पत्ती, ओस जैसी बूँदों तले धीरे से सिर उठाती है। वही पानी, दिए जाने के ढंग के हिसाब से बिल्कुल अलग अभिवादन बन जाता है।"},"ICON-1666":{"nm":"आहार मापन कप","de":"एक कप, दो कप। दोस्त का एक वक़्त का खाना अंदाज़े से नहीं, मन लगाकर नापा जाता है। ज़्यादा हो तो बचा रह जाए, कम हो तो मन खट्टा हो, इसलिए ठीक-ठीक मात्रा नापने का काम। प्यार कभी-कभी नाप-तौल के रूप में भी आता है।"},"ICON-1667":{"nm":"फर-झड़ान कंघी कवर","de":"फर झड़ने के मौसम में, ब्रश में उलझे मुलायम रोयों को कवर संभालकर लपेट लेता है। सँवारना ख़त्म होने के बाद कंघी को टोपी पहना दो, तो अगला दिन भी मुलायम शुरुआत लेकर आता है। साथ रहने वाले परिवार की चमक ऐसी ही छोटी सफ़ाइयों से चुपचाप बढ़ती है।"},"ICON-1668":{"nm":"नाखून कतरनी कैप","de":"तेज़ नाखून कतरनी की नोक पर एक छोटा ढक्कन लगा दिया जाता है, ताकि सँवार चुका औज़ार दराज़ की दूसरी चीज़ों को न खरोंचे। देखभाल का वक़्त ख़त्म होने के बाद, औज़ार को थपथपाकर सुला देना ही परवाह के एक पूरे चक्र को पूरा करता है।"},"ICON-1669":{"nm":"कॉलर चार्म","de":"गले के पट्टे पर एक चमकता चार्म लटका दो, तो रोज़ की सैर की राह थोड़ी और ख़ास हो जाती है। धूप में इठलाकर चमकता एक नन्हा गहना। भड़कीला भले न हो, पर यह बताने भर के लिए काफ़ी है कि यह छोटा साथी किसी का बेहद प्यारा परिवार-सदस्य है।"},"ICON-1670":{"nm":"पालतू स्वास्थ्य कार्ड","de":"आज ठीक से खाया या नहीं, कहीं तकलीफ़ तो नहीं। साथ रहने वाले दोस्त के दिन को कार्ड पर एक-एक पंक्ति करके लिखा जाता है। बोल न पाने वाले परिवार-सदस्य की हालत जब लिखावट में दर्ज हो जाती है, तो देखभाल करने वाला मन भी उतना ही बारीक़ और भरोसेमंद बन जाता है।"},"ICON-1671":{"nm":"सोने का गद्दा कवर","de":"सोने के गद्दे को मुलायम नए कपड़े पहनाए जाते हैं। लोटते-पोटते और सहलाते हुए घिस गया कपड़ा उतारो तो धूप में सुखाए गए रोयों की महक फैल उठती है। सबसे ज़्यादा लेटी जाने वाली जगह को सबसे साफ़ रखना, साथ रहने वाले परिवार-सदस्य के लिए रोज़ का एक छोटा स्नेह है।"},"ICON-1672":{"nm":"छोटी बाड़ पिन","de":"क्यारी के किनारे नन्हे पिन गाड़-गाड़कर एक नीची बाड़ खड़ी की जाती है। यह \"मत लाँघो\" की धमकी नहीं, बल्कि यहाँ तक फूलों की जगह है, यह बताने वाली एक कोमल सीमा है। रखी जाने वाली एक रेखा हो, तभी उसके भीतर बेफ़िक्र होकर बढ़ा जा सकता है।"},"ICON-1673":{"nm":"घुलमिल स्नैक डिब्बी","de":"शर्मीला बच्चा भी इस डिब्बी के हिलने की आवाज़ पर कान खड़े कर लेता है। भीतर मन खोल देने वाला एक मुट्ठी नाश्ता है। नज़दीक आने में शब्दों से ज़्यादा छोटे-छोटे वादे तेज़ चलते हैं, यह खनकती आवाज़ पहले क़दम बढ़ाकर बता देती है।"},"ICON-1674":{"nm":"सैर लॉग टैग","de":"आज कौन सी राह पर कितना चला, यह टैग पर गाँठ की तरह दर्ज कर लिया जाता है। पदचाप जमा हो जाएँ तो नक़्शा बनता है, नक़्शे जमा हों तो यादें बनती हैं। साथ चली हर एक दिन इस छोटी सी पट्टी पर करीने से जमा होती जाती है।"},"ICON-1675":{"nm":"चिड़िया-दाना कटोरी","de":"खिड़की की चौखट पर कटोरी रखकर बाजरे के कुछ दाने डाल दो, तो अनजान मेहमान एक-एक करके उड़ते चले आते हैं। चोंच मारने की टक-टक आवाज़, पंखों की फड़फड़ाहट। दी गई एक मुट्ठी हर सुबह एक छोटा संगीत-समारोह ले आती है, यह एक नन्हा भोजन-मेज़ है।"},"ICON-1676":{"nm":"गिलहरी अवलोकन डिब्बा","de":"पारदर्शी डिब्बे के भीतर गिलहरी की गोल-गोल आँखों से नज़रें मिलती हैं। गाल में बलूत के फल भर-भरकर सिर टेढ़ा करने का वह दृश्य! कुछ देर झाँककर फिर छोड़ देने के वादे पर, एक नन्हे जंगल से एक क्षणिक नमस्ते बाँटा जाता है।"},"ICON-1677":{"nm":"पंजा-छाप प्लास्टर साँचा","de":"नरम प्लास्टर उड़ेलकर एक नन्हा पंजा-निशान उतारा जाता है। जमने का इंतज़ार करते वक़्त, आँगन का समय भी कुछ देर के लिए थम जाता है। बड़े होते ही मिट जाने वाले उस बित्ता भर पैर की छाप को, सफ़ेद साँचा हमेशगी की तरह उठाकर दोनों हाथों में धीरे से थमा देता है।"},"ICON-1678":{"nm":"रात्रि स्कोप लेंस कैप","de":"रात में झाँकने वाले लेंस की नोक पर एक छोटा ढक्कन बंद कर दिया जाता है। तारे और घोंसले देख चुका शीशे का गोला बिना किसी धूल-कण के अगली रात का इंतज़ार करता रहे, इसलिए। अंधेरे को साफ़ देखने वाली आँखों को भी दिन भर के लिए एक ठहराव चाहिए।"},"ICON-1679":{"nm":"घोंसला सुरक्षा सूचक","de":"डालियों के बीच घोंसला मिले तो, नज़दीक जाने के बजाय एक सूचक खड़ा कर दिया जाता है। \"यहाँ चिड़िया-परिवार रहता है, कृपया शांत रहें।\" देखना, पर घुसपैठ न करना—यही एक कोमल क़दम पीछे घोंसले को सबसे सुरक्षित बनाता है।"},"ICON-1680":{"nm":"पशु-ध्वनि रिकॉर्डर चिप","de":"घास-झाड़ी का गीत, छज्जे के नीचे की चहचहाहट, रात के कीड़ों की आवाज़—इन्हें चिप में क़ैद नहीं, बस थोड़ी देर के लिए उधार लिया जाता है। दोबारा बजाओ तो उस पल की हवा तक फिर से जी उठती है, ऐसा एक नन्हा ध्वनि-बक्सा। ताकि सुनी हुई कोई भी चीज़ कभी न मिटे।"},"ICON-1681":{"nm":"दूरबीन कवर","de":"एक चिड़िया के उड़ान भरने से ठीक पहले, जंगल कुछ देर के लिए साँस रोक लेता है। उस सन्नाटे के पल में लेंस पर ढका एक कपड़ा, बिना किसी उँगली के निशान के, दूर की स्पष्टता की रखवाली करता है।"},"ICON-1682":{"nm":"वन-पथ कैमरा पट्टा","de":"खड़ी वन-पगडंडी पर चढ़ते हर बार कैमरा छाती से हल्के से टकराता है। धड़कती धड़कन और शटर की आवाज़ एक ही लय में हिलती है, और यह एक पट्टा उन पलों को छाती के सामने मज़बूती से थामे रखता है।"},"ICON-1683":{"nm":"प्रकृति परिचय कार्ड","de":"घास की एक पत्ती का भी नाम होता है, यह कार्ड चुपचाप बता देता है। अनजाने में गुज़र जाने वाली चीज़ को जब एक नाम मिल जाता है, तो पहाड़ी रास्ता अचानक जाने-पहचाने चेहरों से स्नेहपूर्वक भर उठता है।"},"ICON-1684":{"nm":"पाल मरम्मत पैच","de":"हवा को पूरे बदन पर झेलने वाले कपड़े पर भी घाव रह जाते हैं। फटी जगह पर धीरे से लगाया गया एक छोटा टुकड़ा, पाल को फिर से दूर समुद्र थामने का हक़ दिला देता है।"},"ICON-1685":{"nm":"रस्सी गाँठ अभ्यास पट्टी","de":"ऊपर, नीचे, एक बार और लपेटो—हाथों ने याद रखा वह क्रम ही गाँठ बन जाता है। जिस रात तूफ़ान डेक पर दस्तक देता है, वह एक विधि ही इंसान और जहाज़ को एक साथ बाँध देती है।"},"ICON-1686":{"nm":"लंगर-ज़ंजीर कैप","de":"ज़ंजीर के सिरे पर पहनाई जाने वाली इस छोटी टोपी को हल्के में मत लो। जंग भीतर ही भीतर चुपके से बढ़ती है, इसलिए समुद्री हवा के आगे डटी एक कैप लंगर की उम्र चुपचाप बढ़ा देती है।"},"ICON-1687":{"nm":"दिशा-सूचक झंडा","de":"कोहरा इतना घना हो कि आगे का रास्ता मिट जाए, उस दिन एक झंडा उसकी जगह राह बता देता है। हवा में लहराता रंग का एक बिंदु, भटकते हुए पतवार-चालक के अकड़े कंधों को आख़िरकार ढीला कर देता है।"},"ICON-1688":{"nm":"केबिन चाबी-छल्ला","de":"हिलते-डुलते समुद्र पर, संकरे केबिन के दरवाज़े पर एक छोटा छल्ला टँगा है। जब तक चाबी अपनी जगह पर टिकी है, लौटने के लिए एक कमरा हमेशा तुम्हारे लिए बंद नहीं होता।"},"ICON-1689":{"nm":"जलरोधी नक़्शा केस","de":"बारिश में काग़ज़ का नक़्शा पहले रास्ता ही मिटा देता है। पारदर्शी केस के भीतर एक शीट सूखी बनी रहती है, तब तक भीगा हुआ सफ़र भी आख़िर तक अपनी दिशा नहीं खोता।"},"ICON-1690":{"nm":"जहाज़ी दीये की बत्ती","de":"बत्ती ने धीरे-धीरे जो तेल सोखा, वह आख़िरकार लौ बनकर खिल उठता है। डेक पर रोशनी का एक बिंदु, उस नन्हे टिमटिमाने भर से रात के समुद्र की दूरी हल्के से नज़दीक आ जाती है।"},"ICON-1691":{"nm":"संकट संकेत कपड़ा","de":"जहाँ आवाज़ नहीं पहुँचती, वहाँ लाल कपड़ा ऊँचा लहराता हाथ शब्दों से भी दूर तक जाता है। हवा को चीरती यह एक चादर, यहाँ कोई ज़िंदा है, यह पुकार उसकी जगह लगा देती है।"},"ICON-1692":{"nm":"समुद्री हवा दिशा पिन","de":"हवा कहाँ से आ रही है, यह जानने वाला ही राह तय करता है। एक छोटी पिन जो दिशा चुपचाप दिखाती है, उस पर आज भर के पूरे सफ़र की क़िस्मत हल्के से टिकी रहती है।"},"ICON-1693":{"nm":"तह होने वाला फावड़ा कवर","de":"फल को मोड़कर ढक दो, तो मेहनती फावड़ा भी कुछ देर साँस ले लेता है। सारी मिट्टी खोद चुका हाथ आख़िर में जो करता है, वह है कल की धार को कुंद होने से बचाना।"},"ICON-1694":{"nm":"जेबी दिशासूचक केस","de":"सुई हमेशा बिना काँपे उत्तर की ओर इशारा करती है, पर उस सुई की रक्षा एक मज़बूत केस करता है। जो एक बार रास्ता भटक चुका है, वह दिशा को उतना ही ज़्यादा संजोकर रखना जानता है।"},"ICON-1695":{"nm":"कैंप बर्तन जाली","de":"धोए गए बर्तनों को जाली में टाँगकर सुबह की धूप में सुखाया जाता है। शिविर का दिन पानी सूखने की आवाज़ से शुरू होता है, और यही छोटी सी बात तंबू के भीतर को भरोसे से भर देती है।"},"ICON-1696":{"nm":"शिविर अनुमति कार्ड","de":"इस पहाड़ पर एक रात ठहरने की इजाज़त। हाथ में एक काग़ज़ आते ही, अनजाना जंगल भी कुछ देर के लिए अपना बन जाता है और छोटे तंबू को धीरे से अपना लेता है।"},"ICON-1697":{"nm":"अभियान-मार्ग झंडा डोरी","de":"हर चौराहे पर एक झंडा बाँध दो, तो लौटने की राह अंधेरे में बिखरती नहीं। आगे गए इंसान का छोड़ा एक छोटा निशान, पीछे आने वाले क़दमों की पीठ को चुपचाप आगे धकेल देता है।"},"ICON-1698":{"nm":"जलरोधी माचिस डिब्बी","de":"एक बूँद पानी में भीगते ही माचिस हमेशा के लिए ख़ामोश हो जाती है। पानी की एक बूँद भी न घुस सके, ऐसे सील डिब्बे के भीतर, चिंगारी सूखी और चुपचाप ठीक सबसे ठंडी रात के लिए ही इंतज़ार करती है।"},"ICON-1699":{"nm":"पोर्टेबल जल शुद्धिकरण फ़िल्टर","de":"धुँधला होने से हिचकिचाहट पैदा करने वाला पानी भी इस फ़िल्टर से गुज़रकर साफ़ हो जाता है। प्यास से पहले शक़ को उतार देने वाला एक छोटा उपकरण—पी सकने का भरोसा ही एक घूँट भर सुकून है।"},"ICON-1700":{"nm":"आपातकालीन कंबल पैक","de":"तह करो तो हथेली जितना, खोलो तो एक इंसान की गर्माहट बन जाता है। \"आपातकाल\" शब्द थोड़ा कम भारी लगे, इसलिए यह कंबल थैले के एक कोने में हमेशा गर्म होने को तैयार बैठा रहता है।"},"ICON-1701":{"nm":"रात्रि संकेत कंगन","de":"अंधकार में डूबे पहाड़ी रास्ते पर, एक कलाई चुपचाप प्रकाश बिखेरती है। एक-दूसरे का स्थान बताने वाली वह छोटी सी पट्टी, साथ चलने वालों को एक अदृश्य डोर से स्नेहपूर्वक जोड़ देती है।"},"ICON-1702":{"nm":"खनिक हेलमेट स्टिकर","de":"हेलमेट पर लगा स्टिकर खनिक का एक और नाम-पट्टिका है। जहाँ प्रकाश भी दुर्लभ हो, उस गहरी सुरंग में, साथी को दीपक की रोशनी में झलकते उस छोटे से चित्र से ही प्रसन्नतापूर्वक पहचान लिया जाता है।"},"ICON-1703":{"nm":"अयस्क शिरा चिह्न पिन","de":"जहाँ अयस्क की शिरा मिली हो, वहाँ चुपचाप एक पिन गाड़ दी जाती है। अंधकार में अकेले चमकता वह एक बिंदु, आने वाले किसी और को स्नेह से बता देता है कि यहीं से खुदाई शुरू करो।"},"ICON-1704":{"nm":"दरार मापक स्केल","de":"दीवार में पड़ी दरार को नापना एक धीमा और अटूट धैर्य है। क्या यह कल से एक बित्ता और चौड़ी हो गई है—स्केल का बताया वह छोटा सा अंक ढहने से पहले ही उसका संकेत दे देता है।"},"ICON-1705":{"nm":"पुरावशेष रगड़-छाप कागज़","de":"पत्थर पर उकेरी आकृति पर कागज़ रखकर, धीरे-धीरे स्याही थपथपाई जाती है। हज़ार साल पहले के स्पर्श के काली रेखाओं में उभर आने के उस क्षण, यह रगड़-छाप बीते हुए समय को कुछ देर के लिए आमने-सामने बिठा देती है।"},"ICON-1706":{"nm":"प्राचीन सिक्का केस","de":"जंग से बचा कर सहेजी गई यह छोटी सी धातु, किसी लुप्त हो चुके देश की अंतिम आवाज़ को अपने भीतर समेटे है। एक सिक्के में एक पूरा युग समाया है, जो पारदर्शी केस के भीतर धीरे-धीरे बूढ़ा होता जाता है।"},"ICON-1707":{"nm":"क्रिस्टल टुकड़ा स्टैंड","de":"भीतर प्रकाश को क़ैद करने वाले क्रिस्टल को भी किसी सहारे की ज़रूरत होती है। जब वह एक छोटे से स्टैंड पर चुपचाप टिकता है, तभी वह नाज़ुक चीज़ अपनी पूरी चमक को खुलकर प्रकट कर पाती है।"},"ICON-1708":{"nm":"गुफा मानचित्र टुकड़ा","de":"फटा हुआ नक्शा अपने आधे रहस्य को ही चुपके से दिखाता है। बाकी टुकड़े मिलने के उस दिन तक, यह एक टुकड़ा गुफा में कहीं शेष मार्ग को आधा छिपाए रखता है।"},"ICON-1709":{"nm":"रस्सी अवतरण कैराबिनर","de":"चट्टान से नीचे शरीर को सौंपने से पहले, इस कड़ी पर पूरा भरोसा करना पड़ता है। एक ठंडे लोहे के टुकड़े पर अपना पूरा भार टिका देना—विश्वास तो स्वभाव से ही इतना भारी होता है।"},"ICON-1710":{"nm":"उत्खनन अनुमति-पत्र","de":"ज़मीन खोदने की अनुमति की स्पष्ट मुहर लगा एक कागज़। दबी हुई चीज़ को जगाने से पहले पहले अनुमति माँगो—उत्खनन चुपचाप यही सिखाता है कि हर शुरुआत शिष्टाचार से होनी चाहिए।"},"ICON-1711":{"nm":"पवन-रोधी पैक","de":"हवा की ओर पीठ करके इसे फैलाओ, तो तेज़ हवाओं वाले मैदान के बीचोबीच एक छोटी सी शांति उभर आती है। इस एक परत के पीछे एक छोटी सी चिंगारी सुरक्षित रहती है, और थका हुआ यात्री कुछ पल आराम पा लेता है।"},"ICON-1712":{"nm":"रेतीय तूफ़ान चश्मा कवर","de":"रेत चाहे कितनी भी बेरहमी से उमड़े, दृष्टि को अंत तक बचाए रखना ही होता है। चश्मे को ढकने वाला यह एक पतला कवर, तूफ़ान के बीच भी आँखें खोलकर आगे बढ़ने का साहस बन जाता है।"},"ICON-1713":{"nm":"वर्षा-आगंतुक ट्रे","de":"आए हुए मेहमान के जूतों की नोक से बारिश का पानी टपकता रहता है। दहलीज़ पर चुपचाप रखी एक ट्रे, भीगे और ठंडे पड़ चुके पैरों को बिना कुछ कहे गर्मजोशी से थाम लेती है।"},"ICON-1714":{"nm":"लू शीतलक टैग","de":"दोपहर की तपिश को धीरे से ठंडा करने वाला एक छोटा टैग। बैग से लटका हुआ यह ठंडक को थामे रखता है, और जब पसीने की बूँदें जमने लगें, तब चुपके से मुट्ठी भर छाँव थमा देता है।"},"ICON-1715":{"nm":"शीतलहर हैंड-वॉर्मर बेल्ट","de":"कमर के चारों ओर एक बार लपेटी जाने वाली गर्म पट्टी। जब हैंड-वॉर्मर की ऊष्मा कमर के निचले हिस्से में फैलती है, तो कड़ाके की जाड़े का मैदान भी थोड़ा सहनीय जगह बन जाता है।"},"ICON-1716":{"nm":"नमी अवशोषक पैक","de":"सीलन बिना आवाज़ किए चीज़ों को चाट जाती है। जब तक डिब्बे में रखा छोटा पैक चुपचाप नमी सोखता रहता है, प्रिय वस्तुएँ सूखी और अपने असली रूप में सुरक्षित बनी रहती हैं।"},"ICON-1717":{"nm":"कीचड़ जूता कवर","de":"कभी-कभी कीचड़ में चलते हुए भी जूते साफ़ रहने चाहिए। मिट्टी को रोकने वाला यह पतला आवरण, घर लौटकर दहलीज़ पार करते क़दमों को और भी हल्का बना देता है।"},"ICON-1718":{"nm":"समुद्री कोहरा दीप कवर","de":"जब समुद्री कोहरा दीपक को पूरी तरह निगलने की कोशिश करता है, तब यह कवर बिखरती रोशनी की धार को चुपचाप समेट लेता है। धुंधली भोर में भी बंदरगाह की एक बत्ती अंत तक बुझने से इनकार करती है।"},"ICON-1719":{"nm":"वज्रपात चेतावनी पिन","de":"जब काले बादल नीचे उतर आएँ, तो एक पिन सबसे पहले चेतावनी देती है। बिजली गिरने से पहले झुक जाने की यह सीख—प्रकृति के आगे विनम्रता हमेशा पहले से सीख लेना ही भला है।"},"ICON-1720":{"nm":"रेसिपी बुकमार्क","de":"खुली रखी पाक-पुस्तक के बीच रखा जाने वाला एक छोटा बुकमार्क। चूल्हे के सामने खो गई पंक्ति को टटोलकर फिर से ढूँढ़ने पर, माँ के हाथ का स्वाद भी उसी पन्ने पर साथ जाग उठता है।"},"ICON-1721":{"nm":"मसाला माप छड़ी","de":"माँ हमेशा बस इतना कहती थीं, \"एक चुटकी।\" अंदाज़े से नापना कभी सटीक नहीं हो सकता, फिर भी उनका वह हाथ का स्वाद कभी नहीं डगमगाया। इस छड़ी से नमक तोलते हुए यह समझ आता है कि माप से भी अधिक जो पका था, वह अंदाज़ा नहीं, प्रेम था।"},"ICON-1722":{"nm":"किण्वन ढक्कन बैंड","de":"क्या तुम्हें पता है कि मटका भी साँस लेता है? जब यह बैंड ढक्कन को कसकर लपेट लेता है, तो भीतर और बाहर धीरे-धीरे बातचीत शुरू करते हैं। जल्दबाज़ी न करने वाले उन कुछ दिनों के बीत जाने के बाद ही, प्रतीक्षा को आख़िरकार \"स्वाद\" नाम मिलता है।"},"ICON-1723":{"nm":"पकने की तिथि पर्ची","de":"बनाई गई तारीख़ स्पष्ट अक्षरों में लिखकर चिपकाई गई एक छोटी पर्ची। लिखावट धुंधली होती जाती है, पर भीतर का स्वाद और गहरा होता जाता है। भूल जाने का बहाना करते हुए लिख छोड़ना और किसी दिन अचानक फिर निकाल लेना—पकना यूँ ही निभाया गया एक वादा है।"},"ICON-1724":{"nm":"शोरबा छन्नी","de":"निर्मल शोरबा छानने और फिर छानने के अंत में ही आता है। ठोस टुकड़ों को थामे रखते हुए केवल सार को धीरे से बहा देने वाली इस छन्नी को देखते हुए, पुरानी रसोई की यह बात उँगलियों तक पहुँचती है कि जो निकाला जाता है, उसी स्थान पर गहराई ठहर जाती है।"},"ICON-1725":{"nm":"आटा-किण्वन कपड़ा","de":"आटे के ऊपर चुपचाप एक कपड़ा ढक दिया जाता है। उस धुंधलके के नीचे जब ख़मीर लगन से फूलता रहता है, तब पहली बार यह सीखा जाता है कि अनदेखी जगहों में चुपचाप बढ़ने वाली चीज़ों में भी कितनी कोमलता होती है।"},"ICON-1726":{"nm":"सामग्री तैयारी पिन","de":"हरे प्याज़ की रेशों को चीरने और लहसुन को मज़बूती से थामने वाली एक छोटी पिन। सामग्री को तैयार करना मानो उसे दिया गया पहला अभिवादन है, इसलिए जितनी मन से काट-छाँट की जाए, शाम की मेज़ का उजाला उतना ही एक टोन और चमकीला हो जाता है।"},"ICON-1727":{"nm":"प्लेटिंग चिमटी","de":"थाली पर आख़िरी टुकड़ा कहाँ रखा जाए, यह अंततः यही चिमटी तय करती है। कुशल हाथ के हवा में आधे पल के लिए ठिठकने के उस छोटे से क्षण में, एक भोजन चुपके से एक चित्र बन जाता है।"},"ICON-1728":{"nm":"इंसुलेटेड टिफ़िन कवर","de":"स्कूल के फाटक पर सौंपा गया टिफ़िन दोपहर की घंटी बजने तक गर्म रहना ज़रूरी था। इस कवर के भीतर क़ैद ऊष्मा, भोर से चूल्हे के सामने खड़े किसी के मन की गहराई जितनी, ठंडी नहीं पड़ती।"},"ICON-1729":{"nm":"भोजन आमंत्रण-पत्र","de":"\"एक दिन हमारे घर आकर खाना खाओ।\" इससे बढ़कर स्नेहपूर्ण बात और क्या हो सकती है। बिना किसी बड़े वादे के, बस एक ही मेज़ पर बैठने का यह न्यौता—कोरियाई भाषा में दिया जा सकने वाला सबसे पुराना आमंत्रण इस एक पत्र में समाया है।"},"ICON-1730":{"nm":"टेबल आरक्षण चिप","de":"नाम लिखकर सीट सुरक्षित कर ली जाती है। जब एक छोटी चिप ख़ाली मेज़ को कुछ देर के लिए किसी का बना देती है, तब निर्धारित वह समय क़दमों की आहट की तरह धीरे-धीरे नज़दीक आता है।"},"ICON-1731":{"nm":"स्वाद-परख कार्ड","de":"एक कौर लेकर बड़ी गंभीरता से सितारे देते हुए चेहरे। इस कार्ड पर साफ़ अक्षरों में लिखी वह ईमानदार पंक्ति, अगली थाली को और स्वादिष्ट बनाने वाली सबसे गर्मजोशी भरी नसीहत है।"},"ICON-1732":{"nm":"टिफ़िन धन्यवाद पट्टी","de":"साफ़-सुथरे खाली किए गए टिफ़िन डिब्बे पर एक पट्टी लपेटकर वापस भेज दी जाती है। जो शख़्स आख़िर तक \"अच्छा खाया\" कहना न कर पाया, उसका भी अनकहा मन यह गाँठ उसकी जगह बाँधकर पहुँचा देती है।"},"ICON-1733":{"nm":"एलर्जी चेतावनी टैग","de":"यह एक छोटा टैग किसी की मेज़ की चुपचाप रक्षा करता है। इसमें क्या है, यह साफ़-साफ़ बता देना, अनदेखी जगहों तक ध्यान रखने वाली आतिथ्य-भावना का ही एक और नाम है।"},"ICON-1734":{"nm":"स्वाद-स्मृति चम्मच","de":"जीभ की नोक पर लंबे समय तक बना रहने वाला वह स्वाद, वास्तव में उस दिन का दृश्य ही था। एक चम्मच पल भर में बचपन की रसोई तक ले जाता है, यह देखकर लगता है कि स्मृति पेट नहीं, बल्कि मन ही उठाकर सहेजता है।"},"ICON-1735":{"nm":"आज का मेन्यू टोकन","de":"आज क्या खाएँ। दुनिया के सबसे मुश्किल सवाल के सामने हम हर बार हार जाते हैं। इस टोकन को उछालकर भाग्य के हाथों मेन्यू सौंप देने के बाद, मन अनायास ही हल्का और प्रसन्न हो उठता है।"},"ICON-1736":{"nm":"साझा भोजन-मेज़ घंटी","de":"घंटी एक बार बज उठे तो कमरों में बिखरा परिवार एक जगह इकट्ठा हो जाता है। गोल मेज़ पर बजती वह घंटी की आवाज़, \"बन गया, जल्दी आओ\" शब्दों का सबसे मधुर अनुवाद है।"},"ICON-1737":{"nm":"डेज़र्ट क्रम कार्ड","de":"मीठा हमेशा सबसे आख़िर में। किसने तय किया यह भी पता नहीं, फिर भी इस वादे को यह कार्ड निभाता है। स्वाद के चरम को डेज़र्ट के आख़िरी कौर तक बचाकर रखने वाला, यह मेज़ का एक छोटा और स्नेहमय संचालक है।"},"ICON-1738":{"nm":"मोल-भाव टोकन","de":"बाज़ार के बीचोबीच, \"थोड़ा कम कर दो\" और \"पहले से ही घाटे में हूँ\" प्रेमपूर्वक टकराते हैं। यह टोकन उस मोल-भाव के अंत में आख़िरकार हँसी में बदल जाने वाली, किसी पुराने ग्राहक की रसीद है।"},"ICON-1739":{"nm":"स्टॉक जाँच पिन","de":"गोदाम की अलमारियों को चुपचाप देखते हुए ख़ाली जगह ढूँढ़कर पिन गाड़ी जाती है। क्या बचा है और क्या ख़त्म हो गया, यह जानना—गृहस्थी जैसा बड़ा काम हमेशा इसी छोटी सी जाँच से शुरू होता है।"},"ICON-1740":{"nm":"दुकान सफ़ाई ब्रश","de":"बाज़ार बंद होने की शाम, ख़ाली काउंटर को झाड़ती ब्रश की आवाज़ दुकान में धीमे से फैल जाती है। कल फिर भरी जाने वाली जगह को पहले से साफ़ करती उँगलियों में, दिन को सलीक़े से समेटने वाली मेहनत बसी होती है।"},"ICON-1741":{"nm":"आज की सिफ़ारिश कार्ड","de":"\"आज यह अच्छा है।\" दुकान मालिक द्वारा चुपके से बढ़ाया गया एक कार्ड। क्या चुनें, यह तय न कर पा रहे ग्राहक के कंधे को धीरे से हौले देने वाली उस सिफ़ारिश में, एक दिन भर का गर्व सलीक़े से समाया रहता है।"},"ICON-1742":{"nm":"नियमित ग्राहक स्टैंप होल्डर","de":"दस बार भरो तो एक बार मुफ़्त। स्टैंप के ख़ाने धीरे-धीरे भरते जाने वाला यह होल्डर \"नियमित ग्राहक\" शब्द का दूसरा चेहरा है, और बार-बार आना अंततः पसंद करने का ही मतलब है।"},"ICON-1743":{"nm":"विनिमय बही क्लिप","de":"बदली और लौटाई गई वस्तुओं का लेखा-जोखा एक साथ थामने वाली क्लिप। जितना अधिक आदान-प्रदान होता है, बही उतनी ही मोटी होती जाती है, और उस मोटाई के बराबर पड़ोसियों के साथ बना विश्वास भी सघन होता जाता है।"},"ICON-1744":{"nm":"विक्रय-समाप्त टैग","de":"आख़िरी वस्तु पर यह टैग लगने के उस क्षण, अजीब ढंग से मन भर आता है। किसी की मेज़ तक, किसी कमरे के कोने तक जाने वाली वस्तु को दिया गया, \"अलविदा\" जैसा एक छोटा-सा विदाई-शब्द है यह।"},"ICON-1745":{"nm":"आरक्षित वस्तु टोकरी","de":"तुम्हारा नाम-पट्टिका लगी टोकरी अलमारी के एक ख़ाने की रखवाली करती है। पहले से सुरक्षित रखी वह एक जगह, अंदर आते हुए तुमसे चुपचाप कहती है, \"मैं इतनी देर से तुम्हारा इंतज़ार कर रही थी।\""},"ICON-1746":{"nm":"पैकिंग काउंटर मैट","de":"पैकिंग काउंटर पर बिछी मैट व्यस्त हाथों की गतिविधि का मंच है। कागज़ मुड़ने और डोरी करीने से बँधने के उस छोटे से समय में, एक साधारण वस्तु चुपके से किसी का उपहार बन जाती है।"},"ICON-1747":{"nm":"मिलने का वादा-पर्ची","de":"\"कल आऊँगा।\" एक पंक्ति लिखकर दरवाज़े की दरार में हौले से खोंसी गई पर्ची। भले ही दोनों का आमना-सामना न हो पाया हो, यह वादा एक कागज़ पर सवार होकर, इंसान से पहले पहुँचकर चुपचाप इंतज़ार करता है।"},"ICON-1748":{"nm":"पड़ोसी उपहार टोकरी","de":"दीवार के उस पार बढ़ाई गई टोकरी में हमेशा \"थोड़ा ज़्यादा बन गया था\" जैसा बहाना साथ में समाया रहता है। कोरियाई आत्मीयता ऐसे ही उदारता का बहाना बनाकर, चुपके से इस ओर पार कर आती है।"},"ICON-1749":{"nm":"गाँव समाचार पेटी","de":"गाँव की छोटी-बड़ी ख़बरें इस पेटी में धीरे-धीरे जमा होती जाती हैं। कौन नया रहने आया, किसके घर उत्सव है—कुछ कागज़ मिलकर मोहल्ले की शांत धड़कन को सुना देते हैं।"},"ICON-1750":{"nm":"धन्यवाद-भेंट स्टैंप","de":"आने के लिए धन्यवाद कहने वाले मन को, एक मुहर से दबाकर छाप दिया जाता है। कागज़ पर फैला वह एक स्याही का निशान, \"मैं नहीं भूलूँगा\" शब्दों से भी अधिक देर तक वहाँ बना रहता है।"},"ICON-1751":{"nm":"दयालुता प्रशंसा कार्ड","de":"आज किसी ने दिखाई गई दयालुता को चुपचाप लिखकर वापस लौटाने वाला कार्ड। छोटी-छोटी कोमलताओं को जान-बूझकर शब्दों में उतार कर सहेजने वाले गाँव में, अच्छाई बार-बार घूमकर लौट आती है।"},"ICON-1752":{"nm":"क्षमा-पत्र मुहर","de":"लाल पके सेब की तरह, माफ़ी का शब्द भी पर्याप्त रूप से पकने के बाद ही दिया जा सकता है। लिफ़ाफ़े पर दबाकर लगाई गई यह मुहर, न कह सकी माफ़ी को अंत तक सँजोए रखने वाले साहस का निशान है।"},"ICON-1753":{"nm":"साझा कार्य तालिका","de":"कौन क्या ज़िम्मेदारी लेगा, यह ख़ानों में बाँटकर लिखा गया एक चार्ट। अकेले भारी लगने वाला काम भी नाम बाँटकर लिखने पर काफ़ी हल्का हो जाता है, यह वही जानता है जिसने कंधे से कंधा मिलाकर काम किया हो।"},"ICON-1754":{"nm":"पड़ोसी पसंद रिबन","de":"पड़ोसी को क्या पसंद है, यह रंग-बिरंगे रिबन से चुपचाप चिह्नित कर दिया जाता है। किसी की पसंद याद रखना, \"मैं तुम्हें चाहता हूँ\" कहे बिना दिया गया सबसे शांत इक़रार है।"},"ICON-1755":{"nm":"आमंत्रण नाम-पट्टी छल्ला","de":"नाम-पट्टिका पर टँगा एक छल्ला \"आज मेहमान स्वागत है\" बता देता है। हथेली भर का यह चिह्न भले हो, पर उसमें किसी का स्वागत करने को तैयार पूरी तरह खुला हुआ एक मन टंगा रहता है।"},"ICON-1756":{"nm":"उत्सव प्रवेश कंगन","de":"खोलने में मन न मानने के कारण कई दिनों तक कलाई पर बाँधे रखा, फीका पड़ चुका एक फ़ीता। कलाई पर बँधने के उसी क्षण असल में उत्सव शुरू हुआ था। उसके भीतर, समाप्त होकर भी कभी न ख़त्म होने वाला वह एक दिन शांति से सोया हुआ है।"},"ICON-1757":{"nm":"आतिशबाज़ी टिकट होल्डर","de":"रात का आकाश फटने से ठीक पहले, इस होल्डर में रखा टिकट धड़कन को मज़बूती से थामे रहता है। \"धड़ाम\" के साथ पहली आतिशबाज़ी खिलने के उस एक क्षण के लिए, हथेली में पसीना आने तक कसकर पकड़ा गया एक वादा है यह।"},"ICON-1758":{"nm":"चंद्र-दर्शन थाली","de":"ऐसी रातें भी थीं जब लगता था मानो पूरा पूर्णिमा का चाँद ही कटोरे में उठा लिया गया हो। इस थाली में ताज़े फल और सोंगप्योन सलीक़े से सजाकर चाँद के आगे प्रणाम करने पर, एक गोल मन आकाश के छोर तक जा पहुँचता है।"},"ICON-1759":{"nm":"शीतकालीन उत्सव दस्ताना पिन","de":"बर्फ़ के मैदान में हाथ सुन्न हो जाएँ फिर भी दस्ताने बार-बार कलाई से फिसल जाते हैं। यह पिन आस्तीन के सिरे पर मज़बूती से लग जाने के बाद ही, आख़िरकार शीतकालीन उत्सव में मन भर कर दौड़ा जा सकता है।"},"ICON-1760":{"nm":"वसंत-स्वागत बीज कार्ड","de":"कार्ड के भीतर सोए हुए कुछ बीज अपनी-अपनी वसंत की प्रतीक्षा करते हैं। मिट्टी में दबा देने पर वादे की तरह अचूक अंकुर फूटता देख, लगता है हर शुरुआत किसी छोटे और ठोस बिंदु से ही जन्म लेती है।"},"ICON-1761":{"nm":"ग्रीष्म समुद्रतट स्टैंप","de":"लहर रेत पर मुहर दबाकर धीरे से पीछे हट जाती है। जल्द मिट जाने का पता होते हुए भी, यहाँ कोई आया था, इसका छोटा-सा निशान छोड़ जाती है। गर्मी हमेशा ऐसे ही एक बार स्पष्ट रूप से छपकर, खारी गंध के साथ बह जाती है।"},"ICON-1762":{"nm":"शरद फ़सल रिबन","de":"अनाज की बालियाँ बाँधने वाला हाथ अंत में एक रिबन सुंदरता से बाँधता है। साल भर के पसीने को मन से समेटने वाली एक गाँठ। खेत ख़ाली होते जाएँ फिर भी शरद ऋतु सबसे सुंदर रंग में, संध्या की लालिमा की तरह, एक बार और विदाई-अभिवादन देती है।"},"ICON-1763":{"nm":"स्मृति-चित्र वार्ता-बुलबुला","de":"\"यहाँ तक आने के लिए धन्यवाद।\" मुँह से न कह पाया अभिवादन कागज़ पर गोल-गोल फूल उठता है। तस्वीर में ठहरी ख़ामोशी को धीरे से आवाज़ उधार देने वाला, एक गोल दिल का टुकड़ा।"},"ICON-1764":{"nm":"उत्सव मानचित्र पिन","de":"विशाल मैदान में रास्ता न भटके, इसलिए किसी ने ठीक-ठीक गाड़ा हुआ निशान। लोक-वाद्य की धुन पर पैर पहले दौड़ पड़ें, फिर भी यह एक पिन भटकते हुए तुम्हें निर्धारित जगह तक चुपचाप ले जाती है।"},"ICON-1765":{"nm":"एल्बम मास्टर चाबी","de":"जो बंद है वह एल्बम नहीं, बल्कि उसके भीतर मुहरबंद समय है। पहली रिकॉर्डिंग की कँपकँपी, आख़िरी मिक्स की भोर। चाबी धीरे-धीरे घुमाओ, तो बनाने वाले ही जानते हैं जिस कमरे को, उसका दरवाज़ा चरचराहट के साथ खुल जाता है।"},"ICON-1766":{"nm":"ट्रैकलिस्ट कार्ड","de":"एक पन्ने पर लिखा गीतों का क्रम असल में मन का ही क्रम है। कहाँ गला भर आएगा, कहाँ साँस थमेगी—कागज़ पहले से यह सब जानता है। पहला सुर सुनने से पहले ही उमड़ आने वाली धड़कन।"},"ICON-1767":{"nm":"ऑडियो जाँच टैग","de":"एक ही हिस्से को सौ बार पीछे घुमाकर सुन चुका व्यक्ति ही यह टैग लगाता है। एक बार और, बस एक ही बार और सुन लें, यह सोचकर। \"पास\" मुहर के बगल में भोर तक अपने ही कानों पर शक करते किसी की रात छिपी है।"},"ICON-1768":{"nm":"प्री-ऑर्डर लेबल","de":"अभी दुनिया में आई भी न चीज़ की पहले से प्रतीक्षा करने का वादा। लेबल लगने के उस क्षण, एक ख़ाली जगह किसी के नाम से चुपचाप आरक्षित हो जाती है। रोमांचक प्रतीक्षा का भी एक क्रमांक-टोकन होता है।"},"ICON-1769":{"nm":"प्रथम संस्करण मुहर स्टिकर","de":"मटके पर हानजी कागज़ ढककर गोंद से सील करते पुराने हाथों की याद दिलाती है। शुरुआत को ज्यों की त्यों बचाने का वादा करता एक स्टिकर। हटाने पर मिट जाने का पता होते हुए भी, उसकी बनावट को बार-बार और देर तक निहारते रहते हैं।"},"ICON-1770":{"nm":"कमबैक कैलेंडर चिप","de":"कैलेंडर पर एक गोला और बढ़ जाए तो उस दिन तक बची रातें एक-एक ख़ाना कम होती जाती हैं। हाथ में थमी छोटी चिप पर लौटने की तारीख़ साफ़ अंकित है। प्रतीक्षा करने वाले के लिए समय यूँ ही उँगलियों पर गिना जाता है।"},"ICON-1771":{"nm":"कॉन्सेप्ट फ़ोटो स्लीव","de":"एक कॉन्सेप्ट का रंग अगले कॉन्सेप्ट द्वारा हटाए जाने से पहले, उसकी बनावट को सहेजकर रखने वाली एक पारदर्शी परत। मौसम बदलने पर भी भुलाई न जाए, इसलिए बीते दिनों के रंग को कोनों समेत धीरे से सुरक्षित रखती है।"},"ICON-1772":{"nm":"टीज़र रिवील टोकन","de":"पर्दा हटाने से ठीक पहले, हथेली में थामा एक छोटा सिक्का। इसे बढ़ाने के उस क्षण, बंद रखा गया पहला दृश्य दुनिया की ओर एक बित्ता खुल जाता है। प्रकटीकरण अंततः इस बात का मामला है कि पहले कौन हाथ बढ़ाता है।"},"ICON-1773":{"nm":"एल्बम प्रदर्शन स्टैंड","de":"एक नीचा स्टैंड एल्बम को हौले से उठाता है, उसी क्षण एक साधारण डिस्क प्रदर्शन-मेज़ की नायिका बन जाती है। प्रकाश सबसे सुंदर ढंग से पड़ने वाले कोण को, बिना कुछ कहे पीछे से थामने वाला एक स्नेहमय सहायक कलाकार।"},"ICON-1774":{"nm":"डेब्यू शोकेस पास","de":"\"पहली बार आपके सामने प्रस्तुत\" शब्द अंकित एक पास। मंच के पीछे लंबे गलियारे से गुज़रकर दर्शकों की पहली तालियों तक, यह पास डेब्यू की काँपती दहलीज़ पार करने में मदद करता है।"},"ICON-1775":{"nm":"प्रथम मंच स्थान चिप","de":"फ़र्श पर चिपकी चिप को पैर की उँगलियों से चुपचाप टटोला जाता है। बिना देखे भी शरीर पहले जान लेता है वह एक ख़ाना। याद किए गए स्थान पर ठीक-ठीक पहुँचने के उस क्षण, उँगलियों की कँपकँपी आख़िरकार एक स्पष्ट भाव-भंगिमा बन जाती है।"},"ICON-1776":{"nm":"अभिवादन-वक्तव्य कार्ड","de":"\"यह सब आप सबकी बदौलत है\" जैसी आम बात भी काँपती हस्तलिपि में लिखी जाए तो अब आम नहीं रहती। भावुक होकर भूल न जाऊँ, इस डर से पहले से लिखी गई कुछ पंक्तियाँ। सच्चा मन कभी-कभी एक कार्ड का सहारा लेता है।"},"ICON-1777":{"nm":"प्रोफ़ाइल शूट बुकिंग शीट","de":"लेंस के सामने खड़े होने की तारीख़ स्पष्ट अक्षरों में लिखी एक शीट। सबसे अच्छा चेहरा धीरे-धीरे तैयार करने की समय-सारणी। जैसे-जैसे ख़ाने भरते जाते हैं, दर्पण के सामने बिताई जाने वाली रातें भी लंबी होती जाती हैं।"},"ICON-1778":{"nm":"फ़ैन क्लब सदस्यता पर्ची","de":"नाम और मन को एक पंक्ति में लिखकर संकोच से बढ़ाया गया प्रवेश-कागज़। पसंद करने की बात कहना हमेशा कठिन होता है, पर यह एक पर्ची उस बात को उसकी जगह स्पष्ट रूप से लिख देती है। साथ रहने का पहला हस्ताक्षर।"},"ICON-1779":{"nm":"डेब्यू उपहार जाँच शीट","de":"पाने वाले को याद करते हुए एक-एक करके जाँचता हाथ। कोना कहीं टूटा तो नहीं, मन कहीं छूट तो नहीं गया। उपहार, सौंपे जाने से पहले ही, एक बार प्रेम पाकर अपनी यात्रा शुरू कर देता है।"},"ICON-1780":{"nm":"मंच समापन चिह्न","de":"पर्दा गिरने से ठीक पहले, आख़िरी मुद्रा जहाँ ठहरती है उस जगह रखा गया चिह्न। यह अंत की सूचना नहीं, बल्कि अंत को सुंदरता से बाँधने वाला एक छोटा बिंदु है। अच्छी तरह बंद हुआ मंच ही अगला मंच खोलता है।"},"ICON-1781":{"nm":"इंटरव्यू प्रतीक्षा पिन","de":"प्रश्न शुरू होने से पहले की ख़ामोशी को चुपचाप थामे रखने वाली पिन। दिमाग़ में उत्तर चुनने की छोटी-सी ख़ामोशी के दौरान, यह छोटा चिह्न उसकी जगह स्नेह से कह देता है, \"अभी नहीं, बस कुछ ही देर में।\""},"ICON-1782":{"nm":"डेब्यू स्मृति-चिह्न लिफ़ाफ़ा","de":"यात्रा पर निकलने वाले के हाथ में लिफ़ाफ़े सहित बहुमूल्य पत्र थमा देने वाले पुराने मन की तरह, पहले मंच का रिकॉर्ड सहेजकर रखने वाली एक परत। बहुत दिनों बाद खोलने के दिन, उस दिन की कँपकँपी भी साथ में उमड़कर बाहर आ जाती है।"},"ICON-1783":{"nm":"वोकल श्वास स्ट्रॉ","de":"पतली नली के सिरे से साँस को लंबी, एक ही धार में बाहर भेजने का अभ्यास। गाना अंततः अच्छी तरह साधी हुई साँस ही है, यह छोटा स्ट्रॉ हर सुबह चुपचाप बता देता है। ध्वनि से पहले हवा।"},"ICON-1784":{"nm":"लय अभ्यास क्लिक चिप","de":"टिक, टिक, टिक—दुनिया का सबसे ईमानदार दोस्त। तेज़ होने पर थाम लेता है, धीमे होने पर पीठ पर धकेल देता है। लय को शरीर में बसाना इस मज़बूत चिप के साथ हुई एक लंबी बातचीत जैसा है।"},"ICON-1785":{"nm":"नृत्य-रेखा जाँच रिबन","de":"उँगलियाँ कहाँ रुकती हैं, कंधे कहाँ खुलते हैं—एक रिबन से गति की रेखा को चुपचाप जाँचा जाता है। अच्छी तरह खींची गई नृत्य-रेखा दर्शकों की नज़र से परे भी सीधी और सलीक़ेदार बनी रहती है।"},"ICON-1786":{"nm":"भाव-भंगिमा फ़ीडबैक कार्ड","de":"हँसना भी सीखा जाता है, यह कहावत। आँखों के कोण और होंठों के किनारे की ऊँचाई को क्रम से लिखा गया एक पन्ना। दर्पण जो भाव नहीं बता पाया, वह इस कार्ड द्वारा स्नेह से बता दिया जाता है।"},"ICON-1787":{"nm":"रैप फ़्लो मेमो","de":"\"यहाँ थोड़ा रुको, वहाँ उड़ेल दो\"—शब्दों की धारा को पहले से खींचा गया मेमो। जितना तेज़ हिस्सा, उतना स्पष्ट साँस का मार्ग होना चाहिए। बहते हुए खींचे गए तीरों में एक पद की लय जीवंत साँस लेती है।"},"ICON-1788":{"nm":"स्वर तापमान स्टिकर","de":"आवाज़ के भी गर्म दिन और ठंडे दिन होते हैं। आज की बनावट को रंग चुनकर लगाया गया एक छोटा चिह्न। गर्म होकर फिर ठंडा होकर, ध्वनि हर दिन थोड़े अलग तापमान पर जागती है।"},"ICON-1789":{"nm":"विश्राम दिनचर्या टोकन","de":"अच्छी तरह आराम करना भी एक हुनर है, यह कहते हुए हाथ में थमाया गया एक सिक्का। इसे बढ़ाओ तो बिना अपराध-बोध के कुछ देर रुक सकते हो। लगातार दौड़ते आए व्यक्ति के लिए, रुकना ही सबसे साहसी चुनाव है।"},"ICON-1790":{"nm":"विकास लक्ष्य पिन","de":"\"चलो यहाँ तक पहुँचने की कोशिश करते हैं\" कहते हुए ठीक-ठीक गाड़ी गई एक छोटी पिन। छूने जैसा पास दिखते हुए भी दूर लगे, फिर भी हर दिन एक क़दम उस दिशा में बढ़ते जाते हैं। लक्ष्य मानो दूर से इशारा करता एक स्नेहिल वादा है।"},"ICON-1791":{"nm":"साप्ताहिक समीक्षा लिफ़ाफ़ा","de":"एक सप्ताह के पसीने और आँसुओं को एक लिफ़ाफ़े में सलीक़े से भरकर सौंप दिया जाता है। जो अच्छा हुआ और जो अधूरा रहा, दोनों साथ-साथ भीतर रहते हैं। इसे खोलना अगले सप्ताह के अपने आप को दिया गया एक छोटा गृहकार्य है।"},"ICON-1792":{"nm":"मंच सजावट पार्ट्स डिब्बा","de":"चमकते मंच के पीछे नामहीन पुर्ज़े बसते हैं। एक पेच, एक कड़ी मिलकर छत पर सितारों को उड़ाते हैं। डिब्बा खोलने पर, भव्यता को चुपचाप थामे रखने वाली छोटी-छोटी लगन से भरा मिलता है।"},"ICON-1793":{"nm":"पोशाक कॉन्सेप्ट बोर्ड","de":"कपड़े के टुकड़े और रंग एक-एक कर चिपकाते हुए, अभी दुनिया में न आया पहनावा पहले से पहन लिया जाता है। बोर्ड पर सबसे पहले पूरा होता मंच का परिधान। कल्पना हमेशा सुई-धागे से एक क़दम आगे चलती है।"},"ICON-1794":{"nm":"रंग-मिलान चिप","de":"एक ही पोशाक भी रोशनी के अनुसार बिल्कुल अलग चेहरा दिखाती है। कौन-सा रंग उस व्यक्ति के साथ सबसे उजला मुस्कुराता है, यह चिप एक-एक कर लगाकर ढूँढ़ा जाता है। मेल-जोल, लंबे समय तक तुलना करने के अंत में हुई एक खोज है।"},"ICON-1795":{"nm":"जूता-फ़ीता नमूना बोर्ड","de":"मंच पर मज़बूत क़दम की ज़िम्मेदारी संयोग से एक छोटा फ़ीता उठाता है। खुल न जाए, फिर भी तंग भी न लगे। कई बनावटें फैलाकर चुनने वाली, सबसे निचली जगह की एक स्नेहिल उलझन।"},"ICON-1796":{"nm":"सहायक-वस्तु जाँच लिफ़ाफ़ा","de":"जितनी चीज़ चमकीली हो, उतना ही एक निशान भी असाधारण रूप से बड़ा दिखता है। लिफ़ाफ़े में रखे गहने को रोशनी में परखते हुए धीरे-धीरे जाँचता हाथ। छोटी चीज़ को अंत तक निहारने वाला मन ही मंच की रक्षा करता है।"},"ICON-1797":{"nm":"हेयर कलर पैच","de":"बालों को नया मौसम पहले से पहनाकर देखने वाला एक छोटा नमूना। एक लट पर चुपके से रंगी हुई रंगत, अगले कॉन्सेप्ट की पहली छवि को चुपचाप इशारे में बता देती है। बदलाव हमेशा हथेली जितनी जगह से ही शुरू होता है।"},"ICON-1798":{"nm":"नेल कॉन्सेप्ट कार्ड","de":"दसों उँगलियों के सिरे पर बनाई जाने वाली छोटी तस्वीर पहले से तय की गई एक शीट। एक इशारे में भी कॉन्सेप्ट धीमे से झलके, इसके लिए सबसे छोटे विवरण तक भी मन से एक कहानी पहनाई जाती है।"},"ICON-1799":{"nm":"स्टाइल परिवर्तन टिकट","de":"\"आज कल से थोड़ा अलग बनकर देखें\"—इस एक पंक्ति को संभव बनाने वाला एक टिकट। बाल हों, कपड़े हों या मिज़ाज, यह टिकट नए रूप की ओर जाने वाला रोमांचक द्वार खोलता है।"},"ICON-1800":{"nm":"साइज़ समायोजन टैग","de":"शरीर पर बिल्कुल फ़िट होने तक घटाई और बढ़ाई जाने वाली जगहें मन से लिखा गया एक टैग। बच्चे के कपड़े एक-एक टाँका सँवारते पुराने हाथों की तरह, यह छोटा-सा समायोजन मंच को एक बित्ता और आरामदायक बना देता है।"},"ICON-1801":{"nm":"थंबनेल रफ़ कार्ड","de":"रंग अभी न छुआ एक पन्ना। खुरदरी पेंसिल-रेखाओं के ऊपर, यह चुपचाप अंदाज़ा लगाता है कि अगला दृश्य कहाँ बहेगा। पूर्णता से कहीं ज़्यादा रोमांचक हमेशा यही अधूरी पहली पंक्ति होती है, यह शांत संपादन कक्ष हमें याद दिलाता है।"},"ICON-1802":{"nm":"शूटिंग सहमति स्टिकर","de":"“क्या यहाँ क़ैद होना ठीक रहेगा?” शब्दों की जगह, सीने पर एक गोल निशान चिपका दिया जाता है। एक छोटा-सा स्टिकर कैमरे और दिल के बीच एक कोमल वादा तय कर देता है।"},"ICON-1803":{"nm":"फ़ोटो-वॉल स्थान पिन","de":"दीवार के एक कोने में गड़ी एक नन्ही पिन। यह पहले से तय करती है कि कौन कहाँ खड़ा होगा। जहाँ भी पिन लगती है, वहाँ एक मुस्कान ठहर जाती है और एक तस्वीर बन जाती है।"},"ICON-1804":{"nm":"कट चयन चिप","de":"सैकड़ों तस्वीरों में से केवल एक की ओर इशारा करती उँगली। जिस पल यह चिप नीचे रखी जाती है, बाकी सहेजे गए भाव भी मानो उसी एक फ़्रेम के लिए जिए हुए लगते हैं। चुनना हमेशा एक ख़ामोश विदाई जैसा लगता है।"},"ICON-1805":{"nm":"बिहाइंड-द-सीन लिफ़ाफ़ा","de":"कैमरे के पीछे जो कुछ घटा, वह यहीं समाया रहता है। मुँह मोड़ते ही हँसी, एनजी शॉट्स और नींद में ली जम्हाइयाँ सब एक साथ सो जाती हैं। मूल फ़ुटेज से भी ज़्यादा प्यारा अक्सर यही भीतर छिपा हिस्सा बन जाता है।"},"ICON-1806":{"nm":"संपादन अनुरोध मेमो","de":"“यहाँ एक सेकंड और, संगीत ज़रा धीमा कर दो।” लाल स्याही से भरी एक पर्ची। किसी की बारीक नज़र वीडियो की साँस को एक ताल आगे-पीछे कर देती है। निखार इन्हीं छोटे-छोटे स्पर्शों पर पनपता है।"},"ICON-1807":{"nm":"अपलोड शेड्यूल टैग","de":"कल सुबह ठीक सात बजे, अपने-आप दुनिया में क़दम रखने वाले वीडियो पर लगा एक छोटा-सा चिह्न। सब सोए हों तब भी वादा जागता रहता है। पहले से तय किया गया समय देर होना जानता ही नहीं।"},"ICON-1808":{"nm":"थंबनेल फ़्रेम कवर","de":"सबसे उम्दा पहले दृश्य को लपेटता एक ढक्कन। यह किनारों को इस तरह सँभालकर मोड़ता है कि उँगलियों के निशान और धूल तक न छू सकें। दिखाए जाने से पहले, पहली छाप कुछ इस तरह जतन से बचाई जाती है।"},"ICON-1809":{"nm":"फ़ुटेज लंबाई चिप","de":"आज कितने मिनट की शूटिंग हुई, यह भाँपती एक नन्ही चिप। लंबा होना बेहतर नहीं, न ही छोटा होना हल्का। सही लंबाई पहचानने वाला मन ही संपादन का पहला बटन है।"},"ICON-1810":{"nm":"चीयर स्लोगन जाँच पत्रक","de":"गला फाड़कर पुकारने से पहले एक बार फिर जाँचा जाने वाला काग़ज़। एक अक्षर भी चूका, तो हज़ारों आवाज़ें बिखर जाती हैं। जयकारे के पीछे, प्रूफ़रीडिंग का एक अनदेखा हाथ पहले ही गुज़र चुका होता है।"},"ICON-1811":{"nm":"फ़ैन-आर्ट सुरक्षा स्लीव","de":"किसी ने रात भर जागकर बनाई एक तस्वीर। इसे मुड़ने से बचाने को एक पारदर्शी घर दिया जाता है। जो दिल से बनाया गया, उसे दिल से ही थामना पड़ता है—मानो यही कहते हुए स्लीव उसे चुपचाप गले लगा लेती है।"},"ICON-1812":{"nm":"फ़ैन-लेटर छँटाई डोरी","de":"ढेर सारी चिट्ठियों को भेजने वाले के हिसाब से करीने से बाँधती डोरी। हर गाँठ में एक दिन की चाहत सलीके से समा जाती है। जवाब न दे पाने पर भी एक भी चिट्ठी न छूटने देने वाला हाथ यहीं है।"},"ICON-1813":{"nm":"गुड्स-अदला-बदली पंजीकरण पत्रक","de":"“मेरी चीज़ से बदलना चाहेंगे कोई?” काँपते दिल से लिखकर बढ़ाया गया एक काग़ज़। एक ही चीज़ पसंद करने की वजह से, पहली बार मिले दो अजनबी थोड़ी देर के लिए दोस्त बन जाते हैं।"},"ICON-1814":{"nm":"सामूहिक चीयर सीट चिप","de":"एक जैसे रंग पहने लोगों के साथ बैठने की जगह तय करती चिप। बिखरे हुए मन जब एक हिस्से में जमा होते हैं, तो पूरा दर्शक-दीर्घा एक विशाल इंसान की तरह गाने लगती है।"},"ICON-1815":{"nm":"जन्मदिन विज्ञापन रसीद","de":"बड़े बोर्ड पर प्यार उड़ेलकर हाथ में थमी एक रसीद। रकम के बग़ल में जो नहीं लिखा जाता, वह है रात भर जुटाई गई लगन। यह काग़ज़ केवल एक इंसान के लिए मनाए गए उत्सव का प्रमाण बनकर रह जाता है।"},"ICON-1816":{"nm":"मैसेज बुक कवर","de":"कई लोगों की हस्तलिपि से बनी किताब को लपेटता आवरण। खोलते ही अलग-अलग लिखावटें एक दिल में तह होकर बिछ जाती हैं। बाहर से सादा, पर भीतर से गर्मजोशी भरी चहल-पहल से भरा हुआ।"},"ICON-1817":{"nm":"फ़ैन क्लब सदस्यता पिन","de":"एक ही नाम पुकारने वालों को ही सौंपी जाने वाली नन्ही पिन। सीने पर लगते ही अकेली पसंद, कई लोगों के साझा वादे में बदल जाती है। अपनेपन का यह गोल आकार होता है।"},"ICON-1818":{"nm":"ऑनलाइन चीयर टोकन","de":"दूर बैठे हाथ स्क्रीन के उस पार हिलाते एक बिंदु प्रकाश। दूरी कितनी भी अथाह हो, ताल एक जैसी ही रहती है। यह प्रमाण है कि अनदेखी जगहों से भी हौसला-अफ़ज़ाई बिना चूके पहुँचती है।"},"ICON-1819":{"nm":"जीर्ण चाबी का टुकड़ा","de":"दाँत टूटा एक धातु का टुकड़ा। अब किसी को याद नहीं कि यह किस दरवाज़े को खोलता था। बंद जगह से भी ज़्यादा देर तक बचती है ऐसी बेकार हो चुकी चाबी की आधी काया।"},"ICON-1820":{"nm":"गुप्त सुरंग नक़्शा","de":"आइवी लताओं के पीछे छुपे रास्ते को उकेरता पुराना काग़ज़। छोटा रास्ता बस जानने वाले ही जानते हैं। खुलते ही, साधारण-सा द्वीप चुपके से अपना चेहरा एक साहसिक मंच में बदल लेता है।"},"ICON-1821":{"nm":"कोड-भेदन कार्ड","de":"गड्डमड्ड बिखरे अक्षरों को उनकी सही जगह लौटाता कार्ड। एक पंक्ति सही बैठते ही अगला रहस्य इशारा करने लगता है। न सुलझने वाली लगती गाँठ भी आख़िर पहले अक्षर से ही खुलती है।"},"ICON-1822":{"nm":"मुहरबंद बक्सा डोरी","de":"मानो कह रही हो मत खोलना, इतनी मज़बूती से बँधी डोरी। गाँठ के भीतर क्या सोया है, यह बस बाँधने वाला ही जानता है। खोलने की चाह और बचाने की चाह, इस एक डोरी में साथ-साथ बँधी हैं।"},"ICON-1823":{"nm":"खंडहर पहेली चिप","de":"पुरानी पत्थर की दीवार से टूटकर गिरा एक नन्हा टुकड़ा। इसे सही जगह जमाते ही, हज़ार साल पहले किसी की कारीगरी उँगलियों में फिर जी उठती है। बिखरे को समेटना, दरअसल समय को फिर से जोड़ना है।"},"ICON-1824":{"nm":"द्वीप किंवदंती संग्रह-पत्र","de":"द्वीप पर भटकती पुरानी कहानियों को हाथ से नकल करके रखा गया काग़ज़। सच है या नहीं, इससे बहुत फ़र्क़ नहीं पड़ता। मुँह-दर-मुँह चली आई कहानी अपने-आप में द्वीप का एक वलय बन जाती है।"},"ICON-1825":{"nm":"छिपा हुआ निशान पत्थर","de":"रास्ते के किनारे यूँ ही रखा-सा एक पत्थर। बस जानने वाली आँख को ही यह चुपचाप दिशा बताता है। जितना गहरा राज़ छुपाना हो, उतना ही सामान्य चेहरा लेकर वह वहाँ खड़ा रहता है।"},"ICON-1826":{"nm":"पहेली लिफ़ाफ़ा","de":"बाहर कुछ भी नहीं लिखा। मुहर तोड़ने से ठीक पहले का यह छोटा-सा पल सबसे रोमांचक होता है। जवाब हाथ में आने तक, हर संभावना अभी भी लिफ़ाफ़े के भीतर ज़िंदा रहती है।"},"ICON-1827":{"nm":"जासूसी आवर्धक टोपी","de":"आवर्धक शीशे के सिरे पर चुपचाप चढ़ा दी जाने वाली नन्ही टोपी। जब झाँका नहीं जा रहा हो, तब लेंस को चुपचाप विश्राम दिया जाता है। अच्छी तरह देखने के लिए पहले अच्छी तरह सँभालना ज़रूरी है—यह पाठ जासूस जल्दी सीख लेता है।"},"ICON-1828":{"nm":"द्वीप-परिक्रमा बस टिकट","de":"द्वीप का एक चक्कर लगाती बस पर चढ़ने का एक टिकट। आख़िरी पड़ाव फिर से शुरुआती बिंदु है। घूम-फिरकर उसी जगह पहुँचने वाले रास्ते पर, नज़ारा हर बार थोड़ा नया दिखता है।"},"ICON-1829":{"nm":"साइकिल किराया टैग","de":"उधार ली गई साइकिल के हैंडल पर लटका एक टैग। लौटाने तक थोड़ी-सी आज़ादी मिली रहती है। हवा को चीरते हुए बीता वह समय ख़त्म होते ही, यह टैग चुपचाप उस वादे को वापस समेट लेता है।"},"ICON-1830":{"nm":"छोटी नाव सवारी टिकट","de":"एक छोटी नाव पर चढ़ने का सवारी टिकट। हिलते डेक पर द्वीप और द्वीप के बीच की दूरी कम हो जाती है। जलमार्ग पार करना हमेशा थोड़ी-सी सिहरन और थोड़ी-सी मितली साथ लेकर आता है।"},"ICON-1831":{"nm":"ठेला पहिया पिन","de":"ठेले के पहिये को मज़बूती से थामे रखती पिन। धातु का यह छोटा-सा टुकड़ा भारी बोझ को लुढ़कते रहने देता है। सबसे कम नज़र आने वाला पुर्ज़ा ही अक्सर सबसे ज़्यादा वज़न चुपचाप सह लेता है।"},"ICON-1832":{"nm":"केबल कार टोकन","de":"हवा को चीरती केबल कार में डाला जाने वाला गोल टोकन। पैर ज़मीन से उठते ही, पूरा द्वीप एक नज़र में समा जाता है। जितना ऊँचा उठते हैं, नज़ारा उतना ही उदार होता जाता है।"},"ICON-1833":{"nm":"गुब्बारा सवारी पट्टी","de":"टोकरी में चढ़ने से पहले कलाई पर बाँधी जाने वाली पट्टी। जैसे-जैसे लौ फैलती है और ज़मीन दूर होती जाती है, दिल भी उतना ही हल्का होता जाता है। उड़ना, मतलब है थोड़ी देर के लिए बोझ उतार देना।"},"ICON-1834":{"nm":"वॉटर-टैक्सी बुलावा चिप","de":"पानी पर दौड़ती टैक्सी को बुलाने वाली नन्ही चिप। हाथ उठाते ही, धारा को चीरती नाव क़रीब आ जाती है। जहाँ रास्ता नहीं होता वहाँ भी रास्ता बनाना, आख़िरकार पहले पुकारने वाले का साहस ही होता है।"},"ICON-1835":{"nm":"पर्वत-मार्ग प्रवेश पास","de":"पहाड़ में घुसने के पहले फाटक पर सौंपा गया पास। यहाँ से आगे, पैर की नोक ही रास्ता तय करती है। चोटी भले दूर हो, पर फाटक पार करने वाले को ही वह नज़ारा वादे में मिलता है।"},"ICON-1836":{"nm":"बंदरगाह लॉकर चाबी","de":"घाट किनारे लॉकर खोलने वाली नन्ही चाबी। सामान सौंपकर हल्के हाथों से समंदर को निहारा जाता है। थोड़ी देर के लिए बोझ रखने की जगह होना, दूर निकल जाने का साहस उधार देना है।"},"ICON-1837":{"nm":"अचार बरनी ढक्कन","de":"खट्टी चीज़ों को क़ैद रखने वाला बरनी का ढक्कन। कसकर बंद करने पर गर्मी की खीरा सर्दी तक अपनी कुरकुराहट सँभाले रहती है। समय को मात देने का राज़, अच्छी तरह बंद करने से ही शुरू होता है।"},"ICON-1838":{"nm":"सुखाने की जाली लेबल","de":"छलनी पर फैलाकर सुखाई जाने वाली चीज़ों पर लगा नाम-पत्र। क्या कब फैलाया गया, यह लिख देने से इंतज़ार बिखरता नहीं। धूप और हवा के समय में भी, बारी नाम की चीज़ ज़रूरी होती है।"},"ICON-1839":{"nm":"धुआँकित चिप लिफ़ाफ़ा","de":"सुगंधित लकड़ी के टुकड़े रखने वाला लिफ़ाफ़ा। मुँह खोलते ही अलाव-सी महक पहले नाक तक पहुँच जाती है। धुएँ से गहरा हुआ स्वाद, इंतज़ार करना जानने वाले के लिए ही धीरे-धीरे खुलता है।"},"ICON-1840":{"nm":"परिरक्षित खाद्य स्टिकर","de":"पूरा साल अच्छे से गुज़रे, यह चाहते हुए मर्तबान पर लगाया गया स्टिकर। बनाने की तारीख़ और लगन उस पर लिखी जाती है। लंबे समय तक रखकर खाए जाने वाले भोजन के साथ हमेशा उस दिन के हाथ-स्वाद को याद रखने की एक छोटी-सी चिट्ठी चली आती है।"},"ICON-1841":{"nm":"किण्वन घड़ी टैग","de":"किण्वन को घड़ी पर भरोसा नहीं। यह समय मिनट की सुई से नहीं, महक से नापता है। खट्टी गंध नाक तक पहुँचते ही, टैग चुपचाप सिर हिलाकर कहता है, ‘अब हो गया।’ इंतज़ार की भी अपनी-अपनी नाप होती है।"},"ICON-1842":{"nm":"फ्रिज ख़ाना छँटाई पिन","de":"फ्रिज के भीतर का नन्हा यातायात-सिपाही यहीं है। सब्ज़ियाँ ऊपर, नाश्ता-भोजन नीचे, कल का बचा सामने की क़तार में। एक पिन लगा दो, तो दरवाज़ा खोलने पर भटकता हाथ पल भर में रास्ता जान जाता है।"},"ICON-1843":{"nm":"टिफ़िन गरमाई पट्टी","de":"माँ ने टिफ़िन के इर्द-गिर्द एक पट्टी बाँध दी, ताकि दोपहर तक गर्मी भाग न जाए। पट्टी खोलने पर, भाप से धुंधले ढक्कन के नीचे सुबह की लगन अब भी गरम पड़ी मेरा इंतज़ार कर रही थी।"},"ICON-1844":{"nm":"सॉस पकाई बोतल","de":"अच्छा मसाला कभी जल्दबाज़ी नहीं करता। सोया सॉस और लहसुन को एक-दूसरे में रचने-बसने का समय चुपचाप देना ही उसका काम है। बोतल के अँधेरे में स्वाद धीरे-धीरे गहराता है, और मर्तबान की धीमी बुद्धि एक छोटी बोतल में जा बसती है।"},"ICON-1845":{"nm":"मौसमी जैम लेबल","de":"बसंत में स्ट्रॉबेरी, गर्मी में खुबानी, पतझड़ में अंजीर। एक लेबल मौसम को मर्तबान पर साफ़-साफ़ लिख देता है। कड़ाके की सर्दी में ढक्कन खोलो, तो बीती धूप एक-एक चम्मच धीरे-धीरे पिघलकर बाहर आती है।"},"ICON-1846":{"nm":"संग्रह-दर बैज बोर्ड","de":"कितना जमा किया, यह गिनने की ज़हमत लेने की ज़रूरत नहीं—बैज बोर्ड यह ख़ुद बताकर गर्व करता है। एक-एक ख़ाली जगह भरते ही कंधे ख़ुद-ब-ख़ुद ऊँचे हो जाते हैं—यह अंक नहीं, पंजों के बल चला गया एक पदचिह्न है।"},"ICON-1847":{"nm":"अनखोजी जगह कार्ड","de":"अभी तक न मिली एक जगह। कार्ड पर छाया सिर्फ़ धुंधली रूपरेखा में एक वादा सौंपती है। ख़ाली होना, यानी जल्द भर जाने की बात होना, इसलिए उत्सुकता हमेशा प्रश्न-चिह्न का रूप लेकर तुम्हारा इंतज़ार करती है।"},"ICON-1848":{"nm":"संकलन पूर्णता मुहर","de":"आख़िरी ख़ाने पर मुहर के “धम्म” से बैठने की वह आवाज़। संकलन बंद करते हुए हथेली खोलकर देखो, तो लाल स्याही की एक बूँद पूर्णता के तमग़े-सी चिपकी मिलती है। आख़िर तक जमा करने वाले को ही मिलने वाली वह गहरी राहत।"},"ICON-1849":{"nm":"दुर्लभता रंग चिप","de":"आकार एक-सा हो भी, तो रंग बदलते ही कहानी बदल जाती है। एक चिप ही साधारण और अनमोल के बीच चुपचाप रेखा खींच देती है। संग्रहकर्ता की नज़र हमेशा उस बारीक रंग-भेद के आगे देर तक ठहरी रहती है।"},"ICON-1850":{"nm":"दोहराव संग्रह विनिमय पत्र","de":"फिर वही निकला, फिर से। पहले से रखी चीज़ तीसरी बार उठाने वाले दिन, यह विनिमय-पत्र चुपचाप हाथ बढ़ाता है। जैसे यह कोमल दिलासा हो कि दोहराव को भी फेंके बिना गले लगाया जाए तो एक दिन वह कुछ अनमोल बनकर लौटता है।"},"ICON-1851":{"nm":"संग्रह बक्सा नंबर पट्टिका","de":"हर बक्से पर एक नंबर लगा दो, तो गोदाम एक छोटी-सी लाइब्रेरी बन जाता है। 17 नंबर में बसंत में जमा किया सामान, 23 में समंदर किनारे उठाया हुआ। मैं बिखरी यादों को एक-एक पंक्ति सजाती एक शांत अनुक्रमणिका हूँ।"},"ICON-1852":{"nm":"प्रदर्शन स्थान मार्गदर्शिका","de":"प्रदर्शन का आधा हिस्सा जगह ही तय करती है। ऊँची चीज़ें पीछे, चमकती चीज़ें बीच में। मार्गदर्शिका के सहारे हाथों से चीज़ें सरकाते जाओ, तो अस्त-व्यस्त शेल्फ़ जल्द ही एक छोटी कला-वीथिका की तरह चुपचाप साँस सँभाल लेती है।"},"ICON-1853":{"nm":"संग्रह धूल-झाड़न","de":"जितनी प्यारी चीज़, उतनी ही जल्दी उस पर धूल जम जाती है। मुलायम ब्रश की नोक से धीरे-धीरे, देर से न देख पाने की मलाल भी साथ में झाड़ दी जाती है। साफ़ करते-करते सोई हुई यादें भी पल भर के लिए फिर चमक उठती हैं।"},"ICON-1854":{"nm":"भंडारण सीमा विस्तार पत्र","de":"जमा करते-करते जगह कम पड़ जाना भी एक ख़ुशनुमा उलझन बन जाती है। एक शेल्फ़ और बढ़ते देख चुपचाप महसूस होने वाला सुकून—यह लालच नहीं, बल्कि इस बात का सबूत है कि पसंद की चीज़ें उतनी ही ज़्यादा हैं।"},"ICON-1855":{"nm":"मित्र आमंत्रण कोड कार्ड","de":"यह कोड सौंपना “साथ खेलें” कहने वाला सबसे प्यारा न्यौता है। कुछ अंकों में समाया दिल, कोड पाने वाला दोस्त जब द्वीप पर पहला क़दम रखता है, तभी दोनों की अपनी कहानी शुरू होती है।"},"ICON-1856":{"nm":"साझा गोदाम चाबी","de":"गोदाम का दरवाज़ा कभी अकेले नहीं खुलता। तुम्हारे और मेरे, दोनों के हाथ मिलें तब कहीं ताला घूमता है। साझा जगह में साझा वादा हमेशा चाबी के आकार में लटका रहता है।"},"ICON-1857":{"nm":"खोया-पाया सूचना टैग","de":"खोई हुई चीज़ भी किसी के लिए अनमोल होती है। “यह यहाँ है” यह एक पंक्ति लिखकर टाँग देना—यह टैग थोड़ी देर के लिए भटके दिल और मालिक के बीच फिर से चुपचाप जोड़ता एक नन्हा धागा है।"},"ICON-1858":{"nm":"सहायता याचना ध्वज","de":"मदद माँगना कमज़ोरी नहीं, साहस है। ध्वज ऊपर उठते ही कहीं से कोई दौड़ा चला आता है। इस द्वीप पर सबसे तेज़ी से फैलने वाली चीज़ अफ़वाह नहीं, बल्कि एक-दूसरे की ओर बढ़ते हाथ हैं।"},"ICON-1859":{"nm":"आपातकालीन संपर्क कंगन","de":"कलाई पर बँधी एक छोटी-सी तसल्ली। कुछ भी हो जाए, यहाँ लिखा नंबर सबसे पहले दौड़ा चला आता है। आम दिनों में भुला दिया जाने वाला, पर ज़रूरत के पल में सबसे भरोसेमंद बन जाने वाला एक शांत साथी।"},"ICON-1860":{"nm":"कार्य-बँटवारा चिप","de":"कौन बाज़ार जाए और कौन खाना बनाए—चिप बाँट लो तो झगड़े की गुंजाइश ही नहीं रहती। साथ मिलकर कुछ बनाने का पहला क़दम, अपना-अपना हिस्सा प्यार से आपस में तय करने से ही शुरू होता है।"},"ICON-1861":{"nm":"सहयोग निर्माण पत्रक","de":"अकेले जिसे शुरू करने की हिम्मत भी न होती, कई लोग मिलकर उसे जादू की तरह संभव बना देते हैं। पत्रक पर एक-एक नाम भरता जाए, ख़ाली जगह घटती जाए और हँसी बढ़ती जाए। सहयोग ख़ानों के बीच की जगह में ही चुपचाप पनपता है।"},"ICON-1862":{"nm":"शिष्टाचार कार्ड","de":"किसी और के घर में क़दम रखते ही पंजों की नोक से सतर्कता जागती है। कार्ड पर लिखे भारी-भरकम नियम नहीं, बस “जूते करीने से रखो, पहले नमस्ते करो” जैसे छोटे-छोटे गर्मजोश वादे ही हैं।"},"ICON-1863":{"nm":"पार्टी विदाई घंटी","de":"ख़ुशी को भी अंत चाहिए, तभी अगली का इंतज़ार रहता है। घंटी “टन्न” बजते ही सब उदास चेहरे लिए धीरे-धीरे सामान समेटने लगते हैं। अच्छी तरह विदा लेना जानने वाली पार्टी दिल में सबसे लंबे समय तक रहती है।"},"ICON-1864":{"nm":"गद्दा कोना पट्टी","de":"चादर कितनी भी करीने से बिछाओ, कोने ज़रूर उठ जाते हैं। चारों कोनों को मज़बूती से थामे पट्टी की बदौलत, हर सुबह बिस्तर होटल के कमरे जैसा सलीके से आँख खोलता है।"},"ICON-1865":{"nm":"रज़ाई कॉलर बटन डोरी","de":"मैं रज़ाई का कॉलर थामे रखने वाली बटन डोरी हूँ। रात भर कितनी भी करवटें बदलो, मैं कॉलर को भागने न देकर कसकर पकड़े रहती हूँ। सोकर उठने पर बिना एक भी सिलवट वाली रज़ाई—यही मेरी रातभर की चौकीदारी का फल है।"},"ICON-1866":{"nm":"टॉपर स्थिरक क्लिप","de":"टॉपर मौक़ा मिलते ही धीरे से खिसक जाना चाहता है। हर बार क्लिप कोने को कसकर काटकर उसकी जगह बचा लेती है। किसी अनदेखे कोने से बिस्तर को व्यवस्थित रखने वाली एक ख़ामोश ज़िद्दी चीज़।"},"ICON-1867":{"nm":"चादर सिलवट सुधारक","de":"रात भर में चादर पर पड़ी बारीक सिलवटें किसी तरह दिल की सिलवटों जैसी लगती हैं। सुधारक से एक बार सहलाते ही चिकना हो जाने वाले कपड़े की तरह, काश उलझा हुआ दिन भी उतनी ही कोमलता से प्रेस हो पाता।"},"ICON-1868":{"nm":"गद्दा वायु-संचार आधार","de":"गद्दे को भी साँस लेने की जगह चाहिए। आधार नीचे से हवा का रास्ता खोल दे, तो नमी बाहर निकल जाती है और सूखापन भीतर तक पहुँचता है। अच्छी नींद पीठ को सहारा देती उसी हवा से चुपचाप शुरू होती है।"},"ICON-1869":{"nm":"रज़ाई कवर ज़िप फ़्लैप","de":"रज़ाई का कवर बदलते समय रुई के बार-बार बाहर झाँकने की वह आधी रात की अफ़रा-तफ़री। ज़िप को फ़्लैप से एक बार ढक दो, तो सोते समय पैर उलझकर जागने की नौबत ही नहीं आती। एक छोटे-से फ़्लैप का लाया गया इतना बड़ा सुकून।"},"ICON-1870":{"nm":"गद्दी-गुच्छ रोधी पैड","de":"तकिये की रुई पता नहीं कब एक तरफ़ जमा होकर एक छोटी पहाड़ी बना देती है। पैड चुपचाप बीच की जगह सँभाले रखे, तो चपटापन अंत तक बना रहता है। इसकी बदौलत हर रात बिना चूके एक नई जैसी मुलायमियत लौट आती है।"},"ICON-1871":{"nm":"बेड शीट लोचदार हुक","de":"चादर हमेशा धीरे-धीरे एक तरफ़ से उतरने की कोशिश करती रहती है। कोनों में हुक लगाकर उसे कसकर खींच दो, तो रात भर करवट बदलने पर भी वह टस से मस नहीं होती। यह कसावट ही चुपचाप गहरी नींद की नींव बन जाती है।"},"ICON-1872":{"nm":"तकिए का ग़िलाफ़ बदलाव टैग","de":"आज तकिए का ग़िलाफ़ धोया था या नहीं, यह अचानक भूल जाने पर एक टैग साफ़-साफ़ जवाब दे देता है। सोते-सोते फिर सो जाने में बार-बार भुला दिया गया कार्यक्रम, यह छोटा-सा निशान बड़ी लगन से याद रखता है।"},"ICON-1873":{"nm":"स्वप्न-डायरी बुकमार्क","de":"जागते ही उँगलियों के बीच से बिखर जाने वाले सपने को, बुकमार्क अपने रखे गए उस पन्ने पर थाम लेता है। खोलते ही, कल रात का समंदर और आकाश ज्यों का त्यों—नींद और लेखनी के बीच धीरे से रखा गया एक नन्हा पुल।"},"ICON-1874":{"nm":"श्वेत-ध्वनि गोल पत्थर","de":"बहुत ज़्यादा शांत रात अक्सर नींद उड़ा देती है। कंकड़ जब सरसराहट-सी, हल्की बारिश जैसी आवाज़ छोड़ता है, तो दिल उस लय पर धीरे-धीरे शांत होता जाता है। ख़ामोशी को धीरे से थपथपाता एक नन्हा पत्थर।"},"ICON-1875":{"nm":"तापमान-संवेदी निद्रा चिप","de":"सोते समय माथा गरम है या पैर की उँगलियाँ ठंडी, चिप बग़ल में चुपचाप नज़र रखे रहती है। शरीर के लिए बिल्कुल सही तापमान चुपचाप ढूँढ़ने वाले इस रात्रि-रक्षक की बदौलत, भोर तक बिना जागे नींद बहती रहती है।"},"ICON-1876":{"nm":"ब्लैकआउट पर्दा क्लिप","de":"सुबह की धूप इतनी मेहनती है कि बार-बार पर्दे की दरार से घुस आती है। क्लिप से दोनों किनारे कसकर पकड़ दो, तो कमरा फिर से आधी रात जैसा काला हो जाता है। एक बार और सोने का यह भरोसेमंद साथी।"},"ICON-1877":{"nm":"चंद्रप्रकाश प्रक्षेपण स्टैंड","de":"बत्ती बुझाते ही छत पर चाँद उग आता है। स्टैंड से फेंकी गई हल्की रोशनी कमरे को एक छोटा रात-आकाश बना देती है। चाँद को निहारते-निहारते सो जाने वाला वह मन, ज्यों का त्यों तकिए के पास रख दिया जाता है।"},"ICON-1878":{"nm":"निद्रा-सुगंध थैली धारक","de":"लैवेंडर और घास की महक भरी एक थैली तकिए के पास हौले-हौले झूलती है। नाक तक पहुँचती उस ख़ुशबू के साथ कंधे धीरे-धीरे ढीले पड़ते हैं, और एक थैली तकिये से पहले ही नींद को बुला लेती है।"},"ICON-1879":{"nm":"लोरी संगीत-बक्सा पिन","de":"चाबी को धीरे से घुमाओ, एक छोटी धुन निकल आती है। पिन की नोक से घूमकर आती लोरी, दादी की पीठ थपथपाने वाली उसी ताल से मिलती-जुलती है। एक-एक सुर पलकों को धीरे-धीरे भारी करता जाता है।"},"ICON-1880":{"nm":"नमी पौधा कप","de":"मैं मिट्टी की बजाय साफ़ पानी में पौधे उगाने वाला कप हूँ। पानी में तैरती महीन जड़ों को निहारते रहो, तो कमरे की हवा भी ज़रा और नम हो जाती है। मेज़ पर ठहरा एक छोटा-सा हरा कुआँ।"},"ICON-1881":{"nm":"स्वप्न-कण संग्रह बोतल","de":"नींद में बहा सपना बेआकार होता है, जागते ही उँगलियों के बीच से रिस जाता है। ग़ायब होने वाले उस एक टुकड़े को ढक्कन से चुपचाप रोककर सुबह तक थामे रखना—याद रखने की चाह ऐसी ही छोटी जगह से शुरू होती है।"},"ICON-1882":{"nm":"शीश-तकिया चश्मा ट्रे","de":"चश्मा उतारकर रखते ही, अजीब तरह से दिनभर की थकान भी साथ में उतर जाती है। तकिए के पास की यह छोटी-सी जगह उसी एक हरकत को थामने के लिए वहाँ रखी है। सोने से पहले दुनिया को चुपचाप धुँधला कर देने वाली एक ट्रे।"},"ICON-1883":{"nm":"साइड-टेबल कोस्टर रिंग","de":"पानी का गिलास छोड़ जाता एक गोल निशान भले मामूली लगे, पर साइड-टेबल की लकड़ी के लिए वह एक दाग़ बन जाता है। इसे रोकने के लिए लगाई गई एक नन्ही रिंग। जतन करने वाला मन हमेशा इन्हीं अनदेखी जगहों में चुपचाप काम करता है।"},"ICON-1884":{"nm":"रज़ाई तह-निर्धारक","de":"रज़ाई को चौकोर सलीके से तह करने में भी एक कायदा होता है। कोना पकड़ने वाले इस औज़ार के सहारे किनारे मिलाओ, तो उलझा हुआ मन भी एक बार सुलझ जाता है। सजी हुई जगह दिन शुरू करने का सबसे सलीकेदार अभिवादन है।"},"ICON-1885":{"nm":"शीश-तकिया चार्जिंग तार हुक","de":"चार्जिंग तार के रात भर धीरे-धीरे ज़मीन पर फिसल जाने से नफ़रत होने के कारण तकिए के पास लटकाया गया एक हुक। सोते समय चुपचाप ऊर्जा से भरता तार, सुबह भरा-पूरा होकर उँगलियों का इंतज़ार करता है।"},"ICON-1886":{"nm":"शीश-तकिया नाश्ता टोकरी","de":"हाथ की पहुँच में पसंदीदा नाश्ता जमा करती एक टोकरी। देर रात भूख लगने का पहले से अंदाज़ा लगाकर की गई एक कोमल तैयारी। अँधेरे में एक दाना उठाकर चबाने की सरसराहट अकारण ही अपनी-सी लगती है।"},"ICON-1887":{"nm":"शयन-पुस्तक धारक पंख","de":"नींद हावी हो भी जाए, तो भी पढ़ी जा रही पंक्ति न खोए, इसके लिए खुले पन्ने को चुपचाप सहारा देने वाला एक पंख। आँखें बंद होने से ठीक पहले बंद किया गया वह एक पन्ना, कल रात उसी जगह पर तुम्हारा इंतज़ार करता है।"},"ICON-1888":{"nm":"शीश-तकिया अलार्म पत्थर आधार","de":"सुबह जगाने वाली अलार्म घड़ी को भी बिना डगमगाए अपनी जगह चाहिए। गोल पत्थर आधार भारी-भरकम भार सँभाल लेता है, और भोर आते ही भी न फिसलने वाले वादे की तरह वह जगह थामे रहता है।"},"ICON-1889":{"nm":"निद्रा-पट्टी टाँगने की कील","de":"रात भर रोशनी रोकने वाली आँख-पट्टी को दिन में साँस लेने देने के लिए टाँगा गया एक कील। अपना काम पूरा कर चुके कपड़े को सूखी जगह देना—छोटी देखभाल इस तरह बिना किसी दाग़ के रिस आती है।"},"ICON-1890":{"nm":"शीश-तकिया टॉर्च क्लिप","de":"आधी रात को ज़रूरी नन्ही रोशनी को मनचाही दिशा में थामे रखती क्लिप। बिस्तर के किनारे टॉर्च दबाकर रख दो, तो अँधेरे में टटोलता हाथ बहुत सहज हो जाता है। रोशनी की दिशा तय करने वाला एक स्पर्श।"},"ICON-1891":{"nm":"विभाजक पर्दा बंधनी डोरी","de":"साझा जगह को बाँटने वाले पर्दे को थामने वाली बंधनी डोरी। यह महज़ एक पतली चादर है, पर उसके उस पार किसी की निजी रात है। साथ रहने वाले कमरे में एक-दूसरे की नींद बचाने वाली एक कोमल सीमा-रेखा।"},"ICON-1892":{"nm":"साझा प्लग बँटवारा तख़्ता","de":"एक ही सॉकेट को कई लोगों में बाँटकर इस्तेमाल कराने के लिए बना तख़्ता। यह बिजली को बराबर बाँटकर किसी की भी रात अँधेरी नहीं होने देता। साथ रहना दरअसल इन्हीं छोटी चीज़ों को बाँटने से शुरू होता है।"},"ICON-1893":{"nm":"रोशनी-मंदन अनुरोध पत्थर","de":"रोशनी बहुत तेज़ हो, तो शब्दों की जगह चुपके से एक पत्थर बढ़ा दिया जाता है। “थोड़ा कम कर दोगे?” यह एक वाक्य यह छोटी-सी चीज़ ख़ुद-ब-ख़ुद कह देती है। साझा कमरे की सबसे नरम गुज़ारिश।"},"ICON-1894":{"nm":"जागने का समय अनुबंध टोकन","de":"पहले जागने वाले की हथेली पर सौंपा जाने वाला एक नन्हा टोकन। कौन ज़्यादा भोर की नींद ले और कौन पहले जागे, यह टोकन बिना झगड़े के तय कर देता है। बारी-बारी छूट देने का क्रम उँगलियों की नोक से तय करने वाला मन।"},"ICON-1895":{"nm":"साझा हैंगर नंबर रिंग","de":"कई लोगों की साझा हैंगर पर लगाई गई नंबर रिंग। किसकी जगह कौन-सी है, यह भ्रम न हो, इसलिए एक छोटा-सा अंक चुपचाप व्यवस्था बना देता है। आसानी से गड्डमड्ड हो जाने वाली रोज़मर्रा में खींची गई एक कोमल रेखा।"},"ICON-1896":{"nm":"दो-मंज़िला बिस्तर सीढ़ी टोपी","de":"ऊपरी मंज़िल पर चढ़ने वाले पायदान पर चढ़ाई गई टोपी। नंगे पैर छूने पर न ठंडी लगे न फिसले, इस तरह एक पायदान की सुरक्षा सँभाली जाती है। सीढ़ी के छोर पर यह छोटी-सी देखभाल ऊपर के सपनों को मज़बूती से सँभालती है।"},"ICON-1897":{"nm":"साझा टिशू धारक भुजा","de":"साझा शौचालय के टिशू को टाँगने वाली भुजा-आकार धारक। कोई भी एक हाथ से आसानी से एक पत्ती खींच सके, इस तरह जगह तय की गई है। मामूली लगे भले, पर यह कई लोगों की सुबह को सहजता से जोड़ने वाला स्पर्श है।"},"ICON-1898":{"nm":"एयर फ़्रेशनर बारी चिप","de":"एयर फ़्रेशनर कौन दोबारा भरेगा, यह बारी लिखी हुई एक चिप। हल्की-सी महक की एक लहर भी बारी-बारी ज़िम्मेदारी लेने का वादा है। अच्छी महक यूँ ही नहीं आती, वह किसी की बारी में खिलती है।"},"ICON-1899":{"nm":"साझा नाइट-लाइट हैंडल","de":"कई लोग मिलकर जलाते-बुझाते नाइट-लाइट का हैंडल। सबसे देर तक जागा हाथ ही आख़िर में रोशनी समेटता है। हल्की रोशनी बाँटकर रखने वाला, एक कमरा साझा करने वालों का एक शांत वादा।"},"ICON-1900":{"nm":"सोफ़ा आर्मरेस्ट कप-गड्ढा","de":"सोफ़े के आर्मरेस्ट में खोदी गई गोल गिलास-जगह। हाथ से गिलास पल भर के लिए रख दो तो भी छलकने की चिंता नहीं रहती। आराम की जगह में गिलास रखने की कोई जगह हो, तभी मन आख़िरकार सहज होकर पसर पाता है।"},"ICON-1901":{"nm":"कुशन ज़िप हैंडल","de":"तकिये के गद्दे को खोलने-बंद करने वाली ज़िप पर लगी एक छोटी सी कड़ी। एक ही कड़ी धुलाई बदलने की मेहनत को हल्का कर देती है। दिखाई न देने वाले भीतरी हिस्से तक का ख़याल रखने वाली उंगलियाँ—गृहस्थी की मिठास हमेशा वहीं छिपी रहती है।"},"ICON-1902":{"nm":"सोफ़ा बैकरेस्ट वेज कुशन","de":"बैकरेस्ट की दरार को भरकर कमर को सहारा देने वाला कुशन। देर तक बैठे रहने पर भी पीठ न दुखे, इसलिए खाली जगह को भर देता है। टेक लगाकर बैठते ही शरीर पहले ही पहचान लेता है, \"आह, यही तो है\" वाला आराम।"},"ICON-1903":{"nm":"गद्दी कोना पकड़ बैंड","de":"बैठते ही धीरे-धीरे खिसक जाने वाली गद्दी को कोनों से पकड़कर रखने वाला बैंड। फिसले नहीं, इसलिए एक जगह टिकाए रखता है। सफ़ाई-सुथरापन ऐसी ही छोटी मगर ज़िद्दी पकड़ से शुरू होता है।"},"ICON-1904":{"nm":"कुशन सीवन गार्ड पट्टी","de":"तकिये में सबसे पहले घिसने वाली जगह हमेशा कोने की सिलाई होती है। उस जगह को पहले से लपेटकर फटने से बचाने वाली सुरक्षा पट्टी। लंबे समय तक पास रखने की चाहत, सिलाई जितनी ही मज़बूत होती है।"},"ICON-1905":{"nm":"सोफ़ा दरार रिमोट पॉकेट","de":"कुशनों के बीच बार-बार गुम हो जाने वाले रिमोट को आख़िरकार अपना घर मिल गया। सोफ़े की दरार में टिकाई गई एक छोटी सी जेब। जो खोया समझा जाता था, वह हमेशा वहीं है—यह जानना सोच से कहीं बड़ा सुकून है।"},"ICON-1906":{"nm":"घुटना-कंबल रोल डोरी","de":"घुटनों पर ओढ़ने वाले कंबल को लपेटकर बांधने वाली डोरी। खुला पड़ा रहने पर बिखर जाने वाली गर्माहट को, अगली रात के लिए करीने से समेट देती है। गर्माहट को भी ऐसे संभाल लें, तो कल फिर निकालकर ओढ़ी जा सकती है।"},"ICON-1907":{"nm":"फ़ुटरेस्ट कवर बटन","de":"पैर छूने से सबसे जल्दी घिसने वाले फ़ुटरेस्ट कवर को आसानी से बदलने के लिए बंद करने वाला बटन। टक से लगने वाला वह एक इशारा कपड़े की उम्र बढ़ा देता है। चीज़ों को लंबे समय तक इस्तेमाल करने की चाहत छोटी-छोटी बातों में भी सतर्क रहती है।"},"ICON-1908":{"nm":"सोफ़ा पैर फिसलन कैप","de":"भारी सोफ़ा भी फ़र्श को खरोंचे नहीं, तभी तो सही। चारों पैरों के सिरों पर पहनाया गया मुलायम कवर, लकड़ी के फ़र्श को दबे पाँव संभालता है। पैरों के सिरे तक सावधान रहने वाला फ़र्नीचर किसी तरह और भी अपना लगता है।"},"ICON-1909":{"nm":"रिमोट स्टैंड","de":"इधर-उधर लुढ़ककर बिखर जाने वाले रिमोटों को एक जगह करीने से खड़ा रखने वाला स्टैंड। लंबी और छोटी छड़ें जब कतार में सीधी खड़ी होती हैं, बस इतने भर से कमरे की हवा एक सुर शांत हो जाती है।"},"ICON-1910":{"nm":"गेम पैड चार्जिंग हुक","de":"खेल का एक राउंड जमकर खेलने के बाद गेम पैड को टांगकर चार्ज करने वाला हुक। लटककर चुपचाप ऊर्जा भरते समय, हाथ भी थोड़ी देर आराम कर लेते हैं। यह छोटा सा विराम अगले राउंड को मज़बूती से तैयार करता है।"},"ICON-1911":{"nm":"बोर्ड गेम मोहरा थैली","de":"रंग-बिरंगे मोहरों को रखने वाली एक छोटी थैली। एक थैले के भीतर अगले राउंड का इंतज़ार करते टुकड़े, हिलाने पर खनकते हैं। उस आवाज़ में \"एक राउंड और?\" वाली सिहरन सबसे पहले जाग उठती है।"},"ICON-1912":{"nm":"पासा फेंकने की थाली","de":"पासे फेंकने के लिए बनी विशेष थाली। मेज़ से बाहर उछलकर गुम हो जाने वाली किस्मत को, इसका किनारा भीतर ही रोक लेता है। घूमकर रुकने के उस छोटे से पल में, सबकी साँस एक साथ पल भर को थम जाती है।"},"ICON-1913":{"nm":"कार्ड डेक बैंड","de":"ताश की एक गड्डी को बिखरने से रोकने वाला बैंड। फेंटे जाने से पहले तक वह क्रम ही एक वादा होता है। बैंड खोलकर पत्ते फैलाने के उस इशारे से, एक राउंड की कहानी आख़िरकार शुरू होती है।"},"ICON-1914":{"nm":"कंसोल केबल क्लिप","de":"कंसोल के पीछे उलझे तारों को पकड़कर करीने से सुलझाने वाली क्लिप। मुश्किल से दिखने वाली जगह की अव्यवस्था को चुपचाप सँवारती है। सफ़ाई हमेशा ऐसे ही पीठ पीछे, ख़ामोशी से पूरी होती है।"},"ICON-1915":{"nm":"स्कोर डायल","de":"अंक दिखाने के लिए घुमाई जाने वाली एक छोटी डायल। टक, हर खाने पर अंक बढ़ते ही जयकारे साथ चलते हैं। मन में गिनती न भी करें, तो उंगलियाँ पहले ही उस दिन की जीत-हार याद रख लेती हैं।"},"ICON-1916":{"nm":"बोर्ड स्टैंडिंग बेस","de":"बोर्ड को तिरछा खड़ा करके, बैठे सभी लोगों को एक नज़र में पूरा बोर्ड दिखाने वाला कोण बनाए रखने वाला आधार। किसी को गर्दन न बढ़ानी पड़े, इसलिए यह सबके लिए एक जैसा नज़ारा चुपचाप बिछाता है।"},"ICON-1917":{"nm":"बारी तय करने वाला ड्रॉ कप","de":"खेल की बारी तय करने के लिए हाथ डालकर निकाली जाने वाली नली। टटोलकर पकड़ी एक छड़ी पहली बारी तय कर देती है। किस्मत पर थोड़ा भरोसा करने के उस छोटे पल में, गोल नली के भीतर सब मिलकर धड़कते हैं।"},"ICON-1918":{"nm":"नाश्ता बाँट थाली","de":"नाश्ते को किस्म के हिसाब से बाँटकर रखने वाली खानेदार थाली। जगह अलग होने से हाथ टकराए बिना, पसंद की चीज़ चुनकर उठाई जा सकती है। बाँटकर खाने वालों का ख़याल हर खाने में समाया रहता है।"},"ICON-1919":{"nm":"चायदानी कोज़ी","de":"चायदानी के कंधों को लपेटकर गर्माहट बचाए रखने वाला आवरण। चाय धीरे-धीरे उतरते समय ठंडी न हो, इसलिए उसे लपेट देता है। एक गर्म प्याली को अंत तक गर्म परोसने की चाहत, उंगलियों के इस स्पर्श में बसी है।"},"ICON-1920":{"nm":"टी बैग रेस्ट","de":"पूरी तरह उतर चुकी चाय की पत्ती को उठाकर थोड़ी देर टिकाए रखने वाला आधार। आख़िरी बूँद तक बिना गिरे संभाल लेता है। अपना काम पूरा कर चुकी पत्ती को भी एक करीना अंत देने वाली जगह।"},"ICON-1921":{"nm":"साझा मग पहचान रिंग","de":"पैंट्री की शेल्फ़ पर एक जैसे छह मग। किसका है यह पूछने के बजाय रंग-बिरंगी रिंगें पहना दीं। एक छोटा सा निशान अलग-अलग स्वाद वाले छह लोगों को, एक ही मेज़ पर चुपचाप बाँध देता है।"},"ICON-1922":{"nm":"पॉपकॉर्न शेयरिंग टोकरी","de":"हाथ से हाथ गुज़रते समय ख़ुशबूदार भाप सबसे पहले स्वागत करती है। मुट्ठी भर-भरकर निकालने पर भी अजीब तरह से न घटे कुछ, तो वह साथ बैठकर बाँटी गई शाम का मन ही होगा।"},"ICON-1923":{"nm":"शुगर क्यूब चिमटा होल्डर","de":"चौकोर चीनी का एक टुकड़ा चिमटे से टक करके चाय के प्याले में गिराओ। सफ़ेद कोनों को धीरे-धीरे घुलकर ग़ायब होते देखना—दादी की चाय-मेज़ पर पहली बार सीखी गई, जल्दबाज़ी न करने वाली मिठास की तमीज़।"},"ICON-1924":{"nm":"ट्रे स्लिप-रोधी मैट","de":"ट्रे झुक भी जाए तो प्याले अपनी जगह पर टिके रहते हैं। नीचे से चुपचाप थामे रखने वाली चीज़ों की तरह ही, यह मैट फिसलने ही वाले पल को अकेले सह लेती है और आख़िर तक चुप रहती है।"},"ICON-1925":{"nm":"स्ट्रॉ स्टैंड कप","de":"स्ट्रॉ को सीधा खड़ा रखने पर न पेय बिखरता है, न मन। बस एक छोटी सी सीधी खड़ी चीज़ से मेज़ सुथरी हो जाने वाली दोपहर में, कप एक नन्हा खंभा थामे धीमी घड़ियों को चुपचाप सहारा देता है।"},"ICON-1926":{"nm":"कुकी टुकड़ा पकड़","de":"कुरकुरा—कुकी टूटने के उस पल में गिरे टुकड़े यहीं जमा होते हैं। सबसे स्वादिष्ट कौर के छोड़े निशान तक को समेट लेना—आख़िरी टुकड़े तक अपनापन दिखाने वाला, मेज़ का ख़ामोश समापन।"},"ICON-1927":{"nm":"फ़ोटो क्लिप हैंगिंग लाइन","de":"कपड़े सुखाने की रस्सी जैसी लटकी डोरी पर पोलेरॉइड तस्वीरें क्लिप से टाँकी जाती हैं। आज खिंची मुस्कानें हवा में झूलते हुए सूखती रहती हैं, और दीवार का एक कोना यादों की छोटी, रोशन प्रदर्शनी बन जाता है।"},"ICON-1928":{"nm":"यादों की तकली","de":"उलझा धागा सुलझाकर करीने से लपेटी गई तकली। हर टूटी जगह पर गाँठ बाँधकर आगे बढ़ाई गई चीज़ें। याद को भी इसी तरह धीरे-धीरे एक-एक फेरा वापस लपेटें, तो छोटा लगने वाला रास्ता फिर से लंबा हो जाता है।"},"ICON-1929":{"nm":"दीवार कील ढक्कन","de":"कील के निशान को छुपाने वाला छोटा गोल ढक्कन। जहाँ कभी कुछ टँगा था, उतारने के बाद बचे उस छोटे से निशान को भी चुपचाप ढक दें, तो दीवार मानो कुछ हुआ ही न हो, फिर से चिकना चेहरा पा लेती है।"},"ICON-1930":{"nm":"ग्रुप फ़ोटो फ्रेम","de":"छह लोगों की कंधे से कंधा मिलाकर खिंची सामूहिक तस्वीर। फ्रेम में डालते ही उस दिन की हँसी और गर्माहट साथ में सील हो जाती है। फ्रेम बहते हुए दिन को सबसे ख़ामोशी से थाम लेने वाला हाथ है।"},"ICON-1931":{"nm":"मेमो कॉर्क बोर्ड","de":"पिन के निशानों से भरा भूरा बोर्ड। न भूलने लायक वादा, किसी का लिखा हौसला अफ़ज़ाई का पर्चा, आज के काम—सब परत दर परत टँगे रहते हैं। दिमाग़ की जगह याद रखने वाली, मेज़ के पास खड़ी एक भरोसेमंद दीवार।"},"ICON-1932":{"nm":"रीथ हैंगिंग नॉट","de":"दरवाज़े पर टाँगी एक रीथ में भी उंगलियों का हुनर लगता है। गाँठ मज़बूती से बाँधनी पड़ती है ताकि हवा भरे मौसम में भी न गिरे। किसी का स्वागत करने वाला मन हमेशा किसी अनदेखी जगह से ही मज़बूत होता है।"},"ICON-1933":{"nm":"वॉल क्लॉक पेंडुलम कवर","de":"टिक-टिक करते लोलक को लपेटकर धूल से बचाने वाला कपड़े का ढक्कन। समय नापने का काम भी इस तरह देखभाल पाता है। पुराना न पड़ने दें, धीरे से बचाए रखें, तो दीवार घड़ी हमारे साथ थोड़ी और देर टिकी रहती है।"},"ICON-1934":{"nm":"स्टिकर कलेक्शन बोर्ड","de":"हर दराज़ में बिखरे स्टिकर एक ही बोर्ड पर जुटकर कतार बनाते हैं। मनपसंद किरदार, चमकता तारा, हाथ से लिखा एक पन्ना। छोटे संग्रह की ख़ुशी करीने से सजते ही मन भी सीधा-सुथरा हो जाता है।"},"ICON-1935":{"nm":"बंटिंग जोड़ने वाली डोरी","de":"रंग-बिरंगे झंडों को एक कतार में जोड़ने वाली डोरी। जन्मदिन हो या स्वागत, डोरी के छत के आर-पार जाते ही एक साधारण कमरा जश्न का घर बन जाता है। जश्न मनाना टूटे हुए मन को जोड़ने-सिलने का काम है।"},"ICON-1936":{"nm":"इलेक्ट्रिक केतली कॉर्क ट्रिवेट","de":"गर्म केतली के तले को थामने वाला कॉर्क का एक टुकड़ा। मेज़ न झुलसे, इसलिए वह गर्मी अकेले सह लेता है। किसी की गर्माहट निशान बनकर न रह जाए, इसलिए चुपचाप सहारा देने वाली एक छोटी सी सोच।"},"ICON-1937":{"nm":"टोस्टर क्रम्ब ट्रे","de":"सुनहरी सिंकी ब्रेड से गिरे टुकड़े ट्रे में लुढ़ककर आ जाते हैं। खींचकर झाड़ दो, बस ख़त्म। व्यस्त सुबह को बिना कुछ कहे संभाल लेती है, और अगले भोजन के लिए फिर से साफ़-सुथरी तैयार हो जाती है।"},"ICON-1938":{"nm":"माइक्रोवेव टर्नटेबल रिंग","de":"घूमती हुई रिंग पर थाली धीरे-धीरे एक पूरा चक्कर खींचती है। बराबर गर्म हो, इसलिए घुमाया गया वह चक्कर, कल की ठंडी पड़ी दाल-चावल को फिर से भाप उठता एक निवाला बना देता है।"},"ICON-1939":{"nm":"मिनी इंडक्शन बर्नर कवर","de":"तेल चाहे जितना भी चारों ओर छिटके, बर्नर हमेशा साफ़ रहता है। एक ढक्कन तेज़ गर्मी और हाथ के बीच फ़ासला बना देता है। अनदेखे खड़ी रहने वाली चीज़ें रसोई को झुलसने से बचाकर रखती हैं।"},"ICON-1940":{"nm":"राइस कुकर स्टीम कैप","de":"सिट्ट—भाप निकलने की आवाज़। भीतर जमा दबाव को धीरे से छोड़ने वाली एक छोटी टोपी की बदौलत, ताज़ा पका चावल सबसे मुलायम चेहरे के साथ ढक्कन खोलता है। दम पर पकने के समय में कोई जल्दबाज़ी नहीं होती।"},"ICON-1941":{"nm":"कलछी स्टैंड होल्डर","de":"दाल चलाती कलछी को सीधा खड़ा रखो। रसोई के स्लैब पर दाग़ का एक भी निशान न गिरे, यह छोटी सी सोच। रसोई की सफ़ाई हमेशा इन्हीं नज़र न आने वाली मामूली जगहों से शुरू होती है।"},"ICON-1942":{"nm":"बर्तन हैंडल सिलिकॉन ग्रिप","de":"गरम हो चुके बर्तन के हैंडल पर सिलिकॉन पहनाओ तो हाथ नहीं जलता। गर्मी और हथेली के बीच आ खड़ी होने वाली एक परत। गरम खाना पकाने वाले को, सबसे नज़दीक की जगह से बचाती है।"},"ICON-1943":{"nm":"इलेक्ट्रिक केतली स्केल फ़िल्टर","de":"रोज़ उबाले जाने वाले पानी में भी हल्का सा निशान जमता है। एक बारीक जाली धीरे से पानी का मैल छानकर, सिर्फ़ साफ़ प्याली उड़ेलती है। चाय के पहले घूँट को अनदेखी जगह से बचाने वाला मेहनती हाथ।"},"ICON-1944":{"nm":"कुकिंग टाइमर क्लिप टाँगें","de":"बस तीन मिनट और, कहकर क्लिप वाली टाँगों से मेज़ का किनारा मज़बूती से जकड़े रहता है टाइमर। नूडल पकने तक अपनी नन्ही टाँगों पर टिका खड़ा रहकर, टिक-टिक करते हुए दिन के सबसे प्रतीक्षित पल को साथ गिनता है।"},"ICON-1945":{"nm":"कटलरी ड्रिप कप","de":"अभी-अभी धुले चम्मच-काँटे से टपाटप पानी बहता है। ड्रिप कप उस नमी को चुपचाप इकट्ठा कर ले, तो मेज़ पल भर में सूखी हो जाती है। सफ़ाई एक बूँद पानी तक का भी ख़याल रखने वाली मीठी मेहनत है।"},"ICON-1946":{"nm":"प्लेट स्टैंडिंग डिवाइडर रैक","de":"थालियों को खड़ी करके खाना-खाना बाँट दो। पोर करके रखने पर एक-दूसरे को खरोंचने वाले बर्तन अब अपनी-अपनी जगह पाते हैं। संवारना आख़िर, सबको बिना टकराए अपना ख़ाना देने का काम है।"},"ICON-1947":{"nm":"चॉपस्टिक जोड़ी रिंग","de":"जोड़ा खोकर अकेली रह गई चॉपस्टिक को रिंग में पिरोकर फिर से जोड़ी बनाओ। एक अकेली छड़ी जल्द ही बेकार हो जाती है, इसलिए साथ बाँधकर रखने वाली यह छोटी रिंग दराज़ के भीतर व्यवस्था बचाए रखती है।"},"ICON-1948":{"nm":"कप ट्री","de":"टहनी की तरह कई दिशाओं में फैले आधार पर एक-एक करके कप टाँगो। उल्टे रखे हर प्याले पर से नमी सूखते समय, रसोई का एक कोना छोटे, सलीकेदार पेड़ की तरह चुपचाप खड़ा रहता है।"},"ICON-1949":{"nm":"कटलरी ट्रे हैंडल","de":"चम्मच, चॉपस्टिक, काँटा खानों में करीने से लेटे ट्रे। हैंडल पकड़कर पूरी ट्रे उठा लो तो मेज़ लगाना कहीं आसान हो जाता है। दराज़ के भीतर भी बेशक व्यवस्था की सुंदरता बसती है।"},"ICON-1950":{"nm":"कप ड्रिप-ड्राई बोर्ड","de":"धुले प्यालों को उल्टा रखो तो पानी की बूँदें टप-टप गिरती हैं। धूप आती खिड़की के पास धीरे-धीरे सूखते समय, गिलास अगले घूँट के लिए शांति से अपनी पहली पारदर्शिता वापस पा लेता है।"},"ICON-1951":{"nm":"फ़ोर्क-गैप कंघी","de":"काँटे के दाँतों के बीच खाना न फँसे, इसलिए बारीक दाँतों से धीरे से सँवारा जाता है। सबसे तंग दरार तक का ख़याल रखने वाले स्पर्श की बदौलत, अगला भोजन हमेशा बेदाग़, साफ़ पहले कौर से शुरू होता है।"},"ICON-1952":{"nm":"स्टैकिंग फ़ेल्ट","de":"बर्तन पोर करने पर चीनी मिट्टी की तेज़ आवाज़ से टकराव होता है। बीच में रखा फ़ेल्ट का एक टुकड़ा उस रगड़ को शांत कर देता है। साथ लंबा चलने का राज़ यही है—एक-दूसरे को थोड़ा नरम रखना।"},"ICON-1953":{"nm":"चम्मच हैंगिंग लूप डोरी","de":"नन्हा सा चाय का चम्मच रिंग में टाँगकर दीवार पर लटकाओ। दराज़ में दबा न रहे, हमेशा हाथ की पहुँच में चमकता रहे—एक छोटा औज़ार गर्व से अपनी जगह घेरे रहता है। गृहस्थी में भी हर चीज़ की एक तय जगह होती है।"},"ICON-1954":{"nm":"फ़्रिज कम्पार्टमेंट ट्रे","de":"फ़्रिज के खाने को हिस्सों में बाँटो तो हर सामान को अपना छोटा घर मिल जाता है। गड्डमड्ड होकर भुला दी जाने वाली चीज़ें अपनी जगह पाती हैं, और दरवाज़ा खोलते ही एक नज़र में साफ़ दिखता है कि क्या कहाँ है।"},"ICON-1955":{"nm":"फ़्रीज़र बैग स्टैंडिंग क्लिप","de":"आधा बचा फ़्रीज़र ज़िप बैग क्लिप से पकड़कर सीधा खड़ा करो। गिरकर बिखरे नहीं, अगली बार ढूँढ़ना आसान हो। ठंडे फ़्रीज़र के भीतर भी एक चतुर, सुघड़ गृहिणी की सूझ-बूझ बसी रहती है।"},"ICON-1956":{"nm":"बॉटल कैप टाइटनर","de":"ढीली बंद बोतल में जल्द ही हवा भर जाती है। कलाई की एक बार की ताक़त से ढक्कन कसकर बंद करना, भीतर की ख़ुशबू और झाग को कल सुबह तक अछूता रोक देता है। चतुराई छोटी-छोटी बातों में चमकती है।"},"ICON-1957":{"nm":"एग ट्रे नॉन-स्लिप मैट","de":"गोल अंडे लुढ़ककर न टूटें, इसके लिए खानों में सहारा देने वाला बिछावन। सबसे नाज़ुक चीज़ को सबसे सावधानी से संभालने की चाहत, फ़्रिज के दरवाज़े के एक कोने में छोटी, दुलारी सी जगह पाती है।"},"ICON-1958":{"nm":"फ़्रिज डोर पॉकेट एक्सटेंडर","de":"फ़्रिज दरवाज़े की जेब को थोड़ा बग़ल में बढ़ाकर एक खाना और बना लो। गृहस्थी बढ़े तो उसकी जगह भी साथ बढ़नी चाहिए। तंग जगह को फैलाकर इस्तेमाल करने के हुनर में, चतुर गृहिणी का मन झलकता है।"},"ICON-1959":{"nm":"बचा खाना ढक्कन","de":"बचे हुए खाने पर धीरे से दबाकर बंद करने वाला ढक्कन। सूखने न पाए, दूसरी गंध न लगे, इसलिए चुपचाप संभाले रखता है। ख़याल रखने वाला हाथ एक वक़्त के बचे हुए हिस्से को भी संजोकर रखता है।"},"ICON-1960":{"nm":"कोल्ड-एयर डायरेक्शन वेन","de":"ठंडी हवा किस दिशा में बहेगी, यह एक छोटा पंख चुपचाप तय करता है। हवा के अनदेखे रास्ते को उंगली से हल्का मोड़ दो, तो ठंडक भीतर के सबसे गहरे कोने तक भी पहुँच जाती है।"},"ICON-1961":{"nm":"क्रिस्पर मॉइस्चर पैड","de":"फ़्रिज के सब्ज़ी वाले खाने के सबसे अँधेरे कोने में, मैं चुपचाप नमी थामे रहता हूँ। कल मुरझाया पत्ता सुबह फिर से ताज़ा हो उठने का छोटा सा चमत्कार। किसी को पता न भी हो, ताज़गी की ज़िम्मेदारी हमेशा मेरी ही है।"},"ICON-1962":{"nm":"सोडा कैन रोल-स्टॉप रिज","de":"मेज़ के किनारे चुपचाप चिपककर, लुढ़कने वाले कैन का पैर पकड़ लेता है। लगभग गिरता पेय, लगभग पुँछने वाली मेज़। गृहस्थी का सुकून ऐसी ही एक अनदेखी छोटी सी उभार से शुरू होता है।"},"ICON-1963":{"nm":"काम-बारी डायल","de":"आज बर्तन कौन धोएगा, कचरा कौन अलग करेगा। तीर एक बार घुमाओ, हर झगड़ा गोल-गोल घूमकर सुलझ जाता है। पाँच लोगों के साथ रहने वाले घर में, बारी लेना ही सबसे मीठी शांति है।"},"ICON-1964":{"nm":"मेंबर कप सिलिकॉन बैंड","de":"एक जैसे पाँच प्याले, और किसका कौन सा है यह उलझन भरी सुबह। कलाई जितनी रंगीन पट्टी पहना दो तो \"यह मेरा है\" वाला छोटा वादा साफ़ हो जाता है, और नाश्ते की मेज़ पर एक मीठी सी व्यवस्था घुल जाती है।"},"ICON-1965":{"nm":"पोर्शन बाउल रिंग","de":"व्यस्त दिन में कटोरे के भीतर की रेखा एक भरोसेमंद दोस्त बन जाती है। एक खाना चावल के लिए, एक खाना सब्ज़ी के लिए। न कम, न ज़्यादा—आज कितना खाना है, यह चुपचाप बताने वाली एक मीठी लकीर।"},"ICON-1966":{"nm":"स्नैक शेयरिंग टॉन्ग टब","de":"पूरा पैकेट आगे बढ़ा दो तो हाथ लगी जगह छूटी रह जाती है, अटपटा सा। चिमटे से एक-एक करके बाँटो तो तभी सबका हिस्सा बराबर होता है। बाँटने में हथेली भर से ज़्यादा सलीकेदार हाथ की आदत फबती है।"},"ICON-1967":{"nm":"केतली ड्यूटी नेमप्लेट होल्डर","de":"पानी उबालने का काम हमेशा एक ही हाथ के हिस्से आता था। केतली के पास वाले होल्डर में बारी-बारी नामपट्टी टाँगने के बाद से, एक गरम प्याली चाय बारी-बारी उतरने वाली मिठास बन गई।"},"ICON-1968":{"nm":"क्लीन-प्लेट स्पैटुला चिप","de":"'कुछ मत छोड़ना' एक छोटा सा वाक्य पलटे के सिरे पर लटका है। सुनने में नसीहत जैसा लगे तो भी उसमें कोई ख़राबी नहीं। हर निवाला संजो कर रखने वाली पुरानी थाली का मन, यहीं बसा है।"},"ICON-1969":{"nm":"निजी कटलरी पाउच हुक","de":"चम्मच-काँटे अब दराज़ में इधर-उधर नहीं लुढ़कते। हर एक की जोड़ी अपनी थैली में जाकर दीवार पर टँगते ही, पाँच घरवालों की जगह एक कतार में सज जाती है। छोटी सी सुव्यवस्था हर दिन की शांति को थामे रखती है।"},"ICON-1970":{"nm":"टेबल सीट कॉर्क चिप","de":"मेज़ पर कॉर्क के टुकड़े बिछा दो तो साफ़ हो जाता है कौन कहाँ बैठेगा। हमेशा बैठने वाली जगह, हमेशा आमने-सामने दिखने वाला चेहरा। तय जगह ही \"साथ रहना\" शब्द का सबसे ख़ामोश सबूत है।"},"ICON-1971":{"nm":"ड्यूटी एप्रन रोल हुक","de":"बर्तन धोकर उतारा एप्रन यूँ ही कहीं फेंका नहीं जाता। लपेटकर हुक पर टाँग दो तो अगली सुबह फिर से ताज़ा हाथ आ जाता है। अगले इंसान का ख़याल इस छोटी सी गाँठ में बसा है।"},"ICON-1972":{"nm":"डिस्पोज़ेबल स्लिपर फोल्ड बैग","de":"मेहमान आने के दिन मैं थैले समेत खुल जाता हूँ। भीतर करीने से रखी डिस्पोज़ेबल चप्पलें नए आए पैरों का नरम स्वागत करती हैं। मेहमाननवाज़ी हमेशा दरवाज़े से ही चुपचाप शुरू होती है।"},"ICON-1973":{"nm":"कॉटन-स्वैब पेपर-टेल पॉकेट","de":"कान की सफ़ाई की छड़ियाँ ख़त्म होकर सिर्फ़ काग़ज़ की पूँछ बचे, तो मैं उसके सिरे भी सलीके से समेट लेता हूँ। फेंकी जाने वाली चीज़ को भी जगह देना। साफ़-सुथरी मेज़ का राज़ ऐसी ही मामूली मिठास में छिपा है, यह मैं जानता हूँ।"},"ICON-1974":{"nm":"सिलाई किट धागा बंडल","de":"तकलियाँ खुलकर उलझें नहीं, इसलिए रंगीन धागों को एक साथ बाँध दो। गिरा बटन हो या ढीली हुई आस्तीन, यह एक बंडल पल भर में सब ठीक कर देता है। किसी ज़रूरी दिन की शाम को चुपचाप बचा लेने वाली हाथ की सिलाई।"},"ICON-1975":{"nm":"सिंगल-रैप्ड साबुन टुकड़ा","de":"अलग-अलग करीने से लिपटा साबुन का एक टुकड़ा हर मेहमान कमरे में रखा जाता है। हथेली भर का शरीर, झाग की एक मुट्ठी से दिन भर की धूल धो देता है। सफ़ाई हमेशा ऐसी ही छोटी जगहों से शुरू होती है।"},"ICON-1976":{"nm":"शावर कैप फ़ोल्डिंग कैप्सूल","de":"सिलवटें मोड़ो तो हथेली में समा जाए, खोलो तो बालों को पूरा लपेट ले। एक बार के नहाने से सँवारे बाल न बिगड़ें, इसलिए। कल सुबह की सलीकेदारी इसी एक परत की बदौलत बची रहती है।"},"ICON-1977":{"nm":"टूथब्रश प्रोटेक्टिव स्लीव","de":"ब्रश के बाल सोच से कहीं ज़्यादा नाज़ुक होते हैं। एक ग़िलाफ़ उनके सिरे ढक दे तो बैग की धूल भी नहीं पहुँच पाती। अनदेखी जगहों की रक्षा करना—हर सफ़र में सीखा जाने वाला स्वच्छता का असली काम।"},"ICON-1978":{"nm":"कॉटन-पैड सिंगल-पुल चिमटी","de":"कॉटन पैड एक-एक करके उठाओ तभी करीने से निकलता है। एक साथ बिखेर दो तो बर्बाद ज़्यादा होता है। \"एक-एक करके, ध्यान से\"—यह ड्रेसिंग टेबल का ख़ामोश नियम है।"},"ICON-1979":{"nm":"मिनी फ़ोल्डिंग शूहॉर्न","de":"मोड़ो तो जेब में, खोलो तो एड़ी पर। अपने छोटे शरीर से काफ़ी बड़ा काम कर जाने का मुझे गर्व है। देर तक सोकर उठी सुबह में भी, जूता बिना ख़राब किए पहनाना हमेशा मेरा ही काम रहा है।"},"ICON-1980":{"nm":"सिंगल फ़्लॉस वाइंडर","de":"फ़्लॉस के एक धागे को करीने से लपेटकर रखो तो ज़रूरत पड़ने पर ठीक उतना ही काटा जा सकता है। नाख़ून जितनी छोटी रील, फिर भी रोशन मुस्कान बचाने के काम से कभी ग़ायब नहीं होती। मुस्कान की भी अनदेखी तैयारी होती है।"},"ICON-1981":{"nm":"इलेक्ट्रिक केतली ढक्कन हैंडल","de":"उबलते पानी की भाप से हाथ न जले, इसलिए मैं ढक्कन पर लगा हूँ। गर्मी और हथेली के बीच बस एक बालिश्त भर फ़ासला। यह छोटी सी दूरी किसी की व्यस्त सुबह को सुरक्षित रूप से गरमाती है।"},"ICON-1982":{"nm":"आयरन रेस्ट सिलिकॉन पैड","de":"इस्त्री करते-करते पल भर के लिए हाथ हटाने का वह पल सबसे ख़तरनाक होता है। सिलिकॉन पैड पर इस्त्री खड़ी कर दो तो न मेज़ झुलसे, न कपड़े। सिलवटें मिटाने का काम आधार पर टिककर ही आख़िर पूरा होता है।"},"ICON-1983":{"nm":"चोरी-रोधी हैंगर हुक","de":"टँगा कपड़ा यूँ ही फिसलकर न गिरे, इसलिए हुक अपना मुँह मज़बूती से बंद रखता है। अलमारी में सहेजे प्रिय कपड़े के पास खड़ा एक छोटा पहरेदार। संभालना, ऐसे ही एक ख़ामोश काम है।"},"ICON-1984":{"nm":"केतली स्केल स्ट्रेनर","de":"उबलते पानी में तैरते मैल को चुपचाप छान देना मेरा काम है। अनदेखे तलछट तक छानने के बाद ही एक प्याली चाय साफ़ होती है। लगन हमेशा उन जगहों से उभरती है जहाँ किसी की नज़र नहीं पड़ती।"},"ICON-1985":{"nm":"हैंगर नॉन-स्लिप पट्टी","de":"फिसलन-रोधी पट्टी लपेटा हैंगर हल्के रेशम को भी नहीं गिराता। फ़र्श पर गिरकर सिकुड़े कपड़े को एक बार देख चुका इंसान जानता है, इस पतली सी लकीर का शुक्रिया।"},"ICON-1986":{"nm":"आयरन कॉर्ड टाइडी क्लिप","de":"खुली पड़ी डोरी पैर में उलझकर किसी को लड़खड़ा देती है। क्लिप से करीने से बाँध देने वाला एक हाथ का स्पर्श। दुर्घटना रोकने का काम हमेशा ऐसी ही छोटी, मामूली सफ़ाई से शुरू होता है।"},"ICON-1987":{"nm":"इलेक्ट्रिक केतली बेस स्लॉट","de":"हिले नहीं, इसलिए केतली को मैं अपने खाँचे में ठीक से बिठा लेता हूँ। अपनी जगह पर रखा होना ही सुकून का दूसरा नाम है। हर सुबह गरम पानी एक ही जगह गरम होने की कोई तो वजह है।"},"ICON-1988":{"nm":"ट्राउज़र हैंगर क्लिप टाँगें","de":"पैंट के छोर को क्लिप वाली टाँगें मज़बूती से जकड़ें, तो एक भी सिलवट नहीं पड़ती। अच्छे से इस्त्री किया कपड़ा हैंगर पर टँगते ही आदर पाने लगता है। सुथरी फ़िटिंग अलमारी के भीतर ही पूरी होती है।"},"ICON-1989":{"nm":"हेयर ड्रायर हैंगिंग हुक","de":"ड्रायर को यूँ ही कहीं रख दो तो डोरी जल्द ही उलझ जाती है। हुक पर टाँग दो तो सिंक भी चौड़ा लगता है और अगली सुबह हल्की हो जाती है। सँवरी जगह व्यस्त दिन को थोड़ा सा ढीला कर देती है।"},"ICON-1990":{"nm":"मिनीबार ड्रिंक कोस्टर","de":"प्याले के नीचे चुपचाप बिछा दो तो बूँदें मेज़ पर नहीं फैलतीं। एक कोस्टर की यह सोच गोल निशान नहीं छोड़ती। सफ़ाई का मतलब है कोई निशान न छोड़ने वाली मिठास।"},"ICON-1991":{"nm":"डू-नॉट-डिस्टर्ब साइन","de":"दरवाज़े की कुंडी पर टँगा एक बोर्ड धीरे से फुसफुसाता है, \"अभी आराम में हूँ\"। एक लंबे दिन के अंत में एक झपकी की साँस बचाए रखने का काम। विराम को भी कोई प्यार से संभाले, यह ज़रूरी है।"},"ICON-1992":{"nm":"रूम सर्विस कॉल बटन कैप","de":"बटन को ढकने वाली टोपी की बदौलत, कपड़े का छोर छू भी जाए तो ग़लती से नहीं दबता। सचमुच ज़रूरत हो तभी साफ़ पुकार पहुँचे, इसलिए। एक छोटा ढक्कन व्यस्त कमरे को कहीं ज़्यादा सलीकेदार बना देता है।"},"ICON-1993":{"nm":"मिनीबार आइस टॉन्ग","de":"नंगे हाथ से बर्फ़ उठाओ तो ठंडी लगती है और बार-बार फिसलती है। यह काम चिमटे की टाँगें बड़ी सफ़ाई से संभाल लेती हैं। एक ठंडे पेय की शुरुआत में एक अनदेखा मददगार हाथ छिपा होता है।"},"ICON-1994":{"nm":"रूम की कार्ड स्लॉट","de":"कार्ड को स्लॉट में डालो तो कमरे की बत्ती टक जल उठती है। मैं बस एक छोटी सी दरार भर हूँ, पर दिन भर की थकान उतारने की जगह खोलने वाला पहला इशारा हूँ। लौटने की जगह पर फिर से बत्ती जलती है।"},"ICON-1995":{"nm":"बॉटल-नेक सील रिंग","de":"पानी की बोतल की गर्दन पर लगी सील रिंग अगर सही-सलामत है, तो इसका मतलब है अभी तक किसी ने हाथ नहीं लगाया। शुरू जैसा ही होने का सबूत देने वाला एक छोटा वादा। भरोसा हमेशा एक अटूट सील से शुरू होता है।"},"ICON-1996":{"nm":"ब्रोशर स्टैंड","de":"सूचना पुस्तिका को तिरछा खड़ा रखो तो गुज़रती नज़र अपने आप वहीं ठहर जाती है। खुलने का इंतज़ार करती जानकारी की शालीन मुद्रा। बस अच्छी तरह दिखाई देना ही किसी का रास्ता कहीं आसान बना देता है।"},"ICON-1997":{"nm":"मिनीबार बॉटल-ओपनर चिप","de":"चपटे शरीर के एक कोने में बोतल का ढक्कन खोलने का खाँचा हल्के से छिपा है। छोटा होकर भी अपना काम बख़ूबी करता है। एक बोतल पेय के ठंडे पहले घूँट का दरवाज़ा हमेशा इसी छोटी चिप से खुलता है।"},"ICON-1998":{"nm":"लाइट डिमर नॉब कवर","de":"ढके हुए नॉब को धीरे से घुमाओ तो कमरे की रोशनी धीरे-धीरे बदलती है। कभी तेज़, कभी मद्धम। सोने के वक़्त की रोशनी चुनना, दिन को प्यार से समेटने वाला एक विधान है।"},"ICON-1999":{"nm":"सूटकेस व्हील स्टॉप वेज","de":"पहिये के नीचे हल्के से लगाओ तो सूटकेस अपनी मर्ज़ी से नहीं लुढ़कता। ढलानदार स्टेशन प्लेटफ़ॉर्म पर भी सामान अपनी जगह टिका रहता है। सफ़र पर निकलने का सुकून इसी छोटे से खूँटे से मज़बूत होता है।"},"ICON-2000":{"nm":"ट्रैवल पैकिंग फ़ोल्ड बोर्ड","de":"फैलाकर उस पर रखो तो कमीज़ हो या पैंट, दोनों करीने से मुड़ जाते हैं। बैग के भीतर का सामान बिखरे नहीं, पहुँचे शहर में बेसिलवट निकला जा सके, इसलिए। अच्छे से बाँधा सामान निकलने से पहले ही सफ़र में मदद करने लगता है।"},"ICON-2001":{"nm":"रूम सेफ लॉक नॉब","de":"घुंडी घुमाते ही एक छोटी सी कुंडी भीतर की ओर सरक जाती है। कीमती सामान सौंपना यही वादा है कि बस एक रात के लिए दिल को पूरी तरह निश्चिंत कर लिया जाए। यह ताला वहाँ चिंता नहीं, बल्कि सुकून के दूसरे नाम की तरह मौजूद है।"},"ICON-2002":{"nm":"सूटकेस हैंडल कवर","de":"हाथों के स्पर्श से घिसे हर निशान में किसी की विदाई अंकित है। जितनी दूरी तय हुई उतना ही घिसा यह कवर पकड़ते ही चुपचाप पता चलता है कि जाना, आखिरकार, लौटने को अपने भीतर समेटे एक शब्द है।"},"ICON-2003":{"nm":"ट्रैवल पाउच हैंगिंग क्लिप","de":"सिंक के किनारे पर पाउच टांगते ही तंग कमरा एक बित्ता और खुल जाता है। बैग के भीतर की व्यवस्था एक छोटी सी क्लिप से शुरू होती है, यह बात दूर की यात्रा कर चुका हाथ पहले से ही जानता है।"},"ICON-2004":{"nm":"चार्जर मल्टी-प्लग क्लिप","de":"एक ही सॉकेट में कई केबल इकट्ठा करके लगाई जाती हैं। चार्ज पूरा भरने का इंतज़ार करती रात में, बिखरी हुई डोरियों को एक जगह प्यार से थामे रखने वाला एक छोटा सा हाथ यहाँ मौजूद है।"},"ICON-2005":{"nm":"सूटकेस नेम टैग स्ट्रैप","de":"एक जैसे काले बैगों के बीच अपना बैग पहचनवाने वाला एक धागा। नाम टांगना यह जताता है कि यह सामान किसी के पास लौटने का रास्ता रखता है—यह एक कोमल पहचान चिह्न है।"},"ICON-2006":{"nm":"रूम वॉल चार्ज-कॉर्ड होल्डर बोर्ड","de":"बिस्तर के सिरहाने की दीवार पर लगा एक छोटा बोर्ड चार्जिंग तार को करीने से थामे रखता है। किसी अनजान कमरे में मिलने वाली पहली रात, जब एक जानी-पहचानी रोशनी जलती है, तो वह जगह भी थोड़ी देर के लिए घर बन जाती है।"},"ICON-2007":{"nm":"लगेज स्टैंड की फोल्डिंग टांगें","de":"मुड़ी हुई टांगें खोलते ही बैग धूल भरी ज़मीन से एक बित्ता ऊपर उठ जाता है। अभी न खोला गया ट्रंक, बिना बताए, एक अधूरी यात्रा को चुपचाप अपने भीतर समेटे अगली सुबह की राह देखता है।"},"ICON-2008":{"nm":"की-कार्ड स्लॉट","de":"कार्ड डालने पर ही कमरे में रोशनी आती है। ठहरने भर के लिए जलने वाली यह रोशनी—यात्री का दिन इसी छोटे स्लॉट की इजाज़त जितनी ही रोशनी से गर्माता है।"},"ICON-2009":{"nm":"की-कार्ड स्ट्रैप लूप","de":"एक कार्ड गले में लटकाते ही दोनों हाथ हल्के हो जाते हैं। खो जाने की चिंता को एक डोरी से बांध देने की यह छोटी सी चतुराई, भारी सामान ढोने वाले यात्रियों से लंबे समय से चली आ रही सूझ है।"},"ICON-2010":{"nm":"फ्रंट डेस्क कॉल बेल बटन","de":"दबाते ही फ्रंट डेस्क पर कहीं एक साफ़ आवाज़ खनखना उठती है। मदद मांगना शर्मिंदगी की बात न लगे, इसलिए यह घंटी हमेशा हाथ की एक पहुंच भर की दूरी पर प्यार से रखी होती है।"},"ICON-2011":{"nm":"चेक-इन नंबर क्लिप","de":"कतार के आखिर में मिली नंबर की पर्ची को उठाकर टांक दिया जाता है। इंतज़ार का भी एक क्रम होता है—व्यवस्था एक-दूसरे के समय को चुपचाप संजोने के छोटे से वादे से पनपती है।"},"ICON-2012":{"nm":"रूम की टैसल","de":"चाबी के सिरे पर लटका फुंदना हर कदम पर हल्के से हिलता है। उपयोगिता में थोड़ा सा सौंदर्य जोड़ देने का मन उन्हीं का होता है जो उंगलियों की छोटी खुशी को पहचानते हैं।"},"ICON-2013":{"nm":"फ्रंट डेस्क डोरबेल कवर","de":"डोरबेल के ऊपर ढक्कन चढ़ा देने से दोपहर की खामोशी टूटती नहीं। किसी की गहरी नींद की रखवाली करने की यह छोटी सी परवाह—सन्नाटा भी किसी के मन लगाकर बनाया हुआ होता है।"},"ICON-2014":{"nm":"रूम नंबर डोर टैग","de":"दरवाज़े की कुंडी पर टंगी पर्ची पर कमरे का नंबर साफ़ लिखा है। कुछ अंक ही आज रात लौटने की मेरी जगह तय कर देते हैं, और अनजान गलियारे में यह एक छोटा प्रकाशस्तंभ बन जाता है।"},"ICON-2015":{"nm":"की-कार्ड मैग्नेटिक स्ट्रिप","de":"काली पट्टी को दरवाज़े की दरार पर टिकाते ही ताला सहज खुल जाता है। एक अदृश्य संकेत से दरवाज़ा खुलने का यह युग—कभी जादू सा लगने वाला काम अब हथेली पर रोज़मर्रा की बात बनकर उतर आया है।"},"ICON-2016":{"nm":"चेक-इन स्टैंप रेस्ट","de":"हर बार मुहर लगने पर यह आधार स्याही को समान रूप से थाम लेता है। पुष्टि की एक रेखा स्पष्ट अंकित रहे, इसके लिए एक अदृश्य जगह से चुपचाप सहारा देने वाला हाथ यहाँ है।"},"ICON-2017":{"nm":"लगेज कार्ट हैंगिंग बार","de":"सामान की ट्रॉली पर लगा एक डंडा गारमेंट बैग को बिना सिलवट के थामे रखता है। भारी दिन को हमारी जगह उठाने वाली इन चीज़ों को भी कभी-कभी शुक्रिया कहने का मन करता है।"},"ICON-2018":{"nm":"ट्रंक हैंडल टैग","de":"ट्रंक के हैंडल पर एक छोटा टैग लटका दिया जाता है। जब तक नाम लिखने की जगह खाली है, तब तक यह उत्साह बना रहता है कि इस बैग की अगली मंज़िल अभी तय नहीं हुई।"},"ICON-2019":{"nm":"लगेज कार्ट व्हील लॉक वेज","de":"ढलान पर ट्रॉली न लुढ़के इसलिए पहिये के नीचे एक कील अड़ा दी जाती है। ठहराव की रखवाली करना ही, कभी-कभी, सुरक्षा का सबसे भरोसेमंद दूसरा चेहरा होता है।"},"ICON-2020":{"nm":"लगेज स्ट्रैप बकल","de":"यात्रा के सामान से फूला बैग फटे नहीं इसलिए पट्टी को कसकर बांध दिया जाता है। रास्ता खत्म होने पर भी यादों का आयतन कम नहीं होता, इसलिए यह बकल उस भार को अंत तक थामे रखता है।"},"ICON-2021":{"nm":"लगेज कार्ट हुक कवर","de":"ट्रॉली के हुक पर चढ़ा कवर कपड़ों पर एक भी निशान नहीं छोड़ता। अनदेखी खरोंचों तक का पहले से ख़याल रखने वाला मन—अच्छी आवभगत ऐसी ही छोटी बातों में पूरी होती है।"},"ICON-2022":{"nm":"सूटकेस नेम-टैग पॉकेट","de":"बैग की बगल में लगी एक छोटी जेब नेम टैग को अपने भीतर संजोए रखती है। किसका सामान है यह लिख देना, गुम होने पर भी दोबारा मिलने के अधिकार को पहले से ही अंकित करने जैसा है।"},"ICON-2023":{"nm":"लगेज ग्लव क्लिप","de":"भारी सामान उठाते समय दस्ताने फिसलें नहीं इसलिए क्लिप उन्हें मज़बूती से जकड़ लेती है। हाथों की रक्षा करना और काम को अच्छे से निभाना, आखिरकार, एक ही मन से निकलते हैं।"},"ICON-2024":{"nm":"लगेज नेट कवर","de":"जाल बिछा देने से छोटा-मोटा सामान चारों ओर बिखरता नहीं। हर घनी बुनी हुई गांठ भागदौड़ भरी यात्रा के बीच छोटी चीज़ों को छूटने से बचाकर थामे रखती है।"},"ICON-2025":{"nm":"लगेज कार्ट मेमो होल्डर","de":"ट्रॉली के हैंडल पर टंकी पर्ची पर कमरे का नंबर लिखा है। कहाँ जाना है यह लिख लेने की यह आदत—जितने व्यस्त हाथ हों उतना ही वे एक पंक्ति की लिखावट पर चुपचाप टिक जाते हैं।"},"ICON-2026":{"nm":"ट्रे प्लेट कवर डोम","de":"चांदी जैसा गुंबद उठाते ही भाप एक साथ उठ खड़ी होती है। खाना ठंडा न हो इसलिए उसे ढके रखने वाला मन, गर्माहट को वैसी की वैसी सौंपने की चाहत भर है।"},"ICON-2027":{"nm":"डू-नॉट-डिस्टर्ब डोरनॉब प्लेट","de":"दरवाज़े की कुंडी पर यह तख्ती लटकाते ही गलियारे में पड़ते कदमों की आवाज़ तक सहम जाती है। \"मुझे मत जगाना\" यह एक वाक्य—आराम भी तभी पूरा होता है जब कोई उसकी रखवाली करे।"},"ICON-2028":{"nm":"रूम सर्विस पेपर नैपकिन रिंग","de":"कागज़ के नैपकिन को गोल छल्ले में पिरोकर सलीकेदार आकार दिया जाता है। एक वक़्त के खाने की शालीनता इसी छोटी सी अंगूठी से शुरू होती है, परवाह सबसे छोटी चीज़ों में सबसे साफ़ झलकती है।"},"ICON-2029":{"nm":"ट्रे नॉन-स्लिप मैट","de":"ट्रे पर एक चटाई बिछाते ही बर्तन फिसलते नहीं। हिलते-डुलते रहने पर भी अपनी जगह टिके रहना—इस शांत स्थिरता में भी किसी की बारीक सोच छिपी है।"},"ICON-2030":{"nm":"ब्रेकफास्ट ऑर्डर डोर टैग","de":"दरवाज़े की कुंडी पर नाश्ते की ऑर्डर पर्ची टांगते ही कल की सुबह पहले से तय हो जाती है। आज रात पहले भोजन को लिख देना, कोमल प्रतीक्षा का एक और चेहरा है।"},"ICON-2031":{"nm":"ट्रे लेग स्टैंड","de":"ट्रे की टांगें खोलते ही बिस्तर पर भी एक सजा-धजा मेज़ बन जाती है। लेटे-लेटे मिलने वाला सुबह का खाना—एक छोटा सा स्टैंड साधारण कमरे को शानदार दृश्य में बदल देता है।"},"ICON-2032":{"nm":"चायदानी कोज़ी कवर","de":"चायदानी पर कोज़ी चढ़ाते ही पानी की गर्माहट देर तक टिकी रहती है। चूल्हे के इर्द-गिर्द बैठी जाती पुरानी रातों की तरह, गर्माहट संजोए रखने की यह चाह किसी युग की मोहताज नहीं।"},"ICON-2033":{"nm":"क्लीनिंग रिक्वेस्ट डोर टैग","de":"दरवाज़े की कुंडी पर सफाई की गुज़ारिश वाली पूंछ टांगकर एक ख़ामोश संकेत छोड़ा जाता है। बिना होंठ खोले पहुंचती यह विनती—एक करीने से सजे कमरे के पीछे किसी अनदेखे हाथ का वादा छिपा होता है।"},"ICON-2034":{"nm":"ट्रे कंडीमेंट होल्डर","de":"मसाले की शीशी लुढ़के नहीं इसलिए होल्डर उसे मज़बूती से थामे रखता है। हिलती हुई ट्रे पर भी स्वाद का संतुलन बनाए रखना, इस छोटी सी पकड़ का चुपचाप निभाया गया दायित्व है।"},"ICON-2035":{"nm":"रिज़र्वेशन मेमो स्टैंड","de":"बुकिंग की पर्चियों को खड़ा करके रखने से क्रम एक नज़र में समझ आ जाता है। व्यस्त हाथ भी उलझें नहीं, इसलिए एक कागज़ को साफ़-साफ़ खड़ा रखने वाला यह एक छोटा व्यवस्था-यंत्र है।"},"ICON-2036":{"nm":"साइटसीइंग पिन मैप बोर्ड","de":"नक्शे पर पिन गाड़कर जाने की इच्छा वाली जगहों को एक-एक कर चिह्नित किया जाता है। हर पिन अभी न देखी गई जगह का एक रोमांच है—सफ़र नक्शा खोलते ही उसी क्षण शुरू हो जाता है।"},"ICON-2037":{"nm":"टैक्सी हेल फ्लैग क्लिप","de":"टैक्सी बुलाते समय एक छोटा झंडा क्लिप से सीधा खड़ा किया जाता है। हाथ उठाने की जगह झंडा ही पुकार लगाता है—सड़क पर भी बुलावा साफ़ हो तभी वह पहुंचता है।"},"ICON-2038":{"nm":"कंसीयर्ज डोरबेल हैंडल","de":"घुंडी दबाते ही कंसीयर्ज डेस्क तक एक साफ़ आवाज़ पहुंचती है। कुछ भी पूछ सकते हैं, इस आवभगत का संकेत—अनजान शहर में सबसे भरोसेमंद एक पुकार।"},"ICON-2039":{"nm":"रिज़र्वेशन नंबर क्लिप बोर्ड","de":"बुकिंग नंबर की पर्ची को क्लिपबोर्ड में जकड़कर साफ़ दिखने लायक रखा जाता है। तय की गई जगह उलझे नहीं, इसलिए अंकों की एक पंक्ति को करीने से थामे रखने वाली यह एक छोटी लगन है।"},"ICON-2040":{"nm":"टूर पैम्फलेट डिस्प्ले फ्रेम","de":"टूर पैम्फलेट सजाकर रखते ही यात्री का हाथ अपने आप ठहर जाता है। एक-एक कर खोले जाने वाले हर पन्ने में, अभी न तय हुए रास्ते का दृश्य चुपचाप मुड़ा हुआ पड़ा रहता है।"},"ICON-2041":{"nm":"मैप स्टैंप रेस्ट","de":"प्रवेश द्वार पर पहली बार रखे गए कदमों के लिए, नक्शे पर लगने वाली मुहर का डिब्बा बिना हिले टिका रहता है। स्याही न फैले तो रास्ता भी उलझता नहीं। एक छोटा मार्गदर्शक सीधा खड़ा रहे, इसके लिए चुपचाप भार संभालने वाली यह जगह है।"},"ICON-2042":{"nm":"छाता स्टोरेज टैग","de":"जिस दोपहर छज्जे से बूंदें टपटप टपक रही थीं, हर छाते पर एक-एक नंबर लटका दिया जाता है। बारिश थमने पर लौटा हुआ व्यक्ति जब अपना छाता ढूंढता है, यह टैग भीगी याद को साफ़-साफ़ पुकार देता है।"},"ICON-2043":{"nm":"इन्फो डेस्क कॉल बेल होल्डर","de":"टन्न, एक बार बजते ही उस पार से कोई खुशी से दौड़ा आता है। डेस्क के कोने पर टंगी यह छोटी घंटी वे शब्द भी पहुंचा देती है जो होंठों तक नहीं आ पाए—यह सबसे कोमल दुभाषिया है।"},"ICON-2044":{"nm":"शैम्पू डिस्पेंसर नोज़ल","de":"हथेली फैलाकर हल्के से दबाते ही झाग फुस्स से उठ खड़ा होता है। खुशबू पूरे बाथरूम में फैल जाने वाला वह एक क्षण। एक ऊंघती सुबह को सबसे नरमी से जगाने वाली घंटी की आवाज़ ठीक यहीं से शुरू होती है।"},"ICON-2045":{"nm":"साबुन दानी ड्रेन ट्रे","de":"साबुन के नीचे जमा पानी को चुपचाप बहा देने वाली पट्टी। न गलने दे, न मुलायम पड़ने दे। रोज़ थोड़ा-थोड़ा घिसती चीज़ को थोड़ी देर और साथ रखने की यह एक छोटी, प्यारी सी परवाह है।"},"ICON-2046":{"nm":"बाथ सॉल्ट स्कूप","de":"एक चम्मच पाउडर उठाकर गुनगुने पानी में घोलते ही रंग और खुशबू धीरे-धीरे फैलने लगते हैं। कलाई से हिलाते-हिलाते टब एक छोटी झील बन जाता है, और दिनभर की थकान उसमें चुपचाप डूब जाती है।"},"ICON-2047":{"nm":"लैदर नेट पाउच","de":"साबुन का एक टुकड़ा जाल में बंद करके मलते ही हथेलियां भरपूर मुलायम झाग से भर जाती हैं। खुरदुरी चीज़ को नरम में बदल देने वाला, बाथरूम के एक कोने में बैठा यह एक ख़ामोश कीमियागर है।"},"ICON-2048":{"nm":"टूथब्रश सैनिटाइज़िंग कैप","de":"जो चीज़ मुंह को छुए वह हमेशा साफ़ रहे, यही चाहत है। ब्रश के सिरे को नरमी से ढक लेने वाली यह एक छोटी टोपी अनदेखी जगहों तक का भी ख़याल रखती है। साफ़-सफ़ाई ऐसी ही छोटी बातों के जमा होने से बनती है।"},"ICON-2049":{"nm":"कॉटन स्वैब टब लिड","de":"जिस डिब्बे में सफेद डंडियां करीने से लेटी हों, उसके ऊपर गोल-सा ढक्कन चढ़ता है। खोलने पर टक, बंद करने पर टक। एक छोटी सी आवाज़ से बाथरूम की सफाई को पूर्ण विराम देने वाला यह एक कोमल पड़ाव है।"},"ICON-2050":{"nm":"बाथ ऑयल ड्रॉप बॉटल","de":"थोड़ा सा झुकाते ही एक-एक बूंद टपाक से खुशबूदार तेल टपकता है। टब में फैलती चमक और हल्की सी महक। ऐशो-आराम कहने के लिए सादा और रोज़मर्रा कहने के लिए कोमल, बस एक बूंद।"},"ICON-2051":{"nm":"एमेनिटी ट्रे डिवाइडर","de":"खानों में बंटी ट्रे पर छोटी-छोटी शीशियां अपनी-अपनी जगह ढूंढ लेती हैं। बिखरने पर अस्त-व्यस्त और इकट्ठा होने पर सलीकेदार लगने वाली चीज़ें। एक बंटवारा ही व्यस्त सुबह की व्यवस्था बनाए रखता है।"},"ICON-2052":{"nm":"सौना ऑवरग्लास स्टैंड","de":"जब तक रेत पूरी तरह बह न जाए, कम से कम तब तक पीठ को गर्माहट देने का यह एक कोमल वादा है। स्टैंड पर तिरछी टिकी घड़ी जब समय गिनती जाती है, घने भाप के बीच इंसान थोड़ी देर के लिए कुछ भी न होते हुए विश्राम करता है।"},"ICON-2053":{"nm":"शीप-इयर स्टीम टॉवल","de":"तौलिये के सिरों को लपेटकर भेड़ के कानों जैसा खड़ा करते ही शीशे में दिखने वाला चेहरा हल्के से ढीला पड़ जाता है। गर्म भाप के बीच, हर कोई थोड़ी देर के लिए बचपन में लौट आने वाला भांप घर का एक छोटा सा अनुष्ठान है।"},"ICON-2054":{"nm":"सौना वॉटर लैडल","de":"कलछी भरकर पानी उठाकर तपे हुए पत्थरों पर डालते ही छिश्श—भाप छत तक उठ जाती है। उस पल पूरा शरीर गर्म धुंध में डूब जाता है, और पुरानी थकान पसीने की बूंदों में धीरे-धीरे घुलकर मुक्त हो जाती है।"},"ICON-2055":{"nm":"फुट बाथ टेम्परेचर रॉड","de":"पानी में छड़ी डुबोते ही निशान धीरे से बात कहने लगते हैं। न बहुत गर्म, न ठंडा—बस ठीक वही तापमान। पैर की उंगलियां डुबाने से पहले, सबसे पहले पानी का हाल पूछने वाली यह एक उंगली है।"},"ICON-2056":{"nm":"स्टीम स्टोन टॉन्ग्स","de":"अभी-अभी तपा हुआ पत्थर खाली हाथ से पकड़ा नहीं जा सकता। चिमटा उसे मज़बूती से पकड़कर उठाते ही तपिश एक सुरक्षित दूरी पर पहुंच जाती है। सावधानी भी एक हुनर है, यह भांप घर चुपचाप कह देता है।"},"ICON-2057":{"nm":"सौना कुशन मैट","de":"गर्म फर्श पर एक चटाई बिछाते ही पीठ छूने वाली जगह और नरम हो जाती है। पसीने में भीगे दिन को बिना कुछ कहे थाम लेने वाली यह चटाई। विश्राम, आखिरकार, फर्श से सही दूरी से ही आता है।"},"ICON-2058":{"nm":"फुट बाथ सॉल्ट पाउच","de":"एक मुट्ठी मोटा नमक घोलकर गुनगुने पानी में डालते ही पैरों की उंगलियों से थकान धीरे-धीरे पिघलने लगती है। नमकीन भाप जब पिंडलियों को लपेटने लगती है, तब दिनभर चली हुई यात्रा आखिरकार थम जाती है।"},"ICON-2059":{"nm":"सौना सेंट स्टोन डिश","de":"तपे हुए पत्थर पर इत्र की कुछ बूंदें टपकाते ही गर्म हुई खुशबू सौना में धीरे-धीरे फैल जाती है। आंखें बंद करो तो यह जंगल है या फूलों का बगीचा, पता नहीं चलता। यह नाक से की जाने वाली सबसे छोटी यात्रा है।"},"ICON-2060":{"nm":"हीट पैक कोज़ी कवर","de":"गर्म पैक को पूरी तरह लपेटकर गर्माहट को देर तक थामे रखने वाला कपड़ा। ठंडा न पड़ जाए इसलिए कसकर गले लगाने वाले मन की तरह ही, पेट पर टिकी यह गर्माहट रातभर साथ निभाती है।"},"ICON-2061":{"nm":"अरोमा डिफ्यूज़र स्टिक्स","de":"पतली छड़ियां खुशबू को सोखकर धीरे-धीरे कमरे में फैला देती हैं। हर सांस के साथ हल्के से रचती महक। जिस जगह में हम रहते हैं वह धीरे-धीरे उस व्यक्ति की खुशबू से मिलती-जुलती बनती जाती है, यह उसी का एक तरीका है।"},"ICON-2062":{"nm":"सन लाउंजर एंगल हैंडल","de":"घुंडी को धीरे-धीरे घुमाते ही पीठ का सहारा सरककर झुक जाता है। थोड़ा धूप की ओर, थोड़ा छांव की ओर। सबसे आरामदेह कोण को टटोलकर ढूंढना, पूरी तरह अपना ही गणित है।"},"ICON-2063":{"nm":"पूलसाइड नॉन-स्लिप स्ट्रिप","de":"पानी के किनारे के चारों ओर लिपटी फिसलन-रोधी पट्टी। छपाछप करते और खुशी से दौड़ते छोटे पैर सुरक्षित रुक सकें, इसलिए अनदेखी जगह पर चुपचाप बिछाई गई सुरक्षा की यह एक फिनिश-लाइन है।"},"ICON-2064":{"nm":"ट्यूब एयर वॉल्व लूप","de":"हवा को बंद रखने वाले छोटे ढक्कन पर एक कड़ी करीने से बांध दी गई है। ताकि ट्यूब से निकला ढक्कन पानी में बहकर न जाए। गर्मी की दोपहर में होने वाले एक छोटे से नुकसान को पहले से रोकने की यह सूझबूझ है।"},"ICON-2065":{"nm":"पूल स्टेप एंट्री कैप","de":"पानी में उतरती सीढ़ी के सिरे को नरमी से ढकने वाला ढक्कन। नंगे तलवे छिलें नहीं, इसलिए प्रवेश के पहले कदम को नरमी से थाम लेता है। क्योंकि हर शुरुआत हमेशा सावधान होनी चाहिए।"},"ICON-2066":{"nm":"सन लाउंजर कुशन स्ट्रैप लूप","de":"कुशन फिसलकर न गिरे इसलिए डोरी बांधने वाली एक कड़ी। हवा चले तब भी अपनी जगह टिके रहने का एक छोटा वादा। एक गांठ ही दोपहर की सुस्ती को उसी जगह जकड़ लेती है।"},"ICON-2067":{"nm":"पूल विला ड्रिंक स्लॉट बोर्ड","de":"पूल के किनारे पेय का गिलास सटाकर टिकाने वाला बोर्ड। जोश से पानी में छपाके मारने पर भी न हिलने वाली एक जगह। हाथ की पहुंच में ठंडक रखना, गर्मी की दोपहर को लंबा खींच देता है।"},"ICON-2068":{"nm":"वेट स्विमसूट हैंगिंग क्लिप","de":"टपकते हुए स्विमसूट को उठाकर हवा के हवाले चुपचाप छोड़ दिया जाता है। धूप में सूखने के दौरान क्लिप ख़ामोशी से थामे खड़ी रहती है। अगली बार तैरने के लिए, एक शांत और कोमल प्रतीक्षा।"},"ICON-2069":{"nm":"पैरासोल पोल बेस वेट","de":"पैरासोल हवा में डगमगाए नहीं इसलिए खंभे के नीचे रखा जाने वाला भारी वज़न। छांव एक जगह देर तक टिकी रहती है, यह सब इसी वज़न की बदौलत है। भरोसा अक्सर सबसे नीची जगह में छिपा होता है।"},"ICON-2070":{"nm":"पूल टेम्परेचर फ्लोट चिप","de":"पानी पर तैरते हुए तापमान चुपचाप बता देने वाली एक छोटी चिप। बहुत ठंडा हो तो लाल, ठीक हो तो नरम रंग की। एक ही रंग से पानी का मिज़ाज पढ़ लेने वाली यह एक प्यारी सी भविष्यवक्ता है।"},"ICON-2071":{"nm":"टेंट ज़िपर पुल टैसल","de":"ज़िपर के सिरे पर लटका छोटा फुंदना खींचते ही टेंट का दरवाज़ा सरककर खुल जाता है। उंगलियां टटोलें भी तो तुरंत पकड़ में आ जाने वाला यह हैंडल गहरी रात के आने-जाने को प्यार से राह दिखाता है।"},"ICON-2072":{"nm":"टेंट कॉर्ड बटरफ्लाई पिन","de":"डोरी को तितली के आकार में जकड़कर मज़बूती से थामने वाली पिन। हवा में फड़फड़ाता कपड़ा आख़िरकार शांत हो जाता है। शिविर की रात को ऐसी ही छोटी और सक्षम गांठें चुपचाप संभालती हैं।"},"ICON-2073":{"nm":"ग्लैम्पिंग मैट एयर वॉल्व","de":"मुंह लगाकर फूं-फूं फूंकते ही मैट धीरे-धीरे फूलने लगती है। भरने के बाद वॉल्व को कसकर बंद करते ही फर्श नरम हो जाता है, और सितारों भरे आसमान तले लेटने की जगह आखिरकार पूरी बनती है।"},"ICON-2074":{"nm":"टेंट सीलिंग हैंगिंग हुक","de":"टेंट की छत पर लटकाकर लालटेन या रूमाल टांगने वाला हुक। सिर के ऊपर की छोटी जगह तक बचत से इस्तेमाल करने की गृहस्थी की सूझबूझ। यह मानो आसमान की जगह छत पर एक सितारा टांग देना है।"},"ICON-2075":{"nm":"स्लीपिंग बैग रोल बैंड","de":"लपेटकर रखे गए स्लीपिंग बैग को न खुलने देने वाली बांधी हुई पट्टी। सुबह होते ही फिर से छोटा हो जाने वाला बिस्तर। जाने की तैयारी करना, कल रात की गर्माहट को करीने से समेटकर रख देना है।"},"ICON-2076":{"nm":"टेंट एंट्रेंस शू रेस्ट बोर्ड","de":"टेंट के प्रवेश द्वार पर रखा जूतों को करीने से थामने वाला बोर्ड। मिट्टी बाहर, भीतर स्वच्छता। एक दहलीज़ से भीतर और बाहर को प्यार से बांटने वाला, शिविर की यह एक छोटी सी शालीनता है।"},"ICON-2077":{"nm":"ग्लैम्पिंग लालटेन हैंगिंग हुक","de":"लालटेन टांगने वाला मुड़ा हुआ काँटा। यहां टांग देते ही रोशनी तंबू के भीतर गोल-गोल फैल जाती है। अंधेरे में एक रोशनी टांगने की वह जगह ही आज रात हमारा बैठक कमरा बन जाती है।"},"ICON-2078":{"nm":"टेंट वेंट रोल क्लिप","de":"हवादान को लपेटकर पकड़े रखने वाली क्लिप। हवा की एक राह हल्की सी खुली रखते ही तंबू के भीतर की हवा कहीं ज़्यादा ताज़ा हो जाती है। एक छोटी सी दरार ही रातभर सांस लेने की जगह चुपचाप बना देती है।"},"ICON-2079":{"nm":"टेंट फ्लोर ग्राउंड मैट","de":"टेंट के फर्श पर बिछाकर मिट्टी और नमी रोकने वाली चटाई। घास के ऊपर भी सूखी सेज बिछा देने वाली एक परत। प्रकृति में रहते हुए भी उससे भीगे न, इसके लिए यह चुपचाप साथ निभाती है।"},"ICON-2080":{"nm":"बारबेल कॉलर रिंग","de":"बारबेल के दोनों सिरों पर, प्लेट न फिसले इसलिए भरी जाने वाली रिंग। उठाने वाले के वज़न पर पूरा भरोसा करने वाली एक छोटी कुंडी। जब सुरक्षा मज़बूती से थामे रखे, तभी सीमा एक पायदान आगे बढ़ती है।"},"ICON-2081":{"nm":"केटलबेल हैंडल कैप","de":"लोहा हथेली कुतरता हुआ आखिरी सेट—यह एक छोटी टोपी दर्द को गायब कर देती है। वज़न उठाने से ज़्यादा मुश्किल आखिर तक पकड़े रहना है, यह हाथ सबसे पहले उस आखिरी पल में जान जाता है।"},"ICON-2082":{"nm":"प्लेट इंसर्ट वेज","de":"प्लेट हल्की सी भी हिले तो उठाने से पहले ही मुद्रा बिगड़ जाती है। दरार में पतली सी घुसाई गई कील बिना आवाज़ के केंद्र थामे रखती है। मज़बूती हमेशा किसी अदृश्य जगह से चुपचाप शुरू होती है।"},"ICON-2083":{"nm":"बारबेल लैच क्लिप","de":"कुंडी बंद करने वाली उंगलियों में हिचक नहीं होनी चाहिए। टक की वह एक छोटी सी लॉक की आवाज़ ही अगली पूरी हरकत को थाम लेती है। शरीर सबसे पहले सीखता है एक क्लिप पर भरोसा टिकाना।"},"ICON-2084":{"nm":"प्लेट वेट कलर चिप","de":"हर वज़न पर अलग रंग की चिप—अंक न पढ़ पाओ तब भी हाथ पहले पहचान लेता है। लाल भारी, नीला हल्का—रंग से वज़न याद रखने की यह बात। शरीर, आश्चर्यजनक रूप से, ताकत को आंखों से ही आंकता है।"},"ICON-2085":{"nm":"केटलबेल फ्लोर रेस्ट","de":"फर्श को छूने वाली सतह को चौड़ा करने वाले इस आधार की बदौलत लकड़ी का फर्श गड्ढेदार नहीं होता। कसरत के निशान बस पसीने और मांसपेशियों में ही रहें, इतना काफ़ी है। पैरों तले भी घाव न छोड़ने की एक छोटी सोच यहां बिछी है।"},"ICON-2086":{"nm":"बारबेल सेंटर मार्क","de":"डंडे के ठीक बीच में उकेरा गया निशान बाएं-दाएं संतुलन का आधार बिंदु है। बीच को ठीक-ठीक पकड़ने वाला हाथ हिलने-डुलने को आधा कर देता है। केंद्र कहां है यह जानते ही, आख़िरकार सुरक्षित रूप से उठाया जा सकता है।"},"ICON-2087":{"nm":"प्लेट स्टोरेज रैक","de":"इस्तेमाल की गई प्लेट फिर अपनी जगह लौट जाती है। रैक पर वज़न के क्रम में करीने से टंगा यह दृश्य अगले व्यक्ति के लिए एक ख़ामोश परवाह है। एक सलीकेदार जगह ही सबसे भरोसेमंद सुरक्षा-यंत्र है, ऐसा कोई मानता है।"},"ICON-2088":{"nm":"प्लेट रोल-स्टॉप लेज","de":"फर्श पर रखी प्लेट का हल्के से लुढ़ककर पैर पर आ गिरना, यह हादसा हमेशा एक बेखयाल पल में आता है। रोक-किनार उस पल को चुपचाप रोक देता है। बड़ी मुसीबत बड़ी जगहों से नहीं, छोटी दरारों से लुढ़ककर आती है।"},"ICON-2089":{"nm":"बेंच बैकरेस्ट कुशन","de":"पीठ को थामने वाला कुशन बहुत सख्त हो तो सांस तक उथली हो जाती है। ठीक-ठाक सख्त और ठीक-ठाक नरम की यह सीमा-रेखा, बस वही महसूस कर सकता है जिसने देर तक बैठकर उंगलियों से टटोला हो।"},"ICON-2090":{"nm":"रैक हाइट एडजस्टमेंट पिन","de":"ऊंचाई तय करने वाली एक पिन से डंडा किसी के भी कंधे पर ठीक बैठ जाता है। अलग-अलग कद के लोग एक ही उपकरण मिल-जुलकर इस्तेमाल करें—यह एक छोटा सा एडजस्टमेंट छेद ही वह कोमल बराबरी रचता है।"},"ICON-2091":{"nm":"मशीन पुली कवर","de":"पुली को लपेटे कवर के भीतर केबल बिना आवाज़ के घूमती और घूमती है। घर्षण को भीतर छुपाकर हाथ को सिर्फ़ चिकनाई सौंपने वाला एक पुर्ज़ा। अच्छा उपकरण अपनी उठाई गई मेहनत कभी उजागर नहीं करता।"},"ICON-2092":{"nm":"बेंच लेग नॉन-स्लिप फीट","de":"चारों टांगों के सिरों पर लगे फिसलन-रोधी पैर बेंच को फर्श से मज़बूती से बांधे रखते हैं। जब यह हिले नहीं, तभी निश्चिंत होकर पूरी ताकत लगाई जा सकती है। स्थिरता, आख़िरकार, पैर के सिरे की एक छोटी घर्षण से ही शुरू होती है।"},"ICON-2093":{"nm":"रैक बारबेल होल्डिंग हुक","de":"डंडा टांगने वाला हुक हमेशा हाथ की पहुंच जितनी ऊंचाई पर होना चाहिए। थकी हुई बांह जहां आख़िर में डंडे को चुपचाप नीचे रखती है—वह एक बित्ता जगह ही आज की कसरत को सुरक्षित रूप से समाप्त करती है।"},"ICON-2094":{"nm":"मशीन वेट पिन हैंडल","de":"पिन लगाकर वज़न चुनने वाला हैंडल चिकना होना चाहिए ताकि नाखून न छिलें। वज़न बदलने की उस एक पल की छोटी सी हरकत में भी, इंसान की उंगलियों का ख़याल रखने वाली फिनिशिंग चुपचाप छिपी है, यह महसूस होता है।"},"ICON-2095":{"nm":"बेंच एंगल लॉक लीवर","de":"पीठ का कोण जकड़ने वाला लीवर ढीला हो तो मुद्रा धीरे से बिगड़ जाती है। टक की आवाज़ के साथ जम जाने वाले उस पल का भरोसा। परिचालक हर सुबह दरवाज़ा खोलते ही सबसे पहले यही आवाज़ चुपचाप जांचता है।"},"ICON-2096":{"nm":"रैक सेफ्टी बार रेस्ट","de":"बारबेल के हाथ से छूट जाने के सबसे बुरे क्षण में, सुरक्षा-डंडे का आधार उस वज़न को अपनी जगह थाम लेता है। नीचे हमेशा अदृश्य होकर इंतज़ार करता यह आधार होने से ही, इंसान आख़िरकार अपनी सीमा तक धकेलकर देख सकता है।"},"ICON-2097":{"nm":"मशीन केबल एंड कैप","de":"केबल के सिरे को समेटने वाली छोटी टोपी उधड़ने के खिलाफ आख़िरी गांठ है। धागे बिखरें नहीं, इसलिए उन्हें करीने से बांध देना—फिनिश की शान हमेशा उस अनदेखे आख़िरी बिंदु में ठहरती है।"},"ICON-2098":{"nm":"चॉक पाउच","de":"हाथों पर मलकर फिसलन मिटा देने वाला एक मुट्ठी सफेद पाउडर। मंच के पीछे के मेकअप की तरह अदृश्य होते हुए भी, आज की हर हरकत की स्थिरता इसी एक मुट्ठी से शुरू होती है। तैयारी हमेशा उंगलियों से ही शुरू होती है।"},"ICON-2099":{"nm":"ग्रिप ट्रेनिंग क्लिप","de":"भींचना और छोड़ना चुपचाप दोहराती एक छोटी क्लिप मुट्ठी की ताकत बढ़ाती है। पकड़ की ताकत बड़ी मांसपेशियों से धीरे बढ़ती है, इसलिए यह जल्दबाज़ी को चुपचाप उतार फेंकने का एक अभ्यास भी है।"},"ICON-2100":{"nm":"फिंगर स्प्रेडर बैंड","de":"उंगलियों के बीच फंसाकर धीरे-धीरे बाहर की ओर फैलाने वाला बैंड। सिर्फ़ भींचने वाली मांसपेशियां इस्तेमाल करने वाला हाथ फैलाने की ताकत फिर से पा लेता है। कसकर पकड़ने जितना ही, चुपचाप छोड़ देने में भी अभ्यास चाहिए, यह हाथ ही कहता है।"},"ICON-2101":{"nm":"चॉक-पाउडर डिब्बे का ढक्कन","de":"अगर पाउडर के डिब्बे का ढक्कन थोड़ा भी ढीला हो, तो पूरा बैग सफ़ेद हो जाता है। ठीक से बंद होने वाला एक छोटा-सा ढक्कन इस मामूली मुसीबत को पहले ही टाल देता है। रोक-थाम की सफलता हमेशा ढक्कन पर ही टिकी होती है।"},"ICON-2102":{"nm":"घुटना सहारा पट्टी","de":"घुटने को लपेटकर सहारा देने वाली पट्टी को ठीक उतने ही दबाव पर रुकना चाहिए। ज़्यादा कसने से खून रुक जाता है, ज़्यादा ढीला छोड़ने से कोई फ़ायदा नहीं होता, इसलिए एक अनुभवी हाथ उस नाज़ुक बीच के फ़ासले को याद से चुपचाप नाप लेता है।"},"ICON-2103":{"nm":"लचीली प्रतिरोध लूप डोरी","de":"खिंचने और वापस सिकुड़ने वाली लचीली डोरी बिना किसी भार के सोई हुई मांसपेशियों को जगा देती है। प्रतिरोध का भारी होना ज़रूरी नहीं। हल्के से खींचने पर भी शरीर हमेशा ईमानदारी से जवाब देता है।"},"ICON-2104":{"nm":"टखना भार थैली","de":"टखने पर बांधी गई रेत की थैली हर क़दम को भारी बनाकर खींच लेती है। थोड़ा-सा वज़न जोड़ते ही एक साधारण टहलना भी असली अभ्यास बन जाता है। रोज़मर्रा में हल्के से मेहनत जोड़ने की यह एक छोटी-सी समझदारी है।"},"ICON-2105":{"nm":"कलाई मज़बूती रोलर","de":"डोरी से लटके वज़न को कलाई से धीरे-धीरे लपेटकर ऊपर उठाने वाला रोलर। सबसे छोटा और सबसे ज़्यादा भुलाया जाने वाला जोड़ कलाई ही है, और यह सीधा-सा औज़ार उस भूली हुई ताक़त को चुपचाप फिर से जगा देता है।"},"ICON-2106":{"nm":"पकड़ मज़बूती रबर बॉल","de":"हाथ में मुट्ठी बंद-खोल की जाने वाली रबर की गेंद डेस्क पर बैठे-बैठे भी अभ्यास को धीरे-धीरे जारी रखती है। फुर्सत के पलों में जुटाई गई ताक़त एक ही बार में लगाई गई ताक़त से ज़्यादा टिकती है। निरंतरता हमेशा ऐसी छोटी-छोटी चीज़ों से ही बढ़ती है।"},"ICON-2107":{"nm":"हृदय-गति पट्टी बकल","de":"छाती पर बंधी पट्टी का बकल थोड़ा भी टेढ़ा हो जाए तो आंकड़े उछलने लगते हैं। अपने ही दिल की धड़कन सुनने के काम में भी सबसे पहले एक मज़बूत बंधन चाहिए होता है। हर मापन आख़िरकार बिना किसी फ़ासले के कसे हुए जुड़ाव से ही शुरू होता है।"},"ICON-2108":{"nm":"नब्ज़ क्लिप","de":"उंगली के सिरे को हल्के से दबाने वाली क्लिप चुपचाप नब्ज़ गिनती है। लगाकर सांस को थामो, तो छोटी-सी स्क्रीन पर दिल की लय साफ़-साफ़ उभर आती है। शरीर हमेशा बिना झूठ बोले अपनी असली हालत बता देता है।"},"ICON-2109":{"nm":"कलाई मॉनिटर बैंड केस","de":"कलाई-मॉनिटर को संभालकर रखने वाला यह केस छोटा तो है, पर अपने ही घर के सदस्य को पहचानता है। जो छोटा उपकरण जितनी आसानी से खो सकता है, उसे उतना ही ज़्यादा लौटने के लिए एक घर चाहिए। संभालकर रखना भी अपनेपन का एक तरीक़ा है।"},"ICON-2110":{"nm":"दौड़ लक्ष्य झंडी पिन","de":"दौड़ने वाले के लक्ष्य-बिंदु को ठीक-ठीक चिह्नित करने वाली छोटी झंडी पिन। \"बस यहीं तक\" कहकर पहले से तय किया गया एक बिंदु थके हुए पैरों को आख़िर तक ले जाता है। मन का फ़िनिश लाइन हमेशा अपने ही हाथ से गाड़ा जाता है।"},"ICON-2111":{"nm":"धड़कन दीपक टोपी","de":"दिल की धड़कन के साथ चुपचाप टिमटिमाने वाली एक छोटी-सी बत्ती। जलने-बुझने की उस लय को गौर से देखते रहो, तो मन अचानक भर आता है यह सोचकर कि जीवित होना इतनी नियमित बात हो सकती है।"},"ICON-2112":{"nm":"गिनती मनका डोरी","de":"एक बार में एक मनका सरकाकर गिनती की जाती है। संख्या को दिमाग़ में याद रखने की ज़रूरत नहीं, उंगलियां तुम्हारी जगह याद रख लेती हैं। गिनती हाथों को सौंप दो, तो मन पूरी तरह सिर्फ़ हरकत में ही टिका रह सकता है।"},"ICON-2113":{"nm":"रक्त-ऑक्सीजन क्लिप पैड","de":"उंगली के सिरे में लगाई गई क्लिप-पैड चुपचाप ख़ून में ऑक्सीजन की मात्रा पढ़ लेती है। सांस की अनदेखी गहराई जब आंकड़े के रूप में उभरती है, तब समझ आता है कि शरीर की देखभाल आख़िरकार ग़ौर से देखने भर का काम है।"},"ICON-2114":{"nm":"हृदय-गति रंग पट्टी","de":"व्यायाम की तीव्रता को रंगों में बांटने वाली यह पट्टी एक नज़र में बता देती है कि अभी मैं कितनी मेहनत कर रहा हूं। नीला यानी आराम, लाल यानी हद। रंग ही यहां एक कोमल भाषा बनकर एक चुपचाप किया गया वादा बन जाता है।"},"ICON-2115":{"nm":"मापन जेली कैप्सूल","de":"शरीर की हालत मापने वाला यह छोटा जेली कैप्सूल एक ही दाने में दिन-भर की जानकारी संभालकर रखता है। इसके पारदर्शी ख़ोल के भीतर चाहे जो भी हो, ख़ुद को थोड़ा और जानने की चाहत भी वहीं समाई होती है।"},"ICON-2116":{"nm":"पसीना तौलिया हुक","de":"कहीं भी यूं ही न डालकर हर बार अपने ही हुक पर टांगने की यह छोटी-सी आदत पूरे कमरे को सलीके से बचाए रखती है। तौलिये के लौटने की जगह पहले से तय कर देने वाली इस चीज़ की तरह, सफ़ाई हमेशा छोटी-छोटी बातों में ही चमकती है।"},"ICON-2117":{"nm":"पानी की बोतल ढक्कन डोरी","de":"पानी की बोतल के ढक्कन से जुड़ी छोटी डोरी ढक्कन के लुढ़ककर कहीं दूर चले जाने की मुसीबत रोकती है। जो चीज़ आसानी से खो सकती है, उसे शरीर से बांध रखने की समझदारी—एक छोटी-सी डोरी दिन-भर की झंझट चुपचाप समेट ले जाती है।"},"ICON-2118":{"nm":"पंखा पत्ती","de":"पूरा खोलने पर हवा उठाने वाली पंखे की पत्ती। गर्म दिनों में पसीना सुखाने वाले पुराने पंखे की तरह, सबसे सादा औज़ार ही सबसे ठंडी राहत देता है। हवा की एक लहर हमेशा उंगलियों के सिरे से ही जन्म लेती है।"},"ICON-2119":{"nm":"कूलिंग तौलिया थैली","de":"भिगोते ही ठंडा हो जाने वाला तौलिया रखने की एक छोटी थैली। गर्मी दूर करने वाला वह एक टुकड़ा कपड़ा वहां चैन से सोया रहता है, फिर थकी हुई गर्दन पर धीरे से उतरकर दोपहर की गर्मी चुपचाप ले जाता है।"},"ICON-2120":{"nm":"बूंद तश्तरी","de":"टपकने वाली बूंदों के गिरने की जगह पहले से बनाकर रखी गई तश्तरी। बहने का दोष देने की बजाय, पकड़ने की जगह पहले दे देना। रसोई की मेहरबानी हमेशा ऐसे ही बिना आवाज़ के टिकी रहती है।"},"ICON-2121":{"nm":"पंखा दिशा पत्ती","de":"सीधे टकराती हवा जिस पल एक छोटी पत्ती के सहारे थोड़ा मुड़ जाती है, उमस भरे अभ्यास-कक्ष की हवा आख़िर सांस ले पाती है। धारा बदलना हमेशा ऐसे ही मामूली कोण से हुआ है।"},"ICON-2122":{"nm":"माथा हेडबैंड","de":"चेहरा धोते वक़्त अगर आगे के बाल भीग जाएं, तो पूरा दिन उलझ जाता है। बालों को माथे से हल्के से ऊपर उठाकर रखने वाली यह पट्टी, शीशे के सामने खड़े इंसान को पांच सूखे मिनट थमा देती है। इसके बिना होने पर ही इसकी क़दर समझ आती है।"},"ICON-2123":{"nm":"पानी का गिलास क्लिप स्टैंड","de":"जब डेस्क के किनारे पर गिलास ख़तरनाक ढंग से डगमगाता है, तो यह क्लिप चुपचाप एक तरफ़ से थाम लेती है। बिना गिराए बीता दिन, यह याद दिलाता है पानी का एक घूंट, कि किसी ने तुम्हारी जगह किनारा थाम रखा था।"},"ICON-2124":{"nm":"खिड़की हुक हैंडल","de":"पूरी बंद खिड़की घुटन देती है और चौड़ी खुली खिड़की ठंड। इन दोनों के बीच का ठीक-ठाक फ़ासला यह हुक-हैंडल याद रखता है। हवादार रखना आख़िरकार दिल का काम है—बस उतना ही खुला छोड़ देना जितना काफ़ी हो।"},"ICON-2125":{"nm":"कॉर्क ब्लॉक कोना टोपी","de":"टकराकर चोट हमेशा नुकीले कोने से ही लगती है। इसलिए कॉर्क का एक टुकड़ा तराशकर हर कोने पर चढ़ा दिया जाता है। नरमी से लिपटी हुई यह जगह अब किसी के घुटने को दर्द नहीं देती।"},"ICON-2126":{"nm":"बोल्स्टर पट्टा हैंडल","de":"लंबे तकिये को उठाना सोचने से ज़्यादा झंझट भरा काम है। एक पट्टा लगा दो, तो वह एक ही हाथ में आराम से आ जाता है। भारी चीज़ को हल्के से उठाने का तरीक़ा इस पर टिका होता है कि हैंडल कहां लगाया गया है।"},"ICON-2127":{"nm":"बेल्ट बकल कसनी","de":"कुछ दिन कमर एक निशान और कस ली जाती है, कुछ दिन एक निशान ढीली छोड़ दी जाती है। उस दिन की हालत को सबसे ईमानदारी से जानने वाली यह छोटी कसनी ही है। शरीर की सच्चाई को बिना कुछ कहे दर्ज करने वाली एक धातु।"},"ICON-2128":{"nm":"क्वार्टर-ब्लॉक सहारा","de":"चार टुकड़ों में कटा ब्लॉक फ़र्श को मज़बूती से थाम लेता है। न ज़्यादा ऊंचा, न ज़्यादा नीचा—बस उतना ही संतुलन। सहारा देने का मतलब है ख़ुद को नीचा करके ऊपर वाले को उठाना, यह चुपचाप दिखा देता है।"},"ICON-2129":{"nm":"अंडाकार बोल्स्टर कवर","de":"अंडे जैसे गोल तकिये को ठीक फिट होने वाला वस्त्र पहनाया जाता है। पसीना जज़्ब हो जाए तो बस उतार कर धो लो। रोज़ त्वचा से सटने वाली चीज़ को बदलने के लिए एक और परत ज़रूरी होती है, यह गृहस्थी जानती है।"},"ICON-2130":{"nm":"ब्लॉक समतल पच्चर","de":"फ़र्श थोड़ा-सा भी झुका हो, तो मेहनत से रखा हुआ सब कुछ हिलने लगता है। उस दरार में एक पतली पच्चर सरका दो, तो दुनिया फिर से समतल हो जाती है। सीधा करने के लिए किसी बड़े-भारी काम की ज़रूरत नहीं होती।"},"ICON-2131":{"nm":"पट्टा-सिरा गांठ मनका","de":"पट्टे का सिरा खुलकर बिखर न जाए, इसलिए एक मज़बूत गांठ बांध दी जाती है। सिरे को सलीके से बंद करने वाली डोरी लंबे समय तक चलती है। शुरुआत से ज़्यादा मुश्किल आख़िर तक निभाना होता है, यह एक छोटी गांठ सिखा देती है।"},"ICON-2132":{"nm":"घुटना कुशन तह-पैड","de":"सख़्त फ़र्श पर घुटना टिकाते ही उठने वाला वह चुभता दर्द। मुड़ने-खुलने वाला एक पैड घुटने और फ़र्श के बीच धीरे से आ बैठता है। यह किसी और के घुटने को अपनी जगह पर सहारा देने वाली मेहरबानी है।"},"ICON-2133":{"nm":"ब्लॉक फिसलनरोधी तली","de":"कितना भी मज़बूत ब्लॉक क्यों न हो, फिसल जाए तो बेकार है। तली में कोरे-कोरे उभार फ़र्श को कसकर पकड़ लेते हैं। न डगमगाने का राज़ हमेशा उस अनदेखी निचली सतह में छुपा होता है।"},"ICON-2134":{"nm":"संरेखण छड़ क्लिप","de":"छड़ों को सीधी क़तार में लगाकर क्लिप से थाम दिया जाता है। क़तार बिठाने की आदत रखने वाला हर कोई जानता है वह अजीब-सी छोटी संतुष्टि, जो टेढ़ी चीज़ों को एक सीध में रखने से उमड़ आती है।"},"ICON-2135":{"nm":"हैमस्ट्रिंग पट्टा फंदा","de":"जांघ के पिछले हिस्से में खिंचाव से चीख़ निकलने को हो, तो यह फंदा हाथ की पहुंच से दूर पंजे तक ख़ुद पहुंच जाता है। जहां अकेले पहुंचना नामुमकिन था, वहां डोरी की एक लड़ी पैर के लिए पुल बना देती है।"},"ICON-2136":{"nm":"पंजा-फैलाव पैड","de":"दिन-भर जूते में बंद रहे पैर की उंगलियों को भी सांस लेने की छुट्टी चाहिए। बीच-बीच में फैलाने वाले पैड पर पैर आख़िरकार अंगड़ाई लेता है। सबसे दूर की जगह से शुरू होकर आराम देने वाली शाम।"},"ICON-2137":{"nm":"मुद्रा कोण मापक","de":"अपनी मुद्रा कितने डिग्री टेढ़ी हो गई है, यह आंख से बिल्कुल अंदाज़ा नहीं लगता। जब मापक चुपचाप कोण बता देता है, तब जाकर शरीर सीधा खड़ा हो पाता है। न दिखने वाले झुकाव को दिखा देने वाली एक नाप-रेखा।"},"ICON-2138":{"nm":"श्रोणि संरेखण पच्चर","de":"कमर की हड्डी एक तरफ़ को झुककर अकड़ गई एक ऊंघती-सी दोपहर। एक पच्चर टिकाकर धीरे-धीरे केंद्र फिर से पाया जाता है। यह ज़बरदस्ती सीधा करना नहीं, बल्कि सही जगह फिर से ढूंढ देना है।"},"ICON-2139":{"nm":"कंधा-विस्तार पट्टी बकल","de":"सिकुड़े हुए कंधों को धीरे से खोलने वाली पट्टी। बकल कसते ही झुकी हुई पीठ धीरे-धीरे खुल जाती है। पूरी तरह खुले कंधों से गहरी सांस लो, तभी जाकर मंच पर झुककर अभिवादन करने वाली मुद्रा आती है।"},"ICON-2140":{"nm":"रीढ़ सहारा वेज","de":"पीठ के बल लेटते ही रीढ़ अपनी असली वक्र-रेखा बना लेती है। उस मोड़ के ख़िलाफ़ जाए बिना चुपचाप सहारा देने वाला वेज। अच्छे से आराम करने का तरीक़ा शरीर की जन्मजात वक्र-रेखा को स्वीकार करने से शुरू होता है।"},"ICON-2141":{"nm":"पंजा-खिंचाव पच्चर","de":"पैर के ऊपरी हिस्से को खींचने वाली स्ट्रेचिंग हमेशा कहीं न कहीं अधूरी रह जाती थी। सही पच्चर टिकाओ, तो न पहुंचने वाली गहराई तक ताज़गी भरा खिंचाव पहुंच जाता है। थोड़ा और दूर तक पहुंचने में मदद करने वाली एक छोटी ढलान।"},"ICON-2142":{"nm":"कलाई संरेखण आधार","de":"कीबोर्ड के सामने मुड़ी हुई कलाई में झुनझुनी उठने लगे, तो आधार धीरे से कलाई के नीचे आ जाता है। लंबे समय तक काम करने वाले हाथों का सबसे पहले ख़याल ऐसी ही निचली-सी जगह पर रहने वाली चीज़ें रखती हैं।"},"ICON-2143":{"nm":"कलाई सहारा रैप","de":"कुछ भारी उठाने से पहले, कलाई पर एक बार रैप लपेट लिया जाता है। जितना लपेटा जाता है, उतना ही मन भरोसे से भर जाता है। चोट लगने से पहले ही लपेट लेने की आदत लंबे समय तक व्यायाम करने वालों का चुपचाप राज़ है।"},"ICON-2144":{"nm":"आर्मबैंड फ़ोन थैली","de":"दौड़ते वक़्त फ़ोन कहां रखा जाए, यह हमेशा की चिंता थी। बांह पर बंधी यह थैली उस चिंता को अपने साथ ले जाती है। पसंदीदा गाना बांह से बांधकर दौड़ो, तो रास्ता काफ़ी छोटा-सा महसूस होता है।"},"ICON-2145":{"nm":"पकड़-यंत्र स्प्रिंग टोपी","de":"पकड़-यंत्र की स्प्रिंग का सिरा हथेली को न चुभे, इसलिए चढ़ाई गई टोपी। मुट्ठी बंद-खोल करते रहने के दौरान यह छोटा-सा ढक्कन हाथ और धातु के बीच शांति बनाए रखता है। न दिखने वाली जगह पर रखी गई एक फ़िक्र।"},"ICON-2146":{"nm":"दस्ताना अंगुश्ताना","de":"सिलाई में माहिर दादी की उंगलियों में हमेशा एक अंगुश्ताना रहता था। दस्ताने के सिरे पर लगा यह अंगुश्ताना उंगली के सिरे को बचाता है। लंबे समय तक काम करने वाले हाथों को संभालने की चाहत पीढ़ियों के पार भी हूबहू एक जैसी रहती है।"},"ICON-2147":{"nm":"पकड़ घट्टा पैड","de":"हथेली पर पड़ा घट्टा मेहनत का छोड़ा हुआ निशान है। उसके ऊपर लगाया गया पैड अगली बार को मुमकिन बनाता है। सख़्त हो चुकी जगह को फिर से लपेटकर, इंसान एक बार फिर लटक जाता है।"},"ICON-2148":{"nm":"हथेली फिसलनरोधी टेप","de":"हथेली बार-बार फिसलती रहे तो मेहनत से पकड़ी गई चीज़ छूट जाती है। खुरदुरा टेप लपेट लो, तो हाथ और औज़ार एक हो जाते हैं। न छूटने वाली ताक़त हैरानी की बात है कि घर्षण से ही आती है।"},"ICON-2149":{"nm":"बांह पसीना पट्टी","de":"व्यायाम के दौरान बहता पसीना कलाई तक पहुंचे, उससे पहले बांह की यह पट्टी उसे सोख लेती है। पसीना शर्म की बात नहीं है, यह पूरी तरह भीगा हुआ कपड़ा बिना कुछ कहे गवाही देता है।"},"ICON-2150":{"nm":"दस्ताना सुखाने वाला हैंगर","de":"यूं ही कहीं भी फेंक दो तो अगली सुबह मुसीबत बन जाती है, पर सलीके से टांग दो तो रातभर हवा ख़ुद उन्हें सुखा देती है। अच्छी तरह सूखे दस्तानों की साफ़ महक कल को ताज़गी से खोलती है।"},"ICON-2151":{"nm":"ट्रैकसूट ज़िप हैंडल","de":"पूरी तरह भीगे हाथों से एक नन्ही-सी ज़िप बिल्कुल नहीं पकड़ी जाती। एक हैंडल लगा दो, तो एक ही झटके में सीधी खिंच जाती है। एक मामूली-सी कड़ी घबराहट भरे पूरे एक मिनट को बचा लेती है।"},"ICON-2152":{"nm":"पसीना-निकास पैच","de":"शरीर की सबसे गर्म जगह पर हवादार पैच लगाया जाता है। बंद पड़ी गर्मी पैच के बीच से चुपके से निकल जाती है। घुटन भरे बीचोंबीच एक छोटा-सा सांस लेने का छेद खोल देने का काम।"},"ICON-2153":{"nm":"जूता सोल कुशन टुकड़ा","de":"पुराने सोल के घिसे हुए हिस्से को ही काटकर उसमें नया टुकड़ा फिट किया जाता है। पूरी चीज़ फेंकने के बजाय सिर्फ़ दर्द वाली जगह बदलने वाला यह स्पर्श। पैर के नीचे की एक छोटी मरम्मत दिन-भर के हर क़दम को हल्का बना देती है।"},"ICON-2154":{"nm":"ट्रैकसूट नंबर पैच","de":"पीठ का नंबर इस्त्री से दबाकर कपड़े में छाप दिया जाता है। गर्मी ठंडी होने के दौरान वह अंक कपड़े पर मज़बूती से जम जाता है। एक ही नंबर पहनने वाले लोगों के एक टीम बनने की शुरुआत की यह मुहर है।"},"ICON-2155":{"nm":"जूता-पंजा मज़बूती टोपी","de":"बार-बार टकराते पंजे वाले जूते की क़िस्मत को नोक पर लगी मज़बूती-टोपी चुपचाप रोक लेती है। सबसे पहले घिसने वाली जगह सबसे मज़बूत बनाई गई। जितना लंबा चलने वाला जूता, उतना ही उसका पंजा मज़बूत।"},"ICON-2156":{"nm":"ट्रैकसूट डोरी गांठ","de":"ट्रैकसूट की कमर-डोरी को एक बार खींचकर बांधते ही, ढीला कपड़ा शरीर से कस जाता है। न खुलने वाली यह मज़बूत गांठ ज़ोरदार हरकतों के दौरान भी सब कुछ सम्भाले रखती है।"},"ICON-2157":{"nm":"टखना मोज़ा फिसलनरोधी पट्टी","de":"टखने का मोज़ा बार-बार जूते के अंदर लुढ़ककर घुस जाने की वह झुंझलाहट। एक पट्टी उस फिसलन को थाम लेती है। छोटा होने के कारण अनदेखा किया गया एक मोज़ा आख़िरकार अपनी जगह बनाए रखता है।"},"ICON-2158":{"nm":"ट्रैकसूट बग़ल पसीना पैड","de":"सबसे ज़्यादा पसीना निकलने वाली जगह पर पहले से लगाया गया पैड। पूरी तरह भीग जाए तो भी कपड़े के बाहर कोई निशान नहीं दिखता। बिना दिखे चुपचाप काम करने वाली चीज़ें ही मंच को साफ़-सुथरा बचाए रखती हैं।"},"ICON-2159":{"nm":"जूता एड़ी खींच-फंदा","de":"जूता पहनने के बाद एड़ी का फंदा हल्के से खींचते ही पैर सीधा भीतर चला जाता है। झुककर बैठने की ज़रूरत न पड़ने वाली वह छोटी-सी सुविधा। व्यस्त सुबह में ऐसा एक फंदा ही सबसे काम आता है।"},"ICON-2160":{"nm":"मसाज-गन हेड कैप","de":"थपथपाई जाने वाली जगह के हिसाब से हेड बदल दिया जाता है। हर अकड़ी हुई मांसपेशी की अपनी अलग सही शक्ल होती है। दिन-भर झेल चुके कंधे को राहत की ठीक सही तीव्रता चुनकर देने वाली एक शाम।"},"ICON-2161":{"nm":"मसाज-गन चार्जिंग डॉक","de":"दिन-भर शरीर ढीला करने वाला हाथ भी चार्ज होकर ही जागता है। लाल बत्ती हरी होने तक थोड़ा आराम किया जा सकता है। टिमटिमाना थमते ही, अकड़े कंधों को फिर सहलाने की बारी चुपचाप क़रीब आ जाती है।"},"ICON-2162":{"nm":"मसाज-गन तीव्रता डायल","de":"हल्का, थोड़ा और, बस यहीं तक। डायल घुमाते हुए उंगलियों के सिरे चुपचाप अपने ही शरीर से मोल-भाव करते हैं। \"जितना दर्द हो उतना ही मज़बूत बनें\" वाला आज का वादा उन छोटे-छोटे निशानों के बीच साफ़-साफ़ लिखा रहता है।"},"ICON-2163":{"nm":"वाइब्रेशन-बॉल होल्डर रिंग","de":"अच्छे से लुढ़कने वाली गेंद को भी कभी थमने की जगह चाहिए होती है। यह गोल होल्डर लुढ़ककर चले जाने की उतावली इच्छा को चुपचाप गोद में लेकर, अगली बारी आने तक उसकी जगह सम्भाले रखता है। आराम भी व्यायाम का ही हिस्सा है।"},"ICON-2164":{"nm":"दबाव-छड़ी हैंडल टोपी","de":"सिरे पर लगी एक छोटी-सी टोपी से हथेली का दर्द धीरे-धीरे ग़ायब हो जाता है। सख़्ती और त्वचा के बीच हमेशा एक नरम परत चाहिए होती है। छूने वाली जगह को पहले गोल बनाकर तराशने वाला यह एक स्नेहमय बिंदु है।"},"ICON-2165":{"nm":"मूंगफली रोलर थैली","de":"मूंगफली के आकार का रोलर रखने की एक छोटी थैली। बैग के किसी कोने से लुढ़ककर बाहर आ जाए, तो साथ में कल का यह इरादा भी चला आता है कि आज भी शरीर का थोड़ा ख़याल रखा जाए। एक छोटी थैली वादा याद रखती है।"},"ICON-2166":{"nm":"पैर रोलर स्टैंड","de":"जहां पैर टिकाए जाएं वह जगह डगमगाए, तो आराम भी डगमगाता है। रोलर को थामे खड़ा यह स्टैंड फ़र्श को मज़बूती से पकड़कर थके हुए दोनों पैरों को बेफ़िक्र होकर टिकने की जगह बना देता है। भरोसा हमेशा न डगमगाने से आता है।"},"ICON-2167":{"nm":"रोलर कोर प्लग","de":"खाली भीतरी नली को बंद करने वाला एक छोटा प्लग। भीतर की न दिखने वाली जगह भरी हो, तभी बाहर का रूप बिगड़ता नहीं। लुढ़कते समय जिस जगह को कोई कभी नहीं देखेगा, उसे यह चुप-सा पुर्ज़ा बिना कुछ कहे थामे रखता है।"},"ICON-2168":{"nm":"मसाज-छड़ी सिरा टोपी","de":"छड़ी के सिरे पर गोल चढ़ाई गई टोपी। न घिसे, न खरोंच लगे—सिरे को बचाना आख़िरकार लंबे समय तक साथ रखने का रास्ता है। सबसे पहले चोट खाने वाली जगह को सबसे नरमी से लपेटने की चाहत है यह।"},"ICON-2169":{"nm":"टेप-रोल कटर","de":"एक हाथ से खींचते ही टेप साफ़-सुथरा कट जाता है। गांठ बांधने और काम पूरा करने में भी एक छोटी-सी तरकीब होती है, और यह ब्लेड सलीकेदार अंत के एहसास को अच्छे से जानता है। साफ़-सुथरा अंत अगले काम को हल्का बना देता है।"},"ICON-2170":{"nm":"टेप-सिरा चिपकाने वाली टोपी","de":"न खुले, इसलिए सिरे को चुपचाप दबाए रखने वाली टोपी। शुरुआत तो कोई भी कर सकता है, पर आख़िर तक चिपके रहना हमेशा मुश्किल होता है। आख़िरी हिस्से को थामे रखने वाला यह छोटा हाथ आज के काम को चुपचाप पूरा करने की ज़िम्मेदारी उठाता है।"},"ICON-2171":{"nm":"कलाई दबाव स्लीव","de":"थकी हुई कलाई पर एक परत लपेट दो, तो दर्द एक पल देर से आता है। किसी के चुपचाप थामे हुए हाथ की तरह, दबाव कभी-कभी सबसे कोमल सुरक्षा बन जाता है। यह कसना नहीं, सहारा देना है।"},"ICON-2172":{"nm":"टखना ब्रेस बकल","de":"बकल बंद होने की छोटी-सी \"क्लिक\" ध्वनि से मन शांत हो जाता है। टखने को मज़बूती से लपेट लो, तो एक क़दम और आगे बढ़ाने की हिम्मत धीरे-धीरे भर आती है। एक छोटी-सी आवाज़ ही एक भरोसेमंद शुरुआत बन जाती है।"},"ICON-2173":{"nm":"घुटना दबाव पट्टा कसनी","de":"डोरी जितनी खींचकर कसी जाती है, घुटना उतना ही मज़बूत महसूस होता है। न खुले, पर दर्द भी न हो—इन दोनों के बीच कहीं एक बिल्कुल सही जगह होती है। यह कसनी हर बार वह जगह बिना भूले याद रखती है।"},"ICON-2174":{"nm":"उंगली-टेपिंग कैंची","de":"पोर पर लपेटे टेप को बारीकी से काटने वाली छोटी कैंची। सिरा गोल होने के कारण त्वचा को चोट नहीं पहुंचती। जो औज़ार देखभाल के लिए बना हो, उसकी धार उतनी ही कोमलता से तराशी जाती है, यह कैंची चुपचाप दिखा देती है।"},"ICON-2175":{"nm":"दबाव-पट्टी लपेटने का फ्रेम","de":"खुली हुई दबाव-पट्टी को क़रीने से वापस लपेटने वाला एक फ्रेम। इस्तेमाल की गई चीज़ को मन लगाकर लपेटने वाला हाथ अगली बार खोलते समय भी उलझने नहीं देता। हर क़रीने से लिपटी परत में आज का सलीका बसा रहता है।"},"ICON-2176":{"nm":"पिंडली-रक्षक पट्टा","de":"पिंडली के आगे के हिस्से की रक्षा करने वाले पैड को बांधने वाला पट्टा। जहां चोट लग सकती है उसे पहले ही देख लेने वाला मन ख़ुद ही तैयारी है। मज़बूती से बंधी हुई टांगों के साथ मैदान में उतरो, तो मन का डर आधा कम हो जाता है।"},"ICON-2177":{"nm":"कोहनी ब्रेस क्लिप","de":"ब्रेस नीचे न सरके, इसलिए मज़बूती से थामे रखने वाली एक छोटी क्लिप। कागज़ का एक पन्ना पकड़ने जितनी मामूली, फिर भी इसके खुलते ही सब कुछ ढीला पड़ जाता है। एक छोटा-सा बंधन दिन-भर के भरोसे को मज़बूती से थामे रखता है।"},"ICON-2178":{"nm":"स्ट्रेचिंग लूप हैंडल","de":"फंदा पकड़कर शरीर को लंबा खींचो, तो कल से एक बित्ता और दूर पहुंची उंगलियां दिखाई देती हैं। खींचने के साथ जो फैलता है वह सिर्फ़ मांसपेशी नहीं। अकड़ा हुआ मन भी उसी बीच थोड़ा-थोड़ा खुल जाता है।"},"ICON-2179":{"nm":"पंजा-फैलाव स्पेसर","de":"दिन-भर जूते में बंद उंगलियों के बीच फैलाव दो, तो तंग जगह में हवा आ जाती है। दुनिया में कुछ चीज़ें ऐसी भी होती हैं जो कुछ देर अलग होकर ही चैन पाती हैं। पंजों को भी सांस लेने की जगह चाहिए होती है।"},"ICON-2180":{"nm":"पिंडली-राहत वेज बोर्ड","de":"पिंडलियों के नीचे पच्चर की तरह टिका दो, तो टांगें धीरे-धीरे ढीली पड़ जाती हैं। एक तिरछा कोण दिन-भर का वज़न चुपचाप बहा ले जाता है। थोड़ा तिरछा टेककर लेट जाना—यही कभी-कभी सबसे आरामदायक मुद्रा होती है।"},"ICON-2181":{"nm":"गर्दन-राहत आधार","de":"गर्दन टिकाकर कुछ देर आंखें बंद कर लो। भारी सिर को थोड़ी देर के लिए नीचे रख देना ठीक है, यह छोटा-सा आधार हमेशा उसी जगह से कंधों से धीमे से फुसफुसाता है। टेककर आराम करने में भी हिम्मत चाहिए होती है।"},"ICON-2182":{"nm":"स्ट्रेचिंग-छड़ी सिरा टोपी","de":"लंबी फैली छड़ी के सिरे पर लगी एक टोपी। सिरा नरम हो तो जहां भी छुए, बेफ़िक्री रहती है। चाहे किसी की भी ओर फैलाओ, पहले कोनों को गोल बनाकर तराश देना—फ़िक्र हमेशा ऐसे ही बिना आवाज़ के शुरू होती है।"},"ICON-2183":{"nm":"दबाव-कुशन उभार बोर्ड","de":"ऊबड़-खाबड़ उभारों पर शरीर लिटाओ, तो हर दबी हुई जगह से दिन-भर की थकान निकल जाती है। दर्द और राहत की उस सीमा-रेखा पर, दिन-भर अकड़े कंधे धीरे-धीरे मानो हार मानते हुए ढीले पड़ जाते हैं।"},"ICON-2184":{"nm":"विश्राम-श्वास रेत-घड़ी","de":"रेत के आख़िरी दाने तक गिर जाने तक लंबी सांस को स्थिर रखने का चुपचाप किया गया वादा। रेत की महीन धार आती-जाती सांस की लय चुपचाप गिनती रहती है। व्यस्त मन भी बीच में कुछ देर के लिए थम जाता है।"},"ICON-2185":{"nm":"तलवा दबाव-गेंद आधार","de":"तलवे के बीचोंबीच गेंद टिकाकर धीरे-धीरे दबाया जाता है। दिन-भर पूरे शरीर को थामे रखने वाले पैरों को अब यह छोटा आधार चुपचाप अपनी जगह सौंपते हुए कहता है कि अब तुम्हारी थमे जाने की बारी है। थामने वाली चीज़ों को भी कभी आराम की ज़रूरत होती है।"},"ICON-2186":{"nm":"कंधा-राहत फंदा डोरी","de":"कंधे पर टांगकर खींची जाने वाली फंदे वाली डोरी। अकड़ी हुई जगह की ओर डोरी खींचो, तो जमी हुई गांठ एक-एक निशान करके ढीली होती जाती है। आज़ाद होने के काम में भी कोई हाथ थामने वाला चाहिए होता है, यह बता देती है।"},"ICON-2187":{"nm":"लेन-रोप डिस्क","de":"पानी की राह बांटने वाली लेन-रस्सी की वह एक गोल कड़ी। बग़ल वाले तैराक से न टकराओ, इसलिए पानी पर खींची गई एक कोमल सीमा-रेखा। हर एक की राह की रखवाली करने वाला छोटा-सा बंटवारा सबको आख़िर तक कंधे से कंधा मिलाकर आगे बढ़ाता है।"},"ICON-2188":{"nm":"लेन-रस्सी तनाव हुक","de":"लेन-रस्सी को तानकर बांधने वाला हुक। ढीली हो तो लहरों में मुड़ जाती है, ज़्यादा खींचो तो टूट जाती है। सही तनाव ढूंढना मन को थामने के काम जैसा है, इसलिए हमेशा उन दोनों के बीच कहीं टटोलते हुए ढूंढा जाता है।"},"ICON-2189":{"nm":"लेन रंग टोपी","de":"हर लेन को अलग रंग देने वाला एक छोटा ढक्कन। दूर से भी अपनी राह एक नज़र में पहचानी जाए, इसलिए रंगा गया निशान। एक ही रंग से भटकने से बचाना—मार्गदर्शन बुनियादी तौर पर ऐसी ही छोटी मेहरबानी से शुरू होता है।"},"ICON-2190":{"nm":"लेन-रस्सी टांगने का बोर्ड","de":"इस्तेमाल न होने पर लेन-रस्सियों को क़रीने से टांगकर रखने वाला बोर्ड। अगली शुरुआत के लिए रस्सियों को सलीके से सुलझाने वाले हाथ में, आज के दिन को अच्छे से समेटने का शांत इरादा चुपचाप बसा होता है।"},"ICON-2191":{"nm":"लेन-रस्सी रील हैंडल","de":"हैंडल को गोल-गोल घुमाकर लंबी खुली रस्सी को लपेटा जाता है। बिखरी हुई चीज़ को समेटने के काम में हमेशा धैर्य चाहिए। एक चक्कर, फिर एक और चक्कर—अंत ऐसे ही बिना जल्दबाज़ी के धीरे-धीरे पूरा होता है।"},"ICON-2192":{"nm":"लेन-रस्सी सिरा गांठ क्लैंप","de":"रस्सी के सिरे की गांठ न खुले, इसलिए मज़बूती से थामने वाला क्लैंप। एक भी छोटा-सा टुकड़ा फिसलने नहीं देता। आख़िर तक ध्यान रखने वाला हाथ हो, तभी लंबी रस्सी बिना बिखरे अपनी क़रीने की शक्ल बनाए रखती है।"},"ICON-2193":{"nm":"लेन-रस्सी तैरन-मनका","de":"पानी पर उतराता लेन-रस्सी का तैरन-मनका। डूबने से बचने के लिए इसने अपने भीतर भरपूर हवा भर रखी है। कोई-कोई हल्कापन मेहनत से भरे गए ख़ालीपन से आता है, यह हिलती-डुलती लहरें हर बार तैरा कर दिखा देती हैं।"},"ICON-2194":{"nm":"लेन नंबर झंडी","de":"लेन का नंबर बताने वाली एक छोटी झंडी। हवा में फहराता कपड़े का वह एक टुकड़ा साफ़-साफ़ बता देता है—\"यह तुम्हारी जगह है\"। बिना भटके सीधे अपनी राह पर ले जाने वाला यह एक छोटा मगर स्पष्ट मील-पत्थर है।"},"ICON-2195":{"nm":"लेन-रस्सी जोड़ हुक","de":"लेन-रस्सी को अगली रस्सी से जोड़ने वाला हुक। टूटी हुई राह को फिर से जोड़ने वाले एक ही काँटे से पानी की राह आख़िरकार पूरी होती है। जोड़ना आख़िरकार दूर हो चुकी चीज़ों के बीच धीरे से हाथ बढ़ाने वाली एक छोटी धातु का काम है।"},"ICON-2196":{"nm":"स्टार्टिंग-ब्लॉक फुटप्लेट","de":"शुरुआती रेखा पर लगा फुटप्लेट पहली छलांग का पूरा भार अपने ऊपर ले लेता है। ज़ोर लगाकर उड़ने वाला वह 0.1 सेकंड, जिस मज़बूती पर पंजे टिकते हैं, वही एक पूरी दौड़ की शुरुआत को धकेल देती है। हर उड़ान मज़बूती से टिकने की जगह से ही शुरू होती है।"},"ICON-2197":{"nm":"स्टार्ट पकड़ बार","de":"शुरुआत के संकेत से ठीक पहले हाथ जिसे कसकर पकड़ लेते हैं, वह बार। कांपते मन को कहीं थाम लेना ज़रूरी है, वरना शुरुआत डगमगा जाती है। बस पकड़ने की एक जगह होना ही अगली एक हरकत को कहीं ज़्यादा साफ़ और मज़बूत बना देता है।"},"ICON-2198":{"nm":"बैकस्ट्रोक झंडी डोरी","de":"छत की ओर देखकर तैरने वाले को यह बता देने वाली झंडी-डोरी कि दीवार क़रीब आ गई है। न दिखने वाली चीज़ को पहले से बता देने वाली मेहरबानी। पीठ के पीछे का सावधानी से ख़याल रखने वाला एक संकेत आख़िरी स्ट्रोक को सुरक्षित बना देता है।"},"ICON-2199":{"nm":"टर्न-वॉल पैड","de":"दिशा बदलने वाली दीवार पर लगाया गया नरम पैड। ज़ोर से टकराने पर भी दर्द न हो, इसलिए मुड़ने वाली जगह को नरमी से लपेट रखा जाता है। लौटने के रास्ते पर हमेशा किसी की चुपचाप की गई फ़िक्र पहले से बिछी होती है।"},"ICON-2200":{"nm":"फ़िनिश टचपैड","de":"उंगली के सिरे के छूते ही सब कुछ ख़त्म हो जाता है। लंबी, सांस फुलाने वाली राह का अंत आख़िरकार इसी एक हल्की-सी थपकी पर टिका होता है। पहुंचना कोई बड़ी बात नहीं, बल्कि ठीक-ठीक सही जगह छूने का काम है, यह पैड चुपचाप जवाब देता है।"},"ICON-2201":{"nm":"स्टार्ट-प्लेटफ़ॉर्म फिसलन-पट्टी","de":"ढलान के छोर पर खड़े होकर हर कोई एक बार साँस रोक लेता है। उस छोटे-से डर को पार करके फिसलते ही, छपाक—पानी की बौछार के साथ हँसी फूट पड़ती है। शुरुआत हमेशा डर के एक छोटे कदम के आगे से ही होती है।"},"ICON-2202":{"nm":"मोड़-दूरी संकेत कोन","de":"दोराहे पर जब कदम ठिठक जाएँ, तो यह छोटा-सा निशान पहले बोल उठता है। यहीं से मुड़ जाओ, राह मत भटको। कोई इसी एक रंग को देखकर फिर से अपनी दिशा पा लेता है और चल पड़ता है।"},"ICON-2203":{"nm":"स्टार्टिंग-ब्लॉक कोण-पच्चर","de":"छलांग से ठीक पहले, वह आधा पल जब शरीर सबसे नीचे झुकता है। पैर की उँगलियाँ फिसलें नहीं, इसके लिए कोण को थामे यह छोटा सहारा वहाँ मौजूद रहता है। ऊँची उड़ान का हर क्षण इसी ढाल से जन्म लेता है।"},"ICON-2204":{"nm":"दीवार-कोना गद्दी टोपी","de":"खेलते-कूदते टकरा भी जाओ तो चोट न लगे, इसलिए कोने ने अपनी नुकीली धार को गोलाई के आगे झुका दिया। तुम्हें चोट न लगे, यही चाहत घिस-घिसकर दीवार से जा चिपकी है। सबसे स्नेहिल रक्षा अक्सर ऐसी ही ख़ामोश होती है।"},"ICON-2205":{"nm":"लाइफ़बॉय टाँगने का हुक","de":"आम दिनों में यह बस एक जगह है जहाँ कुछ टँगा रहता है। पर जिस पल कोई पानी में डूब जाए, सबसे पहले हाथ यहीं की ओर बढ़ता है। इस दुनिया में एक ऐसा भरोसा भी है जो कभी इस्तेमाल न हो, तभी सबसे अच्छा है।"},"ICON-2206":{"nm":"बचाव हुक डंडा","de":"जिस दूरी तक पहुँचना नामुमकिन था, उसे यह लंबी बाँह पल भर में समेट देती है। जब हाथ कम पड़ जाए, तो यह हुक ही हाथ बनकर आगे बढ़ता है। बचाव, आख़िर में, दूर खड़े किसी के लिए अपनी उँगलियों की नोक बढ़ा देने का ही काम है।"},"ICON-2207":{"nm":"पूलसाइड शावर हेड","de":"\"अंदर जाने से पहले ज़रूर धो लो।\" लाइफ़गार्ड के इस जाने-पहचाने जुमले की तरह सिर के ऊपर से पानी की धार बरस पड़ती है। एक ठंडी फुहार में ही दिन भर की धूल फिसलकर बह जाती है।"},"ICON-2208":{"nm":"फिसलनरोधी फ़र्श टाइल","de":"नंगे पाँव फिसलें नहीं, इसलिए बारीक उभरी हुई ये रेखाएँ बनाई गई हैं। किसी अनदेखी जगह से ये चुपचाप तलवों को थामे रहती हैं। सबसे मज़बूत सुरक्षा हमेशा ऐसी ही सादी जगहों में छिपी होती है।"},"ICON-2209":{"nm":"जल-गहराई संकेत पट्टिका","de":"पैर रखने से पहले, आँकड़ा पहले ही गहराई बता देता है। अनजाने में उतरने पर जो जगह डरा सकती थी, एक बार पढ़ लेने भर से मन उसका अंदाज़ा लगा लेता है। यह पट्टिका बस इतना ही करती है—एक छोटी-सी तैयारी में मदद।"},"ICON-2210":{"nm":"सुरक्षा-रेखा फ्लोट रस्सी","de":"पानी पर तैरती हुई रंग-बिरंगी रस्सी सीमाएँ बाँटती है। यहाँ तक सब सुरक्षित है, फ्लोट एक-दूसरे का हाथ थामे यही वादा करते हैं। सीमा हो, तभी बेफ़िक्र होकर मन भर के तैरा जा सकता है।"},"ICON-2211":{"nm":"पैर-स्नान कीटाणुनाशक टब","de":"पानी में उतरने से पहले नंगे पाँव थोड़ी देर यहीं ठहरते हैं। पैर की उँगलियों से शुरू होकर स्वच्छ होने की एक छोटी-सी रस्म इसमें बसी है। सफ़ाई हमेशा इसी एक कदम की सजगता से शुरू होती है।"},"ICON-2212":{"nm":"गीला-फ़र्श सावधानी कोन","de":"एक पीला शंकु धीरे से कदमों को थाम लेता है। \"यहाँ फिसलन है, ज़रा संभलकर।\" शब्दों की जगह रंग से जताई गई फ़िक्र। गिरते-गिरते बचे किसी के दिन को यह छोटी-सी चेतावनी चुपचाप संभाल लेती है।"},"ICON-2213":{"nm":"प्राथमिक-चिकित्सा दीवार कैबिनेट","de":"दीवार पर लगी यह सफ़ेद पेटी शायद ही कभी खुलती है। पर जिस पल यह खुलती है, वह किसी के लिए राहत बन जाती है। आपात स्थिति हमेशा सबसे नज़दीकी जगह पर ख़ामोशी से प्रतीक्षा करती रहती है।"},"ICON-2214":{"nm":"सतह छनाई जाली","de":"पानी की सतह पर तैरते पत्तों और धूल को यह चुपचाप उठा लेती है। निर्मलता अपने-आप नहीं आती, इसलिए रोज़ किसी हाथ को एक बार इसे बाहर निकालना पड़ता है। शांत जल के पीछे एक मेहनती जाली छिपी होती है।"},"ICON-2215":{"nm":"फ़र्श-सफ़ाई रोबोट नली","de":"जब सब सो जाते हैं, उस रात में भी यह फ़र्श को टटोलते हुए धीरे-धीरे घूमती रहती है। जिस वक़्त कोई नहीं देखता, उसी वक़्त का सबसे ईमानदार कारीगर। सुबह की वह पारदर्शिता दरअसल इस नली के रातभर खींचे गए निशान हैं।"},"ICON-2216":{"nm":"क्लोरीन ख़ुराक कनस्तर","de":"पानी को निर्मल रखने के काम में भी एक सही मात्रा होती है। ज़्यादा हो तो कठोर, कम हो तो धुँधला—इन दोनों के बीच का संतुलन। कोई अनदेखा हाथ रोज़ चुपचाप उस नाप को ठीक करता रहता है।"},"ICON-2217":{"nm":"जल-परीक्षण बोतल","de":"एक छोटी बोतल में पानी की एक घूँट भरकर आज का हाल पूछा जाता है। आँखों को भले सब एक-सा दिखे, पर आँकड़े झूठ नहीं बोलते। भरोसा ऐसी ही चीज़ है, जिसे रोज़ एक बार जाँचना पड़ता है।"},"ICON-2218":{"nm":"फ़्लोट-बोर्ड बटोरने वाला रेक","de":"पानी पर तैरते तख़्तों और तिनकों को एक साथ खींच लाने वाला लंबा रेक। बिखरी चीज़ों को समेटता यह हाथ मानो किसी के दिल जैसा लगता है। बिखराव को भी एक बार बुहार दिया जाए, तो वह सलीके से सज जाता है।"},"ICON-2219":{"nm":"नाली ढक्कन जाली","de":"पानी के बाहर निकलने की राह पर पहरा देती एक घनी जाली। यह चुपचाप छाँट लेती है कि किसे बहने देना है और किसे रोक लेना है। विदा करने में भी छन्नी की ज़रूरत होती है, यह छोटी-सी जाली बिना कुछ कहे यही समझा देती है।"},"ICON-2220":{"nm":"जल-तापमान फ्लोट","de":"पानी पर तैरता हुआ एक छोटा-सा गश्ती, जो तापमान भाँप लेता है। ठंडा है या ठीक-ठाक, शरीर छूने से पहले ही यह बता देता है, यही इसकी नरमी है। पानी में उतरने की पहली तसल्ली हमेशा इसी फ्लोट से शुरू होती है।"},"ICON-2221":{"nm":"पूल-कवर लपेटन छड़","de":"चौड़े ढक्कन को लपेटकर एक ओर समेट देने वाला हैंडल। कब फैलाना है और कब समेटना है, यह जानने वाला औज़ार भरोसेमंद लगता है। विश्राम के समय पानी को भी मानो एक रज़ाई ओढ़ा दी जाती है।"},"ICON-2222":{"nm":"स्किमर टोकरी डिब्बा","de":"सतह पर तैरता कचरा आख़िर में जाकर इसी टोकरी में जमा होता है। किसी अनदेखी जगह में गंदगी थामे रखने वाला यह पात्र है, इसीलिए ऊपर का पानी हमेशा साफ़ रहता है। सफ़ाई के पीछे मेहनत ढेर सारी जमा होती है।"},"ICON-2223":{"nm":"स्विम-कैप सुखाने की टाँगन","de":"पानी से भीगी स्विमिंग कैप को उलटा टाँग दिया जाता है। बूँद-बूँद टपकते हुए वह टोपी धीरे-धीरे साँस सामान्य करती है। सूखना, आख़िर में, प्रतीक्षा का ही दूसरा नाम है।"},"ICON-2224":{"nm":"स्विमसूट कंधा-पट्टी लूप","de":"पट्टी कंधे से फिसले नहीं, इसलिए उसे थामे रखने वाला यह छोटा लूप। किसी अनदेखी जगह से यह चुपचाप पहनावे की सलीक़ेदारी बचाए रखता है। सुघड़ता हमेशा ऐसी ही मामूली टेक पर पूरी होती है।"},"ICON-2225":{"nm":"स्विम-कैप व्यवस्था थैली","de":"भीगी हुई स्विमिंग कैप एक-एक करके अपनी जगह इसी थैली में पा लेती हैं। आसानी से बिखर जाने वाली चीज़ों को एक गोद में समेटने वाला छोटा-सा बसेरा। सलीका दरअसल कुछ न खोने की एक स्नेहिल आदत है।"},"ICON-2226":{"nm":"स्विमसूट चेस्ट पैड","de":"कपड़े के भीतर चुपचाप बैठा एक पैड। बाहर से भले न दिखे, पर पहनने वाले के कंधों को धीरे से तान देता है। कुछ भरोसे बाहर से नहीं, भीतर से ही चुपचाप भरे जाते हैं।"},"ICON-2227":{"nm":"स्विम-कैप नेम-टैग क्लिप","de":"स्विमिंग कैप के किनारे नाम की पर्ची दबाए रखने वाली छोटी क्लिप। एक-जैसी दिखने वाली चीज़ों के बीच यह साफ़-साफ़ कह देती है, \"यह मेरी है।\" एक निशान भर से सारी उलझन पल में सुलझ जाती है।"},"ICON-2228":{"nm":"स्विमसूट ज़िप लूप","de":"\"ज़रा पीठ की ज़िप ऊपर कर दोगे?\" अकेले जिस जगह तक हाथ नहीं पहुँचता था, वहाँ यह छोटा लूप हाथ की जगह लेकर ज़िप को ऊपर खींच देता है। आख़िरी एक कदम में साथ देने वाली एक स्नेहिल दूरी।"},"ICON-2229":{"nm":"स्विम-कैप मुड़ाव-रोधक पट्टी","de":"मुड़-मुड़कर आदत बना चुकी स्विमिंग कैप को सीधा करके टिका देती है। जो टेढ़ा हो चुका था, वह अपना आकार फिर से पा सके, इसमें चुपचाप मदद करने वाला सहारा। सीधा करने वाला हाथ हो, तभी कोई भी चीज़ फिर से सलीके में लौटती है।"},"ICON-2230":{"nm":"स्विमसूट कमर-डोरी कसनी","de":"कमर को ठीक-ठाक लपेटकर फिसलने से रोकने वाली यह कसनी। न ज़्यादा कसी हुई, न ढीली—बस उतनी ही, जितनी सही हो। आराम हमेशा इन्हीं दोनों के बीच कहीं बसा रहता है।"},"ICON-2231":{"nm":"स्विम-कैप उलटाई क्लैंप","de":"अंदर-बाहर हुई स्विमिंग कैप को पकड़कर एक झटके में ठीक कर देने वाली क्लैंप। उलटी हुई चीज़ को सही तरफ़ पलटने का यह सुख काफ़ी सुकून देता है। सलीके का छोटा-सा आनंद ऐसी ही मामूली बातों से आता है।"},"ICON-2232":{"nm":"किकबोर्ड हैंडल पट्टी","de":"किकबोर्ड हाथ से छूटे नहीं, इसलिए हाथ से लिपट जाने वाली पट्टी। पानी की धार में बहते हुए भी कुछ थामने को हो, यह बड़ी तसल्ली की बात है। पहली बार लात मारना सीखने वाले उस दिन की धड़कन आज भी इस पट्टी में बाक़ी है।"},"ICON-2233":{"nm":"पुल-बॉय कसनी पट्टी","de":"दोनों टाँगों के बीच दबाए बॉय को मज़बूती से थामे रखने वाली पट्टी। ढीली न पड़े, तभी पूरा ध्यान केवल तकनीक पर लग पाता है। अच्छे से थमी हुई चीज़ के ऊपर ही उस दिन का अभ्यास बित्ता-बित्ता गहरा होता जाता है।"},"ICON-2234":{"nm":"फ़िन दीवार टाँगन","de":"जब फ़िन्स दीवार पर एक क़तार में टँगे होते हैं, तो बिलकुल पानी किनारे आराम करती बतखों के झुंड जैसे लगते हैं। तैरना ख़त्म कर चुके ये पैर पानी की बूँदें झाड़ते हुए कल का इंतज़ार करते हैं। यह विश्राम भी मानो कहीं गोल-मटोल और प्यारा-सा है।"},"ICON-2235":{"nm":"किकबोर्ड कोना टोपी","de":"किकबोर्ड के कोने पर हल्के से चढ़ाई गई एक छोटी टोपी। टकराने पर चोट न लगे, घिसने पर ख़राब न हो, इसलिए यह किनारे को लपेटे रहती है। लंबे समय तक साथ रखने का राज़ कोनों से ही सँभालना शुरू करने में छिपा है।"},"ICON-2236":{"nm":"फ़िन भंडारण जाली","de":"बतख के जाल-पैरों जैसे दिखने वाले फ़िन्स जाली के भीतर धूप सेंकते हैं। पानी से अभी-अभी निकली बतखों के पंख सूखते जैसे, ये भी जाली में धीरे-धीरे सूखते हैं। अगली तैराकी के लिए एक इत्मीनान भरी झपकी।"},"ICON-2237":{"nm":"पुल-बॉय व्यवस्था टैग","de":"हर बॉय पर नाम की पर्ची लगाकर उसका मालिक साफ़-साफ़ बता दिया जाता है। जितनी जगह कई लोग मिलकर साझा करते हैं, उतना ही ज़रूरी है कि \"किसकी है\" यह स्पष्ट रहे, तभी मन शांत रहता है। एक छोटा-सा टैग ही व्यवस्था खड़ी करता है।"},"ICON-2238":{"nm":"किकबोर्ड जल-निकास टेक","de":"किकबोर्ड में जमा पानी लुढ़ककर बह जाए, इसलिए तिरछा रखा गया एक सहारा। जो भीतर भर गया है उसे ख़ाली करने से ही हल्कापन आता है, यह टेक चुपचाप यही सिखाती है। सूखने का पहला कदम है—ठीक से टिका देना।"},"ICON-2239":{"nm":"फ़िन पट्टी कसनी","de":"फ़िन की पट्टी को पैर में ठीक-ठाक कसने वाला यह छोटा पुर्ज़ा। ढीला हो तो निकल जाए, कसा हो तो चुभे—वह बारीक-सी सीमा। जाल-पैरों वाली बतख जैसे सहज तैरने के लिए बस यही एक बारीक फ़र्क़ चाहिए।"},"ICON-2240":{"nm":"किक रिदम चिप","de":"हर बार लात मारने पर ताल बताने वाली छोटी-सी चिप। एक, दो, तीन—जब लय शरीर में बस जाती है, तो पानी भी कब गीत बन जाता है, पता ही नहीं चलता। तैराकी में भी ताल होती है, यह चिप धीरे से यही सिखा देती है।"},"ICON-2241":{"nm":"भीगा-स्विमसूट थैली","de":"पूल से निकले बैग के भीतर सबसे पहले जगह घेरने वाली हमेशा मैं ही होती हूँ। बाक़ी सामान भले नज़रें तरेरे, क्या करूँ, भीगे को अलग रखना ही पड़ता है ताकि सब सूखे रहें। नमी का पृथक-वास, यही वह स्नेहिल ज़िम्मेदारी है जो मैंने ओढ़ रखी है।"},"ICON-2242":{"nm":"पानी-निचोड़ प्रेस पट्टी","de":"नमी में यह गुण होता है कि दबाते ही चुपके से भाग जाना चाहती है। एक बार दबाओ, दूसरी बार दबाओ—पट्टी पर रखकर वज़न डालो, तभी वह हार मानती है। कलाई की ताक़त जिनके किसी काम न आती थी, उनके लिए ऐसा मंच मुश्किल से मिलता है।"},"ICON-2243":{"nm":"स्विम-बैग विभाजक पट्टी","de":"सब कुछ एक ही डिब्बे में भर दो, तो भीगा और सूखा एक-दूसरे में सट जाते हैं। इनके बीच धीरे से घुसकर एक रेखा खींच देने का काम। अगर एक ख़ाने से ही शांति आ जाए, तो शायद सुलह इतनी ही सीधी-सादी बात हो।"},"ICON-2244":{"nm":"वाटरप्रूफ़ जूता थैली","de":"रेत लगे जूतों को पूरा का पूरा निगल कर भी यह अपने चेहरे का भाव तक नहीं बदलती। भीतर चाहे जो हो, बाहर हमेशा सूखा रहे—यही जलरोधन की शिष्टता है। मुँह भारी रखने वाली थैली हर जगह स्वागत पाती है।"},"ICON-2245":{"nm":"स्विम-बैग निकास ढक्कन","de":"ढक्कन घुमाओ, तो बैग की तली में जमा हुआ पूरा दिन धार बनकर बह निकलता है। ख़ूब खेलने के बाद की सफ़ाई हमेशा इसी एक छोटे छेद पर टिकी होती है। बहने देना जानने में भी पूरी एक डिज़ाइन छिपी है।"},"ICON-2246":{"nm":"जल-अवशोषक चटाई","de":"दरवाज़े के आगे चुपचाप बिछी यह चटाई आने वाले हर पैर से नमी सोख लेती है। कोई पहचान न दे तो भी फ़र्श जानता है—आज भी कोई फिसला नहीं। ख़ामोश जगह में ख़ामोश संतोष बसता है।"},"ICON-2247":{"nm":"भीगी-कैप तश्तरी","de":"उतारकर फेंकी हुई स्विमिंग कैप को जब कोई ठिकाना नहीं मिलता, तो मैं उसे थाम लेती हूँ। तश्तरी कहलाकर भी खाने की जगह बूँदें ढोने की क़िस्मत मिली है, पर अगर काम किसी को जगह देने का हो, तो एक टेक भी सिर उठाकर खड़ी रह सकती है।"},"ICON-2248":{"nm":"तौलिया-सुखाने की क्लिप","de":"तार पर एक तौलिये को कसकर दबोच लेने का काम। हवा चाहे जितना छेड़े, न छोड़ने की यह ज़िद ही मेरा गर्व है। धूप में सूखकर मुलायम होने तक, एक बार पकड़ा हाथ पहले कभी नहीं छूटता।"},"ICON-2249":{"nm":"वाटरप्रूफ़ पाउच टाँगन","de":"हुक पर टँगते ही, भटकते हुए पाउच को आख़िरकार एक पता मिल जाता है। दीवार का बस एक कोना उधार लेकर लटके रहने भर से ही सही, खोने का डर न हो ऐसी जगह से बढ़कर भरोसेमंद और क्या होगा।"},"ICON-2250":{"nm":"स्लाइड प्रवेश कलाई-पट्टी","de":"बारी की प्रतीक्षा में चुपचाप धड़कता उत्साह इस एक छोटी पट्टी में पूरी तरह बँधा है। कलाई पर बँधने के बाद ही स्लाइड की क़तार में हलचल शुरू होती है, तो शायद प्रवेश दरअसल कलाई पर एक वादा बाँध लेने का ही नाम है।"},"ICON-2251":{"nm":"वॉटर-स्लाइड मैट टुकड़ा","de":"पैरों तले टूट जाने का पता भी नहीं चलता, लोग बेफ़िक्र होकर दौड़ते रहते हैं। फिसलन रोकने के लिए बिछाई गई यह जगह, जब उसका एक टुकड़ा ग़ायब होता है, तभी उसका होना उजागर होता है। इस दुनिया में ऐसी बहुत-सी चीज़ें हैं जिन्हें केवल उनकी ख़ाली जगह से याद किया जाता है।"},"ICON-2252":{"nm":"लॉकर-चाबी वाटरप्रूफ़ पट्टी","de":"लॉकर की चाबी को पानी से बचाना ही मेरी उम्रभर की नौकरी है। कलाई पर लिपटकर मैं भी साथ छपाकते हुए तैरता हूँ, पर उस एक चाबी को हमेशा सूखा रखता हूँ। मुझे खो दो तो कपड़े तक न मिलें, तो इतना कहना काफ़ी है कि मैं एक भारी ज़िम्मेदारी वाला अफ़सर हूँ।"},"ICON-2253":{"nm":"स्लाइड स्टार्ट संकेत बत्ती पैनल","de":"लाल से हरे में बदलने का वह छोटा-सा पल, स्लाइड के ऊपर मौजूद हर दिल एक साथ धड़क उठता है। शुरुआत की इजाज़त देने का यह अधिकार—इस नन्हे-से संकेत-पैनल में इतना बड़ा रोमांच समाया होगा, किसे पता था।"},"ICON-2254":{"nm":"लेज़ी-रिवर लाइफ़ वेस्ट बकल","de":"लेज़ी-रिवर में तैरते-बहते शरीर को मज़बूती से थामे रखने वाली बकल। \"क्लिक\" की वह आवाज़ आए, तभी बेफ़िक्र होकर धार के हवाले हुआ जा सकता है। भरोसा कभी-कभी ऐसे ही एक छोटे ताले से शुरू होता है।"},"ICON-2255":{"nm":"वेव-पूल संकेत झंडा","de":"लहरें कब आएँगी, यह पहले ही सबको बता देता है। झंडा ऊपर उठे तो जयकार, नीचे उतरे तो पल भर साँस लेना। हिलोरें लेते पूल के किनारे लय बाँधने का काम, कमाल की बात है, एक टुकड़ा कपड़ा ही करता है।"},"ICON-2256":{"nm":"स्लाइड नंबर हार","de":"कौन-सी क़तार में खड़े हो, यह गले में लटकाए फिरो तो कोई उलझन नहीं रहती। एक नंबर की पर्ची से बारी तय हो जाने का यह नज़ारा—व्यवस्था अक्सर ऐसे ही एक छोटे हार से शुरू होती है।"},"ICON-2257":{"nm":"कलाई-पट्टी रीचार्ज टोकन","de":"कलाई की पट्टी पर हल्के से छुआओ, रीचार्ज पूरा। न नक़द न कार्ड लिए पानी में घूमने का यह ज़माना है, और यह छोटा-सा टोकन ही पूरे बटुए का काम कर देता है। जितनी हल्की कलाई, उतना ही हल्का मन।"},"ICON-2258":{"nm":"वॉटर-कैनन ग्रिप टोपी","de":"कसकर पकड़ने पर ही मज़ा देने वाली वॉटर-कैनन की मूठ। एक टोपी निकल जाए तो निशाना लगाना तो दूर, बस हाथ में घूमती रहती है—भरी गर्मी की पानी-लड़ाई की हार-जीत इसी एक छोटे-से समापन पर टिकी है।"},"ICON-2259":{"nm":"रेत-महल मीनार साँचा","de":"गीली रेत को दबाकर भरो और उलट दो, तो एक छोटी मीनार उठ खड़ी होती है। गिरना तय है यह जानते हुए भी फिर से बनाने वाले मन को मुझसे बेहतर कोई नहीं जानता। रेत के वास्तुकार के लिए साँचा ही नक्शा है।"},"ICON-2260":{"nm":"रेत-रेक दाँते","de":"कंघी करते जैसे रेत पर खींचो, तो सलीक़ेदार खाँचे रह जाते हैं। लहरें जल्द ही मिटा देंगी यह पैटर्न, यह जानते हुए भी दाँते मेहनत से रेखाएँ खींचते रहते हैं। मिट जाने वाली चीज़ को मन लगाकर गढ़ने में भी अपना ही एक सौंदर्य है।"},"ICON-2261":{"nm":"छाता-खंभा लंगर भार","de":"पैरासोल हवा में उड़ न जाए, इसके लिए पैरों के पास ख़ामोशी से टिका रहता है। छाया की रक्षा करने का काम चमकदार कपड़े का नहीं, बल्कि भारी-भरकम गड़े इस भार का है। अनदेखा वज़न ही सबसे भरोसेमंद होता है।"},"ICON-2262":{"nm":"रेत-छन्नी मूठ","de":"रेत हिलाकर छान लो, तो हाथ में सिर्फ़ सीपियाँ और छोटे ख़ज़ाने ही बचते हैं। मूठ पकड़कर हिलाओ-डुलाओ—समुद्र किनारे के ख़ज़ाने की खोज का आधा फ़ैसला इसी एक छन्नी से हो जाता है।"},"ICON-2263":{"nm":"सीपी-आकार रेत साँचा","de":"गीली रेत भरकर हल्के से थपथपाओ, तो हथेली-जितनी सीपियाँ किनारे-किनारे खिल उठती हैं। असली सीपी भले न खाई जा सके, पर यह आकार कोई भी बना सकता है। गर्मियों का एक सादा-सा जादू।"},"ICON-2264":{"nm":"छाता कोण-समायोजन पिन","de":"सूरज जब भी खिसकता है, छाते को भी उसके पीछे सिर घुमाना पड़ता है। एक पिन निकालकर फिर लगा दो, तो छाया चुपचाप जगह बदल लेती है। धूप से बचने की कला का सार इसी छोटे-से कोण में छिपा है।"},"ICON-2265":{"nm":"रेत-फावड़ा फल-नोक टोपी","de":"तेज़ फल की नोक पर चढ़ा दो, तो बैग के भीतर सब सुरक्षित रहता है। रेत खोदने वाली वीरता थोड़ी देर के लिए तह करके, एक टोपी चढ़ते ही यह सीधा-सादा खिलौना बन जाता है। धार को छुपाना जानना भी एक तरह की फ़िक्रमंदी है।"},"ICON-2266":{"nm":"बीच-मैट कोना क्लिप","de":"हवा जब चटाई का कोना उठाने की कोशिश करती है, मैं उसे कसकर काट लेती हूँ। रेत पर बिछी एक जगह को थामे रखना आख़िर चारों कोनों की ज़िद पर ही टिका है। फड़फड़ाहट-रहित दोपहर छोटी-छोटी क्लिपों की ही मेहनत है।"},"ICON-2267":{"nm":"छाता-छाया कपड़ा हुक","de":"छाते के खंभे पर हल्के से टाँग दो, तो भीगे कपड़े छाँव में सूखते हैं। धूप से बचें, हवा मिले—एक हुक से बनी अस्थायी तार। समुद्र-किनारे में भी घर-गृहस्थी की सूझबूझ बसी है।"},"ICON-2268":{"nm":"वाटरप्रूफ़ फ़ोन गले की थैली","de":"फ़ोन को समेटकर गले में टाँग लो, तो पानी के भीतर भी तस्वीर लेने का साहस जुट आता है। एक और पल क़ैद कर लेने की चाहत को जलरोधन से बचाए रखने का काम। यादों के मुहाफ़िज़ के हिसाब से यह काफ़ी दमदार है।"},"ICON-2269":{"nm":"भीगे-कपड़े वाटरप्रूफ़ पाउच","de":"उतारे हुए भीगे कपड़ों को बिना किसी शिकायत के पूरा-पूरा अपने भीतर समेट लेती है। बाक़ी सामान पर एक बूँद भी पानी न लगने देना ही मेरा स्वाभिमान है, इसलिए मुँह कसकर बंद रखे बैग के एक कोने की रखवाली करती हूँ। साफ़-सुथरी विदाई मुझसे ही शुरू होती है।"},"ICON-2270":{"nm":"वॉटर-सैंडल पंजा पट्टी","de":"नंगे पाँव की सैंडल उतर न जाए, इसलिए पंजे को धीरे से लपेटे रखती है। रेत पर कितना भी दौड़ो-भागो, एक पट्टी हो तो निश्चिंत रहा जा सकता है। कदमों की भरोसेमंद साथी, दिखे न दिखे, पर हमेशा साथ रहती है।"},"ICON-2271":{"nm":"वाटरप्रूफ़ कार्ड गले का केस","de":"प्रवेश-पत्र और कार्ड समेटे गले में लटककर जल-क्रीड़ा में साथ देती है। कुछ खोने की फ़िक्र किए बिना मन भर छपाकते रहो, इसलिए यह अपने ही शरीर को ढाल बनाकर कार्ड की रखवाली करती है। एक भरोसेमंद मुहाफ़िज़ की मुद्रा।"},"ICON-2272":{"nm":"गॉगल धुँध-रोधी कपड़ा थैली","de":"धुँधली हुई तैराकी चश्मे की भीतरी सतह को कपड़े से एक बार पोंछो, तो पानी के भीतर की दुनिया फिर से साफ़ हो उठती है। एक छोटी कपड़ा-थैली ही धुँधले दृश्य को खोलने की कुंजी है।"},"ICON-2273":{"nm":"गीली-रेत ब्रश","de":"पैर की उँगलियों के बीच की रेत तक कोमलता से झाड़ देती है। समुद्र में मस्ती से घूमने के निशान घर के दरवाज़े पर आख़िरी बार सँवारने वाला हाथ। ब्रश एक बार फिर जाए, तो दिनभर की रेत को भी आख़िरकार विदाई मिल जाती है।"},"ICON-2274":{"nm":"वाटरप्रूफ़ सिक्का ज़िप थैली","de":"कुछ सिक्कों को ज़िप के भीतर कसकर बंद रखती है। भीग जाए तो भी खनखनाहट वैसी ही रहती है, इसलिए दुकान तक जाने के आपातकालीन पैसे आख़िर तक बचाए रखती है। छोटी सही, पर सूझबूझ भरी थैली है।"},"ICON-2275":{"nm":"तौलिया-रोल बंधन","de":"लपेटकर बेलनाकार बनाए तौलिये को एक डोरी से बाँधो, तो वह सीधे बैग की पट्टी पर टँग जाता है। दोनों हाथ आज़ाद, तौलिया कंधे पर। हल्के सामान वाली जल-क्रीड़ा का राज़ इसी छोटे बंधन में छिपा है।"},"ICON-2276":{"nm":"वाटरप्रूफ़ पट्टी चाबी-रिंग टोपी","de":"चाबी को पानी से बचाने वाली पट्टी का आख़िरी बटन। टोपी जब \"क्लिक\" कर बंद हो जाए, तभी बेफ़िक्र होकर पूल में छलाँग लगाई जाती है। ताले के अंत की ज़िम्मेदारी उठाने वाला, छोटा पर बेदाग़ पूर्ण-विराम।"},"ICON-2277":{"nm":"स्नॉर्कल मुखपत्र प्लग","de":"मुँह में दबाते ही साँस की राह खुल जाती है, और समंदर के भीतर का नज़ारा आँखों के सामने आ जाता है। पानी के नीचे भी साँस लेने देने वाला यह छोटा-सा प्लग। साँस उधार देने का काम इतना रोमांचक हो सकता है, किसे पता था।"},"ICON-2278":{"nm":"मास्क धुँध-रोधी पैड","de":"मास्क का भीतरी हिस्सा धुँधला हो जाए, तो पानी के भीतर की सैर का सारा मज़ा भी फीका पड़ जाता है। एक पैड उस धुँध को रोक लेता है, इसलिए साफ़ नज़ारा दरअसल इस अनदेखी परत की ही मेहनत है।"},"ICON-2279":{"nm":"फ़िन पंजा कसनी क्लिप","de":"फ़िन के अगले हिस्से को पैर में ठीक-ठाक कसती है, ताकि बिना ढीलेपन के पानी को लात मारी जा सके। एक लात में लगी ताक़त कहीं बह न जाए, इसलिए क्लिप पंजे पर चुपचाप एक मज़बूत गाँठ बाँध देती है।"},"ICON-2280":{"nm":"मास्क पट्टी कवर","de":"मास्क की पट्टी बालों को न खींचे, इसलिए उसे मुलायमी से लपेटे रखती है। उतारते वक़्त हर बार होने वाली उस चुभन को मिटा देने वाली एक तह की फ़िक्रमंदी। एक छोटा कवर जो सँभालता है, वह हैरानी की बात है कि दरअसल स्नेह ही है।"},"ICON-2281":{"nm":"स्नॉर्कल निकास वाल्व टोपी","de":"साँस थामे रखने के काम में भी कहीं चुपचाप रिसाव की एक दरार होती है। एक छोटा वाल्व उस पानी की धार को धीरे से वापस मोड़ देता है, और साँस लेने की जगह को आख़िर तक बचाए रखता है। समंदर इस मामूली-सी चौकसी को सबसे कृतज्ञता से याद रखता है।"},"ICON-2282":{"nm":"फ़िन भंडारण हुक","de":"दीवार में गड़े एक हुक पर फ़िन्स सलीक़े से टँग जाएँ, तो बिखरे हुए उपकरण-कक्ष में भी एक व्यवस्थित शांति उतर आती है। किसी चीज़ को उसकी जगह पर रखना, अगली ग़ोताख़ोरी के लिए किया गया सबसे ख़ामोश वादा है।"},"ICON-2283":{"nm":"मास्क नाक-ख़ाना पैड","de":"नाक को हल्के से दबाए रखने वाला एक टुकड़ा पैड। पानी को घुसने से रोकने वाली इस छोटी-सी कोमलता की बदौलत, ठंडे समंदर में भी चेहरा अपना भाव नहीं खोता।"},"ICON-2284":{"nm":"स्नॉर्कल शीर्ष गार्ड","de":"स्नॉर्कल के सिरे को गोलाई से लपेटता यह गार्ड लहरें उछलकर आने पर चुपचाप पानी को धकेल देता है। जो पुर्ज़ा जितना अनदेखे रहकर काम करता है, वह उतनी ही गहराई से एक साँस की सुरक्षा को थामे रहता है।"},"ICON-2285":{"nm":"फ़िन तल्ला फिसलनरोधी पट्टी","de":"फ़िन के तल्ले पर चिपकी एक पतली पट्टी। भीगे डेक पर फिसले नहीं, इसके लिए पंजे जिस एक रेखा के घर्षण को थामे रहते हैं, वह यही है। सुरक्षा हमेशा ऐसी ही मामूली बनावटों में चुपचाप शुरू होती है।"},"ICON-2286":{"nm":"एयर-टैंक वाल्व टोपी","de":"हवा से भरे टैंक के वाल्व को ढाँपने वाली टोपी। धूल न बैठे, साँस की राह गंदी न हो। ढककर रखना दरअसल अगले इंसान की पहली साँस तक की पहले से की गई देखभाल है।"},"ICON-2287":{"nm":"रेगुलेटर मुखपत्र टोपी","de":"जो जगह होठों को छूती है, वह हमेशा सबसे साफ़ रहनी चाहिए। मुखपत्र पर चढ़ाई गई यह एक टोपी, खारी हवा और रेत से साँस के प्रवेश-द्वार को बिना कुछ कहे बचाए रखती है।"},"ICON-2288":{"nm":"वेटसूट ज़िप-खिंचाव लूप","de":"वेटसूट की ज़िप पर टँगा एक छोटा-सा लूप। ठंडे पानी से अकड़े हाथ भी एक झटके में उसे ऊपर खींच सकें, इसी सोच से यह लगाया गया है। कपड़े को कसकर बंद करने के काम में भी किसी की गहरी सोच बसी होती है।"},"ICON-2289":{"nm":"एयर गेज सुरक्षा टोपी","de":"बची हुई हवा बताने वाला यंत्र, उसके शीशे को लपेटने वाली सुरक्षा टोपी। क्योंकि आँकड़े कभी धुँधले नहीं पड़ने चाहिए। जो पैमाना जीवन को पढ़ता है, उसे उतनी ही मेहनत से पोंछकर ढाँपा जाता है।"},"ICON-2290":{"nm":"वेट-बेल्ट बकल","de":"कमर पर वज़न बाँधकर गहराई में उतरने वाले लोग। एक बकल के खुलने और बंद होने के उस पल में, ऊपर उठने और नीचे डूबने का चुनाव उँगलियों की नोक पर ख़ामोशी से जमा होता है।"},"ICON-2291":{"nm":"ग़ोता-लालटेन कलाई-पट्टी","de":"गहरे अंधेरे पानी में, कलाई पर बँधी एक पट्टी लालटेन को मज़बूती से थामे रहती है। हाथ छूट भी जाए तो रोशनी साथ चलती रहती है। अँधेरे के बीच एक छोटी लौ न खोना, इसीलिए इतना भरोसेमंद लगता है।"},"ICON-2292":{"nm":"श्वास-नली व्यवस्था क्लिप","de":"बिखरी हुई नलियों को एक साथ समेटने वाली छोटी क्लिप। उलझने को पहले ही रोक दिया जाए, तो अफ़रा-तफ़री के पल में भी हाथ नहीं भटकते। सलीका दरअसल भविष्य के अपने लिए की गई एक ख़ामोश मेहरबानी है।"},"ICON-2293":{"nm":"ग़ोता-दस्ताना उँगली सुदृढ़न","de":"हर उँगली की नोक पर जोड़ा गया मज़बूत कपड़ा। रस्सी खींचने और चट्टान थामने वाली जगह सबसे पहले घिसती है, इसलिए उस घिसाव को पहले ही गले लगाने के लिए एक अतिरिक्त परत चढ़ाई गई है।"},"ICON-2294":{"nm":"एयर-टैंक आधार रिंग","de":"भारी टैंक को सीधा खड़ा रखने वाली एक आधार रिंग। कहीं गिर न जाए ऐसे वज़न को गोलाई से समेटकर संतुलन देती है। सहारा देना दरअसल गिरने न देने के लिए अपना साथ दे देने की भावना है।"},"ICON-2295":{"nm":"सर्फ़बोर्ड फ़िन टोपी","de":"बोर्ड के नीचे लगे फ़िन की नुकीली धार को लपेटने वाली टोपी। रेत पर चलने पर चोट न लगे, इसलिए लहरों को चीरने वाली इस तलवार-सी धार को कुछ देर सुला देती है। विश्राम के समय हर कोई थोड़ा कुंद हो जाए तो भी कोई हर्ज़ नहीं।"},"ICON-2296":{"nm":"पैडल फल-नोक सुरक्षा टोपी","de":"चप्पू की धार की नोक की रक्षा करने वाली टोपी। चट्टान से टकराने पर आया खरोंच पानी की धारा को बिगाड़ न दे, इसके लिए यह आगे खड़ी होती है। नोक को सहेजो, तो एक बार का खेवा कहीं ज़्यादा दूर तक ले जाता है।"},"ICON-2297":{"nm":"कयाक चप्पू ग्रिप","de":"हथेली और चप्पू के मिलने की जगह पर लिपटी हुई ग्रिप। जहाँ पहले छाले पड़ते थे, उसे मुलायमी से थामकर, नदी के विरुद्ध बहते हुए भी हाथ को चप्पू से नाराज़ नहीं होने देती।"},"ICON-2298":{"nm":"सर्फ़ वैक्स भंडारण टिन","de":"वैक्स का एक टुकड़ा रखने वाला छोटा टिन का डिब्बा। बोर्ड पर पैर टिकाए रखने वाला वह जादू हमेशा इसी हथेली-जितने डिब्बे से निकाला जाता है। एक सुघड़ डिब्बे से ही आज की तैयारी शुरू होती है।"},"ICON-2299":{"nm":"लीश टख़ना कसनी लूप","de":"टख़ने और बोर्ड को जोड़ने वाली लीश को कसने वाला लूप। बड़ी लहर में बह भी जाओ तो तुम्हें नहीं छोड़ूँगी, यही एक गाँठ है। जुड़ाव दरअसल यह वादा है कि दूर बहने नहीं दिया जाएगा।"},"ICON-2300":{"nm":"पैडलबोर्ड एयर प्लग","de":"हवा भरने पर मज़बूत होने वाला बोर्ड, और उस साँस को क़ैद करने वाला यह प्लग। खोलो तो चपटा तह हो जाए, बंद करो तो पानी पर खड़ा हो जाए। एक छोटे-से प्लग में फूलने और पिचकने वाला पूरा दिन समाया है।"},"ICON-2301":{"nm":"कयाक सीट कुशन पट्टी","de":"वह पट्टी जो सीट पर कुशन को बांधे रखती है। देर तक बैठकर चप्पू चलाने वाली कमर और पीठ के लिए, यह मुलायमपन को फिसलने नहीं देती, अपनी जगह पर टिकाए रखती है। आराम को भी एक मज़बूत गाँठ की ज़रूरत होती है।"},"ICON-2302":{"nm":"सर्फ़बोर्ड नोज़ बम्पर","de":"बोर्ड के अगले सिरे को लपेटे हुए बम्पर। जहाँ टकराव सबसे ज़्यादा होता है, उस नोक पर यह गद्दी इसलिए चढ़ाई गई है ताकि वही पहले घिस जाए। जो आगे बढ़ता है, उस जगह पर नरमी रखना — यह लंबे समय तक साथ निभाने की प्रतिज्ञा है।"},"ICON-2303":{"nm":"वॉटरप्रूफ़ बैग बकल","de":"एक बूंद भी अंदर न जाने देने के लिए दो-तीन बार मोड़कर बंद की जाने वाली बकल। किसी प्यारी चीज़ को सूखा रखने के काम में हमेशा हाथ एक बार और चलता है। कसकर बंद करने वाला वह एक पल ही सुकून बन जाता है।"},"ICON-2304":{"nm":"फ़ुटसल गोल जाल का टुकड़ा","de":"गोलपोस्ट को हिला देने वाले जाल का एक टुकड़ा। यह हर धागे में उस पल की जयकार को याद रखता है जब गेंद जाल में समा गई थी। हर गाँठ में एक गोल बसा है, और हर घिसे हुए हिस्से में उस दिन का मैच अब भी जीवित है।"},"ICON-2305":{"nm":"फ़ुटबॉल पंप नोज़ल","de":"हवा निकली हुई गेंद में साँस भरने वाली पंप नोज़ल। पिचककर लुढ़कती फिरी चमड़ा फिर से उछलने-कूदने लगती है। भरना यानी रुके हुए खेल को फिर से खड़ा कर देना।"},"ICON-2306":{"nm":"कॉर्नर फ़्लैग स्टैंड","de":"मैदान के कोने में झंडे को सीधा खड़ा रखने वाला स्टैंड। यह सीमा बताने वाला एक छोटा-सा चिह्न भर है, पर उसी एक बिंदु से मिट्टी का मैदान आख़िरकार स्टेडियम का आकार पाता है।"},"ICON-2307":{"nm":"शिन गार्ड पट्टी","de":"पिंडली की गार्ड को टांग से बांधने वाली पट्टी। जिस जगह बार-बार चोट लगती है, उसे मज़बूती से थामे रखती है, ताकि तीखी धक्का-मुक्की में भी हर कदम बेख़ौफ़ रहे।"},"ICON-2308":{"nm":"स्टड बदलने की पिन","de":"घिसे हुए स्टड को नए से बदलने की पिन। पैर की नोक के वे छोटे-छोटे दाँत, जो घास को जकड़ते हैं। फिसलने से बचना है तो कभी-कभी पैरों तले से ही नए सिरे से खड़ा होना पड़ता है।"},"ICON-2309":{"nm":"फ़ुटबॉल वाल्व कैप","de":"गेंद के साँस लेने के छेद को बंद करने वाली छोटी वाल्व कैप। यह प्रवेश द्वार पर पहरा देती है ताकि भरी हुई हवा रिसकर न निकल जाए। कसाव बनाए रखना, अगले मैच तक भी अपनी धार न खोने जैसा ही है।"},"ICON-2310":{"nm":"लाइन मार्कर कोन","de":"ज़मीन पर रेखा खींचकर राह बांटने वाला कोन। यहाँ तक हमारी टीम, वहाँ से विरोधी। एक छोटा-सा कोन बिखरे हुए खाली मैदान को नियमों वाले खेल के मैदान में बदल देता है।"},"ICON-2311":{"nm":"फ़ुटसल जूता धूल ब्रश","de":"फ़ुटसल जूतों की दरारों में फँसी मिट्टी-धूल झाड़ने वाला ब्रश। मैच ख़त्म होने पर जूतों पर भी दिन भर की मिट्टी जमा हो जाती है। झाड़ता हुआ हाथ, अच्छी तरह दौड़े पैरों के लिए एक ख़ामोश धन्यवाद है।"},"ICON-2312":{"nm":"गोलकीपर दस्ताना हैंगर","de":"गोलकीपर के दस्तानों को सुखाकर टांगने वाला हैंगर। यह वह जगह है जहाँ रोके गए शॉट्स जितने ही पसीने से भीगे हाथ पल भर आराम करते हैं। अगले मैच के लिए, गीलापन सूखता है और कठोर हुआ मन धीरे-धीरे ढीला पड़ता है।"},"ICON-2313":{"nm":"बास्केटबॉल रिम जाल हुक","de":"रिम में जाल टांगने वाले छोटे हुक। इन्हीं की वजह से गेंद के निकलते वक़्त वह सरसराती हुई आवाज़ आती है। स्कोर की वह मीठी आवाज़ असल में इन्हीं छोटे हुक से शुरू होती है।"},"ICON-2314":{"nm":"बास्केटबॉल हवा निकालने वाला औज़ार","de":"बहुत ज़्यादा कड़क गेंद की हवा थोड़ी कम करने वाला औज़ार। ज़्यादा कसाव उछाल को बेक़ाबू बना देता है। ठीक-ठाक कम करना — अच्छे स्पर्श वाली गेंद हमेशा इसी संतुलन से जन्म लेती है।"},"ICON-2315":{"nm":"बैकबोर्ड सेंसर पैड","de":"बैकबोर्ड के पीछे लगा सेंसर पैड। यह गेंद के छूने का पल संख्याओं में साफ़-साफ़ पढ़ लेता है। आँखों से छूट गया पल भी यह छोटी-सी इंद्रिय याद रखती है, इसलिए फ़ैसला उतना ही निष्पक्ष बनता है।"},"ICON-2316":{"nm":"ड्रिबल अवरोध कोन","de":"ड्रिबल अभ्यास के रास्ते पर क़तार में खड़े अवरोध कोन। इनके बीच इधर-उधर बचते हुए पैरों का हुनर बढ़ता है। राह रोकना भी एक तरह की दयालुता है, जो और बेहतर तरीक़े से निकल भागना सिखाती है।"},"ICON-2317":{"nm":"बास्केटबॉल वाल्व ब्रश","de":"गेंद के वाल्व छेद को साफ़ करने वाला छोटा ब्रश। धूल जम जाए तो सुई अंदर नहीं जाती, इसलिए अनदेखे प्रवेश द्वार को ही पहले साफ़ किया जाता है। भरने से पहले हमेशा ख़ाली करना और पोंछना ज़रूरी है।"},"ICON-2318":{"nm":"फ़िंगर टेपिंग रोल","de":"उँगली पर लपेटी जाने वाली टेप का एक रोल। मुड़े हुए जोड़ को मज़बूती से थामकर, गेंद फिर से पकड़ने का हौसला देता है। चोट को लपेटकर बांधना, न रुकने का एक छोटा-सा एलान है।"},"ICON-2319":{"nm":"जर्सी नंबर क्लिप","de":"पीठ की जर्सी पर नंबर टांकने वाली क्लिप। तुम्हारे नाम की जगह एक नंबर कोर्ट पर दौड़ता है। न गिरे इसलिए कसकर दबाई गई उस एक पकड़ में, आज कौन खेल रहा है यह साफ़-साफ़ लिखा जाता है।"},"ICON-2320":{"nm":"शूटिंग अभ्यास लक्ष्य रिंग","de":"रिम के भीतर लगाकर निशाना संकरा करने वाली लक्ष्य रिंग। घुसने की जगह छोटी करके, चूक को सहना सिखाती है। उस तंग दरवाज़े की ओर फेंकते-फेंकते, कब उँगलियाँ सटीकता सीख जाती हैं, पता ही नहीं चलता।"},"ICON-2321":{"nm":"बास्केटबॉल जूता तलवा पोंछन","de":"कोर्ट में क़दम रखने से पहले, घुटने मोड़कर पहले तलवे पोंछे जाते हैं। क्योंकि लकड़ी के फ़र्श पर फिसलन का एक भी निशान नहीं छोड़ना। साफ़ हुई उँगलियों से पहला क़दम रखते ही, आज का मैं कल से थोड़ा और मज़बूत हूँ।"},"ICON-2322":{"nm":"वॉलीबॉल नेट टेंशन हुक","de":"कसाव आँखों से नहीं दिखता। बस उस पल जब हुक डोरी को आख़िर तक खींचकर रुकता है, नेट एक बालिश्त भर तनाव से कोर्ट को दो हिस्सों में बाँट देता है। कोई अनदेखा हाथ जो संतुलन थामे रखता है, वही खेल को जगाता है।"},"ICON-2323":{"nm":"एंटीना फ़िक्सिंग क्लिप","de":"हवा में बार-बार हिलता रहा एंटीना एक क्लिप से सीधा खड़ा हो जाता है। एक छोटी चीज़ का बड़ी लड़खड़ाहट को थाम लेना। मंच के पीछे एक तार को चुपचाप कस देने वाला हाथ भी ठीक इतने ही दिल से चलता है।"},"ICON-2324":{"nm":"लिबेरो जैकेट हैंगर","de":"रक्षा में समर्पित अलग रंग की जैकेट दीवार पर टंगी अगले मैच का इंतज़ार करती है। भले चमकीली न हो, पर पूरे कोर्ट को थामे रखने वाला नाम है — लिबेरो। सबसे नीची जगह पर बैठी वह आँख है जो सबसे दूर तक देखती है।"},"ICON-2325":{"nm":"नी पैड पाउच","de":"फ़र्श पर जितना लुढ़को, घुटनों को उतनी ही बार चोट लगती है। पैड को सलीक़े से भीतर रखने वाली यह छोटी थैली जानती है — जो पहले अच्छे से गिरना सीख लेता है, आख़िर में वही सबसे दूर तक उड़ान भरता है।"},"ICON-2326":{"nm":"वॉलीबॉल प्रेशर गेज","de":"उँगली से हल्का थपथपाकर कुछ पता नहीं चलता। गेज की सुई हल्के से काँपकर एक निशान की ओर इशारा करती है। एक गेंद की साँस नापना ही मैच का पहला बटन है। ईमानदार दबाव से ही एक ईमानदार वक्र जन्म लेता है।"},"ICON-2327":{"nm":"डॉजबॉल लाइन टेप","de":"मैदान की मिट्टी पर टेप से खींचा गया एक गोला। इसका अंदर और बाहर आधे दिन की छुआछुई की एक पूरी दुनिया बांट देता है। रेखा खींचने वाला हाथ जानता है, नियम ही खेल की असली शुरुआत है।"},"ICON-2328":{"nm":"रेफ़री सीटी स्टैंड","de":"तीखी सीटी की आवाज़ थमते ही, यह अपनी जगह पर स्टैंड पर चुपचाप वापस रख दी जाती है। रेफ़री की साँस को सबसे क़रीब से सुनने वाली जगह। निष्पक्षता हमेशा अपनी जगह बनाए रखने के छोटे-से काम से शुरू होती है।"},"ICON-2329":{"nm":"टॉस अभ्यास दीवार लक्ष्य","de":"सुबह-सुबह, जब कोई पास लेने वाला नहीं होता, दीवार पर लगे निशाने की ओर हज़ारों बार उँगलियाँ उछाली जाती हैं। दीवार सबसे सहनशील साथी है। लौटती हुई गेंद थके हुए मुझे फिर से खड़ा कर देती है।"},"ICON-2330":{"nm":"नेट ऊँचाई नापने की छड़","de":"नेट एक उँगली भर भी नीचा हो तो खेल बिगड़ जाता है। नापने वाली छड़ उठाते ही उस पल, निष्पक्षता कोई संख्या नहीं, रोज़ की आदत बन जाती है। अनदेखी सटीकता ही कोर्ट की रखवाली करती है।"},"ICON-2331":{"nm":"स्टार्टिंग ब्लॉक कोण पिन","de":"झुकी हुई मुद्रा में पैर की नोक जिस कोण पर टिकती है, वही एक डिग्री शुरुआत तय करती है। एक पिन से ब्लॉक को स्थिर करके साँस साधी जाती है। शुरुआत की मुद्रा फ़िनिश लाइन तक चुपचाप साथ चलती है।"},"ICON-2332":{"nm":"ट्रैक लेन नंबर झंडी","de":"हर लेन में गड़ी छोटी झंडी हवा में अपना नंबर लहराती है। सब एक ही दिशा में दौड़ते हैं, पर हर किसी की अपनी अलग राह है। ट्रैक साथ-साथ चलना और अलग होना, दोनों को एक साथ अपने भीतर समेटे रखता है।"},"ICON-2333":{"nm":"रिले बैटन एंड कैप","de":"आख़िरी धावक के हाथ को छूने वाले उस पल के लिए, एंड कैप कोनों को गोल-मटोल बना देती है। रिले में सबसे क़ीमती चीज़ रफ़्तार नहीं, अगले इंसान को थमाया गया हाथ है।"},"ICON-2334":{"nm":"रिकॉर्ड मेज़रिंग टेप हैंगर","de":"निशान नापने वाले फ़ीते को उलझने से बचाने के लिए दीवार पर टांगा जाता है। यह वह जगह है जहाँ कल की दूरी और आज की दूरी साथ-साथ टंगी रहती हैं। बढ़त हमेशा पहले संख्याओं के छोटे-से फ़र्क़ के रूप में आती है।"},"ICON-2335":{"nm":"ट्रैक कर्व मार्कर कोन","de":"मोड़ के भीतरी हिस्से पर रखा एक छोटा कोन राह की मंशा बताता है। न बहुत अंदर घुसना, न बहुत बाहर बिखरना। जो अच्छे से मुड़ना जानता है, आख़िर में वही सबसे आगे रहता है।"},"ICON-2336":{"nm":"फ़िनिश लाइन रिबन क्लिप","de":"सबसे पहले किसी की छाती को छूने वाली उस रिबन को, क्लिप कसकर थामे इंतज़ार करती है। यह एक ऐसी डोरी है जो टूटने के लिए ही बनी है। किसी के एक सेकंड के लिए यह दिन भर हवा सहती है।"},"ICON-2337":{"nm":"स्टार्टिंग गन कवर","de":"धमाके जैसे संकेत की गूँज उठने तक, बंदूक की नली अपने कवर के नीचे सोई रहती है। शुरुआत को अपने भीतर थामे रखने वाला आवाज़ का एक पात्र। सन्नाटा जितना गहरा हो, पहली गूँज उतनी ही दूर तक फैलती है।"},"ICON-2338":{"nm":"हर्डल ऊँचाई समायोजन पिन","de":"जब भी लांघने की ऊँचाई एक पायदान बढ़ती है, पिन की जगह भी उसी के साथ बदल जाती है। डर भी ठीक उतना ही बढ़ता है। फिर भी पैर हर बार थोड़ी और ऊँची जगह का अंदाज़ा लगाते हुए दौड़ते चले जाते हैं।"},"ICON-2339":{"nm":"लैप काउंटर डायल","de":"कितने चक्कर बचे हैं यह उलझ जाए तो, डायल को एक पायदान घुमाया जाता है। घटती संख्या की वह छोटी-सी टिक-टिक टांगों में फिर से ताक़त भर देती है। बची हुई दूरी गिनता हाथ ही रफ़्तार को थामे रखता है।"},"ICON-2340":{"nm":"पोल स्टोरेज स्टैंड","de":"लंबे और लचकते डंडे को टिकने के लिए अपनी अलग जगह चाहिए। यह ऐसा औज़ार है जिसे उछलने के लिए झुकना पड़ता है, इसलिए इसे और भी सावधानी से खड़ा किया जाता है। सँभालकर रखी गई लचक ही सबसे ऊँची छलाँग को अपने भीतर समेटे रखती है।"},"ICON-2341":{"nm":"सैंड पिट लेवलिंग रेक","de":"पिछले खिलाड़ी के छोड़े पदचिह्नों को कुदाल से धीरे-धीरे बराबर किया जाता है। रेत का गड्ढा हर बार पहली बार की तरह फिर से समतल हो जाता है। किसी की छलाँग के लिए निशान मिटाता हुआ हाथ वहाँ, चुपचाप, मौजूद है।"},"ICON-2342":{"nm":"अप्रोच रन दूरी चिह्न पट्टी","de":"एक क़दम कम भी नहीं चलेगा, और एक क़दम ज़्यादा भी नहीं। ज़मीन पर लगी दूरी चिह्न पट्टी ईमानदारी से बता देती है कि पैर कहाँ रखना है। अच्छी अप्रोच रन बेतहाशा लालच से नहीं, शांत गणना से जन्म लेती है।"},"ICON-2343":{"nm":"डिस्कस ग्रिप","de":"उँगलियाँ फिसलें तो फेंकने से पहले ही फेंक दिया जाता है। डिस्क को लपेटती ग्रिप की खुरदरी सतह घुमाव को थामे रखती है। छोड़ने का समय हमेशा पकड़ के एहसास से ही शुरू होता है।"},"ICON-2344":{"nm":"शॉट पुट क्रेडल रिंग","de":"भारी लोहे की गेंद लुढ़क न जाए, इसके लिए क्रेडल रिंग उसे चुपचाप गोद में थामे रखती है। फेंकने से ठीक पहले की स्तब्धता को सहेजने वाला एक छोटा-सा घोंसला। ताक़त जितनी विस्फोटक होगी, टिकने की जगह उतनी ही मज़बूत चाहिए।"},"ICON-2345":{"nm":"जेवलिन टिप गार्ड कैप","de":"भाले की तीखी नोक पर चढ़ी कैप उसे एक नरम ख़ामोशी में ढँक देती है। दूर तक उड़ने वाला औज़ार जब चुपचाप लेटा रहता है, तो ख़तरा दयालुता से क़ाबू में आ जाता है। सुरक्षा भंडारण में भी बसी रहती है।"},"ICON-2346":{"nm":"हाई जंप बार सपोर्ट कैच","de":"हल्के-से छूने पर भी क्रॉसबार न गिरे, इसके लिए कैच उसे एक अद्भुत संतुलन से थामे रखता है। लांघना या न लांघना — उस काँपती रेखा की ज़िम्मेदारी यहीं है। निष्पक्षता छोटी-छोटी बारीकियों में बसती है।"},"ICON-2347":{"nm":"लैंडिंग मैट कॉर्नर एंकर","de":"लैंडिंग मैट का कोना उठ जाए तो चोट लग जाती है। एंकर चारों कोनों को मज़बूती से दबाए रखता है। सबसे ऊँची उड़ान भरा शरीर सबसे सुरक्षित तरीक़े से उतरे, इसलिए यह अनदेखे ही उसे थामे रहता है।"},"ICON-2348":{"nm":"थ्रोइंग सर्कल बाउंड्री टेप","de":"फेंकने की जगह की सीमा टेप की एक रेखा से खींची जाती है। उस रेखा पर पैर पड़ा या नहीं, इसी से रिकॉर्ड जीता या मरा जाता है। आज़ादी और नियम जहाँ मिलते हैं, वह एक पतली-सी रेखा का वादा है।"},"ICON-2349":{"nm":"बैलेंस बीम रबर फ़ुट","de":"संकरा बैलेंस बीम हिले नहीं, इसके लिए रबर का पैर फ़र्श को कसकर जकड़े रहता है। उसके ऊपर बिना काँपे बना संतुलन, दरअसल नीचे की उस अनदेखी मज़बूती से ही बना है।"},"ICON-2350":{"nm":"होराइज़ॉन्टल बार ग्रिप रैप","de":"हथेली फिसले नहीं, इसके लिए बार के हैंडल पर एक पट्टी लपेटी जाती है। गोल-गोल घूमते हुए घुमाव का राज़ चमक-दमक में नहीं, कसकर पकड़े हाथ में छुपा है। मैट पर टपका पसीना यह बात जानता है।"},"ICON-2351":{"nm":"रिंग स्ट्रैप हाइट कैच","de":"दोनों डोरियों की ऊँचाई हथेली भर भी अलग हो, तो पूरी हरकत बिगड़ जाती है। कैच उस संतुलन को चुपचाप थामे रखता है। बिल्कुल एक-सी ऊँचाई पर ही आख़िर आज़ाद उड़ान शुरू होती है।"},"ICON-2352":{"nm":"पॉमेल हॉर्स हैंडल कवर","de":"हैंडल को लपेटा हुआ कवर हथेली पर छाले पड़ने से रोकता है। गोल-गोल घूमती हरकत के पीछे एक ऐसा हाथ है जो अनगिनत बार छिला और फिर भरा है। सुरक्षा असल में अगले अभ्यास के लिए दिया गया एक कोमल वादा है।"},"ICON-2353":{"nm":"अनईवन बार्स स्पेसिंग पिन","de":"दोनों डंडों के बीच की दूरी को पिन से सटीक तरीक़े से मिलाया जाता है। शरीर के आने-जाने वाली वह ख़ाली जगह ही मंच बन जाती है। सटीक दूरी पर ही सबसे साहसी छलाँग जन्म लेती है, यह उँगलियाँ पहले जान लेती हैं।"},"ICON-2354":{"nm":"वॉल्ट स्प्रिंगबोर्ड स्प्रिंग कैप","de":"फुटबोर्ड को ठोकर मारते ही स्प्रिंग शरीर को आसमान की ओर धकेल देती है। कैप उस उछाल की ताक़त को कसकर लपेटे रखती है। सबसे छोटी अप्रोच रन ही सबसे लंबी उड़ान रचती है।"},"ICON-2355":{"nm":"मैग्नीशियम चॉक पाउच","de":"हाथों पर लगने वाला सफ़ेद चूरा फिसलन को मिटाने वाला एक छोटा-सा कवच है। थैली में हाथ डालकर निकालने की वह छोटी-सी रस्म डर को शांत कर देती है। घबराहट भी आख़िर उँगलियों पर ही क़ाबू में आती है।"},"ICON-2356":{"nm":"जिमनास्टिक्स बैंड रिस्ट रैप","de":"कलाई पर बैंड लपेटते ही मन की डोरियाँ भी साथ-साथ कस जाती हैं। डगमगाने वाले जोड़ को पहले से थाम लेना। एक अच्छी तरह बंधी हुई कलाई ही चुपचाप और साहसी घुमाव की इजाज़त देती है।"},"ICON-2357":{"nm":"ट्रैपीज़ सेफ़्टी लूप","de":"हवा में शरीर फेंकने से ठीक पहले, सेफ़्टी लूप एक अनदेखा हाथ बन जाता है। गिरने का डर मिटते ही आख़िर सबसे दूर तक उड़ान भरी जा सकती है। भरोसा ही उड़ान को पूरा करता है।"},"ICON-2358":{"nm":"टेनिस बॉल कैन कैप","de":"डिब्बे के मुँह को बंद करती कैप के नीचे, नई गेंदें दबाव थामे सोई रहती हैं। एक कैन खोलने की छोटी-सी 'पॉप' आवाज़ मैच की सिहरन जगा देती है। सील ताज़गी बनाए रखने का एक वादा है।"},"ICON-2359":{"nm":"रैकेट स्ट्रिंग टेंशन क्लैंप","de":"डोरी के कसाव को क्लैंप मज़बूती से दबोचकर आख़िर तक नहीं छोड़ता। क्योंकि एक डोरी का तनाव ही गेंद के उछाल को तय करता है। वह अनदेखा हाथ का एहसास इसी छोटी क्लैंप से शुरू होता है।"},"ICON-2360":{"nm":"टेनिस कोर्ट लाइन स्वीपर","de":"मैच ख़त्म होने पर कोर्ट की सफ़ेद रेखाओं के साथ-साथ धीरे-धीरे झाड़ा जाता है। मिट्टी-धूल हटते ही रेखा फिर से साफ़ उभर आती है। अगले मैच के लिए राह सँवारना, वह आख़िरी देखभाल ही कोर्ट को जीवित रखती है।"},"ICON-2361":{"nm":"रैकेट हेड गार्ड टेप","de":"रैकेट के किनारे को एक चक्कर लपेटते ही, तीखी टक्करें भी गोल-मोल होकर सह ली जाती हैं। मैं जानता हूँ कि किनारा ही सबसे पहले घिसता है। घिसने का बोझ अपने हिस्से लेना ही मेरा काम है, इसलिए आज भी मैं सबसे बाहर खड़ा हूँ।"},"ICON-2362":{"nm":"इनडोर टेम्परेचर चिप","de":"दरवाज़ा खुलते ही अंदर घुसी सुबह की ठंडी हवा को, हथेली जितनी छोटी चिप इंसान से पहले पढ़ लेती है। नाक ठंडी होने से पहले ही भाँप लेना — यह ख़ाली जिम का दिन खोलने वाली सबसे ख़ामोश नमस्ते है।"},"ICON-2363":{"nm":"बेसलाइन फ़ुट प्लेट","de":"पैर की नोक कहाँ रखे, यह न समझ पाने वाले खिलाड़ी के लिए, ज़मीन पर खिंची एक रेखा ही काफ़ी है। जो रेखा पार नहीं करनी, वही सबसे दूर तक की छलाँग की शुरुआती लकीर बन जाती है — यह फ़ुट प्लेट बिना बोले बता देती है।"},"ICON-2364":{"nm":"टेनिस बॉल बास्केट हैंगर","de":"दर्जनों गेंदों को एक ही मुँह में समेटकर भी एक भी नहीं गिरने देता। कोर्ट पर बिखरी चीज़ों को समेटकर अगले अभ्यास तक पहुँचाना — कोने में चुपचाप व्यस्त एक हाथ आज भी यहीं टंगा है।"},"ICON-2365":{"nm":"रैकेट हैंडल एंड कैप","de":"हैंडल के सिरे पर टक से लगाते ही, आख़िरकार रैकेट हथेली में समा जाता है। एक छोटी-सी कैप फिसलन और भरोसे के बीच रेखा खींच देती है। सिरा जब कसकर बंद हो, तभी पहला स्विंग मज़बूत बनता है।"},"ICON-2366":{"nm":"कोर्टसाइड तौलिया क्लिप","de":"हवा कितनी भी तेज़ चले, मेहनत से निचोड़ा तौलिया उड़ न जाए, इसलिए कोर्ट के किनारे मुँह भींचकर डटी रहती है। पल भर साँस साधने का विराम बचाने में भी किसी की सधी हुई उँगलियाँ लगी होती हैं।"},"ICON-2367":{"nm":"शटलकॉक फ़ेदर स्ट्रेटनिंग क्लिप","de":"एक भी पंख बिगड़े तो उड़ान डगमगा जाती है। मुड़े हुए पंख को धीरे से सीधा कर दिया जाए, तो शटलकॉक फिर से सीधा उड़ने को तैयार हो जाता है। दूर तक जाना हमेशा ऐसी ही छोटी सजावट से शुरू होता है।"},"ICON-2368":{"nm":"शटलकॉक ट्यूब कैप","de":"क़तार में रखे शटलकॉक मुरझा न जाएँ, इसलिए ट्यूब का सिरा मज़बूती से बंद किया जाता है। नमी की एक बूंद भी पंख को झुका देती है, यह देर से देखकर जाना है। अच्छे से सहेजना भी मैच का हिस्सा ही है।"},"ICON-2369":{"nm":"टेबल टेनिस बॉल रोल रेस्ट","de":"लुढ़कती-लुढ़कती आई छोटी गेंद मेरे ऊपर पल भर साँस साधती है। लुढ़ककर गिर न जाए, इसलिए चुपचाप थामे रखना — टेबल के पास दी गई, सबसे गोल आकार की एक देखभाल है।"},"ICON-2370":{"nm":"टेबल टेनिस रबर रोलर","de":"रबर की सतह पर रोलर धीरे से घुमाते ही पुरानी धूल उठती है और चिपचिपाहट फिर से जाग उठती है। घुमाव ज़िंदा रहे तभी गेंद मुड़ती है। रैकेट की आज की हालत इसी एक कोमल देखभाल से जागती है।"},"ICON-2371":{"nm":"नेट हाइट मेज़रिंग स्टिक","de":"नेट एक बालिश्त भी ऊँची हो तो खेल का रंग-ढंग बदल जाता है। आँख के अंदाज़े पर आख़िर भरोसा न करने वाले लोग मुझे उठाकर सामने रखते हैं। निष्पक्षता, लगता है, इसी तरह नियम से नापी गई ऊँचाई से ही आती है।"},"ICON-2372":{"nm":"शटलकॉक स्पीड सेंसर चिप","de":"हवा को चीरती शटलकॉक की रफ़्तार को मैं चुपचाप नाप लेता हूँ। कभी न दिखने वाली रफ़्तार जब एक साफ़ संख्या में बदल जाती है, कोच का अगला शब्द उतना ही स्पष्ट हो जाता है। यह अंदाज़े को सच्चाई में बदलने का काम है।"},"ICON-2373":{"nm":"टेबल टेनिस बॉल स्टोरेज कैप्सूल","de":"एक गोल गेंद को कैप्सूल में धीरे से लिटाते ही, खरोंच और धूल दूर हट जाते हैं। अगले मैच तक बस सही-सलामत रहे, यही सोचकर एक पूरा छोटा-सा कमरा उसे सौंप दिया जाता है।"},"ICON-2374":{"nm":"बैडमिंटन रैकेट स्ट्रिंग हैंगर","de":"ढीली पड़ी डोरियों को सलीक़े से टांग दिया जाए, तो अगली बारी वाला हाथ भटकता नहीं। सँभालना आख़िर, कल के मुझे पहले से लिखी गई एक प्यारी-सी चिट्ठी जैसा है। आज कल को आसान बना देता है।"},"ICON-2375":{"nm":"टेबल टेनिस रैकेट एज गार्ड टेप","de":"रबर के आसानी से उखड़ने वाले किनारे को मैं एक रेखा में चुपचाप गले लगाता हूँ। किनारा फटे तो गेंद का रुख़ भी बिगड़ जाता है। कोने को बचाना, आख़िर एक अंक को बचाना बन जाता है।"},"ICON-2376":{"nm":"स्क्वॉश बॉल वॉर्मिंग पाउच","de":"ठंडी गेंद मुश्किल से ही उछलती है। मैच से पहले, हथेली जैसी गर्माहट से उसे गोद में सेंकने वाली थैली। हाथ तक पहुँचती वह छोटी-सी गर्माहट, एक राउंड की साँस और लय पहले से तय कर देती है।"},"ICON-2377":{"nm":"लैक्रॉस मेश नेट क्लिप","de":"जाल की गाँठ जब धीरे से ढीली पड़ने लगती है, मैं बिना कुछ कहे उस एक फंदे को दबोच लेता हूँ। जाल कसा हो तभी गेंद टिकती है। अनदेखी जगह से पूरे खेल को थामे रखने वाला हाथ, यहीं है।"},"ICON-2378":{"nm":"स्क्वॉश रैकेट टिप गार्ड टेप","de":"दीवार की ओर जितनी ज़ोर से घुमाओगे, रैकेट उतना ही पहले अपनी नोक से रोने लगता है। उस रोती हुई नोक को धीरे से लपेट दो, तो वह एक सीज़न और साथ खेलता है। जो नोक को सहेजना जानता है, आख़िर वही लंबे समय तक रैकेट थामे रहता है।"},"ICON-2379":{"nm":"हॉकी स्टिक ब्लेड कवर","de":"तीखे ब्लेड पर कवर चढ़ाते ही, आख़िरकार बैग के भीतर भी और उँगलियों को भी चैन मिलता है। ख़तरनाक चीज़ को चुपचाप सुला देना — स्टिक समेटते वक़्त सबसे पहले निभाई जाने वाली, एक पुरानी शिष्टता है।"},"ICON-2380":{"nm":"क्रिकेट बॉल पॉलिशिंग कपड़ा","de":"लाल गेंद को कपड़े से रगड़कर चमकाते ही एक तरफ़ आईने-सी चमक भर जाती है। चमक ज़िंदा हो तभी गेंद घूमती है, यह गेंदबाज़ उँगलियों के एहसास से जानता है। मन लगाकर चमकाने में भी एक ख़ामोश रणनीति बसी है।"},"ICON-2381":{"nm":"लैक्रॉस बॉल स्टोरेज ट्यूब कैप","de":"कड़ी गेंदें मनमानी करके लुढ़क न जाएँ, इसलिए ट्यूब का मुँह मज़बूती से बंद किया जाता है। बिखरने की आदत वाली चीज़ों को एक जगह सहेजकर जुटाना — इंतज़ाम की बुनियाद हमेशा इतनी-सी छोटी बात होती है।"},"ICON-2382":{"nm":"स्क्वॉश वॉल टारगेट पीस","de":"दीवार में जड़ा एक छोटा निशान, डगमगाती खिलाड़ी की नज़रों को एक बिंदु पर समेट देता है। कहाँ निशाना साधना है, यह बताने वाला बस वही एक बिंदु — वह चौड़ी दीवार भी इस टुकड़े के सामने एक साफ़ निशाने में सिमट जाती है।"},"ICON-2383":{"nm":"हॉकी स्टिक ग्रिप स्लीव","de":"हाथ को जाना-पहचाना ग्रिप एक अजनबी नई स्टिक पर चढ़ा दो, उसी पल औज़ार तुरंत अपना बन जाता है। जान-पहचान को ज्यों-का-त्यों बदल देने वाली छोटी-सी स्लीव — यही तो नए में ढलने का सबसे छोटा रास्ता है।"},"ICON-2384":{"nm":"फ़ील्ड गोल नेट हैंगर","de":"गोलपोस्ट पर जाल टंगे, तभी गोल सचमुच गोल जैसा लगता है। जिस छोटे पल में गेंद पूरी तरह समाई थी, उसे आख़िर तक थामे रखने वाला हमेशा जाल ही रहा है। फूटती हुई जयकार का आकार थामने वाली जगह पर, मैं वहीं हूँ।"},"ICON-2385":{"nm":"स्केट ब्लेड कवर","de":"ब्लेड तीखी खुली हो तो बर्फ़ के बाहर एक क़दम भी बेफ़िक्र नहीं चला जा सकता। बर्फ़ छोड़ते ही, मुझे कृपया पहना दो। तीखेपन को चुपचाप सुला देना भी, स्केटरों की सालों पुरानी शिष्टता है।"},"ICON-2386":{"nm":"स्केट लेस हैंगर","de":"उतारे हुए बूट के लंबे फीतों को एक-एक करके सलीक़े से टांगा जाता है। उलझने से बचाकर खोले गए फीते अगली बार बर्फ़ को सहजता से खोलते हैं। आज की समाप्ति ही, बस इसी तरह, कल की तैयारी बन जाती है।"},"ICON-2387":{"nm":"स्केट ब्लेड तौलिया","de":"बर्फ़ छोड़ी ही ब्लेड पर छोटी-छोटी बूंदें बादल-सी उभर आती हैं। उस नमी को कोमलता से पोंछ दिया जाए तो जंग किनारा कर जाती है। ठंड ने छोड़े निशान को चुपचाप समेटना, यही मेरा दिन है।"},"ICON-2388":{"nm":"स्केट बूट एंकल पैड","de":"टखना एक बार डगमगाए तो पूरी फिसलन बिखर जाती है। उसे मज़बूती से लपेटकर पैर जमाने वाला पैड। बर्फ़ पर वह सुंदर संतुलन हमेशा पहले, अनदेखी जगह से ही शुरू होता है।"},"ICON-2389":{"nm":"स्केट ब्लेड गार्ड पाउच","de":"ब्लेड गार्ड को सहेजकर रखने वाली एक छोटी थैली बैग के एक कोने में है। जो चाहिए वह छोड़े बिना समेटने की आदत उपकरण को लंबे समय तक जीवित रखती है। सुव्यवस्थित बैग ही एक अच्छी फिसलन का पहला दृश्य है।"},"ICON-2390":{"nm":"स्केट बूट इनसोल क्लिप","de":"बूट के भीतर की इनसोल धीरे से खिसक न जाए, इसलिए पैर तले उसे कसकर थामा जाता है। जिस जगह पैर टिका, वही खिसक जाए तो छलाँग भी बिगड़ जाती है। सबसे नीची जगह को थामने वाला हाथ, आख़िर सबसे ऊँची छलाँग की मदद करता है।"},"ICON-2391":{"nm":"स्केट ब्लेड कवर लूप","de":"कवर धीरे से फिसलकर उतर न जाए, इसलिए हुक से इसे मज़बूती से जकड़कर बंद किया जाता है। ढीली सुरक्षा आख़िर सुरक्षा नहीं होती, यह पता है। एक अच्छी तरह बंद हुक ही उस ब्लेड को आख़िर तक बचाए रखता है।"},"ICON-2392":{"nm":"स्केट लेस टाइटनिंग कैप","de":"फीतों को ज़ोर से खींचकर कैप से बंद कर दिया जाए, तो अब फिर कभी खुलने का सवाल ही नहीं। पैर की उँगलियों से लेकर बिना किसी कमी के सलीक़े से कसना — बर्फ़ पर पहला क़दम रखने से पहले बाँधी गई सबसे भरोसेमंद गाँठ है।"},"ICON-2393":{"nm":"स्केट ब्लेड सुखाने वाला कपड़ा","de":"एक राउंड फिसलन ख़त्म करके आई ब्लेड से जमी नमी को चुपचाप समेटा जाता है। गीला छोड़ दिया जाए तो ब्लेड रोने लगती है, यह पता है। सूखी और मुलायम रही ब्लेड ही अगला वक्र बर्फ़ पर साफ़-साफ़ खींच पाती है।"},"ICON-2394":{"nm":"स्की पोल ग्रिप कैप","de":"पोल के हैंडल के सिरे को नरमी से लपेटते ही, पकड़ने वाली हथेली को उतना ही आराम मिलता है। बर्फ़ीले मैदान को चीरने वाली ताक़त आख़िर उसी कसकर पकड़ी जगह से निकलती है। एक छोटी कैप ही लंबे उतराव को आख़िर तक थामे रखती है।"},"ICON-2395":{"nm":"स्नोबोर्ड बाइंडिंग पिन","de":"बोर्ड और पैर को जोड़ने वाली छोटी पिन जिस पल निकल जाती है, सामने का पहाड़ थम जाता है। नज़र में मुश्किल से आने वाला पर सबसे पहले जाँचा जाने वाला टुकड़ा — यही मज़बूत जुड़ाव, आख़िर बर्फ़ीले मैदान पर आज़ादी बन जाता है।"},"ICON-2396":{"nm":"स्की एज टिप गार्ड क्लिप","de":"तीखा किनारा बैग के भीतरी हिस्से को खरोंच न दे, इसलिए सिरे को धीरे से दबोच लिया जाता है। तीखेपन को दुलारकर सुला देना — एक अच्छी उतराई के बाद दिया जाने वाला, एक प्यारा-सा समापन है।"},"ICON-2397":{"nm":"स्नोबोर्ड नोज़ गार्ड","de":"बोर्ड की अगली नोक को पूरी तरह लपेट दो, तो सामने से लगने वाली टक्कर भी नरमी से बिखर जाती है। सबसे पहले टकराने वाली जगह को चुपचाप सँभालना — तीखी ढलान का सामना करने का साहस यहीं से शुरू होता है।"},"ICON-2398":{"nm":"स्की बूट बकल कवर","de":"बकल ठंडी बर्फ़ से टकराकर ख़राब न हो, इसलिए इसे चुपचाप ढँक दिया जाता है। बंद करने वाले उपकरण की रक्षा करने वाला एक और ताला — यह छोटा-सा कवर बूट का एक सीज़न चुपके से थोड़ा और बढ़ा देता है।"},"ICON-2399":{"nm":"स्नोबोर्ड लीश लूप","de":"हाथ से छूटने पर भी बोर्ड दूर न भाग जाए, इसलिए मैं टखने और बोर्ड को एक डोरी में जोड़े रखता हूँ। भले हाथ से फिसल जाए, पर आख़िर खो न जाए — लंबी डोरी के सिरे पर टंगा, एक ख़ामोश भरोसे का लूप हूँ।"},"ICON-2400":{"nm":"स्की बेस स्क्रेपर टिप","de":"तली पर जमी पुरानी वैक्स को चिकनाई से खुरचकर हटाया जाता है। पुराना साफ़ हो तभी नई फिसलन जीवित होती है। मन लगाकर सँवारी गई तली, अगले बर्फ़ीले मैदान को और भी तेज़ी से खोल देती है।"},"ICON-2401":{"nm":"स्नोबोर्ड डेक बम्पर","de":"बोर्ड बर्फ को चीरे, उससे पहले नोक की नोक दुनिया को छूती है। हर टक्कर को यही छोटा रबर सबसे पहले सहता है। सबसे आगे रहकर, बिना दिखावे के घिसती यह जगह—किसी की ढलान इसी मौन समर्पण पर फिसलती है।"},"ICON-2402":{"nm":"स्की पोल बास्केट रिंग","de":"गहरी बर्फ में डंडा धँसने ही वाला होता है कि यह गोल घेरा उसकी जगह ज़मीन को टटोल लेता है। लड़खड़ाते एक कदम को चुपचाप थाम लेने वाला घेरा। दिखे न दिखे, यह फिसलने से बचाने वाले हाथ जैसा साथ निभाता है।"},"ICON-2403":{"nm":"एज-वैक्सिंग ब्रश कैप","de":"सफाई पूरी होते ही, पाउडर सूखने से पहले यह धीरे से ढक देता है। एक भी रेशा बिखरने न दे, आज की कोमलता को यूँ सील कर देना। ताकि अगली बार खोलने पर, कल की मेहनत वैसे ही इंतज़ार कर रही हो।"},"ICON-2404":{"nm":"ईयरमफ़ हैंगर","de":"याद है? बसंत आते ही बैग के पास कुछ देर के लिए भुला दिए गए ईयरमफ़। फिर भी पहली बर्फबारी की खबर सुनते ही रात में सबसे पहले पुकारे जाते हैं। मौसम को टाँगने की एक अलग जगह होती है, और यह हुक उस वादे को कभी नहीं भूलता।"},"ICON-2405":{"nm":"शार्पनिंग स्टोन केस","de":"चाकू तेज़ करने के लिए पहले पत्थर को भिगोना पड़ता है—दादी माँ के हाथों की तरह रचा-बसा यह क्रम। कुंदपन को साधने वाले औज़ार को भी आराम की एक जगह चाहिए, इसलिए यह छोटा-सा घर पत्थर को गोद में लिए अगली सफाई का इंतज़ार करता है।"},"ICON-2406":{"nm":"वैक्स ब्लॉक पाउच","de":"चमकती ढलान बनाने वाला यह पदार्थ, अंदर ही अंदर कठोर होकर सोया रहता है। एक जमे हुए टुकड़े को समेटे भारीपन। फिसलन हमेशा इसी शांत भार से खुलकर बर्फीले मैदान पर फैल जाती है।"},"ICON-2407":{"nm":"हैंड-वॉर्मर पाउच लूप","de":"सर्दी की सैर में, जेब के अंदर उंगलियाँ सबसे पहले जिस जगह को टटोलती हैं। जमे हाथों को गर्माहट देने वाली छोटी-सी गर्मी को एक तय ठिकाना देता है। जितनी ठंडी दोपहर, उतना ही मायालु हो जाता है यह छोटा-सा लूप।"},"ICON-2408":{"nm":"एज-ग्राइंडिंग स्टोन रेस्ट","de":"हिले तो धार टेढ़ी हो जाए, इसलिए यह पहले खुद को मज़बूती से जमा लेता है। दूसरे की सटीकता की ज़िम्मेदारी उठाते हुए खुद हिलता तक नहीं यह टेका। किसी की सीधी धार इसी मौन दृढ़ता पर खड़ी होती है।"},"ICON-2409":{"nm":"नेक वॉर्मर क्लिप","de":"ठंडी हवा में स्कूल जाते रास्ते पर, नेक वॉर्मर फिसलने ही वाला होता है कि कॉलर पर क्लिक की आवाज़ आती है। गर्माहट को भी अपनी जगह थामे रखना पड़ता है, तभी वह सच में गर्म होती है। एक छोटी-सी आवाज़ सुबह की गर्मी को थाम लेती है।"},"ICON-2410":{"nm":"वैक्सिंग आयरन कवर","de":"गरम-गरम काम करने वाली सतह जब ठंडी हो रही होती है, तब एक कपड़ा चुपचाप उसे धूल से बचाता है। ढलान तैयार करने वाले औज़ार की देखभाल एक और औज़ार करता है। देखभाल यूँ ही चुपचाप आगे बढ़ती रहती है।"},"ICON-2411":{"nm":"एज-ऑयल पेन कैप","de":"एक बार खोलकर सूख जाए तो अगली लकीर नहीं खिंच पाती। इसलिए बंद करना ही अगला खोलना है—पेन की नोक की नमी को सील करके, कल की एक रेखा का वादा पहले ही कर लेने वाला छोटा-सा ढक्कन।"},"ICON-2412":{"nm":"चियर पॉम टॉप","de":"सैकड़ों धागे इसी एक बिंदु से निकलकर, ताल पर एक साथ लहराते हैं। हिलने की शोभा हमेशा एक मज़बूती से बँधी जगह से शुरू होती है। मंच के नीचे, दर्शकों में लहर पैदा करने वाली पहली गाँठ।"},"ICON-2413":{"nm":"लाइट स्टिक हैंड स्ट्रैप","de":"दो घंटे की चीयरिंग के बाद, लाइट स्टिक हाथ से छूटने ही वाली होती है कि यह पट्टी उसे वापस हाथ में ले आती है। गिर भी जाए तो खोना नहीं चाहती, ऐसी चाहत। यह मायालु बेचैनी कलाई पर एक फंदा बना लेती है।"},"ICON-2414":{"nm":"स्टेडियम कुशन फोल्डिंग क्लैस्प","de":"चीयर करते हुए दर्जनों बार खड़े होना और फिर बैठना। इस बीच कुशन को करीने से मोड़कर जगह सँभालने वाला यह छोटा क्लैस्प। उमड़ते दर्शकों में भी किसी की सीट का ख्याल रखने वाला स्पर्श छिपा होता है।"},"ICON-2415":{"nm":"चियर बंदाना लूप","de":"जिस दिन एक ही डिज़ाइन पूरे दर्शकदीर्घा में फैल जाता है, एक कपड़ा हज़ारों दिलों को एक ही रंग में बाँध देता है। जहाँ से यह लहर शुरू होती है, वह पहला बिंदु यही छोटा-सा लूप है—जहाँ अकेली चीयर 'हम' बन जाती है।"},"ICON-2416":{"nm":"क्लैपर पैडल हाफ़","de":"अकेले बजाओ तो हल्की आवाज़, दर्शकों में मिले तो लहर बन जाए। यह जानने वाला सबसे ईमानदार आधा हिस्सा कि यह तभी गूंजता है जब दूसरे से टकराता है। तुम्हारी ताली मेरी ताली से मिलने के क्षण, चीयर बड़ी हो जाती है।"},"ICON-2417":{"nm":"चियर पिकेट कॉर्नर कैप","de":"नुकीले कोने को गोल लपेट देती है, ताकि बगल वाला कोई चोटिल न हो। जोश से लहराते दिल में भी एक-दूसरे के लिए ख्याल छिपा होता है। चीयर इसी गोलाई में और गर्म हो जाती है।"},"ICON-2418":{"nm":"चियर रिबन पोल होल्डर","de":"लहराना थमने के क्षण में भी डंडा सीधा खड़ा रहकर अगली चीख का इंतज़ार करता है। फिर से हिलने के लिए कुछ पल शांत ठहरने की जगह। एक चीख और दूसरी चीख के बीच, रिबन के साँस लेने का छोटा-सा सन्नाटा।"},"ICON-2419":{"nm":"चियर मेगाफ़ोन फ़ैन","de":"एक व्यक्ति की पुकार मंच के आखिरी छोर तक पहुँचे, इसलिए पंखे का आकार आवाज़ के रास्ते को संकरा कर देता है। दिल की गहराई से ज़्यादा, पहुँचाने के तरीके पर सोचता हुआ मुँह। और दूर तक पहुँचने की तड़प ने ही यह आकार गढ़ा है।"},"ICON-2420":{"nm":"बैज पिन-बैक केस","de":"सीने पर लगने से पहले और उतारे जाने के बाद, बैज का आराम यहीं से शुरू और यहीं खत्म होता है। नुकीली पिछली पिन को सुरक्षित सुला देने वाला छोटा-सा घर। चमकते एक बिंदु को भी कुछ देर लेटकर आराम करने की जगह चाहिए।"},"ICON-2421":{"nm":"स्कोरबोर्ड नंबर प्लेट","de":"हर गोल पर हाथ से बदली जाने वाली उस दौर की मेहनत इसमें रची-बसी है। डिजिटल युग से पहले, नतीजा इंसानी उंगलियों से एक-एक खाने में उकेरा जाता था। एक अंक में भी किसी की धड़कन बसती थी, ऐसा टुकड़ा।"},"ICON-2422":{"nm":"टैक्टिक बोर्ड मैग्नेट पीस","de":"कोच की उंगलियों के इशारे पर रक्षा और आक्रमण जगह बदलते हैं। मैच से पहले मन में बनने वाली हर तस्वीर, इन छोटे बिंदुओं की हलचल में पहले खिंचती है। नतीजा बोर्ड पर एक बार पहले ही खेला जाता है।"},"ICON-2423":{"nm":"स्कोरबोर्ड ग्लेयर वाइज़र","de":"चमकते अंक खिलाड़ी की नज़र धुँधली न करें, इसलिए यह छज्जा रोशनी को काट देता है। रोशनी को भी कभी-कभी सही मात्रा में ढकना पड़ता है, तभी वह अपना काम करती है। सबसे रोशन जगह पर, सबसे चुपचाप काम करने वाली छाया।"},"ICON-2424":{"nm":"स्कोर फ़्लिप रिंग","de":"एक-एक पन्ना पलटते ही अंक बदलता है और उसके पीछे जयकार उठती है। हाथ के अहसास से रिकॉर्ड ताज़ा करने वाले उस एनालॉग दौर का निशान। स्कोर पलटने की आवाज़ पर दिल भी पलट जाता था, वो ज़माना।"},"ICON-2425":{"nm":"टैक्टिक-लाइन मार्कर पेन केस","de":"लॉकर रूम के व्हाइटबोर्ड पर खिंची हर रेखा इसी पेन से निकलती है। मुकाबले का खाका समेटे, छोटा मगर मज़बूत यह बक्सा। फैसले से पहले की खामोशी में, सबसे ज़्यादा बातें अपने भीतर रखने वाली जगह।"},"ICON-2426":{"nm":"स्कोर काउंटर क्लिकर","de":"हर दबाव पर एक खाना, साफ़ 'टिक' की आवाज़ से गिनती बढ़ती है। अंकों को उंगलियों पर छोड़ दो तो दिल पूरी तरह खेल की तरफ़ मुड़ सकता है। गिनने का बोझ हल्का करने वाली एक छोटी-सी लय।"},"ICON-2427":{"nm":"स्कोरबोर्ड केबल कवर","de":"चमकदार रोशनी के पीछे हमेशा उलझे हुए, बेतरतीब तार पड़े होते हैं। उस अस्तव्यस्तता को करीने से ढक देने का काम। जो नहीं दिखता उसे सुव्यवस्थित रखो, तभी जो दिखता है वह चमकता है।"},"ICON-2428":{"nm":"टैक्टिक बोर्ड इरेज़र ब्रश","de":"एक दौर खत्म होते ही अगली तस्वीर के लिए सतह को साफ़ कर देता है। नई रणनीति हमेशा एक खाली जगह पर ही शुरू हो सकती है। मिटाने वाला ब्रश असल में अगली चाल का पहला स्ट्रोक है।"},"ICON-2429":{"nm":"स्कोर फ़्लैग क्लिप","de":"हवा में उड़ने को बेताब झंडे को मज़बूती से पकड़कर नहीं छोड़ता। लहराता कपड़ा अपनी जगह बनाए रखे, इसलिए। दुनिया को रिकॉर्ड बताने के काम में भी, पहले एक मज़बूती से थामने वाला हाथ चाहिए।"},"ICON-2430":{"nm":"रेफ़री व्हिसल कॉर्ड क्लिप","de":"एक सीटी से खेल रुकता है और फिर बहने लगता है। उस अधिकार को गले में मज़बूती से बाँधने वाली छोटी-सी गाँठ। सीटी बजने तक, खामोशी को करीने से बाँधे रखना भी इसी क्लिप का काम है।"},"ICON-2431":{"nm":"टेप मेज़र रील","de":"नापी गई लंबाई को फिर अपने अंदर समेट लेता है। नापना, आखिर में, खोलने और लपेटने के दोहराव का ही नाम है। इस सीधे-सादे आने-जाने में बिना किसी शिकायत साथ देने वाला हैंडल, सटीकता के पीछे हर बार घूमता है।"},"ICON-2432":{"nm":"कॉल फ़्लैग फ़ोल्डिंग केस","de":"भीतर और बाहर को दृढ़ता से अलग करने वाला झंडा, खेल खत्म होते ही करीने से मुड़कर आराम करता है। वह स्पष्ट संकेत भी अगली बार के लिए कुछ देर साँस लेता है। दृढ़ता के पीछे भी एक शांत विश्राम होता है।"},"ICON-2433":{"nm":"स्टॉपवॉच हैंगिंग लूप","de":"बहते समय को कलाई पर नहीं, एक जगह टाँग देता है। नापने से पहले थमा रहता है, पुकारते ही दौड़ पड़ता है—समय का यह स्टेशन। शुरुआत के इशारे का इंतज़ार करता, साँस थामे एक छोटा-सा सेकंड का घर।"},"ICON-2434":{"nm":"फ़ील्ड लाइन-मार्कर व्हील","de":"जहाँ-जहाँ यह घूमता है, वहाँ एक साफ़ सफ़ेद रास्ता रह जाता है। नियमों की सीमा यूँ ही एक-एक चक्कर में ज़मीन पर उकेरी जाती है। खेल शुरू होने से पहले, मैदान पर सबसे पहला निशान छोड़ने वाला पहिया।"},"ICON-2435":{"nm":"रेफ़री कार्ड पॉकेट","de":"फ़ैसले के पल में, सीने से निकाला जाने वाला वह कार्ड यहीं सोया रहता है। दिखाए जाने तक अंत तक खामोश रहने वाले फ़ैसले का प्रतीक्षा-कक्ष। न निकलना पड़े, यही चाहते हुए हमेशा तैयार बैठी रहने वाली जेब।"},"ICON-2436":{"nm":"स्केल वेट रेस्ट","de":"वज़न तौलने का काम बिना हिली-डुली सतह पर ही ईमानदार होता है। भार को थामे हुए खुद अपना बदन समतल दे देने वाला टेका। सटीक नाप का पहला कदम हमेशा एक शांत जगह से शुरू होता है।"},"ICON-2437":{"nm":"स्टार्टर क्लिकर","de":"एक आवाज़ पर सारे पैर एक साथ ज़मीन से उछल पड़ते हैं। शुरुआत बेहद छोटी होती है, पर उस छोटेपन को बनाने वाला हाथ किसी से भी ज़्यादा शांत होता है। स्टार्ट लाइन की कंपकंपी को एक ही क्लिक से खोल देने वाला हाथ।"},"ICON-2438":{"nm":"फ़ील्ड कोन बेस","de":"नाम भले अनजाना लगे, काम साफ़ है—मंच जैसे मैदान के बीचोबीच को भारी-भरकम थामे रखना। जहाँ सब कोई चमकता है, वहाँ हमेशा एक अनदेखा पैर चुपचाप डटा रहता है।"},"ICON-2439":{"nm":"डायाफ़्राम ब्रीदिंग बेल्ट बकल","de":"अच्छी आवाज़ गले से नहीं, गहरी साँस से आती है—यह कमर पहले जान जाती है। पेट के फूलने और सिकुड़ने को हथेली से महसूस कराने वाला बकल। गाने की शुरुआत हमेशा इसी एक साँस के नीचे होती है।"},"ICON-2440":{"nm":"ब्रेथ-प्रैक्टिस फ़ेदर प्लेट","de":"फूँक से पंख हल्के से हिले तो यह इशारा है कि साँस सम है। दिखाई न देने वाली साँस को हल्के से आकार देकर, गीत की नींव सिखाता है। पहले सुर से पहले की साँस को, आँखों से सीखने की कवायद।"},"ICON-2441":{"nm":"इनहेल सैंड टाइमर","de":"काँच के भीतर रेत साँस की तरह बहती है। साँस भरो, पल भर रुको, धीरे से छोड़ो—इसकी लय को दाने गिन देते हैं। बिना आवाज़ गिरती रेत को शांति से देखते रहो, तो कब बिखरी साँस अपने आप सम हो जाती है, पता ही नहीं चलता।"},"ICON-2442":{"nm":"कैंडल-प्रैक्टिस स्टैंड","de":"बत्ती जलाते ही थरथराती लौ के साथ आवाज़ भी काँपने लगती है। उस छोटी-सी कंपकंपी को कुछ देर सँभालने के लिए किसी ने मन से यह जगह तराशी। मोम जमकर बनी मोटाई जितनी, यहाँ अकेले गाई गई रातें ठहरी हैं।"},"ICON-2443":{"nm":"बेली-प्रेस कुशन स्ट्रैप","de":"पेट पर हाथ रखने की जगह, एक पट्टी चुपचाप वहाँ दबाव देती है। साँस भरने पर तनकर खिंच जाती है, खाली हो जाने पर धीरे से ढीली पड़ जाती है। शरीर पहले ताल याद रखे, इसमें साथ देने वाली खामोश छोटी दोस्त।"},"ICON-2444":{"nm":"ब्रेथ-होल्ड बैलून कैप","de":"गुब्बारा एक साँस में मत फुलाओ। लंबा, धीरे, आखिर तक धकेलो। कैप को दांतों से पकड़े हवा छोड़ते समय, हवा फेफड़ों की सबसे गहरी जगह तक पहुँचती है। गीत, आखिरकार, उतनी ही दूर उड़ता है जितनी लंबी साँस तुमने थामी।"},"ICON-2445":{"nm":"ब्रेथ-स्टेडीइंग ग्रिप","de":"दिल जितना डगमगाए, हाथ उतना ही किसी चीज़ को कसकर पकड़ना चाहता है। इस पकड़ को थामो तो कंधे धीरे से झुक जाते हैं, साँस एक बित्ता और लंबी हो जाती है। पकड़ना सीखना ही खुद को सँभालना सीखना है, यह हथेली पहले जान जाती है।"},"ICON-2446":{"nm":"ऐब-वाइब्रेशन बैंड लूप","de":"लूप में बैंड टाँगो तो हल्की कंपन पेट के बीचोबीच फैल जाती है। ज़ोर से हँसते वक़्त काँपने वाली उसी जगह पर चुपचाप ताकत जमा होती है। मज़बूत केंद्र हमेशा ऐसे ही, किसी की नज़र से दूर धीरे-धीरे बढ़ता है।"},"ICON-2447":{"nm":"इनहेल-काउंट डायल","de":"एक, दो, तीन—डायल जब एक खाना घूमता है, तब भरी साँस की गहराई उकेरी जाती है। एक खाना बढ़े तो गीत भी एक कड़ी और थाम लेता है। इस छोटे डायल पर, आज बढ़ाई गई फेफड़ों की ताकत चुपचाप दर्ज होती है।"},"ICON-2448":{"nm":"टंग-एक्सरसाइज़ स्पून प्लेट","de":"जिस जगह जीभ की नोक पहुँचनी चाहिए, वह प्लेट पर साफ़-साफ़ उकेरी गई है। घुमाना, उछालना, फिर पल भर रुकना। सहज बहते उच्चारण के पीछे, जीभ ने रास्ता याद करने में बिताई ऐसी अनगिनत भोर छिपी होती हैं।"},"ICON-2449":{"nm":"माउथ-शेप मिरर क्लिप","de":"शीशे में झलकते मुँह के आकार को क्लिप धीरे से थाम लेती है। 'आ' गोल हो, 'ई' दोनों ओर लंबा फैले। अपने ही चेहरे को सीधे देखते हुए आवाज़ का आकार गढ़ने की, शीशे और मुझ दोनों की ही खामोश कक्षा।"},"ICON-2450":{"nm":"डिक्शन कॉर्क सील","de":"कॉर्क से तराशा एक छोटा-सा सील मेज़ के कोने पर बैठकर उच्चारण सुनता है। जिस रात 'र' बार-बार फिसलकर मन उदास कर दे, सील की गोल आँखें चुपचाप कहती हैं। कोई बात नहीं, एक बार और कोशिश करते हैं।"},"ICON-2451":{"nm":"लिरिक ब्रेथ-मार्क पिन","de":"गीत में कहाँ साँस लेनी है, यह पिन पहले ही बता देती है। एक पंक्ति के आखिर में टिका दो तो वह जगह गीत का मायालु विराम बन जाती है। मन खोलकर गाने के लिए, वाक्य को भी साँस लेने की एक जगह चाहिए होती है।"},"ICON-2452":{"nm":"डिक्शन-प्रैक्टिस चिन रेस्ट","de":"ठोड़ी को हल्का-सा सहारा देते ही बिखरने वाला उच्चारण अपनी जगह पा लेता है। साफ़ बोल सिर्फ़ मुँह का काम नहीं, ठोड़ी, गले और साँस मिलकर गढ़ते हैं। यह छोटा टेका उस मुश्किल संतुलन में चुपचाप साथ देता है।"},"ICON-2453":{"nm":"वॉवल माउथ-शेप स्टैंड","de":"आ·ए·इ·ओ·उ, पाँच स्वर मुँह से निकलने का जो रास्ता है, उसे जस का तस खड़ा रखने वाला साँचा। शीशे के पास चुपचाप रखकर हर दिन आवाज़ का ढाँचा गढ़ते हैं। कोई भी गीत हो, उसकी बुनियाद आखिर इन्हीं पाँच स्वरों से शुरू होती है।"},"ICON-2454":{"nm":"टंग-ट्विस्टर कार्ड","de":"पढ़ते-पढ़ते जीभ उलझ जाए और आखिर में हँसी छूट जाए, ऐसा एक कार्ड। गलत हो जाए तो सच में कोई बात नहीं, गलती ही तो अभ्यास है। इस शरारती वाक्य को हर बार पार करने पर एक उच्चारण साफ़ जागता है।"},"ICON-2455":{"nm":"लिप-लूज़निंग प्लग","de":"होंठ थरथराकर अकड़े मुँह को जगाने वाली वॉर्म-अप। प्लग को दाँतों से पकड़े हवा लंबी छोड़ो, तो सोए होंठ नरम होकर खुल जाते हैं। पहली पंक्ति को कोमलता से खोलने के लिए, सबसे छोटी और सबसे मायालु तैयारी।"},"ICON-2456":{"nm":"लिरिक-सेक्शन रबर बैंड","de":"बार-बार अटकने वाले हिस्से पर रबर बैंड लगाकर निशान बना देते हैं। कलाई पर बंधी वह जगह देखते ही आज पार करने वाला पहाड़ याद आ जाता है। जितनी मुश्किल कड़ी, उतनी ही बार देखते हैं उसे, उतनी देर दिल में बसाते हैं।"},"ICON-2457":{"nm":"नेक-वॉर्मिंग स्कार्फ़ लूप","de":"मौसम बदलने की सुबह की हवा में गला बैठ न जाए, इसलिए स्कार्फ़ को लूप पर मज़बूती से टाँग देते हैं। गर्मजोशी से लिपटे गले से ही साफ़ आवाज़ खुलती है। आवाज़ को बचाना हमेशा गले को पहले संभालने से शुरू होता है।"},"ICON-2458":{"nm":"वोकल-कॉर्ड वाइब्रेशन रोलर टिप","de":"रोलर की नोक गर्दन के किनारे धीरे-धीरे घूमे तो रातभर सोई वोकल कॉर्ड धीरे से जाग उठती है। हल्की कंपन से अकड़ा तनाव ढीला पड़ता है, हिचकिचाता पहला सुर कहीं ज़्यादा मुलायम हो जाता है। गाने से पहले, शरीर को गर्माने वाला स्पर्श।"},"ICON-2459":{"nm":"हमिंग वॉर्म-अप कप कोस्टर","de":"मुँह बंद कर गुनगुनाते हुए, भाप उठती गरम प्याली को दोनों हाथों से थामो तो गला भी गर्म हो जाता है। धीमी गुनगुनाहट कोस्टर पर गोल-गोल फैलती है। गीत यूँ ही, थोड़ी-सी गुनगुनी गर्माहट के एक घूँट से शुरू होता है।"},"ICON-2460":{"nm":"थ्रोट-कैंडी स्टोरेज कैप्सूल","de":"गले के खरखराकर बैठ जाने वाले दिनों के लिए, कैप्सूल में मिठाइयाँ चुपचाप जमा रखी हैं। मंच पर जाने से ठीक पहले एक को मुँह में घुमाओ तो तीखी पुदीना बंद गला ठंडा कर खोल देती है। छोटे-से डिब्बे में रखा, अपना ही आपातकालीन दिलासा।"},"ICON-2461":{"nm":"स्टीम थ्रोट-कंप्रेस पाउच","de":"गरम भाप से महकी थैली को गले पर लपेटो तो लंबे अभ्यास से अकड़ी जगह धीरे से पिघल जाती है। ताज़ा गरम किए तौलिये जैसी वही गर्माहट, थके-हारे बैठे स्वर को चुपचाप एक धड़कन का आराम सौंपती है।"},"ICON-2462":{"nm":"वोकल-रेस्ट आवरग्लास","de":"आज न बोलने का चुपचाप लिया गया वादा, महीन दाने धीरे-धीरे गिन देते हैं। कुछ देर मुँह बंद रखकर आवाज़ को बचा लेना। सबसे अच्छी देखभाल भी यही शांत समय है, जो यहाँ धीरे-धीरे बहता है।"},"ICON-2463":{"nm":"वॉर्म-अप लिप-ट्रिल प्लग","de":"होंठ हल्के से फड़फड़ाते हुए सुरों पर ऊपर-नीचे सवारी करने वाला लिप-ट्रिल। प्लग को हल्का-सा दाँतों से पकड़ते ही बेकाबू काँपना कहीं ज़्यादा सम हो जाता है। स्वर के पहले बटन को कोमलता से लगाने वाला, हथेली भर का छोटा औज़ार।"},"ICON-2464":{"nm":"थ्रोट-मॉइस्चर स्प्रे कैप","de":"सूखे मंच पर गला बिल्कुल सूखने न पाए, इसलिए कैप दबाकर बारीक फुहार छिड़क देते हैं। नम हुई हवा को गहरी साँस में भरो तो सूखी हुई आवाज़ फिर से साफ़ चमक पा लेती है।"},"ICON-2465":{"nm":"वोकल-लूज़निंग वाइब्रेशन बॉल","de":"हथेली पर बारीक काँपती गेंद को चुपचाप थामे रहो तो वह कंपन बाँह होकर धीरे से गले तक चढ़ आती है। तनाव से अकड़े स्वर-अंगों को धीरे से हिलाकर जगाने वाला, गोल और मायालु वॉर्म-अप दोस्त।"},"ICON-2466":{"nm":"फ़ॉर्मेशन स्पॉट मार्कर","de":"मंच के फ़र्श पर टिका एक छोटा-सा निशान। यहाँ तुम्हारी जगह है, वहाँ मेरी। कई लोग मिलकर एक तस्वीर बनाते वक़्त, किसी को बिखरने न देते हुए चुपचाप थामे रखने वाला अनदेखा वादा।"},"ICON-2467":{"nm":"पाथ ऐरोहेड चिप","de":"तीर के निशान जैसी चिप अगले एक कदम की दिशा साफ़ बताती है। कहाँ मुड़ना है, कहाँ रुकना है, रास्ता भटके नहीं इसलिए फ़र्श पहले बता देता है। चलने का रास्ता, आखिर पैरों की नोक ने अनगिनत बार चलकर याद किया हुआ नक्शा है।"},"ICON-2468":{"nm":"फ़ॉर्मेशन सेंटर पिन","de":"कई लोग जमा होने पर चुपचाप आधार बन जाने वाला बस एक बिंदु। इस पिन के इर्द-गिर्द गोल घेरा खिंचता है, और फ़ॉर्मेशन खुलकर फैल जाता है। बिखरी हरकतें भी बस एक केंद्र-बिंदु पाकर कब अपना क्रम पा लेती हैं, पता ही नहीं चलता।"},"ICON-2469":{"nm":"क्रॉसिंग-पॉइंट वेज","de":"दो राहें जहाँ एक जगह मिलती हैं, वहाँ कील मज़बूती से गाड़ दी जाती है। ताकि आपस में टकराएँ नहीं, राह चूककर उलझें नहीं। साँस रोक देने वाले उस छोटे-से गुज़रते पल में भी, किसी का भी रास्ता न भटके।"},"ICON-2470":{"nm":"एग्ज़िट-डायरेक्शन फ़्लैग","de":"आखिरी सुर की गूँज मिटते ही झंडे के इशारे की तरफ़ चुपचाप निकल जाते हैं। आने जितना ही, जाना भी बिखरा नहीं होना चाहिए। मंच के अंत में भी, पहले से तय की गई एक दिशा होती है।"},"ICON-2471":{"nm":"स्पेसिंग टेप-मेज़र क्लिप","de":"टेप के सिरे को क्लिप से मज़बूती से पकड़ लो तो एक बित्ता, फिर एक बित्ता बिना चूके सटीक होता जाता है। इंसान और इंसान के बीच की दूरी को भी फ़ीते से नापे जैसा करीने से मिलाना। एक अच्छा लगने वाला दृश्य हमेशा ऐसी ही बारीक उंगलियों से जन्म लेता है।"},"ICON-2472":{"nm":"एलाइनमेंट रेफ़रेंस कॉर्ड लूप","de":"डोरी को लूप में टाँगकर एक सीध में तान दो तो वह महीन रेखा सबके एक साथ खड़े होने का मापदंड बन जाती है। कतार में खड़ी सूरत इतनी करीने से दिखती है, यह सब इसी न दिखने वाली सीधी रेखा की बदौलत है।"},"ICON-2473":{"nm":"मूवमेंट-पाथ डॉटेड पीस","de":"फ़र्श पर बिंदीदार रेखा से चुपचाप रास्ता खींचने वाले टुकड़े। इस हल्के निशान के सहारे चलो तो अँधेरे में भी नहीं भटकोगे। एक बिंदु से दूसरे बिंदु को जोड़ते-जोड़ते, बिखरे कदम एक ही धारा में बंध जाते हैं।"},"ICON-2474":{"nm":"पोज़िशन फ़्लोर टैक","de":"अपनी जगह भूल न जाए, इसलिए फ़र्श में गड़ी एक छोटी कील। घुप्प अँधेरे में भी पैर की नोक उस छोटी-सी उभार को टटोलकर आखिरकार ढूँढ लेती है। ठीक उसी एक बिंदु पर रुकते ही, तभी रोशनी सिर के ऊपर बरस पड़ती है।"},"ICON-2475":{"nm":"नेक-आइसोलेशन फ़ोकस बैंड","de":"ठोड़ी साथ हिले तो आवाज़ भी साथ काँपकर बिखर जाती है। सिर स्थिर रखकर सिर्फ़ गर्दन को अलग से हिलाना सीखने के लिए यह बैंड बाँधते हैं। बेहद आज़ाद दिखने वाली हरकत के पीछे, ऐसी ही मौन जुदाई का अभ्यास होता है।"},"ICON-2476":{"nm":"शोल्डर-फ़िक्सिंग कुशन क्लिप","de":"कंधे अपनी मर्ज़ी से न उछलें, इसलिए कुशन को क्लिप से चुपचाप जमा देते हैं। शरीर साफ़-साफ़ जान ले कि कहाँ हिलना है और कहाँ ठहरे रहना है। संयमित रेखा हमेशा ऐसी ही छोटी-छोटी सँभाल से जन्म लेती है।"},"ICON-2477":{"nm":"रिब-सेंसिंग बेल्ट बकल","de":"पसलियों के फैलने और फिर सिमटने की महीन बुनावट को बेल्ट चुपचाप पढ़ लेती है। बकल बंद करते ही साँस की हरकत उंगलियों तक साफ़ महसूस होती है। गहरी और मज़बूत आवाज़ इसी अनदेखी हड्डी की हरकत से उपजती है।"},"ICON-2478":{"nm":"हिप-स्वे पेंडुलम","de":"लोलक धीरे-धीरे दाएँ-बाएँ झूलते हुए कमर की बनाई ताल चुपचाप बता देता है। शरीर का केंद्र भार को कैसे ढोता-सरकाता है, यह हथेली भर का छोटा वज़न बिना बोले सिखा देता है। कि हिलने-डुलने में भी एक बुनावट होती है।"},"ICON-2479":{"nm":"रिस्ट-रोटेशन लूप","de":"लूप को कलाई पर टाँगकर अंदर की ओर, फिर बाहर की ओर धीरे-धीरे घुमाओ तो रातभर अकड़ा जोड़ नरम होकर खुल जाता है। उंगलियों की नोक तक जीवंत पहुँचने वाली हरकत के लिए, पहले कलाई का लचीला होना ज़रूरी है। यह छोटा-सा घुमाव एक बड़ी अभिव्यक्ति खोल देता है।"},"ICON-2480":{"nm":"एंकल-रेज़िस्टेंस रिंग कॉर्ड","de":"टखने पर रिंग पहनकर डोरी खींचो तो हर उठते कदम पर पैर की नोक में हल्का प्रतिरोध अटकता है। जितने भारी पैर रखे, उतनी ही चुपचाप ताकत टाँगों में जमती है। पंख जैसी हल्की छलाँग हमेशा ऐसे ही भारी अभ्यास पर खड़ी होती है।"},"ICON-2481":{"nm":"कोर-फ़ोकस सैंडबैग","de":"पेट पर बाँधने के बाद ही पता चलता है कि शरीर का ठीक बीचोबीच कहाँ था। वज़न कंधों को खींचता है, इस बीच लड़खड़ाता केंद्र धीरे-धीरे अपनी जगह पा लेता है, और खोलने के बाद जो बचती है वह है सीधी खड़ी एक मुद्रा।"},"ICON-2482":{"nm":"स्पाइन-एलाइनमेंट बार कैप","de":"दिनभर झुकी रही पीठ को यह छोटी-सी कैप छूती है तो लगता है जैसे कोई चुपके से कंधे सीधे कर रहा हो। झुककर भी गुज़ारा हो सकता है, पर सीधे खड़े होना एक मायालु हुनर है जिसे धीरे-धीरे फिर से सीखना पड़ता है।"},"ICON-2483":{"nm":"मसल-रिलैक्सिंग एक्यूप्रेशर बॉल","de":"गुत्थमगुत्था हुई जगह पर ज़ोर से दबाओ तो पहले हल्की सी चुभन, फिर जल्दी ही राहत मिलती है। बचपन में दादी माँ के हाथ की पीठ सहलाने वाली उसी गर्माहट की तरह, ढीला करना यानी थोड़ी देर और दर्द सहते हुए साथ बने रहना।"},"ICON-2484":{"nm":"मिरर-एंगल एडजस्टिंग स्क्रू","de":"हथेली भर भी घुमाओ तो शीशा बिल्कुल अलग चेहरा दिखाता है। एक पेच के घुमाव से दुनिया झुक जाती है और फिर सीधी खड़ी हो जाती है, तो लगता है खुद को आमने-सामने देखने के लिए भी एक शांत निशाना ज़रूरी है।"},"ICON-2485":{"nm":"मिरर-फ़ॉग वाइपिंग पैड","de":"गरम भाप से धुँधले शीशे के सामने, इंसान कुछ देर के लिए अपना चेहरा खो देता है। एक झटके में पोंछते ही चेहरा लौट आता है। यह धुँधलापन हटाने वाला स्पर्श ही है जिसकी बदौलत हर सुबह मैं खुद से फिर मिलता हूँ।"},"ICON-2486":{"nm":"कैमरा ट्राइपॉड फ़ुट रबर","de":"तिपाई के पैर की नोक पर नाखून जितना एक रबर का टुकड़ा, स्क्रीन की तक़दीर तय करता है। ज़मीन को कसकर पकड़ने वाली उसकी ताकत हिलना शांत कर देती है, इसलिए बिना कँपकँपी वाली तस्वीर हमेशा एक अनदेखे घर्षण से चुपचाप शुरू होती है।"},"ICON-2487":{"nm":"एंगल-रेफ़रेंस ग्रिड फ़िल्म","de":"फ़िल्म पर बनी महीन जाल-रेखाएँ आँखों के लिए मानो सहारे वाले पहिए हों। रचना जितनी हाथ में बसती जाती है, रेखाएँ उतनी ही धीरे से गायब होकर सिर्फ़ अंतर्ज्ञान रह जाता है। सीखने के निशान जितने पके होते हैं, उतने ही अदृश्य होते चले जाते हैं।"},"ICON-2488":{"nm":"रिकॉर्डिंग-स्टार्ट फ़ुट पेडल","de":"दोनों हाथ भर सामान थामे इंसान की आखिरी उंगली हमेशा पैर की नोक ही होती थी। हल्के से दबाते ही रिकॉर्डिंग शुरू हो जाती है—मंच के पीछे की देखभाल यूँ ही, पैर की नोक तक बड़ी फुर्ती से अपना काम कर जाती है।"},"ICON-2489":{"nm":"लाइटिंग-डायरेक्शन क्लिप","de":"रोशनी कहाँ गिरेगी, यह नाखून जितनी इस क्लिप की उंगलियों पर टिका है। छाया को एक बित्ता खिसकाने और रूपरेखा उभारने का काम, उस छोटे-से फ़र्क़ पर कोई देर तक गहराई से सोच में डूब जाता है।"},"ICON-2490":{"nm":"फ़ुटेज-कम्पेरिज़न स्क्रीन","de":"कल और आज को साथ-साथ रखो, तभी बदलाव मुँह खोलता है। पर्दा सरकते ही, बीच में गुज़री हुई समय की दूरी स्क्रीन पर ईमानदारी से उजागर हो जाती है।"},"ICON-2491":{"nm":"रिमोट रिस्ट स्ट्रैप","de":"कलाई पर एक डोरी लपेट दो तो गिर जाने की फ़िक्र में डूबा मन हल्का हो जाता है। एक छोटा सुरक्षा-उपाय हाथ को उल्टे और आज़ाद कर देता है, बंधा हुआ होना ही मन को चैन देता है, यह एक मायालु विडंबना है।"},"ICON-2492":{"nm":"लेंस कैप","de":"कैमरा आराम करता है तो लेंस भी चुपचाप अपनी आँख मूँद लेता है। जहाँ धूल का एक कण भी स्क्रीन पर निशान बनकर रह जाता है, वहाँ धीरे से ढक देना ही उसे लंबे समय तक सहेजने की चाहत है।"},"ICON-2493":{"nm":"लिप-कॉर्नर लिफ़्ट बैंड","de":"होंठों के कोने हल्के से ऊपर खींचो तो अकड़ा भाव धीरे से खुल जाता है। मुस्कान भी आखिर एक मांसपेशी ही है, पहले औज़ार का सहारा लेते हैं, फिर किसी सुबह अपनी ही ताकत से खुलकर मुस्कुरा उठते हैं।"},"ICON-2494":{"nm":"चीक-मसल मसाज रोल","de":"गाल के भीतरी हिस्से को धीरे-धीरे घुमाकर ढीला करो तो बोल कहीं ज़्यादा सहजता से बहते हैं। गाने से पहले चेहरे को धीरे से जगाने वाली शांत तैयारी। भाव को भी गर्माओ, वह और गर्म हो जाता है।"},"ICON-2495":{"nm":"स्माइल-एंगल गेज","de":"मुस्कान का भी सही कोण होता है, यह कैमरा जानता है। गेज से इधर-उधर नाप-नापकर आखिर में यही पता चलता है, सबसे सुंदर मुस्कान उस सच्चे दिल से खिलती है जिसे कभी नापा ही नहीं जा सकता।"},"ICON-2496":{"nm":"आइब्रो-मूवमेंट क्लिप","de":"भौंह एक मिलीमीटर भी हिले तो मन की पूरी बुनावट बदल जाती है। भाव के सबसे छोटे पुर्ज़े को चुपचाप थामे रखने वाली क्लिप—अभिनय आखिर ऐसी बारीकियों को साधने वाली उंगलियों का ही काम है।"},"ICON-2497":{"nm":"चीकबोन-लिफ़्ट स्टिकर","de":"गाल की हड्डी को हल्का-सा ऊपर खींचकर चिपकाओ तो चेहरे पर एक ऐसी जगह बन जाती है जहाँ रोशनी ठहरती है। नाखून जितने एक स्टिकर से बना यह उभार, मंच के मेकअप में ऐसे ही अदृश्य राज़ छिपे होते हैं।"},"ICON-2498":{"nm":"विंक-कवर आई पैच","de":"एक आँख ढक दो तो बची हुई आँख में मन पूरी तरह जमा हो जाता है। विंक का अभ्यास, आखिर में, आधे हिस्से को खूबसूरती से छिपाना सीखने का काम है। ढका जितना जाए, उतनी ही साफ़ होने वाले भाव भी ज़रूर होते हैं।"},"ICON-2499":{"nm":"माउथ-शेप मोल्ड क्लिप","de":"ग, ग्या, गो... मुँह का आकार साँचे में बिठाओ तो धुँधला उच्चारण साफ़ हो जाता है। हर स्वर असल में चेहरे की एक मुद्रा है, यह बात शीशे के सामने धीरे-धीरे शरीर में उतरती है।"},"ICON-2500":{"nm":"एक्सप्रेशन वॉर्म-अप पाउच","de":"मंच पर जाने से ठीक पहले, चेहरे को धीरे से गरमाने वाली गरम थैली। जैसे ठंडे हाथ प्रदर्शन को अकड़ा देते हैं, वैसे ही भाव भी। मुस्कान को भी पहले से गर्माना ज़रूरी है, यह मंच के पीछे का एक छोटा-सा सच है।"},"ICON-2501":{"nm":"सलवट-मिटाओ माथा-पट्टी","de":"माथे पर पट्टी बाँधते ही गहरी जमी सिलवटें चुपचाप सुलझ जाती हैं। यह वह वस्तु है जो चिंता से बनी झुर्रियों को थोड़ी देर के लिए आराम देती है। सुलझे हुए माथे के नीचे इंसान थोड़ा और जवान दिखने लगता है।"},"ICON-2502":{"nm":"पन्ना-पलट अंगुश्ताना","de":"कागज़ पलटती उँगली की नोक पर पहना जाने वाला एक नन्हा अंगुश्ताना। मोटी स्क्रिप्ट को पन्ना दर पन्ना पलटने की वह लय कब कहानी की धड़कन बन जाती है, पता ही नहीं चलता। पढ़ने के काम में भी हाथ की एक स्नेहिल आदत बस जाती है।"},"ICON-2503":{"nm":"भावना-रंग झंडी","de":"खुशी पीली है, दुख नीला। मन को रंग चढ़ाकर झंडी खड़ी करो, तो अनदेखी भावना हवा में लहराते हुए अपना आकार पा लेती है। भावनाओं को भी इस तरह हाथ से रंगकर देखा जा सकता है।"},"ICON-2504":{"nm":"संवाद-बल क्लिप","de":"\"इस शब्द पर ज़ोर दो,\" क्लिप चुपचाप बता देती है। एक ही संवाद केवल एक बल से पूरा अर्थ बदल देता है, इसलिए यह वाणी के गुरुत्व-केंद्र को थामे रखने वाला एक छोटा-सा चिह्न है।"},"ICON-2505":{"nm":"विराम-श्वास ब्लॉक","de":"\"यहाँ एक पल ठहर जाओ,\" यही कहने के लिए रखा गया ब्लॉक। संवाद में अल्पविराम रुकावट नहीं, बल्कि अगले शब्दों के लिए ली गई साँस है। जो अच्छी तरह ठहरना जानता है, वही अंततः अच्छी तरह बोल पाता है।"},"ICON-2506":{"nm":"श्वास-चिह्न क्लिप-पट्टी","de":"क्लिप के सहारे पट्टी ऊपर-नीचे होकर साँस की लंबाई आँखों के सामने खींच देती है। साँस अंदर लेने और छोड़ने की लय देखकर उसका अनुसरण करना—गीत की शुरुआत हमेशा साँस को साधने से ही खुलती है।"},"ICON-2507":{"nm":"भावना-पासा थैली","de":"थैली से लुढ़कता हुआ पासा आज की भावना तय करता है। खुशी आए तो खुश होकर देखो, गुस्सा आए तो गुस्सा करके देखो। अभिनय का अभ्यास इस तरह मन को संयोग के हवाले करने का एक खेल बन जाता है।"},"ICON-2508":{"nm":"स्क्रिप्ट-ढलान स्टैंड","de":"तिरछे झुके हुए स्टैंड पर स्क्रिप्ट रखो तो सिर झुकाने की ज़रूरत नहीं रहती। आँखों की सीध बनाए रखने वाला यह नन्हा ढलान, लंबे अभ्यास से अकड़ी गर्दन की चुपचाप देखभाल करता है।"},"ICON-2509":{"nm":"फुसफुसाहट पर्दा","de":"यहाँ से फुसफुसाने का इशारा। पर्दे के पीछे आवाज़ धीमी करो तो दर्शक दीर्घा उलटे साँस रोककर कान लगा देती है। जितना धीमे बोलो उतना बड़ा पहुँचना—मंच का यह स्नेहिल विरोधाभास है।"},"ICON-2510":{"nm":"भूमिका-अदला टोकन डिब्बा","de":"टोकन को हल्के से पलटो तो निभाई जाने वाली भूमिका बदल जाती है। आज नायक, कल साथ निभाने वाला दोस्त। साथ बढ़ने वाले इस द्वीप पर बारी-बारी से हर किसी को मंच के बीचोबीच खड़े होने की बारी आती है।"},"ICON-2511":{"nm":"दृष्टि-स्थिर बिंदु स्टिकर","de":"कैमरे के पास एक नन्हे बिंदु पर चुपचाप नज़र टिकाओ। भटकती नज़र जिस पल एक जगह टिकती है, स्क्रीन में आँखों की चमक साफ़ जीवंत हो उठती है। एकटक देखना अंततः ठहर जाने से ही शुरू होता है।"},"ICON-2512":{"nm":"कोण-जाँच त्रिकोण स्केल","de":"स्क्रीन का कोई कोना कुछ तिरछा दिखे तो त्रिकोण स्केल हल्के से लगाकर देखो, जवाब मिल जाता है। टेढ़े को सीधा करने का काम। आँखों पर भरोसा करने से पहले, थोड़ी देर स्केल पर भरोसा करके देखना।"},"ICON-2513":{"nm":"लेंस दृष्टि-सम विश्राम","de":"लेंस को इंसान की आँखों की सीध में लाओ तो स्क्रीन कम झूठ बोलती है। न ऊपर से, न नीचे से—जब वही आँखें आमने-सामने होती हैं, तभी बिना सजावट का असली भाव क़ैद होता है।"},"ICON-2514":{"nm":"दृष्टि-मार्ग तीर-पंख","de":"पंख जिस ओर इशारा करता है, नज़र सरसराते हुए उधर ही चली जाती है। देखने वाले की नज़र को धीरे से ले जाने वाला एक नन्हा तीर। अच्छी तस्वीर हमेशा दयालुता से इशारा कर देती है कि कहाँ देखना है।"},"ICON-2515":{"nm":"शूटिंग-मार्ग फ़र्श चिप","de":"घिस जाने तक याद किए गए मार्ग के एक बिंदु पर चुपचाप पैर रखो तो अगली जगह तुरंत हाथ लग जाती है। मंच पर घूमते कदम, फ़र्श पर गड़े इन नन्हे चिह्नों को जोड़कर बनाया गया एक अदृश्य रास्ता है।"},"ICON-2516":{"nm":"कैमरा-दूरी फ़ीता","de":"विषय और कैमरे के बीच की दूरी फ़ीते से नापी जाती है। जहाँ एक बित्ता दूर और पास को बाँटता है, वहाँ यह फ़ीता धुँधलेपन और स्पष्टता की सीमा की रखवाली करने वाला एक शांत प्रहरी बन जाता है।"},"ICON-2517":{"nm":"सिर-झुकाव मार्गदर्शक","de":"सिर कितना झुकाने पर सबसे स्नेहिल दिखता है? गाइड का अनुसरण करते-करते धीरे से पता चल जाता है—झुकाव का कोण अंततः मन खोलने की मात्रा से बिल्कुल मिलता-जुलता है।"},"ICON-2518":{"nm":"नज़र-मिलान हस्त-दर्पण क्लिप","de":"क्लिप से हाथ का आईना कैमरे के पास रखो तो अपनी आँखें देखते हुए भी तुमसे नज़र मिलती है। आईने में मैं और स्क्रीन में तुम—दोनों के बीच नज़र का एक पुल धीरे से बिछाने वाला नन्हा उपकरण।"},"ICON-2519":{"nm":"शूटिंग-संकेत बत्ती","de":"बत्ती जलते ही संकेत मिलता है कि अभी शूटिंग चल रही है। एक नन्ही बत्ती उत्साहित सेट के तनाव को एक जगह समेट लेती है। रोशनी जलने के उस पल से सबकी साँसें एक ही लय में सध जाती हैं।"},"ICON-2520":{"nm":"प्रतिक्रिया-घंटी बटन","de":"बटन दबाते ही साफ़ घंटी शीतल-सी बज उठती है। अच्छे दृश्य के बाद फूट पड़ने वाली तालियों की तरह, किसी का गर्मजोशी भरा \"शाबाश\" इस नन्ही घंटी में समाया रहता है।"},"ICON-2521":{"nm":"फुर्ती-चिट्ठी नली","de":"हिलाओ तो लकड़ी की तीलियाँ खड़खड़ाकर पहले माहौल जगा देती हैं। मंच कौन खोलेगा यह कलाई की एक झटक में तय होता है—निकलने वाला झेंपकर मुस्कुराता है, बाकी लोग राहत की साँस लेते हैं। किस्मत बाँटने में भी एक स्नेहिल नियम होता है।"},"ICON-2522":{"nm":"ध्वनि-प्रभाव झुनझुना","de":"कलाई हल्के-से हिलाओ तो छनक के साथ एक टिप्पणी बीच में आ जुड़ती है। सन्नाटे को अजीब होने से पहले यह नन्हा घंटा भर देता है। हँसी की लय गिनने में यही हमेशा एक कदम आगे रहता है।"},"ICON-2523":{"nm":"चौंका-डिब्बा ढक्कन","de":"खुलने से पहले कोई भी अंदाज़ा नहीं लगा सकता कि भीतर क्या है। यही इस ढक्कन का इकलौता काम है। हल्के-से उठने के उस क्षण में चीख़ और हँसी एक साथ फूट पड़ें, इसके लिए यह एक कब्ज़े पर पूरी धड़कन टाँगे रखता है।"},"ICON-2524":{"nm":"प्रतिक्रिया मोड़-पंखा","de":"फट से खुलने की आवाज़ ही अपने आप में जवाब बन जाती है। शब्दों में न कही जा सकी वाहवाही को पंखे की तीलियाँ हवा देकर भेज देती हैं। मोड़ने-खोलने के इशारों के बीच उमंग आती-जाती है, और हवा के संग मन का एक कोना भी हिलता-डुलता है।"},"ICON-2525":{"nm":"सज़ा-रूलेट चक्र","de":"सुई किस खाने पर रुकेगी, यह पहले से कोई नहीं जानता। चक्र जितना धीमा होता जाता है, दिल उतना ही उल्टा तेज़ धड़कने लगता है—टक की आवाज़ के साथ, रुकी जगह पर आज की हास्यास्पद नियति लिखी जाती है। कुछ ऐसे पल जहाँ काँपना भी मज़ेदार लगे।"},"ICON-2526":{"nm":"उद्गार बुलबुला बोर्ड","de":"सिर के ऊपर चमकाकर उठाओ तो \"वाह\" अक्षर बनकर उभर आता है। मुँह जिस मन का पीछा नहीं कर पाया, उसे कागज़ का एक टुकड़ा आगे बढ़कर चिल्ला देता है। क्योंकि प्रतिक्रिया को भी मंच का थोड़ा निर्देशन चाहिए होता है।"},"ICON-2527":{"nm":"थम-जाओ हाथ-झंडी","de":"झंडी उठने के उस पल, सब वहीं के वहीं जम जाते हैं। साँस की आवाज़ तक को स्थिर चित्र में क़ैद करने वाला संकेत। फिर से नीचे होते ही, थमी हुई हँसी एक साथ फूट पड़ती है।"},"ICON-2528":{"nm":"बेतुका-जवाब क्लिप टब","de":"जवाब जितना बेतुका हो, उतनी ही मज़बूती से टाँगकर लटकाया जाता है। रस्सी पर टँगे गलत जवाब जब हवा में हिलते हैं, तो सही जवाब से ज़्यादा वही ग़लतियाँ प्यारी लगने वाला मंच बन जाता है। ग़लत होने पर भी ठीक रहने वाले एक दिन का दृश्य।"},"ICON-2529":{"nm":"मुद्रा-सुधार पीठ-सहारा वेज","de":"पीठ टिकाते ही, झुकी हुई रीढ़ धीरे से अपनी राह टटोलने लगती है। बिना कुछ कहे थामने वाला एक नन्हा वेज। सही मुद्रा तभी सहज होती है जब कोई थाम लेता है—यही बात पीठ के पीछे से चुपचाप बता देता है।"},"ICON-2530":{"nm":"कूल्हा-संरेखण सहारा ब्लॉक","de":"गुरुत्व-केंद्र डगमगाए तो पैरों के नीचे टिकाई गई एक नन्ही मज़बूती। शरीर का संतुलन अंततः फ़र्श से ही धीरे-धीरे ऊपर उठता है। अनदेखी जगह से मुद्रा थामे रखने वाला, बिना नाम का एक सहयोगी किरदार।"},"ICON-2531":{"nm":"पेट-कसाव संतुलन गेंद","de":"पेट में लगाकर धीरे से कसो तो बिखरा हुआ केंद्र एक बिंदु पर सिमट आता है। साँस जितनी गहरी साधोगे, गेंद उतनी मज़बूत होती जाएगी, और शरीर भूली हुई अपनी धुरी को एक-एक साँस में वापस पा लेगा।"},"ICON-2532":{"nm":"रीढ़-वक्र जाँच स्केल","de":"पीठ पर स्केल लगाओ तो अनदेखा मोड़ पैमाने पर उभर आता है। सीधा खड़ा होना वक्र मिटाने का काम नहीं, बल्कि उस नन्हे टेढ़ेपन को भी स्नेह से पढ़ लेने का काम है।"},"ICON-2533":{"nm":"कंधा-खिंचाव लचीला फंदा","de":"कंधों पर डालकर धीरे से खींचो तो सिमटा हुआ सीना खुल जाता है। लचीलापन हमेशा फुसफुसाता है, अपनी जगह लौट आओ, और दिनभर झुकी रही पीठ इस कोमल पुकार से थोड़ा-थोड़ा सीधी होती जाती है।"},"ICON-2534":{"nm":"कोर-उद्दीपक रेत-थैली","de":"कमर पर बाँधो तो भारी रेत के कण सोए हुए कोर को जगा देते हैं। हल्की-सी हरकत भी इस भार के सामने एक पल में सच्ची मेहनत बन जाती है। जितना सहोगे उतने मज़बूत बनोगे, यह हर एक कण चुपचाप बता देता है।"},"ICON-2535":{"nm":"पुच्छ-अस्थि सहारा गद्दी टैग","de":"पुच्छ-अस्थि के नीचे धीरे से सहारा देने वाली गद्दी, उसके सिरे पर लटका एक नन्हा टैग। लंबे समय बैठे थके हुए दिन के लिए \"यहाँ थोड़ी देर टिक जाओ\" लिखकर चिपकाया गया, एक स्नेहिल पर्ची जैसा उपकरण।"},"ICON-2536":{"nm":"कमर-सहारा कोण तिपाई","de":"तीन पैरों पर टिककर, कमर को टेक लगाने का कोण चुपचाप थामे रखती है। गिरती-सी मुद्रा में हल्के से घुस आने वाला सहारा। डगमगाते को थामने के लिए तीन बिंदु अजीब तरह से काफ़ी होते हैं।"},"ICON-2537":{"nm":"ठुड्डी-दबाव मुद्रा क्लिप","de":"ठुड्डी को हल्के-से खींचकर टिकाओ तो बिगड़ी हुई गर्दन की रेखा अपनी जगह ढूँढ लेती है। उँगली जितनी क्लिप की टोकाटोकी कहीं-न-कहीं स्नेहिल लगती है। सिर सीधा उठाने का तरीका यह नन्हा उपकरण सिखाता है।"},"ICON-2538":{"nm":"पद-चिह्न सीढ़ी पट्टी","de":"फ़र्श पर बिछाई गई पट्टी पैर रखने के खाने बारी-बारी से बना देती है। एक-एक खाने पर ईमानदारी से पैर रखते-रखते, अनजाने में स्टेप शरीर में उतर जाता है। रास्ता जितना चला जाए, उतना ही साफ़ होता जाता है।"},"ICON-2539":{"nm":"दिशा-परिवर्तन शंकु चिप","de":"खड़ा कर दो तो \"यहाँ मुड़ो\" कहकर दिशा बताने वाला एक नन्हा चिह्न। सीधा ही दौड़ते रहे पैरों को यह एक मोड़ भेंट करता है। घूमकर जाने वाले रास्ते में भी अपनी एक लय छिपी होती है।"},"ICON-2540":{"nm":"एक-पैर संतुलन डगमग तख़्ता","de":"एक पैर पर खड़े होते ही तख़्ता हल्के से झुक जाता है। डगमगाहट पर काबू पाने की जान लगा देने वाले वे चंद पल, संतुलन का सबसे ईमानदार पाठ हैं। गिरने से बचती पैर की उँगलियाँ ही सब कुछ कह देती हैं।"},"ICON-2541":{"nm":"प्रतिक्रिया-गति चमक बत्ती","de":"संकेत जलते ही उस पल, हाथ पहले जाएगा या आँख—इसी की होड़ लगती है। चमकती बत्ती हिचकिचाने का ज़रा भी मौका नहीं देती। तेज़ हाथ हमेशा सोच से आधी धड़कन पहले हिल जाता है।"},"ICON-2542":{"nm":"टेढ़ी-मेढ़ी कदम मार्कर","de":"फ़र्श पर तिरछे चिपके नन्हे बिंदु पैरों को टेढ़े-मेढ़े नाचने के लिए ले जाते हैं। सीधी रेखा से हमेशा मुश्किल होता है आड़ा-तिरछा चलना। बिंदुओं का पीछा करते-करते भटकते हुए, फुर्तीले कदम पक कर तैयार हो जाते हैं।"},"ICON-2543":{"nm":"संतुलन रस्सी-बार","de":"पतले बार पर पैर रखो तो दुनिया एक अकेली रस्सी जितनी संकरी हो जाती है। हवा में चलने वाले नटखट की तरह, एक बित्ते जितनी चौड़ाई पर पूरे शरीर का ध्यान लाद देते हो। संतुलन जितना संकरा होता है, उतना ही उलटे साफ़ होता जाता है।"},"ICON-2544":{"nm":"फुर्ती उछाल-गेंद कंगन","de":"कलाई पर पहनो तो नन्ही गेंद उछलकर वापस आ जाती है। फेंकने और पकड़ने के उस पल में प्रतिक्रिया की गति उँगलियों में उतर जाती है। तेज़ी अंततः यही है—लौटती चीज़ को चूकना नहीं।"},"ICON-2545":{"nm":"फुर्तीला-पैर हूला रिंग","de":"पैर में डालकर घुमाओ तो हूला रिंग पिंडली को बार-बार उकसाती रहती है। रुकते ही गिर जाती है, इसलिए पैर बिना रुके हिलते रहते हैं। खेलते हुए-सी हरकत के बीच पैरों की चाल फुर्तीली होकर पक जाती है।"},"ICON-2546":{"nm":"पंजा-संतुलन लकड़ी की लट्टू","de":"हथेली पर घूमती लट्टू केंद्र खोते ही वहीं थम जाती है। आँगन में लट्टू घुमाते बचपन के उन दिनों की तरह, संतुलन वह चीज़ है जो निरंतर घूमकर ही खड़ी रह पाती है।"},"ICON-2547":{"nm":"टखना-सुरक्षा कसाव डोरी","de":"टखने को लपेटकर कसो तो डगमगाता कदम कहीं ज़्यादा मज़बूत हो जाता है। जो जगह जल्दी चोटिल होती है, उसे उतना ही स्नेह से थामना चाहिए। डोरी का एक धागा एक कदम की तसल्ली बन जाता है।"},"ICON-2548":{"nm":"घुटना-ऊष्मा लपेट पट्टी","de":"ठंडे घुटने पर लपेट दो तो गर्माहट जोड़ों के बीच रिसने लगती है। अकड़ा जोड़ गर्म होने पर ही मुलायम हो पाता है। हिलने-डुलने से पहले, अपने शरीर को दिया गया सबसे गर्मजोशी भरा सुबह का अभिवादन।"},"ICON-2549":{"nm":"मांसपेशी-राहत दबाव गेंद","de":"अकड़ी जगह को धीरे से दबाओ तो दाने गाँठ को चुपचाप सहला देते हैं। जितना दर्द उतनी राहत—यह एक अजीब सांत्वना है। हाथ जहाँ नहीं पहुँच पाता उस अकड़न को भी यह नन्ही गेंद बदले में थपथपा देती है।"},"ICON-2550":{"nm":"वार्म-अप क्रम चक्र","de":"चक्र जिस खाने पर रुकता है, वहीं से शरीर को जगाया जाता है। गर्दन, कंधा, टखना—क्रम किस्मत पर छोड़ो और मन हल्का रखो। वार्म-अप में भी जब खेल घुल जाए, तो अकड़ा शरीर सबसे पहले धीरे से मुस्कुरा देता है।"},"ICON-2551":{"nm":"जोड़-ऊष्मा सेंक थैली","de":"गर्म सेंक थैली जोड़ पर रखो तो जाड़े की गर्म कोठरी जैसी राहत फैल जाती है। यह वह समय है जब अकड़े जोड़ आलस भरी राहत में ढीले पड़ते हैं। तभी गर्म हुआ शरीर धीरे-धीरे हिलने की तैयारी करता है।"},"ICON-2552":{"nm":"खिंचाव हत्था फंदा","de":"फंदा पकड़कर खींचो तो अकड़ी मांसपेशी लंबी होकर तन जाती है। थामते हाथ और खुलते शरीर के बीच एक तनी हुई बातचीत चलती है। जितना खिंचेगा, उतना ही कल का हर हरकत हल्का लगेगा।"},"ICON-2553":{"nm":"तलवा-उद्दीपक गुटका तख़्ता","de":"उभारों पर नंगे पैर खड़े हो तो सोए हुए तलवे चौंककर जाग उठते हैं। कंकरीली राह पर नंगे पैर चलने की उस चुभती अनुभूति की तरह, ज़मीन को महसूस करने का एहसास पंजों से भर आता है।"},"ICON-2554":{"nm":"चोट-नोट चुंबक पिन","de":"\"ज़्यादा ज़ोर मत लगाना\" लिखकर धातु की पट्टी पर टक से चिपका दो। दर्द भरी यादें आसानी से भुला दी जाती हैं, इसलिए इसे चुंबक से आँखों के सामने टाँग देते हो। शरीर को संभालने वाला मन भी अंततः एक पंक्ति की टिप्पणी से शुरू होता है।"},"ICON-2555":{"nm":"फ़ेशिया-मुक्ति गाँठदार रोलर","de":"गाँठदार डंडे को धीरे से घुमाओ तो चिपकी हुई फ़ेशिया एक-एक खंड करके खुलती जाती है। गाँठ को चुपचाप हटाता एक स्पर्श। गुँथा हुआ दिन भी इसी तरह गाँठ-गाँठ करके खोला जाए तो कहीं हल्का हो जाता है।"},"ICON-2556":{"nm":"चाल-रेखा फ़र्श पट्टी","de":"फ़र्श पर सीधी बिछाओ तो पैरों को चलने के लिए एक रेखा मिल जाती है। बिगड़ी हुई चाल भी इस रेखा पर आते ही अनजाने में सीधी हो जाती है। रास्ता खींच दो तो पैर फिर भटकते नहीं।"},"ICON-2557":{"nm":"कंधा-समतल छड़","de":"कंधों पर आड़ा रखो तो एक तरफ़ झुका हुआ संतुलन धीरे से उजागर हो जाता है। समतल होना हमेशा एक तरफ़ को नीचे और दूसरे को ऊपर करने का काम है। एक छड़ ही टेढ़ी आदत को चुपचाप इशारा कर देती है।"},"ICON-2558":{"nm":"सिर-शिखर संतुलन भार","de":"सिर के शिखर पर रखे भार को गिरने से बचाना हो तो पूरा शरीर एक सीध में सीधा खड़ा होना चाहिए। सिर पर पानी का घड़ा उठाकर चलने वाले उस पुराने दृश्य की तरह, केंद्र सबसे ऊँचे स्थान से पकड़कर नीचे उतरता है।"},"ICON-2559":{"nm":"ठुड्डी-कोण विश्राम","de":"ठुड्डी को धीरे से टिकाओ तो बार-बार झुकता सिर अपना सही कोण फिर से पा लेता है। एक सहारे पर टिका हुआ चंद पल का विश्राम। सीधी रेखा तभी पूरी होती है जब कोई उसे नीचे से थाम ले।"},"ICON-2560":{"nm":"पद-दूरी खूँटा","de":"फ़र्श में गड़ा खूँटा पहले से नाप देता है कि पैर कहाँ पड़ेगा। न ज़्यादा चौड़ा, न ज़्यादा संकरा एक कदम—वह ईमानदार दूरी। चाल का संतुलन इसी नन्हे चिह्न से चुपचाप शुरू होता है।"},"ICON-2561":{"nm":"पंजा-दिशा वेज","de":"हिचकिचाता पहला कदम—कहाँ जाना है, पंजे पहले हिचकिचाते हैं। यह नन्हा वेज दिशा तय कर दे तो मन भी धीरे से उधर ही झुक जाता है। रास्ता चुनना कोई बड़ा फ़ैसला नहीं, बल्कि पंजे के इशारे वाला वही एक बित्ता है।"},"ICON-2562":{"nm":"पीठ-सीधाई बेल्ट","de":"\"पीठ सीधी करो, सीधी करो\" कहने वाली वह आवाज़ जैसे इस बेल्ट के भीतर ज़िंदा है। झुके हुए दिन को चुपचाप सीधा करो तो कंधों पर टिका बोझ भी अजीब तरह थोड़ा हल्का हो जाता है। एक मुद्रा ही मन को भी सीधा खड़ा कर देती है।"},"ICON-2563":{"nm":"भार-वितरण पद-तख़्ता","de":"बाएँ पैर पर सात, दाएँ पर तीन। भार कहाँ ज़्यादा टिकाओगे, यही संतुलन तय करता है। तख़्ता चुपचाप पूछता है—अभी तुम किस ओर ज़्यादा झुककर खड़े हो? सीधा खड़ा होना भी असल में लगातार समायोजन ही है।"},"ICON-2564":{"nm":"दृष्टि-सम लक्ष्य खंभा","de":"आँखें बार-बार पंजों पर गिरती हैं। ऐसे में दूर खड़ा एक खंभा नज़र को धीरे से ऊपर उठा देता है। दूर देखने का अभ्यास दूर जाने का ही अभ्यास है, इसलिए सिर उठाते ही न पहुँच पाने जैसी लगने वाली जगह भी पास आ जाती है।"},"ICON-2565":{"nm":"नमन-कोण कार्ड क्लिप","de":"पंद्रह डिग्री, तीस डिग्री, पैंतालीस डिग्री। कमर जितनी गहराई से झुकती है, मन भी उतना ही साथ झुकता है। कार्ड पर लिखा कोण महज़ एक संख्या नहीं, बल्कि दूसरे के प्रति सम्मान नापने वाला एक नन्हा पैमाना है।"},"ICON-2566":{"nm":"हाथ-जोड़ शिष्टाचार फंदा","de":"दोनों हाथ करीने से जोड़ो तो उतावला मन भी शांति से एक जगह टिक जाता है। बेचैन, बेढंगी उँगलियों को यह नन्हा फंदा स्नेह से थाम लेता है और अभिवादन की पहली मुद्रा चुपचाप बना देता है।"},"ICON-2567":{"nm":"दिशा-तीर चुंबक","de":"भटके हुए पैर सबसे पहले जो ढूँढते हुए इधर-उधर देखते हैं, वह तीर ही है। चुंबक से टक चिपकी एक दिशा हिचकिचाहट तोड़ देती है और कदमों को उस जगह की ओर धीरे से खींच लेती है जहाँ जाना है। भटकता मन भी आख़िर एक दिशा पा लेता है।"},"ICON-2568":{"nm":"निकास-दिशा चिह्न पिन","de":"आने का रास्ता से जाने का रास्ता हमेशा कठिन होता है। बत्ती बुझे अँधेरे में भी साफ़ चमकता यह पिन आख़िरी मार्ग चुपचाप बता देता है। अच्छी तरह विदा लेना भी मंच का हिस्सा है, यह अंत में ही पता चलता है।"},"ICON-2569":{"nm":"औपचारिक-नमन क्रम पट्टी","de":"पहले झुकने वाला और बाद में झुकने वाला—यह क्रम कभी बहुत साफ़ हुआ करता था। पट्टी पर लिखे क्रम के अनुसार झुको तो शिष्टाचार में भी एक बनावट उभरती है और शालीनता में एक प्रवाह बहता है। यह मन के क्रम को सहेजने का काम है।"},"ICON-2570":{"nm":"पद-संरेखण चुंबक चिप","de":"एक इंसान बेसुरा हो जाए तो पूरी कतार डगमगा जाती है। पंजे मिलते ही टक से चिपकने वाली चिप की तरह, साथ खड़ा होना अपना कदम बग़ल वाले को धीरे से सौंप देना है। एक ही लय में पड़ते पैरों की आवाज़ सबसे भरोसेमंद लगती है।"},"ICON-2571":{"nm":"मंच-नमन स्थान नाल-चिह्न","de":"मंच पर एक नमन के लिए भी एक स्थान होता है। घोड़े की नाल जैसे गोल फैले चिह्नों पर पैर रखो तो घबराहट से बार-बार बिगड़ता पहला अभिवादन आख़िर अपना आकार पा लेता है। जगह पता हो तो कँपकँपी भी थोड़ी शांत हो जाती है।"},"ICON-2572":{"nm":"आभार-इशारा कार्ड","de":"शब्दों में जो कृतज्ञता पूरी तरह नहीं समा पाती, वह उँगलियों की नोक से बह निकलती है। दिल बनाना, सीने पर हाथ रखना—कार्ड पर लिखा हर एक इशारा मन का लिखा हुआ अनुवाद बन जाता है। पहुँचने की चाहत रखने वाली सच्चाई का हमेशा एक आकार होता है।"},"ICON-2573":{"nm":"कतार-दूरी कार्ड खूँटा","de":"कतार में लगने के काम में भी एक स्नेहिल शिष्टाचार है। आगे वाले से ठीक एक बित्ता दूरी बनाए रखने वाले खूँटे की तरह, इंतज़ार एक-दूसरे को न धकेलने की छोटी-सी परवाह से शुरू होता है। थोड़ा दूर खड़ा होना भी मन लगाकर किया गया काम है।"},"ICON-2574":{"nm":"संकेत-कार्ड पलट रिंग","de":"अगला संवाद जब होंठों पर बार-बार मँडराता है, तो उँगली धीरे से एक पन्ना पलट देती है। रिंग में पिरोए नन्हे कागज़ धड़कती धड़कन को चुपचाप दबा देते हैं और अगले संवाद का खाना शांति से खोल देते हैं। काँपने पर भी प्रवाह टूटता नहीं।"},"ICON-2575":{"nm":"कार्यक्रम-क्रम रेत-घड़ी","de":"फिसलते हुए बहते रेत के कणों को चुपचाप देखो, तो अगला क्रम मन में शांति से सज जाता है। आख़िरी कण गिरने तक, बिना जल्दबाज़ी किए आँखों से समय पढ़ना यह नन्ही घड़ी सिखा देती है।"},"ICON-2576":{"nm":"माइक-पकड़ अभ्यास छड़","de":"हाथ में बसने से पहले एक खाली छड़ भी हज़ार मन का बोझ लगती है। पकड़ने का कोण, मुँह से दूरी, कलाई का ज़ोर—बार-बार पकड़ने और छोड़ने का यह अभ्यास एक दिन अचानक एक सहज हरकत बनकर खिल उठता है।"},"ICON-2577":{"nm":"स्पष्ट-उच्चारण जीभ-छड़ी","de":"ग, न, द, र। जीभ की नोक साफ़ होने तक छड़ी मुँह में दबाकर उच्चारण घुमाकर देखा जाता है। साफ़-साफ़ पार हुआ एक शब्द, सैकड़ों बार लड़खड़ाए और बिगड़े हुए वक़्त के ऊपर चुपचाप खिलने वाले एक फूल जैसा है।"},"ICON-2578":{"nm":"संकेत हाथ-झंडी","de":"शुरू, रुको, एक धड़कन ठहरो। बिना एक शब्द बोले एक झंडी मंच की साँस का संचालन कर देती है। दर्शक दीर्घा से न दिखने वाली जगह से चुपचाप हिलता हाथ हर एक धड़कन को बिना चूक थामे रखता है।"},"ICON-2579":{"nm":"दृश्य-परिवर्तन घंटी","de":"टुनटुन साफ़ बजते ही दृश्य बदल जाता है। सूर्यास्त के समय बाज़ार में फैलती घंटी की आवाज़ की तरह, यह नन्ही झंकार हिचकिचाते मन को धीरे से अगले कोने में पहुँचा देती है। बदलाव हमेशा एक आवाज़ से शुरू होता है।"},"ICON-2580":{"nm":"वाणी-श्वास लोलक","de":"साँस अंदर लो—एक, दो—फिर धीरे से बाहर छोड़ो। दाएँ-बाएँ हिलते लोलक के साथ साँस साधो तो जल्दबाज़ी में बहते शब्द भी कब अपनी लय वापस पा लेते हैं, पता ही नहीं चलता। बोलने की गति अंततः साँस की ही गति थी।"},"ICON-2581":{"nm":"कार्यक्रम मोड़-पट्टी","de":"मोड़ने और खोलने की महज़ एक हरकत में आज का पूरा क्रम समाया रहता है। हाथ के स्पर्श से गहरा घिसा पट्टा खोलते ही, पहले क्या निकालूँ—यह उलझा मन शांति से पंक्तिबद्ध हो जाता है। एक खुलने भर से दिन सज जाता है।"},"ICON-2582":{"nm":"श्वास-लय रेत-घड़ी","de":"श्वास लो तीन, रोको चार, छोड़ो छह। रेत बहते समय मेरी साँस भी चुपचाप उसके साथ बहती है। एक-एक साँस गिनना, व्यस्त मुझे धीरे से संभालने का सबसे पुराना, सबसे स्नेहिल तरीका है।"},"ICON-2583":{"nm":"ध्यान-गद्दी झालर","de":"गद्दी के सिरे पर लटकी झालर बिना हवा के भी चुपचाप हिलती है। पालथी मारकर बैठो तो, पुराने ज़माने के किसी बुज़ुर्ग के छज्जे पर बैठकर मन साधने वाली वह शांति धीरे से पास आकर थोड़ी देर ठहरकर चली जाती है।"},"ICON-2584":{"nm":"श्वास-स्थिरता हस्त-घंटी","de":"एक झोंका हवा गुज़रे तो साफ़ आवाज़ चुपचाप गूँजती है। छज्जे की पवन-घंटी जैसी लटकी यह चीज़, उथल-पुथल मचे मन पर ठंडक और ताज़गी की एक बूँद टपका देती है। आवाज़ में भी ठंडक देने की ताक़त होती है।"},"ICON-2585":{"nm":"धूप-धुआँ प्लेट","de":"जलती धूपबत्ती से बचा धुआँ धीरे-धीरे प्लेट पर उतर आता है। त्योहार की सुबह थाली के सामने उठती उस सुगंध की तरह, धुएँ की एक लट अशांत हवा को धीरे से शांत कर कमरे को सन्नाटे से भर देती है।"},"ICON-2586":{"nm":"श्वास-झूला भार","de":"धीरे-धीरे ऊपर जाकर फिर नीचे आने वाले एक भार पर मेरी साँस सवार होती है। साँस लेते वक़्त ऊपर उठना, छोड़ते वक़्त नीचे बैठना—जिस दिन शरीर साँस लेना भूल जाए, यह नन्ही घड़ी उसे फिर से शुरुआत से सिखा देती है।"},"ICON-2587":{"nm":"ध्यान-घंटी हथौड़ी","de":"घंटी को एक बार चुपचाप बजाओ तो गूँज देर तक फैलती चली जाती है। पहाड़ी मंदिर में बजती पवन-घंटी की आवाज़ की तरह, वह गूँज हवा में पूरी तरह ग़ायब होने तक शांति से सुनने भर से मन का एक कोना साफ़ धुल जाता है।"},"ICON-2588":{"nm":"श्वास-मार्ग पंख","de":"पंख को नाक के आगे चुपचाप रखो तो अनदेखी साँस की राह आख़िर दिख जाती है। हल्के से हिलना—अच्छी तरह साँस ले रहे हो; ठहर जाना—बहुत देर तक रोक रखी है। सबसे हल्की चीज़ कभी-कभी सबसे ईमानदार मार्गदर्शक बन जाती है।"},"ICON-2589":{"nm":"मन-शांति कंकड़","de":"हथेली में पकड़ा कंकड़ ठंडा और चिकना है। नदी किनारे लंबे समय तक लुढ़ककर अपने सारे कोने गँवा चुके पत्थर की तरह, उँगलियों से बार-बार सहलाते रहो तो उथल-पुथल मचे मन की नुकीली धार भी धीरे-धीरे गोल होकर घिस जाती है।"},"ICON-2590":{"nm":"श्वास-ताप क्लिप","de":"नाक की नोक का तापमान साँस की गहराई चुपचाप बता देता है। ठंडी अंदर आती और गर्म बाहर जाती हवा को क्लिप शांति से पढ़ लेती है, और वैसे तो महसूस भी न होने वाली साँस आँखों के सामने साफ़ दिखा देती है। साँस का भी एक भाव होता है।"},"ICON-2591":{"nm":"भाव-मौसम स्टिकर बोर्ड","de":"आज मेरा मन साफ़ है या बादलों भरा? एक नन्हा स्टिकर चुनकर बोर्ड पर टक चिपकाते ही, शब्दों में निकालना मुश्किल रहा मूड भी एक तरह का मौसम बनकर साफ़ आकार पा लेता है। मन को भी एक मौसम-पूर्वानुमान की ज़रूरत होती है।"},"ICON-2592":{"nm":"भावना-रंग हस्त-मुहर","de":"खुशी पीली है, दुख नीला। रंग चुनकर कागज़ पर दबाकर छापो तो मन का रंग निशान बनकर रह जाता है। नाम देना मुश्किल लगने वाली भावना को भी रंग पहले आकर चुपचाप पहचान लेता है।"},"ICON-2593":{"nm":"आज-का-मन पंखुड़ी चिप","de":"एक पंखुड़ी पर आज दिन भर का मन धीरे से रख कर देखो। बसंत में उड़ती अज़ेलिया की तरह हल्की और नाज़ुक एक चिप, ढलते दिन के अंत में धीमे से पूछती है कि तुम कैसे रहे।"},"ICON-2594":{"nm":"प्रोत्साहन बुलबुला चुंबक","de":"कहने की चाहत रखने वाली बात होंठों पर बार-बार मँडराती रहती है। बुलबुला-चुंबक टक से चिपकाते ही, आवाज़ में न कही जा सकी हौसले की एक बात किसी के थके हुए दिन पर चुपचाप पहुँच जाती है। मन इसी तरह पहुँचाया जाता है।"},"ICON-2595":{"nm":"मन-की-बात लिफ़ाफ़ा मुहर","de":"न कह पाई बातें करीने से लिफ़ाफ़े में बंद कर सील कर दी जाती हैं। उँगलियों से लेई लगाकर पुराना पत्र बंद करते किसी बुज़ुर्ग की तरह, एक मुहर मन की बात सुरक्षित रख देती है, कभी खोलकर पढ़ने के दिन का चुपचाप इंतज़ार करते हुए।"},"ICON-2596":{"nm":"भाव-ताप फूल-कली","de":"बंद कली गर्माहट के छूते ही एक-एक परत सावधानी से खुलती जाती है। मन का ताप बढ़ने पर साथ खिलती यह कली—आज मैं कितना गर्माया हूँ, यह शब्दों से पहले यही फूल जान लेता है। मन में भी बसंत आता है।"},"ICON-2597":{"nm":"आत्म-प्रशंसा हस्त-दर्पण पट्टा","de":"आईना उठाकर उसमें झलकते अपने आप से चुपचाप नज़र मिलाओ। पट्टे पर लटका नन्हा शीशा जो दिखाता है वह चेहरा नहीं, बल्कि कल का वह मैं है जिसे \"अच्छी तरह झेला\" कहने वाली एक बात मिलनी चाहिए। सांत्वना कभी दूर नहीं थी।"},"ICON-2598":{"nm":"मनोभाव मुहर सेट","de":"उजली मुस्कान, छलकते आँसू, फूला हुआ रूठा होंठ। भाव-मुहरें दबाकर छापते हुए मन की डायरी लिखी जाती है। शब्दों में लिखना भारी लगने वाले दिन, एक नन्हा चेहरा मेरी जगह उस दिन का मूड चुपचाप बता देता है।"},"ICON-2599":{"nm":"भावना-उलझन सुलझा फंदा","de":"कितनी भी उलझी हुई गुच्छी हो, एक-एक धागा करके सुलझाओ तो आख़िर एक ही डोरे में लौट आती है। गड्डमड्ड होकर घुटन बनी भावनाओं को फंदे में एक-एक कर टाँगो, तो बिल्कुल समझ न आने वाले मन को भी एक पतला-सा सिरा मिल जाता है।"},"ICON-2600":{"nm":"निद्रा-सुगंध थैली डोरी","de":"तकिए के पास लटकी सुगंध-थैली से हल्की जड़ी-बूटी की महक चुपचाप फैलती है। अलमारी में गहराई से सुगंध रखने वाली दादी की उस खुशबू की तरह, डोरी सहलाते-सहलाते दिनभर तनी हुई अकड़न धीरे-धीरे सो जाती है।"},"ICON-2601":{"nm":"नींद पलटाव तख्ती","de":"करवटें बदलते हुए भोर में कहीं जाकर नींद आई रात। लेटी हुई मुद्रा को धीरे से पलट दें, तो कल की करवटें आज सुबह की ताज़गी में चुपके से बदल जाती हैं। आराम करना भी अभ्यास है, यह छोटी-सी तख्ती बिना कुछ कहे साथ देती है।"},"ICON-2602":{"nm":"तकिया-किनारे चाँदनी टांगन","de":"पर्दे की दरार से आई रोशनी की एक कतरन तकिए के किनारे टांग दो। सोए हुए चेहरे पर एक धुंधली नदी बहती है, और अंधेरे से डरने वाली प्रशिक्षु की रातें भी आख़िरकार नरम पड़ गईं। यह उसका पहला छोटा सुकून था।"},"ICON-2603":{"nm":"हाल-कली चिप","de":"आज की तबियत एक कली की तरह बंद है। चिप को हल्के से दबाओ तो वह धीरे-धीरे खिलती है — तुम अच्छी नींद सोए या नहीं, शरीर को यह सबसे पहले पता चलता है। पूरी तरह खिलने से पहले की वह हिचकिचाहट भी चुपचाप प्यारी लगती है।"},"ICON-2604":{"nm":"रात्रि-दीप बाती ढक्कन","de":"\"बत्ती मत बुझाना।\" अंधेरे से डरने वाली सबसे छोटी सदस्या के लिए किसी ने बाती पर धीरे से एक ढक्कन चढ़ा दिया। न बहुत तेज़, न बहुत मद्धम — सोने तक ही साथ निभाने का यह छोटा-सा, स्नेहिल वादा है।"},"ICON-2605":{"nm":"सुबह-सूरजमुखी पिन","de":"सिरहाने लगा दो, तो यह सूरजमुखी की तरह धीरे से सिर पहली धूप की ओर घुमा लेती है। उठने का मन न करने वाले दिनों में भी, रोशनी के बुलाने का कोई-न-कोई कारण होता ही है — यह सुबह को एक दिशा में ले चलती है।"},"ICON-2606":{"nm":"नींद-जड़ी-बूटी तकिया ब्रश","de":"लैवेंडर और कैमोमाइल को ब्रश की नोक पर लगाकर तकिए पर एक बार फेर दो। खुशबू तकिए के गिलाफ़ में रचती जाती है, और दिन भर का तनाव कंधों से धीरे-धीरे उतर जाता है। अच्छी नींद इसी छोटी-सी खुशबू से शुरू होती है।"},"ICON-2607":{"nm":"बिस्तर रज़ाई-कोना क्लिप","de":"भोर होते-होते पैर की उंगलियाँ बार-बार रज़ाई से बाहर भाग जाती हैं। कोने को क्लिप से मज़बूती से जकड़ दो, तो रातभर गर्माहट भाग नहीं पाती। \"अच्छी नींद\" कहने की जगह चुपचाप बाँध दी गई यह एक छोटी-सी हिफ़ाज़त है।"},"ICON-2608":{"nm":"तबियत-कंकड़ टोकरी","de":"दिन में एक अच्छी बात, हथेली-भर एक कंकड़। टोकरी में जमा पत्थर जितने भारी होते जाते हैं, मन भी उतना ही चुपचाप मज़बूत होता जाता है। छोटे-छोटे पलों को हाथ में समेटना — ख़ुशी हमेशा से यूँ ही गिनी जाती रही है।"},"ICON-2609":{"nm":"प्रण-तारा संग्रह मटका","de":"हर रात आज के संकल्प को तारे का आकार देकर मर्तबान में टपका देते हैं। जब वह लबालब भर जाता है, मर्तबान एक छोटा-सा रात्रि-आकाश बन जाता है। खाली रहा मुँह जानता है — वादे तभी चमकते हैं जब उन्हें जमा किया जाए।"},"ICON-2610":{"nm":"छोटा-इनाम कैंडी-टांगन","de":"थके हुए दिन के अंत में खुद को दी जाने वाली एक टॉफी। टांगन से एक निकालकर मुँह में रखते ही, कोई पहचाने या न पहचाने, सब ठीक लगने लगता है। छोटा इनाम ही सबसे ईमानदार वाहवाही होती है।"},"ICON-2611":{"nm":"आज-सम्पन्न मुहर","de":"स्याही लगाकर डायरी पर ज़ोर से दबाओ — \"आज कर दिखाया।\" अच्छे से बिताया दिन हो या बस किसी तरह गुज़ारा दिन, दोनों एक ही खाना समान रूप से भरते हैं। हर दिन का सम्पूर्ण होना ज़रूरी नहीं, बस मुहर लगाना न रुके, इतना काफ़ी है।"},"ICON-2612":{"nm":"हौसला-ध्वज आधार","de":"ज़मीन में मज़बूती से गाड़ दो, तो हवा जितनी तेज़ चलेगी, झंडा उतना ही ज़ोर से लहराएगा। जो डोलता है उसे भी सहारा देने वाला हाथ चाहिए होता है। किसी का हौसला बढ़ाने वाला मन इसी तरह नीचे से टिका रहता है।"},"ICON-2613":{"nm":"लक्ष्य-बीज रोपण गमला","de":"लक्ष्य ज़बानी रटा नहीं जाता, मिट्टी में बोया जाता है। एक बीज बोकर, पानी देकर इंतज़ार करते-करते, बेचैनी धीरे-धीरे जड़ों में बदल जाती है। गमले के भीतर सिर्फ़ अंकुर नहीं उगता।"},"ICON-2614":{"nm":"शाबाशी-स्टिकर बोर्ड","de":"अच्छा किए हर काम पर एक स्टिकर। बोर्ड जितना रंग-बिरंगा भरता जाता है, बिना ध्यान दिए बीत गए दिन उतने ही रंगों में फिर से जी उठते हैं। बचपन में हम जानते थे — तारीफ़ जितनी चिपकाई जाए, उतनी ही गहरी दिखती है।"},"ICON-2615":{"nm":"प्रण-रिबन बाँधन कड़ी","de":"रिबन को कड़ी में पिरोकर गाँठ बाँधता हाथ। इतनी मज़बूती से कि खुले नहीं, पर इतनी ज़ोर से भी नहीं। संकल्प ठीक इस गाँठ जैसा होता है — बहुत कस दो तो टूट जाता है, बहुत ढीला छोड़ दो तो चुपके से खिसक जाता है।"},"ICON-2616":{"nm":"छोटी-सफलता शंख-चिप","de":"समुद्र किनारे से बीने सीप के खोल पर एक छोटी उपलब्धि लिख दो। लहरों से तराशा और सँवारा जाकर यहाँ तक पहुँचे एक टुकड़े की तरह, तुम्हारा दिन भी लंबा सफ़र तय करके अब चमकदार हो चुका है। जो समय को सह लेता है, वह अंततः चमकता ही है।"},"ICON-2617":{"nm":"इनाम-मेडल हुक","de":"मेहनत से पाया पदक दराज़ में नहीं, आँखों की ऊँचाई पर टांगा जाता है। कुंडी पर टंगा वह भार हर सुबह कंधे तान देता है। पुरस्कार छिपाने की चीज़ नहीं, देखे जाने के लिए वहाँ टांगकर रखी जाने वाली चीज़ है।"},"ICON-2618":{"nm":"बारिश-छाता टपकन-कप","de":"बरसाती बारिश छाते की नोक से टपटप बहती है। एक कप नीचे रख दो तो दहलीज़ नहीं भीगती। जो बरस रहा है उसे रोका नहीं जा सकता, पर उसके गिरने की जगह ज़रूर तय की जा सकती है।"},"ICON-2619":{"nm":"गर्मी-शीतलन थैली","de":"कड़ी गर्मी में मंच के पीछे, गर्दन पर हल्के से रखा एक ठंडा पैक। भभकती, चढ़ती गर्मी एक पल को थम जाती है। \"थोड़ा साँस ले लो।\" गर्मी से पहले मेरी परवाह करने वाला हाथ भरोसा देता है।"},"ICON-2620":{"nm":"पंखा-ब्लेड फ़िक्सिंग क्लिप","de":"ज़ोर से घूमते पंख भी एक क्लिप से चुपचाप थम जाते हैं। हवा जितनी तेज़ हो, उसे मज़बूती से थामने वाली किसी चीज़ की उतनी ही ज़रूरत होती है। तेज़ घूमती चीज़ें आख़िर में इसी से सुरक्षित होती हैं कि उन्हें कौन थामे रखता है।"},"ICON-2621":{"nm":"गीला-जूता सुखावन छड़","de":"बारिश में भीगे जूते एक रात में मन तक को सीलन से भर देते हैं। छड़ी को अंदर डाल दो, तो सुबह तक वे फिर से पहनने लायक सूखे हो जाते हैं। जो गीला है उसे फेंकना नहीं, संभालकर सुखाना होता है।"},"ICON-2622":{"nm":"जूता-मिट्टी खुरचन तख्ता","de":"धान के खेत की मिट्टी लपेटे लौटे गमबूट। पायदान पर रगड़-रगड़कर झाड़ने के बाद ही फर्श पर कदम रखा जाता है। बाहर की कीच़ दरवाज़े पर ही छोड़ आना — घर को साफ़-सुथरा रखने की एक पुरानी शिष्टता है।"},"ICON-2623":{"nm":"गर्मी ठंडी-टाइल तख्ती","de":"नंगे पाँव पहले जान जाते हैं। गर्मी में फर्श पर बिछी टाइल पर तलवे रखते ही, दोपहर की तपिश एक मुट्ठी ठंडक में चुपचाप घुल जाती है। एक छोटी-सी ठंडक भी लंबे मौसम को सहनीय बना देती है।"},"ICON-2624":{"nm":"बारिश-रोधक चौखट पट्टी","de":"दहलीज़ पर बस एक पट्टी बाँधी, और बरसात का पानी अब भीतर नहीं आ पाता। भीतर और बाहर को बाँटती एक पतली रेखा। जिस जगह की रक्षा करनी हो, वहाँ बड़ी दीवार से ज़्यादा एक चुस्त सीमा-रेखा फबती है।"},"ICON-2625":{"nm":"मच्छर-धूप आधार थाली","de":"गर्मी की रात, मच्छर अगरबत्ती को स्टैंड पर रखो तो तीखा पर जाना-पहचाना धुआँ उठने लगता है। गोल-गोल घटती अगरबत्ती की तरह रात भी धीरे-धीरे गहराती जाती है। यह उस ज़माने की महक है जब चबूतरे पर लेटकर तारे गिने जाते थे।"},"ICON-2626":{"nm":"गर्मी कूल-स्लीव कड़ी","de":"धूप से झुलसी बाँहों को स्लीव से ढक लो। कड़ी से कमीज़ की आस्तीन पर कसकर बाँध दो तो दोपहर का काम भी सहनीय हो जाता है। ठंडक तो बस उस जगह को एक बित्ता ढक देने की छोटी-सी दयालुता है, जहाँ धूप छूती है।"},"ICON-2627":{"nm":"सूखे-पत्ते झाड़ू","de":"आँगन भर बिखरे सूखे पत्तों को हाथ-झाड़ू से सरसराते हुए बुहार लो। एक पूरा मौसम पैरों तले खड़खड़ाता है। किसी चीज़ को समेटना, दरअसल जिसे विदा करना है उसे प्रेम से विदा करना भी है।"},"ICON-2628":{"nm":"हवादार खिड़की टेक छड़","de":"घुटन भरे कमरे में एक छड़ी लगाकर खिड़की हल्की-सी खुली छोड़ दो। पतझड़ की हवा चुपके से भीतर आकर बासी हवा को साथ ले जाती है। हवादारी दरअसल भीतर जमा हो गई चीज़ को बाहर की हवा से चुपचाप बदल देने वाला एक छोटा-सा साँस-द्वार है।"},"ICON-2629":{"nm":"बलूत-फल थैली स्टॉपर","de":"गिलहरी की तरह थैली भर बलूत फल भरकर मुँह पर ढक्कन लगा दो। कसकर, ताकि एक भी लुढ़ककर बाहर न जाए। जमा की गई चीज़ की रक्षा करने की चाह, सर्दी पार करने वाली नन्ही चीज़ों की पुरानी सहज-वृत्ति है।"},"ICON-2630":{"nm":"पतझड़ रज़ाई धूल-झाड़न","de":"गर्मी भर ओढ़ी रज़ाई को आँगन में टांग कर पीटने वाले से ज़ोर-ज़ोर से पीटो। धूल के बीच से धूप की महक फैलती है। पुराने मौसम को झाड़ना पड़ता है, तभी नए मौसम को ओढ़ा जा सकता है — यह बात कलाई पहले याद रखती है।"},"ICON-2631":{"nm":"खिड़की-दरार हवारोधी डोर","de":"खिड़की की दरार से रिसती ठंडी हवा को एक डोरी से मज़बूती से रोक दो। एक पतली लकीर कमरे की गर्माहट को आख़िर तक बचाती है। बड़ी ठंड हमेशा एक छोटी-सी दरार से शुरू होती है — यह बात सर्दी की तैयारी जानती है।"},"ICON-2632":{"nm":"सूखे-पत्ते छलनी आवरण","de":"नाली के ऊपर बिछी छलनी। सूखे पत्तों को महीन छान लेती है और सिर्फ़ पानी को बहने देती है। बिना रुके बहने के लिए यह तय करना पड़ता है कि क्या पार जाने दें और क्या रोक लें — पतझड़ की छज्जा यही कहती है।"},"ICON-2633":{"nm":"सूखा-घास पूला क्लिप","de":"बिल्कुल सूखी घास के पूले को क्लिप से मज़बूती से बाँधो। बिखरने वाली चीज़ों को एक साथ समेटता हाथ। गर्मी की हरियाली पूरी तरह उतर चुकी जगह पर भी, समेट लेने से उपयोगिता ज्यों की त्यों बची रहती है।"},"ICON-2634":{"nm":"पतझड़-हवा तापमान झुलनी","de":"हवा चले तो झुलनी हौले से डोल उठती है। उसके डोलने की चौड़ाई से अंदाज़ा लगता है कि आज पतझड़ कितना गहरा हो चुका है। तापमान कोई अंक नहीं, वह सबसे पहले किसी डोलती चीज़ के रूप में हाथ तक पहुँचता है।"},"ICON-2635":{"nm":"जैकेट-जेब हाथ-गरमाई खोल","de":"\"हाथ ठंडे हो रहे होंगे न।\" कोट की जेब में रखा हैंड-वॉर्मर का खोल ठंडी उंगलियों को धीरे से गरमाता है। किसी की ठंड का पहले ख़याल रखने वाला मन हमेशा चुपचाप जेब के भीतर बैठा रहता है।"},"ICON-2636":{"nm":"खिड़की-नमी बूँद-आधार","de":"सर्दी की खिड़की ने रातभर जो आँसू बहाए, उन्हें किनारी चुपचाप थाम लेती है। भीतर और बाहर के तापमान के फ़र्क़ से बनी एक नन्ही जलधारा। जहाँ फ़र्क़ बड़ा हो, वहाँ बहने वाला भी उतना ही ज़्यादा होता है — भोर की खिड़की यह हर दिन दिखाती है।"},"ICON-2637":{"nm":"स्टोव-आग रक्षक जाली","de":"धधकते चूल्हे के आगे सुरक्षा-जाली खड़ी कर दो। गर्माहट पास, ख़तरा ठीक एक बित्ता दूर। आग को पास रखते हुए भी किसी को चोट न लगने देना, किसी की देखभाल करने की सबसे बुनियादी दूरी है।"},"ICON-2638":{"nm":"जाड़ा-रज़ाई पकड़-क्लिप","de":"मोटी शीत-रज़ाई बार-बार खिसक जाए, तो क्लिप उसे दबाकर चुपचाप जगह पर टिका देती है। भारी गर्माहट को मज़बूती से थामना पड़ता है, तभी वह अपने मोल की साबित होती है। जाड़े की रात का आराम इसी तरह चुस्ती से सँभाला जाता है।"},"ICON-2639":{"nm":"बर्फ़-जमाव खुरचन","de":"भोर में शीशे पर सफ़ेद जमी बर्फ़ को खुरचनी से खुरच-खुरचकर हटा दो। धुंधला होता नज़ारा एक-एक लकीर करके साफ़ होता जाता है। जो जम चुका है, वह भी आख़िर खुरचा जा सकता है — यह बात जाड़े की सुबह की उंगलियाँ सिखाती हैं।"},"ICON-2640":{"nm":"गरम-पानी-बोतल ढक्कन खोल","de":"गर्म पानी भरी बोतल पर एक खोल चढ़ा दो। रातभर ठंडी न पड़े, इसलिए गर्माहट पर एक और परत लपेट दी जाती है। गर्माहट को लंबे समय थामे रखने का तरीक़ा आख़िर यही है — किसी चीज़ से उसे मन लगाकर लपेट देना।"},"ICON-2641":{"nm":"पवन-अवरोधक कागज़ छड़","de":"दरवाज़े की दरार से घुसती छुरी-सी तेज़ हवा तुमसे मिलते ही ठिठक जाती है। कागज़ी परदे के निचले किनारे को कसकर दबाए रखने वाली एक छड़ी। कमरे की गर्माहट आख़िरकार अपने घर वालों की रक्षा कर पाती है — जाड़ा इसी छोटी-सी ज़िद से गर्म रहता है।"},"ICON-2642":{"nm":"पैर-वॉर्मर आधार प्लेट","de":"पैर के हीटर के नीचे बिछी गोल थाली। सारी गर्मी अकेली सहती है, फिर भी फर्श पर एक धब्बा तक नहीं छोड़ती। जब किसी के पैर की उंगलियाँ आराम से गरमाती हैं, तब मेरे हिस्से का दिन चुपचाप ख़त्म होता है।"},"ICON-2643":{"nm":"नमी-पोंछ कपड़ा लटकन","de":"भोर की खिड़की पर जमी बूँदें पोंछ चुका कपड़ा अपनी जगह न खोए, इसलिए एक कड़ी दीवार पर टंगी इंतज़ार करती है। लबालब भीग जाने से ज़्यादा, फिर से सूखा होकर अगली सुबह का इंतज़ार करना ही सोख लेने का असली मक़सद है।"},"ICON-2644":{"nm":"जाड़ा-दस्ताने सुखाने की टांगन","de":"बर्फ़ की एक जंग ख़त्म करके लौटे दस्ताने रेडिएटर के पास अपनी उंगलियाँ पूरी तरह फैला देते हैं। टांगन पर लटके, हल्की भाप छोड़ते उनका यह नज़ारा। लाल हो चुकी नाक वाली दोपहर के अंत में आने वाला, जाड़े का सबसे सुकून भरा कपड़ा-सुखाना है यह।"},"ICON-2645":{"nm":"पंख-झाड़न रिफ़िल","de":"पंख घिस जाएँ तो नए पंखों से बदल दो। धूल भगाता सिरा फिर से मुलायम हो जाने का पल। सफ़ाई के औज़ारों के भी मौसम बदलते हैं — यह छोटी-सी बदली हथेली पर चुपचाप बता देती है।"},"ICON-2646":{"nm":"पोंछा निचोड़न मूठ","de":"कलाई की ताकत थोड़ी बचाने के लिए लगा है यह हैंडल। एक बार मरोड़ो और पोंछा ख़ुद-ब-ख़ुद पानी उगल देता है। धोबी-पाट के आगे कराहने वाले दिनों को अलविदा। घर-गृहस्थी में एक मुट्ठी सलीका ही दरअसल अपनापन बन जाता है।"},"ICON-2647":{"nm":"फ़र्श-ब्रश रिप्लेसमेंट हेड","de":"फर्श का ब्रश जब पूरी तरह घिस जाए, तो सिर्फ़ सिरा बदल दिया जाता है। मूठ जस की तस रहती है, हाथ को जानी-पहचानी लगती वज़न भी वैसी ही रहती है। लंबे समय इस्तेमाल होने वाली चीज़ों में यह छोटी, पर पक्की अपनत्व बसती है — पूरी चीज़ को न फेंकने की।"},"ICON-2648":{"nm":"धूल-रोलर रिफ़िल कोर","de":"रोलर की आख़िरी परत उतारने के बाद न जाने क्यों कुछ अधूरा-सा लगता है। तभी लगाया जाता है एक नया कोर। स्वेटर पर लगी एक भी रोएंदार महीन धूल तक की ज़िम्मेदारी आख़िर तक निभाने का, यह हठी पर स्नेहिल रिफ़िल का वादा है।"},"ICON-2649":{"nm":"कोना धूल खुरचन","de":"झाड़ू जहाँ नहीं पहुँच पाती, उन कोनों में भी धूल चुपचाप अपना घर बसा लेती है। पतले सिरे से कोने को कुरेद-कुरेदकर साफ़ करना। जो नज़र नहीं आता, उसका भी ख़याल रखने वाला मन ही घर-गृहस्थी की असली शान है।"},"ICON-2650":{"nm":"झाड़ू साफ़ करने की कंघी","de":"बुहारते हुए झाड़ू को भी कभी-कभार आराम देने वाले हाथ की ज़रूरत होती है। सींकों में उलझे बालों को इस कंघी से सुलझा दो, तो एक बार का काम पूरा कर चुका झाड़ू आख़िरकार अगली बुहारन के लिए तैयार होता है।"},"ICON-2651":{"nm":"लकड़ी-नस वैक्स पैड","de":"फर्श की नसों के साथ-साथ मोम की एक परत चढ़ाओ, तो लकड़ी धीरे-धीरे उस चमक को याद करती है जिसे वह लंबे समय से भूल चुकी थी। तलवे फिसलते-से, न फिसलते-से — पूरा घर चमकदार, ख़ुशनुमा मुस्कुराता है ऐसी एक दोपहर।"},"ICON-2652":{"nm":"किवाड़-दरार धूल बुहारन","de":"मैं दरवाज़े की दरार में बसने वाली धूल पर नज़र रखता हूँ। दरवाज़ा खुलते-बंद होते हर बार चुपके से जमा होने वाली उसे, अपने पतले शरीर से बुहार लेता हूँ। दरार जितनी संकरी और गहरी होती है, उतनी ही पक्की मेरी बारी आती है।"},"ICON-2653":{"nm":"दहलीज़-पायदान जाली कैप","de":"दहलीज़ के पायदान ने जो धूल निगली, वह फिर बाहर न रिसे, इसलिए एक जाली-टोपी आख़िरी पहरेदार बनकर खड़ी होती है। कीचड़ भरे जूते बाहर की दुनिया से जो धूल लाते हैं, उसे यहीं तक अंदर आने दिया जाता है, आगे नहीं।"},"ICON-2654":{"nm":"नल-मैल ब्रश","de":"नल की गर्दन पर चुपके से जम गई मैल को छोटा-सा ब्रश गोल-गोल घूमकर उतार देता है। जिस जगह को हाथ रोज़ छूते हैं, उसे उतना ही ज़्यादा चमकना चाहिए — यही वह शिष्टता है जो यह नन्हा ब्रश बाथरूम में निभाता है।"},"ICON-2655":{"nm":"निकास-बाल जाली टोपी","de":"नाली की ओर बह रहे बालों को मैं चुपचाप थाम लेता हूँ। जाम होने की छोटी-सी विपत्ति को एक टोपी से रोक देना। गोल, दमदार इस छोटे नायक का दिन हमेशा पैरों तले, चुपचाप बहता रहता है।"},"ICON-2656":{"nm":"टाइल-जोड़ खुरचन","de":"सफ़ेद टाइलों के बीच काली फैली सीवन, उस पुराने वक़्त को नोक से हौले-हौले खुरच दो। तंग दरारें जब साफ़ हो जाती हैं, तो पूरा बाथरूम नए जैसा हल्की साँस लेता है।"},"ICON-2657":{"nm":"शावर-सिर सफ़ाई पिन","de":"बंद शावर-हेड के छिद्रों को पिन की नोक से टक करके खोल दो, तो अब तक बस टप-टप टपकता पानी फिर से ठंडा-ठंडा बहने लगता है। एक छोटी-सी रुकावट खुलने की, वह सुखद सुबह की पानी-ध्वनि।"},"ICON-2658":{"nm":"शौचालय-ब्रश स्टैंड कप","de":"टॉयलेट-ब्रश भी तभी असल में स्वच्छ रहता है जब वह किसी सूखी जगह पर आराम करे। बूँदें थामने वाले एक छोटे प्याले में सलीके से टिककर अगली बारी का इंतज़ार करता है। किसी औज़ार की गरिमा उसके इस्तेमाल में नहीं, उसे रखने के तरीक़े में झलकती है।"},"ICON-2659":{"nm":"फफूँद साफ़ करने का स्पंज","de":"टाइल के कोनों में काली फैली फफूँदी को, इस ज़िद्दी मेहमान से स्पंज विनम्रता से विदा होने को कहता है। एक बार पोंछते ही बाथरूम फिर से अपनी असली सफ़ेदी में जगमगा उठता है।"},"ICON-2660":{"nm":"शीशा-धुँध पोंछन","de":"नहाकर निकलने के बाद धुँधले हुए आईने के सामने, निचोड़न एक लकीर खींचता है और साफ़ चेहरा लौट आता है। धुंध के पीछे कुछ देर छिपी रही आज की भाव-भंगिमा से फिर से आमने-सामने होने का पल।"},"ICON-2661":{"nm":"स्नानघर-चप्पल हुक","de":"भीगी चप्पल को उलटा लटका दो तो पानी टपटप बहकर निकल जाता है और भीतरी सतह सूखी-आरामदायक हो जाती है। ताकि अगले की पाँव को ठंडक न लगे। एक छोटी-सी टांगन की परवाह हमेशा एक क़दम पहले, आगे बढ़कर स्वागत करने खड़ी रहती है।"},"ICON-2662":{"nm":"नाख़ून ब्रश केस","de":"नाख़ूनों के नीचे की मैल रगड़ने वाले छोटे ब्रश का भी अपना घर होता है। डिब्बी में सलीके से बैठकर, बिना नमी के सूखा-सुहावना रहते हुए, यह अगले वॉशबेसिन का इंतज़ार करता है। सफ़ाई हमेशा चीज़ों को व्यवस्थित रखने से चुपचाप शुरू होती है।"},"ICON-2663":{"nm":"टूथब्रश सैनिटाइज़र-कप ढक्कन","de":"दिन में दो बार मुँह से मिलने वाले टूथब्रश को भी एक छोटी-सी पनाहगाह चाहिए होती है। रोगाणुनाशक प्याले का ढक्कन जैसे ही बंद होता है, बाथरूम में तैरती नमी से एक हिस्से की स्वच्छता चुपचाप सुरक्षित हो जाती है।"},"ICON-2664":{"nm":"रुई-कली सफ़र कैप्सूल","de":"यात्रा बैग में कॉटन-स्वैब टूटें या बिखरें नहीं, इसलिए एक कैप्सूल उन्हें अपनाकर धीरे से संभाल लेता है। जितनी छोटी चीज़ होती है, उतना ही पहले से सँभालकर रखना पड़ता है — तभी अनजान राह पर घबराहट नहीं होती।"},"ICON-2665":{"nm":"साँस-जाँच लघु बोर्ड","de":"हथेली पर \"हा\" फूँककर मिनी पट्टिका से छुआओ, तो साँस उसे छूकर दूधिया धुँधली कर देती है। ठंडे दिन में \"मैं यहाँ ज़िंदा हूँ\" का सबसे प्यारा सबूत, यह छोटी पट्टिका बिना कुछ कहे दर्ज कर लेती है।"},"ICON-2666":{"nm":"कान-साफ़ी संग्रह-घर","de":"कान-खुजाई अगर बैग में लेकर बाहर जाए, तो उसकी नोक जल्दी कुंद हो जाती है। इसीलिए बनाया गया एक नन्हा-सा घर। जहाँ ले जाने पर भी नोक को चोट नहीं लगती, वहाँ यह नाज़ुक औज़ार चैन से सोता है।"},"ICON-2667":{"nm":"रुमाल तह लगाने की क्लिप","de":"चारों कोनों को करीने से मोड़े रूमाल को क्लिप धीरे से दबोच लेती है, ताकि बैग में वह बिखरे नहीं। सलीके से तह किया हुआ एक टुकड़ा, जब भी निकाला जाए, ख़ामोश सी शालीनता दे जाता है।"},"ICON-2668":{"nm":"पट्टी-बैंड केस","de":"घुटना छिल जाने वाले दिन, डिब्बी खोलते ही तरह-तरह की पट्टियाँ कतार में तुम्हारा इंतज़ार करती हैं। एक छोटी-सी खरोंच पर भी इतनी फ़िक्र करने वाली यह मायूसी। प्राथमिक-चिकित्सा-पेटी हमेशा हाथ की पहुँच के पास ही रखनी चाहिए।"},"ICON-2669":{"nm":"अंगुली-छाप पोंछन","de":"शीशे पर रह गए उंगलियों के निशान पोंछ दो, तो झिझकते हाथों की छाप मिट जाती है। हर छुए गए स्थान पर धुँधली रही खिड़की के पार की दुनिया फिर से साफ़ हो जाती है — हथेली-भर की यह छोटी-सी जादूगरी है।"},"ICON-2670":{"nm":"अलगाव-कचरा विभाजक","de":"काग़ज़ इस तरफ़, डिब्बे उस तरफ़। एक विभाजक उलझने ही वाली नियति को अलग कर देता है। पुनर्चक्रण आख़िर में सलीके से बाँटने वाला मन ही तो है, और उसकी पहली लकीर यह चुस्त खाना साफ़-साफ़ खींच देता है।"},"ICON-2671":{"nm":"स्टिकर छीलन फावड़ा","de":"चिपचिपा जमा हुआ स्टिकर भी मेरे आगे चुपचाप हार मान लेता है। चपटे फल को कोने में हल्के से खिसकाओ, तो बिना एक भी निशान छोड़े साफ़-सुथरी विदाई हो जाती है।"},"ICON-2672":{"nm":"मास्किंग टेप काटने के दाँत","de":"मास्किंग टेप इस्तेमाल करने के लिए कैंची ढूँढ़ते फिरने की ज़रूरत नहीं। दाँतों पर लगाकर खींचो, तो वह नस के साथ-साथ ठीक-ठाक कट जाता है। सजावट करते हाथ की उँगलियों का सबसे प्यारा, छोटा और फुर्तीला दोस्त।"},"ICON-2673":{"nm":"कोना जोड़ बंधक-कील","de":"उखड़ते कोने को भीतर से मज़बूती से थामे रखने वाली एक छोटी कील। बिना दिखे किसी जगह से चुपचाप कोण को सही बनाए रखती है। ऊपर से सीधी दिखने वाली चीज़ों के पीछे प्रायः ऐसा ही कोई छिपा सहारा होता है।"},"ICON-2674":{"nm":"सील-पत्रक सुरक्षा डिब्बा","de":"प्यारी सील-शीट्स मुड़ें या सीली न हों, इसलिए वे रक्षक फ़िल्म के साथ नली में सोती हैं। संग्रह करने की ख़ुशी के साथ हमेशा-हमेशा उसे प्रेम से बचाए रखने की फ़िक्र भी जुड़ी रहती है।"},"ICON-2675":{"nm":"स्याही-स्टैम्प साफ़ी ब्रश","de":"स्याही में तर मुहर की दरारों को ब्रश नस के साथ-साथ हौले-हौले बुहारकर पुराना रंग उतार देता है। अगली छपी छाप साफ़-सुथरी आए, इसके लिए पहले से सफ़ाई कर देने वाला यह छोटा, मेहनती हाथ।"},"ICON-2676":{"nm":"साफ़-पन्ना होल्डर विंग","de":"बाइंडर के पन्ने फिसलकर बाहर न आएँ, इसलिए पंख दोनों ओर से कसकर पकड़े रहते हैं। हर पन्ना अपनी जगह पर टिका रहता है, इसीलिए पन्ने पलटती उंगली कभी उलझती नहीं।"},"ICON-2677":{"nm":"सजावटी-टुकड़े स्कूप","de":"यहाँ-वहाँ बिखरे सजावटी छोटे टुकड़ों को छोटी कुदाल से एक ही झटके में उठा लो। उंगलियों से एक-एक करके बीनने की झंझट ख़त्म हो जाए, तो मन लगाकर कुछ बनाने का वक़्त और भी सुहावना हो जाता है।"},"ICON-2678":{"nm":"बुकमार्क गुच्छा जड़न-कील","de":"बुकमार्क के छोर पर लगी लटकन ढीली न पड़े, इसलिए फास्टनर उसे कसकर बाँध देता है। अधूरे पन्ने तक वापस ले जाने वाली इस राह-दिखाई का भी अपना बना-ठना रहना ज़रूरी होता है, तभी मन को चैन मिलता है।"},"ICON-2679":{"nm":"डेको-पेन ढक्कन क्लिप","de":"सजावटी पेन की नोक सूखने न पाए, इसलिए ढक्कन को कसकर पकड़े रहती है यह क्लिप। भूले से खुला रह गया पेन अकड़ जाए, इस मुसीबत को रोक देती है, ताकि रंग हमेशा पहली बार जैसा नम बहता रहे।"},"ICON-2680":{"nm":"पेचकस बिट इंसर्ट टिप","de":"स्क्रूड्राइवर की मूठ वैसी ही छोड़कर सिर्फ़ आगे की नोक बदल दी जाती है। चौकोर हो या सीधी, दोनों बड़ी सहजता से। एक ही चीज़ से कई काम निपटा लेने वाली चतुराई इस नन्हे नोक-सिरे में सलीके से समाई है।"},"ICON-2681":{"nm":"रेगमाल कोना रैप","de":"खुरदुरी सतह को गोल लपेटकर पकड़ो तो हथेली ही औज़ार बन जाती है। सर-सर, नस के साथ-साथ हर बार रगड़ने पर खुरदुरा कोना गोल होता जाता है, और आख़िरी चिकनाहट को हमेशा इंसान की उंगलियाँ ही पहचानती हैं।"},"ICON-2682":{"nm":"स्क्रू-छंटनी फ़नल","de":"बिखरे पेंच संकरी गर्दन से गुज़रकर लुढ़कते-लुढ़कते एक जगह जमा हो जाते हैं। मेज़ पर इधर-उधर लुढ़कती छोटी चीज़ों के अपनी जगह मिलने की आवाज़ — जैसे उलझा हुआ मन भी सलीके से सुलझ जाता है।"},"ICON-2683":{"nm":"टेप-मेज़र हुक","de":"फ़ीता-नाप के छोर की कुंडी अकेले काम करने वाले का दूसरा हाथ है। कोने पर टिका दो तो फ़ीता डगमगाता नहीं, और नापी गई लंबाई जितना ही हाथ और मन भी ज़्यादा ईमानदार होते जाते हैं।"},"ICON-2684":{"nm":"स्पैनर हैंडल कवर","de":"ठंडी धातु की मूठ पर चढ़ी एक परत। हाथ में पकड़ते ही ठंडक की जगह मुलायम गर्माहट छूती है। जब औज़ार पकड़ने वाले का पहले ख़याल रखे, तभी वह लंबे समय तक साथ रहता है।"},"ICON-2685":{"nm":"सूआ-सिरा रक्षक शंकु","de":"हर नुकीले सिरे पर एक-एक छोटी टोपी चढ़ा दी जाती है। दराज़ में हाथ फेरने पर भी चुभने का डर नहीं — जो जितना तेज़ होता है, उसे उतनी ही सावधानी से ढँक दो तो किसी को चोट नहीं लगती।"},"ICON-2686":{"nm":"बिजली-तार खोल उतारन फल","de":"बस बाहरी आवरण पतला-सा उतारो, भीतर के तार को कोई नुक़सान न पहुँचे। एक परत को धीरे से खोलते ही ताँबे की चमकती लट जैसे ही नज़र आती है, एक अच्छा फल जानता है कि ठीक कहाँ रुकना है।"},"ICON-2687":{"nm":"समतल-मापी बुलबुला-खिड़की सफ़ाई","de":"बुलबुला ठीक बीचोबीच जाकर रुके, तभी असल में समतल होता है। नन्ही खिड़की को साफ़ पोंछ देना, लकीर खींचने से पहले साँस को सम करने की उस ख़ामोश तैयारी जैसा ही है।"},"ICON-2688":{"nm":"कील ठोंकने की उंगली-सुरक्षा-आस्तीन","de":"कील थामे उंगली को घेरे रहने वाली एक छोटी आस्तीन। हथौड़ा चूक भी जाए तो कोई बात नहीं, बेख़ौफ़ होकर ठोको — उंगली की जगह चोट सहने की तैयारी पूरी तरह से की जा चुकी है।"},"ICON-2689":{"nm":"खाना-कटोरा एंटी-स्लिप मैट","de":"खाने की कटोरी फर्श पर न फिसले, इसे थामने वाली रबड़ की एक परत। मज़े से खाते-खाते कटोरी भाग न जाए, इसलिए एक बार के खाने की शांति एक न डगमगाने वाली जगह से शुरू होती है।"},"ICON-2690":{"nm":"आहार-स्कूप हुक","de":"चारा उलीचने वाली करछुल को दीवार पर टांगकर हल्के से सुखाओ। हर बार खाने की बेला पर उसी जगह से हाथ का स्वागत करने वाली एक छोटी सी व्यवस्था — किसी का पेट भरने की ज़िम्मेदारी होना, दरअसल इतना ही स्नेहिल काम है।"},"ICON-2691":{"nm":"पानी-कटोरा ओवरफ़्लो प्लेट","de":"पानी की कटोरी के किनारे से छलककर बहा एक घूँट पानी चुपचाप थाम लेती है। फर्श गीला न हो, इसलिए पहले से ही उसे संभाले रखने वाली चौड़ी थाली की बदौलत, पाँव तले हमेशा सूखा-सुहावना रहता है।"},"ICON-2692":{"nm":"स्नैक-बाँटन चिमटा","de":"नाश्ते का ठीक एक टुकड़ा उठाकर सौंपने वाली चिमटी। नाक आगे बढ़ाए इंतज़ार करते नन्हे मुँह के सामने भी, बाँटने के काम की एक बेहद सलीकेदार, प्रेमिल उंगली होती है।"},"ICON-2693":{"nm":"आहार-बोरी रोल क्लिप","de":"खोली गई चारा-थैली के मुँह को गोल लपेटकर काटती एक छोटी क्लिप। एक ही टक-से बंद होते ही सीलन रुक जाती है, और अगली सुबह की करारी मुट्ठी भर पूरी तरह सुरक्षित रहती है।"},"ICON-2694":{"nm":"बोतल-टोंटी स्टॉपर","de":"पानी की बोतल की टोंटी में सटीक बैठने वाला एक ढक्कन। टप — टपकता पानी थम जाता है और किनारा सूख जाता है। जो अच्छे से बंद हो, वह रिसता नहीं, और लंबे समय तक साफ़ जमा रहता है।"},"ICON-2695":{"nm":"आहार-नाप निशानदार कप","de":"निशान के अनुसार ठीक एक प्याला निकाल दो। न ज़्यादा, न कम — आज के खाने को निष्पक्षता से नापने वाले इस हाथ में, नन्हे परिवार-सदस्य का दिन बिल्कुल सही मात्रा में समाया रहता है।"},"ICON-2696":{"nm":"गिरा-चारा मैट रिम","de":"गिरा हुआ खाना चटाई से बाहर न फैले, इसे रोकने वाली एक किनारी। हल्की-सी उठी हुई एक किनारी, बिखरने ही वाले कणों को कसकर समेट लेती है।"},"ICON-2697":{"nm":"स्टैक्ड-बाउल सेपरेटर रिंग","de":"एक-दूसरे में फँसी दो कटोरियों को हल्के से अलग कर देने वाली एक छोटी वलय। जो हाथ उन्हें कसकर चिपकी देखकर कराह रहा था, वह अब हल्का हो जाता है। अच्छे से अलग कर देना भी, ग़ौर करो तो, एक स्नेहिल देखभाल ही है।"},"ICON-2698":{"nm":"आँगन बॉल फ़नल","de":"आँगन भर लुढ़ककर बिखरी गेंदों को एक जगह जमा कर देने वाली कीप। भरपूर खेल-कूद वाली शाम के बाद, इधर-उधर बिखरी चीज़ों को समेटने वाला हाथ अपने-आप याद आ जाता है।"},"ICON-2699":{"nm":"बाड़ खूँटी कैप","de":"बाड़ के हर खूँटे पर एक गोल टोपी चढ़ा दी जाती है। हवा-बारिश में सिरा फटे नहीं, इसलिए एक-एक नन्ही चीज़ तक का ख़याल रखकर उसे ढँकने वाला मन पूरे आँगन में रच-बस गया है।"},"ICON-2700":{"nm":"प्ले-टनल फ़ोल्डिंग हुक","de":"भरपूर खेली गई खेल-सुरंग को करीने से तह करके टांगने वाली एक कड़ी। मिट्टी से सना दिन अच्छे से समेटकर टांग दो, तो अच्छे से समेटा गया खेल हमेशा कल का वादा करता है।"},"ICON-2701":{"nm":"रस्सी-हैंडल कुशन","de":"एक कुशन जो खिंचाव वाली रस्सी की पकड़ को मुलायमी से लपेटता है। चाहे कितनी भी ज़ोर से खींचो, हथेली कभी नहीं छिलती। जितनी देर पकड़े रहो, हाथ उतना ही आरामदायक रहता है—यह किसी के छोटे से ख़याल की बदौलत है।"},"ICON-2702":{"nm":"आँगन छाया-कपड़ा क्लैंप","de":"एक क्लैंप जो आँगन में तने छाया-कपड़े को मज़बूती से थामे रखता है। दोपहर की ठंडक भी तभी ठहरती है जब उसे थाम कर रखा जाए। क्लैंप के सहारे टिकी उस छाया तले, एक सुस्त दोपहर लंबी होकर विश्राम करती है।"},"ICON-2703":{"nm":"फावड़ा-फल आवरण","de":"खुदाई वाले फावड़े के फल पर धीरे से चढ़ाया जाने वाला आवरण। कड़ी मेहनत के दिन के बाद उसे विश्राम करने दो, तो वह कुंद हुए बिना ही रहता है—अगले बसंत की मिट्टी से फिर मिलने के लिए तैयार।"},"ICON-2704":{"nm":"गेंद-लुढ़कन ढलान","de":"एक ऐसी ढलान जिस पर गेंद सरसराती हुई लुढ़कती है। हल्की सी झुकी ढलान के सहारे गेंद उल्लास से दौड़ पड़ती है। एक छोटी सी ढलान ही पूरे दिन की खुशी बना देती है।"},"ICON-2705":{"nm":"बाड़-द्वार सिटकिनी छल्ला","de":"बाड़ के द्वार को बंद करने वाला सिटकिनी छल्ला। खट् की छोटी सी आवाज़ के साथ बंद होते ही मन को चैन मिलता है। एक कसकर बंद द्वार ही छोटे से आँगन को अपने आप में एक पूरी दुनिया बनाकर सुरक्षित रखता है।"},"ICON-2706":{"nm":"खेल-घंटी डोरी","de":"घंटी बंधी डोरी को हल्के से हिलाओ तो एक साफ़ आवाज़ फैल जाती है। टुनटुन, टुनटुन—एक शांत कमरा जाग उठता है, और एक नन्ही सी झंकार से पूरा मन कान लगाकर सुनने लगता है।"},"ICON-2707":{"nm":"गमला जल-कटोरी","de":"गमले के नीचे रिसकर बहते पानी को चुपचाप थाम लेने वाली तश्तरी। खिड़की की चौखट भीगने न पाए, इसलिए वह बहा हुआ पानी अपने भीतर समेट लेती है। जब स्नेह भी उमड़ पड़े, तो उसे थामने की भी एक जगह चाहिए होती है।"},"ICON-2708":{"nm":"पौध-रोपण खुरपी","de":"नाज़ुक पौध को मिट्टी में उठाकर धीरे से रोप देने वाली छोटी खुरपी। एक-एक पौधे को सावधानी से बिठाती उँगलियों के छोर पर, हथेली भर की क्यारी में भी हरा बसंत सिर उठाता है।"},"ICON-2709":{"nm":"क्यारी-नामांकन पिन","de":"हर क्यारी में क्या बोया गया है, यह लिखकर टाँकी जाने वाली नामांकन पिन। जहाँ अभी अंकुर भी नहीं फूटा, उस मिट्टी पर एक छोटा सा नामपत्र चुपचाप याद रखता है कि आगे क्या उगने वाला है।"},"ICON-2710":{"nm":"पानी-कैनी टोंटी जाली","de":"पानी की कैनी की टोंटी पर लगाई गई महीन जाली। जो पानी एक ही धार में बहता था, वह अब फुहार सी कई धाराओं में बिखर जाता है। बस एक कोमल जलधार ही नाज़ुक पत्तियों को चोट पहुँचाए बिना उन्हें सींचती है।"},"ICON-2711":{"nm":"सहारा-छड़ पकड़ क्लिप","de":"लड़खड़ाते तने को सहारा-छड़ से धीरे से बाँध देने वाली क्लिप। अभी नाज़ुक चीज़ के सीधा खड़ा होने तक थोड़ी देर के लिए उधार दिया गया सहारा—बढ़ने के लिए ऐसी टेक की ज़रूरत होती है।"},"ICON-2712":{"nm":"बीज-थैली सीलिंग क्लिप","de":"बचे हुए बीजों की थैली को मज़बूती से भींचकर बंद करने वाली क्लिप। एक बार लगा दो, तो एक दाना भी बाहर नहीं झरता। अगले बसंत का एक छोटा सा वादा, इसी एक भिंचाव में बसा रहता है।"},"ICON-2713":{"nm":"मिट्टी-खाद मापन चम्मच","de":"मिट्टी और खाद को ठीक मात्रा में उठाने वाली छोटी चम्मच। न ज़्यादा, न कम—बस एक नपा-तुला चम्मच भर। ठीक-ठीक नापी गई मात्रा पर ही मिट्टी आख़िरकार अपना काम कर पाती है।"},"ICON-2714":{"nm":"लटकता गमला हुक","de":"गमले को हवा में धीरे से लटका देने वाला हैंगर हुक। ऊपर उठी हरियाली धूप और हवा के थोड़ा और नज़दीक आ जाती है। खिड़की के पास एक नन्हा बगीचा हवा में तैरने लगता है।"},"ICON-2715":{"nm":"अंकुर-रक्षक जाली आवरण","de":"अभी-अभी फूटे अंकुर को कोमलता से ढँकने वाली जाली। जब तक नाज़ुक पत्तियाँ पहली ठंड और तीखी धूप सहने लायक न हो जाएँ, तब तक सबसे नाज़ुक चीज़ को ही सबसे पहले सँभाला जाता है।"},"ICON-2716":{"nm":"संवारने वाली कंघी टांगन","de":"झड़े हुए बालों को टकटका कर झाड़ते हुए करीने से टाँग देने की जगह। मुलायमी से खाली हुई कंघी अगले स्पर्श की राह देखती है। सफ़ाई हमेशा अपने औज़ारों की देखभाल की एक छोटी सी आदत से शुरू होती है।"},"ICON-2717":{"nm":"पैर-धुलाई टब फिसलन-रोधी छल्ला","de":"पैर धोने वाले टब को फिसलने से बचाकर थामने वाला छल्ला। छपछप करते नन्हे पैरों के नीचे टब हिलता नहीं, तो न धोते हाथ डगमगाते हैं, न धुलता मन।"},"ICON-2718":{"nm":"सैर-पट्टा दीवार हुक","de":"सैर वाली पट्टी को दरवाज़े के पास टाँगने का एक हुक। दरवाज़े की बग़ल में अपनी जगह पर, निकलने की तैयारी हमेशा राह देखती रहती है। जैसे ही पट्टी नीचे उतरती है, एक उत्साहित कदम भी साथ चल पड़ता है।"},"ICON-2719":{"nm":"नाखून-कटाई रक्षक टोपी","de":"नाखून काटते समय नाज़ुक हिस्से की रक्षा करने वाली आवरण टोपी। \"बस यहीं तक\" खींची गई एक सुरक्षित सीमा हो, तभी कैंची थामे हाथ भी बिना काँपे शांत रह पाता है।"},"ICON-2720":{"nm":"नहाने के पानी की तापमान पट्टी","de":"नहाने के पानी में तैरकर उसका तापमान बताने वाली पट्टी। हाथ की पीठ डुबोकर सही गर्माहट टटोलने वाला वह पुराना मन, अब एक ही रंग-रेखा में साफ़-साफ़ अनूदित होकर तैर रहा है।"},"ICON-2721":{"nm":"लिंट-रोलर छड़ी","de":"काले कपड़े पर एक सफ़ेद बाल, मंच पर जाने से ठीक पहले वही सबसे बड़ा दिखता है। लुढ़कने की सरसराहट के साथ दिनभर की धूल-कण चिपचिपे काग़ज़ पर एक-एक कर जुड़ती जाती है। साफ़-सफ़ाई इसी तरह, एक-एक पट्टी में, जितना उतारा जाए उतनी ही पूरी होती है।"},"ICON-2722":{"nm":"सैर मल-थैली चिमटा","de":"सैर के आख़िर में झुकने का एक कोमल पल आता है। चिमटे की नोक पर थैली थाम लो तो हाथ साफ़ रहते हैं और मन हल्का। साथ चलने में पीछे की सफ़ाई का भी एक छोटा शिष्टाचार शामिल है—यह बात यह चिमटा सबसे पहले जानता है।"},"ICON-2723":{"nm":"पायदान किनारा पट्टी","de":"दरवाज़े के आगे पायदान का किनारा पैर से मिलने वाला पहला स्वागत है। गीले पंजे यहाँ एक बार थम जाएँ, तो भीतर का फ़र्श सूखा रहता है। भीतर आने वाले हर किसी को बिना कुछ कहे पोंछकर स्वागत करने वाली, सबसे नीची जगह।"},"ICON-2724":{"nm":"संवारने वाली घंटी-गाँठ डोरी","de":"एक घंटी बाँधने का भी अपना क्रम होता है। डोरी को दो बार लपेटकर एक बार पिरो दो, तो हर कदम पर एक साफ़ आवाज़ छनकती चली आती है। संवरना, आख़िर में, इस छोटी सी अंतिम कड़ी को न छोड़ने का ही मन है।"},"ICON-2725":{"nm":"मुड़ने वाली छतरी बूंद-थैली","de":"बारिश थमने के बाद के लॉबी में, मुड़ी हुई छतरी की नोक से बूँदें फ़र्श पर बिखर जाती हैं। एक थैली चुपचाप उन्हें थाम ले, तो किसी के पैरों तले फिसलन नहीं होती। स्नेह अक्सर ऐसे ही, बिना आवाज़ किए, पास बना रहता है।"},"ICON-2726":{"nm":"बैग-पट्टा क्लिप","de":"कुर्सी पर टाँगा बैग बार-बार सरककर नीचे गिर जाता है। पट्टा-क्लिप से एक बार भींच दो, तो गिरने की फ़िक्र के बिना दोनों हाथ हल्के हो जाते हैं। बाहर निकलने की फ़ुरसत तभी शुरू होती है जब सामान को कुछ देर के लिए भुलाया जा सके।"},"ICON-2727":{"nm":"हैंड-वॉर्मर कपड़ा थैली","de":"ठंडी हवा वाली गली में, जेब के भीतर का कपड़े का थैला हथेली तक धीरे से गर्माहट पहुँचाता है। गर्म चीज़ को मुलायमी से एक परत में लपेटकर ठीक उतना ही गर्म रखने की बुनावट। सर्दी की कोमलता हमेशा एक कपड़े की परत से होकर ही पहुँचती है।"},"ICON-2728":{"nm":"मुड़ने वाला दर्पण स्टैंड","de":"खोलते ही एक छोटा दर्पण तिरछा होकर अपना कोण पकड़ लेता है। हाथ में पकड़े बिना भी चेहरा देख सको, इसके लिए स्टैंड उसकी जगह खड़ा रहता है। रूप-सज्जा ठीक करने के उस छोटे से पल में भी, एक भरोसेमंद सहयोगी पास रहता है।"},"ICON-2729":{"nm":"यात्रा वेट-वाइप ढक्कन कैप","de":"वेट-वाइप्स की पहली परत हमेशा सूखती ही जा रही थी। कैप को खट् से बंद कर दो, तो आख़िरी परत तक नमी बनी रहती है। आख़िर तक इस्तेमाल लायक बनाए रखना—लंबे समय तक चलने वाले घर-गृहस्थी का राज़ ऐसी ही छोटी चीज़ों में छिपा होता है।"},"ICON-2730":{"nm":"पर्स सिक्का विभाजक","de":"सिक्के नोटों के बीच बिखर जाएँ तो काउंटर के आगे हमेशा हड़बड़ी मच जाती है। एक विभाजक गोल चीज़ों को एक तरफ़ समेट दे, तो उँगलियाँ अब भटकती नहीं। सजाना दरअसल हर चीज़ को उसकी जगह और नाम देने का काम है।"},"ICON-2731":{"nm":"यात्रा मास्क फोल्डिंग केस","de":"मोड़कर रखने पर मास्क बैग के भीतर भी नहीं सिकुड़ता। थोड़ी देर के लिए उतारी गई एक परत को साफ़-सुथरा थामने वाला केस। अगली बार के लिए उसे करीने से सँभाल कर रखने की एक कोमल आदत यहाँ समाई है।"},"ICON-2732":{"nm":"यात्रा कंघी दाँत-आवरण","de":"बैग के भीतर कंघी के दाँत अक्सर बाकी सामान को खरोंच दिया करते थे। दाँत-आवरण चढ़ाओ तो कंघी भी सुरक्षित रहती है और साथ रखा सामान भी। एक छोटी सी सुरक्षा की परत दोनों तरफ़ को बचाती है—यह बात वही जानता है जिसने चीज़ों की देखभाल की हो।"},"ICON-2733":{"nm":"दराज़ खाना विभाजक क्लिप","de":"दराज़ खुलती हर बार, बिखरा सामान एक आह की तरह बाहर गिर पड़ता था। एक क्लिप से खाने बाँटो, तो छोटी चीज़ें आख़िरकार अपना कोना पा लेती हैं। सुव्यवस्थित दराज़ हर सुबह का मिज़ाज चुपचाप बदल देती है।"},"ICON-2734":{"nm":"सिक्का प्रदर्शन स्टैंड","de":"एक पुराने सिक्के को खड़ा कर दो, तो वह अपने आप में एक छोटी प्रदर्शनी बन जाता है। स्टैंड उसे तिरछा थामकर सामने की नक्काशी साफ़ दिखाता है। हाथों से घिसे हुए समय को आँखों की सीध पर ला रखना—संग्रह का सुख यहीं गहराता है।"},"ICON-2735":{"nm":"ईयरफ़ोन लपेटन कुंडल","de":"उलझी हुई ईयरफ़ोन की डोरी सुलझाने में सुबह का आधा हिस्सा बह जाया करता था। लपेटन कुंडल में करीने से घुमाकर लपेट दो, तो अगली बार निकालना आसान हो जाता है। एक छोटी सी सफ़ाई कल के अपने आप को दिया गया एक चुपचाप उपहार बन जाती है।"},"ICON-2736":{"nm":"चार्जिंग-केबल दीवार हुक","de":"फ़र्श पर लटकती चार्जिंग की तार बार-बार पैरों तले आ जाती थी। दीवार पर एक हुक लगाकर टाँग दो, तो मेज़ काफ़ी खुली-खुली लगने लगती है। अव्यवस्था को सँभालना कोई बड़ी बात नहीं, बस एक कील भर जगह की बात है।"},"ICON-2737":{"nm":"रिमोट-कंट्रोल स्टैंड","de":"सोफ़े की दरार में खोए रहने वाले रिमोट को आख़िरकार लौटने के लिए एक घर मिल गया। स्टैंड में खड़ा कर दो तो न ढूँढना पड़ता है, न उस पर बैठ जाना पड़ता है। अपनी एक जगह होना, किसी चीज़ के लिए भी एक छोटा सा विश्राम बन जाता है।"},"ICON-2738":{"nm":"चश्मे की भुजा टांगन क्लिप","de":"उतारा हुआ चश्मा हमेशा चुपके से कहीं न कहीं सरक जाया करता था। भुजा को क्लिप पर हल्के से टाँग दो तो लेंस फ़र्श को नहीं छूते। बिना खरोंच के अगला दिन देखने की चाह, इस छोटी टांगन में समाई है।"},"ICON-2739":{"nm":"चाबी-गुच्छा छँटाई क्लिप","de":"चाबियों का गुच्छा जितना भारी होता है, उतना ही धुँधला हो जाता है कि कौन सी किस दरवाज़े की है। छँटाई क्लिप से बाँध दो तो सिर्फ़ उँगलियों के स्पर्श से ही अपनी जोड़ी पहचान आती है। रोज़ खुलने-बंद होने वाले दरवाज़ों को चुपचाप व्यवस्था देने वाला, मौन मार्गदर्शक।"},"ICON-2740":{"nm":"मेमो-पत्रक स्टैंड क्लिप","de":"लिखा हुआ मेमो मेज़ पर अक्सर औंधा गिर जाया करता था। क्लिप काग़ज़ को सीधा थाम ले, तो अक्षर सीधे आँखों में देखते हैं। जो एक पंक्ति भूलनी नहीं चाहिए, उसे हमेशा नज़र आने वाली जगह बसाने का एक तरीक़ा।"},"ICON-2741":{"nm":"पेन-नोक स्टैंड","de":"लुढ़ककर गिरे पेन को उठाने के लिए कितनी बार कमर झुकानी पड़ी है? नोक को स्टैंड में गाड़कर खड़ा कर दो, तो अगली पंक्ति तक की दूरी बित्ता भर छोटी हो जाती है। लिखने वाले के पास हमेशा जागा हुआ, एक छोटा सा पड़ाव।"},"ICON-2742":{"nm":"रेत-घड़ी पलटन आधार","de":"रेत-घड़ी की रेत पूरी बह जाने के बाद उसे फिर से जीने के लिए किसी का उसे पलटना ज़रूरी होता है। आधार उस आख़िरी दाने के पल को थामकर उसे सफ़ाई से फिर सीधा खड़ा कर देता है। समय को शुरुआत में लौटाने वाला वह स्पर्श, यहाँ एक छोटे से लकड़ी के टुकड़े पर ठहरा रहता है।"},"ICON-2743":{"nm":"मक्खन-भुना आलू","de":"छिलके सहित भुने आलू पर मक्खन धीरे-धीरे पिघलकर बहता है। भाप के साथ पीली धार जब भीतर तक रिसती है, तो भुरभुरा गूदा चुपचाप उस सोंधेपन को अपने भीतर समेट लेता है। मिट्टी की महक लिए यह जड़-सब्ज़ी सबसे गर्म होने का, ठीक वही पल।"},"ICON-2744":{"nm":"मक्खन-भुनी भुट्टा","de":"एक-एक करके जड़े पीले दाने तवे पर टक-टक की आवाज़ करते हैं। मक्खन का एक टुकड़ा जब उनके ऊपर से फिसलता है, तो मीठी महक हवा में उठ आती है। गर्मियों के खेत की मिठास बिल्कुल वैसे ही एक कौर में उतर आती है।"},"ICON-2745":{"nm":"वैफ़ल","de":"जालीदार हर छोटे खाने में सिरप के भर जाने की चुपचाप प्रतीक्षा होती है। ऊपर से कुरकुरा, भीतर से मुलायम—एक कौर काटते ही गर्म भाप बाहर छलक आती है। चौकोर खाने मानो एक ऐसा बर्तन हैं जो छोटी-छोटी खुशियाँ बाँट-बाँट कर परोसते हैं।"},"ICON-2746":{"nm":"पैनकेक","de":"तवे पर घोल के सुनहरा होकर फूलने की उस महक को मैं याद रखता हूँ। तह-दर-तह जमी गोल रोटियों पर मक्खन धीरे से पिघलकर ढह जाता है। एक इत्मीनान भरी सुबह को ही चुपचाप दी जाने वाली, एक मुलायम थाली।"},"ICON-2747":{"nm":"चॉकलेट","de":"एक टुकड़ा मुँह में रखते ही शरीर की गर्मी पाकर वह धीरे-धीरे घुलने लगता है। कड़वेपन के अंत में फैलती मिठास मन का तनाव हौले से छोड़ देती है। थके हुए दिन, जेब से निकालकर खाया जाने वाला सांत्वना का एक छोटा भूरा टुकड़ा।"},"ICON-2748":{"nm":"स्ट्रॉबेरी केक","de":"लाल स्ट्रॉबेरी सफ़ेद व्हिप्ड क्रीम पर बैठकर सबसे पहले बसंत की ख़बर देती है। काँटा जब नरम परत को चीरता है, तो एक खट्टी सी खुशबू धीरे से खिल उठती है। जिस दिन कुछ मनाने को हो, मेज़ के ठीक बीच में रखा जाने वाला एक कोमल नायक।"},"ICON-2749":{"nm":"चीज़केक","de":"एक भारी टुकड़ा जीभ पर गहराई से ढह जाता है। नमकीन अंतिम स्वाद मिठास का हाथ थाम लेता है और बार-बार एक और कौर के लिए बुलाता रहता है। जिन्हें गाढ़ी सघनता पसंद है, वे इस मिठाई को चुपचाप संजोकर खाते हैं।"},"ICON-2750":{"nm":"केला कुकीज़","de":"मसले हुए केले की महक ओवन के भीतर पीली होकर पकती है। एक कौर काटते ही मुलायम मिठास पूरे मुँह में फैल जाती है। एक अच्छी तरह पका फल कुकी बनकर फिर से जन्म लेता है, यह उसका एक गर्म रूपांतरण-क्षण।"},"ICON-2751":{"nm":"चॉकलेट चिप कुकीज़","de":"घोल के भीतर चॉकलेट के दाने पकते-पकते गाढ़े होकर घुल जाते हैं। गरम रहते ही तोड़ो तो गहरा भूरा रंग उँगलियों पर लग जाता है। एक गिलास दूध के साथ, दोपहर को थोड़ा और अपनापन देने वाला, ऐसा एक टुकड़ा।"},"ICON-2752":{"nm":"काकाओ निब्स कुकीज़","de":"बारीक कुचले काकाओ के टुकड़े घोल के बीच टक-टक चबते हैं। बिना मिठास वाली गहरी कड़वाहट बड़ों के स्वाद को धीरे से शांत करती है। प्रसंस्करण से पहले की मूल महक को जस का तस समेटे, थोड़ी गंभीर कुकी।"},"ICON-2753":{"nm":"चीज़ टोस्ट","de":"सुनहरी सिंकी ब्रेड पर चीज़ धागे की तरह लंबा खिंचता है। बाहर की कुरकुराहट और भीतर की सोंधी मिठास एक ही कौर में मिलकर एक हो जाती है। देर हुई सुबह को भरपूर तरीक़े से भरने वाला, सबसे सरल और सबसे अपनत्व भरा भोजन।"},"ICON-2754":{"nm":"सैंडविच","de":"दो ब्रेड की परतों के बीच दिनभर की मेहनत तह-दर-तह भर जाती है। एक कौर काटते ही परत-दर-परत जमे स्वाद एक साथ नमस्ते कहते हैं। हथेली पर रखी एक छोटी सी मेज़, जिसे कहीं भी उठाकर ले जाया जा सके।"},"ICON-2755":{"nm":"फ्रेंच टोस्ट","de":"अंडे के घोल में भीगी ब्रेड तवे पर सुनहरी होकर पकती है। मक्खन की महक के साथ फूले किनारे सबसे पहले कुरकुरे होते हैं। सिरप की एक धार डाल दो, तो साधारण ब्रेड भी छुट्टी की एक विलासिता बन जाती है।"},"ICON-2756":{"nm":"मशरूम रामेन","de":"उबलते शोरबे पर मशरूम की गहरी महक भाप के साथ उठती है। एक कुरकुरी टोपी उठाओ तो मिट्टी की महक लिए मिठास मुँह में फैल जाती है। नूडल से पहले खुशबू से ही पेट भरने वाला, थोड़ा ख़ास कटोरा।"},"ICON-2757":{"nm":"भुना रामेन","de":"बिना शोरबे के सने नूडल पर तीखा मसाला चमकीली परत बनकर लिपट जाता है। चॉपस्टिक से उठाओ तो भाप के बीच से सोंधी धुआँदार महक फैल जाती है। जब मन को एक तेज़, गाढ़ा भोजन चाहिए हो, तो सबसे भरोसेमंद साथी।"},"ICON-2758":{"nm":"चीज़ रामेन","de":"गरम नूडल पर चीज़ की एक परत रखो तो वह धीरे-धीरे ढहकर घुल जाती है। तीखा शोरबा और मुलायम सोंधापन मिलकर सारे कोने गोल कर देते हैं। जिस रात तीखेपन को थोड़ा नरम करना हो, उसके लिए बिल्कुल फ़बता एक कटोरा।"},"ICON-2759":{"nm":"करी रामेन","de":"गहरी करी की महक नूडल को लपेटकर पीली भाप उठाती है। एक कौर सुड़ककर लो तो गर्म तीखापन भीतर तक सेंक देता है। जाने-पहचाने शोरबे में थोड़ी अनजानी महक जोड़ता, आनंददायी विविधता वाला नूडल।"},"ICON-2760":{"nm":"सीफ़ूड रामेन","de":"समुद्र की महक भरे शोरबे पर झींगे और सीपियाँ मोटी-मोटी होकर तैरने लगती हैं। ताज़गी भरा फिर भी गहरा स्वाद नूडल की एक-एक तह में रिस जाता है। दूर गए बिना ही समुद्र-तट की महक एक कटोरे में समेट लाने वाला, छोटा सा जादू।"},"ICON-2761":{"nm":"अचारी मूली गिम्बाप","de":"पीली अचारी मूली को बीच में रखकर चावल गोल घेरा बनाकर बैठ जाते हैं, और एक सीवीड की चादर उन सबको एक ही लपेटे में अपनत्व से बाँध देती है। पिकनिक की भोर में, कटिंग बोर्ड पर जन्मा सबसे ईमानदार भोजन।"},"ICON-2762":{"nm":"टूना गिम्बाप","de":"मेयो में सने टूना का एक चम्मच जब चावल के बीच रिसता है, तो देर रात के कन्वीनियंस स्टोर की रोशनी में भी एक भोजन पूरी तरह गर्म हो उठता है। व्यस्त हाथों की सबसे बार-बार पहुँचने वाली सांत्वना।"},"ICON-2763":{"nm":"फल सलाद","de":"मौसम भर के जमा किए रंग एक कटोरे में पहली बार मिलते हैं। लाल, हरा और पीला बिना झगड़े साथ रहना कैसे सीखते हैं—यह फल तभी दिखाता है जब वह काटा जाकर एक साथ रखा जाता है।"},"ICON-2764":{"nm":"चिकन सलाद","de":"हल्के से भुना चिकन ब्रेस्ट हरी पत्तेदार सब्ज़ियों पर करीने से रखा जाता है। कल के मंच की तैयारी करने वाले की मेज़ पर, हमेशा ऐसी ही एक सुघड़ थाली सजी होती है।"},"ICON-2765":{"nm":"टमाटर-खीरा सलाद","de":"अच्छी तरह पके टमाटर और कुरकुरे खीरे को खट्टा-मीठा करके बनाया जाता है। सेमल की आवाज़ से भरी दोपहर में, एक कौर मुँह में डालते ही उसके भीतर गर्मी एक धड़कन ठंडी हो जाती है।"},"ICON-2766":{"nm":"लेट्यूस सलाद","de":"क्यारी से अभी-अभी तोड़ी पत्तियों को ठंडे पानी से धो लो तो उँगलियाँ ठंडक से जाग उठती हैं। सबसे सामान्य सब्ज़ी मेज़ पर सबसे हरी, सबसे ताज़ी जगह पाने का वह पल।"},"ICON-2767":{"nm":"भुट्टा सलाद","de":"हर बार जब मीठा दाना टक् से फूटता है, धूप से भरा गहरी गर्मियों का खेत आँखों के आगे फैल जाता है। सलाद के कटोरे में भी पीला भुट्टा अपनी धूप को कभी नहीं भूलता।"},"ICON-2768":{"nm":"कोलस्लॉ","de":"कतरी पत्तागोभी जब खट्टी-मीठी चटनी को सोख लेती है, तो उसकी कुरकुराहट थोड़ी और नरम हो जाती है। किसी भी मुख्य व्यंजन के साथ रखो, बिना चमक की होड़ किए अपना हिस्सा निभाने वाले सह-व्यंजन का गुण।"},"ICON-2769":{"nm":"नींबू-झींगा सलाद","de":"लाइम को हल्के से निचोड़ते ही झींगे की मिठास और तीखी होकर जाग उठती है। एक खट्टी बूँद पूरी थाली में जान फूँक देती है—छोटा मगर निर्णायक अंतिम स्पर्श।"},"ICON-2770":{"nm":"हैम्बर्ग स्टेक","de":"मोटा गढ़ा हुआ मीट का घोल गरम तवे पर सुनहरा होकर पकता है। चाकू की नोक छूते ही रिसता रस—घर के खाने और पश्चिमी व्यंजन के बीच सबसे लंबे समय से चाहा गया एक भोजन।"},"ICON-2771":{"nm":"पिज़्ज़ा","de":"चीज़ के लंबा खिंचने वाले उस एक कौर को कई लोग घेरा बनाकर बैठे हाथ से हाथ में बाँटते हैं। जब एक गोल पिज़्ज़ा साथ मिलकर टुकड़ों में बाँटा जाता है, तभी कोई जुटान सच में एक जुटान बनता है।"},"ICON-2772":{"nm":"मशरूम क्रीम पास्ता","de":"मशरूम की गहरी मिट्टी-महक और क्रीम की मुलायमी नूडल के एक-एक धागे को गले लगा लेती है। बारिश की हल्की आवाज़ भरी शाम में, गाढ़ी खुशबू धीरे-धीरे थाली की तह तक फैल जाती है।"},"ICON-2773":{"nm":"झींगा पास्ता","de":"मोटे झींगों को जैतून तेल में हल्का भूनकर नूडल के साथ मिला दिया जाता है। जब समुद्र की नमकीनी और नूडल की सादगी मिलती है, तो एक साधारण शाम थोड़ी ख़ास बन जाती है।"},"ICON-2774":{"nm":"ऑयल पास्ता","de":"लहसुन, तेल और नूडल—बस यही तीन चीज़ें। जितना कम करो उतना ही साफ़ उभरने वाला एक स्वाद होता है—आलियो ओलियो बिना किसी फ़ुज़ूल चीज़ के चुपचाप यह साबित करता है।"},"ICON-2775":{"nm":"क्लैम पास्ता","de":"सीपियाँ मुँह खोलकर छोड़ा हुआ शोरबा नूडल के एक-एक धागे में गहराई तक रिस जाता है। सफ़ेद वाइन के एक घूँट की महक थाली पर बसंत के दिन की तरह लंबे समय तक बनी रहती है।"},"ICON-2776":{"nm":"क्रीम पास्ता","de":"गाढ़ी क्रीम जब नूडल को चुपचाप गले लगाती है, तो पहले कौर से ही मन का एक कोना गर्म हो उठता है। जितना हवा तेज़ चले, उतनी ही गहरी हो जाने वाली, मुलायमी की दी हुई सांत्वना।"},"ICON-2777":{"nm":"टमाटर पास्ता","de":"देर तक उबाली गई टमाटर की चटनी नूडल पर लाल होकर फैल जाती है। मिठास और खटास धीरे-धीरे पककर आख़िर संतुलन पा लेते हैं, तब सबसे बुनियादी थाली ही सबसे भरोसेमंद बन जाती है।"},"ICON-2778":{"nm":"ओमुराइस","de":"मुलायम अंडा गरम चावल को कंबल की तरह धीरे से ओढ़ा देता है। केचप से अगर एक नाम भी लिख दिया जाए, तो उस दिन की मेज़ किसी के हाथों सौंपा गया एक छोटा सा पत्र बन जाती है।"},"ICON-2779":{"nm":"भुना सैल्मन","de":"छिलका कुरकुरा होने तक आँच के आगे धीरे-धीरे सेंका जाता है। गुलाबी गूदा अपनी रेखाओं के सहारे बँटता हुआ जब भाप की एक लकीर उठाता है—सब्र को हमेशा सैल्मन ईमानदारी से चुकाता है।"},"ICON-2780":{"nm":"ब्रुशेटा","de":"कुरकुरी सिंकी ब्रेड पर कटा टमाटर और तुलसी भरपूर मात्रा में रखी जाती है। उँगलियों से उठाकर एक कौर लेने की वह हल्कापन ही किसी जुटान की पहली नमस्ते को अपनत्व से खोलता है।"},"ICON-2781":{"nm":"मैंगो स्मूदी","de":"अच्छी तरह पके आम को महीन पीसकर बर्फ़ के साथ ठंडा मिला दिया जाता है। पीले गिलास पर जब बूँदें मोती-मोती बन जाती हैं, तो एक सुस्त गहरी गर्मियों की दोपहर स्ट्रॉ की नोक तक भर आती है।"},"ICON-2782":{"nm":"लेमोनेड","de":"ताज़ा निचोड़ा नींबू, चीनी और ठंडा पानी मिलाकर गिलास समेत हिलाया जाता है। पीली खटास जब गले से ठंडक बनकर उतरती है, तो उग्र गर्मी भी एक पल के लिए हार मान लेती है।"},"ICON-2783":{"nm":"स्ट्रॉबेरी मिल्क","de":"मसली हुई स्ट्रॉबेरी को दूध में घोलो तो गुलाबी बादल गिलास के भीतर धीरे-धीरे नीचे बैठ जाता है। बचपन में फ़्रिज का दरवाज़ा खोलने वाली उँगलियों की वह हलचल, एक गिलास में पूरी तरह समाई रहती है।"},"ICON-2784":{"nm":"बनाना मिल्क","de":"बस अपनी उस गोल कद-काठी से ही यह एक पूरे दौर की याद बन चुका पेय है। नहाने के तालाब की चौकी पर स्ट्रॉ गाड़ने वाली पीली याद, हर घूँट के साथ अपनत्व से लौट आती है।"},"ICON-2785":{"nm":"ब्लूबेरी मिल्क","de":"बैंगनी दानों को टक-टक कुचलकर मिलाओ तो सफ़ेद दूध हल्के आसमानी रंग में रंग जाता है। उस मुट्ठी भर छोटे फल एक पूरे गिलास को नए रंग में बदल देते हैं।"},"ICON-2786":{"nm":"फल जूस","de":"कई फलों को एक साथ निचोड़ दो तो वह एक ऐसा स्वाद बन जाता है जिसे किसी एक नाम से नहीं पुकारा जा सकता। एक-दूसरे में घुलकर और भी भरपूर फूलने वाला, मिठासों का एक छोटा सा गायन-मंडल।"},"ICON-2787":{"nm":"कोको","de":"बर्फ़ गिरती खिड़की के पास, गरम मग को दोनों हाथों से चुपचाप थाम लो। भाप उड़ाता एक भूरा प्याला उँगलियों से लेकर मन तक धीरे-धीरे गर्माहट पहुँचाता है।"},"ICON-2788":{"nm":"कॉफ़ी","de":"भोर के अभ्यास कक्ष की बत्ती जलाने वाला हमेशा यही एक प्याला होता है। कड़वी महक जब नींद को धीरे से परे धकेलती है, तो एक और दिन का मंच चुपचाप वैसे ही शुरू हो जाता है।"},"ICON-2789":{"nm":"सैल्मन सुशी","de":"हाथ में चावल थामकर सख़्ती और मुलायमी के बीच की वह महीन रेखा नापी जाती है। पतला कटा सैल्मन का एक टुकड़ा जब धीरे से उस पर लेट जाता है, तो एक कौर एक छोटी सी लगन की पूर्णता बन जाता है।"},"ICON-2790":{"nm":"मीठा कद्दू दलिया","de":"पीले कद्दू को खूब उबालकर महीन पीस लिया जाता है। हर चम्मच के साथ शरद की धूप मुँह में गर्म होकर घुल जाती है। बीमार पड़ने पर सबसे पहले याद आने वाला दलिया।"},"ICON-2791":{"nm":"फ़िश करी","de":"मसालों में हल्का उबाला गया मछली का गूदा करी में मुलायमी से बिखर जाता है। एक जाने-पहचाने कटोरे में समुद्र की बुनावट जोड़ दो, तो एक साधारण शाम बित्ता भर दूर की यात्रा पर निकल पड़ती है।"},"ICON-2792":{"nm":"तला झींगा","de":"पूँछ पकड़कर घोल लपेटने और खौलते तेल में डालने का वह छोटा सा पल ही निर्णायक होता है। सुनहरे लबादे में लिपटा झींगा, कुरकुराहट ठंडी होने से पहले ही खाया जाए तो सबसे ज़्यादा चमकता है।"},"ICON-2793":{"nm":"तला स्क्विड","de":"गोल छल्ले गरम तेल में मोटे होकर फूल उठते हैं। कुरकुराहट में लिपटी नरमाहट का वह कौर, फेरी वाली दुकान की पीली रोशनी तले सबसे ज़्यादा जँचता है।"},"ICON-2794":{"nm":"भुना चिकन","de":"मसाला लगाकर आँच के आगे धीरे-धीरे भूनते जाओ तो त्वचा चमक से दमकने लगती है। आँच के एक फेरबदल पर ही स्वाद बदल जाने वाला, सबसे सादा होने के कारण ही सबसे ईमानदार व्यंजन।"},"ICON-2795":{"nm":"पोर्क किमची स्टिर-फ़्राई","de":"अच्छी तरह पका किमची और पोर्क को साथ भूनो तो खट्टापन पककर मिठास में ढल जाता है। सफ़ेद चावल का एक कटोरा अपने आप याद दिलाने वाला, कोरियाई मेज़ का सबसे भरोसेमंद साथी।"},"ICON-2796":{"nm":"पोर्क स्टिर-फ़्राई","de":"तेज़ आँच पर फटाफट भूनकर बाहर से कड़क सेंक दिया जाता है। सोंधी तेल की महक जब रसोई भर जाती है, तो आज रात के खाने का मेन्यू बिना और पूछे पहले ही तय हो जाता है।"},"ICON-2797":{"nm":"बीफ़-मशरूम स्टिर-फ़्राई","de":"सुगंधित मशरूम और बीफ़ को साथ भूनो तो दोनों का स्वाद और गहरा हो जाता है। मिट्टी और खेत एक थाली पर चुपचाप हाथ मिला लेते हैं, यह शरद का एक सुघड़ भोजन।"},"ICON-2798":{"nm":"चीज़ डाक-गल्बी","de":"तीखे डाक-गल्बी पर चीज़ को भरपूर पिघलाकर लंबा खींचा जाता है। गरम तवे के इर्द-गिर्द कई लोग घेरा बनाकर बैठें, तो झनझनाता तीखापन भी हँसी में घुल जाता है।"},"ICON-2799":{"nm":"किमची स्ट्यू","de":"जितना पुराना किमची हो, उतना ही गहरा और गाढ़ा शोरबा वह देता है। खदबदाते मिट्टी के बर्तन के आगे आमने-सामने बैठो, तो \"परिवार\" शब्द फिर से गर्म होकर पिघल उठता है।"},"ICON-2800":{"nm":"दोएनजांग स्ट्यू","de":"सोंधे दोएनजांग को घोलकर टोफू और तोरई डालकर धीमी आँच पर पकाया जाता है। मिट्टी के बर्तन में आख़िर तक खदबदाती वह आवाज़ ही घर लौट आने का सबसे पक्का संकेत है।"},"ICON-2801":{"nm":"बीफ़ मूली का सूप","de":"मूली के पारदर्शी होने तक, धीमी आँच के सामने चुपचाप बीता आधा दिन। जब निथरे शोरबे का एक चम्मच होंठों को छूता है, तो उन दिनों की सीधी-सादी थाली याद आ जाती है। जो चीज़ें सादी होती हैं, वही सबसे लंबे समय तक ठहरती हैं।"},"ICON-2802":{"nm":"सीपी का सूप","de":"सीपियों के अपना मुँह खोलते ही, हांडी के भीतर बसंत गहरा जाता है। भाप के साथ जब समुद्र की सोंधी गंध का एक झोंका ऊपर उठता है, तो किसी समुद्र किनारे के गाँव की भोर की रसोई आँखों के सामने उभर आती है। हर खुले हुए खोल में नमकीन समुद्र की एक बूंद ठहरी रहती है।"},"ICON-2803":{"nm":"शकरकंद कैंडी","de":"स्कूल से लौटते वक़्त कागज़ के कप में हैंड-वॉर्मर जैसे थामा हुआ पीला टुकड़ा। सुनहरे बाहरी हिस्से को दाँतों से काटते ही भीतर से भाप उठ आती है। मीठी लेप-चढ़ी परत और गर्म भीतरी हिस्सा — सर्दी का सबसे स्नेहिल स्वाद।"},"ICON-2804":{"nm":"बैंगन भाजी","de":"बैंगनी रंग जब तेल से मिलकर धीरे-धीरे घुलने लगता है, वह पल। जिस सब्ज़ी को नरम होने के लिए ताना जाता है, वही असल में सबसे अच्छे से मसाला अपने भीतर समेट लेती है। एक कौर लेते ही सबसे पहले हाथ का वह कोमल, रचा-बसा स्वाद पहुँचता है।"},"ICON-2805":{"nm":"सोया सॉस आलू","de":"वह शाम जब सोया सॉस के औटते-औटते पूरी रसोई में मीठी खुशबू फैल जाती थी। एक-एक चमकते भूरे टुकड़े को टिफ़िन के खाने में भरता हुआ वह हाथ। किसी भी नुस्खे में न लिखी गई वह लगन हर छोटे टुकड़े में रची-बसी है।"},"ICON-2806":{"nm":"पेरिला पत्तों का अचार","de":"गर्मी की पूरी खुशबू को नमक में डुबोकर सर्दी की थाली तक ले आने का काम। एक पत्ता उठाकर चावल पर रखते ही बीता मौसम मुँह में फिर से खिल उठता है। परत-दर-परत सजे पत्तों के बीच उस साल की धूप सोई हुई है।"},"ICON-2807":{"nm":"ताज़ी नापा किमची","de":"किमजांग तक इंतज़ार न कर पाए हाथ उसी दिन इसे मल-मल कर बना डालते हैं। करारी पत्तियों में मसाला अभी-अभी रचना शुरू ही हुआ हो, उस पल में ही मिलने वाली ताज़गी। किण्वन से पहले की वह कच्ची हरियाली आज ही के दिन की एक विलासिता है।"},"ICON-2808":{"nm":"मशरूम भाजी","de":"बारिश थमने के बाद जंगल की छाँव में चुपचाप उग आई चीज़ें। तिल के तेल में भुनते हुए मिट्टी की गंध सोंधेपन में बदल जाती है। अँधेरे में जितनी ख़ामोशी से कोई चीज़ बढ़ती है, उसकी महक उतनी ही गहरी और गाढ़ी होती है।"},"ICON-2809":{"nm":"मसाला पालक","de":"उबालते ही मुट्ठी भर में सिमट जाने वाली पत्तेदार सब्ज़ी को उँगलियों से धीरे-धीरे मला जाता है। उसका वह विनम्र आकार ही बसंती साग का गुण है। हरे रंग की एक थाली भर से मेज़ पर एक बित्ता और वसंती धूप उतर आती है।"},"ICON-2810":{"nm":"समुद्री शैवाल सलाद","de":"समुद्र से अभी-अभी निकाले गए फिसलन भरे रेशे खट्टी मिर्च-सिरके की चटनी से घुल-मिल जाते हैं। हर बार चबाने पर टूटता-फूटता नमकीन एहसास। लहरों के हिलते-डुलते एहसास को जस-का-तस थाली में उतार दिया गया एक व्यंजन।"},"ICON-2811":{"nm":"तोरी भाजी","de":"कुछ सब्ज़ियाँ ऐसी होती हैं जिनकी मिठास उम्र बढ़ने के साथ-साथ गहराती जाती है। पतले टुकड़ों में काटकर सूखे झींगे के साथ भूनने पर सीधी-सादी तोरी भी चुपके से अपनी मिठास उजागर कर देती है। मुँह में आख़िर तक नरमी से घुलता वह पीला रंग।"},"ICON-2812":{"nm":"किमची फ्राइड राइस","de":"जब पुरानी किमची अपने स्वाद में और गहरी उतर जाती है, तब वह ठंडे चावल से एक ही कड़ाही में मिलती है। बचा हुआ और बचा हुआ मिलकर सबसे भरपूर बनने वाली एक थाली। देर रात किसी छोटे कमरे की बत्ती के नीचे मिलने वाला सबसे स्नेहिल सहारा।"},"ICON-2813":{"nm":"चिकन करी","de":"जब पीला शोरबा सफ़ेद चावल को ढक लेता है, तो पूरी थाली रोशन हो उठती है। जिस दौर में मसाले अनजान थे, उस बाहरी दुनिया का सबसे पहला अपनाया गया स्वाद। किसी इतवार की दोपहर, जब चिकन का मांस नरम होकर मुँह में घुल जाता था।"},"ICON-2814":{"nm":"फ्राइड राइस","de":"फ्रिज के कोने में बचे टुकड़े-टाकड़े एक ही कड़ाही में मेल-जोल से घुल-मिल जाते हैं। किसी को भी उदारता से अपनाने वाली वह भरपूरता। बिखरी हुई चीज़ों को एक जगह समेटना — गृहस्थी की शुरुआत यहीं से होती है।"},"ICON-2815":{"nm":"बुल्गोगी राइस बाउल","de":"मीठे मसाले में मैरिनेट किया मांस भाप उठते चावल पर धीरे से फिसल जाता है। जब मेहमानों की थाली का मुख्य व्यंजन किसी आम दिन की एक कटोरी में उतर आता है, तो वह खासियत और भी स्नेहिल हो जाती है।"},"ICON-2816":{"nm":"बिबिमबाप","de":"फूले हुए चावलों के ऊपर पाँच रंगों की सब्ज़ियाँ गोल घेरा बनाकर बैठ जाती हैं। रंगों को सजाती उँगलियों में एक पुराना सौंदर्यबोध बहता है, जो हर चीज़ को सलीक़े से सँवारता है। सब कुछ मिलाकर ही पूरा होने वाला वह सामंजस्य का स्वाद।"},"ICON-2817":{"nm":"झींगा फ्राइड राइस","de":"गुलाबी रंग में उभरते मोटे-तगड़े झींगे चावल के दानों के बीच जगमगाते हैं। समुद्र की एक मुट्ठी भूनकर डाल दी जाए, तो एक आम भोजन भी दावत की नक़ल कर बैठता है। दाँतों तले टूटते ही फैलने वाली मिठास मन को भा जाती है।"},"ICON-2818":{"nm":"स्पाइसी पोर्क राइस बाउल","de":"तीखे मसाले में गहरे रचा-बसा सूअर का मांस भाप उठते चावल से मिलता है। दोपहर के खाने के वक़्त सबसे पहले ख़ाली होने वाली थाली। एक व्यस्त दिन को थपथपाकर सहलाने वाला भोजन का वह सुकून।"},"ICON-2819":{"nm":"टूना मेयो राइस","de":"एक डिब्बाबंद टूना, मेयोनेज़ की एक लकीर, और गर्म चावल की एक कटोरी। सामग्री थोड़ी है, पर सुकून भरपूर। रात की पढ़ाई ख़त्म कर क्लासरूम की मेज़ पर चुपके से मिलाया गया, उस रात का वह स्वाद।"},"ICON-2820":{"nm":"करी राइस","de":"गाढ़ा सुनहरा रंग थाली को पूरी तरह भर देता है। आलू और गाजर के पूरी तरह नरम होने तक देर तक हिलाई गई वह लगन। पूरा परिवार एक ही पतीले में झाँकता हुआ, उस शाम की आत्मीयता याद आ जाती है।"},"ICON-2821":{"nm":"समुद्री शैवाल बिबिमबाप","de":"समुद्र की गंध लिए रेशे कोरियाई मिर्च-पेस्ट से मिलकर धीरे-धीरे मिलाए जाते हैं। जब फिसलन भरी, खट्टी बनावट चावल के दानों को लपेट लेती है, तो साँस रोककर एक गोताखोर महिला द्वारा निकाला गया समुद्र एक ही कटोरी में फैल जाता है।"},"ICON-2822":{"nm":"भुनी मैकेरल मछली","de":"चांदी जैसी पीठ तवे पर सुनहरी होती चली जाती है। कांटे निकालकर गूदे को चावल पर रखने वाला वह हाथ। नीली पीठ वाली मछली के एक टुकड़े में इस तरह खिलाकर पाला गया वह चुप्पा प्यार रचा-बसा है।"},"ICON-2823":{"nm":"आलू का पैनकेक","de":"बारिश के दिन गैंगवोन के पहाड़ी गाँव की रसोई में घिसकर तला जाता था यह। कुरकुरे किनारे और चबाने में चिपचिपा बीच का हिस्सा, दोनों एक ही टुकड़े में साथ-साथ बसते हैं। खिड़की पर बजती बारिश की आवाज़ से सबसे अच्छा मेल खाने वाला यह घोल।"},"ICON-2824":{"nm":"किमची पैनकेक","de":"तेल लगे तवे पर खट्टी किमची छूते ही, पूरा घर छनछनाती आवाज़ से भर उठता है। मक्कोली का एक कटोरा अपने आप बुला लेने वाला वह सुनहरा गोला। छज्जे तले बजती बारिश की आवाज़ के साथ जोड़ी बनाने वाला यह जाना-पहचाना व्यंजन।"},"ICON-2825":{"nm":"हरे प्याज़ का पैनकेक","de":"हरे प्याज़ को क़तार में बिछाकर घोल डाला जाता है, फिर धीरे-धीरे सेंका जाता है। कुरकुरेपन और मुलायमियत के बीच झूलता हुआ एक टुकड़ा। मेले के दिन ठेले पर भाप उठाता वह अपनापन भरा दृश्य, जस-का-तस।"},"ICON-2826":{"nm":"तोरी पैनकेक","de":"पतली कटी तोरी को घोल में लपेटकर सुनहरा तला जाता है। पूजा की थाली के एक कोने को सलीक़े से सँभालता वह हल्के हरे रंग का गोला। बहुत मेहनत लगने पर ही सज पाने वाला वह लगन भरा शिष्टाचार।"},"ICON-2827":{"nm":"मसालेदार स्क्विड भाजी","de":"लाल मसाले में लिपटे पैर चमक से दमकते हैं। तीखेपन से माथे पर पसीने की बूँदें उभर आएँ, तब भी चॉपस्टिक रुकने का नाम नहीं लेतीं। पसीने और आनंद के गुँथे हुए उस एक थाली का जादू।"},"ICON-2828":{"nm":"तेओकबोक्की","de":"लाल औटी हुई गोचुजांग की चटनी में तोक और मछली के केक पूरी तरह डूब जाते हैं। सिक्के जोड़कर दो दोस्तों के साथ बाँटकर खाए गए स्नैक शॉप की एक पूरी दोपहर इसमें समाई है। नाम सुनते ही मुँह में पानी ले आने वाला यादों का स्वाद।"},"ICON-2829":{"nm":"फ़िश केक सूप","de":"जहाँ शोरबे में मछली के केक हिलते-डुलते हैं, वह ठेला, जिसकी भाप शीशे को धुँधला कर देती है। एक सींक थामकर कागज़ के कप में शोरबा भरकर घूँट-घूँट पीते ही, ठिठुरती सर्दी की रात कहीं ज़्यादा गर्म हो जाती है।"},"ICON-2830":{"nm":"टोफू किमची","de":"नरम टोफू के पास तीखी भुनी हुई किमची क़तार में बैठ जाती है। ठंडक और गर्माहट, नरमी और तीखापन, एक ही थाली में घुल-मिल जाते हैं। बड़ों की रातों की लंबे समय से रखवाली करने वाली यह जोड़ी।"},"ICON-2831":{"nm":"सॉसेज-सब्ज़ी भाजी","de":"लाल सॉसेज और सब्ज़ियाँ केचप के रंग में छनछनाकर घुल-मिल जाती हैं। खेल-दिवस के टिफ़िन का ढक्कन खोलते ही सबसे पहले ख़ाली होने वाला वह खाना। उस दिन का रंग समय बीतने पर भी हमेशा उतना ही चमकीला बना रहता है।"},"ICON-2832":{"nm":"शकरकंद लाते","de":"बारीक मसला हुआ शकरकंद गर्म दूध में धीरे से घुलकर नरम हो जाता है। मेन्यू बोर्ड पर हांगुल में लिखी वह देसी मिठास। जिस दिन उँगलियाँ ठंड से सुन्न हों, दोनों हाथों में थामते ही इसकी गर्माहट धीरे-धीरे कप-भर फैल जाती है।"},"ICON-2833":{"nm":"मेयोनेज़","de":"यह सॉस अभी तक चमकते द्वीप की रसोई तक नहीं पहुँचा। जल्द ही इसे मलाई के रंग वाले आइकॉन के रूप में बनाया जाएगा। (तैयारी में)"}};